gameforge.collect_quest_lv40._70_say = "Por favor traz-me estes livros! E certifica-te[ENTER]que est\227o intactos - alguns deles poder\227o ser t\227o[ENTER]velhos que se tornam quase imposs\237veis de ler.[ENTER]N\227o posso fazer nada com exemplares desses.[ENTER]Preciso de um total de 15 livros para a minha[ENTER]investiga\231\227o. Traz-me apenas um de cada vez para[ENTER]que eu os possa analisar individualmente. "
gameforge.collect_quest_lv40._80_sayTitle = "A magia das Eras Antigas "
gameforge.collect_quest_lv40._90_say = "O Bi\243logo Chaegirab, aprendiz do Uriel, est\225 a[ENTER]investigar os feiti\231os de tempos antigos. No Vale[ENTER]Seungryong existem 15 livros pertencentes a uma[ENTER]colec\231\227o de Livros da Maldi\231\227o. Leva estes livros[ENTER]ao Bi\243logo Chaegirab, mas apenas um de cada vez.[ENTER]Poder\225s obt\234-los dos Atormentadores Negros e dos[ENTER]Grandes Atormentadores. "
