gameforge.collect_quest_lv50._310_say = "Como recompensa por teres encontrado as[ENTER]Lembran\231as do Dem\243nio e a Pedra-Esp\237rita, o[ENTER]Bi\243logo Chaegirab deu-te uma receita secreta. Vai[ENTER]ter com o Baek-Go, que ir\225 criar-te a po\231\227o[ENTER]milagrosa. "
gameforge.collect_quest_lv50._320_say = "Oh, essa \233 a receita secreta do Bi\243logo[ENTER]Chaegirab? Hm, a po\231\227o ir\225 aumentar a tua defesa[ENTER]em 60 unidades.[ENTER]Aqui tens a tua po\231\227o! Tamb\233m \233 suposto dar-te[ENTER]esta caixa de madeira. Toma bem conta dela. "
