gameforge.collect_quest_lv50._40_npcChat = "Ouve-me. "
gameforge.collect_quest_lv50._50_say = "Ainda bem que aqui est\225s! Ando a investigar todas[ENTER]as criaturas negras neste reino. Tenho a certeza[ENTER]que compreender\225s que, como acad\233mico, n\227o posso[ENTER]dar-me ao luxo de ir pessoalmente ca\231ar monstros[ENTER]para a minha investiga\231\227o. Podes ajudar-me? "
gameforge.collect_quest_lv50._60_say = "Durante o decorrer das minhas investiga\231\245es,[ENTER]gostaria de estudar os dem\243nios da Torre Gumsan.[ENTER]At\233 mesmo daqui consigo sentir a energia negra do[ENTER]edif\237cio e das criaturas no seu interior. Podes[ENTER]arranjar-me Lembran\231as do Dem\243nio para a minha[ENTER]investiga\231\227o? "
gameforge.collect_quest_lv50._70_say = "Ficaria muito grato pela tua ajuda. Mas por favor[ENTER]lembra-te: as Lembran\231as do Dem\243nio t\234m[ENTER]diferentes n\237veis de qualidade. Mas para as[ENTER]minhas investiga\231\245es apenas preciso de Lembran\231as[ENTER]de alta qualidade.[ENTER]Ao todo preciso de 15 Lembran\231as do Dem\243nio. Por[ENTER]favor traz-mas uma de cada vez, pois a[ENTER]investiga\231\227o demora algum tempo "
