gameforge.collect_quest_lv80._300_sayReward = "Como recompensa por teres completado o pedido do[ENTER]Bi\243logo Chaegirab, o teu Valor de Ataque \233[ENTER]permanentemente aumentado em 10% e a tua Rapidez[ENTER]de Ataque \233 permanentemente aumentada em 6[ENTER]unidades. "
