gameforge.collect_quest_lv80._50_say = "Obrigado por arranjares algum tempo para mim de[ENTER]novo! De momento estou a reunir informa\231\245es sobre[ENTER]a Plan\237cie Seca. \201 uma tarefa extensiva e[ENTER]naturalmente irei precisar de informa\231\245es em[ENTER]primeira-m\227o.[ENTER]Podes ir \224 Plan\237cie Seca por mim? Sabes que n\227o[ENTER]sou forreta no que toca a recompensas. "
gameforge.collect_quest_lv80._60_say = "A Plan\237cie Seca fica para l\225 dos montes no[ENTER]Deserto. Aparentemente \233 um lugar desolado[ENTER]habitado por gigantes. Essas criaturas n\227o s\227o[ENTER]apenas poderosas, como tamb\233m muito agressivas.[ENTER]Cada uma delas possui um pequeno Certificado e[ENTER]pergunto-me se o segredo do seu poder n\227o estar\225[ENTER]nele contido. "
gameforge.collect_quest_lv80._70_say = "Por favor arranja-me 30 destes Certificados dos[ENTER]Ogres na Plan\237cie Seca. Traz-me um de cada vez[ENTER]para que eu os possa analisar individualmente.[ENTER]Por favor, lembra-te que apenas posso usar[ENTER]Certificados completos e que n\227o estejam[ENTER]danificados. "
gameforge.collect_quest_lv80._80_sayTitle = "Certificados da Plan\237cie Seca "
gameforge.collect_quest_lv80._90_say = "O Bi\243logo Chaegirab, aprendiz do Uriel, est\225 a[ENTER]reunir informa\231\245es sobre a Plan\237cie Seca. Ele[ENTER]precisa de 30 Certificados de Tugyi para a sua[ENTER]investiga\231\227o. Leva-lhe apenas um de cada vez,[ENTER]para que ele tenha tempo de os analisar[ENTER]individualmente. Poder\225s obt\234-los dos Ogres. "
