gameforge.collect_quest_lv92._060_say = "Hey tu, guerreiro corajoso! Chegaste mesmo a[ENTER]tempo. Estou \224 procura de um tipo especial de[ENTER]J\243ia para a minha investiga\231\227o na \225rea das armas.[ENTER]Podes ajudar-me? Algumas das criaturas na Gruta[ENTER]das Almas est\227o na posse destas J\243ias. Mas sou[ENTER]demasiado importante para arriscar a minha vida[ENTER]num local t\227o perigoso. "
gameforge.collect_quest_lv92._070_say = "De momento preciso de algumas J\243ias da[ENTER]Malevol\234ncia em estado impec\225vel - s\227o j\243ias[ENTER]maravilhosas que apenas crescem nas profundezas[ENTER]das montanhas. S\227o diamantes especiais que[ENTER]estiveram sujeitos durante anos aos poderes do[ENTER]negro Deus Beran-Setaou e absorveram uma pequena[ENTER]parte da sua energia. Preciso de 10 dessas J\243ias.[ENTER]Boa sorte e espero que nos vejamos brevemente! "
gameforge.collect_quest_lv92._080_say_title = "J\243ias para Seon-Pyeong "
gameforge.collect_quest_lv92._090_say = "O Armeiro e Cientista Seon-Pyeong precisa de 10[ENTER]J\243ias da Malevol\234ncia para a sua investiga\231\227o na[ENTER]\225rea das armas. Leva-lhe uma de cada vez para que[ENTER]ele as possa estudar separadamente. Podes[ENTER]obt\234-las dos Homens de Gelo Negro e dos Golems de[ENTER]Gelo Negro. "
gameforge.collect_quest_lv92._100_sayReward = "J\225 conseguiste entregar %s j\243ia(s). "
gameforge.collect_quest_lv92._110_say = "Ainda n\227o podes utilizar o Elixir do Investigador. "
gameforge.collect_quest_lv92._120_say = "J\225 utilizaste um Elixir! "
gameforge.collect_quest_lv92._130_say = "Podes utilizar o Elixir assim que tiveres[ENTER]encontrado uma J\243ia. "
gameforge.collect_quest_lv92._140_send_letter = "Encontraste uma J\243ia "
gameforge.collect_quest_lv92._145_npcChat = "J\243ia da Sabedoria (94) "
gameforge.collect_quest_lv92._150_say = "Tu? Aqui? Desculpa, mas ainda n\227o terminei a[ENTER]an\225lise da J\243ia que me trouxeste antes. Regressa[ENTER]mais tarde! "
gameforge.collect_quest_lv92._160_say = "Ainda n\227o encontraste nada? Desculpa, mas ent\227o[ENTER]porque est\225s aqui? Vamos l\225, despacha-te! Volta[ENTER]quando me puderes trazer algumas J\243ias. "
gameforge.collect_quest_lv92._170_say = "Encontraste uma J\243ia? Fant\225stico! Espera um[ENTER]segundo, deixa certificar-me... "
gameforge.collect_quest_lv92._180_say = "Sim, essa parece-me boa. \201, sem d\250vida, uma das[ENTER]J\243ias mais belas que j\225 vi. Muito obrigado! "
gameforge.collect_quest_lv92._190_say = "Mas como j\225 sabes preciso de mais %s J\243ias desta[ENTER]qualidade. D\225-me um dia para analisar esta[ENTER]completamente. Depois disso poder\225s trazer-me[ENTER]outra. "
gameforge.collect_quest_lv92._200_say = "Boa sorte! "
gameforge.collect_quest_lv92._210_say = "Esta foi a \250ltima J\243ia. J\225 me trouxeste 10. Estou[ENTER]t\227o grato... E n\227o serei picuinhas em rela\231\227o \224[ENTER]tua recompensa. Agora escolhe! "
gameforge.collect_quest_lv92._220_1_select = "+1000 Vida "
gameforge.collect_quest_lv92._220_2_select = "+120 Defesa "
gameforge.collect_quest_lv92._220_3_select = "Valor de Ataque +51 "
gameforge.collect_quest_lv92._230_say = "Hum... E esta J\243ia vem mesmo da Gruta das Almas?[ENTER]\201 bonita, mas parece faltar-lhe algo... N\227o[ENTER]parece que me v\225 ser \250til. De qualquer forma irei[ENTER]analis\225-la para me certificar. Entretanto poder\225s[ENTER]arranjar-me uma nova, ok? "
