gameforge.collect_quest_lv94._030_say = "Seon-Pyeong, que se encontra no Vale Seungryong,[ENTER]precisa da tua ajuda. Vai ter com ele e v\234 o que[ENTER]se passa. "
gameforge.collect_quest_lv94._040_npcChat = "Ajuda na Investiga\231\227o "
gameforge.collect_quest_lv94._050_say_title = "Seon-Pyeong: "
gameforge.collect_quest_lv94._060_say = "Ol\225! Ent\227o recebeste a minha carta? \211ptimo, ent\227o[ENTER]j\225 sabes que mais uma vez preciso de ajuda na[ENTER]minha pesquisa das Armas. Desde que redescobri a[ENTER]Gruta das Almas cada vez mais verdades t\234m vindo[ENTER]ao de cima. Agora descobri que as criaturas nesta[ENTER]montanha tamb\233m possuem outros tipos de j\243ias. "
gameforge.collect_quest_lv94._070_say = "\201 relativo \224s belas j\243ias da sabedoria - elas s\227o[ENTER]diamantes excepcionalmente l\237mpidos e puros que[ENTER]aparentemente cont\234m a ess\234ncia da deusa[ENTER]Bahar-Taraji. Lembra-te de manter os olhos bem[ENTER]abertos enquanto vagueias pela gruta. Preciso de[ENTER]20 j\243ias perfeitas.[ENTER]Boa sorte e n\227o me fa\231as esperar muito tempo! "
gameforge.collect_quest_lv94._080_say_title = "J\243ias para Seon-Pyeong "
gameforge.collect_quest_lv94._090_say = "O armeiro e investigador Seon-Pyeong precisa de[ENTER]20 J\243ias da Sabedoria para a sua investiga\231\227o na[ENTER]\225rea das armas. Leva-lhe as J\243ias separadamente[ENTER]para que ele as possa estudar individualmente.[ENTER]Podes obt\234-las dos Arqueiros e Comandantes Setaou. "
gameforge.collect_quest_lv94._100_sayReward = "J\225 conseguiste entregar %s j\243ia(s). "
gameforge.collect_quest_lv94._110_say = "Ainda n\227o podes utilizar o Elixir do Investigador. "
gameforge.collect_quest_lv94._120_say = "J\225 utilizaste um Elixir! "
gameforge.collect_quest_lv94._130_say = "Podes utilizar o Elixir assim que tiveres[ENTER]encontrado uma J\243ia. "
gameforge.collect_quest_lv94._140_send_letter = "Encontraste uma J\243ia "
gameforge.collect_quest_lv94._150_npcChat = "J\243ia da Sabedoria (94) "
gameforge.collect_quest_lv94._160_say = "Tu de novo? Desculpa, mas ainda n\227o acabei de[ENTER]analisar a \250ltima. Volta mais tarde! "
gameforge.collect_quest_lv94._170_say = "Ainda n\227o encontraste nada? Desculpa, mas ent\227o[ENTER]porque est\225s aqui? Vamos l\225, despacha-te! Volta[ENTER]quando me puderes trazer algumas J\243ias. "
gameforge.collect_quest_lv94._180_say = "Encontraste uma J\243ia? Fant\225stico! Espera um[ENTER]segundo, deixa certificar-me... "
gameforge.collect_quest_lv94._190_say = "Oh, que J\243ia maravilhosa. Consegues sentir o[ENTER]calor no teu cora\231\227o? A paz? \201 tudo obra desta[ENTER]J\243ia... Muito obrigado! "
gameforge.collect_quest_lv94._200_say = "Mas como j\225 sabes preciso de mais %s J\243ias desta[ENTER]qualidade. D\225-me um dia para analisar esta[ENTER]completamente. Depois disso poder\225s trazer-me[ENTER]outra. "
gameforge.collect_quest_lv94._210_say = "Boa sorte! "
gameforge.collect_quest_lv94._230_1_select = "+1100 Vida "
gameforge.collect_quest_lv94._230_2_select = "+140 Defesa "
gameforge.collect_quest_lv94._230_3_select = "+60 Ataque "
gameforge.collect_quest_lv94._240_say = "Hum... \201 um belo diamante, sem d\250vida. Mas n\227o me[ENTER]parece ter uma aura divina. Infelizmente n\227o me[ENTER]ir\225 ajudar. Arranja-me outro! E n\227o te esque\231as[ENTER]que mesmo assim preciso de algum tempo para[ENTER]analisar este detalhadamente. "
gameforge.collect_quest_lv94._250_say = "Tu conseguiste mesmo! 20 J\243ias da Sabedoria...[ENTER]Estou impressionado![ENTER]Mas infelizmente isto por si s\243 n\227o \233 suficiente.[ENTER]Aquilo que preciso agora, para me ajudar a[ENTER]compreender realmente a origem do poder das[ENTER]J\243ias, \233 uma Pedra-Esp\237rita: A Pedra-Esp\237rita do[ENTER]Lorde da Gruta - o Drag\227o Beran-Setaou. "
gameforge.collect_quest_lv94._260_send_letter = "O Pedido de Seon-Pyeong "
gameforge.collect_quest_lv94._270_say_title = "A Pedra-Esp\237rita do Drag\227o "
gameforge.collect_quest_lv94._280_say = "Conseguiste obter a Pedra-Esp\237rita do Drag\227o.[ENTER]Leva-a ao Seon-Pyeong que se encontra na entrada[ENTER]da Gruta das Almas. "
gameforge.collect_quest_lv94._290_say_title = "A Pedra-Esp\237rita do Drag\227o "
gameforge.collect_quest_lv94._300_say = "Entregaste as 20 J\243ias da Sabedoria ao[ENTER]Seon-Pyeong no Vale Seungryong. Agora ele apenas[ENTER]precisa da Pedra-Esp\237rita do Drag\227o. "
gameforge.collect_quest_lv94._310_say = "Podes obt\234-la do Drag\227o Beran-Setaou. "
gameforge.collect_quest_lv94._320_send_letter = "Recebeste a Pedra-Esp\237rita do Drag\227o. "
gameforge.collect_quest_lv94._330_npcChat = "Tenho a Pedra-Esp\237rita do Drag\227o! "
gameforge.collect_quest_lv94._340_say = "Isto \233... incr\237vel. A Pedra-Esp\237rita do Drag\227o![ENTER]Eu curvo-me perante ti por este teu grande feito![ENTER]Agora nada me impede de continuar a minha[ENTER]investiga\231\227o - e irei dar-te uma recompensa[ENTER]generosa. Escolhe uma! "
gameforge.collect_quest_lv94._350_say = "Tens a Pedra-Esp\237rita do Drag\227o? Ent\227o porque \233[ENTER]que n\227o a estou a ver?! N\227o tentes enganar-me...[ENTER]Sei que te dei uma tarefa muito dif\237cil, mas[ENTER]tenho a certeza que a conseguir\225s completar! "
gameforge.couple_ring = {}
gameforge.couple_ring._100_sendLetter = "Derrota as Jin-Hees "
gameforge.couple_ring._10_npcChat = "Vingar o Vendedor de An\233is "
gameforge.couple_ring._110_sayReward = "A Idosa pediu a tua ajuda: o seu amigo, o[ENTER]Vendedor de An\233is, foi assassinado pelas Jin-Hee,[ENTER]as guerreiras de elite do Cl\227 Jura de Cristal.[ENTER]Vinga a morte do Vendedor de An\233is matando 30[ENTER]Jin-Hee. "
gameforge.couple_ring._120_sayReward = "N\250mero de Jin-Hee em falta "
gameforge.couple_ring._130_say = "Oh, vejo que lutaste contra as Jin-Hee? E[ENTER]obviamente n\227o conseguiste derrotar todas. Eu[ENTER]conhe\231o a sua for\231a e habilidades - n\227o \233 um[ENTER]trabalho f\225cil.  "
gameforge.couple_ring._140_say = "A fam\237lia do Vendedor de An\233is entrou num luto[ENTER]profundo ap\243s a sua morte. Seria muito nobre da[ENTER]tua parte se pudesses vingar a sua morte para os[ENTER]ajudares a ultrapassar a sua perda. "
gameforge.couple_ring._150_say = "\201 uma pena que n\227o queiras vingar a morte do[ENTER]Vendedor de An\233is. Mas \233 \243bvio que todas as vidas[ENTER]t\234m o seu valor e \233 claro que d\225s valor \224 tua[ENTER]pr\243pria vida. "
gameforge.couple_ring._160_say = "Conseguiste ver algo nas m\227os da idosa enquanto[ENTER]ela se virava. Era um objecto reluzente. Parecia[ENTER]ser uma pedra valiosa. "
gameforge.couple_ring._170_select = "Vou tentar de novo. "
gameforge.couple_ring._180_say = "N\227o estou interessada em pedras preciosas. Eu[ENTER]quero que o Vendedor de An\233is seja vingado para[ENTER]que a sua fam\237lia sofra menos pela sua perda.[ENTER]Ainda bem que reconsideraste e decidiste[ENTER]completar a miss\227o. "
gameforge.couple_ring._190_say = "Sinto muito pela fam\237lia do Vendedor de An\233is. \201[ENTER]pena que n\227o tenhas aceite o desafio. "
gameforge.couple_ring._200_sendLetter = "Regressa \224 Idosa "
gameforge.couple_ring._20_sayTitle = "Idosa "
gameforge.couple_ring._210_say = "Regressa \224 Idosa e diz-lhe que vingaste a morte[ENTER]do Vendedor de An\233is matando as 30 Jin-Hee. "
gameforge.couple_ring._220_npcChat = "Derrotaste as 30 Jin-Hee! "
gameforge.couple_ring._230_say = "Derrotaste todas as Jin-Hee. Muito bem! O[ENTER]Vendedor de An\233is deve estar satisfeito agora.[ENTER]Este \233 o anel que ele me confiou. Tu merece-lo.[ENTER]Esta \233 a tua recompensa por vingares a sua morte.[ENTER]Tenho a certeza que ele quereria que assim fosse. "
gameforge.couple_ring._240_sayReward = "Recebeste um Anel de Casal. "
gameforge.couple_ring._250_sayItem = "Anel de Casal "
gameforge.couple_ring._255_sayItem = "O anel simboliza um casamento iminente. "
gameforge.couple_ring._30_say = "\201s agora um dos guerreiros desta vila. Se eu ao[ENTER]menos soubesse como podes utilizar as tuas rec\233m[ENTER]descobertas habilidades... J\225 ouviste falar nas[ENTER]Jin-Hee? S\227o um grupo de muito perigosas[ENTER]guerreiras de elite. Uma delas matou o nosso[ENTER]vendedor de an\233is. O vendedor era n\227o s\243 um amigo[ENTER]meu como um homem justo que vendia j\243ias a jovens[ENTER]casais que pretendiam casar-se. Est\225s pronto para[ENTER]vingar a sua morte? Para o fazeres tens de matar[ENTER]30 Jin-Hee... "
gameforge.couple_ring._40_select = "Irei vingar o Vendedor de An\233is. "
gameforge.couple_ring._50_select = "N\227o, as Jin-Hee s\227o muito fortes para mim. "
gameforge.couple_ring._60_say = "A tua decis\227o \233 boa e honrada! Mas lembra-te,[ENTER]ter\225s de matar 30 Jin-Hees.[ENTER]Mas aten\231\227o, elas s\227o espertas e sabem onde se[ENTER]esconder! "
gameforge.couple_ring._70_say = "Tenho pena da tua decis\227o, mas tamb\233m tens raz\227o.[ENTER]A bravura desmesurada rapidamente leva \224 morte.[ENTER]Continuamo-nos a ver por a\237. "
gameforge.couple_ring._75_say = "N\250mero de Jin-Hee em falta "
gameforge.couple_ring._80_sayTitle = "Derrotaste todas as Jin-Hee "
gameforge.couple_ring._90_say = "A morte do vendedor de an\233is foi vingada. Assim[ENTER]sendo a miss\227o foi completada. "
