gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "Lasca de Pedra do Drag\227o?! "
gameforge.dragon_soul._020_say = "Nas tuas m\227os tens a lasca de uma pedra. Ela[ENTER]brilha, repleta de segredos, e podes sentir o seu[ENTER]poder a correr atrav\233s de ti.[ENTER]Que tipo de pedra \233? Leva-a ao alquimista. Ele[ENTER]poder\225 ajudar-te melhor. "
gameforge.dragon_soul._030_npcChat = "Lasca de Pedra do Drag\227o?! "
gameforge.dragon_soul._040_say = "Esta \233 uma lasca de uma Pedra do Drag\227o - um[ENTER]cristal extremamente raro e valioso, e detentor[ENTER]de um grande poder. Diz-se que tal pedra \233 a alma[ENTER]de um drag\227o. Inacreditavelmente bela![ENTER]Sentes o seu poder atravessar-te assim que lhe[ENTER]pegas?[ENTER]Traz-me dez destas Lascas de Pedra do Drag\227o.[ENTER]Poderei torn\225-las numa pedra completa. "
gameforge.dragon_soul._050_npcChat = "Transmuta\231\227o de Pedra do Drag\227o "
gameforge.dragon_soul._060_say = "N\227o sejas t\227o impaciente. Apenas posso transmutar[ENTER]dez lascas numa Pedra do Drag\227o. Continua \224[ENTER]procura! "
gameforge.dragon_soul._070_say = "Ah, muito bem! Encontraste dez Lascas de Pedra do[ENTER]Drag\227o. Por favor aguarda um momento.[ENTER]...[ENTER]Est\225 feito! Olha olha, conseguimos criar um Cor[ENTER]Draconis durante o processo - um cora\231\227o de[ENTER]drag\227o cristalino que rodeia e protege a Pedra do[ENTER]Drag\227o.[ENTER]Parte-o para o abrires e descobrires que Pedra[ENTER]cont\233m. Ser\225 movida directamente para o[ENTER]invent\225rio de Alquimia de Pedra de Drag\227o.[ENTER]Sabes que tamb\233m podes refinar as Pedras do[ENTER]Drag\227o? "
gameforge.dragon_soul._080_say = "Gostarias de receber outro Cor Draconis? Bah, os[ENTER]meus tempos \225ureos j\225 l\225 v\227o e o processo de[ENTER]produ\231\227o de um item t\227o complexo gasta as minhas[ENTER]energias. Mas irei tent\225-lo por ti. No entanto,[ENTER]mesmo no meu melhor, n\227o conseguirei produzir[ENTER]mais de dez por dia! "
gameforge.dragon_soul._090_say = "J\225 chega por hoje. Simplesmente n\227o aguento[ENTER]produzir mais de dez por dia. As minhas for\231as[ENTER]est\227o esgotadas e preciso de descansar. Volta[ENTER]amanh\227. "
gameforge.dragon_soul._100_npcChat = "Abrir Loja "
gameforge.dragon_soul._1010_sendLetter = "Chegada da Lasca de Pedra do Drag\227o "
gameforge.dragon_soul._1020_say = "O alquimista de minerais mais s\225bio de todo o[ENTER]reino anda \224 tua procura. Vai ter com ele assim[ENTER]que poss\237vel! "
gameforge.dragon_soul._1030_npcChat = "Lasca de Pedra do Drag\227o?! "
gameforge.dragon_soul._1040_say = "Ah, a\237 est\225s tu! Descobri algo muito[ENTER]impressionante: a lasca de uma Pedra do Drag\227o![ENTER]Uma Pedra do Drag\227o \233 um cristal extremamente[ENTER]raro e valioso que cont\233m um grande poder. Diz-se[ENTER]que outrora foram a alma de um drag\227o.[ENTER]Inacreditavelmente belo! Irei dar-te o Poder do[ENTER]Olho do Drag\227o, para que tamb\233m possas detectar[ENTER]as lascas.[ENTER]Traz-me um total de dez Lascas de Pedra do[ENTER]Drag\227o. Irei ent\227o transmut\225-las para formar uma[ENTER]pedra completa. "
gameforge.dragon_soul._1050_sendLetter = "Obt\233m Lascas de Pedra do Drag\227o "
gameforge.dragon_soul._1060_say = "Leva 10 Lascas de Pedra do Drag\227o ao alquimista. "
gameforge.dragon_soul._1070_say = "Ah, muito bem! Encontraste 10 Lascas de Pedra do[ENTER]Drag\227o. Por favor aguarda um momento.[ENTER]...[ENTER]Incr\237vel! A transmuta\231\227o resultou num Cor[ENTER]Draconis - um cora\231\227o de drag\227o cristalino, que[ENTER]rodeia e protege a Pedra do Drag\227o. Quando o[ENTER]partires para o abrir, a Pedra do Drag\227o no seu[ENTER]interior ir\225 directamente para o invent\225rio de[ENTER]Alquimia de Pedra do Drag\227o.[ENTER]Para encontrares Lascas de Pedra do Drag\227o, ir\225s[ENTER]precisar do Poder do Olho do Drag\227o. Posso[ENTER]emprestar-to - apenas tens de vir ter comigo[ENTER]todos os dias. Ent\227o tamb\233m tu poder\225s efectuar a[ENTER]transmuta\231\227o de Pedras do Drag\227o![ENTER]J\225 te criei uma hoje, as restantes %d podes tu[ENTER]mesmo encarregar-te delas. "
gameforge.dragon_soul._1080_say = "Hey, n\227o percas tempo! Parte em busca das Lascas[ENTER]de Pedra do Drag\227o! "
gameforge.dragon_soul._1090_sendLetter = "Poder do Olho do Drag\227o "
gameforge.dragon_soul._1100_say = "Poder do Olho do Drag\227o Restante: %d "
gameforge.dragon_soul._110_say = "Seleccionar. "
gameforge.dragon_soul._1110_notice = "Es gibt keine Drachensteinsplitter mehr "
gameforge.dragon_soul._1120_npcChat = "D\225-me o Poder do Olho do Drag\227o "
gameforge.dragon_soul._1130_say = "Ol\225! J\225 recebeste o Poder do Olho do Drag\227o hoje.[ENTER]O processo enfraquece-me tanto que apenas te[ENTER]posso ajudar uma vez por dia. Volta amanh\227! "
gameforge.dragon_soul._1140_say = "Ol\225! Aposto que est\225s aqui por causa do Poder do[ENTER]Olho do Drag\227o. Certo? Muito bem ent\227o, aqui[ENTER]tens.[ENTER]Boa sorte na tua busca! Espero que encontres[ENTER]Lascas suficientes para 10 Pedras do Drag\227o! "
