gameforge.energy_system._001_npcChat = "Uma nova tecnologia! "
gameforge.energy_system._010_say = "Consegui![ENTER]Finalmente consegui desenvolver uma tecnologia[ENTER]completamente nova.[ENTER]Sou agora capaz de processar itens e extrair[ENTER]deles energia pura. \201 brilhante! "
gameforge.energy_system._020_say = "Se destru\237res um item com a minha nova[ENTER]tecnologia, ir\225s receber um Fragmento de Energia.[ENTER]Se juntares 30 destes Fragmentos, ir\225s receber um[ENTER]Cristal de Energia! \201 energia pura contida numa[ENTER]pedra preciosa. Este poder ir\225 fluir por todo o[ENTER]teu equipamento.[ENTER]Est\225s interessado? "
gameforge.energy_system._030_say = "Traz-me equipamento que encontres nas tuas[ENTER]ca\231adas, como armas, j\243ias e armaduras. Irei[ENTER]process\225-los e transform\225-los em Fragmentos de[ENTER]Energia.[ENTER]O futuro e esperan\231a do nosso reino est\227o[ENTER]dependentes desta tecnologia. Iremos ser[ENTER]invenc\237veis! "
gameforge.energy_system._035_npcChat = "Extrair Fragmentos de Energia "
gameforge.energy_system._040_say = "Funcionou? Recebeste Fragmentos de Energia?[ENTER]Traz-me mais itens e irei destru\237-los utilizando[ENTER]a minha alquimia. A minha tecnologia ainda n\227o[ENTER]foi aperfei\231oada. Por isso n\227o posso garantir[ENTER]quantos fragmentos ir\225s receber. "
gameforge.energy_system._050_say = "Existe uma condi\231\227o: o teu n\237vel e o n\237vel do[ENTER]item t\234m de ser no m\237nimo 35.[ENTER]Hm, vamos l\225 ver... "
gameforge.energy_system._060_say = "Ainda n\227o \233s suficientemente forte! Volta quando[ENTER]tiveres atingido, no m\237nimo, o n\237vel 35. "
gameforge.energy_system._070_say = "Ah, excelente! \201s forte e experiente.[ENTER]D\225-me o item que pretendes processar. "
gameforge.energy_system._080_say = "N\227o \233s suficientemente forte para controlar o[ENTER]poder contido nestes Fragmentos de Energia. Volta[ENTER]quando tiveres atingido, no m\237nimo, o n\237vel 35. "
gameforge.energy_system._090_say = "Este item n\227o \233 apropriado para a minha[ENTER]tecnologia. Traz-me algo diferente. "
gameforge.energy_system._100_say = "Este item n\227o possui energia suficiente. Traz-me[ENTER]um item com um n\237vel m\237nimo de 35 - \233 a \250nica[ENTER]forma de poder usar a minha tecnologia para[ENTER]extrair a energia de itens. "
gameforge.energy_system._110_say = "Devo destruir este item? "
gameforge.energy_system._120_select = "Sim "
gameforge.energy_system._130_select = "N\227o, ainda n\227o! "
gameforge.energy_system._140_say = "Falhei - infelizmente n\227o consegui extrair[ENTER]qualquer Fragmento de Energia. Talvez tenha sorte[ENTER]da pr\243xima vez. "
gameforge.energy_system._150_say = "Maravilhoso! Consegui encontrar %d Fragmento(s)[ENTER]de Energia.[ENTER]Aqui tens. "
gameforge.energy_system._160_npcChat = "Produzir Cristal de Energia "
gameforge.energy_system._170_say = "J\225 usaste todas as tuas reservas de energia? N\227o[ENTER]devias trabalhar t\227o duro e colocar a tua vida em[ENTER]risco de forma t\227o despreocupada.[ENTER]Irei precisar de %d Fragmentos de Energia para[ENTER]produzir um Cristal de Energia. "
gameforge.energy_system._180_say = "N\227o tens Fragmentos de Energia suficientes. Assim[ENTER]n\227o consigo produzir um Cristal de Energia.[ENTER]Volta quando tiveres obtido pelo menos %d[ENTER]Fragmentos. "
gameforge.energy_system._190_say = "Muito bem, conseguiste obter os %d Fragmentos de[ENTER]Energia necess\225rios. Com eles posso agora[ENTER]produzir um Cristal de Energia. Por favor espera[ENTER]um minuto. Vou tentar, mas n\227o garanto que[ENTER]funcione. "
gameforge.energy_system._200_say = "Tenho tudo pronto para derreter os Fragmentos e[ENTER]formar um Cristal de Energia. No entanto, tenho[ENTER]de viver de alguma coisa, e as minhas ferramentas[ENTER]n\227o caem do c\233u. Preciso de uma pequena taxa de[ENTER]%d Yang. Queres pagar? "
gameforge.energy_system._210_select = "Naturalmente. "
gameforge.energy_system._220_select = "N\227o, para j\225 n\227o. "
gameforge.energy_system._230_say = "Muito bem, respeito a tua decis\227o.[ENTER]Volta quando tiveres mudado de ideias e queiras[ENTER]um Cristal de Energia. "
gameforge.energy_system._240_say = "Desculpa, mas tens de pagar primeiro. N\227o fa\231o[ENTER]isto por caridade. O neg\243cio \233 assim - d\225-me o[ENTER]dinheiro e ent\227o farei o meu trabalho. "
