gameforge.find_squareguard._10_targetVid = "Guarda da Cidade: "
gameforge.find_squareguard._110_sayTitle = "Guarda da Cidade: "
gameforge.find_squareguard._120_say = "Podes obter a Po\231\227o Vermelha da Negociadora da[ENTER]Loja Geral. Ela est\225 ali. Se n\227o a conseguires[ENTER]ver, dirige-te ao circulo a piscar no mapa grande[ENTER]ou ao ponto a piscar no mini-mapa! "
gameforge.find_squareguard._130_sayTitle = "Loja Geral: "
gameforge.find_squareguard._131_targetVid = "Loja Geral: "
gameforge.find_squareguard._140_say = "Bem-vindo aventureiro![ENTER]Oh, o Guarda da Cidade enviou-te? Ele precisa de[ENTER]uma Po\231\227o Vermelha? Vou dar-te cinco.[ENTER]Aqui tens. Estas Po\231\245es servem para regenerar a[ENTER]tua Vida e s\227o bastante saborosas. "
gameforge.find_squareguard._150_say = "Podes ser novo, mas tenho a certeza que te[ENTER]tornar\225s um cliente regular. \201 por isso que te[ENTER]ofere\231o estas po\231\245es a custo zero. Espero ver-te[ENTER]de novo. "
gameforge.find_squareguard._160_sayReward = "Recebeste 5 Po\231\245es Vermelhas(P) da Negociadora da[ENTER]Loja Geral. "
gameforge.find_squareguard._170_sayReward = "As Po\231\245es Vermelhas servem para a regenera\231\227o dos[ENTER]teus Pontos de Vida (VD). "
gameforge.find_squareguard._180_sendLetter = "Regressa ao Guarda da Cidade "
gameforge.find_squareguard._190_sayReward = "Regressa ao Guarda da Cidade e d\225-lhe uma Po\231\227o[ENTER]Vermelha. "
gameforge.find_squareguard._200_say = "N\227o conseguiste a Po\231\227o Vermelha(P) que eu te[ENTER]pedi? Que pena! Ok... podes ficar com o Yang para[ENTER]as tuas necessidades.[ENTER]J\225 agora... Os Professores perguntaram por ti.[ENTER]Eles querem conhecer-te. "
gameforge.find_squareguard._20_sayReward = "Vai at\233 ao centro da vila e fala com o Guarda da[ENTER]Cidade. Ele ir\225 dar-te a primeira miss\227o.[ENTER]Podes encontr\225-lo no centro da vila. "
gameforge.find_squareguard._210_say = "Obrigado por me trazeres a po\231\227o! Agora posso[ENTER]cumprir melhor o meu dever e nem precisei de[ENTER]abandonar o meu posto. Queres saber o que fa\231o?[ENTER]Bem, geralmente eu limito-me a anunciar[ENTER]informa\231\245es importantes. Por vezes tamb\233m ofere\231o[ENTER]os meus servi\231os a pessoas com problemas ou que[ENTER]est\227o sob ataque. Mas o meu trabalho principal \233[ENTER]gerir as Guilds. Vem ter comigo se tiveres[ENTER]interesse em juntar-te ou fundar uma Guild. "
gameforge.find_squareguard._220_say = "J\225 agora, os Professores andam \224 tua procura.[ENTER]Devias ir ter com eles agora.[ENTER]Ah, e quase me esquecia! Como s\237mbolo da minha[ENTER]gratid\227o podes ficar com o troco! At\233 breve. "
gameforge.find_squareguard._30_sayTitle = "Guarda da Cidade: "
gameforge.find_squareguard._40_say = "Bem-vindo \224 nossa vila, aventureiro! Ficaria[ENTER]muito grato se me fizesses um favor. Se te der[ENTER]200 Yang podes comprar-me uma Po\231\227o Vermelha?[ENTER]Podes compr\225-la na Loja Geral.[ENTER]Neste momento estou a trabalhar, por isso n\227o[ENTER]posso abandonar o centro da vila. "
gameforge.find_squareguard._50_select = "Sim "
gameforge.find_squareguard._60_sayReward = "Recebeste 200 Yang do Guarda da Cidade. Podes[ENTER]usar Yang para comprar itens e servi\231os a outros[ENTER]habitantes da vila. Vai ter com a Negociadora da[ENTER]Loja Geral e compra uma Po\231\227o Vermelha. "
