gameforge.ghost_story._060_npcChat = "Quem \233s tu? "
gameforge.ghost_story._070_say = "O meu nome \233 Akuma. Eu era um grande guerreiro,[ENTER]alguns dizem que eu era o melhor de todos os[ENTER]tempos. At\233 eu pr\243prio acreditava nisso. Mas olha[ENTER]para mim agora. Olha para o que restou de mim[ENTER]desde que eu descobri a gruta...e deixar de[ENTER]existir. "
gameforge.ghost_story._080_npcChat = "Tu sabes a hist\243ria deste sitio? "
gameforge.ghost_story._090_say = "Oh, eu sei o que aconteceu. Durante muito tempo[ENTER]investiguei, procurando a raz\227o por detr\225s de[ENTER]tudo isto e tentando encontrar a Gruta. E desde[ENTER]que morri tenho tido muito tempo para pensar.[ENTER]Pergunta-me o que quiseres saber! "
gameforge.ghost_story._100_npcChat = "Que tipo de portal \233 este? "
gameforge.ghost_story._110_say = "Este portal conduz-te at\233 aos aposentos do[ENTER]Drag\227o, o ca\237do Deus Beran-Setaou. Ele pode ser[ENTER]activado com uma chave m\225gica que apenas as[ENTER]tropas de Beran-Setaou conseguem obter... "
gameforge.ghost_story._120_npcChat = "Os Tr\234s Deuses "
gameforge.ghost_story._130_say = "Era uma vez, tr\234s Deuses irm\227os que criaram as[ENTER]funda\231\245es do ser.[ENTER]Bahar-Taraji, a Deusa da Cria\231\227o, era a mais nova[ENTER]dos tr\234s. A sua fun\231\227o era criar novos seres -[ENTER]onde quer que ela fosse, as flores desabrochavam[ENTER]e a vida prosperava. "
gameforge.ghost_story._140_say = "O irm\227o mais velho chamava-se Beran-Setaou. Ele[ENTER]era respons\225vel pelo fim da vida e a sua[ENTER]dissolu\231\227o. Sempre que o ciclo da vida estava no[ENTER]final, ele separava o corpo e a alma um do outro[ENTER]e guiava a alma para a vida depois da morte.[ENTER]E assim um ciclo constante de nascer e morrer - a[ENTER]funda\231\227o de toda a vida - foi assegurada. "
gameforge.ghost_story._150_say = "O irm\227o do meio era Baljit-Elvedin. Como Deus da[ENTER]Conserva\231\227o, ele moderava aquilo que os seus[ENTER]irm\227os faziam e permitia a exist\234ncia de um ciclo[ENTER]da vida eterno para todas as criaturas do mundo.[ENTER]Por exemplo, ele era respons\225vel pelas Esta\231\245es[ENTER]do ano. "
gameforge.ghost_story._160_npcChat = "A Discuss\227o "
gameforge.ghost_story._170_say = "Em tempos de necessidade, as pessoas rezavam aos[ENTER]tr\234s Deuses por ajuda. Mas, infelizmente, todos[ENTER]temiam e desprezavam Beran-Setaou, uma vez que[ENTER]eram incapazes de compreender que, tal como[ENTER]existe luz tamb\233m existe escurid\227o, ele era[ENTER]necess\225rio como contrapartida da Cria\231\227o. "
gameforge.ghost_story._180_say = "Durante bastante tempo o Deus ignorou tudo isso,[ENTER]mas \224 medida que os anos iam passando, a inveja[ENTER]crescia dentro dele, tornando-se em \243dio e[ENTER]malevol\234ncia. Primeiro ele dirigia a sua f\250ria[ENTER]para as pessoas, dando-lhes guerra e doen\231as. Mas[ENTER]isto apenas fez com que as pessoas o rejeitassem[ENTER]ainda mais e dirigissem as suas preces para[ENTER]Bahar-Taraji, Deusa da Cria\231\227o e da Vida. E assim[ENTER]come\231ou um ciclo vicioso que acabou por levar \224[ENTER]ru\237na. "
gameforge.ghost_story._190_say = "E quando a ira do Deus se tornou t\227o intensa que[ENTER]ele j\225 nem era capaz de a controlar, algo[ENTER]inacredit\225vel aconteceu: Ele matou a sua irm\227, a[ENTER]preferida de todos. N\227o houve qualquer provoca\231\227o[ENTER]que tenha levado a este acto, pois nesse dia ela[ENTER]tratou o seu irm\227o com o mesmo amor e carinho de[ENTER]todos os dias. E ele, olhando para aqueles olhos[ENTER]gentis, tirou-lhe a vida na mesma. "
gameforge.ghost_story._200_npcChat = "As Consequ\234ncias "
gameforge.ghost_story._210_say = "A morte de Bahar-Taraji teve terr\237veis[ENTER]consequ\234ncias, tanto para o mundo dos Deuses como[ENTER]o dos Humanos: Um longo e cruel Inverno[ENTER]instalou-se, matando criaturas do mar e da terra.[ENTER]O continente congelou de tal forma que as pedras[ENTER]ficaram rachadas e mesmo as \225rvores mais antigas[ENTER]e fortes secaram. "
gameforge.ghost_story._220_say = "Pessoas jovens e animais morreram, e quando[ENTER]finalmente o clima come\231ou a reaquecer, a taxa de[ENTER]nascimentos era a mais baixa de sempre. Os campos[ENTER]fracos n\227o produziam o suficiente para manter as[ENTER]pessoas alimentadas - quanto mais permitir a[ENTER]alimenta\231\227o de novas vidas. A esperan\231a morreu,[ENTER]tal como a vida, e ambas precisariam de muito[ENTER]tempo para recuperar completamente. "
gameforge.ghost_story._230_say = "At\233 os Deuses sofreram, pois o tempo passa mais[ENTER]devagar para eles. Beran-Setaou fugiu e[ENTER]refugiou-se na sua solid\227o assim que compreendeu[ENTER]as consequ\234ncias do que tinha feito. Os seus[ENTER]sentimentos debatiam-se entre pesados remorsos e[ENTER]uma profunda satisfa\231\227o - at\233 que finalmente o[ENTER]segundo venceu este combate mental. O seu cora\231\227o[ENTER]gelou e o Deus da Dissolu\231\227o tornou-se o Deus do[ENTER]Gelo e da Frieza, do \211dio e do Medo. "
gameforge.ghost_story._240_npcChat = "A Batalha "
gameforge.ghost_story._250_say = "Baljit-Elvedin, Deus da Conserva\231\227o, chorou a[ENTER]morte da sua irm\227 durante muito tempo. E quando[ENTER]as fortes garras da dor finalmente se afrouxaram[ENTER]em volta do seu cora\231\227o, ele foi \224 procura do seu[ENTER]irm\227o. A prud\234ncia e sabedoria ainda guiavam a[ENTER]sua vida, por isso reconheceu que, apesar da sua[ENTER]dor, a vida no mundo n\227o podia continuar[ENTER]desequilibrada. "
gameforge.ghost_story._260_say = "Ele seguiu o rasto do seu irm\227o, e ao fim de[ENTER]v\225rios anos finalmente encontrou-o, h\225 muito sem[ENTER]contactar com qualquer forma de vida, numa[ENTER]caverna repleta de gelo, \243dio e solid\227o.[ENTER]Baljit-Elvedin fez o que tinha de fazer, apesar[ENTER]de isso apenas provocar mais uma ferida no seu[ENTER]cora\231\227o: Desafiou o irm\227o para um duelo.[ENTER]Beran-Setaou desviou-se tanto do caminho da honra[ENTER]que n\227o hesitou um segundo sequer... "
gameforge.ghost_story._270_say = "Aparentemente, o combate foi terr\237vel e para al\233m[ENTER]de toda a compreens\227o. Baljit-Elvedin venceu o[ENTER]combate. E mantendo-se fiel aos seus valores[ENTER]morais, n\227o matou o seu irm\227o, mas removeu-lhe[ENTER]todos os seus poderes e selou-o na Gruta. E assim[ENTER]esta ainda \233 a casa de Beran-Setaou, assim como[ENTER]de todas as criaturas que ele tem criado nos[ENTER]\250ltimos s\233culos... "
gameforge.ghost_story._280_npcChat = "J\225 ouvi o suficiente. "
gameforge.ghost_story._290_say = "Que o teu destino seja diferente do meu. Boa[ENTER]sorte! "
gameforge.ghost_story._300_sayTitle = "Fantasma de um guerreiro: "
gameforge.ghost_story._310_npcChat = "Porque \233s transparente? "
gameforge.ghost_story._320_say = "O que achas?! Sou um fantasma e estou preso a[ENTER]esta rocha h\225 milhares de anos... "
gameforge.ghost_story._330_say = "Socorro, um fantasma! "
gameforge.ghost_story._340_say = "Claro, um fantasma. Foge r\225pido, ou eu vou-te[ENTER]comer! "
gameforge.ghost_story._350_npcChat = "Quem \233s tu? "
gameforge.ghost_story._360_say = "Eu era um mercen\225rio, um homem simples. Os meus[ENTER]pais eram agricultores. No entanto eu n\227o queria[ENTER]continuar a trabalhar no campo para o resto da[ENTER]minha vida, por isso juntei-me ao ex\233rcito. Foi[ENTER]muito dif\237cil e sangrento, mas nem tudo era mau.[ENTER]S\243 que um dia finalmente cansei-me de receber[ENTER]ordens de nobres in\250teis e abandonei o ex\233rcito.[ENTER]Foi ent\227o que o destino me conduziu at\233 este[ENTER]lugar negro. "
gameforge.ghost_story._370_npcChat = "Conheces a hist\243ria da Gruta? "
gameforge.ghost_story._380_say = "N\227o, n\227o conhe\231o. Acho que apenas tive azar.[ENTER]Depois de desertar queria esconder-me nas[ENTER]montanhas, e encontrei este lugar. Logo \224 partida[ENTER]pareceu-me um s\237tio estranho, mas era conveniente[ENTER]e parecia completamente abandonado. Alguns dias[ENTER]depois tornei-me testemunha e v\237tima de um[ENTER]combate inacredit\225vel. Se quiseres posso[ENTER]contar-te tudo sobre isso. "
gameforge.ghost_story._390_npcChat = "O Inicio da Batalha "
gameforge.ghost_story._400_say = "Um dia - estava eu a colher ra\237zes nas encostas[ENTER]da montanha - surgiu dos c\233us um drag\227o prateado.[ENTER]Pensei que ele andava \224 minha procura, mas ele[ENTER]nem sequer reparou em mim - estava completamente[ENTER]focado na entrada da Gruta. Sem abrandar,[ENTER]atravessou o vale e atirou-se para dentro da[ENTER]Gruta. "
gameforge.ghost_story._410_say = "Tudo ficou calmo por uns minutos e eu n\227o sabia o[ENTER]que fazer. Todo o meu equipamento estava no[ENTER]interior da Gruta, mas eu n\227o me queria cruzar[ENTER]com o drag\227o! Foi ent\227o que o ch\227o come\231ou a[ENTER]tremer e um rugido grave soou das profundezas da[ENTER]Gruta - mas para meu horror n\227o era apenas uma[ENTER]voz, e sim duas! Pouco depois, dois drag\245es[ENTER]sa\237ram disparados da Gruta - um prateado, seguido[ENTER]de um azul. "
gameforge.ghost_story._420_say = "Um combate quase indescrit\237vel teve lugar entre[ENTER]os drag\245es. Eles provocaram rasg\245es no corpo um[ENTER]do outro, enrolaram-se um no outro e ferraram os[ENTER]seus dentes no pesco\231o do outro... Chovia[ENTER]sangue... Mas nem por isso afrouxavam o seu[ENTER]aperto. "
gameforge.ghost_story._430_npcChat = "O Fim da Batalha "
gameforge.ghost_story._440_say = "Os dois drag\245es rolaram pelas montanhas como uma[ENTER]tempestade - causando deslizamentos de terras e[ENTER]caos \224 sua volta. Trov\245es queimaram a boca do[ENTER]drag\227o azul, gelo perfurou as asas do drag\227o[ENTER]prateado. A grossa crosta de gelo que h\225 muitos[ENTER]anos cobria a terra derreteu sob esta[ENTER]carnificina, deixando para tr\225s um res\237duo[ENTER]lamacento. Escondi-me atr\225s de uma rocha,[ENTER]petrificado mas incapaz de ignorar aquilo que se[ENTER]passava \224 minha frente. "
gameforge.ghost_story._450_say = "Passaram v\225rias horas at\233 os seus poderes[ENTER]finalmente come\231arem a enfraquecer. E finalmente[ENTER]vi uma oportunidade, arranquei de l\225 e atravessei[ENTER]o vale para ir buscar o meu equipamento \224 Gruta.[ENTER]E foi dessa forma que selei o meu destino. J\225[ENTER]estava a caminho quando os drag\245es dispararam[ENTER]vindos das montanhas, o azul \224 frente do[ENTER]prateado. Ele tinha sofrido danos terr\237veis. "
gameforge.ghost_story._460_say = "Mesmo antes de desaparecerem no interior da[ENTER]Gruta, o drag\227o prateado apanhou-o e algo muito[ENTER]estranho aconteceu: O c\233u come\231ou a tremeluzir, o[ENTER]ar ficou extremamente seco e um v\243rtice de[ENTER]energia surgiu, apanhando o drag\227o azul. Ele[ENTER]rugia de dor e f\250ria... E ent\227o come\231ou a[ENTER]encolher, o seu rugido ficando cada vez mais[ENTER]fraco e as suas escamas perdendo o seu brilho,[ENTER]at\233 ficarem ba\231as e descoloradas... "
gameforge.ghost_story._470_say = "Finalmente o drag\227o prateado atirou o outro para[ENTER]dentro da Gruta. Com a \250ltima das suas for\231as, o[ENTER]drag\227o azul arrastou-se para os confins da[ENTER]montanha. Mas ent\227o o drag\227o prateado come\231ou a[ENTER]conjurar uma poderosa tempestade m\225gica, selando[ENTER]a Gruta com uma barreira de energia e causando o[ENTER]colapso de parte da montanha. O drag\227o azul e eu[ENTER]fic\225mos presos. Condenados a uma miser\225vel e[ENTER]excruciante morte \224 fome... "
gameforge.ghost_story._480_npcChat = "J\225 ouvi o suficiente. "
gameforge.ghost_story._490_say = "Obrigado por me ouvires. Neste \250ltimos mil anos[ENTER]tenho estado realmente muito sozinho... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Antes de escapar ao Cl\227 Vento Negro encontrei o[ENTER]local onde eles escondem o seu Ouro. L\225 estavam[ENTER]guardadas pilhas de Barras de Ouro! Nem iriam dar[ENTER]pela falta de uma. S\227o uns tolos. Se concordares[ENTER]em contratar-me poderei ir buscar uma Barra de[ENTER]Ouro para ti. Apenas n\227o posso trazer mais de uma[ENTER]Barra de Ouro de cada vez. "
