gameforge.goldbar._280_say = "O qu\234? Queres vender uma Barra d'Ouro? Ainda n\227o[ENTER]ouviste? Neste momento os membros do Cl\227 Vento[ENTER]Negro andam muito desconfiados e est\227o de olhos[ENTER]bem abertos. Se venderes agora a Barra d'Ouro[ENTER]ir\225s ter bastantes problemas. Seria melhor que a[ENTER]deixes onde est\225. Esconde-a bem! "
gameforge.goldbar._290_sayReward = "De momento n\227o podes vender Barras d'Ouro. "
gameforge.goldbar._300_say = "Se quiseres devolver a Barra d'Ouro, "
gameforge.goldbar._30_say = "O qu\234? Uma vitima do Cl\227 Vento Negro? Ha ha ha![ENTER]Ainda \233s uma crian\231a. Onde ouviste isso?[ENTER]Desaparece e vai brincar com os c\227es selvagens! "
gameforge.goldbar._310_say = "precisar\225s de esperar cerca de %s %s. "
gameforge.goldbar._320_say = "N\227o tens Barras d'Ouro. Se me trouxeres Barras[ENTER]d'Ouro irei oferecer-te Yang por elas. "
gameforge.goldbar._330_say = "O qu\234? Queres devolver a tua Barra d'Ouro? Ent\227o[ENTER]para que \233 que a compraste? Se queres tanto[ENTER]devolv\234-la n\227o te impedirei... O Cl\227 Vento Negro[ENTER]guarda os seus tesouros muito bem... N\227o posso[ENTER]fazer isto regularmente. Continuas a querer[ENTER]devolv\234-la? "
gameforge.goldbar._340_select = "Devolver "
