gameforge.goldbar._40_sayReward = "A Miss\227o 'A V\237tima do Cl\227 Vento Negro' est\225[ENTER]dispon\237vel apenas a jogadores de n\237vel 30 ou[ENTER]superior. "
gameforge.goldbar._50_say = "Tem cuidado! Os membros do Cl\227 Vento Negro est\227o[ENTER]extra-cautelosos. Ser\225 melhor n\227o darmos nas[ENTER]vistas. Adeus. "
gameforge.goldbar._60_sayReward = "A Miss\227o 'A V\237tima do Cl\227 Vento Negro' n\227o se[ENTER]encontra dispon\237vel de momento. "
gameforge.goldbar._70_say = "Shh! Podem existir membros do Cl\227 Vento Negro[ENTER]escondidos por a\237. Onde ouviste isso? N\227o, est\225[ENTER]bem. N\227o \233 importante. Sabes o que se passa? "
