gameforge.guild_building._10_sayTitle = "Dono do Terreno: "
gameforge.guild_building._110_say = "Volta quando decidires o que fazer. Lembra-te que[ENTER]outros podem compr\225-lo primeiro. "
gameforge.guild_building._20_say = "Sou o Agente do Terreno e o respons\225vel pela[ENTER]venda. Antes dos monstros terem ocupado a regi\227o[ENTER]no centro do continente, n\227o havia falta de[ENTER]terrenos e todos estavam contentes. Por isso[ENTER]agora apenas vendo terrenos a l\237deres de Guilds.[ENTER]Queres comprar o terreno? "
