gameforge.guild_building_alter_of_power._170_say = "N\227o h\225 nada que possa fazer por ti: a tua Guild[ENTER]j\225 possui o melhor Altar do Poder. "
gameforge.guild_building_alter_of_power._180_say = "O Altar do Poder permite \224 tua Guild aceitar mais[ENTER]membros. "
gameforge.guild_building_alter_of_power._20_say = "Sou Yaholo, o Guarda do Altar do Poder.[ENTER]Este edif\237cio permite \224 tua Guild aceitar mais[ENTER]membros. \192 medida que a tua Guild se torna mais[ENTER]forte, poder\225s construir um Altar do Poder maior[ENTER]e ent\227o poder\225s convidar ainda mais membros. "
