gameforge.guild_building_npc._10_sayTitle = "Armeiro Iseul: "
gameforge.guild_building_npc._20_say = "Oh, \233s um membro da minha Guild! Se quiseres[ENTER]melhorar as tuas Armas, tr\225-las at\233 mim, e n\227o[ENTER]\224quele Ferreiro principiante da vila. A minha[ENTER]taxa de sucesso \233 10% maior. Al\233m disso os nossos[ENTER]membros t\234m 5% de desconto. Apenas tens de me dar[ENTER]a Arma que pretendes melhorar e eu irei deitar[ENTER]m\227os ao trabalho. "
gameforge.guild_building_npc._30_say = "Sou o Armeiro Iseul, respons\225vel pelo[ENTER]melhoramento de Armas. Sou muito melhor que o[ENTER]Ferreiro da vila! O meu trabalho aumenta a[ENTER]probabilidade de sucesso em 10%. D\225-me a Arma que[ENTER]pretendes melhorar. "
gameforge.guild_building_npc._40_sayTitle = "Ferreiro Haneul: "
gameforge.guild_building_npc._50_say = "Ah, \233s um membro da minha Guild! Isto significa[ENTER]que podes dar-me Armaduras, Escudos, Sapatos e[ENTER]Elmos para eu os melhorar. A minha taxa de[ENTER]sucesso \233 10% maior que a daquele Ferreiro da[ENTER]vila! Al\233m disso, dou um desconto de 5% a membros[ENTER]da minha Guild. Apenas tens de me dar o[ENTER]equipamento que pretendes melhorar. "
gameforge.guild_building_npc._60_say = "O meu nome \233 Haneul. Sou respons\225vel pelo[ENTER]melhoramento de Armaduras, Escudos, Sapatos e[ENTER]Elmos. E sou muito melhor que o Ferreiro da Vila:[ENTER]a minha taxa de sucesso \233 10% maior. D\225-me o[ENTER]equipamento que pretendes que eu tente melhorar. "
gameforge.guild_building_npc._70_sayTitle = "Ourives Seung: "
gameforge.guild_building_npc._80_say = "Ah, \233s um membro da minha Guild! Se me deixares[ENTER]melhorar os teus acess\243rios ter\225s mais 10% de[ENTER]probabilidade de melhoramento - as minhas[ENTER]especialidades s\227o Sapatos, Pulseiras, Brincos e[ENTER]Colares. D\225-me o acess\243rio que pretendes[ENTER]melhorar. "
gameforge.guild_building_npc._90_say = "Sou o Ourives Seung, respons\225vel pelo[ENTER]melhoramento de acess\243rios - as minhas[ENTER]especialidade s\227o Sapatos, Brincos, Colares e[ENTER]Pulseiras. E sou muito melhor que o Ferreiro da[ENTER]vila! O meu trabalho aumenta a probabilidade de[ENTER]sucesso em 10%. D\225-me o acess\243rio que pretendes[ENTER]melhorar. "
