gameforge.heavens_cave_escape._020_say_title = "Heuk-Young: "
gameforge.heavens_cave_escape._030_say = "Queres mesmo sair da Gruta das Almas? "
gameforge.heavens_cave_escape._040_say = "Uma decis\227o s\225bia. \201 demasiado perigoso ficares[ENTER]aqui mais tempo. Vai e trata das tuas feridas. "
