gameforge.heavens_cave_keyquest = {}
gameforge.heavens_cave_keyquest._010_target = "Seon-Hae "
gameforge.heavens_cave_keyquest._020_npcChat = "Na Gruta "
gameforge.heavens_cave_keyquest._030_say = "Ouve com aten\231\227o meu rapaz! Apenas te irei contar[ENTER]esta hist\243ria uma vez... "
gameforge.heavens_cave_keyquest._040_say = "Ouve com aten\231\227o minha menina! Apenas te irei[ENTER]contar esta hist\243ria uma vez... "
gameforge.heavens_cave_keyquest._050_say = "Actualmente veneramos o Deus Drag\227o, mas outrora[ENTER]existiam tr\234s Deuses que olhavam por n\243s. No[ENTER]entanto Bahar-Taraji, a Deusa da Cria\231\227o, foi[ENTER]assassinada pelo seu invejoso irm\227o,[ENTER]Beran-Setaou. E o terceiro Deus, Baljit-Elvedin,[ENTER]que conhecemos hoje como o Deus Drag\227o,[ENTER]afundou-se no luto pela sua irm\227. "
gameforge.heavens_cave_keyquest._060_say = "Uma batalha rebentou entre os dois irm\227os,[ENTER]batalha essa ganha pelo Deus Drag\227o. Os rumores[ENTER]contam que rastos dessa batalha podem ainda ser[ENTER]encontrados no local onde foi travada.[ENTER]Beran-Setaou foi encerrado numa gruta ap\243s a sua[ENTER]derrota, gruta desde ent\227o conhecida por Gruta[ENTER]das Almas. "
gameforge.heavens_cave_keyquest._070_say = "Esta Gruta est\225 selada e \233 guardada por membros[ENTER]da Ordem de Baljit-Elvedin. Ter\225s que pagar com[ENTER]uma Pedra de Sangue para poderes prosseguir para[ENTER]o seu interior. Sei como produzir essas Pedras,[ENTER]mas n\227o \233 tarefa f\225cil. "
gameforge.heavens_cave_keyquest._080_say = "Tudo come\231ou com as L\225grimas que o Deus Drag\227o[ENTER]chorou pela sua irm\227, l\225grimas essas que se[ENTER]tornaram pedras e que posteriormente ca\237ram na[ENTER]terra. Ainda as podes encontrar na Terra do Fogo,[ENTER]Doyyumhwan. Obt\233m sete destas L\225grimas e quatro[ENTER]Obsidianas, matando os Chama que vivem nessa[ENTER]regi\227o, e tr\225-las a mim. "
gameforge.heavens_cave_keyquest._090_say_reward = "Recolhe 7 L\225grimas Fossilizadas e 4 Obsidianas em[ENTER]Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "Precisas de outra Pedra de Sangue para passares[ENTER]os Guardas da Ordem? Ent\227o recolhe mais sete[ENTER]L\225grimas Fossilizadas e quadro Obsidianas na[ENTER]Terra do Fogo, Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Precisas de outra Pedra de Sangue? Koe-Pung n\227o \233[ENTER]o mais inteligente, mas deverias esperar um[ENTER]pouco, caso contr\225rio ele poder\225 reparar que n\227o[ENTER]pertences \224 sua Ordem. "
gameforge.heavens_cave_keyquest._120_say = "Algumas horas, cerca de: %s "
gameforge.heavens_cave_keyquest._130_say = "Uma hora e %s minutos. "
gameforge.heavens_cave_keyquest._140_say = "Espera mais %s minutos. "
gameforge.heavens_cave_keyquest._150_say_title = "L\225grima Fossilizada "
gameforge.heavens_cave_keyquest._160_say = "Aqui est\225 uma das L\225grimas Fossilizadas do Deus[ENTER]Drag\227o que caiu na terra. "
gameforge.heavens_cave_keyquest._170_1_select = "Apanhar a l\225grima "
gameforge.heavens_cave_keyquest._170_2_select = "Tentar encontrar mais l\225grimas por aqui "
gameforge.heavens_cave_keyquest._170_3_select = "Deixar a l\225grima no ch\227o "
gameforge.heavens_cave_keyquest._180_say = "Recebeste uma L\225grima Fossilizada. "
gameforge.heavens_cave_keyquest._190_say_title = "L\225grima Fossilizada "
gameforge.heavens_cave_keyquest._200_say = "Decides tentar procurar mais L\225grimas e[ENTER]encontras: %s "
gameforge.heavens_cave_keyquest._210_say = "As criaturas na \225rea est\227o agora com a aten\231\227o[ENTER]virada para ti! "
gameforge.heavens_cave_keyquest._220_say = "Dirige-te \224 Terra do Fogo, Doyyumhwan, e procura[ENTER]as L\225grimas Fossilizadas de Baljit Elvedin, o[ENTER]Deus Drag\227o. Tamb\233m dever\225s recolher Obsidianas[ENTER]matando os Chama. "
gameforge.heavens_cave_keyquest._230_say = "L\225grimas Fossilizadas necess\225rias: %s "
gameforge.heavens_cave_keyquest._240_say = "Obsidianas necess\225rias: %s "
gameforge.heavens_cave_keyquest._250_notice = "J\225 recolheste L\225grimas suficientes! "
gameforge.heavens_cave_keyquest._260_notice = "Encontraste uma Obsidiana! "
gameforge.heavens_cave_keyquest._270_notice = "J\225 recolheste todas as Obsidianas necess\225rias! "
gameforge.heavens_cave_keyquest._280_say = "Regressa a Seon-Hae com as L\225grimas Fossilizadas[ENTER]e as Obsidianas. "
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae encontra-se em: %s "
gameforge.heavens_cave_keyquest._300_say = "L\225grimas de Baljit-Elvedin! Irei revert\234-las para[ENTER]a sua forma l\237quida e introduzi-las nas[ENTER]Obsidianas. O seu poder permite-te invocar a[ENTER]Deusa Bahar-Taraji! "
gameforge.heavens_cave_keyquest._310_say = "O seu esp\237rito ainda vagueia pelo continente.[ENTER]Conseguir\225s ouvir a sua voz quando estiveres na[ENTER]posse das L\225grimas. Procura-a no Bosque Rubro! "
gameforge.heavens_cave_keyquest._320_say = "Toma este vaso e procura a voz de Bahar-Taraji. "
gameforge.heavens_cave_keyquest._330_say = "Procura a voz de Bahar-Taraji no Bosque Rubro,[ENTER]Lungsam. Mesmo que n\227o consigas ver o fantasma da[ENTER]Deusa ser\225s capaz de sentir a presen\231a do seu[ENTER]esp\237rito. "
gameforge.heavens_cave_keyquest._335_say = "Um murm\250rio suave assobia no vento: Vai para um[ENTER]lugar seguro... N\227o podemos falar aqui...[ENTER]Clica no pergaminho da Miss\227o para falares com o[ENTER]Fantasma. "
gameforge.heavens_cave_keyquest._340_say = "Na dist\226ncia ecoa a voz da Deusa assassinada[ENTER]Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "As l\225grimas do meu irm\227o... Ele chorou por mim[ENTER]durante tanto tempo e mesmo assim n\227o foi capaz[ENTER]de punir Beran-Setaou pelos seus feitos. "
gameforge.heavens_cave_keyquest._360_say = "Ele n\227o foi capaz de enfrentar o seu irm\227o[ENTER]Beran-Setaou, o Destruidor, aquele que as pessoas[ENTER]temiam. "
gameforge.heavens_cave_keyquest._370_say = "Mas tu... Quem \233s tu? \201s diferente! N\227o tens medo[ENTER]dele. Pelo contr\225rio, vejo que pretendes[ENTER]combater. "
gameforge.heavens_cave_keyquest._380_say = "%s! Toma estas gotas do meu sangue. Com elas[ENTER]podes produzir uma Pedra de Sangue e fazer[ENTER]Beran-Setaou pagar pelo que fez. A Gruta das[ENTER]Almas n\227o fica muito longe daqui. "
gameforge.heavens_cave_keyquest._390_say = "Na dist\226ncia ecoa a voz da Deusa assassinada[ENTER]Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "%s! Eu reconhe\231o-te! "
gameforge.heavens_cave_keyquest._410_say = "Trouxeste-me as l\225grimas do meu irm\227o para me[ENTER]consolar e por isso mereces o meu sangue como[ENTER]recompensa para que possas continuar a lutar. "
gameforge.heavens_cave_keyquest._420_say = "Regressa a Seon-Hae com o sangue de Bahar-Taraji. "
gameforge.heavens_cave_keyquest._430_say = "Os olhos de Seon-Hae brilham enquanto lhe d\225s as[ENTER]Gotas de Sangue... "
gameforge.heavens_cave_keyquest._440_say = "O sangue de uma verdadeira Deusa! R\225pido,[ENTER]deixa-me transform\225-lo numa Pedra de Sangue antes[ENTER]que seque. "
gameforge.heavens_cave_keyquest._450_say = "O guarda Koe-Pung ir\225 deixar-te utilizar o portal[ENTER]que d\225 acesso \224 Gruta das Almas se estiveres na[ENTER]posse de uma Pedra de Sangue. No entanto ela[ENTER]apenas ir\225 funcionar uma vez. Se precisares de[ENTER]mais Pedras de Sangue vem ter comigo.[ENTER]Infelizmente apenas posso produzir uma Pedra de[ENTER]Sangue por dia, caso contr\225rio iremos atrair a[ENTER]f\250ria da Ordem. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae pode produzir mais Pedras de Sangue para[ENTER]ti, mas apenas uma por dia. "
gameforge.heavens_cave_keyquest._470_say = "Irei transformar o sangue de Bahar-Taraji numa[ENTER]Pedra de Sangue. Que te seja \250til. "
gameforge.heavens_cave_keyquest._480_say_reward = "Apenas posso fabricar uma Pedra de Sangue por[ENTER]dia, caso contr\225rio Koe-Pung poder\225 desconfiar. "
