gameforge.locale.bookworm = {}
gameforge.locale.bookworm.accept_ask = "Ainda aqui est\225s?[ENTER]Aceitaste a miss\227o, por isso despacha-te a[ENTER]terminar o que tens para fazer. Ao ataque! "
gameforge.locale.bookworm.accept_failure_info_label = "Regressa ao Sr. Soon. "
gameforge.locale.bookworm.accept_failure_info_text_1 = "Regressa ao Sr. Soon. "
gameforge.locale.bookworm.accept_failure_info_text_2 = "Regressa \224 vila e conta ao Sr. Soon que n\227o[ENTER]conseguiste encontrar o Livro Milgyo. "
gameforge.locale.bookworm.accept_failure_say_1 = "Regressa \224 vila. "
gameforge.locale.bookworm.accept_failure_say_2 = "Parece que sou seguido pelo azar - n\227o consigo[ENTER]encontrar o Livro Milgyo. A \250nica coisa que posso[ENTER]fazer agora \233 regressar \224 vila. "
gameforge.locale.bookworm.accept_success_info_label = "Encontra o Livro Milgyo para o Sr. Soon. "
gameforge.locale.bookworm.accept_success_info_text_1 = "Encontra o Livro Milgyo para o Sr. Soon. "
gameforge.locale.bookworm.accept_success_info_text_2 = "Regressa \224 vila, entrega o Livro ao Sr. Soon e[ENTER]recebe a tua recompensa. "
gameforge.locale.bookworm.accept_success_say_1 = "Aqui est\225 ele, o Livro Milgyo! "
gameforge.locale.bookworm.accept_success_say_2 = "Encontraste o Livro Milgyo! Entrega-o ao Sr. Soon[ENTER]na vila. "
gameforge.locale.bookworm.aranyeo_complete_say = "Quem foi o tolo que levou este livro estranho ao[ENTER]meu marido? Ele passa o dia todo a olhar para[ENTER]ele, a aprender c\226nticos estranhos... Ele j\225 nem[ENTER]levanta um dedo! Irei partir-lhe todos os seus[ENTER]ossos quando o apanhar! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "O que se passa? Porque est\225s com suores frios? "
gameforge.locale.bookworm.aranyeo_start_say = "Para onde \233 que ele foi agora? As suas atitudes[ENTER]est\227o a irritar-me! Ele desperdi\231a os dias a ler[ENTER]livros sem ganhar um \250nico Yang. E nem tem[ENTER]vergonha de ser um mau modelo para os seus[ENTER]filhos. "
gameforge.locale.bookworm.aranyeo_start_say2 = "S\227o os livros que te p\245em a comida na mesa ou te[ENTER]arranjam a roupa? Vou partir-lhe os ossos[ENTER]todinhos se o apanhar! "
gameforge.locale.bookworm.aranyeo_talk = "Falar. "
gameforge.locale.bookworm.complete_say = "Oh! Sim, consigo ver! Consigo ver! Consigo ver o[ENTER]novo mundo! "
gameforge.locale.bookworm.do_you_find_the_book = "Encontraste o Livro Milgyo? "
gameforge.locale.bookworm.do_you_mean_this_book = "\201 este o Livro? "
gameforge.locale.bookworm.etc_shop_start_say = "Ele veio c\225 ontem e perguntou pelo Livro de[ENTER]Milgyo. Ele n\227o tinha Yang, mas mesmo assim n\227o[ENTER]parava de perguntar por ele. Talvez Milgyo possa[ENTER]estar relacionado com aquelas criaturas brutais[ENTER]do Vale de Seungryong. N\227o fa\231o ideia do porqu\234[ENTER]de ele estar subitamente interessado nessas[ENTER]criaturas. "
gameforge.locale.bookworm.etc_shop_start_say2 = "\201 imposs\237vel n\227o sentir pena da Aranyo. Porque \233[ENTER]que ela ainda o atura? "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "Sobre o Sr. Soon, o rato de biblioteca. "
gameforge.locale.bookworm.order_accept = "Ok! Encontrarei o Livro por ti! "
gameforge.locale.bookworm.order_accept_answer = "Obrigado! Estou a contar contigo. "
gameforge.locale.bookworm.order_find_book_label = "Mata o disc\237pulo de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_1 = "Mata o disc\237pulo de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_2 = "Obt\233m o Livro de Milgyo do disc\237pulo de Milgyo. "
gameforge.locale.bookworm.order_refuse = "Isso dever\225 ser um pouco complicado. "
gameforge.locale.bookworm.order_refuse_answer = "Porque n\227o tentas de novo? Sei que o conseguir\225s[ENTER]fazer! "
gameforge.locale.bookworm.order_say1 = "Queres ouvir algo engra\231ado? Eu posso afirmar que[ENTER]j\225 li todos os livros que existem no mundo! Neste[ENTER]momento ando a estudar uma colec\231\227o de textos[ENTER]sagrados. Rumores dizem que informa\231\245es e dicas[ENTER]sobre como algu\233m se pode tornar um santo podem[ENTER]ser encontradas no Livro de Milgyo. "
gameforge.locale.bookworm.order_say2 = "Gostaria de ler este livro. Achas que consegues[ENTER]arranj\225-lo para mim? E \233 claro que te irei[ENTER]recompensar! "
gameforge.locale.bookworm.order_too_late = "Algu\233m j\225 me trouxe o Livro de Milgyo. N\227o[ENTER]precisas de o procurar mais. "
gameforge.locale.bookworm.start_find_bookworm_label = "Vai ter com o Sr. Soon "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Vai ter com o Sr. Soon "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Fala com o Sr. Soon e pergunta-lhe sobre o Livro[ENTER]de Milgyo. "
gameforge.locale.bookworm.start_say = "Consegues ver a profunda sabedoria presente neste[ENTER]documento? Palavras formam frases, e \233 assim que[ENTER]uma maravilhosa hist\243ria \233 criada. \201 preciso[ENTER]habituarmo-nos a ser guiados pela imagina\231\227o de[ENTER]outras pessoas, e isso n\227o \233 do gosto de muita[ENTER]gente, mas eu adoro. "
gameforge.locale.bookworm.start_say2 = "Quanto mais tens, mais recebes.[ENTER]Quanto mais conheces, mais te divertes.[ENTER]Ah... Se eu pudesse simplesmente ler livros por[ENTER]toda a minha vida... "
gameforge.locale.bookworm.success_thanks = "Oh! \201 isso mesmo! Vou l\234-lo com grande prazer. "
gameforge.locale.bookworm.talk = "Falar. "
gameforge.locale.bookworm.talk_about_milgyo_book = "Perguntar sobre o Livro de Milgyo. "
