gameforge.locale.christmas_santa.hairdye_msg = "%d Yang por um item deste saco. Dentro dele h\225[ENTER]diferentes materiais para melhorar itens. Podes[ENTER]levar um, mas n\227o podes espreitar l\225 para dentro![ENTER]O que achas? "
