gameforge.locale.forked_condition = "Precisamos de encontrar o guardi\227o do Portal[ENTER]antes de qualquer outro Reino.[ENTER]Vamos trabalhar os m\250sculos do nosso Reino e[ENTER]expandir o seu poder! "
gameforge.locale.forked_condition2 = "Agora s\243 precisamos de fazer desaparecer os[ENTER]monstros que est\227o a profanar o Territ\243rio[ENTER]Sagrado. Ao Ataque!!! "
gameforge.locale.forked_enter = "Participar "
gameforge.locale.forked_kill_boss = "Eu sou Thorr Sarch! O que querem de mim? N\227o[ENTER]estou morto, pois vou voltar a viver. E legi\245es[ENTER]de guerreiros ir\227o seguir-me![ENTER]Terminaste a Guerra dos Reinos. Todos ser\227o[ENTER]transportados de volta para a vila. "
gameforge.locale.forked_man_chat = "Participar na Guerra dos Reinos "
gameforge.locale.forked_man_say = "Uma nova \225rea foi descoberta. Encontra-se no[ENTER]centro do continente - pode at\233 ligar os tr\234s[ENTER]Reinos. Mas est\225 repleta de criaturas das trevas.[ENTER]Talvez possas ir at\233 l\225 e confront\225-las?[ENTER]Destr\243i-as e restaura a paz no nosso Reino. "
gameforge.locale.forked_man_say_cant = "Hey! Uma nova \225rea foi descoberta no interior do[ENTER]continente. Ela pode at\233 ligar todos os Reinos.[ENTER]Assim que terminarmos as nossas investiga\231\245es[ENTER]poder\225s ir at\233 essa \225rea. "
gameforge.locale.forked_no_enter = "N\227o participar "
gameforge.locale.forked_open_gate = "A porta, que at\233 agora se encontrava fechada, foi[ENTER]aberta. Vamos para os novos terrenos! Iremos[ENTER]conquist\225-los! Todos ir\227o ser transportados para[ENTER]o Territ\243rio Sagrado. "
gameforge.locale.forked_rule = "Regras para entrar na Guerra dos Reinos:[ENTER]1. Todos os que morrerem nesta \225rea ser\227o[ENTER]transportados para a vila, mas o Beleguim Batalha[ENTER]poder\225 transport\225-los de novo para aqui[ENTER]imediatamente.[ENTER]2. Assim que as portas para o Territ\243rio Sagrado[ENTER]tenham sido abertas, esta \225rea \233 encerrada.[ENTER]3. Para entrar Territ\243rio Sagrado, \233 necess\225rio[ENTER]encontrar a chave correspondente. "
gameforge.locale.forked_rule_sungzi = "Regras da Guerra dos Reinos:[ENTER]1. O Reino que tiver o menor n\250mero de vit\243rias[ENTER]contra os outros Reinos \233 eliminado primeiro.[ENTER]2. Ir\227o surgir monstros. O primeiro Reino a matar[ENTER]uma certa quantidade de monstros vence.[ENTER]3. Se o Nove Caudas for morto depois disso, a[ENTER]Guerra termina.[ENTER]4. Durante a Guerra n\227o \233 poss\237vel obter itens.[ENTER]5. Quem morrer tr\234s vezes no Territ\243rio Sagrado[ENTER]ir\225 ser transportado para a vila e ser\225 eliminado[ENTER]da Guerra dos Reinos. "
gameforge.locale.fortune_words_1_body = "A fortuna sorri-te! Ir\225s ter \"Muito Boa Sorte\"[ENTER]hoje! Hoje ir\225 acontecer algo de bom a todos[ENTER]aqueles que s\227o protegidos por esta aura de[ENTER]harmonia. "
gameforge.locale.fortune_words_1_title = "Muito Boa Sorte! "
gameforge.locale.fortune_words_2_body = "Isso \233 bom. Como \233 que dizem por a\237? Colhes o que[ENTER]semeias. Hoje ir\225s ter \"Boa Sorte\"! Estou[ENTER]contente por ti. Esfor\231a-te um pouco e ir\225s[ENTER]receber mais do que antes! "
gameforge.locale.fortune_words_2_title = "Boa Sorte! "
gameforge.locale.fortune_words_3_body = "N\227o est\225 mau. Hoje ir\225s ter \"Alguma Sorte\". O teu[ENTER]dia ir\225 correr um pouco melhor que o normal, mas[ENTER]n\227o esperes grandes presentes! "
gameforge.locale.fortune_words_3_title = "Alguma Sorte. "
gameforge.locale.fortune_words_4_body = "Nada de muito bom, mas tamb\233m nada de muito mau![ENTER]Hoje ter\225s \"Sorte Normal\". N\227o ir\225 ajudar-te[ENTER]muito, mas \233 melhor do que teres azar. Os dias[ENTER]normais n\227o devem ser desprezados, por isso[ENTER]desfruta! "
gameforge.locale.fortune_words_4_title = "Sorte Normal. "
gameforge.locale.fortune_words_5_body = "Hoje n\227o ter\225s muita sorte. Mesmo que atires as[ENTER]tuas redes como o fazes sempre, n\227o ir\225s apanhar[ENTER]muitos peixes. Pelo lado positivo, posso dizer-te[ENTER]que n\227o ir\225s morrer \224 fome. Ir\225s ter \"Alguma M\225[ENTER]Sorte\" hoje! Mas n\227o h\225 nada melhor do que estar[ENTER]bem preparado. Se quiseres posso vender-te um[ENTER]Talism\227 que poder\225 ajudar-te a evitar a m\225 sorte.[ENTER]Est\225s interessado? "
gameforge.locale.fortune_words_5_title = "Alguma M\225 Sorte. "
gameforge.locale.fortune_words_6_body = "Hoje \233 um mau dia. Um dia durante o qual nem[ENTER]dando o teu melhor conseguir\225s alguma coisa. Hoje[ENTER]ter\225s \"M\225 Sorte\" e tens de ter cuidado com o que[ENTER]fazes e onde vais. Eu posso ajudar-te e vender-te[ENTER]um Amuleto para que possas evitar o mal. Est\225s[ENTER]interessado? "
gameforge.locale.fortune_words_6_title = "M\225 Sorte. "
gameforge.locale.fortune_words_7_body = "Este ir\225 ser um dos piores dias da tua vida.[ENTER]Todos os Deuses do C\233u e da Terra viraram-te as[ENTER]costas. Hoje nada ir\225 correr como pretendes. Se[ENTER]quiseres atear um fogo, ir\225 chover; se tiveres[ENTER]sede, o sol abrasador ir\225 seguir-te. Ir\225s[ENTER]trabalhar t\227o arduamente como os outros, mas n\227o[ENTER]ir\225s receber nada por isso. Ir\225s sofrer \"Muito M\225[ENTER]Sorte\"![ENTER]Sem um Talism\227 ir\225s ter tempos dif\237ceis pela[ENTER]frente. Queres comprar um? "
gameforge.locale.fortune_words_7_title = "Muito M\225 Sorte. "
