gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Todos ir\227o morrer! "
gameforge.locale.monster_chat_1001_2 = "Pequenos, pequenos, pequenos peda\231os... "
gameforge.locale.monster_chat_1001_3 = "N\227o tens escapat\243ria! "
gameforge.locale.monster_chat_1001_4 = "O teu sangue ir\225 encharcar o ch\227o! Morre! "
gameforge.locale.monster_chat_1001_5 = "Podes implorar, mas n\227o te ir\225 ajudar! "
gameforge.locale.monster_chat_1001_6 = "N\227o consegues esconder o medo que sentes por mim! "
gameforge.locale.monster_chat_1002_1 = "Morte! Morte a todos os humanos... "
gameforge.locale.monster_chat_1002_2 = "Seu verme miser\225vel! "
gameforge.locale.monster_chat_1002_3 = "Est\225s a come\231ar a irritar-me... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Vai haver sangue, humano. "
gameforge.locale.monster_chat_1003_1 = "Morte e destrui\231\227o...! "
gameforge.locale.monster_chat_1003_2 = "Alguma vez viste as feridas que uma lan\231a pode causar? "
gameforge.locale.monster_chat_1003_3 = "Sim, vai, foge! Vamos ver qu\227o longe consegues chegar... "
gameforge.locale.monster_chat_1003_4 = "Este confronto j\225 vale a pena pela simples vis\227o das tuas m\227os a tremer... "
gameforge.locale.monster_chat_1003_5 = "Esta escumalha ousa desafiar-me? "
gameforge.locale.monster_chat_1003_6 = "A Morte ser\225 a tua \250nica companheira! "
gameforge.locale.monster_chat_1004_1 = "A tua alma ser\225 minha, humano! "
gameforge.locale.monster_chat_1004_2 = "Ah, carne fresca! "
gameforge.locale.monster_chat_1004_3 = "Parece que mais algu\233m vai encontrar aqui a sua morte! "
gameforge.locale.monster_chat_1004_4 = "Devias sofrer e soltar toda a tua ang\250stia... "
gameforge.locale.monster_chat_1004_5 = "Achas que \233 essa arma rid\237cula que tens na m\227o que te ir\225 proteger? "
gameforge.locale.monster_chat_1004_6 = "A tua coragem trouxe-te at\233 mim. E agora ela abandonar-te-\225... "
gameforge.locale.monster_chat_1035_1 = "Se eu morrer, ir\225s sofrer a minha vingan\231a para sempre! "
gameforge.locale.monster_chat_1035_2 = "Vou matar-te e fazer-te sofrer lentamente, muito lentamente... "
gameforge.locale.monster_chat_1035_3 = "Ser\225 um prazer fazer-te sofrer. "
gameforge.locale.monster_chat_1035_4 = "O teu corpo treme como o de uma velha mulher! "
gameforge.locale.monster_chat_1035_5 = "Consigo cheirar o teu medo, pequeno mortal. "
gameforge.locale.monster_chat_1035_6 = "Acho que est\225 na altura de te tirar algumas partes do corpo. "
gameforge.locale.monster_chat_1036_1 = "Irei enviar-te para o teu Inferno pessoal! "
gameforge.locale.monster_chat_1036_2 = "A tua dor ir\225 levar-te \224 loucura antes de morreres... "
gameforge.locale.monster_chat_1036_3 = "Geme! Suplica! N\227o te servir\225 de nada. "
gameforge.locale.monster_chat_1036_4 = "Ir\225s morrer da pior forma que consegues imaginar... "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "O teu vigor diminui. J\225 est\225s no limiar da morte. "
gameforge.locale.monster_chat_1037_1 = "Est\225s preparado para caminhar na morte para sempre? "
gameforge.locale.monster_chat_1037_2 = "Devias habituar-te \224 ideia de aceitar as trevas eternas... "
gameforge.locale.monster_chat_1037_3 = "Bem-vindo ao Inferno! "
gameforge.locale.monster_chat_1037_4 = "Grita o que quiseres! Aqui ningu\233m te consegue ouvir! "
gameforge.locale.monster_chat_1037_5 = "Se acreditas que me consegues matar dessa forma... \201s mais ing\233nuo do que eu pensava! "
gameforge.locale.monster_chat_1037_6 = "Belo ataque, mas n\227o impedir\225 que a Morte te apanhe. "
gameforge.locale.monster_chat_1038_1 = "Isto \233 o Inferno! "
gameforge.locale.monster_chat_1038_2 = "Vou arrancar-te a pele dos ossos. "
gameforge.locale.monster_chat_1038_3 = "Quero ouvir as tuas lamurias antes de morreres. "
gameforge.locale.monster_chat_1038_4 = "J\225 deves saber que qualquer esperan\231a ser\225 em v\227o, n\227o? "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "N\227o, n\227o morras j\225. Primeiro quero saber quantos golpes da minha espada consegues aguentar... "
gameforge.locale.monster_chat_1039_1 = "Ah, um volunt\225rio... "
gameforge.locale.monster_chat_1039_2 = "Achas que tens a m\237nima hip\243tese de escapar? "
gameforge.locale.monster_chat_1039_3 = "N\227o \233 o ch\227o que se est\225 a mexer... S\227o as tuas pernas que tremem de medo! "
gameforge.locale.monster_chat_1039_4 = "Bem-vindo ao lugar onde encontrar\225s a tua Morte! "
gameforge.locale.monster_chat_1039_5 = "Consigo ver o p\226nico nos teus olhos brilhantes. "
gameforge.locale.monster_chat_1039_6 = "Oh, t\227o jovem e indefeso... "
gameforge.locale.monster_chat_1040_1 = "Observamos todos os teus movimentos... "
gameforge.locale.monster_chat_1040_2 = "Tens pressa? Queres assim tanto morrer? "
gameforge.locale.monster_chat_1040_3 = "A morte tem um lugar reservado para ti... "
gameforge.locale.monster_chat_1040_4 = "Consegues ouvir a minha campainha? Ser\225 a \250ltima coisa que vais ouvir! "
gameforge.locale.monster_chat_1040_5 = "Cheira-me a sangue, e bastante... N\227o sobreviver\225s muito mais tempo... "
gameforge.locale.monster_chat_1040_6 = "Podes lutar... Ou podes render-te imediatamente \224 morte... "
gameforge.locale.monster_chat_1041_1 = "Porque est\225s aqui se est\225s t\227o empenhado em manter-te vivo? "
gameforge.locale.monster_chat_1041_2 = "Ah, novos corpos para eu destruir! "
gameforge.locale.monster_chat_1041_3 = "Foi tua decis\227o vir at\233 aqui, mortal! Agora ter\225s de sofrer as consequ\234ncias... "
gameforge.locale.monster_chat_1041_4 = "A nossa for\231a n\227o nos ir\225 abandonar. N\243s n\227o morremos! "
gameforge.locale.monster_chat_1041_5 = "N\227o faz sentido atacares-nos! Est\225s condenado... "
gameforge.locale.monster_chat_1041_6 = "Talvez morras de exaust\227o... Ou medo... "
gameforge.locale.monster_chat_1091_1 = "Conseguiste chegar at\233 mim... Irei levar-te at\233 \224 Morte. "
gameforge.locale.monster_chat_1091_2 = "Sacrifica a tua alma e torna-te um de n\243s! "
gameforge.locale.monster_chat_1091_3 = "Olha para ti! Fraco e lento... "
gameforge.locale.monster_chat_1091_4 = "O teu corpo e alma s\227o meus! "
gameforge.locale.monster_chat_1091_5 = "As tuas pernas est\227o a tremer! Admite, n\227o aguentas isto... "
gameforge.locale.monster_chat_1091_6 = "Quanto tempo mais vais aguentar isto? "
gameforge.locale.monster_chat_1093_1 = "Quem poderia adivinhar que h\225 algo pior que a morte? "
gameforge.locale.monster_chat_1093_2 = "Bem vindo, banquete da morte. "
gameforge.locale.monster_chat_1093_3 = "Vais pagar pela tua imprud\234ncia. Com o teu sangue e a tua alma. "
gameforge.locale.monster_chat_1093_4 = "Depois de destruir o teu corpo, a tua alma ser\225 minha! "
gameforge.locale.monster_chat_1093_5 = "Quanto tempo mais resistir\225s? "
gameforge.locale.monster_chat_1093_6 = "Tu divertes-me. O teu medo e precipita\231\227o divertem-me... "
gameforge.locale.monster_chat_11000_1 = "Todos os que se preocupam com o seu destino deviam ouvir! "
gameforge.locale.monster_chat_11000_10 = "Se queres controlar os poderes da Natureza e dos Raios recomendo a especializa\231\227o Energia. "
gameforge.locale.monster_chat_11000_11 = "Cada Guerreiro \233 diferente na sua forma de lutar! Foca-te no fortalecimento do teu corpo! "
gameforge.locale.monster_chat_11000_12 = "A for\231a de um Sura \233 m\225gica. Trabalha a tua Intelig\234ncia, Rapidez e For\231a F\237sica! "
gameforge.locale.monster_chat_11000_13 = "Usa as habilidades dos Ninjas! Foca-te na velocidade e for\231a f\237sica. "
gameforge.locale.monster_chat_11000_14 = "Os Xam\227s usam feiti\231os de regenera\231\227o ajuda e combate. Intelig\234ncia \233 vital! "
gameforge.locale.monster_chat_11000_15 = "N\227o te esque\231as de treinar a tua especializa\231\227o! "
gameforge.locale.monster_chat_11000_16 = "Torna-te um aprendiz nosso caso querias treinar as tuas Habilidades! "
gameforge.locale.monster_chat_11000_17 = "Habilidades? Elas subir\227o para o n\237vel de Mestre aleatoriamente entre os n\237veis 17 e 20! "
gameforge.locale.monster_chat_11000_18 = "Queres tornar-te um Grande Mestre? Ent\227o precisas de um Livro de Habilidades especial! "
gameforge.locale.monster_chat_11000_19 = "Assim que acabas de ler um Livro de Habilidades, ele desaparece! "
gameforge.locale.monster_chat_11000_2 = "Todos os her\243is de n\237vel 5 e abaixo, ou\231am-me! "
gameforge.locale.monster_chat_11000_20 = "Queres ler outro Livro de Habilidades? Tens de esperar um dia. "
gameforge.locale.monster_chat_11000_21 = "Aumenta a tua Intelig\234ncia para melhorares as tuas habilidades de Sura! "
gameforge.locale.monster_chat_11000_22 = "Experimenta os grandes poderes de um Sura num combate! "
gameforge.locale.monster_chat_11000_23 = "Sabes onde se encontra o Templo da Seita Secreta? No centro do Vale Seungryong! "
gameforge.locale.monster_chat_11000_24 = "A Caverna das Aranhas reapareceu. A sua entrada encontra-se no Deserto Yongbi! "
gameforge.locale.monster_chat_11000_25 = "Termina as tuas miss\245es e usa as recompensas em melhoramentos! "
gameforge.locale.monster_chat_11000_26 = "Pescar? Parece divertido! J\225 compraste uma Cana de Pesca e isco a um Pescador? "
gameforge.locale.monster_chat_11000_27 = "Queres um desafio maior? O Portal pode enviar-te para um local de ca\231a apropriado para o teu n\237vel! "
gameforge.locale.monster_chat_11000_28 = "Cuidado com jogadores de outros Reinos. N\227o sabes quando te poder\227o apanhar desprevenido! "
gameforge.locale.monster_chat_11000_29 = "Queres reiniciar o treino das tuas Habilidades? Vai \224 Idosa. N\227o te esque\231as de levar Yang suficiente contigo! "
gameforge.locale.monster_chat_11000_3 = "Dirige-te ao Professor de Luta Corpo se quiseres ser conhecido como um grande Guerreiro ofensivo! "
gameforge.locale.monster_chat_11000_30 = "Almeja atingir o n\237vel de Mestre Perfeito nas tuas Habilidades! Essa \233 a \250nica forma de te tornares um verdadeiro her\243i! "
gameforge.locale.monster_chat_11000_31 = "Se te queres dirigir para outro local, procura as pessoas idosas pelo continente! "
gameforge.locale.monster_chat_11000_4 = "Se queres ser um mestre nas Habilidades de defesa de um Guerreiro dirige-te ao Professor de Luta Mental! "
gameforge.locale.monster_chat_11000_5 = "Se te quiseres tornar um Sura mestre nas espadas m\225gicas escolhe a especializa\231\227o Luta d'Armas. "
gameforge.locale.monster_chat_11000_6 = "Escolhe a especializa\231\227o Magia Negra se quiseres ser um Sura h\225bil com os feiti\231os. "
gameforge.locale.monster_chat_11000_7 = "A Arte do Arco est\225 reservada aos Ninjas de n\237vel 5 e acima. "
gameforge.locale.monster_chat_11000_8 = "Escolhe a Arte Furtiva se quiseres subir na hierarquia secreta dos Ninjas! "
gameforge.locale.monster_chat_11000_9 = "Se quiseres controlar os combates como um guerreiro do Deus Drag\227o escolhe a especializa\231\227o For\231a Drag\227o. "
