gameforge.locale.monster_chat_1105_1 = "Estar congelado \233 bom... para mim! "
gameforge.locale.monster_chat_1105_2 = "Tenho a certeza que a Montanha Sohan \233 o melhor lugar! "
gameforge.locale.monster_chat_1105_3 = "Que belo tempo. "
gameforge.locale.monster_chat_1105_4 = "No fim ir\225s ser t\227o frio como eu... "
gameforge.locale.monster_chat_1105_5 = "Poder\225s viver para sempre, pelo menos at\233 o gelo derreter. "
gameforge.locale.monster_chat_1105_6 = "Como achas que te sentir\225s quando te fores lentamente tornando num peda\231o de gelo? "
gameforge.locale.monster_chat_1106_1 = "Humanos... aqui? "
gameforge.locale.monster_chat_1106_2 = "Cansado... Mas suficientemente desperto para ti... "
gameforge.locale.monster_chat_1106_3 = "Quem se passeia pela minha montanha?  "
gameforge.locale.monster_chat_1106_4 = "Tu n\227o pertences aqui! "
gameforge.locale.monster_chat_1106_5 = "\201 melhor fugires daqui! "
gameforge.locale.monster_chat_1106_6 = "Um estranho... t\227o sozinho? "
gameforge.locale.monster_chat_1191_1 = "J\225 passou algum tempo desde que vimos um lutador experiente por aqui. "
gameforge.locale.monster_chat_1191_2 = "N\227o tenho mais nada para fazer al\233m de esperar e polir armas... "
gameforge.locale.monster_chat_1191_3 = "Achas que devia trabalhar nesse aspecto? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Falta algo. N\227o estou contente... "
gameforge.locale.monster_chat_1191_6 = "Vou p\244r um fim r\225pido \224 tua dor - e ser\225 a \250ltima dor que ir\225s sentir! "
gameforge.locale.monster_chat_1301_1 = "Um pesco\231o-longo...! "
gameforge.locale.monster_chat_1301_2 = "Vais ficar ainda mais p\225lido! "
gameforge.locale.monster_chat_1301_3 = "Queres desafiar-me? Est\225 bem! "
gameforge.locale.monster_chat_1301_4 = "Atacaste-me! N\227o vais sobreviver! "
gameforge.locale.monster_chat_1301_5 = "\201s um humano fraco! Fraco! "
gameforge.locale.monster_chat_1301_6 = "Vamos ver quanto tempo te aguentas! "
gameforge.locale.monster_chat_1302_1 = "A tentar fugir? Nem penses nisso. "
gameforge.locale.monster_chat_1302_2 = "\201 isso mesmo... Aproxima-te! "
gameforge.locale.monster_chat_1302_3 = "A espada treme na minha m\227o... "
gameforge.locale.monster_chat_1302_4 = "N\227o sobreviver\225s a este combate! "
gameforge.locale.monster_chat_1302_5 = "Aqui vai a minha espada! "
gameforge.locale.monster_chat_1302_6 = "Doloroso, n\227o \233? "
gameforge.locale.monster_chat_1303_1 = "Mesmo a erva sobre a qual caminhas te pode matar. "
gameforge.locale.monster_chat_1303_2 = "Se fosse a ti teria cuidado... "
gameforge.locale.monster_chat_1303_3 = "\201 isso. Aproxima-te... "
gameforge.locale.monster_chat_1303_4 = "Atreves-te a aproximar-te? Bom... Ter\225s de sofrer as consequ\234ncias! "
gameforge.locale.monster_chat_1303_5 = "Est\225 na hora de dizeres adeus ao mundo! "
gameforge.locale.monster_chat_1303_6 = "J\225 est\225s arrependido por teres vindo? "
gameforge.locale.monster_chat_1305_1 = "Quem conseguir\225 derrotar-me? "
gameforge.locale.monster_chat_1305_2 = "Tu? Tu queres lutar? "
gameforge.locale.monster_chat_1305_3 = "Ataca-me, se te atreveres! "
gameforge.locale.monster_chat_1305_4 = "N\227o est\225s a pensar em fugir, ou est\225s? "
gameforge.locale.monster_chat_1305_5 = "Subestimaste o alcance da minha espada. "
gameforge.locale.monster_chat_1305_6 = "Est\225s com medo? "
gameforge.locale.monster_chat_1901_1 = "Acho que ir\225s morrer nas minhas m\227os hoje. "
gameforge.locale.monster_chat_1901_2 = "Oh... Gosto de ti... "
gameforge.locale.monster_chat_1901_3 = "Ah, ent\227o queres trazer um pouco de variedade \224 minha vida? "
gameforge.locale.monster_chat_1901_4 = "Hey! N\227o te ajudar\225 fugires como um cobarde. "
gameforge.locale.monster_chat_1901_5 = "J\225 te arrepiaste simplesmente de me ver? "
gameforge.locale.monster_chat_1901_6 = "N\227o queres gritar um pouco? "
gameforge.locale.monster_chat_20001_1 = "Pareces estar nervoso... N\227o te preocupes, nada ir\225 explodir. "
gameforge.locale.monster_chat_20001_2 = "\192s vezes s\243 quero ir dar um passeio. "
gameforge.locale.monster_chat_20001_3 = "O tempo passa t\227o devagar... O meu neto j\225 nem me vem visitar. "
gameforge.locale.monster_chat_20001_4 = "Quando envelheces n\227o tens muita companhia. "
gameforge.locale.monster_chat_20001_5 = "Os meus dias j\225 acabaram. "
gameforge.locale.monster_chat_20002_1 = "O sol est\225 t\227o quente... "
gameforge.locale.monster_chat_20002_2 = "Belo tempo para secar roupa, n\227o \233? "
gameforge.locale.monster_chat_20002_3 = "Onde est\225 o pregui\231oso do meu marido? "
gameforge.locale.monster_chat_20002_4 = "Ele nem tem vergonha de os seus filhos conhecerem a sua pregui\231a! E intitula-se pai... "
gameforge.locale.monster_chat_20002_5 = "Livros, sempre livros! Ele n\227o vai trabalhar e n\227o traz Yang para casa. Passa o tempo todo a ler! "
gameforge.locale.monster_chat_20003_1 = "Ol\225 pequeno, dormiste bem? "
gameforge.locale.monster_chat_20003_2 = "Meu anjinho. "
gameforge.locale.monster_chat_20003_3 = "\201s o meu raio de sol... "
gameforge.locale.monster_chat_20003_4 = "O que se passa? Tens fome? "
gameforge.locale.monster_chat_20003_5 = "\201 isso mesmo... dorme, meu pequeno. "
gameforge.locale.monster_chat_20004_1 = "\201 apenas mais um dia... "
gameforge.locale.monster_chat_20004_2 = "Onde irei arranjar algo para comer hoje? "
gameforge.locale.monster_chat_20004_3 = "\201 sempre a mesma coisa com estes guerreiros de espada. "
gameforge.locale.monster_chat_20004_4 = "Deixa ver.... Talvez devesse ir ao Restaurante do Oct\225vio. "
gameforge.locale.monster_chat_20004_5 = "Oh, j\225 agora, parece que a Guerra j\225 terminou... "
gameforge.locale.monster_chat_20005_1 = "A alma de um Mestre Oleiro corre pelos seus dedos. "
gameforge.locale.monster_chat_20005_2 = "Desde que o Reino mergulhou no caos, existem combates por todo o lado. "
gameforge.locale.monster_chat_20005_3 = "Combates, combates por todo o lado. "
gameforge.locale.monster_chat_20005_4 = "Estou a rezar por um mundo calmo e pac\237fico. "
gameforge.locale.monster_chat_20005_5 = "Qual \233 a pressa? Tira uns segundos para relaxares e pensares. "
gameforge.locale.monster_chat_20006_1 = "Oh meu Deus! O que devo fazer? "
gameforge.locale.monster_chat_20006_2 = "N\227o encontro o meu irm\227o, e ele prometeu encontrar-se comigo aqui. "
gameforge.locale.monster_chat_20006_3 = "E agora tudo o que vejo s\227o guerreiros armados com espadas. "
gameforge.locale.monster_chat_20006_4 = "Tenho saudades do meu irm\227o. "
gameforge.locale.monster_chat_20006_5 = "Algu\233m viu o meu irm\227o? "
gameforge.locale.monster_chat_20007_1 = "Hum... Essa carne \233 mesmo fresca! "
gameforge.locale.monster_chat_20007_2 = "Ainda bem que agora as pessoas comem mais carne. "
gameforge.locale.monster_chat_20007_3 = "O neg\243cio corre bem, mas a carne ainda escasseia. "
gameforge.locale.monster_chat_20007_4 = "Quando receberemos a carne encomendada? "
gameforge.locale.monster_chat_20007_5 = "Se a carne n\227o chegar a tempo teremos que partir \224 ca\231a. "
gameforge.locale.monster_chat_20008_1 = "Espero que os clientes venham aos montes quando o tempo estiver bom... "
gameforge.locale.monster_chat_20008_2 = "Aquele desgra\231ado deve estar prestes a aparecer, e de certeza que ir\225 querer algo para comer. "
gameforge.locale.monster_chat_20008_3 = "Pobre homem! "
gameforge.locale.monster_chat_20008_4 = "Outrora ele foi um grande guerreiro. "
gameforge.locale.monster_chat_20008_5 = "Porque ser\225 que ele j\225 n\227o luta? "
gameforge.locale.monster_chat_20009_1 = "Os jovens... T\227o viva\231os e alegres! "
gameforge.locale.monster_chat_20009_2 = "Os guerreiros ficam mais impressionantes quando empunham armas. "
gameforge.locale.monster_chat_20009_3 = "Hoje em dia todos t\234m uma mente assassina. "
gameforge.locale.monster_chat_20009_4 = "Controla o teu cora\231\227o, foca os teus pensamentos e acalma a tua alma. "
gameforge.locale.monster_chat_20009_5 = "N\227o h\225 uma receita infal\237vel para a felicidade, mas existem dicas que podes seguir. "
gameforge.locale.monster_chat_20010_1 = "Este \233 um item muito \250til! "
gameforge.locale.monster_chat_20010_2 = "Bens vindos de Reinos distantes! Pre\231os extraordin\225rios! "
gameforge.locale.monster_chat_20010_3 = "Aproximem-se todos! "
gameforge.locale.monster_chat_20010_4 = "Venham c\225 e comprem, pessoal! N\227o ter\227o outra oportunidade! "
gameforge.locale.monster_chat_20010_5 = "H\225 demasiados bandidos por aqui. Eles deveriam ficar longe dos meus bens! "
gameforge.locale.monster_chat_20011_1 = "Nos \250ltimos anos a terra tem estado muito seca. "
gameforge.locale.monster_chat_20011_2 = "A colheita de cereais j\225 n\227o \233 o que era. "
gameforge.locale.monster_chat_20011_3 = "Porque \233 que os campos j\225 n\227o se enchem de flores? "
gameforge.locale.monster_chat_20011_4 = "Os cereais s\227o quebradi\231os e sabem a podre. "
gameforge.locale.monster_chat_20011_5 = "Isso \233 um mau sinal. A agricultura \233 a funda\231\227o das nossas vidas. "
gameforge.locale.monster_chat_20012_1 = "Bolos de arroz! Bolas de arroz deliciosos! "
gameforge.locale.monster_chat_20012_2 = "Vendo bolos de arroz deliciosos! "
gameforge.locale.monster_chat_20012_3 = "Sim, ultimamente o neg\243cio tem estado muito mau. "
gameforge.locale.monster_chat_20012_4 = "Talvez devesse tentar noutra vila... "
gameforge.locale.monster_chat_20012_5 = "Mas h\225 tantos predadores selvagens por aqui... "
gameforge.locale.monster_chat_20013_1 = "Em dias como este, estar num barco \233 a melhor coisa que te pode acontecer. "
gameforge.locale.monster_chat_20013_2 = "Est\225 o tempo perfeito para a pesca! "
gameforge.locale.monster_chat_20013_3 = "Agora outro n\243... Certo! Nenhum peixe ir\225 escapar a este anzol! "
gameforge.locale.monster_chat_20013_4 = "Aquele est\250pido urso estragou a minha Cana! "
gameforge.locale.monster_chat_20013_5 = "Devia arranjar as minhas redes de novo. "
gameforge.locale.monster_chat_20014_1 = "Huh! "
gameforge.locale.monster_chat_20014_2 = "N\227o te preocupes comigo. Esta \233 a minha maneira de ser. "
gameforge.locale.monster_chat_20014_3 = "Ha! "
gameforge.locale.monster_chat_20014_4 = "O que \233 que deveria fazer para eles... Oh, o que acabei de dizer? "
gameforge.locale.monster_chat_20014_5 = "N\227o sou suficientemente corajoso. "
gameforge.locale.monster_chat_20015_1 = "Este machado est\225 ao meu servi\231o h\225 20 anos! "
gameforge.locale.monster_chat_20015_2 = "Ainda est\225 afiado, mas j\225 n\227o tanto como antigamente. "
gameforge.locale.monster_chat_20015_3 = "Quero continuar a us\225-lo, por isso precisa de estar afiado. "
gameforge.locale.monster_chat_20015_4 = "Mas para isso preciso de pedras com minerais especiais. "
gameforge.locale.monster_chat_20015_5 = "Onde as poderei arranjar? "
gameforge.locale.monster_chat_20016_1 = "Os clientes v\234m aos montes. "
gameforge.locale.monster_chat_20016_2 = "Espero conseguir terminar tudo a tempo. "
gameforge.locale.monster_chat_20016_3 = "Martelada e mais martelada e sem me queixar... "
gameforge.locale.monster_chat_20016_4 = "\201 assim que um martelo deve soar! "
gameforge.locale.monster_chat_20016_5 = "Est\225 muito calor aqui. "
gameforge.locale.monster_chat_20017_1 = "N\227o estou com humor para m\250sicas. "
gameforge.locale.monster_chat_20017_2 = "O meu instrumento encontra-se em mau-estado. "
gameforge.locale.monster_chat_20017_3 = "Talvez devesse arranjar um novo instrumento? "
gameforge.locale.monster_chat_20017_4 = "O meu instrumento est\225 velho e gasto... Adoro coisas antigas! "
gameforge.locale.monster_chat_20017_5 = "Preciso de encontrar algu\233m urgentemente para reparar as cordas partidas. "
gameforge.locale.monster_chat_20018_1 = "Estou muito ocupado! "
gameforge.locale.monster_chat_20018_2 = "Todos os dias recebemos novas pessoas feridas. "
gameforge.locale.monster_chat_20018_3 = "N\227o tenho tempo para assuntos particulares! "
gameforge.locale.monster_chat_20018_4 = "Al\233m de que estamos a ficar sem medicamentos. "
gameforge.locale.monster_chat_20018_5 = "Precisamos de algu\233m que consiga obter ingredientes para o rem\233dio. "
gameforge.locale.monster_chat_20019_1 = "Durante 30 anos vagueei pelas montanhas com o meu arco. "
gameforge.locale.monster_chat_20019_2 = "Com isto consegui sustentar a minha mulher e os meus tr\234s filhos. "
gameforge.locale.monster_chat_20019_3 = "\201 uma vida dif\237cil, mas vale a pena. "
gameforge.locale.monster_chat_20019_4 = "Mas agora a corda partiu-se e n\227o posso ca\231ar. N\227o consigo sustentar a minha fam\237lia assim! "
gameforge.locale.monster_chat_20019_5 = "Se n\227o reparar este arco, terei de comprar um novo. Mas n\227o tenho dinheiro para isso. "
gameforge.locale.monster_chat_20020_1 = "Hey! Para onde est\225s a olhar? "
gameforge.locale.monster_chat_20020_2 = "Fica longe daqui! "
gameforge.locale.monster_chat_20020_3 = "Durante quanto tempo mais terei de continuar escondido? "
gameforge.locale.monster_chat_20020_4 = "N\227o quero morrer sozinho e esquecido pelo mundo. "
gameforge.locale.monster_chat_20020_5 = "Algu\233m tem de me ajudar! "
gameforge.locale.monster_chat_20021_1 = "Este dia ir\225 terminar como qualquer outro. "
gameforge.locale.monster_chat_20021_2 = "Que posso fazer agora? "
gameforge.locale.monster_chat_20021_3 = "Nunca pensei que isto fosse acabar assim. "
gameforge.locale.monster_chat_20021_4 = "Ainda n\227o acredito que ele j\225 n\227o est\225 entre n\243s. "
gameforge.locale.monster_chat_20021_5 = "Ele n\227o merecia aquilo. "
gameforge.locale.monster_chat_20022_1 = "Mais um belo dia. "
gameforge.locale.monster_chat_20022_2 = "O marido da Ariyoung desapareceu. "
gameforge.locale.monster_chat_20022_3 = "Queria ajudar, mas esta teimosia... "
gameforge.locale.monster_chat_20022_4 = "Se ela tivesse casado comigo ela podia ter deixado a sua aborrecida vida para tr\225s. "
gameforge.locale.monster_chat_20022_5 = "Talvez devesse ter expressado os meus sentimentos por ela de outra forma. "
gameforge.locale.monster_chat_20023_1 = "Oh n\227o! Que irei fazer se a minha mulher descobrir? "
gameforge.locale.monster_chat_20023_2 = "Se eu pudesse ao menos viver da leitura de livros! "
gameforge.locale.monster_chat_20023_3 = "Cada livro absorve-te para o seu mundo misterioso. "
gameforge.locale.monster_chat_20023_4 = "N\227o posso viver assim para sempre, mas... "
gameforge.locale.monster_chat_20023_5 = "Gostaria de mudar, pela minha mulher, mas... "
gameforge.locale.monster_chat_20024_1 = "V\225 l\225, esfor\231a-te um pouco! "
gameforge.locale.monster_chat_20024_2 = "Que est\225s a fazer? N\227o te podes despachar? "
gameforge.locale.monster_chat_20024_3 = "Imagina um guerreiro a erguer a sua espada e faz o mesmo! "
gameforge.locale.monster_chat_20024_4 = "Onde se meteu aquele tolo? "
gameforge.locale.monster_chat_20024_5 = "Queres tornar-te um homem? "
gameforge.locale.monster_chat_2091_1 = "Cortar, cortar... Cabelos, gargantas... "
gameforge.locale.monster_chat_2091_2 = "Tenho algo para ti: sono eterno! "
gameforge.locale.monster_chat_2091_3 = "Respira fundo. N\227o te preocupes, \233 apenas veneno! "
gameforge.locale.monster_chat_2091_4 = "Vou deixar apenas a tua cara! Ser\225 uma boa decora\231\227o... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Enrolado em seda ser\225s um bom aperitivo para mais logo... "
gameforge.locale.monster_chat_2092_1 = "J\225 n\227o existem muitos de n\243s por a\237... "
gameforge.locale.monster_chat_2092_2 = "N\227o s\227o os seres de duas pernas que ir\227o mandar aqui. "
gameforge.locale.monster_chat_2092_3 = "Oh! Parece que algu\233m foi capturado pela minha teia! "
gameforge.locale.monster_chat_2092_4 = "Sou uma criatura pac\237fica. Apenas n\227o gosto que me irritem. "
gameforge.locale.monster_chat_2092_5 = "Isso \233 tudo o que consegues fazer? "
gameforge.locale.monster_chat_2092_6 = "Ningu\233m me consegue enfrentar! "
gameforge.locale.monster_chat_2104_1 = "Porque \233 que as pessoas s\227o t\227o h\250midas por dentro? Isso torna a minha espada ferrugenta! "
gameforge.locale.monster_chat_2104_2 = "O veneno do teu ferr\227o j\225 secou? "
gameforge.locale.monster_chat_2104_3 = "Ent\227o e que tal essa luta? "
gameforge.locale.monster_chat_2104_4 = "J\225 est\225s exausto pelo calor? "
gameforge.locale.monster_chat_2104_5 = "Gosto de deixar pessoas para tr\225s no deserto. "
gameforge.locale.monster_chat_2104_6 = "Coitado de ti, enterrado no deserto sem qualquer cerim\243nia... "
gameforge.locale.monster_chat_2105_1 = "Vou contar-te um segredo - detesto sujidade! "
gameforge.locale.monster_chat_2105_2 = "Est\225 muito calor, n\227o est\225? "
gameforge.locale.monster_chat_2105_3 = "Este lugar \233 perigoso. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Vou acertar-te no meio dos olhos! "
gameforge.locale.monster_chat_2106_1 = "Parece que j\225 tenho algo para matar. "
gameforge.locale.monster_chat_2106_2 = "Vejo os meus pr\243ximos esp\243lios diante mim. "
gameforge.locale.monster_chat_2106_3 = "Gosto disso, gosto muito disso! "
gameforge.locale.monster_chat_2106_4 = "Aquele ali \233 bom e gordo. \201 meu! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Adoro o cheiro do sangue. "
gameforge.locale.monster_chat_2107_1 = "Ultimamente n\227o h\225 muito para matar. "
gameforge.locale.monster_chat_2107_2 = "Hey! Estes s\227o mesmo gordos! "
gameforge.locale.monster_chat_2107_3 = "O l\237der vai gostar disto... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Vamos cal\231ar os nossos sapatos de dan\231a! "
gameforge.locale.monster_chat_2107_6 = "Esta flecha \233 s\243 para ti! "
gameforge.locale.monster_chat_2108_1 = "Se eu apanhar um, vou... "
gameforge.locale.monster_chat_2108_2 = "Hey, o que se passa? "
gameforge.locale.monster_chat_2108_3 = "Achas que me ir\225s derrotar facilmente? "
gameforge.locale.monster_chat_2108_4 = "Que mau para ti te teres cruzado comigo no deserto! "
gameforge.locale.monster_chat_2108_5 = "Ah, esta sensa\231\227o! Irei desfrutar dela para sempre! "
gameforge.locale.monster_chat_2108_6 = "Obrigado! "
gameforge.locale.monster_chat_2191_1 = "Sinto o cheiro de humanos. Que cheiro delicioso! "
gameforge.locale.monster_chat_2191_2 = "\201 isso mesmo, chega-te aqui... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "Que sorte que te tenhas perdido por aqui! "
gameforge.locale.monster_chat_2191_5 = "P\225ra! "
gameforge.locale.monster_chat_2191_6 = "Vou comer a tua carne peda\231o a peda\231o. "
gameforge.locale.monster_chat_2202_1 = "Aproxima-te para que eu te possa queimar. "
gameforge.locale.monster_chat_2202_2 = "Sabes quanta dor um enorme calor pode provocar? "
gameforge.locale.monster_chat_2202_3 = "Talvez devesse arrefecer as minhas chamas com sangue. "
gameforge.locale.monster_chat_2202_4 = "O teu sangue... deixa-me prov\225-lo. "
gameforge.locale.monster_chat_2202_5 = "N\227o faz sentido resistires. "
gameforge.locale.monster_chat_2202_6 = "Torna-te como eu! Apenas chamas e calor. "
gameforge.locale.monster_chat_2204_1 = "Enquanto eu aqui estiver, ningu\233m passar\225! "
gameforge.locale.monster_chat_2204_2 = "Por alguma raz\227o come\231as a irritar-me. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Sabes onde est\225s? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "\201s um advers\225rio pat\233tico! "
gameforge.locale.monster_chat_2205_1 = "Uma espada apenas tem utilidade nas m\227os de um guerreiro. "
gameforge.locale.monster_chat_2205_2 = "Mant\233m a espada na tua m\227o. "
gameforge.locale.monster_chat_2205_3 = "A guerra aproxima-se. "
gameforge.locale.monster_chat_2205_4 = "E agora lutaremos at\233 \224 morte! "
gameforge.locale.monster_chat_2205_5 = "N\227o vais conseguir continuar a resistir \224 morte! "
gameforge.locale.monster_chat_2205_6 = "Vais morrer lentamente. "
gameforge.locale.monster_chat_2206_1 = "A lava \233 o Elixir da Vida. "
gameforge.locale.monster_chat_2206_2 = "\201 a lava que me mant\233m vivo e com ela que morrer\225s! "
gameforge.locale.monster_chat_2206_3 = "N\227o \233 lindo, este mundo cheio de lava brilhante? "
gameforge.locale.monster_chat_2206_4 = "Atreves-te a incomodar-me? "
gameforge.locale.monster_chat_2206_5 = "Se amas a tua vida aconselho-te a desaparecer. "
gameforge.locale.monster_chat_2206_6 = "Vais arrepender-te de te cruzares comigo. "
gameforge.locale.monster_chat_2291_1 = "Est\225 um belo dia. Tudo o que quero \233 um pouco de paz. "
gameforge.locale.monster_chat_2291_2 = "Nenhum lugar se compara a Doyyumhwan. "
gameforge.locale.monster_chat_2291_3 = "Um pouco de carne fresca seria uma mudan\231a agrad\225vel. "
gameforge.locale.monster_chat_2291_4 = "Deves estar \224 procura da Morte, caso contr\225rio n\227o me perturbarias. "
gameforge.locale.monster_chat_2291_5 = "J\225 te arrependes de ter vindo at\233 aqui? "
gameforge.locale.monster_chat_2291_6 = "\201 demasiado tarde para fugires. Este \233 o teu destino. "
gameforge.locale.monster_chat_301_1 = "Estes dias tensos deixam-me nervosa. "
gameforge.locale.monster_chat_301_2 = "H\225 dois dias atr\225s uma pequena rapariga foi atacada por animais selvagens. "
gameforge.locale.monster_chat_301_3 = "Os animais selvagens est\227o a tornar-se mais agressivos. Dev\237amos matar tantos quanto pudermos. "
gameforge.locale.monster_chat_301_4 = "N\227o estou de bom humor. N\227o te deverias meter comigo. "
gameforge.locale.monster_chat_301_5 = "O \250ltimo guerreiro que morreu pelas minhas m\227os implorou pela sua vida. "
gameforge.locale.monster_chat_302_1 = "Algu\233m tem de fazer algo em rela\231\227o a estas Pedras. "
gameforge.locale.monster_chat_302_2 = "N\227o confio na paz da manh\227. "
gameforge.locale.monster_chat_302_3 = "A tens\227o no ar est\225 a deixar-me desconfort\225vel. "
gameforge.locale.monster_chat_302_4 = "Estas pontas de flecha foram muito bem forjadas. "
gameforge.locale.monster_chat_302_5 = "Se eu estivesse no teu lugar teria cuidado. A flecha est\225 apontada ao teu cora\231\227o. "
gameforge.locale.monster_chat_302_6 = "Devia ir matar algumas criaturas. "
gameforge.locale.monster_chat_303_1 = "Hoje em dia \233 preciso termos um bom treino de combate. "
gameforge.locale.monster_chat_303_2 = "Os soldados j\225 n\227o conseguem controlar o caos no Reino. "
gameforge.locale.monster_chat_303_3 = "Porque est\225s a olhar para mim dessa forma? "
gameforge.locale.monster_chat_303_4 = "Os cobardes t\234m pouca hip\243tese de sobreviver. "
gameforge.locale.monster_chat_303_5 = "N\227o te sobrestimes. "
gameforge.locale.monster_chat_303_6 = "Parece que algu\233m te treinou bem. "
gameforge.locale.monster_chat_304_1 = "At\233 os meus antepassados se conseguiram impor em combate nestes territ\243rios. "
gameforge.locale.monster_chat_304_2 = "Aqui tens de estar atento e ser habilidoso. "
gameforge.locale.monster_chat_304_3 = "Nem penses em gastar o meu tempo. "
gameforge.locale.monster_chat_304_4 = "Ent\227o, como \233 saber que a tua vida est\225 em perigo? "
gameforge.locale.monster_chat_304_5 = "J\225 queres desistir? "
gameforge.locale.monster_chat_304_6 = "Prepara-te para sofrer. "
gameforge.locale.monster_chat_305_1 = "Oh! Essa espada \233 fant\225stica. "
gameforge.locale.monster_chat_305_2 = "Se persistente e aumenta o teu poder! "
gameforge.locale.monster_chat_305_3 = "Achas que consegues ser t\227o forte como eu? "
gameforge.locale.monster_chat_305_4 = "Ok. Vamos a coisas s\233rias. "
gameforge.locale.monster_chat_305_5 = "Oh! Sou uma simples e fraca mulher! "
gameforge.locale.monster_chat_305_6 = "Pareces cansado. Porque n\227o desistes j\225? Hehe. "
gameforge.locale.monster_chat_306_1 = "O que \233 que Serangyi ir\225 fazer hoje? "
gameforge.locale.monster_chat_306_2 = "Estou t\227o aborrecida. Brinca comigo! "
gameforge.locale.monster_chat_306_3 = "Devo confessar que gosto mais do Sura. "
gameforge.locale.monster_chat_306_4 = "Hey! E que tal uma luta? "
gameforge.locale.monster_chat_306_5 = "N\227o me subestimes s\243 por ser uma mulher! "
gameforge.locale.monster_chat_306_6 = "A dor s\243 durar\225 um momento. "
gameforge.locale.monster_chat_307_1 = "Quero sair daqui a todo o custo. "
gameforge.locale.monster_chat_307_2 = "Qu\227o seguras s\227o as casas dos habitantes da vila? "
gameforge.locale.monster_chat_307_3 = "Raparigas, calem-se! "
gameforge.locale.monster_chat_307_4 = "Deixa-me matar-te com um s\243 golpe. "
gameforge.locale.monster_chat_307_5 = "Nem penses em fugir! "
gameforge.locale.monster_chat_307_6 = "Ent\227o, porque n\227o come\231amos? "
gameforge.locale.monster_chat_394_1 = "N\227o se esque\231am: todos os homens s\227o inimigos. "
gameforge.locale.monster_chat_394_2 = "Se algu\233m tiver uma cara simp\225tica podemos abrir uma excep\231\227o... "
gameforge.locale.monster_chat_394_3 = "O qu\234? Queres lutar? "
gameforge.locale.monster_chat_394_4 = "N\227o demorar\225 muito, mas ir\225 doer. "
gameforge.locale.monster_chat_394_5 = "Oh, realmente pareces estar em dor. "
gameforge.locale.monster_chat_394_6 = "Adeus! Vai para o inferno! "
gameforge.locale.monster_chat_401_1 = "Ent\227o... O que fazes na Jura de Cristal? "
gameforge.locale.monster_chat_401_2 = "Onde vais? "
gameforge.locale.monster_chat_401_3 = "Hey! Queres lutar? "
gameforge.locale.monster_chat_401_4 = "Hehe! Est\225s a esquivar-te dos meus ataques. "
gameforge.locale.monster_chat_401_5 = "Pensas que consegues fugir de mim? "
gameforge.locale.monster_chat_401_6 = "C\225 vai o meu golpe! "
gameforge.locale.monster_chat_402_1 = "Meu Deus, estou t\227o cansado! "
gameforge.locale.monster_chat_402_2 = "Hey, bela armadura! Foi muito cara? "
gameforge.locale.monster_chat_402_3 = "Pelo menos temos bom tempo. "
gameforge.locale.monster_chat_402_4 = "Oh! Tens andado a treinar bastante! Excelente! "
gameforge.locale.monster_chat_402_5 = "O que achas das minhas habilidades? Boas, n\227o? Hehe. "
gameforge.locale.monster_chat_402_6 = "Que se passa? Oh, a minha rapidez incr\237vel est\225 a irritar-te! "
gameforge.locale.monster_chat_403_1 = "Porque n\227o vou ca\231ar? "
gameforge.locale.monster_chat_403_2 = "Ainda ningu\233m atacou a nossa vila hoje. "
gameforge.locale.monster_chat_403_3 = "Se queres lutar, luta, maldito! "
gameforge.locale.monster_chat_403_4 = "Hehe! \201s s\243 um principiante. "
gameforge.locale.monster_chat_403_5 = "Onde te deverei acertar primeiro... No bra\231o ou na perna? "
gameforge.locale.monster_chat_403_6 = "Aqui vai a minha flecha! "
gameforge.locale.monster_chat_404_1 = "Brevemente terei de ir \224 vila e treinar. "
gameforge.locale.monster_chat_404_2 = "Sinto-me muito tenso. "
gameforge.locale.monster_chat_404_3 = "O que ser\225 o jantar hoje? "
gameforge.locale.monster_chat_404_4 = "Estou a observar-te, por isso grita tanto quanto quiseres. "
gameforge.locale.monster_chat_404_5 = "J\225 esperaste muito? E que tal ergueres essa espada?! "
gameforge.locale.monster_chat_404_6 = "A tua espada faz um som \243ptimo! "
gameforge.locale.monster_chat_405_1 = "A minha espada est\225 a postos! "
gameforge.locale.monster_chat_405_2 = "Hmm, vamos ver: Quem \233 que esta espada vai matar primeiro... "
gameforge.locale.monster_chat_405_3 = "Hey! Para onde est\225s a olhar? "
gameforge.locale.monster_chat_405_4 = "Primeiro o teu est\244mago! "
gameforge.locale.monster_chat_405_5 = "Gostaria de te usar como bainha. "
gameforge.locale.monster_chat_405_6 = "Gostaria de te usar como bainha. "
gameforge.locale.monster_chat_406_1 = "Estou a morrer de fome. "
gameforge.locale.monster_chat_406_2 = "H\225 alguma coisa que se coma? "
gameforge.locale.monster_chat_406_3 = "Porque estou ainda com tanta fome depois de comer tanto? "
gameforge.locale.monster_chat_406_4 = "Argh! Morre! "
gameforge.locale.monster_chat_406_5 = "O meu est\244mago ir\225 decidir este combate! "
gameforge.locale.monster_chat_406_6 = "\201 a escolha entre o Para\237so e o Inferno! "
gameforge.locale.monster_chat_491_1 = "N\227o aguento mais! O meu corpo est\225 em pulgas. "
gameforge.locale.monster_chat_491_2 = "Oh sim! J\225 vejo os porcos! "
gameforge.locale.monster_chat_491_3 = "J\225 no ch\227o? "
gameforge.locale.monster_chat_491_4 = "Vou acabar contigo com apenas um golpe! "
gameforge.locale.monster_chat_491_5 = "Isto vai ficar na minha mem\243ria! "
gameforge.locale.monster_chat_491_6 = "Morre! "
gameforge.locale.monster_chat_492_1 = "O meu corpo est\225 mole. "
gameforge.locale.monster_chat_492_2 = "Porque \233 que n\227o treino mais? "
gameforge.locale.monster_chat_492_3 = "Com medo, hein? "
gameforge.locale.monster_chat_492_4 = "Ah, mais uma v\237tima para a minha arma poderosa. "
gameforge.locale.monster_chat_492_5 = "Percebes o meu padr\227o de ataque? N\227o? Pior para ti! "
gameforge.locale.monster_chat_492_6 = "At\233 os mais pequenos cortes influenciam a tua vida. Especialmente se forem feitos por uma moca! "
gameforge.locale.monster_chat_493_1 = "Raios, estas m\227os n\227o d\227o jeito nenhum. "
gameforge.locale.monster_chat_493_2 = "Para onde est\225s a olhar? Nunca viste ningu\233m com um punho de a\231o? "
gameforge.locale.monster_chat_493_3 = "Voc\234s enervam-me realmente. "
gameforge.locale.monster_chat_493_4 = "Queres que te espanque? Se n\227o, come\231a a correr! Percebeste? "
gameforge.locale.monster_chat_493_5 = "Vou mostrar-te o meu melhor golpe! "
gameforge.locale.monster_chat_493_6 = "P\225ra de olhar para a minha m\227o! "
gameforge.locale.monster_chat_494_1 = "Hey, tu a\237! Queres lutar? Ent\227o chega-te aqui! "
gameforge.locale.monster_chat_494_2 = "Acho que sou de cortar a respira\231\227o. "
gameforge.locale.monster_chat_494_3 = "Porque n\227o planeamos qualquer coisa? "
gameforge.locale.monster_chat_494_4 = "N\227o! Anda n\227o te autorizei a ir embora! Luta! "
gameforge.locale.monster_chat_494_5 = "A\237 tens! "
gameforge.locale.monster_chat_494_6 = "Est\225s feito ao bife! "
gameforge.locale.monster_chat_501_1 = "Hey, fica aqui! Brinca comigo! "
gameforge.locale.monster_chat_501_2 = "Podia criar algo engra\231ado com os teus ossos... "
gameforge.locale.monster_chat_501_3 = "Ainda n\227o trein\225mos hoje. "
gameforge.locale.monster_chat_501_4 = "Que bela armadura! Quero-a para mim! "
gameforge.locale.monster_chat_501_5 = "A partir de agora ser\225 mais dif\237cil ignorares os meus ataques. "
gameforge.locale.monster_chat_501_6 = "Ha, ha, ha! Aposto que n\227o estavas \224 espera disto! "
gameforge.locale.monster_chat_502_1 = "A beleza n\227o \233 tudo. "
gameforge.locale.monster_chat_502_2 = "N\227o fiques a olhar! Luta! "
gameforge.locale.monster_chat_502_3 = "N\227o gosto da forma como olhas para mim. Luta! "
gameforge.locale.monster_chat_502_4 = "Ser\225 uma honra morreres pela minha espada! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Excelente! "
gameforge.locale.monster_chat_503_1 = "Hey! N\227o toques! "
gameforge.locale.monster_chat_503_2 = "Parece que a corda do meu arco foi cortada. "
gameforge.locale.monster_chat_503_3 = "Raios, aqueles idiotas estiveram aqui! "
gameforge.locale.monster_chat_503_4 = "Nada mau... Mas vais morrer de qualquer maneira! "
gameforge.locale.monster_chat_503_5 = "Parece-te bem? \211ptimo! "
gameforge.locale.monster_chat_503_6 = "Aqui vai a minha flecha! "
gameforge.locale.monster_chat_504_1 = "Venham c\225 todos! "
gameforge.locale.monster_chat_504_2 = "La, lala, estou a assobiar uma m\250sica... "
gameforge.locale.monster_chat_504_3 = "Que belo tempo! "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "\211ptimo! Gosto do teu esp\237rito lutador! "
gameforge.locale.monster_chat_504_6 = "Venham c\225! Venham todos a mim! "
gameforge.locale.monster_chat_601_1 = "Estou a morrer de fome! "
gameforge.locale.monster_chat_601_2 = "Sinto desejos de frutas. "
gameforge.locale.monster_chat_601_3 = "Bom, o peixe tamb\233m serve. Ao ataque! "
gameforge.locale.monster_chat_601_4 = "N\227o fujas! Fica aqui! "
gameforge.locale.monster_chat_601_5 = "Ganhei. \201 \243bvio! "
gameforge.locale.monster_chat_601_6 = "V\234s? Falhaste! "
gameforge.locale.monster_chat_601_7 = "Devias ter cuidado! Haha! "
gameforge.locale.monster_chat_602_1 = "Onde estou? "
gameforge.locale.monster_chat_602_2 = "Que belo tempo. "
gameforge.locale.monster_chat_602_3 = "Vieste ca\231ar-me? Absurdo! "
gameforge.locale.monster_chat_602_4 = "\201s a minha pr\243xima v\237tima. "
gameforge.locale.monster_chat_602_5 = "Doloroso, n\227o \233? Bom, vai ser r\225pido. "
gameforge.locale.monster_chat_602_6 = "V\234 o qu\227o forte sou: consigo empunhar esta moca enorme! "
gameforge.locale.monster_chat_603_1 = "Aborrecido! "
gameforge.locale.monster_chat_603_2 = "O meu corpo est\225 em pulgas. "
gameforge.locale.monster_chat_603_3 = "Vamos ver quem \233 mais r\225pido. "
gameforge.locale.monster_chat_603_4 = "Tu \233 que come\231aste. Por isso n\227o me responsabilizes pela tua morte! "
gameforge.locale.monster_chat_603_5 = "Assim que aqui entras nunca mais sais! N\227o h\225 escapat\243ria! "
gameforge.locale.monster_chat_603_6 = "Este ser\225 o meu \250ltimo golpe. Vou acabar contigo! "
gameforge.locale.monster_chat_604_1 = "Criei um novo veneno delicioso. Queres prov\225-lo? "
gameforge.locale.monster_chat_604_2 = "Quero ver como funciona! Toma! "
gameforge.locale.monster_chat_604_3 = "Hey, tu! Anda c\225. Queres ser a minha cobaia? "
gameforge.locale.monster_chat_604_4 = "Vou envenenar-te! "
gameforge.locale.monster_chat_604_5 = "Oh! \211ptimo! Uma cobaia! "
gameforge.locale.monster_chat_604_6 = "N\227o me divirto se desistires t\227o depressa! Anda l\225, defende-te! "
gameforge.locale.monster_chat_631_1 = "Espera um pouco. Estou \224 procura de algo para ca\231ar. "
gameforge.locale.monster_chat_631_2 = "N\227o te serve de nada seres t\227o lento. Mexe-te! "
gameforge.locale.monster_chat_631_3 = "Tenho tanta fome! "
gameforge.locale.monster_chat_631_4 = "Ainda bem que encontrei algo para ca\231ar! "
gameforge.locale.monster_chat_631_5 = "Que toda a esperan\231a de sobreviver desapare\231a! N\227o passar\225s por mim! "
gameforge.locale.monster_chat_631_6 = "Agora ir\225s descobrir como \233 a verdadeira dor! "
gameforge.locale.monster_chat_632_1 = "Aborreciiiiiiiido! "
gameforge.locale.monster_chat_632_2 = "H\225 por a\237 algo que eu possa usar como isco? "
gameforge.locale.monster_chat_632_3 = "Vem e luta se quiseres! "
gameforge.locale.monster_chat_632_4 = "Queres ser um guerreiro? Ent\227o mostra-me o que vales! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Foge e volta para a vila se quiseres viver! "
gameforge.locale.monster_chat_633_1 = "Morrer de fome \233 uma morte deplor\225vel. "
gameforge.locale.monster_chat_633_2 = "Oh! Eles v\234m direitos a n\243s! "
gameforge.locale.monster_chat_633_3 = "E que tal um duelo? "
gameforge.locale.monster_chat_633_4 = "N\227o me compares a esses malditos! "
gameforge.locale.monster_chat_633_5 = "Aqui vai o meu golpe trov\227o! Ha! "
gameforge.locale.monster_chat_633_6 = "Aqueles que fogem n\227o s\227o verdadeiros Guerreiros! "
gameforge.locale.monster_chat_634_1 = "Desta vez o veneno dever\225 ser mais eficiente! "
gameforge.locale.monster_chat_634_2 = "Quando tens fome, at\233 os morcegos se tornam uma verdadeira del\237cia! "
gameforge.locale.monster_chat_634_3 = "E que tal um combate? "
gameforge.locale.monster_chat_634_4 = "Assim que o meu veneno penetrar no teu corpo n\227o ter\225s cura poss\237vel! "
gameforge.locale.monster_chat_634_5 = "A minha magia ir\225 queimar tudo! Hehehe! "
gameforge.locale.monster_chat_634_6 = "Arde! Haha! "
gameforge.locale.monster_chat_635_1 = "Nunca te esque\231as afiar a tua espada! O pr\243ximo combate pode ser mais cedo do que pensas. "
gameforge.locale.monster_chat_635_2 = "Sentes-te zonzo? "
gameforge.locale.monster_chat_635_3 = "Morre e acorda no Al\233m! "
gameforge.locale.monster_chat_635_4 = "Derrotar-me? Achas mesmo? "
gameforge.locale.monster_chat_635_5 = "Luta como um homem! "
gameforge.locale.monster_chat_635_6 = "V\225 l\225, s\243 mais um pouco. "
gameforge.locale.monster_chat_636_1 = "Ha, estou \224 espera de um bom combate. "
gameforge.locale.monster_chat_636_2 = "Combater \233 divertido, haha! "
gameforge.locale.monster_chat_636_3 = "Luta! Mais e mais! Sim! "
gameforge.locale.monster_chat_636_4 = "Ha, muito bem! Tenta-o de novo! "
gameforge.locale.monster_chat_636_5 = "Olha para a minha espada a girar! "
gameforge.locale.monster_chat_636_6 = "Vais arrepender-te de me ter acertado! "
gameforge.locale.monster_chat_636_7 = "T\227o fraco! Que rid\237culo! "
gameforge.locale.monster_chat_637_1 = "N\227o quero ser interrompido. "
gameforge.locale.monster_chat_637_2 = "Vai dormir. Para sempre! "
gameforge.locale.monster_chat_637_3 = "Continuas a n\227o querer ir dormir? "
gameforge.locale.monster_chat_637_4 = "H\225 tanto para fazer! Vamos l\225 terminar isto! "
gameforge.locale.monster_chat_637_5 = "N\227o fiques abismado com todo o meu poder! "
gameforge.locale.monster_chat_637_6 = "Vou pulverizar-te! "
gameforge.locale.monster_chat_691_1 = "\211ptimo, advers\225rios fortes duram mais! Defende-te! "
gameforge.locale.monster_chat_691_2 = "O que foi? Tens algum problema com o meu irm\227o? "
gameforge.locale.monster_chat_691_3 = "N\227o me compares a esse principiante! "
gameforge.locale.monster_chat_691_4 = "Ele n\227o gosta de ti. Nem eu! "
gameforge.locale.monster_chat_691_5 = "Vamos lutar! "
gameforge.locale.monster_chat_691_6 = "At\233 \224 morte! "
gameforge.locale.monster_chat_701_1 = "Olha, uma borboleta! T\227o bonita! "
gameforge.locale.monster_chat_701_2 = "N\227o v\234s a verdade sobre o C\233u e Terra? "
gameforge.locale.monster_chat_701_3 = "Depois vai ser demasiado tarde! Tens de acreditar agora! "
gameforge.locale.monster_chat_701_4 = "Acredita na doutrina dos Esot\233ricos! "
gameforge.locale.monster_chat_701_5 = "Todos aqueles que duvidarem ser\227o mortos! "
gameforge.locale.monster_chat_701_6 = "Obt\233m o conhecimento aceitando a morte! "
gameforge.locale.monster_chat_702_1 = "A verdade da cren\231a Esot\233rica baseia-se na compreens\227o da ordem do c\233u. "
gameforge.locale.monster_chat_702_2 = "A filosofia da cren\231a Esot\233rica \233 a ordem celestial! "
gameforge.locale.monster_chat_702_3 = "Verdade Esot\233rica! Verdade do Deus Tigre! Sabaha Sabaha! "
gameforge.locale.monster_chat_702_4 = "Atreves-te a duvidar da verdade sobre o C\233u e a Terra? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Sente as minhas garras! "
gameforge.locale.monster_chat_703_1 = "Quando a verdade do Deus Tigre for cantada por toda a eternidade todo o sofrimento acabar\225. "
gameforge.locale.monster_chat_703_2 = "A verdade da cren\231a Esot\233rica baseia-se na compreens\227o da ordem do c\233u. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha! Envia-nos a tua sabedoria! "
gameforge.locale.monster_chat_703_4 = "N\227o duvides! "
gameforge.locale.monster_chat_703_5 = "Recebe o trov\227o do C\233u! "
gameforge.locale.monster_chat_703_6 = "Golpe do Ju\237zo Final! "
gameforge.locale.monster_chat_704_1 = "A verdade da cren\231a Esot\233rica baseia-se na compreens\227o da ordem do c\233u. "
gameforge.locale.monster_chat_704_2 = "Verdade Esot\233rica! Verdade do Deus Tigre! Sabaha Sabaha! "
gameforge.locale.monster_chat_704_3 = "Pensas que sou um palha\231o n\227o \233? N\227o o far\225s por muito tempo! "
gameforge.locale.monster_chat_704_4 = "O l\237der da Seita \233 um santo acima de qualquer coisa viva! "
gameforge.locale.monster_chat_704_5 = "Arde nas chamas do Inferno! "
gameforge.locale.monster_chat_704_6 = "Aposto que nunca viste um Diapas\227o t\227o grande, hein? "
gameforge.locale.monster_chat_705_1 = "Verdade Esot\233rica! Verdade do Deus Tigre! Sabaha Sabaha! "
gameforge.locale.monster_chat_705_2 = "A verdade da cren\231a Esot\233rica baseia-se na compreens\227o da ordem do c\233u. "
gameforge.locale.monster_chat_705_3 = "S\243 porque sou mais baixo que o meu irm\227o n\227o significa que possa aturar tudo! "
gameforge.locale.monster_chat_705_4 = "A escurid\227o e dor eternas esperam-te! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Isto n\227o \233 o fim. Pelo contr\225rio: S\243 vai ficar melhor. "
gameforge.locale.monster_chat_706_1 = "Apenas pedimos paz e privacidade! Por favor! "
gameforge.locale.monster_chat_706_2 = "Se o medo se apoderar de ti, coloca a tua f\233 no Deus Tigre. "
gameforge.locale.monster_chat_706_3 = "A verdade da cren\231a Esot\233rica \233 o caminho para o conhecimento do C\233u. "
gameforge.locale.monster_chat_706_4 = "Vamos todos para o Inferno! "
gameforge.locale.monster_chat_706_5 = "N\227o te deixarei escapar! "
gameforge.locale.monster_chat_706_6 = "Irei dar-te tudo o que tenho. "
gameforge.locale.monster_chat_707_1 = "Imploro-te! Por favor salva-nos! "
gameforge.locale.monster_chat_707_2 = "A verdade da cren\231a Esot\233rica baseia-se na compreens\227o da ordem do c\233u. "
gameforge.locale.monster_chat_707_3 = "Verdade Esot\233rica! Verdade do Deus Tigre! Sabaha Sabaha! "
gameforge.locale.monster_chat_707_4 = "Os port\245es para o Inferno est\227o escancarados. Entra! "
gameforge.locale.monster_chat_707_5 = "Estou a avisar-te: N\227o me obrigues a usar a t\225bua! "
gameforge.locale.monster_chat_707_6 = "J\225 prevejo a tua morte! "
gameforge.locale.monster_chat_791_1 = "Deixa-me ver: Como posso resumir a ordem do c\233u e da terra em poucas palavras? "
gameforge.locale.monster_chat_791_2 = "Ou\231o os cantos dos crentes. "
gameforge.locale.monster_chat_791_3 = "Est\225 certo! Enche-te de remorsos e ser\225s resgatado! "
gameforge.locale.monster_chat_791_4 = "Ir\225s sofrer eternamente por continuares a questionar a nossa f\233. "
gameforge.locale.monster_chat_791_5 = "Deixa-me ensinar-te. "
gameforge.locale.monster_chat_791_6 = "N\227o o vejas como dor - v\234-o como uma li\231\227o. "
gameforge.locale.monster_chat_901_1 = "Posso n\227o ser bonito, mas divirto-me bastante, hihihi! "
gameforge.locale.monster_chat_901_2 = "Tens de te tornar um de n\243s! "
gameforge.locale.monster_chat_901_3 = "Vem at\233 n\243s, hihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "Aqui vamos n\243s! "
gameforge.locale.monster_chat_903_1 = "Isto \233 o Inferno! "
gameforge.locale.monster_chat_903_2 = "Ahhhhh! "
gameforge.locale.monster_chat_903_3 = "N\227o conseguimos fazer isto sozinhos! N\227o! "
gameforge.locale.monster_chat_903_4 = "Tu tamb\233m ter\225s de provar a dor! "
gameforge.locale.monster_chat_903_5 = "E que tal uma troca? D\225s-me a tua Alma e eu dou-te o meu sofrimento! "
gameforge.locale.monster_chat_903_6 = "Dentro em breve encontrar\225s a paz eterna! "
gameforge.locale.monster_chat_904_1 = "A dor! A dor! "
gameforge.locale.monster_chat_904_2 = "Aargghh, raios! Os meus bra\231os ardem! "
gameforge.locale.monster_chat_904_3 = "Porque temos de sofrer assim? O que fizemos para merecer isto? "
gameforge.locale.monster_chat_904_4 = "Sofrer desta misteriosa doen\231a nem \233 assim t\227o mau! "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhhh! "
gameforge.locale.monster_chat_905_2 = "Eu maaaaaaaato-te! "
gameforge.locale.monster_chat_905_3 = "N\227o te limites a olhar! Participa! "
gameforge.locale.monster_chat_905_4 = "Vamos ser amigos! "
gameforge.locale.monster_chat_905_5 = "J\225 est\225s infectado! "
gameforge.locale.monster_chat_905_6 = "Agora \233s meu amigo. "
gameforge.locale.monster_chat_906_1 = "Hihihi! "
gameforge.locale.monster_chat_906_2 = "Vem c\225 e espeta-te nas minhas flechas. "
gameforge.locale.monster_chat_906_3 = "Est\225s a come\231ar a irritar-me... "
gameforge.locale.monster_chat_906_4 = "Vou infectar-te com a nossa misteriosa doen\231a! "
gameforge.locale.monster_chat_906_5 = "Que cheiro de criar \225gua na boca! "
gameforge.locale.monster_chat_906_6 = "Morre! "
gameforge.locale.monster_chat_907_1 = "E se eu encontrar outra causa da doen\231a... "
gameforge.locale.monster_chat_907_2 = "Ha, ha! Isto vai ser divertido! "
gameforge.locale.monster_chat_907_3 = "Hmm, chicotear ou agarrar...? "
gameforge.locale.monster_chat_907_4 = "Ahhhhh, siiiiiim! "
gameforge.locale.monster_chat_907_5 = "Deixa-me transmitir-te a doen\231a! "
gameforge.locale.monster_chat_907_6 = "A causa desta misteriosa doen\231a persiste! "
