gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Leva uma amostra do agente patog\233nico a Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "Leva uma amostra do agente patog\233nico ao Baek-Go[ENTER]e recebe o Rem\233dio para o Velho Pirata. "
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "Tenho uma amostra do agente respons\225vel pela[ENTER]doen\231a misteriosa. "
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Tenho uma amostra do v\237rus da doen\231a misteriosa.[ENTER]Devia lev\225-la ao Baek-Go. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "N\227o sei o que est\225 por detr\225s desta misteriosa[ENTER]doen\231a. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Descobri a causa da doen\231a misteriosa. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "Mata todas as pessoas infectadas "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "Mata todos os que tiverem sido infectados pela[ENTER]doen\231a misteriosa! "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Mata todos os que tiverem sido infectados pela[ENTER]doen\231a misteriosa e leva uma amostra do agente[ENTER]respons\225vel ao Baek-Go. Ele vai criar um Rem\233dio[ENTER]para o Velho Pirata. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Outra pessoa j\225 me entregou uma amostra do agente[ENTER]respons\225vel. J\225 enviei o Rem\233dio ao Velho Pirata;[ENTER]ele j\225 deve estar a ficar bom. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]Ele teve contacto com algu\233m infectado apenas uma[ENTER]vez e a sua ferida come\231ou a dar comich\227o e a[ENTER]infectar? "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go:[ENTER]Minha nossa! Tenho a certeza que ele est\225[ENTER]infectado com a misteriosa doen\231a! Se ele n\227o for[ENTER]tratado, a doen\231a espalhar-se-\225 por toda a vila! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Ele n\227o pode infectar ningu\233m! Tens de o tratar[ENTER]imediatamente. Para isso precisamos de uma[ENTER]amostra do v\237rus da doen\231a misteriosa. Podes[ENTER]obt\234-lo de uma pessoa doente. H\225 muitas[ENTER]espalhadas pela Montanha Sohan. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Conseguiste! Espera um momento, vou j\225 fazer o[ENTER]Rem\233dio.[DELAY value;1000] [/DELAY][ENTER][ENTER]Estive a faz\234-lo \224 pressa, portanto n\227o sei ir\225[ENTER]funcionar, mas pelo menos dever\225 melhorar o seu[ENTER]estado. Leva-lhe o Rem\233dio o mais r\225pido[ENTER]poss\237vel. "
gameforge.locale.old_pirate.baekgo_talk = "O Velho Pirata enviou-me. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "A doen\231a do Velho Pirata "
gameforge.locale.old_pirate.complete_say = "Velho Pirata:[ENTER]Ainda tenho comich\227o. Mas j\225 me sinto melhor.[ENTER]Acho que posso viver com isto. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "Ainda n\227o tenho o Rem\233dio. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "Aqui est\225 a cura! "
gameforge.locale.old_pirate.etc_shop_start_say = "Loja Geral:[ENTER]O Velho Pirata? Claro que o conhe\231o! Est\225s a[ENTER]falar do tipo que est\225 sempre a dizer asneiras e[ENTER]a co\231ar-se? Ele costuma pedir-me rem\233dios. Ele[ENTER]at\233 gastou v\225rios milhares de Yangs para[ENTER]conseguir comprar Po\231\245es Vermelhas! "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Negociadora da Loja Geral:[ENTER]Onde raio ele consegue tanto Yang se ele nem anda[ENTER]a trabalhar? J\225 lhe disse in\250meras vezes que ele[ENTER]devia deixar um doutor examin\225-lo, mas ele n\227o[ENTER]liga ao que eu digo.[ENTER]A cura vermelha apenas alivia os sintomas, mas[ENTER]n\227o cura a doen\231a. Penso que isto n\227o vai acabar[ENTER]bem para ele. "
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "Conheces o Velho Pirata? "
gameforge.locale.old_pirate.order_accept = "Irei ajudar-te. "
gameforge.locale.old_pirate.order_accept_answer = "Velho Pirata:[ENTER]Ainda bem! Boa Sorte![ENTER]Penso que o m\233dico esteja na vila. "
gameforge.locale.old_pirate.order_find_medicine_label = "Rem\233dio para o Velho Pirata "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Obt\233m o Rem\233dio para o Velho Pirata. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Procura o Baek-Go na vila e pergunta-lhe sobre o[ENTER]Rem\233dio para o Velho Pirata. "
gameforge.locale.old_pirate.order_refuse = "Desculpa, mas n\227o consigo. "
gameforge.locale.old_pirate.order_refuse_answer = "Velho Pirata:[ENTER]Bom, ent\227o n\227o tenho mais nada para te dizer! "
gameforge.locale.old_pirate.order_say1 = "Velho Pirata:[ENTER]Raios, o que queres de mim? Bolas! Aquela mulher[ENTER]chata da Loja Geral contou-te sobre mim, n\227o foi?[ENTER]Sim, tudo o que ela disse \233 verdade. Mas n\227o[ENTER]tenho tempo para ir ver um m\233dico. Tenho tantos[ENTER]inimigos! "
gameforge.locale.old_pirate.order_say2 = "Velho Pirata:[ENTER]Nunca se sabe se um desses patifes n\227o te aparece[ENTER]\224 frente do nada para te atacar! Mas esta[ENTER]comich\227o \233 horr\237vel; n\227o aguento mais! Podes ir[ENTER]ter com o m\233dico e pedir-lhe um rem\233dio? Que tal?[ENTER]Se o fizeres irei dar-te uma boa recompensa. "
gameforge.locale.old_pirate.order_too_late = "Velho Pirata:[ENTER]Outra pessoa trouxe-me o Rem\233dio primeiro,[ENTER]portanto... n\227o ir\225s receber a recompensa! "
gameforge.locale.old_pirate.start_find_old_pirate_label = "Vai falar com o Velho Pirata. "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Vai falar com o Velho Pirata. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Vai perguntar ao Velho Pirata a raz\227o de n\227o ir[ENTER]ver um m\233dico. "
gameforge.locale.old_pirate.start_say = "Velho Pirata:[ENTER]Tenho comich\227o em todo o lado! Eu nunca deveria[ENTER]ter dado um encontr\227o naquele homem! N\243s quase[ENTER]que nem nos tocamos! Desde esse momento o local[ENTER]do encontr\227o ulcerou e tenho comich\227o em todo o[ENTER]meu corpo! Parece que estou a apodrecer vivo! "
gameforge.locale.old_pirate.success_thanks = "Velho Pirata:[ENTER]O qu\234? Fui infectado pela doen\231a misteriosa?! E[ENTER]este \233 o Rem\233dio necess\225rio? Muito, muito[ENTER]obrigado! Provavelmente salvaste a minha vida.[ENTER]Fico agradecido. "
gameforge.locale.old_pirate.talk = "\201s o Velho Pirata? "
gameforge.locale.old_pirate.talk_about_medicine = "Porque \233 que n\227o vai ver um m\233dico? "
