gameforge.locale.questscroll5.mission_10_hunt = "A marcha dos Ursos esfomeados "
gameforge.locale.questscroll5.mission_10_mis = "Mata 25 Ursos Negros e 25 Ursos Cinza. "
gameforge.locale.questscroll5.mission_10_text = "Oh, por favor ajuda-nos. Recentemente tem havido[ENTER]um crescimento no n\250mero de Ursos Negros e Ursos[ENTER]Cinza que atacam as nossas colmeias e planta\231\245es.[ENTER]Por favor ajuda-nos a matar essas criaturas, ou[ENTER]iremos morrer \224 fome! "
gameforge.locale.questscroll5.mission_11_hunt = "A invas\227o de Lobos Azuis "
gameforge.locale.questscroll5.mission_11_mis = "Mata 35 Lobos Azuis e 25 Lobos Alfa Azuis. "
gameforge.locale.questscroll5.mission_11_text = "J\225 ouviste falar da invas\227o de Lobos Azuis?[ENTER]Est\225 relacionada com as confus\245es que os Lobos[ENTER]Azuis t\234m causado nas \250ltimas semanas. Eles[ENTER]destroem tudo no seu caminho, como uma tempestade[ENTER]de p\234lo e presas.[ENTER]Aventureiro, consegues parar esta invas\227o? "
gameforge.locale.questscroll5.mission_12_hunt = "Expuls\227o da Armada de Cristal "
gameforge.locale.questscroll5.mission_12_mis = "Mata 20 Capit\227s Jura de Cristal. "
gameforge.locale.questscroll5.mission_12_text = "Recentemente o cl\227 Jura de Cristal tem causado[ENTER]montes de trabalho. Elas raptam vendedores[ENTER]ambulantes e atacam a vila com frequ\234ncia. Por[ENTER]favor p\225ra o cl\227 Jura de Cristal. Elimina os[ENTER]membros do cl\227 Jura de Cristal e o seu l\237der. "
gameforge.locale.questscroll5.mission_13_hunt = "A agita\231\227o do cl\227 Vento Negro "
gameforge.locale.questscroll5.mission_13_mis = "Mata 25 Jak-To e 25 To-Su do cl\227 Vento Negro. "
gameforge.locale.questscroll5.mission_13_text = "Diz-se por a\237 que o cl\227 Vento Negro quer tomar o[ENTER]reino de assalto. Dever\237amos eliminar os seus[ENTER]l\237deres antes de eles fortalecerem o seu[ENTER]ex\233rcito.[ENTER]Por favor elimina os l\237deres do cl\227 Vento Negro. "
gameforge.locale.questscroll5.mission_14_hunt = "A grande revolta dos Orcs 1 "
gameforge.locale.questscroll5.mission_14_mis = "Mata 30 Orcs Elite e 30 Orcs Explorador Elite. "
gameforge.locale.questscroll5.mission_14_text = "Algumas informa\231\245es secretas parecem indicar que[ENTER]os l\237deres dos Orcs do Vale Seungryong est\227o a[ENTER]planear governar o mundo. Gostava que fosses at\233[ENTER]l\225 dar uma vista de olhos e descobrir a verdade[ENTER]acerca disto. Para que a viagem seja produtiva[ENTER]podes tamb\233m matar alguns Orcs. "
gameforge.locale.questscroll5.mission_15_hunt = "O Ataque dos Selvagens "
gameforge.locale.questscroll5.mission_15_mis = "Mata 30 Infantarias Selvagem e 30 Sarrafeiros[ENTER]Selvagem. "
gameforge.locale.questscroll5.mission_15_text = "Obtivemos informa\231\245es importantes de um espi\227o[ENTER]selvagem que captur\225mos. Os selvagens est\227o a[ENTER]preparar uma invas\227o ao reino. Temos de impedir[ENTER]isto. Mostra a tua lealdade para com o teu reino. "
gameforge.locale.questscroll5.mission_16_hunt = "Destruir Metins da Escurid\227o "
gameforge.locale.questscroll5.mission_16_mis = "Destr\243i 3 Metins da Escurid\227o. "
gameforge.locale.questscroll5.mission_16_text = "Recentemente come\231aram a cair algumas pedras[ENTER]perto da cidade. Elas parecem conter uma m\225[ENTER]energia, porque desde ent\227o os animais da \225rea[ENTER]ficaram loucos. Por favor trata desta problema e[ENTER]destr\243i estas pedras. E \233 claro que ser\225s[ENTER]recompensado pelos teus esfor\231os. "
gameforge.locale.questscroll5.mission_17_hunt = "Destruir Metins Negras "
gameforge.locale.questscroll5.mission_17_mis = "Destr\243i 2 Metins Negras. "
