gameforge.locale.questscroll5.mission_18_hunt = "O Ataque das Se-Rang "
gameforge.locale.questscroll5.mission_18_mis = "Mata 10 Se-Rang do cl\227 Jura de Cristal. "
gameforge.locale.questscroll5.mission_18_text = "Existem novas informa\231\245es sobre o Cl\227 Jura de[ENTER]Cristal. Como reac\231\227o \224 press\227o que andamos a[ENTER]fazer, as Se-Rangs, l\237deres do Cl\227 Jura de[ENTER]Cristal, come\231aram um contra-ataque. Tens de[ENTER]fazer algo imediatamente em rela\231\227o \224s Se-Rangs e[ENTER]tentar frustrar os seus planos. "
gameforge.locale.questscroll5.mission_19_hunt = "A grande revolta dos Orcs 2 "
gameforge.locale.questscroll5.mission_19_mis = "Mata 20 Orcs Lutador Elite e 15 Orcs Mago Elite. "
gameforge.locale.questscroll5.mission_19_text = "Algumas informa\231\245es secretas parecem indicar que[ENTER]os l\237deres dos Orcs do Vale Seungryong est\227o a[ENTER]planear governar o mundo. Por muito estranho que[ENTER]isto pare\231a, dever\225s verificar este rumor. E j\225[ENTER]que l\225 vais, aproveita para tentares reduzir o[ENTER]seu n\250mero. "
