gameforge.locale.questscroll5.mission_20_mis = "Mata 30 Soldados Macaco e 30 Lan\231adores Macaco. "
gameforge.locale.questscroll5.mission_20_text = "Finalmente descobrimos a localiza\231\227o da Caverna[ENTER]dos Macacos Normais no Deserto. Normalmente os[ENTER]macacos que a\237 vivem s\227o inofensivos, mas quando[ENTER]eles se juntam tornam-se uma grande amea\231a para o[ENTER]Reino. Vai \224 Caverna dos Macacos Normais e[ENTER]verifica o que se passa com os macacos. "
