gameforge.locale.questscroll5.mission_21_text = "Finalmente descobrimos a localiza\231\227o da Caverna[ENTER]dos Macacos F\225ceis. Normalmente os macacos que a\237[ENTER]vivem s\227o inofensivos, mas quando eles se juntam[ENTER]tornam-se uma grande amea\231a para o Reino. Vai \224[ENTER]Caverna dos Macacos F\225ceis e verifica o que se[ENTER]passa com os macacos. "
gameforge.locale.questscroll5.mission_22_hunt = "Semear ventos e colher tempestades "
gameforge.locale.questscroll5.mission_22_mis = "Mata 4 Chuong do cl\227 Vento Negro. "
gameforge.locale.questscroll5.mission_22_text = "Os Chuong, l\237deres do cl\227 Vento Negro, come\231aram[ENTER]a causar problemas. Uma vez que s\227o mestres da[ENTER]luta com espadas andam a desafiar aventureiros[ENTER]apenas por divers\227o. P\225ra-os antes que todo o cl\227[ENTER]Vento Negro se junte a eles. "
