gameforge.locale.questscroll5.mission_27_mis = "Mata 40 Beb\233s Aranha. "
gameforge.locale.questscroll5.mission_27_text = "As aranhas, que normalmente vivem pacificamente[ENTER]no Deserto Yongbi, come\231aram subitamente a atacar[ENTER]e matar viajantes. Al\233m do facto de as v\237timas[ENTER]n\227o gostarem muito disso, esses ataques s\227o[ENTER]prejudiciais para o nosso Reino. Por favor coloca[ENTER]um ponto final nisto. "
