gameforge.locale.questscroll5.mission_33_text = "Foi descoberto um sistema de cavernas no Deserto[ENTER]Yongbi que as aranhas usam como esconderijo- N\227o[ENTER]temos mais detalhes sobre as cavernas, mas a \225rea[ENTER]\233 conhecida por ser perigosa. Por outro lado,[ENTER]teres muitas aranhas juntas num espa\231o confinado[ENTER]d\225-te a oportunidade de reduzires os seus[ENTER]n\250meros. Vai j\225 para l\225! E tem cuidado! "
