gameforge.locale.questscroll5.mission_35_hunt = "Ela t\234m 8 pernas 3 "
gameforge.locale.questscroll5.mission_35_mis = "Mata 35 Aranhas Vermelhas Mortais e 35 Aranhas[ENTER]Rubi Venenosas. "
gameforge.locale.questscroll5.mission_35_text = "Foi descoberto um sistema de cavernas no Deserto[ENTER]Yongbi que as aranhas usam como esconderijo- N\227o[ENTER]temos mais detalhes sobre as cavernas, mas a \225rea[ENTER]\233 conhecida por ser perigosa. Por outro lado,[ENTER]teres muitas aranhas juntas num espa\231o confinado[ENTER]d\225-te a oportunidade de reduzires os seus[ENTER]n\250meros. Vai j\225 para l\225! E tem cuidado! "
gameforge.locale.questscroll5.mission_36_hunt = "Elas t\234m 8 pernas 4 "
gameforge.locale.questscroll5.mission_36_mis = "Mata 40 Aranhas Coronel. "
gameforge.locale.questscroll5.mission_36_text = "Foi descoberto um sistema de cavernas no Deserto[ENTER]Yongbi que as aranhas usam como esconderijo- N\227o[ENTER]temos mais detalhes sobre as cavernas, mas a \225rea[ENTER]\233 conhecida por ser perigosa. Por outro lado,[ENTER]teres muitas aranhas juntas num espa\231o confinado[ENTER]d\225-te a oportunidade de reduzires os seus[ENTER]n\250meros. Vai j\225 para l\225! E tem cuidado! "
gameforge.locale.questscroll5.mission_37_hunt = "Destr\243i Metins da Dureza "
gameforge.locale.questscroll5.mission_37_mis = "Destr\243i 2 Metins da Dureza. "
gameforge.locale.questscroll5.mission_37_text = "Recentemente come\231aram a cair algumas pedras[ENTER]perto da cidade. Elas parecem conter uma m\225[ENTER]energia, porque desde ent\227o os animais da \225rea[ENTER]ficaram loucos. Por favor trata desta problema e[ENTER]destr\243i estas pedras. E \233 claro que ser\225s[ENTER]recompensado pelos teus esfor\231os. "
gameforge.locale.questscroll5.mission_38_hunt = "Praga de Escorpi\245es "
gameforge.locale.questscroll5.mission_38_mis = "Mata 30 Reis Escorpi\227o e 20 Homens Escorpi\227o[ENTER]Jovem. "
gameforge.locale.questscroll5.mission_38_text = "Estes Escorpi\245es andam a atormentar viajantes e[ENTER]vendedores ambulantes, o que \233 prejudicial para a[ENTER]economia do Reino. Por favor ajuda-nos a[ENTER]erradicar esta praga. "
gameforge.locale.questscroll5.mission_39_hunt = "A Companhia da Morte 1 "
gameforge.locale.questscroll5.mission_39_mis = "Mata 30 Soldados Dem\243nio e 20 Arqueiros Dem\243nio. "
gameforge.locale.questscroll5.mission_39_text = "J\225 ouviste falar na Torre Gumsan? As seitas[ENTER]esot\233ricas conjuraram, atrav\233s de poderosos[ENTER]feiti\231os, Soldados Dem\243nio. Combate contra eles e[ENTER]descobre o seu poder. "
gameforge.locale.questscroll5.mission_3_hunt = "A revela\231\227o dos Lobos Cinza 2 "
gameforge.locale.questscroll5.mission_3_mis = "Mata 30 Lobos Alfa Cinza. "
gameforge.locale.questscroll5.mission_3_text = "J\225 ouviste falar dos Lobos Alfa Cinza? Eles[ENTER]antigamente vagueavam apenas por a\237 mas, devido \224[ENTER]energia negra das Pedras Metin, nas \250ltimas[ENTER]semanas eles come\231aram a ca\231ar os viajantes em[ENTER]matilhas. Poder\225s eliminar estes Lobos Alfa[ENTER]Cinza? Ser\225s recompensado. "
gameforge.locale.questscroll5.mission_40_hunt = "A Companhia da Morte 2 "
gameforge.locale.questscroll5.mission_40_mis = "Mata 30 Dem\243nios Lanceiros e 25 Dem\243nios Xam\227. "
gameforge.locale.questscroll5.mission_40_text = "J\225 ouviste falar na Torre Gumsan? As seitas[ENTER]esot\233ricas conjuraram, atrav\233s de poderosos[ENTER]feiti\231os, Soldados Dem\243nio. Combate contra eles e[ENTER]descobre o seu poder. "
gameforge.locale.questscroll5.mission_41_hunt = "Segredo da Caverna dos Macacos Dif\237ceis 2 "
gameforge.locale.questscroll5.mission_41_mis = "Mata 15 Lutadores Macaco Fortes e 15 Generais[ENTER]Macaco Fortes. "
gameforge.locale.questscroll5.mission_41_text = "Finalmente descobrimos a localiza\231\227o da Caverna[ENTER]dos Macacos Dif\237ceis no Deserto. Normalmente os[ENTER]macacos que a\237 vivem s\227o inofensivos, mas quando[ENTER]eles se juntam tornam-se uma grande amea\231a para o[ENTER]Reino. Vai \224 Caverna dos Macacos Dif\237ceis e[ENTER]verifica o que se passa com os macacos. "
gameforge.locale.questscroll5.mission_42_hunt = "O gelo ir\225 derreter "
gameforge.locale.questscroll5.mission_42_mis = "Mata 25 Golems do Gelo. "
gameforge.locale.questscroll5.mission_42_text = "Conheces a Montanha Sohan que est\225 coberta de[ENTER]gelo perp\233tuo? Muitos exploradores e guerreiros[ENTER]j\225 l\225 foram sem nunca regressarem. Descobre a[ENTER]raz\227o disso e descobre se foram atacados. Talvez[ENTER]possas encontrar algo enquanto ca\231as monstros[ENTER]nessa \225rea. "
gameforge.locale.questscroll5.mission_43_hunt = "Segredo da Caverna dos Macacos Dif\237ceis 1 "
gameforge.locale.questscroll5.mission_43_mis = "Mata 30 Soldados Macaco Fortes e 30 Lan\231adores[ENTER]Macaco Fortes. "
gameforge.locale.questscroll5.mission_43_text = "Finalmente descobrimos a localiza\231\227o da Caverna[ENTER]dos Macacos Dif\237ceis no Deserto. Normalmente os[ENTER]macacos que a\237 vivem s\227o inofensivos, mas quando[ENTER]eles se juntam tornam-se uma grande amea\231a para o[ENTER]Reino. Vai \224 Caverna dos Macacos Dif\237ceis e[ENTER]verifica o que se passa com os macacos. "
gameforge.locale.questscroll5.mission_44_hunt = "O bra\231o direito do Tigre Fantasma "
gameforge.locale.questscroll5.mission_44_mis = "Mata 30 Generais R\227-Touro. "
gameforge.locale.questscroll5.mission_44_text = "De certeza que j\225 reparaste que os animais[ENTER]ultimamente t\234m andado mais violentos. Os[ENTER]servi\231os secretos do Reino pensam que isto se[ENTER]deve ao facto de o Tigre Fantasma, rei de todos[ENTER]os animais do continente, andar a mobilizar os[ENTER]seus s\250bditos. Como contra-medida dev\237amos[ENTER]eliminar os l\237deres, que s\227o o seu bra\231o direito. "
gameforge.locale.questscroll5.mission_45_hunt = "O dono da Montanha Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "Mata 35 Homens do Gelo e 30 Yetis. "
gameforge.locale.questscroll5.mission_45_text = "Diz-se que o Nove Caudas, mestre da Montanha[ENTER]Sohan, re\250ne dem\243nios \224 sua volta. Antes que ele[ENTER]tenha o seu ex\233rcito temos de matar Homens de[ENTER]Gelo e Yetis, pois eles s\227o a espinha dorsal das[ENTER]tropas. Por favor ajuda-nos. Ser\225s recompensado. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Mata 45 Soldados R\227 de \193rvore e 35 L\237deres R\227 de[ENTER]\193rvore. "
gameforge.locale.questscroll5.mission_46_text = "O Tigre Fantasma parece andar a conspirar com as[ENTER]R\227s de \193rvore. Quebra j\225 a sua uni\227o. Se os[ENTER]ignorares, tudo ir\225 acabar mal para o Reino! "
gameforge.locale.questscroll5.mission_47_hunt = "Monstros do gelo! O seu verdadeiro car\225cter "
gameforge.locale.questscroll5.mission_47_mis = "Mata 45 Gelos Encantados. "
gameforge.locale.questscroll5.mission_47_text = "Sabemos agora como os monstros da Montanha Sohan[ENTER]comunicam entre si: Eles espalham as informa\231\245es[ENTER]que precisam atrav\233s dos Gelos Encantados. Para[ENTER]enfraquecer as tropas da Terra do Gelo temos de[ENTER]interromper esta transmiss\227o de informa\231\227o. Por[ENTER]favor elimina os Gelos Encantados! "
gameforge.locale.questscroll5.mission_48_hunt = "O segredo da Torre Gumsan "
gameforge.locale.questscroll5.mission_48_mis = "Mata 45 Lanceiros Dem\243nio Brutos. "
gameforge.locale.questscroll5.mission_48_text = "H\225 rumores de que os Dem\243nios Lanceiros Vil na[ENTER]Torre Demon\237aca s\227o invenc\237veis. Aparentemente[ENTER]eles levantam-se sempre que s\227o mortos. Se for[ENTER]verdade, ent\227o tempos negros avizinham-se. Por[ENTER]favor descobre mais sobre isto! "
gameforge.locale.questscroll5.mission_49_hunt = "O mestre da Torre Gumsan "
gameforge.locale.questscroll5.mission_49_mis = "Mata 60 Dem\243nios Xam\227 Brutos. "
gameforge.locale.questscroll5.mission_49_text = "Ap\243s uma pesquisa extensiva descobrimos que os[ENTER]Dem\243nios Vil ressuscitam sempre. Temos de[ENTER]eliminar Dem\243nios Xam\227 Brutos para acabar com[ENTER]isto. "
gameforge.locale.questscroll5.mission_4_hunt = "A revela\231\227o dos Lobos Cinza 1 "
gameforge.locale.questscroll5.mission_4_mis = "Mata 35 Lobos Cinza. "
gameforge.locale.questscroll5.mission_4_text = "J\225 ouviste falar dos Lobos Cinza? Eles[ENTER]antigamente vagueavam apenas por a\237 mas, devido \224[ENTER]energia negra das Pedras Metin, nas \250ltimas[ENTER]semanas eles come\231aram a ca\231ar os viajantes em[ENTER]matilhas.[ENTER]Poder\225s eliminar estes Lobos Cinza? Ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_50_hunt = "Explora Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Mata 45 Tigres de Fogo Maus. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan \233 uma \225rea repleta de lava habitada[ENTER]por criaturas desconhecidas. Temos de explorar[ENTER]esta \225rea. Podes ajudar-nos? "
gameforge.locale.questscroll5.mission_51_hunt = "Fantasma de Chamas! A sua identidade "
gameforge.locale.questscroll5.mission_51_mis = "Mata 45 Fantasmas de Chamas. "
gameforge.locale.questscroll5.mission_51_text = "O grupo que tinha como miss\227o derrotar os Tigres[ENTER]de Fogo foi morto por uns inimigos desconhecidos.[ENTER]Correm rumores de que estes inimigos parecem[ENTER]\"raparigas em chamas\". Descobre a verdade. "
gameforge.locale.questscroll5.mission_52_hunt = "Reduzindo o n\250mero de Tigres do Fogo "
gameforge.locale.questscroll5.mission_52_mis = "Mata 60 Tigres de Fogo Maus e 40 Tigres de Fogo. "
gameforge.locale.questscroll5.mission_52_text = "Agora que conseguimos enfrentar os Fantasmas de[ENTER]Chamas temos de elimin\225-los completamente no[ENTER]campo de batalha. Miss\245es deste tipo s\227o[ENTER]normalmente levadas a cabo pelo Ex\233rcito, mas[ENTER]para fortalecermos a nossa frente de combate[ENTER]contra os Fantasmas de Chamas precisamos de[ENTER]alterar a nossa t\225ctica. Por favor certifica-te[ENTER]que os Tigres de Fogo n\227o interferem nos nossos[ENTER]afazeres. "
gameforge.locale.questscroll5.mission_53_hunt = "Examina os Chama "
gameforge.locale.questscroll5.mission_53_mis = "Mata 40 Chama. "
gameforge.locale.questscroll5.mission_53_text = "Os Chama s\227o inacreditavelmente brutais. Eles[ENTER]gostam de assistir ao sofrimento das pessoas cuja[ENTER]pele eles devoram. Ainda n\227o sabemos como fazer[ENTER]para os eliminar. Podes ajudar-nos a descobrir? "
gameforge.locale.questscroll5.mission_54_hunt = "Os Guerreiros Chama "
gameforge.locale.questscroll5.mission_54_mis = "Mata 60 Guerreiros Chama. "
gameforge.locale.questscroll5.mission_54_text = "H\225 pouco tempo o filho de um nobre, que se[ENTER]aventurou em Doyyumhwan, foi morto por um[ENTER]Guerreiro Chama. Se matares alguns Guerreiros[ENTER]Chama ser\225s recompensado. Porque n\227o o tentas? "
gameforge.locale.questscroll5.mission_55_hunt = "Examina as \193rvores Fantasma "
gameforge.locale.questscroll5.mission_55_mis = "Mata 30 \193rvores Fantasma. "
gameforge.locale.questscroll5.mission_55_text = "Normalmente parecem \225rvores como quaisquer outras[ENTER]- mas ent\227o, subitamente, ganham vida e atacam[ENTER]animais e humanos. Descobre como podemos destruir[ENTER]as \193rvores Fantasma. "
gameforge.locale.questscroll5.mission_56_hunt = "O segredo da Floresta Fantasma "
gameforge.locale.questscroll5.mission_56_mis = "Mata 40 Troncos Fantasma e 30 Dr\237ades. "
gameforge.locale.questscroll5.mission_56_text = "Pesquisas t\234m mostrado que a Floresta Fantasma \233[ENTER]uma \225rea habitada por Troncos Fantasma e Dr\237ades.[ENTER]Se eliminares estas criaturas pode ser que ponhas[ENTER]um ponto final na reprodu\231\227o das \193rvores[ENTER]Fantasma. "
gameforge.locale.questscroll5.mission_5_hunt = "Preocupa\231\227o com as Vilas "
gameforge.locale.questscroll5.mission_5_mis = "Mata 40 Javalis Selvagens. "
gameforge.locale.questscroll5.mission_5_text = "Nas \250ltimas semanas o sofrimento dos habitantes[ENTER]das vilas pr\243ximas tem aumentado. Os Javalis[ENTER]Selvagens, que outrora apenas atacavam animais[ENTER]nos montes, tornaram-se agressivos. Eles[ENTER]dirigem-se aos campos e atacam os agricultores.[ENTER]Poderias afugentar os Javalis Selvagens? "
gameforge.locale.questscroll5.mission_6_hunt = "Tigres e Ursos "
gameforge.locale.questscroll5.mission_6_mis = "Mata 25 Tigres e 30 Ursos. "
gameforge.locale.questscroll5.mission_6_text = "J\225 ouviste isto? Dizem que se os Tigres e os[ENTER]Ursos comerem apenas cebolas e alhos durante 100[ENTER]dias, eles ser\227o capazes de se transformar em[ENTER]Tigres gigantes e Ursos de fogo. Tenho a certeza[ENTER]que isto nunca aconteceu, mas n\227o far\225 mal[ENTER]verific\225-lo.[ENTER]Mata alguns Tigres e Ursos e descobre o que eles[ENTER]t\234m no est\244mago. "
gameforge.locale.questscroll5.mission_7_hunt = "Destr\243i Metins da Gan\226ncia "
gameforge.locale.questscroll5.mission_7_mis = "Destr\243i 2 Metins da Gan\226ncia. "
gameforge.locale.questscroll5.mission_7_text = "Recentemente come\231aram a cair algumas pedras[ENTER]perto da cidade. Elas parecem conter uma m\225[ENTER]energia, porque desde ent\227o os animais da \225rea[ENTER]ficaram loucos. Por favor trata desta problema e[ENTER]destr\243i estas pedras. E \233 claro que ser\225s[ENTER]recompensado pelos teus esfor\231os. "
gameforge.locale.questscroll5.mission_8_hunt = "Destr\243i Metins da Batalha "
gameforge.locale.questscroll5.mission_8_mis = "Destr\243i 2 Metins da Batalha. "
gameforge.locale.questscroll5.mission_8_text = "Recentemente come\231aram a cair algumas pedras[ENTER]perto da cidade. Elas parecem conter uma m\225[ENTER]energia, porque desde ent\227o os animais da \225rea[ENTER]ficaram loucos. Por favor trata desta problema e[ENTER]destr\243i estas pedras. E \233 claro que ser\225s[ENTER]recompensado pelos teus esfor\231os. "
gameforge.locale.questscroll5.mission_9_hunt = "Preocupa\231\227o pelas Vilas 2 "
gameforge.locale.questscroll5.mission_9_mis = "Mata 30 Javalis Selvagens Rubros. "
gameforge.locale.questscroll5.mission_9_text = "Desde algum tempo para c\225 os Javalis Selvagens e[ENTER]os seus l\237deres, os Javalis Selvagens Rubros, t\234m[ENTER]andado a atacar as vilas pr\243ximas. O governo[ENTER]ordenou que os Javalis Selvagens Rubros fossem[ENTER]mortos. \201 pedido aos guerreiros que cada um mate[ENTER]pelo menos 30 Javalis Selvagens Rubros. Por favor[ENTER]ajuda-nos tamb\233m. "
gameforge.locale.questscroll_10_hunt = "Serpentes Guerreiro "
gameforge.locale.questscroll_10_mis = "Mata os guerreiros que s\227o meio Humanos, meio[ENTER]Serpentes. "
gameforge.locale.questscroll_10_text = "N\227o os podemos considerar humanos. Mas tamb\233m n\227o[ENTER]os podemos considerar n\227o-humanos. S\227o de[ENTER]apar\234ncia humana, mas cabe\231a, pele e[ENTER]comportamento s\227o os mesmos das Serpentes. Vivem[ENTER]no deserto e atacam Vendedores Ambulantes.[ENTER]Mata 20 destes guerreiros meio Humanos, meio[ENTER]Serpentes. Se o fizeres receber\225s: "
gameforge.locale.questscroll_11_hunt = "Serpentes Arqueiro "
gameforge.locale.questscroll_11_mis = "Mata os arqueiros que s\227o meio Humanos, meio[ENTER]Serpentes. "
gameforge.locale.questscroll_11_text = "S\227o t\227o inteligentes como os humanos. S\227o[ENTER]desonestos e sabem utilizar as suas armas. Estes[ENTER]arqueiros, meio Humanos, meio Serpentes, atacam[ENTER]os Vendedores Ambulantes \224 dist\226ncia. J\225 v\225rios[ENTER]morreram gra\231as a estas criaturas.[ENTER]Mata 20 destes arqueiros meio Humanos, meio[ENTER]Serpentes. Se o fizeres receber\225s: "
gameforge.locale.questscroll_12_hunt = "Bandidos do Deserto "
gameforge.locale.questscroll_12_mis = "Mata Bandidos do Deserto "
gameforge.locale.questscroll_12_text = "H\225 seres malvados a viver no Deserto Yongbi. S\227o[ENTER]conhecidos por Bandidos do Deserto e at\233 o C\233u[ENTER]chora pelos seus crimes. Eles roubam e matam[ENTER]vendedores ambulantes apenas por divers\227o. S\227o[ENTER]tamb\233m os respons\225veis pela destrui\231\227o das vilas[ENTER]que existiam no deserto.[ENTER]Mata 12 Bandidos do Deserto. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_13_hunt = "Tigres de Fogo "
gameforge.locale.questscroll_13_mis = "Mata Tigres de Fogo. "
gameforge.locale.questscroll_13_text = "H\225 umas criaturas chamadas Tigres de Fogo. O seu[ENTER]sangue \233 feito de fogo e os seus corpos foram[ENTER]formados a partir de granito vulc\226nico. S\227o[ENTER]criaturas incrivelmente poderosas! Alimentam-se[ENTER]de lava e do fogo do vulc\227o. Por vezes afastam-se[ENTER]do vulc\227o e atacam as pessoas, para depois as[ENTER]comer...[ENTER]Mata 20 Tigres de Fogo. Se o fizeres receber\225s: "
gameforge.locale.questscroll_14_hunt = "Guerreiros Chama "
gameforge.locale.questscroll_14_mis = "Mata Guerreiros Chama. "
gameforge.locale.questscroll_14_text = "A \225rea de Doyyumhwan \233 grande, escaldante e est\225[ENTER]repleta de criaturas selvagens. \201 um local onde[ENTER]os guerreiros de Chunjo, Jinno e Shinsoo se[ENTER]encontram. Monstros poderosos e destemidos[ENTER]aguardam esses guerreiros. Os Guerreiros Chama[ENTER]s\227o os seres que controlam esta \225rea.[ENTER]Queres desafi\225-los? Se matares 20 Guerreiros[ENTER]Chama receber\225s: "
gameforge.locale.questscroll_15_hunt = "Guerreiros Taehwa "
gameforge.locale.questscroll_15_mis = "Derrota os Guerreiros Taehwa. "
gameforge.locale.questscroll_15_text = "Todos os guerreiros que se acham fortes e[ENTER]destemidos, ou\231am! Este \233 o campo de batalha[ENTER]flamejante onde se podem ver l\225grimas, dor,[ENTER]combates e morte! Eu vivo aqui, no meio de muitos[ENTER]monstros e vil\245es! Quem \233 suficientemente[ENTER]corajoso para me desafiar? Ser\225 poss\237vel[ENTER]encontrar algu\233m que queira enfrentar-me de[ENTER]espada na m\227o?[ENTER]Se tiveres f\233 nas tuas habilidades vem[ENTER]desafiar-me! Se me derrotares a mim e a 12 dos[ENTER]meus camaradas ir\225s receber: "
gameforge.locale.questscroll_16_hunt = "Ursos Negros "
gameforge.locale.questscroll_16_mis = "Mata Ursos Negros "
gameforge.locale.questscroll_16_text = "Receio que este seja o fim. Mas deixa-me[ENTER]contar-te sobre um incidente importante... Quando[ENTER]leres esta carta, eu j\225 estarei morto ou andarei[ENTER]desaparecido. Eu vivia no Vale Seungryong, onde[ENTER]colhia ervas medicinais. Mas uns monstros[ENTER]chamados Ursos Negros enlouqueceram. E mataram a[ENTER]minha fam\237lia.[ENTER]Por favor vinga a nossa morte. Se matares 25[ENTER]Ursos Negros receber\225s: "
gameforge.locale.questscroll_17_hunt = "Ursos Negros gigantes "
gameforge.locale.questscroll_17_mis = "Mata Ursos Negros gigantes. "
gameforge.locale.questscroll_17_text = "Os Ursos criaram um novo monstro ao acasalarem[ENTER]com monstros ainda mais perversos. Estes novos[ENTER]monstros s\227o os Ursos Negros Gigantes. S\227o[ENTER]maiores e mais fortes que os Ursos Negros, al\233m[ENTER]de serem incrivelmente mal\233ficos. As pessoas v\227o[ENTER]sofrer enquanto eles andarem \224 solta pelo Vale[ENTER]Seungryong.[ENTER]Mata 20 Ursos Negros Gigantes. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_18_hunt = "Os Espadachins Infestados "
gameforge.locale.questscroll_18_mis = "Mata os Espadachins Infestados "
gameforge.locale.questscroll_18_text = "A vila parece ter sido erradicada. Os seus[ENTER]habitantes, que sofrem de uma misteriosa doen\231a,[ENTER]atacam todos os infelizes que por ali passam.[ENTER]Atacam e comem viajantes e vendedores ambulantes.[ENTER]S\227o extremamente perigosos.[ENTER]Mata 35 Espadachins Infestados. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_19_hunt = "Os Arqueiros Infestados "
gameforge.locale.questscroll_19_mis = "Mata os Arqueiros Infestados. "
gameforge.locale.questscroll_19_text = "A doen\231a misteriosa \233 a causa dos danos causados[ENTER]por quem dela sofre. Mas os mais perigosos s\227o os[ENTER]Arqueiros que foram infectados por esta doen\231a.[ENTER]Estes Arqueiros disparam flechas t\243xicas para[ENTER]atordoarem viajantes que s\227o capturados e[ENTER]raptados.[ENTER]Mata 25 Arqueiros Infestados. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_1_hunt = "Os Ursos de Fogo "
gameforge.locale.questscroll_1_mis = "Mata 25 Ursos de Fogo "
gameforge.locale.questscroll_1_text = "Os Ursos de Fogo podem ser encontrados perto da[ENTER]vila. Eles vagueiam pelas pradarias e grandes[ENTER]caminhos dos humanos. Muitas pessoas est\227o a[ENTER]tornar-se v\237timas destas criaturas. Muitas j\225[ENTER]foram encontradas mortas.[ENTER]Ca\231a estes Ursos de Fogo. Se matares 25 Ursos de[ENTER]Fogo receber\225s: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Mata 4 inimigos "
gameforge.locale.questscroll_20_text = "Receio estar acabado! A minha vis\227o est\225 cada vez[ENTER]mais distorcida... Ao leres esta carta de certeza[ENTER]que o meu corpo j\225 ter\225 apodrecido. Estes[ENTER]malditos capturaram-me e raptaram-me. Consegui[ENTER]escapar, mas as minhas feridas s\227o demasiado[ENTER]profundas e j\225 n\227o resistirei muito mais. N\227o te[ENTER]conhe\231o, mas por favor vinga-me![ENTER]Mata 4 inimigos no local do combate. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_2_hunt = "Os Grandes Tigres "
gameforge.locale.questscroll_2_mis = "Mata 20 Grandes Tigres "
gameforge.locale.questscroll_2_text = "O nome desta criatura pode ser ouvido por toda a[ENTER]parte: Grande Tigre. Estes tigres costumam ser[ENTER]encontrados perto das vilas principais. Atacam[ENTER]pessoas e comem os vendedores ambulantes. J\225[ENTER]houve in\250meras v\237timas.[ENTER]Ca\231a os Grandes Tigres. Se matares 20 Grandes[ENTER]Tigres receber\225s: "
gameforge.locale.questscroll_3_hunt = "O Lykos "
gameforge.locale.questscroll_3_mis = "Mata o Lykos "
gameforge.locale.questscroll_3_text = "O Lykos \233 o l\237der de uma matilha de c\227es que[ENTER]podem ser encontrados pr\243ximos da vila. Ele \233[ENTER]forte e selvagem. Apareceram perto da vila[ENTER]recentemente e come\231aram a atacar os vendedores[ENTER]ambulantes. Este monstro j\225 causou muitas mortes.[ENTER]As suas ac\231\245es n\227o podem ser mais ignoradas.[ENTER]Mata o Lykos. Se o fizeres receber\225s: "
gameforge.locale.questscroll_4_hunt = "O Scrofa "
gameforge.locale.questscroll_4_mis = "Mata o Scrofa "
gameforge.locale.questscroll_4_text = "Nesta altura do ano os campos enchem-se de[ENTER]cereais. \201 a altura das colheitas; altura de os[ENTER]agricultores ganharem pelo seu trabalho \225rduo.[ENTER]Mas o Scrofa e os seus companheiros andam a comer[ENTER]todo o cereal. A sua gan\226ncia amea\231a os[ENTER]agricultores. Temos de os eliminar![ENTER]Mata o Scrofa. Ele costuma estar perto do Idoso.[ENTER]Se o fizeres receber\225s: "
gameforge.locale.questscroll_5_hunt = "O Bera "
gameforge.locale.questscroll_5_mis = "Mata o Bera "
gameforge.locale.questscroll_5_text = "No seu ambiente natural o Bera \233 uma criatura[ENTER]calma. Mas desde algum tempo para c\225 ele tem[ENTER]rondado a vila e tem atacado v\225rias pessoas. Ele[ENTER]\233 o respons\225vel pelo crescente n\250mero de v\237timas.[ENTER]\201 imposs\237vel saber ao certo quantos j\225 morreram.[ENTER]Ele tem de ser eliminado![ENTER]Mata o Bera. Se o fizeres receber\225s: "
gameforge.locale.questscroll_6_hunt = "O Tigris "
gameforge.locale.questscroll_6_mis = "Mata o Tigris "
gameforge.locale.questscroll_6_text = "N\227o acreditava que o Tigris alguma vez fosse[ENTER]capaz disto... Sou uma simples mulher que, sempre[ENTER]que o Tigris aparecia no caminho para a Montanha,[ENTER]gostava de o agradar. No entanto, um dia o Tigris[ENTER]e os seus companheiros atacaram a minha fam\237lia,[ENTER]matando-os a todos e fazendo-me perder um bra\231o![ENTER]Por favor vinga a minha fam\237lia matando o Tigris.[ENTER]Se o fizeres receber\225s: "
gameforge.locale.questscroll_7_hunt = "A l\237der do cl\227 Jura de Cristal "
gameforge.locale.questscroll_7_mis = "Mata a l\237der do cl\227 Jura de Cristal "
gameforge.locale.questscroll_7_text = "O Cl\227 Jura de Cristal \233 um grupo de mulheres que[ENTER]foram abandonadas pelos seus maridos e s\227o[ENTER]tratadas mal por todos. Elas podem ser pobres,[ENTER]mas a forma como tratam os alde\245es \233 cruel. Uma[ENTER]mulher foi apedrejada at\233 \224 morte quando[ENTER]regressava para a vila. N\227o podemos permitir que[ENTER]isto continue.[ENTER]Mata 20 l\237deres do Cl\227 Jura de Cristal. Se o[ENTER]fizeres receber\225s: "
gameforge.locale.questscroll_8_hunt = "O l\237der do cl\227 Vento Negro "
gameforge.locale.questscroll_8_mis = "Mata o l\237der do cl\227 Vento Negro "
gameforge.locale.questscroll_8_text = "Os ladr\245es do Cl\227 Vento Negro h\225 muito tempo que[ENTER]andam a atormentar os Vendedores Ambulantes. S\227o[ENTER]t\227o assustadores que ningu\233m tem coragem[ENTER]suficiente para retaliar. Mas isto n\227o pode[ENTER]continuar assim; eles est\227o a causar demasiados[ENTER]problemas.[ENTER]Mata 20 l\237deres do Cl\227 Vento Negro. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.questscroll_9_hunt = "Os chefes dos Selvagens "
gameforge.locale.questscroll_9_mis = "Mata os chefes dos Selvagens "
gameforge.locale.questscroll_9_text = "J\225 passou algum tempo desde que os Selvagens[ENTER]atravessaram a fronteira e atacaram a vila. O[ENTER]n\250mero de habitantes mortos atingiu a casa das[ENTER]centenas. O n\250mero total de habitantes afectados[ENTER]foi ainda maior. Os Selvagens s\227o t\227o brutais que[ENTER]nunca ningu\233m teve a coragem suficiente para os[ENTER]enfrentar. Mas este assunto n\227o pode continuar a[ENTER]ser ignorado.[ENTER]Mata 25 chefes dos Selvagens. Se o fizeres[ENTER]receber\225s: "
gameforge.locale.quest_temp_reward_1 = "Recompensa "
gameforge.locale.quest_temp_reward_2 = "Durante o per\237odo de testes das miss\245es n\227o podem[ENTER]ser obtidas recompensas. Assim que a recompensa[ENTER]tiver sido obtida, a miss\227o actual poder\225 ser[ENTER]completada de novo. "
