gameforge.locale.skeleton_gem.order_accept = "Irei encontr\225-lo para ti! "
gameforge.locale.skeleton_gem.order_accept_answer = "Vendedor Ambulante:[ENTER]Oh! Mil Obrigados! Nunca esquecerei o teu gesto! "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_ = "Procura o Diamante do Dem\243nio+. "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_text = "Encontra o Dem\243nio Xam\227 e arranja o Diamante do[ENTER]Dem\243nio+. "
gameforge.locale.skeleton_gem.order_refuse = "Acho que \233 demasiado perigoso para mim. "
gameforge.locale.skeleton_gem.order_refuse_answer = "Vendedor Ambulante:[ENTER]Compreendo a tua hesita\231\227o. \201 claro que \233 uma[ENTER]tarefa dif\237cil e perigosa! Mas se as coisas[ENTER]continuarem assim ser\225 o meu fim! "
gameforge.locale.skeleton_gem.order_say = "Vendedor Ambulante:[ENTER]Agora est\225 tudo acabado. N\227o h\225 mais nada a fazer[ENTER]sen\227o ficar \224 espera da morte. Se os ladr\245es n\227o[ENTER]me tivessem atacado eu n\227o teria perdido os meus[ENTER]pertences. Porque \233 que isto tinha de me[ENTER]acontecer? "
gameforge.locale.skeleton_gem.order_say2 = "Vendedor Ambulante:[ENTER]Por favor ajuda-me. Se conseguires obter o[ENTER]Diamante do Dem\243nio+ de um Dem\243nio Xam\227, irei[ENTER]dar-te uma recompensa generosa. "
gameforge.locale.skeleton_gem.order_too_late = "Vendedor Ambulante:[ENTER]Algu\233m j\225 me entregou um. N\227o precisas de tratar[ENTER]mais disto. "
gameforge.locale.skeleton_gem.start_find_peddler_label = "Dirige-te ao Vendedor Ambulante. "
gameforge.locale.skeleton_gem.start_find_peddler_text_1 = "Dirige-te ao Vendedor Ambulante "
gameforge.locale.skeleton_gem.start_find_peddler_text_2 = "Dirige-te ao Vendedor Ambulante e pergunta-lhe[ENTER]sobre o Diamante do Dem\243nio+. "
gameforge.locale.skeleton_gem.start_say = "Carta do Vendedor Ambulante:[ENTER]N\227o sei mais o que fazer. O Diamante do Dem\243nio+[ENTER]foi roubado. E agora estou na ru\237na porque gastei[ENTER]o meu dinheiro todo nele.[ENTER]Podes ajudar-me por favor? Estou desesperado! "
gameforge.locale.skeleton_gem.success_say = "Vendedor Ambulante:[ENTER]Conseguiste mesmo? Vem a mim minha pedra amada![ENTER]Obrigado. N\227o imaginas o qu\227o aliviado estou. "
