gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "O panfleto mostra:[ENTER]Recrutamos homens e mulheres corajosos que[ENTER]queiram combater pela paz no Reino![ENTER][ENTER]N\237vel m\237nimo de recrutamento: N\237vel 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Aqui treinamos Ninjas para que saibam como se[ENTER]esconder e preparar emboscadas aos seus inimigos.[ENTER]Eles focam-se no uso das Adagas e venenos.[ENTER]Apenas poder\227o participar Ninjas de n\237vel 5 ou[ENTER]superior. Quando tiveres chegado a este n\237vel[ENTER]receber\225s uma mensagem de recruta. Se estiveres[ENTER]preparado para te esgueirares pelos cantos[ENTER]obscuros do mundo como um Ninja vem ter comigo.[ENTER]Nessa altura falaremos melhor disto. "
gameforge.locale.skill_group.dialog_assassin_2 = "Aqui treinamos Ninjas para que saibam como se[ENTER]esconder e preparar emboscadas aos seus inimigos.[ENTER]Eles focam-se no uso das Adagas e venenos.[ENTER]Se estiveres preparado para te esgueirares pelos[ENTER]cantos obscuros do mundo como um Ninja vem ter[ENTER]comigo. Ent\227o falaremos melhor disto. "
gameforge.locale.skill_group.dialog_assassin_3 = "Aqui treinamos Ninjas para que se tornem mestres[ENTER]na Arte do Arco. Eles aprendem a atirar m\250ltiplas[ENTER]setas simultaneamente a inimigos que estejam[ENTER]longe.[ENTER]Apenas poder\227o participar Ninjas de n\237vel 5 ou[ENTER]superior. Quando tiveres atingido o n\237vel[ENTER]necess\225rio ir\225s receber uma carta de recruta. Se[ENTER]estiveres interessado vem ter comigo. "
gameforge.locale.skill_group.dialog_assassin_4 = "Aqui treinamos Ninjas para que se tornem mestres[ENTER]na Arte do Arco. Por exemplo, eles aprendem a[ENTER]atirar m\250ltiplas setas simultaneamente a inimigos[ENTER]que estejam longe.[ENTER]Segue-me. Irei fazer de ti o melhor Arqueiro[ENTER]deste continente. "
gameforge.locale.skill_group.dialog_assassin_5 = "Escolhe entre a Arte Furtiva e a Arte do Arco e[ENTER]receber\225s as Habilidades que pretendes. "
gameforge.locale.skill_group.dialog_shaman_1 = "\201 aqui que os Xam\227s que pretendem seguir o[ENTER]caminho do Deus Drag\227o se encontram. S\227o[ENTER]ensinados a usar amuletos e os seus poderes[ENTER]mentais, que por sua vez os ajudam a repelir as[ENTER]habilidades dos seus advers\225rios. Tamb\233m permitem[ENTER]que eles melhorem a sua defesa atrav\233s de uma[ENTER]protec\231\227o divina e possam ajudar outros her\243is.[ENTER]Apenas poder\227o participar Xam\227s de n\237vel 5 ou[ENTER]superior. Assim que tiveres atingido este n\237vel,[ENTER]ir\225s receber uma carta de recrutamento. Quanto[ENTER]estiveres pronto para os ensinamentos da For\231a[ENTER]Drag\227o vem ter comigo. "
gameforge.locale.skill_group.dialog_shaman_2 = "\201 aqui que os Xam\227s que pretendem seguir o[ENTER]caminho do Deus Drag\227o se encontram. S\227o[ENTER]ensinados a usar amuletos e os seus poderes[ENTER]mentais, que por sua vez os ajudam a repelir as[ENTER]habilidades dos seus advers\225rios. Tamb\233m permitem[ENTER]que eles melhorem a sua defesa atrav\233s de uma[ENTER]protec\231\227o divina e possam ajudar outros her\243is.[ENTER]Achas que est\225s pronto para espalhares os[ENTER]ensinamentos do Deus Drag\227o? Um humilde crente \233[ENTER]sempre bem-vindo. "
gameforge.locale.skill_group.dialog_shaman_3 = "Aqui os Xam\227s adoram as for\231as da Natureza e da[ENTER]Luz. Aqui eles aprendem as Habilidades ligadas[ENTER]aos rel\226mpagos e tempestades, mas tamb\233m aos[ENTER]m\233todos de cura. Xam\227s que seguem esta doutrina[ENTER]muitas vezes trabalham em grupo para se ajudaram[ENTER]mutuamente.[ENTER]Apenas poder\227o participar Xam\227s de n\237vel 5 ou[ENTER]superior. Quando tiveres atingido o n\237vel[ENTER]necess\225rio ir\225s receber uma carta de recruta. Se[ENTER]estiveres interessado vem ter comigo. "
gameforge.locale.skill_group.dialog_shaman_4 = "Aqui os Xam\227s adoram as for\231as da Natureza e da[ENTER]Luz. Aqui eles aprendem as Habilidades ligadas[ENTER]aos rel\226mpagos e tempestades, mas tamb\233m aos[ENTER]m\233todos de cura. Xam\227s que seguem esta doutrina[ENTER]muitas vezes trabalham em grupo para se ajudaram[ENTER]mutuamente.[ENTER]Queres trabalhar comigo para ajudar os outros? O[ENTER]teu apoio iria ajudar todos os que sofrem. Por[ENTER]favor ajuda-me. "
gameforge.locale.skill_group.dialog_shaman_5 = "Escolhe entre a For\231a Drag\227o e a Energia e[ENTER]receber\225s as Habilidades que pretendes. "
gameforge.locale.skill_group.dialog_sura_1 = "Eu ensino aqueles que foram aben\231oados com a[ENTER]Semente do Diabo a utilizarem as suas Habilidades[ENTER]m\225gicas. Aqui aprendem a encantar armas e[ENTER]armaduras, aumentando a sua for\231a de ataque e[ENTER]defesa. Eles tamb\233m aprendem a invocar os[ENTER]esp\237ritos do inferno e reduzir assim a moral do[ENTER]inimigo.[ENTER]Apenas poder\227o participar Suras de n\237vel 5 ou[ENTER]superior. Quando tiveres atingido o n\237vel[ENTER]necess\225rio ir\225s receber uma carta de recruta. Se[ENTER]estiveres interessado vem ter comigo. "
gameforge.locale.skill_group.dialog_sura_2 = "Eu ensino aqueles que foram aben\231oados com a[ENTER]Semente do Diabo a utilizarem as suas Habilidades[ENTER]m\225gicas. Aqui aprendem a encantar armas e[ENTER]armaduras, aumentando a sua for\231a de ataque e[ENTER]defesa. Eles tamb\233m aprendem a invocar os[ENTER]esp\237ritos do inferno e reduzir assim a moral do[ENTER]inimigo.[ENTER]Est\225s pronto a manejar espadas encantadas e a[ENTER]lan\231ar feiti\231os obscuros? Asseguro-te que o poder[ENTER]que aqui encontrar\225s est\225 certamente \224 procura de[ENTER]pessoas do seu tipo. "
gameforge.locale.skill_group.dialog_sura_3 = "Se est\225s interessado neste local: Aqui apenas[ENTER]encontrar\225s aqueles que se dedicam \224s trevas.[ENTER]Eles aprendem a lidar com esp\237ritos, dem\243nios e[ENTER]com as chamas do Inferno.[ENTER]Apenas poder\227o participar Suras de n\237vel 5 ou[ENTER]superior. Assim que tiveres atingido este n\237vel,[ENTER]ir\225s receber uma carta de recrutamento. Se achas[ENTER]que as trevas s\227o a tua casa, ir\225s certamente[ENTER]encontrar aqui v\225rios irm\227os e irm\227s. "
gameforge.locale.skill_group.dialog_sura_4 = "Se est\225s interessado neste local: Aqui apenas[ENTER]encontrar\225s aqueles que se dedicam \224s trevas.[ENTER]Eles aprendem a lidar com esp\237ritos, dem\243nios e[ENTER]com as chamas do Inferno.[ENTER]Se est\225s interessado em travar amizade com[ENTER]esp\237ritos mal\233ficos que consomem a tua alma[ENTER]lentamente e peda\231o a peda\231o, vem comigo![ENTER]Junta-te \224 nossa ordem e deixa para tr\225s tudo[ENTER]aquilo que tens de humano... "
gameforge.locale.skill_group.dialog_sura_5 = "Escolhe entre a Luta d'Armas e a Magia Negra e[ENTER]receber\225s as Habilidades que sempre desejaste. "
gameforge.locale.skill_group.dialog_warrior_1 = "Sabes onde est\225s? Aqui ensinamos os Guerreiros a[ENTER]serem os mais r\225pidos e corajosos. Ensinamos[ENTER]habilidades para golpes r\225pidos e repetitivos,[ENTER]sejam eles desferidos com uma Espada ou uma[ENTER]L\226mina.[ENTER]Apenas poder\227o participar Guerreiros de n\237vel 5[ENTER]ou superior. Assim que tiveres atingido este[ENTER]n\237vel, ir\225s receber uma carta de recrutamento. Se[ENTER]quiseres descobrir o verdadeiro potencial do teu[ENTER]corpo, vem comigo! "
gameforge.locale.skill_group.dialog_warrior_2 = "Sabes onde est\225s? Aqui os Guerreiros s\227o[ENTER]treinados para serem os mais r\225pidos e os mais[ENTER]corajosos. Ensinamos Habilidades que lhes[ENTER]permitem fazer ataques r\225pidos e repetidos, com[ENTER]uma Espada ou uma L\226mina.[ENTER]Como vai ser? Queres treinar? "
gameforge.locale.skill_group.dialog_warrior_3 = "Ensino os Guerreiros a focarem a sua energia[ENTER]correctamente. Isto requer um estilo de combate[ENTER]lento e mentalmente exaustivo. No entanto ser\225s[ENTER]capaz de atingir v\225rios inimigos ao mesmo tempo.[ENTER]E a defesa impenetr\225vel do grande Guerreiro de[ENTER]For\231a Mental \233 lend\225ria.[ENTER]Apenas Guerreiros aprendizes ou com no m\237nimo[ENTER]n\237vel 5 podem participar no treino. Assim que[ENTER]tiveres atingido o n\237vel necess\225rio ir\225s receber[ENTER]uma carta de recruta. Se estiveres interessado,[ENTER]vem ver-me. "
gameforge.locale.skill_group.dialog_warrior_4 = "Ensino os Guerreiros a focarem a sua energia[ENTER]correctamente. Isto requer um estilo de combate[ENTER]lento e mentalmente exaustivo. No entanto ser\225s[ENTER]capaz de atingir v\225rios inimigos ao mesmo tempo.[ENTER]E a defesa impenetr\225vel do grande Guerreiro de[ENTER]For\231a Mental \233 lend\225ria.[ENTER]Como vai ser? Sentes-te capaz de lidar com as[ENTER]exig\234ncias da Luta Mental? "
gameforge.locale.skill_group.dialog_warrior_5 = "Escolhe entre a Luta Corpo e a Luta Mental e[ENTER]receber\225s as Habilidades que desejas. "
gameforge.locale.skill_group.invite = "An\250ncio de recruta: "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]An\250ncio de Recruta de[ENTER]Guerreiros[/COLOR][ENTER]Se admiras os Guerreiros pela sua rapidez e poder[ENTER]de ataque, recomendo-te o treino de Luta Corpo.[ENTER]Se te quiseres tornar invulner\225vel e eliminar[ENTER]grupos inteiros de monstros com um \250nico ataque,[ENTER]ent\227o recomendo-te o treino de Luta Mental.[ENTER][ENTER]Estarei \224 tua espera perto do centro da Vila. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]An\250ncio de Recruta de[ENTER]Ninjas[/COLOR][ENTER]Se te quiseres tornar um Arqueiro incr\237vel, ent\227o[ENTER]dirige-te ao Professor de Arte do Arco. Mas se[ENTER]est\225s preparado para andar nas sombras em[ENTER]diversas miss\245es secretas, ent\227o o treino de Arte[ENTER]Furtiva \233 para ti.[ENTER][ENTER]Estarei \224 tua espera perto do centro da Vila. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]An\250ncio de Recruta de[ENTER]Suras[/COLOR][ENTER]Queres tornar-te um mestre da espada sobre-humano[ENTER]e fazer os teus advers\225rios sentir a ponta da tua[ENTER]L\226mina Encantada? Ent\227o recomendo-te o treino na[ENTER]Luta d'Armas. Se, no entanto, quiseres tornar-te[ENTER]um itimidante manipulador de chamas e maldi\231\245es,[ENTER]dever\225s enveredar pelo treino da Magia Negra.[ENTER][ENTER]Estarei \224 tua espera perto do centro da Vila. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]An\250ncio de Recruta de[ENTER]Xam\227s[/COLOR][ENTER]Se queres acordar os poderes do Deus Drag\227o e[ENTER]usar o seu sopro flamejante contra os teus[ENTER]inimigos, recomendo-te o treino da For\231a Drag\227o.[ENTER]No entanto, se quiseres aliviar e curar a dor[ENTER]daqueles que sofrem, dever\225s treinar com o[ENTER]Professor de Energia.[ENTER][ENTER]Ficarei \224 tua espera perto do centro da Vila. "
gameforge.locale.stamina_food = {}
