gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "Idoso no restaurante Suhpyung:[ENTER]O meu corpo j\225 n\227o tem a utilidade de outrora.[ENTER]Quando era mais jovem, podia trabalhar uma semana[ENTER]inteira de seguida, e ainda assim ter energia[ENTER]para passar as noites a beber! Agora, at\233 o[ENTER]simples acto de me manter em p\233 \233 dif\237cil. \201[ENTER]nestas alturas que uma ta\231a de sopa de r\227 verde[ENTER]se torna uma boa forma de recuperar energia. "
gameforge.locale.stamina_food.butcher.start_say2 = "Idoso no Restaurante Suhpyung:[ENTER]Queres saber o que \233 a sopa de r\227 verde? Se[ENTER]comeres uma ta\231a disto, nunca mais ficar\225s[ENTER]cansado! Mesmo que tenhas passado uma semana[ENTER]inteira a trabalhar nos campos, ainda ter\225s[ENTER]energia de sobra todas as noites! Um amigo meu,[ENTER]chamado Oakgu, cozinha a melhor sopa de r\227 verde[ENTER]que alguma vez comi. No entanto, por alguma[ENTER]raz\227o, ele deixou de a cozinhar. "
gameforge.locale.stamina_food.butcher.talk = "Falar. "
gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]Conseguiste? N\227o constes a ningu\233m sobre a sopa[ENTER]de r\227 verde. Especialmente \224quele idiota que est\225[ENTER]no restaurante Suhpyung! Se as pessoas come\231arem[ENTER]a ouvir falar na sopa de r\227 verde, ir\227o come\231ar a[ENTER]vir at\233 aqui para a comer! "
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Sopa de r\227 verde? Sim! Eu costumava cozinh\225-la.[ENTER]Mas isso era quando eu era mais novo. Na altura[ENTER]n\227o tinha medo dos monstros perigosos, por isso[ENTER]conseguia ca\231ar r\227s verdes. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]Mas agora? Agora estou velho, e n\227o tenho energia[ENTER]suficiente para isto. Eu tamb\233m gostaria de comer[ENTER]a sopa mas as r\227s n\227o s\227o f\225ceis de matar. Se me[ENTER]conseguires alguma carne de r\227 verde, eu poderei[ENTER]fazer a melhor sopa de r\227 verde que alguma vez[ENTER]experimentar\225s! "
gameforge.locale.stamina_food.food_manager.talk = "Falar. "
