gameforge.locale.stamina_food.order_get_greenfrog_general_meat_text = "Ca\231a r\227s verdes e encontra a carne de r\227 verde. "
gameforge.locale.stamina_food.order_refuse = "N\227o estou interessado. "
gameforge.locale.stamina_food.order_refuse_answer = "Oakgu:[ENTER]N\227o \233 todos os dias que tens a oportunidade de[ENTER]comer uma sopa de carne de r\227 verde! "
