gameforge.locale.stash.enlarge_2_again = "Tu de novo? N\227o, ainda n\227o sei. Devias ir[ENTER]procurar o conselho da Idosa. Agora vai! "
gameforge.locale.stash.enlarge_2_have_mark = "Eu tenho o s\237mbolo. "
gameforge.locale.stash.enlarge_2_have_mark2 = "Pensas que sou est\250pido? Esse n\227o \233 o s\237mbolo da[ENTER]Idosa! Perdeste-o? Detesto mentirosos! Vai[ENTER]procurar o s\237mbolo. "
gameforge.locale.stash.enlarge_2_have_mark3 = "Oh! A Idosa aben\231oou-te! Eu disse-te! Est\225s[ENTER]destinado a ser um her\243i! N\227o te esque\231as da[ENTER]minha promo\231\227o quando fores famoso![ENTER][ENTER]Irei expandir o teu Armaz\233m em mais 15 espa\231os. "
gameforge.locale.stash.enlarge_2_msg1 = "Queres que o expanda de novo? Pare\231o-te um[ENTER]filantropo? Por outro lado... Tens a cara de um[ENTER]her\243i. Hmm... "
gameforge.locale.stash.enlarge_2_msg2 = "Ouve: Vou dar-te uma carta de recomenda\231\227o,[ENTER]leva-a \224 Idosa. Ela ir\225 avaliar-te e dizer-te se[ENTER]realmente tens a energia e vontade de um her\243i a[ENTER]correr nas tuas veias. "
gameforge.locale.stash.enlarge_2_no_mark = "A Idosa n\227o quis avaliar-me. "
gameforge.locale.stash.enlarge_2_no_mark2 = "Cara de beb\233? Foi isso que ela te disse? Ha ha[ENTER]ha! Sim, isso \233 mesmo dela! Mas n\227o te preocupes,[ENTER]volta a tentar de novo quando tiveres atingido um[ENTER]n\237vel mais alto. "
gameforge.locale.stash.enlarge_2_oldwoman_accept = "Hum, sim... Ser\225s bem sucedido no futuro. D\225 o[ENTER]teu melhor pelo nosso Reino e ver\225s que no fim[ENTER]valer\225 a pena. Aqui est\225 um sinal do meu apre\231o.[ENTER]Entrega-o ao Guarda do Armaz\233m. "
