gameforge.locale.stash.enlarge_3_counter = "Membros da seita Esot\233rica em falta "
gameforge.locale.stash.enlarge_3_msg1 = "\201s um chato![ENTER][ENTER]E que tal servires o Reino mais uma vez? Existe[ENTER]algures uma seita Esot\233rica que segue uma[ENTER]qualquer F\233 Negra.[ENTER]Elimina 100 membros desta seita e tr\225-los aqui.[ENTER]Tens 30 minutos. "
