gameforge.locale.years_greetings.bless_msg = "Devias ter mais respeito pelos mais velhos.[ENTER]Ainda assim, desejo-te o melhor para este novo[ENTER]ano. "
gameforge.locale.years_greetings.chat_greet = "Feliz Ano Novo! "
gameforge.locale.years_greetings.event_info = "Todos os que me cumprimentarem com uma v\233nia hoje[ENTER]ir\227o receber um pequeno presente de Ano Novo,[ENTER]desde que o seu n\237vel seja no m\237nimo 15. Espero[ENTER]que te tenham ensinado a respeitar os mais velhos[ENTER]e a sua sabedoria? "
