gameforge.main_quest_flame_lv100 = {}
gameforge.main_quest_flame_lv100._010_sendLetter = "Mat\233ria Negra "
gameforge.main_quest_flame_lv100._020_say = "O Yak-Hwan est\225 \224 tua procura. Por favor vai ter[ENTER]com ele. "
gameforge.main_quest_flame_lv100._030_say = "Bem-vindo. O Yon-I-Walker terminou as suas[ENTER]investiga\231\245es. O fen\243meno que observaste na Terra[ENTER]do Fogo foi identificado como Mat\233ria Negra. "
gameforge.main_quest_flame_lv100._040_say = "Ela emana do interior do Forte e altera os[ENTER]dem\243nios nas redondezas. Quanto mais tempo eles[ENTER]passam sob a sua influ\234ncia, mais fortes e[ENTER]agressivos eles se tornam. Temos de evitar que[ENTER]esta Mat\233ria Negra se espalhe mais! "
gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "Enquanto o nosso alquimista procura uma solu\231\227o,[ENTER]n\227o dev\237amos ficar parados. Regressa \224 Terra do[ENTER]Fogo e derrota 300 dem\243nios nas redondezas do[ENTER]Forte. "
gameforge.main_quest_flame_lv100._070_say = "Naturalmente. "
gameforge.main_quest_flame_lv100._080_say = "Obrigado. Agora despacha-te! "
gameforge.main_quest_flame_lv100._090_notice = "Derrota 300 dem\243nios da Terra do Fogo nas[ENTER]redondezas do Forte e no local das Ervas do Sol. "
gameforge.main_quest_flame_lv100._100_sayTitle = "D\228monenhatz "
gameforge.main_quest_flame_lv100._110_say = "Erledige 300 Feuerland D\228monen in der N\228he der Festung und dem Fundort der Sonnenkr\228uter "
gameforge.main_quest_flame_lv100._120_say = "Pressinto que n\227o derrotaste dem\243nios[ENTER]suficientes. Volta \224 Terra do Fogo e continua a[ENTER]lutar. "
gameforge.main_quest_flame_lv100._130_notice = "Derrotaste todos os dem\243nios. Agora regressa ao[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv100._140_say = "Procura o Yak-Hwan. "
gameforge.main_quest_flame_lv100._150_say = "Muito bem, isto dever\225 ter ajudado a impedir a[ENTER]propaga\231\227o da Mat\233ria Negra. Relaxa um pouco[ENTER]enquanto falo com o alquimista. "
gameforge.main_quest_flame_lv100._160_sendLetter = "Tintura Nimbus "
gameforge.main_quest_flame_lv100._170_say = "O alquimista est\225 \224 tua procura. Parece ser[ENTER]urgente! "
gameforge.main_quest_flame_lv100._180_say = "Uma cat\225strofe! Eu disse ao Yak-Hwan para agir[ENTER]com cautela. E o que \233 que ele faz? Envia-nos de[ENTER]espadas em punho para o caos! A Mat\233ria Negra[ENTER]cresce e propaga-se mais r\225pido quando o seu[ENTER]hospedeiro morre. Ouvi dizer que 300 dem\243nios[ENTER]infectados foram mortos! Isso n\227o \233 nada bom... "
gameforge.main_quest_flame_lv100._190_say = "Nestas condi\231\245es, nem mesmo a minha Tintura[ENTER]Nimbus, que tinha como objectivo expulsar a[ENTER]Mat\233ria Negra, ser\225 suficiente. Preciso[ENTER]urgentemente de ingredientes para produzir mais. "
gameforge.main_quest_flame_lv100._200_say = {}
gameforge.main_quest_flame_lv100._210_say = "Traz-me 10 Pedras Basilares, 50 Feles de Urso, 10[ENTER]Sacos Venenosos de Aranha e 200 Fragmentos de[ENTER]Energia. Um guerreiro experiente como tu n\227o[ENTER]dever\225 precisar que lhe digam onde estas coisas[ENTER]podem ser encontradas, certo? "
gameforge.main_quest_flame_lv100._220_say = "Vou j\225 p\244r-me a caminho. "
gameforge.main_quest_flame_lv100._230_say = "Muito bem. Despacha-te, porque a cada minuto que[ENTER]passa sem fazermos nada, a Mat\233ria Negra continua[ENTER]a propagar-se. "
gameforge.main_quest_flame_lv100._240_notice = "Besorge die Zutaten mit denen der Alchemist die Nimbustinktur herstellen kann "
gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Tintura Nimbus "
gameforge.main_quest_flame_lv100._270_say = "Encontra 10 Pedras Basilares, 50 Feles de Urso,[ENTER]10 Sacos Venenosos de Aranha e 200 Fragmentos de[ENTER]Energia.[ENTER]Leva estes ingredientes ao alquimista. "
gameforge.main_quest_flame_lv100._280_say = "Encontraste todos os ingredientes! Genial, vou[ENTER]deitar m\227os \224 obra. Irei mandar chamar-te assim[ENTER]que a Tintura Nimbus estiver pronta. "
gameforge.main_quest_flame_lv100._290_say = "Se n\227o travarmos em breve a propaga\231\227o da Mat\233ria[ENTER]Negra, as coisas n\227o v\227o ficar bem para n\243s. Vai[ENTER]e traz-me todos os ingredientes para a Tintura[ENTER]Nimbus. "
gameforge.main_quest_flame_lv100._300_notice = "Tens todos os ingredientes necess\225rios. Regressa[ENTER]ao alquimista. "
gameforge.main_quest_flame_lv100._310_say = "Fala com o Alquimista. "
gameforge.main_quest_flame_lv100._320_sendLetter = "P\225ra a Mat\233ria Negra "
gameforge.main_quest_flame_lv100._330_say = "Mas que... humph... Queixei-me ao Ferreiro porque[ENTER]as Pedras Basilares foram desfeitas de forma[ENTER]demasiado rudimentar. E agora? Ele est\225 ofendido[ENTER]e recusa-se a converter o resto das Pedras em p\243.[ENTER]Que teimoso! Podes falar com ele? "
gameforge.main_quest_flame_lv100._340_say = "Com certeza. "
gameforge.main_quest_flame_lv100._350_say = "Danke Hier sind die Fundamentsteine Und bringe ihm diesen Korb mit Leckereien als Entschuldigung "
gameforge.main_quest_flame_lv100._360_sayTitle = "Acalmar o Ferreiro "
gameforge.main_quest_flame_lv100._370_say = "Acalma o ferreiro e convence-o a moer as Pedras[ENTER]Basilares num p\243 fino. "
gameforge.main_quest_flame_lv100._380_say = "P\243 de Pedra Basilar: 1 unidade "
gameforge.main_quest_flame_lv100._390_say = "O que posso fazer por ti?[ENTER]Queres que afie a tua arma? Queres a tua armadura[ENTER]polida? "
gameforge.main_quest_flame_lv100._400_say = "N\227o, hoje n\227o. Estou aqui porque o alquimista[ENTER]gostaria de pedir perd\227o pela sua l\237ngua afiada.[ENTER]Ele enviou-te este cesto de coisas boas. "
gameforge.main_quest_flame_lv100._410_say = "Estou relutante em fazer alguma coisa para ajudar[ENTER]aquele traste ingrato. Mas como \233 por ti, irei[ENTER]moer as Pedras Basilares. Espera um momento. "
gameforge.main_quest_flame_lv100._420_say = "Obrigado! "
gameforge.main_quest_flame_lv100._430_say = "O Ferreiro est\225 a ser teimoso? D\225-lhe o cesto e[ENTER]pede a sua ajuda. Ele n\227o ser\225 capaz de dizer n\227o[ENTER]a ti. "
gameforge.main_quest_flame_lv100._440_notice = "O P\243 de Pedra Basilar est\225 pronto. Leva-o ao[ENTER]alquimista. "
gameforge.main_quest_flame_lv100._450_say = "Oh fein wie Babypuder ausgezeichnet Der alte Sturkopf kann es also doch hehe Nun kann ich die Nimbustinktur mischen Ruhe dich etwas aus Ich werde dich rufen wenn sie fertig ist "
gameforge.main_quest_flame_lv101 = {}
gameforge.main_quest_flame_lv101._010_sendLetter = "Forte Misterioso "
gameforge.main_quest_flame_lv101._020_say = "O Yak-Hwan est\225 \224 tua procura. Vai ter com ele e[ENTER]descobre o que ele quer. "
gameforge.main_quest_flame_lv101._030_say = "O alquimista j\225 me informou do meu erro. Espero[ENTER]que n\227o seja demasiado tarde para o corrigir. "
gameforge.main_quest_flame_lv101._040_say = "Irei revestir a tua arma com a Tintura Nimbus.[ENTER]Agora se matares dem\243nios infectados, a Mat\233ria[ENTER]Negra neles contida ser\225 expulsa e n\227o poder\225[ENTER]espalhar-se. "
gameforge.main_quest_flame_lv101._050_say = "Agora tamb\233m podes testar as tuas habilidades no[ENTER]interior do misterioso forte. J\225 tens a Passagem.[ENTER]Talvez l\225 descubras uma pista relativa aos planos[ENTER]dos Servos das Trevas e tamb\233m o meu batedor[ENTER]desaparecido. "
gameforge.main_quest_flame_lv101._060_say = {}
gameforge.main_quest_flame_lv101._070_say = "Irei j\225 para l\225. "
gameforge.main_quest_flame_lv101._080_say = "Danke Ich w\252nsche dir das Beste "
gameforge.main_quest_flame_lv101._090_notice = "For\231a a tua entrada no Forte e combate os[ENTER]dem\243nios que por l\225 encontrares. Mant\233m-te atento[ENTER]ao batedor desaparecido e a quaisquer pistas[ENTER]importantes. "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "For\231a a tua entrada no Forte e derrota dem\243nios[ENTER]que por l\225 encontres. Procura pistas relativas ao[ENTER]plano dos Servos e pelo batedor desaparecido! "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten Bilde eine Gruppe um passieren zu d\252rfen Du erh\228ltst keinen weiteren Passierschein "
gameforge.main_quest_flame_lv101._130_say = "J\225 estiveste no interior do Forte? Devem existir[ENTER]pistas relativas aos planos dos Servos das Trevas[ENTER]e ao meu batedor desaparecido! Regressa \224 Terra[ENTER]do Fogo e procura no Forte. "
gameforge.main_quest_flame_lv101._140_say = "Der Sp\228her ist schon eine Weile tot In seiner Tasche findest du einen Brief \220berbringe ihn Yak Hwan "
gameforge.main_quest_flame_lv101._150_notice = "Descobriste o batedor do Yak-Hwan. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "Consigo ler as m\225s not\237cias na tua cara... J\225[ENTER]temia isto. Ele estava na posse de uma carta?[ENTER]Mostra-me.[ENTER]Tamb\233m deve haver por l\225 uma pista relativa aos[ENTER]planos dos Servos das Trevas. Volta l\225 e[ENTER]procura-a. Iremos ler a carta mais tarde. "
gameforge.main_quest_flame_lv101._190_notice = "Descobriste um Colar Rebitado pertencente aos[ENTER]Servos das Trevas. Mostra-o ao Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "Interessante... O Colar Rebitado pertence aos[ENTER]Servos das Trevas. Talvez seja uma pista relativa[ENTER]aos seus planos! Mas ainda n\227o h\225 sinal do meu[ENTER]batedor? Por favor continua \224 sua procura. Ele[ENTER]deve estar nesse Forte. "
gameforge.main_quest_flame_lv101._210_notice = "Descobriste o Colar Rebitado e o batedor.[ENTER]Regressa ao Yak-Hwan. "
gameforge.main_quest_flame_lv101._220_say = "Leva o relato ao Yak-Hwan. "
gameforge.main_quest_flame_lv101._230_say = "Ent\227o foste bem-sucedido! Este Colar Rebitado[ENTER]pertence aos Servos das Trevas. De certeza que[ENTER]ele cont\233m uma pista escondida relativa aos seus[ENTER]planos. E o que \233 isso? Uma carta do meu batedor?[ENTER]Mostra-ma. "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief den mir mein Sp\228her hinterlassen hat Ich bin ersch\252ttert Lass uns gemeinsam seine letzten Worte lesen "
gameforge.main_quest_flame_lv101._260_sayTitle = "Palavras escritas apressadamente: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, n\227o me voltar\225s a ver com vida, mas[ENTER]espero que esta carta chegue \224s tuas m\227os.[ENTER]Encontrei um Forte na Terra do Fogo que n\227o se[ENTER]encontra marcado em nenhum mapa. O seu governante[ENTER]\233 um poderoso dem\243nio da Terra do Fogo - uma aura[ENTER]\250nica rodeia-o, assim como aos outros dem\243nios[ENTER]que o seguem. O seu rugido \233 ensurdecedor e[ENTER]parece que ele est\225 a guardar qualquer coisa. Mas[ENTER]n\227o consigo dizer do que se trata.[ENTER]Perdoa-me, falhei... "
gameforge.main_quest_flame_lv101._280_say = "Temos de descobrir o que se encontra escondido[ENTER]neste Forte.[ENTER]Repara, aqui no interior do Colar Rebitado existe[ENTER]algo gravado. Irei pedir conselho ao[ENTER]Yon-I-Walker. Ele ir\225 entrar em contacto contigo[ENTER]caso precise da tua ajuda. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "O Yon-I-Walker est\225 \224 tua procura. Vai ter com[ENTER]ele. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen ich habe dich bereits erwartet Ich brauche etwas Hilfe dabei die Gravur in diesem Nietenhalsband zu entschl\252sseln "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Os caracteres no interior do Colar Rebitado s\227o[ENTER]origin\225rios de uma cultura antiga, que existiu h\225[ENTER]muito tempo. Para os decifrar irei precisar do[ENTER]Sangue do Rei Chama. Ele corre pelas suas veias[ENTER]como lava. "
gameforge.main_quest_flame_lv101._340_say = "Considera-o feito. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast musst du so schnell wie m\246glich zu mir zur\252ckkehren Denn selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine begrenzte Zeit ohne Schaden \252berstehen "
gameforge.main_quest_flame_lv101._360_notice = "Obt\233m Sangue do Rei Chama. "
gameforge.main_quest_flame_lv101._370_say = "N\227o podemos tornar a gravura leg\237vel sem Sangue[ENTER]do Rei Chama! "
gameforge.main_quest_flame_lv101._380_notice = "Recebeste Sangue do Rei Chama.[ENTER]Regressa ao Yon-I-Walker. "
gameforge.main_quest_flame_lv101._390_say = "Fala com o Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, muito bem. Com a ajuda do sangue serei capaz[ENTER]de tornar a gravura leg\237vel. Isto ir\225 precisar de[ENTER]algum tempo. Regressa de manh\227. "
gameforge.main_quest_flame_lv101._410_say = "Espera mais %d hrs. %d min. "
gameforge.main_quest_flame_lv101._420_say = "Preciso de mais algum tempo. Regressa mais tarde! "
gameforge.main_quest_flame_lv101._430_sendLetter = "A Gravura "
gameforge.main_quest_flame_lv101._440_say = "Chegaste na altura certa! J\225 decifrei a gravura[ENTER]do Colar Rebitado. "
gameforge.main_quest_flame_lv101._450_say = "Sie verr\228t uns dass die Diener der Dunkelheit einen der m\228chtigesten Feuerd\228monen entsandt haben um die Siegel der Tore zu schmelzen hinter denen die Sechs Drachen an einem verborgenen Ort gefangen gehalten werden Es wird auch ein spezieller Schmelzofen erw\228hnt Ich habe alles in diesem Schreiben an Yak Hwan festgehalten Bringe es bitte zu ihm "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post f\252r Yak Hwan "
gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon I Walker die Gravur lesen Oh ein Brief mit allen Informationen von ihm Sehr gut zeig her "
gameforge.main_quest_flame_lv101._510_say = "O selo do Grande Drag\227o... Aha... O Forte que[ENTER]descobrimos deve ser o lend\225rio Forte do Drag\227o[ENTER]Vermelho! Um dos drag\245es que os Servos precisam[ENTER]de matar para obter as P\233rolas da Noite \233 suposto[ENTER]encontrar-se aprisionado nesse local.[ENTER]Toma, leva esta Passagem e toma conta dela. Ir\225s[ENTER]precisar dela em breve... "
gameforge.main_quest_flame_lv101._520_say = "T\246te den Flammenk\246nig und fange sein brennendes Blut auf "
gameforge.main_quest_flame_lv101._530_say = {}
gameforge.main_quest_flame_lv102 = {}
gameforge.main_quest_flame_lv102._010_sendLetter = "Assalto ao Forte "
gameforge.main_quest_flame_lv102._020_say = "O Yak-Hwan est\225 \224 tua procura. Ele quer falar[ENTER]contigo sobre os planos que se seguem. "
gameforge.main_quest_flame_lv102._030_say = "Barric\225mos o Forte do Drag\227o Vermelho. Desta[ENTER]forma, n\227o poder\227o sair mais dem\243nios infectados[ENTER]e podemos prevenir que a Mat\233ria Negra se[ENTER]continue a espalhar. "
gameforge.main_quest_flame_lv102._040_say = "Deine Aufgabe wird es nun sein in die Festung einzufallen so viele D\228monen wie m\246glich unsch\228dlich zu machen und herauszufinden ob darin tats\228chlich der legend\228re Rotdrache gefangen ist "
gameforge.main_quest_flame_lv102._050_say = "Percebido. "
gameforge.main_quest_flame_lv102._060_say = "Erledige 30 D\228monen und bringe mir als Beweis daf\252r ihre D\228monenkrallen "
gameforge.main_quest_flame_lv102._070_notice = "Erledige 30 D\228monen und bringe Yak Hwan als Beweis ihre D\228monenkrallen "
gameforge.main_quest_flame_lv102._080_sayTitle = "Assalta o Forte do Drag\227o Vermelho! "
gameforge.main_quest_flame_lv102._090_say = "Besiege 30 D\228monen in der Rotdrachenfestung und bringe Yak Hwan ihre D\228monenkrallen als Beweis "
gameforge.main_quest_flame_lv102._100_say = "D\228monenkralle des St\252ck D\228monenkralle des St\252ck "
gameforge.main_quest_flame_lv102._110_say = "R\252stungsfragment des St\252ck Waffenfragment des St\252ck "
gameforge.main_quest_flame_lv102._120_say = "Du hast noch nicht gen\252gend D\228monen besiegt Erledige insgesamt 30 St\252ck und bringe mir ihre D\228monenkrallen als Beweis "
gameforge.main_quest_flame_lv102._130_notice = "Derrotaste todos os Dem\243nios de Brasas. Regressa[ENTER]ao Yak-Hwan. "
gameforge.main_quest_flame_lv102._140_say = "Vai ter com o Yon-I-Walker. "
gameforge.main_quest_flame_lv102._150_say = "Est\225s de volta - e pelo que vejo tiveste sucesso![ENTER]O que me podes dizer? "
gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "Um dem\243nio de chamas poderoso? \201 o Razador,[ENTER]governante do fogo! Se os Servos o enviaram, deve[ENTER]existir algo de enorme valor no Forte. Talvez[ENTER]mesmo o lend\225rio drag\227o vermelho! Irei falar com[ENTER]os meus conselheiros. Toma, aceita esta Passagem[ENTER]e toma conta dela. Ir\225s precisar dela mais tarde. "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
gameforge.main_quest_flame_lv102._190_say = "O Yon-I-Walker est\225 \224 tua procura. Vai ter com[ENTER]ele para descobrires mais. "
gameforge.main_quest_flame_lv102._200_say = "Ent\227o sobreviveste a um encontro com o monstruoso[ENTER]Razador. Curvo-me respeitosamente perante a tua[ENTER]pessoa. "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "Juntamente com o Rei do Gelo, Alastor, o[ENTER]governante do fogo pertence ao grupo de criaturas[ENTER]do submundo mais maldoso e mortal que a[ENTER]humanidade conhece. O pr\243prio Razador poder\225 ser[ENTER]a raz\227o da exist\234ncia da Mat\233ria Negra. "
