gameforge.main_quest_flame_lv102._280_sayTitle = "Materie Kugeln "
gameforge.main_quest_flame_lv102._290_say = "Assalta o Forte do Drag\227o Vermelho, combate os[ENTER]Dem\243nios de Brasas e obt\233m 10 peda\231os de Mat\233ria[ENTER]Negra. "
