gameforge.main_quest_flame_lv102._340_say = {}
gameforge.main_quest_flame_lv102._350_sendLetter = "Neutraliza\231\227o da Mat\233ria Negra "
gameforge.main_quest_flame_lv102._360_say = "Boas not\237cias! Descobri como neutralizar o poder[ENTER]da Mat\233ria Negra. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Todos os poderes da natureza t\234m um oposto - luz[ENTER]e escurid\227o, fogo e \225gua, bem e mal. Mesmo a[ENTER]Mat\233ria Negra tem um oposto, algo com o poder[ENTER]para a neutralizar: Lumen Puro! "
gameforge.main_quest_flame_lv102._390_say = "Para produzir Lumen Puro, precisas de fundir[ENTER]Fragmentos de Energia em \193gua Mong. Podes obter[ENTER]50 garrafas de \193gua Mong e 100 Fragmentos de[ENTER]Energia e lev\225-los ao Yu-Hwan? Obrigado. "
