gameforge.main_quest_flame_lv102._410_notice = "Recolhe 50 garrafas de \193gua Mong e 100 Fragmentos[ENTER]de Energia e leva tudo ao Yu-Hwan. "
gameforge.main_quest_flame_lv102._420_sayTitle = "Lumen Puro "
gameforge.main_quest_flame_lv102._430_say = "Recolhe 50 garrafas de \193gua Mong e 100 Fragmentos[ENTER]de Energia e leva tudo ao Yu-Hwan. "
gameforge.main_quest_flame_lv102._440_say = "Woah, o Yon-I-Walker j\225 me tinha avisado que[ENTER]vinhas aqui ter. Bom, vamos deitar m\227os ao[ENTER]trabalho. E que tal descansares um pouco[ENTER]entretanto? "
gameforge.main_quest_flame_lv102._450_say = "Woah, o Yon-I-Walker j\225 me tinha avisado que[ENTER]vinhas aqui ter. Gostaria de deitar m\227os ao[ENTER]trabalho, mas ainda n\227o tens materiais[ENTER]suficientes para produzir Lumen Puro. Continua a[ENTER]reunir materiais. "
