gameforge.main_quest_flame_lv103._030_say = "Est\225 na hora. O combate come\231ou. Enviei tropas[ENTER]para o Forte do Drag\227o Vermelho. Todos os homens[ENTER]est\227o equipados com Lumen Puro. A sua destreza[ENTER]tornou-se ainda mais afiada. O efeito \233 tremendo! "
