gameforge.main_quest_flame_lv103._150_say = "Todo o batalh\227o caiu? Oh n\227o... isto \233 tudo culpa[ENTER]minha. O ataque foi executado com demasiada[ENTER]pressa e os meus homens pagaram com as suas[ENTER]vidas. "
gameforge.main_quest_flame_lv103._160_say = {}
gameforge.main_quest_flame_lv103._170_say = "Preciso de repensar a minha estrat\233gia. Deve[ENTER]existir outra forma de eliminar estes dem\243nios.[ENTER]Prepara-te. Irei mandar chamar-te assim que tiver[ENTER]um plano. "
