gameforge.main_quest_flame_lv103._330_notice = "Ataca o Forte do Drag\227o Vermelho novamente e[ENTER]derrota 50 de cada dos Reis de Brasas, Barbas de[ENTER]Brasas, Trolls de Brasas, Generais de Brasas e[ENTER]Chefes de Brasas. "
