gameforge.main_quest_flame_lv104._110_say = "Mortal, atenta as minhas palavras! Desfruta da[ENTER]tua ef\233mera vis\227o de triunfo. N\227o durar\225 muito[ENTER]tempo. O drag\227o vermelho ir\225 quebrar as suas[ENTER]correntes. Com o seu poder irei regressar ao teu[ENTER]pat\233tico mundo para completar a minha tarefa. "
