gameforge.main_quest_flame_lv104._220_say = "Vai ter com o Yon-I-Walker e descobre como[ENTER]derrotar o Razador de uma vez por todas. "
gameforge.main_quest_flame_lv104._230_say = "Ainda n\227o foste ter com o Yon-I-Walker? Como[ENTER]prop\245es derrotar o Razador?! Vai! De que est\225s \224[ENTER]espera?! "
gameforge.main_quest_flame_lv104._240_say = "Sim, \233 verdade. O Razador est\225 de volta - e ainda[ENTER]mais agitado do que nunca. Temos apenas uma op\231\227o[ENTER]para evitar que os Servos das Trevas levem a cabo[ENTER]o seu plano... "
gameforge.main_quest_flame_lv104._250_say = "O Razador n\227o ir\225 descansar antes de ele ter[ENTER]completado a sua tarefa e libertado o drag\227o[ENTER]vermelho. Para travarmos isto temos de expulsar o[ENTER]drag\227o. "
