gameforge.main_quest_flame_lv104._470_say = "Nun ben\246tige ich noch ein geeignetes Gef\228\223 f\252r den Verbannungszauber Die Fl\252gelhaut Martyaxwars H\228uptling der Mantikore sollte uns gute Dienste leisten Beschaffe f\252nf St\252cke "
gameforge.main_quest_flame_lv104._480_notice = "Bringe Yon I Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars "
gameforge.main_quest_flame_lv104._490_say = "Bringe Yon I Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars in guter Qualit\228t "
gameforge.main_quest_flame_lv104._500_say = "Estamos t\227o perto do nosso objectivo - n\227o[ENTER]desistas agora. Traz-me o Couro de Mant\237cora! "
gameforge.main_quest_flame_lv104._510_say = "Perfekt Die Fl\252gelhaut ist sehr widerstandsf\228hig Aus ihr kann ich nun Lederbeutel f\252r den Verbannungszauber herstellen Yak Hwan wird dich sp\228ter noch genauer instruieren Aber nun mache ich mich erstmal an die Arbeit "
gameforge.main_quest_flame_lv104._520_notice = "Conseguiste recolher todos os peda\231os de Couro de[ENTER]Mant\237cora. Leva-os ao Yon-I-Walker. "
gameforge.main_quest_flame_lv105 = {}
gameforge.main_quest_flame_lv105._010_sendLetter = "O Combate Come\231a "
gameforge.main_quest_flame_lv105._020_say = "Prepara-te - o combate est\225 a come\231ar. O Yak-Hwan[ENTER]tem algumas \250ltimas informa\231\245es para ti. "
gameforge.main_quest_flame_lv105._030_say = "Est\225 na hora. O nosso ex\233rcito est\225 a postos. O[ENTER]combate pode come\231ar. Tens o Anel de Samael[ENTER]contigo? "
gameforge.main_quest_flame_lv105._040_say = "Ja hier sind sie "
gameforge.main_quest_flame_lv105._050_say = "Ah muito bem. Irei explicar como o podes usar[ENTER]mais tarde. Mas primeiro temos de atravessar as[ENTER]rec\233m-formadas linhas de defesa dos dem\243nios. Vai[ENTER]at\233 ao Forte do Drag\227o Vermelho e derrota:[ENTER]10 Reis de Brasas[ENTER]10 Barbas de Brasas[ENTER]10 Trolls de Brasas[ENTER]10 Generais de Brasas[ENTER]10 Chefes de Brasas "
gameforge.main_quest_flame_lv105._060_say = {}
gameforge.main_quest_flame_lv105._070_say = "Entendido. "
gameforge.main_quest_flame_lv105._080_notice = "Besiege jeweils 10 Glut Flammenk\246nige Glut Flammenb\228rte Glut Flammengolem Glut Flammengener\228le und Glut Flammenf\252rste "
gameforge.main_quest_flame_lv105._090_sayTitle = "Starte die Offensive "
gameforge.main_quest_flame_lv105._100_say = "Assalta o Forte do Drag\227o Vermelho! "
gameforge.main_quest_flame_lv105._110_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein "
gameforge.main_quest_flame_lv105._120_say = "Ainda n\227o conseguimos quebrar as linhas[ENTER]defensivas do inimigo. Derrota todos os Dem\243nios[ENTER]de Brasas necess\225rios. "
gameforge.main_quest_flame_lv105._130_notice = "Derrotaste o ex\233rcito de Dem\243nios de Brasas.[ENTER]Regressa ao Yak-Hwan. "
gameforge.main_quest_flame_lv105._140_say = "Regressa ao Yak-Hwan. "
gameforge.main_quest_flame_lv105._150_say = "Fizeste um bom trabalho. Estamos um passo mais[ENTER]perto do nosso objectivo - o drag\227o vermelho n\227o[ENTER]ser\225 uma amea\231a durante muito mais tempo. "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "O teu arqui-inimigo, Razador, parece ressentir-se[ENTER]do facto de o teres matado. O seu rugido soa mais[ENTER]alto que nunca atrav\233s das plan\237cies de[ENTER]Doyyumhwan. "
gameforge.main_quest_flame_lv105._180_say = "Est\225 na altura de voltar a silenci\225-lo. Ele[ENTER]encontra-se, com olhos de falc\227o, por cima do[ENTER]port\227o onde o drag\227o vermelho se encontra[ENTER]mantido.[ENTER]Tem cuidado com ele! Ele aprendeu com a sua[ENTER]derrota e n\227o ir\225 cometer os mesmos erros duas[ENTER]vezes. "
gameforge.main_quest_flame_lv105._190_notice = "Derrota Razador, governante do fogo. "
gameforge.main_quest_flame_lv105._200_sayTitle = "Brincando com Fogo "
gameforge.main_quest_flame_lv105._210_say = "Derrota Razador, o governante do fogo, no Forte[ENTER]do Drag\227o Vermelho. "
gameforge.main_quest_flame_lv105._220_say = "O Razador foi demasiado para ti desta vez? N\227o[ENTER]consigo acreditar disso! Conseguiste faz\234-lo uma[ENTER]vez - ser\225s capaz de o fazer desta vez tamb\233m! "
gameforge.main_quest_flame_lv105._230_notice = "O Razador foi derrotado. Leva o teu relato ao[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv105._240_say = "Ich wusste du w\252rdest es schaffen Gro\223artig Nun werden wir alles f\252r die Verbannung des Rotdrachen vorbereiten Ich lasse dich rufen sobald wir bereit sind "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Est\225 na hora. Est\225 tudo pronto para a expuls\227o do[ENTER]drag\227o vermelho. "
gameforge.main_quest_flame_lv105._270_say = "Meine M\228nner haben bereits bereits zwei Bannkreise aufgestellt Deine Aufgabe ist es nun sie zu entz\252nden Wirf den Bannbeutel auf die Kreise und sie werden sich entflammen Das wird die Verbannung des Rotdrachen vollziehen "
gameforge.main_quest_flame_lv105._280_notice = "Entz\252nde die Bannkreise und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entz\252nde mithilfe der Bannbeutel die magischen Kreissymbole und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._320_say = "L\225pide de Taramor: 1 unidade "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "O que foi isso, seu verme?! No m\225ximo isso foram[ENTER]umas c\243cegas - n\227o me conseguiste expulsar com[ENTER]isso! Irei voltar a buscar o Razador ao mundo dos[ENTER]mortos. Ele ir\225 libertar-me da minha pris\227o e[ENTER]ir\225s poder sentir a minha f\250ria! "
gameforge.main_quest_flame_lv105._350_notice = "A expuls\227o do Drag\227o Vermelho falhou. Informa o[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen Wie konnte das passieren "
gameforge.main_quest_flame_lv105._370_say = "Ja Eigentlich wurden die Bannkreise aktiviert und die Entflammung hat auch stattgefunden und die Verbannung hatte begonnen aber der Rotdrache war so m\228chtig dass dies fehlgeschlagen ist Er sagte dass er Yamachun 6091 wiederbeleben wird und er die Versiegelung entfernen wird Aber er hat auch gro\223en Schaden durch unseren Verbannungs Versuch erlitten "
gameforge.main_quest_flame_lv105._380_say = "Ach so Gute Arbeit Dank dir konnten wir es so weit bringen Ich habe bereits mit Yon I Walker 20380 gesprochen und \252berlegt was wir nun tun k\246nnen Meine M\228nner werden weiterhin die Lage beobachten und wir werden ach anderen Methoden suchen wie wir die Verbannung vollziehen k\246nnen Wenn wir eine perfekte Methoe gefunden haben den Rotdrachen zu verbannen werde ich nach dir rufen lassen Gute Arbeit "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "Corre para o Fogo "
gameforge.main_quest_flame_lv99._020_say = "O Yak-Hwan est\225 \224 tua procura. Vai ter com ele e[ENTER]descobre o que ele quer. "
gameforge.main_quest_flame_lv99._030_say = "Bem-vindo de volta! Quem me dera que[ENTER]consegu\237ssemos um descanso, por mais curto que[ENTER]fosse - os Servos das Trevas est\227o de volta \224[ENTER]ac\231\227o. Isto n\227o pode ser bom. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "No entanto a minha informa\231\227o \233 muito vaga. Tudo[ENTER]o que sabemos \233 que eles se encontram escondidos[ENTER]na Terra do Fogo. "
gameforge.main_quest_flame_lv99._060_say = "J\225 envi\225mos um batedor. Mas recentemente ele[ENTER]deixou de contactar connosco e estou muito[ENTER]preocupado.[ENTER]Podes procur\225-lo no teu caminho pela Terra do[ENTER]Fogo? "
gameforge.main_quest_flame_lv99._070_say = "Claro. "
gameforge.main_quest_flame_lv99._080_say = "Obrigado. Irei marcar a sua \250ltima posi\231\227o[ENTER]conhecia no mapa. Boa sorte! "
gameforge.main_quest_flame_lv99._090_notice = "Procura o batedor desaparecido na Terra do Fogo.[ENTER]Coordenadas: %d,%d "
gameforge.main_quest_flame_lv99._100_sayTitle = "Explora a Terra do Fogo! "
gameforge.main_quest_flame_lv99._110_say = "Viaja at\233 \224 Terra do Fogo. L\225, procura o batedor[ENTER]e quaisquer pistas relativas aos planos dos[ENTER]Servos das Trevas. "
gameforge.main_quest_flame_lv99._120_say = "Deve haver algo nesta posi\231\227o. Talvez tenhas[ENTER]falhado uma pista. Continua \224 procura. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort den Yak Hwan auf der Karte markiert hat Schaue dich um und kehre dann zu Yak Hwan zur\252ck "
gameforge.main_quest_flame_lv99._140_say = "O Yak-Hwan aguarda o teu relat\243rio na Rocha do[ENTER]Drag\227o Negro. "
gameforge.main_quest_flame_lv99._150_say = "Est\225s de volta! Descobriste alguma coisa? "
gameforge.main_quest_flame_lv99._160_say = "Infelizmente n\227o havia qualquer rasto do batedor.[ENTER]Mas havia l\225 um Forte no qual nunca tinha[ENTER]reparado antes. Uma poderosa aura emana das suas[ENTER]paredes e afecta tudo o que as rodeia. "
gameforge.main_quest_flame_lv99._170_say = "Hmm, n\227o gosto nada disso. Irei descobrir mais[ENTER]sobre esse Forte e voltarei a contactar contigo. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Investigar o Forte "
gameforge.main_quest_flame_lv99._190_say = "Hm wir tappen im Dunkeln Ich habe rein gar nichts \252ber diese geheimnisvolle Festung herausfinden k\246nnen In diesem Brief habe ich alles zusammengetragen was wir bis jetzt wissen Bitte \252berbringe ihn Yon I Walker Er wird wissen was zu tun ist "
gameforge.main_quest_flame_lv99._200_say = "Vai ter com o Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun Ah ein Brief Yak Hwan bittet also um meine Hilfe Dann werden wir mal versuchen Licht in die Dunkelheit zu bringen "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura die aus dem Inneren einer Festung str\246mt Interessant Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um Ich habe da einen Verdacht worum es sich bei dieser Aura handeln k\246nnte Hier nimm dieses Papier und wickel es um deine Waffe Wenn sich mein Verdacht best\228tigt sollte sich das Papier schwarz f\228rben sobald du damit D\228monen t\246test die unter dem Einfluss der dunklen Aura stehen "
gameforge.main_quest_flame_lv99._250_notice = "Derrota dem\243nios que vagueiem nas redondezas do[ENTER]Forte. "
gameforge.main_quest_flame_lv99._260_sayTitle = "Ca\231a ao Dem\243nio "
gameforge.main_quest_flame_lv99._270_say = "Derrota dem\243nios da Terra do Vogo que se[ENTER]encontram nas redondezas do Forte e verifica se a[ENTER]tua arma muda de cor. "
gameforge.main_quest_flame_lv99._280_say = "Hmm, tenho a certeza que provas desta aura[ENTER]poder\227o ser obtidas na Terra do Fogo. Regressa l\225[ENTER]e volta a derrotar dem\243nios que se encontrem nas[ENTER]redondezas do Forte. "
gameforge.main_quest_flame_lv99._290_notice = "A tua arma tornou-se negra. Regressa ao[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._300_say = "Ah so wie ich es erwartet hatte Das ist h\246chst bemerkenswert Ich werde dieses Papier etwas n\228her untersuchen Ruhe dich solange aus "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "O Yon-I-Walker est\225 \224 tua procura. Vai ter com[ENTER]ele para descobrires mais. "
gameforge.main_quest_flame_lv99._330_say = "Ah, aqui est\225s tu! A aura \233 p\233rfida e est\225 a[ENTER]obscurecer a minha mente.[ENTER]Preciso de Ervas do Sol para iluminar a minha[ENTER]mente e continuar as minhas investiga\231\245es. Podes[ENTER]obter-me algumas? "
gameforge.main_quest_flame_lv99._340_say = "Claro. "
gameforge.main_quest_flame_lv99._350_say = "As Ervas do Sol crescem em locais secos e quentes[ENTER]- elas podem ser encontradas na Terra do Fogo o[ENTER]ano todo.[ENTER]Irei marcar no mapa o \250ltimo local onde encontrei[ENTER]algumas. Embora n\227o esteja completamente certo se[ENTER]essa era a sua verdadeira localiza\231\227o... "
gameforge.main_quest_flame_lv99._360_say = "Vou p\244r-me j\225 a caminho! "
gameforge.main_quest_flame_lv99._370_notice = "Vai at\233 \224 localiza\231\227o marcada na Terra do Fogo e[ENTER]procura as Ervas do Sol. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Vai at\233 ao local que o Yon-I-Walker marcou no[ENTER]mapa e procura l\225 as Ervas do Sol. "
gameforge.main_quest_flame_lv99._400_say = "Regressas de m\227os vazias? Isso n\227o \233 bom. Sinto[ENTER]que a minha mente est\225 cada vez mais obscurecida[ENTER]pela aura. Por favor obt\233m algumas Ervas do Sol[ENTER]para mim. "
gameforge.main_quest_flame_lv99._410_notice = "Encontraste as Ervas do Sol. Leva-as ao[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, encontraste as Ervas do Sol! Excelente. Agora[ENTER]posso continuar as minhas investiga\231\245es.[ENTER]O Yak-Hwan ir\225 falar contigo sobre os resultados. "
gameforge.main_quest_flame_lv99._430_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel %d. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Bem-vindo ao Metin2 "
gameforge.main_quest_lv1._20_say = "As excitantes aventuras do Metin2 est\227o prestes a[ENTER]come\231ar. Primeiro encontra o Guarda da Cidade.[ENTER]Ele ir\225 dar-te algumas informa\231\245es b\225sicas e[ENTER]v\225rias tarefas.[ENTER][ENTER]Se quiseres ir \224 ca\231a, poder\225s encontrar animais[ENTER]selvagens nas redondezas da vila. Eles ser\227o[ENTER]mostrados no mini-mapa como pontos vermelhos.[ENTER]Deves concentrar-te nos C\227es Selvagens, para[ENTER]come\231ar, uma vez que s\227o os alvos mais f\225ceis.[ENTER]Boa sorte! "
gameforge.main_quest_lv1._30_targetVid = "Encontra o Guarda da Cidade "
gameforge.main_quest_lv1._40_sayTitle = "Encontra o Guarda da Cidade "
gameforge.main_quest_lv1._50_sayReward = "Fala com o Guarda da Cidade clicando nele. Ele \233[ENTER]o NPC para onde aponta uma seta. Se n\227o o[ENTER]conseguires ver talvez ele esteja demasiado[ENTER]longe. Segue os pontos que piscam no mapa at\233[ENTER]chegares ao Guarda da Cidade. "
gameforge.main_quest_lv1._60_sayTitle = "Guarda da Cidade: "
gameforge.main_quest_lv1._70_say = "Deves ser novo na cidade! Vejo que eles ainda n\227o[ENTER]te tornaram um soldado. J\225 tiveste algum treino[ENTER]sequer? Olha bem para ti! Alguma vez usaste uma[ENTER]arma? Ouve bem! Tens de ser cuidadoso se quiseres[ENTER]sobreviver a esta guerra. Irei ajudar-te at\233[ENTER]teres atingido o n\237vel 10. E n\227o penses que vai[ENTER]ser f\225cil! Agora p\245e-te a andar! "
gameforge.main_quest_lv1._80_say = "Vai e aprende os b\225sicos do combate e ca\231a! Assim[ENTER]que tiveres atingido um n\237vel mais alto regressa[ENTER]\224 vila e fala comigo de novo. Porque \233 que ainda[ENTER]est\225s aqui? N\227o ganhar\225s experi\234ncia ficando aqui[ENTER]a olhar! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Recebeste 50.000 Pontos de Experi\234ncia.[ENTER]Recebeste 12.000 Yang.[ENTER]Recebeste Sapatos Fita d'Ouro+4.[ENTER]Recebeste 5 Po\231\245es Roxas. "
gameforge.main_quest_lv10._10_sendLetter = "Dirige-te ao Capit\227o "
gameforge.main_quest_lv10._110_sayTitle = "O treino do Capit\227o "
gameforge.main_quest_lv10._120_sayReward = "A primeira miss\227o do Capit\227o leva-te \224 vila[ENTER]vizinha. A\237 dever\225s encontrar o m\250sico Yu-Hwan e[ENTER]perguntar-lhe pelos documentos secretos para o[ENTER]Capit\227o. "
gameforge.main_quest_lv10._130_sayTitle = "Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "A vida \233 um sonho, tal como tudo o resto. De onde[ENTER]vimos e para onde vamos? O mundo est\225 envolto em[ENTER]conflito. O trabalho honesto por si s\243 n\227o chega.[ENTER]Est\225s aqui para ouvir a minha m\250sica? "
gameforge.main_quest_lv10._150_say = "Oh, o Capit\227o enviou-te! Pss, baixa a tua voz...[ENTER]Ningu\233m na vila pode descobrir a minha verdadeira[ENTER]identidade. Toma isto. Este documento cont\233m toda[ENTER]a informa\231\227o que fui capaz de recolher. Leva-o ao[ENTER]Capit\227o. "
gameforge.main_quest_lv10._160_sayTitle = "Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Despacha-te e p\245e-te a caminho! Se ficares por[ENTER]aqui demasiado tempo algo de mau ir\225 acontecer.[ENTER]Lembra-te: A vida \233 curta, por isso aproveita-a. "
gameforge.main_quest_lv10._180_targetVid = "Regressa ao Capit\227o "
gameforge.main_quest_lv10._190_sayReward = "O m\250sico Yu-Hwan, que trabalha secretamente como[ENTER]um espi\227o, deu-te documentos importantes.[ENTER]Leva-os ao Capit\227o na primeira vila. "
gameforge.main_quest_lv10._200_say = "Este \233 o documento que o Yu-Hwan enviou? Nada mau[ENTER]para um aventureiro recente como tu! Espero[ENTER]grandes coisas de ti. Toma isto como recompensa[ENTER]pelo teu trabalho. Continua o bom trabalho pelo[ENTER]teu Reino. "
gameforge.main_quest_lv10._20_sayReward = "J\225 tens experi\234ncia suficiente para servir o[ENTER]nosso Reino como um verdadeiro guerreiro. A[ENTER]partir de agora o Capit\227o ir\225 dar-te as tuas[ENTER]novas miss\245es. Poder\225s encontr\225-lo na primeira[ENTER]vila. Vai ter com ele; ele espera-te. "
gameforge.main_quest_lv10._30_sayTitle = "Capit\227o "
gameforge.main_quest_lv10._40_say = "Pareces-me familiar... Oh sim, acho que j\225 ouvi[ENTER]falar de ti. \201s o novo aventureiro e safaste-te[ENTER]bem a provar-nos as tuas Habilidades. Ainda n\227o[ENTER]sei exactamente qu\227o h\225bil \233s, mas podes ter a[ENTER]certeza que ser\225s testado em tarefas futuras. "
gameforge.main_quest_lv10._50_say = "Existem desafios pela frente, por isso prepara-te[ENTER]para eles. Conheces a hist\243ria dos tr\234s Reinos?[ENTER]Ou do continente Para\237so Relampejante? N\227o[ENTER]conheces?! O que andam a ensinar aos mais novos[ENTER]hoje em dia? Tenho mesmo de te ensinar[ENTER]conhecimentos fundamentais? "
gameforge.main_quest_lv10._60_say = "Isto \233 importante, porque \233 a hist\243ria do[ENTER]continente. Por isso vou resumi-la para ti.[ENTER]Outrora, todos os Reinos estavam unidos. Mas[ENTER]ent\227o as Pedras Metin come\231aram a cair e com elas[ENTER]trouxeram guerra e conflitos. O continente foi[ENTER]dividido em tr\234s Reinos diferentes: Shinsoo, o[ENTER]Reino do Com\233rcio; Chunjo, o Reino da Religi\227o;[ENTER]Jinno, o Reino Militar. "
gameforge.main_quest_lv10._70_say = "Cada Reino anda desesperado a tentar recuperar[ENTER]dos problemas causados pela queda das Pedras[ENTER]Metin. Muita gente quer que o continente volte a[ENTER]ser unificado. Tamb\233m deves combater para isso![ENTER]Nunca te esque\231as. "
gameforge.main_quest_lv10._80_say = "Vou dar-te a tua primeira tarefa.[ENTER]Descansa, \233 uma bastante simples. Na vila vizinha[ENTER]poder\225s encontrar um m\250sico chamado Yu-Hwan.[ENTER]Muita gente diz qye ele abandonou o ex\233rcito para[ENTER]se tornar um m\250sico. Mas, na realidade, ele \233 um[ENTER]espi\227o que obt\233m v\225rios documentos secretos. Ele[ENTER]est\225 na posse de um documento que eu preciso.[ENTER]Traz-me esse documento. E n\227o te esque\231as que[ENTER]esta \233 uma miss\227o secreta. "
gameforge.main_quest_lv10._90_say = "Carrega na tecla M para descobrires como podes[ENTER]chegar at\233 \224 pr\243xima vila. Utiliza o portal[ENTER]indicado pelo nome da vila correspondente.[ENTER]Despacha-te! O Yu-Hwan \233 alto - mas poder\225s[ENTER]reconhec\234-lo pelos instrumentos musicais que[ENTER]est\227o com ele. "
gameforge.main_quest_lv12 = {}
gameforge.main_quest_lv12._100_sayTitle = "Mata Lobos Alfa Cinza "
gameforge.main_quest_lv12._10_sayReward = "O Capit\227o tem uma nova tarefa para ti. Vai falar[ENTER]com ele. "
gameforge.main_quest_lv12._110_say = "Queres desistir desta miss\227o? "
gameforge.main_quest_lv12._120_say = "Ent\227o, conseguiste? Muito bem! Espero que n\227o[ENTER]tenhas tido muitos problemas. De qualquer forma,[ENTER]avencemos para o pr\243ximo passo. "
gameforge.main_quest_lv12._130_targetVid = "Encontra o Capit\227o "
gameforge.main_quest_lv12._140_sendLetter = "Miss\227o completada "
gameforge.main_quest_lv12._150_say = "Miss\227o completada "
gameforge.main_quest_lv12._160_sayReward = "Mataste a quantidade necess\225ria de Lobos Alfa[ENTER]Cinza. Agora regressa ao Capit\227o e informa-o do[ENTER]teu sucesso. "
gameforge.main_quest_lv12._170_say = "Mataste os Lobos Alfa Cinza? Bom trabalho.[ENTER]Gra\231as a ti \233 agora mais f\225cil manter a vila a[ENTER]salvo. S\227o boas not\237cias, em tempos de guerra[ENTER]como estes. "
gameforge.main_quest_lv12._180_sayReward = "Recebeste 40.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang.[ENTER]Recebeste um Livro de Habilidades. "
gameforge.main_quest_lv12._20_say = "V\225rios Lobos Alfa Cinza t\234m andado a causar[ENTER]problemas nas redondezas da vila. J\225 h\225 algum[ENTER]tempo que andam com comportamentos fora do[ENTER]normal, mas recentemente ficaram completamente[ENTER]fora de controlo! Come\231aram a atacar a vila e as[ENTER]pessoas na rua. Para voltarmos a ter controlo[ENTER]desta situa\231\227o, temos de matar alguns Lobos Alfa[ENTER]Cinza. Podes ajudar-nos? Mata 10 Lobos Alfa Cinza[ENTER]por n\243s. "
gameforge.main_quest_lv12._30_sayReward = "Ir\225s receber 24.000 Pontos de Experi\234ncia e 3.500[ENTER]Yang como recompensa. "
gameforge.main_quest_lv12._40_sendLetter = "Mata 10 Lobos Alfa Cinza "
gameforge.main_quest_lv12._50_sayReward = "Os Lobos Alfa Cinza andam a atacar a vila. Para[ENTER]colocar a situa\231\227o sob controlo tens de matar 10[ENTER]Lobos Alfa Cinza. "
gameforge.main_quest_lv12._60_sayReward = "At\233 agora mataste %s Lobos Alfa Cinza. "
gameforge.main_quest_lv12._65_counter = "Faltam "
gameforge.main_quest_lv12._70_sayReward = "Mataste 10 Lobos Alfa Cinza. Regressa ao Capit\227o. "
gameforge.main_quest_lv12._80_npcChat = "Mata Lobos Alfa Cinza "
gameforge.main_quest_lv12._90_say = "O qu\234, ainda n\227o terminaste a tarefa? Est\225s a ter[ENTER]problemas em matar os 10 Lobos Alfa Cinza? Se[ENTER]queres continuar a combater pelo teu Reino,[ENTER]devias continuar a tentar. "
