gameforge.main_quest_lv14._10_sayReward = "O Capit\227o tem uma nova miss\227o para ti. Vai falar[ENTER]com ele. "
gameforge.main_quest_lv14._110_sayReward = "Destru\237ste uma Metin da Batalha. Vai ter com o[ENTER]Capit\227o e conta-lhe o teu feito. "
gameforge.main_quest_lv14._120_say = "Bom trabalho! Tornaste-te um ajudante de[ENTER]confian\231a! Agora sei que te posso confiar[ENTER]qualquer miss\227o. Estou orgulhoso por te ter a[ENTER]trabalhar connosco. Aqui est\225 a tua recompensa.[ENTER]Continua com o bom trabalho! "
gameforge.main_quest_lv14._130_sayReward = "Recebeste 20.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang.[ENTER]Recebeste uma Pe\231a d'Ouro. "
gameforge.main_quest_lv14._140_sayReward = "Recebeste uma %s. "
gameforge.main_quest_lv14._20_say = "Tenho conhecimento da energia mal\233fica das Pedras[ENTER]Metin. O m\250sico Yu-Hwan contou-me que as Pedras[ENTER]Metin fazem com que os animais fiquem loucos e[ENTER]espalhem doen\231as terr\237veis. "
gameforge.main_quest_lv14._30_say = "Se n\227o fizermos nada acerca das Pedras Metin, os[ENTER]animais ir\227o voltar a atacar os alde\245es, ou pior;[ENTER]pode come\231ar uma epidemia! Podes tratar das[ENTER]pedras que ca\237ram nas redondezas da vila? "
gameforge.main_quest_lv14._40_sayReward = "Ir\225s receber 48.000 Pontos de Experi\234ncia e[ENTER]10.000 Yang, al\233m de uma Pedra Esp\237rita (+0 a +2)[ENTER]como recompensa. "
gameforge.main_quest_lv14._50_sendLetter = "Destr\243i uma Metin da Batalha "
gameforge.main_quest_lv14._60_sayReward = "As Pedras Metin s\227o um verdadeiro perigo. Ajuda o[ENTER]Capit\227o e destr\243i uma Metin da Batalha. "
gameforge.main_quest_lv14._70_sayTitle = "Miss\227o completada "
