gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "O nosso Reino, Jinno, sempre teve grande poder[ENTER]militar. O Imperador unificou o continente com a[ENTER]sua cavalaria. E embora agora estejamos divididos[ENTER]devido aos combates pelas Pedras Metin, o nosso[ENTER]Reino ainda possui o poder de Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "A situa\231\227o actual "
gameforge.main_quest_lv15._110_say = "Mesmo que n\227o possamos fazer nada contra as[ENTER]Pedras Metin neste momento, ainda temos o[ENTER]ex\233rcito mais poderoso dos tr\234s Reinos. Se[ENTER]realmente quis\233ssemos poder\237amos facilmente[ENTER]conquistar os outros Reinos. Deverias treinar[ENTER]mais para te tornar um bom soldado! "
gameforge.main_quest_lv15._120_say = "Irei dar-te uma nova miss\227o. Leva estas muni\231\245es[ENTER]at\233 ao Yu-Hwan, que se encontra na vila vizinha.[ENTER]Guardamos estas muni\231\245es em v\225rios locais para[ENTER]termos alguma seguran\231a extra, podendo[ENTER]arranj\225-las facilmente em caso de emerg\234ncia. Se[ENTER]entregares isto ao Yu-Hwan ir\225s estar a ajudar a[ENTER]preparar as defesas da vila. "
gameforge.main_quest_lv15._130_sayReward = "Recebeste 36.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang.[ENTER]Recebeste um Ornamento. "
gameforge.main_quest_lv15._140_sayTitle = "A situa\231\227o actual "
gameforge.main_quest_lv15._150_sayReward = "O Capit\227o confiou-te uma encomenda para o[ENTER]Yu-Hwan. Leva-a at\233 ele na Segunda Vila. "
gameforge.main_quest_lv15._160_say = "Outrora, houve um combate sangrento entre Sung[ENTER]Mahi e o Deus Drag\227o. Desde ent\227o, as pessoas t\234m[ENTER]estado divididas e combatem umas com as outras em[ENTER]guerras intermin\225veis... Tu de novo! Precisas de[ENTER]algo? O Capit\227o enviou-me algo importante?[ENTER]Obrigado. E agora p\245e-te a caminho de novo - n\227o[ENTER]\233 bom que nos vejam juntos. "
gameforge.main_quest_lv15._170_makequestbutton = "Fala com o Capit\227o "
gameforge.main_quest_lv15._175_say = "Deste ao Yu-Hwan a encomenda do Capit\227o.[ENTER]Agora regressa ao Capit\227o para receberes a tua[ENTER]recompensa. "
gameforge.main_quest_lv15._180_say = "Muito bem! Se continuares assim poder\225s tornar-te[ENTER]um ajudante indispens\225vel para a nossa Vila.[ENTER]Aqui tens a tua recompensa. "
gameforge.main_quest_lv15._20_say = "Como j\225 deves ter ouvido, a situa\231\227o entre os[ENTER]Reinos n\227o est\225 muito boa. Vai ter com o Capit\227o.[ENTER]Ele pode dar-te mais informa\231\245es. "
gameforge.main_quest_lv15._30_say = "Acho que devias descobrir mais coisas sobre a[ENTER]nossa situa\231\227o actual. Foca os teus esfor\231os no[ENTER]nosso Reino primeiro. Para ganhar uma guerra,[ENTER]tens de te conhecer a ti mesmo antes de[ENTER]conheceres os teus inimigos. "
gameforge.main_quest_lv15._40_say = "O nosso reino, Shinsoo, tem sido sempre um centro[ENTER]do com\233rcio. As nossas extensas rotas comerciais[ENTER]traziam multid\245es de comerciantes e bens at\233 n\243s,[ENTER]vindos de todo o mundo. Mas desde a queda das[ENTER]Pedras Metin, essas rela\231\245es comerciais foram[ENTER]quebradas e a nossa economia caiu a pique. Sempre[ENTER]prosper\225mos, mas nunca tivemos muito poder[ENTER]militar, pelo que decidimos contratar alguns[ENTER]mercen\225rios. Estes soldados s\227o de confian\231a e[ENTER]leais a quem lhes paga. "
gameforge.main_quest_lv15._50_say = "Gra\231as aos mercen\225rios o nosso Reino voltou \224[ENTER]estabilidade. Mas, para nos prepararmos para as[ENTER]guerras que se aproximam, precisamos de mais[ENTER]mercen\225rios e uma economia forte. N\227o ser\225 f\225cil[ENTER]para ningu\233m. "
gameforge.main_quest_lv15._60_say = "Tenho outra tarefa para ti. Leva esta[ENTER]especialidade ao Yu-Hwan, que vive na vila[ENTER]vizinha. O nosso Reino era e ainda \233 um Reino[ENTER]baseado no com\233rcio, e por isso ainda negociamos[ENTER]especialidades de diversas regi\245es. O lucro que[ENTER]podemos obter delas ir\225 ajudar a nossa vila. "
gameforge.main_quest_lv15._70_say = "O nosso Reino, Chunjo, \233 governado por Yoo-Young[ENTER]e foi fundado com base em fortes cren\231as[ENTER]religiosas. Devido a isto sab\237amos da presen\231a de[ENTER]Sung Mahi antes de qualquer outra pessoa. Os[ENTER]nossos Xam\227s prepararam-nos para a queda das[ENTER]Pedras Metin. Sem eles n\227o ter\237amos conseguido[ENTER]proteger o nosso Reino. A sua cren\231a d\225-lhes[ENTER]habilidades que est\227o al\233m das normais[ENTER]capacidades humanas. E sem os Xam\227s seria apenas[ENTER]uma quest\227o de tempo at\233 sermos derrotados por[ENTER]outro Reino. "
gameforge.main_quest_lv15._80_say = "Os habitantes do nosso Reino t\234m muita f\233 e rezam[ENTER]todos os dias ao Deus Drag\227o. O benevolente Deus[ENTER]Drag\227o protege-nos da ressurrei\231\227o de Sung Mahi.[ENTER]Com a sua ajuda vamos continuar a defender-nos[ENTER]destes b\225rbaros ataques, e iremos unificar o[ENTER]continente sob o nosso controlo. "
gameforge.main_quest_lv15._90_say = "Vou dar-te uma nova miss\227o. Entrega esta est\225tua[ENTER]de pedra do Deus Drag\227o ao Yu-Hwan, que se[ENTER]encontra na vila vizinha. A religi\227o e a nossa[ENTER]profunda f\233 no Deus Drag\227o s\227o coisas muito[ENTER]importantes para o nosso Reino. Se entregares[ENTER]isto ao Yu-Hwan ir\225s estar a fazer um grande[ENTER]favor aos alde\245es. "
