gameforge.main_quest_lv16._40_say = "Tenho um pressentimento de que existe um espi\227o[ENTER]entre n\243s. Algu\233m da vila est\225 a trabalhar para o[ENTER]Cl\227 Jura de Cristal. Preciso da tua ajuda neste[ENTER]assunto: Vai matar Soldados Jura de Cristal.[ENTER]Talvez sejas capaz de descobrir alguma informa\231\227o[ENTER]sobre o espi\227o. "
