gameforge.main_quest_lv16._75_say = "Encontraste uma carta.[ENTER]Leva-a ao Capit\227o. "
gameforge.main_quest_lv16._80_sayReward = "Encontraste uma Carta nos Soldados Jura de[ENTER]Cristal. Talvez seja a prova que o Capit\227o[ENTER]procura. Leva a Carta ao Capit\227o. "
gameforge.main_quest_lv16._90_say = "Encontraste alguma prova? Uma Carta? Deixa-me dar[ENTER]uma vista de olhos... Poder\225 ser suficiente para[ENTER]descobrir a identidade do espi\227o. Gra\231as a ti[ENTER]devemos ser capaz de resolver este problema.[ENTER]Muito bem! Deverias descansar. E toma isto como[ENTER]s\237mbolo da minha gratid\227o. "
