gameforge.main_quest_lv2._20_say = "Guarda da Cidade:[ENTER]O teu interesse \233 louv\225vel mas tens de obter mais[ENTER]pontos de experi\234ncia. Volta quando tiveres mais[ENTER]n\237vel! "
gameforge.main_quest_lv2._210_say = "\201s melhor do que eu pensava! Mas suponho que[ENTER]qualquer um pudesse ser capaz de o fazer. Ha ha![ENTER]Quando eu estava no teu lugar, as miss\245es eram[ENTER]muito mais dif\237ceis. Mas prepara-te para a[ENTER]pr\243xima.[ENTER]Toma, ganhaste algumas po\231\245es e Yang, com o qual[ENTER]podes melhorar o teu equipamento. Voltarei a[ENTER]chamar-te assim que tiver uma nova miss\227o para[ENTER]ti. "
