gameforge.main_quest_lv2._40_targetVid = "Encontra o Guarda da Cidade "
gameforge.main_quest_lv2._50_sayReward = "Se est\225s a ler esta mensagem, ent\227o atingiste um[ENTER]novo n\237vel! Parab\233ns! Agora vai ter com o Guarda[ENTER]da Cidade para participares na tua primeira[ENTER]sess\227o de treino! "
gameforge.main_quest_lv2._60_say = "Ainda te falta disciplina, embora pelo menos me[ENTER]tenhas mostrado que sabes manejar uma arma! Achas[ENTER]mesmo que est\225s pronto para enfrentar os C\227es[ENTER]Selvagens? Primeiro vou verificar qu\227o h\225bil \233s.[ENTER]Sai da vila e mata 9 C\227es Selvagens. Depois vem[ENTER]ter comigo para receberes a tua recompensa. "
gameforge.main_quest_lv2._70_say = "Os C\227es Selvagens n\227o s\227o muito fortes, por isso[ENTER]n\227o deve ser muito dif\237cil. Se n\227o conseguires[ENTER]completar esta tarefa, n\227o ir\225s sobreviver muito[ENTER]tempo! Vamos l\225! Quanto mais cedo come\231ares, mais[ENTER]cedo ir\225s terminar! "
gameforge.main_quest_lv2._80_sayReward = "De vez em quando os alde\245es ir\227o dar-te miss\245es[ENTER]que te proporcionar\227o Pontos de Experi\234ncia e[ENTER]Yang. Vale a pena procurares pessoas que tenham[ENTER]uma miss\227o para ti! "
