gameforge.main_quest_lv27._105_say = "Destru\237ste uma Metin Negra. Reporta o sucedido ao[ENTER]Capit\227o. "
gameforge.main_quest_lv27._10_makequestbutton = "Destr\243i a Pedra Metin "
gameforge.main_quest_lv27._110_say = "Destru\237ste a Pedra Metin? Obrigado! Por agora a[ENTER]vila est\225 a salvo! Mas j\225 agora, de onde raio[ENTER]apareceram estas pedras? N\227o temos quase nenhuma[ENTER]informa\231\227o sobre elas, apesar de estarem a causar[ENTER]tantos problemas. Ouvi dizer que o Uriel, o[ENTER]S\225bio, estava a investigar as Pedras Metin. Mas[ENTER]n\227o fa\231o ideia do que ele descobriu at\233 agora.[ENTER]Seja como for, fizeste um bom trabalho! "
gameforge.main_quest_lv27._120_sayTitle = "Recompensa: "
gameforge.main_quest_lv27._130_sayReward = "Recebeste 3.300.000 Pontos de Experi\234ncia.[ENTER]Recebeste 270.000 Yang.[ENTER]Recebeste um Manual de Habilidades. "
gameforge.main_quest_lv27._140_sayReward = "Recebeste %s. "
gameforge.main_quest_lv27._20_say = "A destrui\231\227o causada pelas Pedras Metin est\225 a[ENTER]piorar. O Reino est\225 a sofrer. As Pedras Metin[ENTER]precisam de ser destru\237das! Vai ter com o[ENTER]Capit\227o. "
gameforge.main_quest_lv27._30_say = "A destrui\231\227o causada pelas Pedras Metin est\225 a[ENTER]piorar. O Reino est\225 a sofrer. As Pedras Metin[ENTER]precisam de ser destru\237das! Vai ter com o[ENTER]Capit\227o. "
gameforge.main_quest_lv27._40_say = "Ouvi dizer que tens trabalhado arduamente. H\225[ENTER]muita gente a falar do teu bom trabalho. Est\225s a[ENTER]dever-me algo por te ter enviado ao lugar certo.[ENTER]Ha, ha! N\227o te chateies, estava apenas a brincar![ENTER]Tens feito o teu trabalho muito bem.[ENTER][ENTER]Mas existem cada vez mais Pedras Metin a[ENTER]aparecer. \201 um problema s\233rio. "
gameforge.main_quest_lv27._50_say = "Se o n\250mero de Pedras Metin aumentar, as pessoas[ENTER]ir\227o sofrer. Por vezes penso se os Xam\227s n\227o[ENTER]ter\227o raz\227o e se o mal\233fico Deus Sung Mahi n\227o[ENTER]ter\225 sido ressuscitado... Mas primeiro temos de[ENTER]tratar do problema mais urgente. Informa-me[ENTER]quando tiveres destru\237do uma Pedra Metin! "
gameforge.main_quest_lv27._60_sayTitle = "Miss\227o: "
gameforge.main_quest_lv27._70_say = "O tipo de Pedra Metin que tens de destruir[ENTER]chama-se Metin Negra. Encontra-a! "
gameforge.main_quest_lv27._80_say = "Recentemente mais e mais Pedras Metin t\234m sido[ENTER]avistadas. A sua radia\231\227o maligna tem de ser[ENTER]parada! Destr\243i a Metin Negra. "
gameforge.main_quest_lv27._90_say = "Destru\237ste a Metin Negra. Regressa ao Capit\227o. "
