gameforge.main_quest_lv3._100_say = "Ol\225. O Guarda da Cidade enviou-te? Tenho uma[ENTER]miss\227o simples para ti. Esta manh\227 o meu pai[ENTER]deixou aqui um livro importante. Ele precisa[ENTER]muito dele. "
gameforge.main_quest_lv3._10_npcChat = "Completei a primeira tarefa. "
gameforge.main_quest_lv3._110_say = "Podes levar este livro ao meu pai? Eu mesma[ENTER]poderia faz\234-lo, mas n\227o posso deixar a loja sem[ENTER]ningu\233m a tomar conta dela. Se me fizeres este[ENTER]favor irei dar-te uma boa recompensa. Ele vende[ENTER]Armaduras aqui na vila. "
