gameforge.main_quest_lv3._140_sendLetter = "Entrega o livro "
gameforge.main_quest_lv3._150_sayReward = "Devolve o livro que o pai da Negociadora da Loja[ENTER]Geral deixou para tr\225s. Ele \233 o Vendedor de[ENTER]Armaduras da vila. "
gameforge.main_quest_lv3._160_sayTitle = "Vendedor de Armaduras: "
gameforge.main_quest_lv3._170_say = "Tens ar de quem est\225 em alguma miss\227o! Ah, foi a[ENTER]minha filha que te enviou! Obrigado. Eu preciso[ENTER]deste livro para fazer umas armaduras novas. "
gameforge.main_quest_lv3._180_say = "A minha filha deve estar muito ocupada e por isso[ENTER]pediu-te para me trazeres o livro. Deixa c\225 ver,[ENTER]o que \233 que te darei em troca? "
gameforge.main_quest_lv3._190_say = "Como recompensa irei dar-te algum Yang para[ENTER]poderes comprar algum equipamento decente. Dever\225[ENTER]ser suficiente, n\227o? Obrigado. Quando precisar[ENTER]novamente de ajuda irei provavelmente pedir-te[ENTER]outro favor. E quando precisares de uma armadura[ENTER]nova vem ter comigo. A minha loja est\225 sempre[ENTER]aberta. "
gameforge.main_quest_lv3._200_sayReward = "Recebeste 850 Pontos de Experi\234ncia.[ENTER]Recebeste 5.000 Yang.[ENTER]Recebeste 20 Po\231\245es Azuis. "
gameforge.main_quest_lv3._20_say = "Parece que te divertiste com a tua primeira[ENTER]miss\227o.[ENTER]Est\225s pronto para a pr\243xima? Vem ter comigo[ENTER]quando tiveres atingido o pr\243ximo n\237vel. Nessa[ENTER]altura terei outro trabalho para ti. "
gameforge.main_quest_lv3._30_sendLetter = "Not\237cias do Guarda da Cidade "
gameforge.main_quest_lv3._40_sayReward = "P\225ra de ca\231ar e vai falar com o Guarda da Cidade.[ENTER]Ele tem mais exerc\237cios para ti. "
gameforge.main_quest_lv3._50_say = "Estou contente por teres vindo. Provavelmente j\225[ENTER]conheces a Negociadora da Loja Geral, certo? Ela[ENTER]pediu-me ajuda. Podes descobrir o que ela quer?[ENTER]Espero que n\227o seja nada grave. Tenho a certeza[ENTER]que conseguir\225s ajud\225-la. "
gameforge.main_quest_lv3._60_say = "Para tua informa\231\227o: A Loja Geral vende Po\231\245es de[ENTER]regenera\231\227o e outros itens que poder\227o ajudar-te[ENTER]no futuro. Por isso n\227o seria m\225 ideia ca\237res nas[ENTER]boas gra\231as da Negociadora! Agora vai. "
