gameforge.main_quest_lv30._100_say = "H\225 inscri\231\245es no Memorial de Pedra. Rapidamente[ENTER]fazes uma c\243pia. "
gameforge.main_quest_lv30._10_targetVid = "Encontra o Uriel "
gameforge.main_quest_lv30._110_say = "O Uriel tem raz\227o: havia mesmo algumas inscri\231\245es[ENTER]no Memorial de Pedra. N\227o conseguias perceber,[ENTER]mas conseguiste fazer uma c\243pia. Leva as tuas[ENTER]notas ao Uriel. "
gameforge.main_quest_lv30._120_say = "Encontraste o Memorial de Pedra de Hasun? Oh, at\233[ENTER]tens uma c\243pia. Muito bem! \201 uma descoberta[ENTER]hist\243rica \250nica! Vamos ver.[ENTER]Hmm... Parecem mesmo ser informa\231\245es sobre as[ENTER]Pedras Metin. Embora n\227o consiga decifrar tudo o[ENTER]que est\225 escrito. Esta l\237ngua \233 muito antiga. O[ENTER]que podemos fazer agora? "
gameforge.main_quest_lv30._130_say = "Ah, tive uma ideia! Conheces o Vale Seungryong?[ENTER]Nessa zona existe um local misterioso e antigo.[ENTER]Se encontrares algumas inscri\231\245es a\237, talvez eu[ENTER]seja capaz de tirar algumas conclus\245es sobre o[ENTER]que aqui est\225 escrito.[ENTER]Vai ao Vale Seungryong e procura o Memorial de[ENTER]Seul Rong. "
gameforge.main_quest_lv30._140_targetVid = "Memorial de Pedra no Vale Seungryong "
gameforge.main_quest_lv30._150_say = "O Uriel precisa de mais textos antigos para poder[ENTER]tirar conclus\245es de algumas escritas que ele n\227o[ENTER]conhece.[ENTER]Vai ao Vale Seungryong e procura por inscri\231\245es[ENTER]no Memorial de Seul Rong. "
gameforge.main_quest_lv30._160_say = "Encontraste mais inscri\231\245es? Oh! Gra\231as a ti em[ENTER]breve conseguirei descobrir o segredo das Pedras[ENTER]Metin. As minhas investiga\231\245es poder\227o produzir[ENTER]resultados mais r\225pido do que eu pensava.[ENTER]Obrigado, obrigado! Irei avisar-te quando[ENTER]precisar da tua ajuda de novo. E toma, por favor[ENTER]aceita esta recompensa pelo teu esfor\231o. "
gameforge.main_quest_lv30._20_sendLetter = "O segredo das Pedras Metin "
gameforge.main_quest_lv30._30_say = "O Uriel finalmente conseguiu obter algumas[ENTER]informa\231\245es sobre o segredo das Pedras Metin. Vai[ENTER]ter com o Uriel. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "O Capit\227o j\225 te mandou vir ter comigo uma vez.[ENTER]Pareces ser uma pessoa com muito talento. Tenho[ENTER]um favor a pedir-te.[ENTER]J\225 ouviste falar das Pedras Metin, certo? Elas[ENTER]ca\237ram do c\233u. Essas pedras possuem uma energia[ENTER]negra e est\227o a espalhar doen\231as e a tornar os[ENTER]animais loucos. N\227o sabemos como \233 que elas[ENTER]chegaram ao nosso mundo ou de que s\227o feitas.[ENTER]Isto torna a minha investiga\231\227o muito mais[ENTER]dif\237cil. No entanto, recentemente descobri algo[ENTER]que pode ser a chave para descobrir o segredo das[ENTER]Pedras Metin. "
gameforge.main_quest_lv30._60_say = "H\225 um Memorial de um Reino antigo na Caverna dos[ENTER]Macacos F\225ceis. Penso que a informa\231\227o que se[ENTER]encontra inscrita nesse Memorial se refere ao[ENTER]segredo das Pedras Metin. Se me trouxeres essa[ENTER]informa\231\227o, talvez eu seja capaz de descobrir o[ENTER]segredo. Por favor traz-me a informa\231\227o inscrita[ENTER]no Memorial de Hasun que se encontra na Caverna[ENTER]dos Macacos F\225ceis! "
gameforge.main_quest_lv30._70_sayReward = "Recebeste 122.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang.[ENTER]Recebeste uma Pulseira de Prata. "
gameforge.main_quest_lv30._80_targetVid = "Memorial Pedra na Caverna dos Macacos F\225ceis "
gameforge.main_quest_lv30._90_say = "O Uriel pensa que descobriu uma pista que o[ENTER]poder\225 ajudar a entender as Pedras Metin.[ENTER]Vai \224 Caverna dos Macacos F\225ceis e procura o[ENTER]Memorial de Hasun. "
gameforge.main_quest_lv32 = {}
gameforge.main_quest_lv32._100_sayReward = "Dica: Se viajares montado a Cavalo conseguir\225s[ENTER]terminar a miss\227o mais r\225pida e facilmente. "
gameforge.main_quest_lv32._10_sendLetter = "O Di\225rio Secreto "
gameforge.main_quest_lv32._110_npcChat = "As P\225ginas do Di\225rio Secreto "
gameforge.main_quest_lv32._120_sayTitle = "Vendedor Ambulante: "
gameforge.main_quest_lv32._130_say = "Desde que todos estes problemas come\231aram no[ENTER]mundo o com\233rcio ficou dif\237cil. O que queres[ENTER]comprar? Oh, o Uriel mandou-te? Ele \233 um cliente[ENTER]regular. Est\225 sempre \224 procura de livros antigos[ENTER]dos mais diversos lugares do mundo. Chega a ser[ENTER]um pouco aborrecido. Ha, ha, ha. Queres saber[ENTER]mais sobre livros antigos? Hm, livros antigos... "
gameforge.main_quest_lv32._140_say = "Ouvi algo h\225 uns dias, mas n\227o posso passar a[ENTER]informa\231\227o sem receber algo em troca! Se me deres[ENTER]uma m\227o, eu dou-te uma tamb\233m, eh? O com\233rcio de[ENTER]armas tem corrido muito bem ultimamente, mas[ENTER]infelizmente n\227o consigo disponibilizar[ENTER]quantidades t\227o grandes! Tenho estado soterrado[ENTER]de pedidos! E como tu n\227o est\225s a fazer nada,[ENTER]porque n\227o fazes algo \250til e me arranjas 20[ENTER]Espadas de Prata+0? Assim que as trouxeres at\233[ENTER]mim irei dar-te a informa\231\227o que pretendes. "
gameforge.main_quest_lv32._150_targetVid = "Encontra o Vendedor Ambulante "
gameforge.main_quest_lv32._160_sayTitle = "Tens 20 Espadas de Prata+0 "
gameforge.main_quest_lv32._170_say = "O Vendedor Ambulante ouviu falar das P\225ginas[ENTER]Antigas. D\225-lhe 20 Espadas de Prata+0 e ele ir\225[ENTER]contar-te o que sabe. "
gameforge.main_quest_lv32._180_sayTitle = "Recolhe 20 Espadas de Prata+0 "
gameforge.main_quest_lv32._190_say = "O Vendedor Ambulante ouviu algo sobre as P\225ginas[ENTER]Antigas, mas ele n\227o quer partilhar a informa\231\227o[ENTER]sem receber algo em troca.[ENTER]Arranja 20 Espadas de Prata+0 e entrega-as ao[ENTER]Vendedor Ambulante em troca da informa\231\227o. "
gameforge.main_quest_lv32._200_npcChat = "Tenho as Espadas. "
gameforge.main_quest_lv32._20_targetVid = "Procura o Uriel "
gameforge.main_quest_lv32._210_say = "Que bom. Tens mais talento do que eu pensava. Com[ENTER]a tua ajuda o neg\243cio ir\225 melhorar em breve.[ENTER]Agora, em rela\231\227o \224s P\225ginas... H\225 alguns dias eu[ENTER]estava a passar perto de um edif\237cio com um[ENTER]Memorial perto dele. Decidi parar a\237 para[ENTER]descansar e reparei que havia um peda\231o de papel[ENTER]rasgado aos p\233s do Memorial. "
gameforge.main_quest_lv32._220_say = "Na altura n\227o pensei muito nisso. Mas agora que[ENTER]penso melhor, talvez pudesse ser umas das P\225ginas[ENTER]que procuras. O nome do Memorial, hmm... Seria o[ENTER]Memorial Weol? Sim, acho que \233 esse o nome. O[ENTER]Memorial Weol perto da vila vizinha. \201 a\237 que[ENTER]deves procurar. "
gameforge.main_quest_lv32._230_sayTitle = "Vendedor Ambulante: "
gameforge.main_quest_lv32._240_say = "Traz-me 20 Espadas de Prata+0 e partilharei[ENTER]contigo a informa\231\227o sobre as P\225ginas Antigas... "
gameforge.main_quest_lv32._250_sendLetter = "\192 procura da 1\170 P\225gina "
gameforge.main_quest_lv32._260_targetVid = "Um Memorial perto de um edif\237cio "
gameforge.main_quest_lv32._270_say = "O Vendedor Ambulante viu uma P\225gina Antiga ao p\233[ENTER]do Memorial Weol enquanto estava a descansar num[ENTER]edif\237cio que fica perto.[ENTER]Vai ao Memorial Weol, na primeira vila, e v\234 se \233[ENTER]mesmo a P\225gina que procuras. "
gameforge.main_quest_lv32._280_npcChat = "O Memorial Weol "
gameforge.main_quest_lv32._290_say = "Este \233 o Memorial. Ah, aqui est\225! Consegui[ENTER]encontrar a P\225gina! "
gameforge.main_quest_lv32._300_sendLetter = "A 1\170 P\225gina "
gameforge.main_quest_lv32._30_say = "O Uriel est\225 \224 tua procura. Ele precisa dde ajuda[ENTER]nas suas investiga\231\245es acerca de um Livro antigo[ENTER]e secreto. Vai ter com o Uriel e v\234 o que podes[ENTER]fazer por ele. "
gameforge.main_quest_lv32._310_targetVid = "Procura o Uriel "
gameforge.main_quest_lv32._320_sayTitle = "Encontraste a 1\170 P\225gina "
gameforge.main_quest_lv32._330_say = "Seguiste as pistas do Vendedor Ambulante e[ENTER]encontraste a primeira das P\225ginas. Leva-a ao[ENTER]Uriel. "
gameforge.main_quest_lv32._340_say = "Ent\227o, encontraste a P\225gina Antiga? Oh,[ENTER]conseguiste, genial! Vamos l\225 ver o que est\225[ENTER]escrito.[ENTER]Hm... Parece ser um Di\225rio. Ouve. "
gameforge.main_quest_lv32._350_sayTitle = "1\170 P\225gina do Di\225rio: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop, do Reino Taejo, est\225 a expandir o seu[ENTER]territ\243rio atrav\233s de conquistas. Ele quer[ENTER]conquistar todos os reinos atrav\233s da sua for\231a[ENTER]militar. Temos de nos certificar que ele n\227o[ENTER]conquista o nosso. As nossas op\231\245es s\227o[ENTER]limitadas, uma vez que o seu ex\233rcito \233 muito[ENTER]grande e muito forte. \201 por isso que decidimos[ENTER]recorrer \224 magia proibida! "
gameforge.main_quest_lv32._370_sayTitle = "1\170 P\225gina do Di\225rio (cont.): "
gameforge.main_quest_lv32._380_sayReward = "\201 a nossa \250nica op\231\227o de sobreviv\234ncia. N\227o[ENTER]sabemos se teremos sucesso, mas devemos pelo[ENTER]menos tentar. Antes de nos atacarem temos de[ENTER]arranjar informa\231\245es sobre a Magia Negra[ENTER]proibida. De acordo com as lendas, devemos ser[ENTER]capazes de as obter no Vale do Drag\227o. "
gameforge.main_quest_lv32._390_say = "A partir do que aqui est\225 escrito, consigo[ENTER]perceber que existiam muitas cren\231as antigas[ENTER]neste reino. Antes de Lee Seop, do Reino Taejo,[ENTER]ter unido todos os reinos, cada reino tinha as[ENTER]suas pr\243prias caracter\237sticas especiais. Tanto[ENTER]quanto sei, cada reino at\233 teria as suas pr\243prias[ENTER]cren\231as religiosas. O autor deste livro parece[ENTER]ter sido bastante culto. Provavelmente pertencia[ENTER]a uma das guilds ou pode at\233 mesmo ter sido um[ENTER]dos seus capit\227es. Os membros das guilds eram[ENTER]considerados a elite da sociedade. "
gameforge.main_quest_lv32._400_say = "Muita conversa tem corrido sobre as velhas[ENTER]hist\243rias do Vale. Tamb\233m conhe\231o algumas delas.[ENTER]Talvez possamos ainda encontrar mais informa\231\227o[ENTER]sobre esse assunto ou at\233 mesmo mais P\225ginas[ENTER]deste Di\225rio. Infelizmente nunca descobri onde se[ENTER]situa esse vale.[ENTER]Vai ter com o ca\231ador Yang-Shin, na vila vizinha.[ENTER]Ele conhece os cantos do reino melhor que[ENTER]ningu\233m. Talvez ele saiba onde fica o Vale do[ENTER]Drag\227o e se l\225 existe algo \250til. "
gameforge.main_quest_lv32._40_say = "Ol\225.[ENTER]O teu trabalho da \250ltima vez foi muito \250til. Com[ENTER]a tua ajuda consegui fazer alguns progressos. Mas[ENTER]agora tenho um problema.[ENTER]Enquanto procurava informa\231\245es sobre as Pedras[ENTER]Metin encontrei um livro antigo. Tanto quanto[ENTER]percebo, nele existem especula\231\245es importantes[ENTER]sobre a causa das mudan\231as que est\227o a afectar o[ENTER]nosso reino. \201 muito importante. "
gameforge.main_quest_lv32._410_say = "Que excitante! Oh, antes que me esque\231a: Aqui[ENTER]tens a tua recompensa pela 1\170 P\225gina! "
gameforge.main_quest_lv32._420_sayReward = "Recebeste 1.000.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv32._430_sayReward = "Recebeste 50.000 Yang. "
gameforge.main_quest_lv32._440_sayReward = "Recebeste uma L\225grima de Deusa. "
gameforge.main_quest_lv32._450_sendLetter = "Dirige-te ao Yang-Shin "
gameforge.main_quest_lv32._460_targetVid = "Encontra o ca\231ador Yang-Shin "
gameforge.main_quest_lv32._470_sayTitle = "Pergunta ao Yang-Shin sobre o Vale do Drag\227o. "
gameforge.main_quest_lv32._480_say = "Na 1\170 P\225gina do Di\225rio Secreto fala-se num Vale[ENTER]do Drag\227o. O Uriel j\225 ouviu algumas hist\243rias[ENTER]sobre ele, mas n\227o sabe a sua localiza\231\227o. Vai \224[ENTER]vila vizinha e pergunta ao ca\231ador Yang-Shin se[ENTER]sabe mais alguma coisa sobre o Vale. "
gameforge.main_quest_lv32._490_sayReward = "Dica: O ca\231ador encontra-se na vila vizinha. "
gameforge.main_quest_lv32._500_npcChat = "Informa\231\245es sobre o Vale Seungryong "
gameforge.main_quest_lv32._50_say = "O problema \233 que o Livro \233 muito velho e rasgado.[ENTER]Foi passado de m\227o em m\227o durante anos, raz\227o[ENTER]pela qual est\225 t\227o danificado. Faltam-lhe 13[ENTER]P\225ginas. Podes ajudar-me a encontr\225-las? Elas[ENTER]provavelmente cont\234m informa\231\245es sobre como[ENTER]colocar um ponto final na guerra. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Queres saber onde fica o Vale do Drag\227o? Esse \233[ENTER]um nome muito antigo do actual Vale Seungryong.[ENTER]N\227o h\225 l\225 drag\245es, mas h\225 uma grande quantidade[ENTER]de orcs e at\233 uma seita secreta. Porque queres ir[ENTER]a um lugar t\227o perigoso? Nem mesmo eu, um[ENTER]inteligente ca\231ador, gosto de l\225 ir. Seria melhor[ENTER]se te mantivesses afastado desse lugar. "
gameforge.main_quest_lv32._530_say = "O qu\234? Est\225s \224 procura das P\225ginas Antigas? Hm![ENTER]Uma vez ouvi dizer de outros ca\231adores que os[ENTER]Orcs Magos tinham alguns pap\233is. Ser\225 que \233[ENTER]verdade? Se est\225s t\227o curioso ent\227o vai descobrir[ENTER]por ti mesmo. J\225 te disse que \233 um lugar[ENTER]perigoso. Toma conta de ti! "
gameforge.main_quest_lv32._540_sendLetter = "\192 procura da 2\170 P\225gina "
gameforge.main_quest_lv32._550_say = "Como o ca\231ador j\225 mencionou, dever\225s encontrar[ENTER]Orcs Magos Elite no Vale Seungryong. Eles dever\227o[ENTER]estar na posse da 2\170 P\225gina. Mata Orcs Magos[ENTER]Elite e obt\233m-na. Assim que tiveres apanhado a 2\170[ENTER]P\225gina entrega-a ao Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "A 2\170 P\225gina "
gameforge.main_quest_lv32._570_sayTitle = "Encontraste a 2\170 P\225gina "
gameforge.main_quest_lv32._580_say = "Ca\231ar os Orcs Magos Elite foi um sucesso:[ENTER]encontraste a 2\170 P\225gina do Di\225rio Secreto. Leva-a[ENTER]ao Uriel. "
gameforge.main_quest_lv32._590_say = "Essa \233 a 2\170 P\225gina? Deixa ver. N\227o \233 muito f\225cil[ENTER]de decifrar. Ela diz:  "
gameforge.main_quest_lv32._600_sayTitle = "2\170 P\225gina: "
gameforge.main_quest_lv32._60_say = "Assim que encontrares uma dessas P\225ginas tr\225-la[ENTER]at\233 mim para que eu possa tentar decifr\225-la.[ENTER]Hmm... Onde podes come\231ar a procurar? H\225 algum[ENTER]tempo, um Vendedor Ambulante da vila vizinha[ENTER]contou-me que encontrou uma p\225gina de um livro[ENTER]antigo. Vai ter com ele e v\234 o que consegues[ENTER]descobrir. "
gameforge.main_quest_lv32._610_sayReward = "Os seguidores da magia negra foram encontrados.[ENTER]Eles estavam escondidos no Vale do Drag\227o. Est\227o[ENTER]muito bem informados sobre a Magia Negra.[ENTER]Demor\225mos bastante a convenc\234-los a ajudar-nos,[ENTER]mesmo com algumas amea\231as e adula\231\245es. E o[ENTER]resultado foi: \201 necess\225rio um local especial[ENTER]para praticar a Magia Negra proibida. O local tem[ENTER]de estar repleto de energia negativa. O tempo[ENTER]est\225 a esgotar-se, por isso tenho de encontrar um[ENTER]local adequado o mais r\225pido poss\237vel. "
gameforge.main_quest_lv32._620_say = "Hum, precisamos de um local repleto de energia[ENTER]negativa para podermos utilizar a Magia Negra. um[ENTER]local onde tudo possa ser convertido em Energia[ENTER]Negra. Hmm... Onde podemos encontrar um lugar[ENTER]assim? Hm... Hm... J\225 sei, pode ser o Templo[ENTER]Hwang! Muitas pessoas n\227o lhe chamam o Templo da[ENTER]escurid\227o sem raz\227o. \201 um local onde ningu\233m com[ENTER]cora\231\227o puro se atreve a ir. Nem mesmo os animais[ENTER]l\225 entram. E a seita secreta junta-se no seu[ENTER]interior. "
gameforge.main_quest_lv32._630_say = "Al\233m disso, existe uma liga\231\227o entre a Magia[ENTER]Negra proibida e esta seita secreta. Podes[ENTER]encontrar a chave disso tudo no Templo Hwang.[ENTER]Descobre o que se passa no Templo e v\234 se[ENTER]consegues encontrar mais P\225ginas![ENTER]Aqui tens a tua recompensa pela 2\170 P\225gina... "
gameforge.main_quest_lv32._640_sayReward = "Recebeste 1.000.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv32._650_sayReward = "Recebeste 50.000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Recebeste 10 Bandeiras Brancas. "
gameforge.main_quest_lv32._670_sendLetter = "A 3\170 P\225gina "
gameforge.main_quest_lv32._680_say = "J\225 entregaste as duas primeiras P\225ginas do Di\225rio[ENTER]Secreto ao Uriel. A pr\243xima p\225gina poder\225 ser[ENTER]encontrada no Templo Hwang. "
gameforge.main_quest_lv32._690_sayReward = "Dica: Esta s\233rie de miss\245es continua quando[ENTER]tiveres atingido o n\237vel 40. "
