gameforge.main_quest_lv40._150_targetVid = "A busca pelo Memorial Wha "
gameforge.main_quest_lv40._160_sayTitle = "A busca pela 4\170 P\225gina "
gameforge.main_quest_lv40._170_say = "O Uriel acha que \233 poss\237vel encontrar outra[ENTER]P\225gina na Caverna dos Macacos Normais no Deserto[ENTER]Yongbi. Nesse local h\225 dois Memoriais. Talvez a[ENTER]P\225gina esteja escondida num deles.[ENTER]Vai para o Deserto Yongbi e procura os Memoriais[ENTER]no interior da Caverna dos Macacos Normais. "
gameforge.main_quest_lv40._180_say = "Este \233 o Memorial Wha! "
