gameforge.main_quest_lv40._200_npcChat = "A busca pelo Memorial Su "
gameforge.main_quest_lv40._20_say = "O Uriel anda \224 procura das P\225ginas Antigas. J\225[ENTER]lhe entregaste duas. Agora a excitante ca\231a pelo[ENTER]segredo do Di\225rio Secreto continua.[ENTER]As descobertas feitas at\233 agora indicam que os[ENTER]Fan\225ticos Negros Elite, que vivem no Templo[ENTER]Hwang, est\227o na posse da pr\243xima P\225gina.[ENTER]P\245e-te a caminho! "
gameforge.main_quest_lv40._210_say = "Deve ser isto! O Memorial Su. "
