gameforge.main_quest_lv40._250_say = "Os Memoriais Antigos provaram ser fi\233is guardi\245es[ENTER]dos seus tesouros: encontraste a 4\170 P\225gina na[ENTER]Caverna dos Macacos Normais. Leva-a ao Uriel. "
gameforge.main_quest_lv40._260_npcChat = "A 4\170 P\225gina do Di\225rio "
gameforge.main_quest_lv40._270_say = "Oh! Encontraste a 4\170 P\225gina. Pode ser que[ENTER]consigamos descobrir algo novo com a informa\231\227o[ENTER]presente nela. "
gameforge.main_quest_lv40._280_sayTitle = "4\170 P\225gina: "
gameforge.main_quest_lv40._290_sayReward = "Agora estou na profunda caverna onde os macacos[ENTER]vivem. Os meus companheiros est\227o petrificados,[ENTER]mas a energia negra que aqui reunimos ainda \233[ENTER]insuficiente. O tempo passa a correr e a[ENTER]cavalaria de Lee Seop est\225 cada vez mais perto.[ENTER]Ser\225 que nos vamos safar desta vez? "
gameforge.main_quest_lv40._300_sayTitle = "4\170 P\225gina (cont.): "
gameforge.main_quest_lv40._30_sayTitle = "Encontraste a 3\170 P\225gina "
gameforge.main_quest_lv40._310_sayReward = "Preciso de encontrar o pr\243ximo local o mais[ENTER]r\225pido poss\237vel. Ainda nada est\225 perdido. Vou[ENTER]tentar a Caverna das Aranhas. Desta vez o nosso[ENTER]desejo at\233 poder\225 tornar-se realidade... "
gameforge.main_quest_lv40._320_say = "Hm. A Caverna dos Macacos Normais n\227o \233 o local[ENTER]que procuramos. Vamos tentar de novo! De acordo[ENTER]com o que est\225 escrito, temos de ir \224 Caverna das[ENTER]Aranhas. Mas primeiro temos de tratar de um[ENTER]assunto mais urgente: O Capit\227o est\225 muito[ENTER]preocupado porque t\234m sido vistos muitos[ENTER]estranhos a fazer perguntas pela vila. Devias ir[ENTER]ter com ele e ver o que se passa. "
gameforge.main_quest_lv40._330_say = "Esta situa\231\227o est\225 a deixar-me inquieto. Vamos[ENTER]ver o que o Capit\227o diz. Oh, antes que me[ENTER]esque\231a: Aqui tens a tua recompensa pela 4\170[ENTER]P\225gina. "
gameforge.main_quest_lv40._340_sayReward = "Recebeste 2.000.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv40._350_sayReward = "Recebeste uma B\234n\231\227o da Magia. "
gameforge.main_quest_lv40._360_sendLetter = "Os estranhos misteriosos "
gameforge.main_quest_lv40._370_targetVid = "Dirige-te ao Capit\227o "
gameforge.main_quest_lv40._380_sayTitle = "Pergunta ao Capit\227o sobre os estranhos "
gameforge.main_quest_lv40._390_say = "Correm por a\237 rumores de que t\234m aparecido[ENTER]pessoas estranhas pela vila. T\234m andado a fazer[ENTER]perguntas sobre os Memoriais. O Capit\227o quer[ENTER]fazer algo acerca disso. Vai ter com ele para[ENTER]descobrires mais. "
gameforge.main_quest_lv40._400_npcChat = "Os estranhos na vila "
gameforge.main_quest_lv40._40_say = "As suspeitas do Uriel sobre os Fan\225ticos Negros[ENTER]Elite estavam correctas. Encontraste a 3\170 P\225gina[ENTER]na sua posse. Leva a P\225gina ao Uriel. "
gameforge.main_quest_lv40._410_say = "Tem havido um aumento do n\250mero de pessoas[ENTER]estranhas a entrar na vila. Essas pessoas passam[ENTER]a vida a fazer perguntas sobre Memoriais e Livros[ENTER]Antigos. Alguns alde\245es t\234m conhecimento desses[ENTER]assuntos, mas n\227o querem partilh\225-lo com os[ENTER]estranhos. Tenho medo que esta situa\231\227o nos venha[ENTER]a colocar em problemas. Ningu\233m sabe quem enviou[ENTER]estes estranhos e qu\227o longe est\227o dispostos a ir[ENTER]para obter as informa\231\245es que pretendem. Afinal[ENTER]de contas estamos numa guerra. "
gameforge.main_quest_lv40._420_say = "Se as minhas fontes estiverem certas, o Nakajima[ENTER]da vila vizinha poder\225 ter algo a ver com o[ENTER]assunto.[ENTER]Por favor tenta descobrir o que \233 que os[ENTER]estranhos querem de n\243s. "
gameforge.main_quest_lv40._430_sendLetter = "Vai ter com o Nakajima "
gameforge.main_quest_lv40._440_say = "O Capit\227o acha que h\225 uma liga\231\227o entre o[ENTER]Nakajima e os estranhos que andam pela vila a[ENTER]fazer perguntas sobre os Memoriais. Vai ter com o[ENTER]Nakajima e descobre o que \233 que ele sabe. Poder\225s[ENTER]encontr\225-lo nas redondezas da segunda vila. "
gameforge.main_quest_lv40._450_npcChat = "Sabes algo sobre os estranhos na vila? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Desculpa? Que raio de pergunta \233 essa? Lamento.[ENTER]N\227o te posso ajudar. N\227o fa\231o a m\237nima ideia do[ENTER]que est\225s a falar. N\227o, n\227o. J\225 \233 suficientemente[ENTER]dif\237cil encontrar trabalho tal como as coisas[ENTER]est\227o. Como \233 que \233 suposto eu sustentar-me,[ENTER]hein? "
gameforge.main_quest_lv40._480_say = "Oh bom, eu admito. Mas apenas concordei porque me[ENTER]prometeram muito Yang. N\227o sei o que os estranhos[ENTER]querem daqui. Mas eles deram-me uma miss\227o: \201[ENTER]suposto eu matar os Capit\227es Veneno. "
gameforge.main_quest_lv40._490_say = "Provavelmente poder\225s descobrir mais dos Capit\227es[ENTER]Veneno. Os estranhos queriam mesmo que eu os[ENTER]matasse. Oh, tive uma ideia: Porque n\227o os matas[ENTER]por mim? Por favor? "
gameforge.main_quest_lv40._500_sendLetter = "Mata Capit\227es Veneno "
gameforge.main_quest_lv40._50_say = "Oh, encontraste a pr\243xima pista?! Esta \233 a 3\170[ENTER]P\225gina. Vamos ver o que diz. "
gameforge.main_quest_lv40._510_say = "O Nakajima confessou que os estranhos querem[ENTER]matar os Capit\227es Veneno. Como os estranhos t\234m[ENTER]andado a pedir informa\231\245es sobre as P\225ginas do[ENTER]Di\225rio, \233 \243bvio que um dos Capit\227es Veneno est\225[ENTER]na posse de uma delas. Para descobrir mais[ENTER]preciso de matar Capit\227es Veneno. Eles podem ser[ENTER]encontrados nas redondezas da segunda vila. "
gameforge.main_quest_lv40._520_sendLetter = "Encontraste a 5\170 P\225gina "
gameforge.main_quest_lv40._530_say = "Cheguei l\225 antes dos estranhos e consegui obter a[ENTER]5\170 P\225gina dos Capit\227es Veneno. Estou certo de que[ENTER]os estranhos ir\227o desaparecer, agora que n\227o h\225[ENTER]nada aqui para eles encontrarem. \201 melhor levar[ENTER]esta P\225gina ao Uriel para que ele a possa[ENTER]decifrar. "
gameforge.main_quest_lv40._540_sayTitle = "A 5\170 P\225gina "
gameforge.main_quest_lv40._550_sayReward = "Dica: Apenas poder\225s entregar a 5\170 p\225gina ao[ENTER]Uriel quando chegares a n\237vel 47. At\233 l\225 guarda a[ENTER]p\225gina com cuidado! "
gameforge.main_quest_lv40._60_sayTitle = "3\170 P\225gina: "
gameforge.main_quest_lv40._70_sayReward = "Descobrimos um local que \233 governado por energia[ENTER]negra. Mas parece n\227o ser suficiente. O local \233[ENTER]mal\233fico, mas n\227o \233 apropriado para a pr\225tica da[ENTER]magia, o que \233 desanimador. Mas os nossos espi\245es[ENTER]falam de um s\237tio escondido algures no Deserto[ENTER]que parece ser promissor. Estamos muito[ENTER]optimistas e vamos para l\225 agora. "
gameforge.main_quest_lv40._80_say = "Ent\227o eles foram incapazes de atingir o seu[ENTER]objectivo no Vale do Drag\227o. Hm... O Deserto[ENTER]Yongbi? \201 uma zona bastante inexplorada e n\227o[ENTER]encontras por l\225 muita gente. Mas tudo isto \233[ENTER]muito complicado. Qual era exactamente a \225rea que[ENTER]eles mencionavam? Presumo que eles se referissem[ENTER]\224 Caverna dos Macacos Normais. \201 uma caverna[ENTER]profunda que est\225 muito bem concebida para a[ENTER]recolha de energia negra. "
gameforge.main_quest_lv40._90_say = "Por favor vai \224 Caverna dos Macacos Normais e[ENTER]procura mais Memoriais de Pedra. Com um pouco de[ENTER]sorte poder\225s encontrar mais P\225ginas perto dos[ENTER]Memoriais.[ENTER]Oh, e \233 claro que n\227o nos devemos esquecer da tua[ENTER]recompensa pela 3\170 P\225gina. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "A P\225gina na Caverna das Aranhas "
gameforge.main_quest_lv47._10_sayTitle = "A P\225gina dos Capit\227es Veneno "
gameforge.main_quest_lv47._110_say = "O Uriel pensa que ser\225 poss\237vel encontrar mais[ENTER]informa\231\245es sobre a Magia Negra na Caverna das[ENTER]Aranhas. Talvez possamos encontrar l\225 um[ENTER]monumento como o da Caverna dos Macacos Normais.[ENTER][ENTER]Podes chegar \224 Caverna das Aranhas atrav\233s do[ENTER]Deserto Yongbi. "
gameforge.main_quest_lv47._120_npcChat = "O Memorial Mok "
gameforge.main_quest_lv47._130_say = "Excelente! Aqui est\225 um Memorial e tamb\233m uma[ENTER]P\225gina do Di\225rio. Regressa rapidamente ao Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Encontraste a 6\170 P\225gina "
gameforge.main_quest_lv47._150_say = "Encontraste outro Memorial Antigo na Caverna das[ENTER]Aranhas e, junto dele, a 6\170 P\225gina do Di\225rio.[ENTER]Entrega-a ao Uriel. "
gameforge.main_quest_lv47._160_npcChat = "A 6\170 P\225gina "
gameforge.main_quest_lv47._170_say = "Como estava a Caverna das Aranhas? Encontraste a[ENTER]6\170 P\225gina? Isso \233 fant\225stico! Estava preocupado[ENTER]com poderes chegar l\225 demasiado tarde. N\227o seria[ENTER]a primeira vez que se ouviria falar de outras[ENTER]pessoas \224 procura dos segredos da Magia Negra.[ENTER]Parecem ser informa\231\245es muito importantes. Vamos[ENTER]ver o que esta P\225gina diz. "
gameforge.main_quest_lv47._180_say = "Oh n\227o, esta P\225gina \233 muito dif\237cil de ler. Irei[ENTER]precisar de mais tempo do que \233 normal para a[ENTER]decifrar. Mas o seu conte\250do parece ser muito[ENTER]importante. Este s\237mbolo aqui significa \"Magia[ENTER]Negra\", por isso estamos no caminho certo.[ENTER]Gostava de descobrir porque \233 que a Magia Negra[ENTER]foi banida. Deve haver uma boa raz\227o para isso. "
gameforge.main_quest_lv47._190_say = "Enquanto tento decifrar esta p\225gina devias ir ter[ENTER]com o Yu-Hwan. Ouvi dizer que ele tem algumas[ENTER]informa\231\245es interessantes para a nossa[ENTER]investiga\231\227o. Quando regressares j\225 deverei ser[ENTER]capaz de te dizer o que est\225 escrito nesta[ENTER]P\225gina. \201 claro que ir\225s receber a tua recompensa[ENTER]j\225. "
gameforge.main_quest_lv47._200_sayReward = "Recebeste 3.000.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv47._20_say = "A n\237vel 40 conseguiste obter a 5\170 P\225gina do[ENTER]Di\225rio dos Capit\227es Veneno. Agora leva-a ao[ENTER]Uriel. "
gameforge.main_quest_lv47._210_sayReward = "Recebeste 75.000 Yang. "
gameforge.main_quest_lv47._220_sayReward = "Recebeste uma B\234n\231\227o do Drag\227o. "
gameforge.main_quest_lv47._230_sendLetter = "Vai ter com o Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "Encontra o Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "As for\231as secretas "
gameforge.main_quest_lv47._260_say = "O yu-Hwan pode ter alguma informa\231\227o sobre as[ENTER]P\225ginas Antigas. Vai ter com ele e pergunta-lhe[ENTER]se sabe algo. "
gameforge.main_quest_lv47._270_npcChat = "Alguma novidade? "
gameforge.main_quest_lv47._280_say = "Aproveita a vida, porque \233 curta![ENTER]Tralalalala... Ah, aqui est\225s tu de novo.[ENTER]Provavelmente vens da parte do Uriel. Ele[ENTER]pediu-me para andar por a\237 a fazer algumas[ENTER]perguntas. Descobri que as pessoas em todos os[ENTER]Reinos t\234m andado \224 procura de documentos[ENTER]importantes. Infelizmente ningu\233m me p\244de dizer[ENTER]exactamente que documentos procuram. "
gameforge.main_quest_lv47._290_say = "\201 um pouco estranho que estas pessoas misteriosas[ENTER]andem por a\237 enquanto estamos a meio de uma[ENTER]guerra. Sem contar contigo, \233 claro! Tamb\233m ouvi[ENTER]dizer que os Bandidos do Deserto conseguiram[ENTER]roubar algumas coisas que podem ser importantes[ENTER]para n\243s. Talvez devesses experimentar ver o que[ENTER]consegues arrancar deles. "
gameforge.main_quest_lv47._300_say = "Os Bandidos do deserto s\227o criaturas bastante[ENTER]perigosas, por isso tem cuidado. Mas acho que vai[ENTER]valer a pena. Vou dedicar-te uma can\231\227o e deixar[ENTER]que o vento a leve contigo para o Deserto. "
gameforge.main_quest_lv47._30_npcChat = "A 5\170 P\225gina "
gameforge.main_quest_lv47._310_sendLetter = "Os Bandidos do Deserto "
gameforge.main_quest_lv47._320_sayTitle = "\192 busca pela informa\231\227o secreta "
gameforge.main_quest_lv47._330_say = "O Uriel precisa de toda a informa\231\227o sobre a[ENTER]Magia Negra que conseguir. Yu-Hwan, o m\250sico,[ENTER]disse que os Bandidos do Deserto roubaram algo[ENTER]que poder\225 ajudar-nos. Devia ir at\233 ao Deserto e[ENTER]matar alguns Bandidos do Deserto. "
gameforge.main_quest_lv47._340_sendLetter = "Encontraste a 7\170 P\225gina "
gameforge.main_quest_lv47._350_targetVid = "\192 procura do Yu-Hwan "
gameforge.main_quest_lv47._360_say = "Gra\231as \224s informa\231\245es que o Yu-Hwan te deu, foste[ENTER]capaz de obter dos Bandidos do Deserto a 7\170[ENTER]P\225gina do Di\225rio. Vai ter com o Yu-Hwan e[ENTER]conta-lhe que a sua informa\231\227o estava correcta. "
gameforge.main_quest_lv47._370_say = "Os teus olhos s\227o t\227o belos quanto o lago de uma[ENTER]montanha lalalala... Hey, aqui est\225s tu de novo.[ENTER]Tiveste sorte com os Bandidos do Deserto? O qu\234,[ENTER]isso \233 tudo? Um peda\231o de papel velho? Isso n\227o[ENTER]me serve de nada. Mas se te faz feliz... Leva-o[ENTER]ao Uriel. E manda-lhe os meus cumprimentos! "
gameforge.main_quest_lv47._380_sendLetter = "Dirige-te ao Uriel. "
gameforge.main_quest_lv47._390_targetVid = "Dirige-te ao Uriel. "
gameforge.main_quest_lv47._400_sayTitle = "A 7\170 P\225gina "
gameforge.main_quest_lv47._40_say = "Conseguiste a 5\170 P\225gina? Inacredit\225vel. Temos[ENTER]muita sorte em estas P\225ginas ainda existirem[ENTER]depois de tantos anos. \201s muito proficiente.[ENTER]Agora vamos ver o que esta P\225gina diz. "
gameforge.main_quest_lv47._410_say = "Encontraste a 7\170 P\225gina do Di\225rio Secreto. Leva-a[ENTER]ao Uriel. "
gameforge.main_quest_lv47._420_say = "Ol\225, \233 bom ver-te de novo! Tenho boas not\237cias:[ENTER]Acabei de decifrar a 6\170 P\225gina. Nada mau, hein?[ENTER]Tenho de admitir que estou muito orgulhoso de mim[ENTER]mesmo. Porque aquilo que realmente me chamou a[ENTER]aten\231\227o foi este car\225cter... Desculpa?[ENTER]Encontraste outra? Meu Deus! Isso \233 que foi[ENTER]rapidez. Mostra-me.[ENTER]Wow, onde encontraste esta? Se n\227o estou em erro,[ENTER]estes s\227o os caracteres que eram usados pela[ENTER]Fam\237lia Real. "
gameforge.main_quest_lv47._430_say = "Uma vez que estes caracteres eram raramente[ENTER]usados e apenas eram conhecidos por um punhado de[ENTER]gente, \233 muito dif\237cil traduzi-los. Mas um[ENTER]pequeno desafio nunca fez mal a ningu\233m. Os[ENTER]Bandidos do Deserto roubaram esta P\225gina dos[ENTER]misteriosos estranhos? Hmm... Ser\225 que os[ENTER]estranhos compreendem estes caracteres? Isto est\225[ENTER]a ficar muito confuso. Temos de nos certificar[ENTER]que n\227o falhamos nenhum pormenor. "
gameforge.main_quest_lv47._440_say = "Ah sim, estou a adiantar-me: Antes de me[ENTER]concentrar na pr\243xima P\225gina, provavelmente \233[ENTER]melhor contar-te o que estava na 6\170 P\225gina.[ENTER]Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "6\170 P\225gina: "
gameforge.main_quest_lv47._460_sayReward = "O tempo est\225 a esgotar-se. Tent\225mos usar a Magia[ENTER]Negra na Caverna das Aranhas, mas mesmo assim n\227o[ENTER]funcionou. O que nos estar\225 a escapar? Alguns dos[ENTER]nossos m\237sticos acham que a Magia Negra precisa[ENTER]de grandes sacrif\237cios. Se isso for verdade ent\227o[ENTER]o seu poder deve ser imenso. "
gameforge.main_quest_lv47._470_sayReward = "De acordo com as hist\243rias e lendas, este tipo de[ENTER]magia exigia sempre sacrif\237cio humano. Mas se eu[ENTER]matar os seus entes-queridos no altar, a minha[ENTER]reputa\231\227o entre as pessoas do Reino ir\225[ENTER]desaparecer. Precisamos de um substituto[ENTER]adequado. Vamos experimentar com as Serpentes[ENTER]Guerreiro do Deserto. "
gameforge.main_quest_lv47._480_say = "Aha. Ent\227o, como eles n\227o podiam sacrificar[ENTER]humanos, decidiram usar Serpentes Guerreiro. N\227o[ENTER]posso dizer que goste deste desenvolvimento. Isto[ENTER]vai acabar mal... No entanto precisamos de[ENTER]continuar a seguir as pisadas deles. Vai at\233 ao[ENTER]Deserto e mata algumas Serpentes Guerreiro e[ENTER]Serpentes Arqueiro. Quem sabe o que mais[ENTER]poderemos encontrar. J\225 agora: aqui tens a tua[ENTER]recompensa! "
gameforge.main_quest_lv47._490_sendLetter = "Mata Serpentes Guerreiro "
gameforge.main_quest_lv47._500_sayTitle = "A 8\170 P\225gina "
gameforge.main_quest_lv47._50_sayTitle = "5\170 P\225gina: "
gameforge.main_quest_lv47._510_say = "O Di\225rio descreve a tentativa de sacrificar[ENTER]Serpentes Guerreiro e Serpentes Arqueiro para[ENTER]conseguir conjurar a Magia Negra. Vai ao Deserto[ENTER]Yongbi e mata Serpentes Guerreiro e Serpentes[ENTER]Arqueiro. Procura mais informa\231\245es. "
gameforge.main_quest_lv47._520_sendLetter = "Encontraste a 8\170 P\225gina "
gameforge.main_quest_lv47._530_targetVid = "Vai ter com o Uriel "
gameforge.main_quest_lv47._540_say = "Encontraste a 8\170 P\225gina do Di\225rio nas Serpentes[ENTER]do Deserto. Leva-a ao Uriel. "
gameforge.main_quest_lv47._550_say = "Essa \233 a 8\170 P\225gina. Muito bem. Uma vez que \233[ENTER]bastante curta penso que conseguirei l\234-la sem[ENTER]esfor\231o. Um momento por favor... Ah, sim. "
gameforge.main_quest_lv47._560_sayTitle = "8\170 P\225gina: "
gameforge.main_quest_lv47._570_sayReward = "As v\237timas necess\225rias foram encontradas. Estamos[ENTER]com sorte. Penso para mim se isso n\227o ser\225 um[ENTER]sinal? Precisamos de um sino de cerim\243nia. Se bem[ENTER]me lembro, as Aranhas tinham algo assim. Vamos[ENTER]para l\225 agora. "
gameforge.main_quest_lv47._580_say = "Ah, a Caverna das Aranhas de novo, que estranho.[ENTER]Tens de ir at\233 l\225 e procurar o sino. Ser\225 uma[ENTER]viagem cansativa, por isso descansa um pouco e[ENTER]volta mais tarde. Irei pensar um pouco e traduzir[ENTER]mais algumas passagens. Quando regressares irei[ENTER]dar-te uma nova miss\227o.[ENTER]E n\227o te preocupes, \233 claro que ir\225s receber a[ENTER]tua recompensa pela 8\170 P\225gina agora. "
gameforge.main_quest_lv47._590_sayReward = "Pontos de Experi\234ncia: 3.000.000[ENTER]Yang: 70.000[ENTER]Capas da Bravura: 20[ENTER]Nota: Para a pr\243xima miss\227o precisas de ser pelo[ENTER]menos n\237vel 50. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop chegou ao Reino Taejo com a sua[ENTER]cavalaria, mas parece querer ficar por l\225 um[ENTER]pouco. Entretanto, pequenos e grandes meteoritos[ENTER]est\227o a cair por todo o Reino. Est\227o a causar[ENTER]caos, destrui\231\227o e conflitos. O vasto Reino foi[ENTER]dividido em tr\234s Reinos mais pequenos. Eles[ENTER]tamb\233m combatem entre si, em vez de se juntarem[ENTER]para combater o mal. O Deus Drag\227o j\225 n\227o fala[ENTER]connosco. \192s vezes ele apoia-nos e outras vezes[ENTER]ele apoia os nossos inimigos. Todos lutam com a[ENTER]sua b\234n\231\227o, e entretanto o desastre fica cada vez[ENTER]pior... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Uma testemunha ocular dos primeiros dias desta[ENTER]era. Isto \233 inestim\225vel! Oh sim, pagamento. Aqui[ENTER]tens uma recompensa pelo teu trabalho excelente.[ENTER]E mais uma coisa: Algu\233m anda obviamente a fazer[ENTER]as mesmas investiga\231\245es que n\243s. Por isso n\227o[ENTER]temos tempo a perder. No fundo da P\225gina diz que[ENTER]o Lee Seop andou em busca da energia negra na[ENTER]Caverna das Aranhas. Se encontrares algo por l\225[ENTER]vem ter comigo imediatamente.[ENTER]Mal posso esperar! "
gameforge.main_quest_lv47._90_sendLetter = "A 6\170 P\225gina "
