gameforge.main_quest_lv50._120_sayReward = "Recebeste 125.000 Yang. "
gameforge.main_quest_lv50._130_sayReward = "Recebeste um S\237mbolo do Rei S\225bio "
gameforge.main_quest_lv50._140_sendLetter = "Pista na Terra do Gelo "
gameforge.main_quest_lv50._150_targetVid = "A Caixa velha com pap\233is "
gameforge.main_quest_lv50._160_sayTitle = "\192 procura da Caixa velha com pap\233is "
gameforge.main_quest_lv50._170_say = "Os ex\233rcitos inimigos finalmente encontraram-se[ENTER]na Montanha Sohan. Procura mais P\225ginas do Di\225rio[ENTER]ou qualquer outro registo escrito referente ao[ENTER]combate. "
gameforge.main_quest_lv50._180_npcChat = "Uma Caixa Velha com Pap\233is! "
gameforge.main_quest_lv50._190_say = "Isto s\227o notas e planos militares.[ENTER]E aqui est\225 outra P\225gina do Di\225rio! \201 melhor[ENTER]lev\225-la ao Uriel. "
gameforge.main_quest_lv50._200_sendLetter = "A 10\170 P\225gina "
gameforge.main_quest_lv50._20_say = "A nossa investiga\231\227o anterior indica que existem[ENTER]pistas na Caverna das Aranhas. Mata Aranhas[ENTER]Coronel Elite. Se encontrares outra P\225gina leva-a[ENTER]ao Uriel. "
gameforge.main_quest_lv50._210_sayTitle = "Encontraste a 10\170 P\225gina "
gameforge.main_quest_lv50._220_say = "Encontraste a 10\170 P\225gina do Di\225rio Secreto na[ENTER]Terra do Gelo. Estava numa Caixa Velha com[ENTER]Pap\233is.[ENTER]Leva-a ao Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, encontraste a 10\170 P\225gina! \211ptimo, estamos[ENTER]cada vez mais perto do fim da hist\243ria. Ainda bem[ENTER]que eles documentaram tudo, caso contr\225rio todo[ENTER]este conhecimento estaria perdido.[ENTER]Vamos ver o que esta p\225gina nos diz. "
gameforge.main_quest_lv50._235_sayTitle = "10\170 P\225gina: "
gameforge.main_quest_lv50._240_sayReward = "Conseguimos defender-nos do primeiro ataque. Mas[ENTER]o pr\243ximo est\225 para breve. O terreno ir\225[ENTER]prejudicar os pesados soldados de Lee Seop,[ENTER]dando-nos alguma vantagem. Mas eles s\227o[ENTER]demasiados. N\227o conseguimos vencer. Temos apenas[ENTER]um \250ltimo recurso: terminar a nossa investiga\231\227o[ENTER]da Magia Negra. Durante a noite deveremos[ENTER]conseguir esgueirar-nos pelas linhas inimigas e[ENTER]voltar \224 Caverna das Aranhas. Estou a rezar. N\227o[ENTER]pela vit\243ria, mas por um pouco de esperan\231a... "
gameforge.main_quest_lv50._250_say = "Ooohh. Acho que estamos quase l\225! Brevemente[ENTER]iremos descobrir o que \233 esta Magia Negra. Mal[ENTER]posso esperar! Tens de regressar \224 Caverna das[ENTER]Aranhas. Esperemos que a 11\170 P\225gina se encontre[ENTER]a\237. "
gameforge.main_quest_lv50._260_say = "Aqui tens, mais uma vez, a tua merecida[ENTER]recompensa! "
gameforge.main_quest_lv50._270_sayReward = "Recebeste 5.500.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv50._280_sayReward = "Recebeste 137.500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Recebeste uma Luva do Rei S\225bio. "
gameforge.main_quest_lv50._300_sayTitle = "Mata Aranhas Rubi Venenosas "
gameforge.main_quest_lv50._30_sendLetter = "A 9\170 P\225gina "
gameforge.main_quest_lv50._310_say = "A investiga\231\227o da Magia Negra continua na Caverna[ENTER]das Aranhas. Vai at\233 l\225 e mata algumas Aranhas[ENTER]Rubi Venenosas. "
gameforge.main_quest_lv50._320_sendLetter = "A 11\170 P\225gina "
gameforge.main_quest_lv50._330_targetVid = "Regressa ao Uriel "
gameforge.main_quest_lv50._335_sayTitle = "Encontraste a 11\170 P\225gina "
gameforge.main_quest_lv50._340_say = "Encontraste a 11\170 P\225gina do Di\225rio na Caverna das[ENTER]Aranhas. Leva-a ao Uriel. "
gameforge.main_quest_lv50._350_say = "Encontraste mais alguma informa\231\227o? Aha, a 11\170[ENTER]P\225gina! Deixa-me ver...[ENTER]Ah sim, parece-me bastante f\225cil. Fiquei muito[ENTER]bom a ler estas p\225ginas. Agora, v\234 isto! "
gameforge.main_quest_lv50._355_sayTitle = "11\170 P\225gina: "
gameforge.main_quest_lv50._360_sayReward = "N\227o funcionou. Apesar de toda a nossa prepara\231\227o,[ENTER]tivemos de actuar r\225pido. Muito r\225pido. Agora[ENTER]muitos de n\243s est\227o feridos e outros[ENTER]enlouqueceram por completo. A Magia Negra \233[ENTER]realmente uma maldi\231\227o. A cavalaria de Lee Seop[ENTER]est\225 em cima de n\243s, mas isso j\225 n\227o interessa.[ENTER]N\227o temos homens suficientes para nos defendermos[ENTER]contra ele e vamos acabar por morrer na mesma. "
gameforge.main_quest_lv50._365_sayTitle = "Continua\231\227o da 11\170 P\225gina: "
gameforge.main_quest_lv50._370_sayReward = "Um \250ltimo pensamento mant\233m o resto do ex\233rcito[ENTER]de Lee Seop unido e d\225-nos for\231a: os nossos[ENTER]informadores do Vale Seungryong mentiram. Eles[ENTER]n\227o nos avisaram sobre os terr\237veis efeitos[ENTER]secund\225rios da Magia Negra. Ir\227o pagar por isso.[ENTER]Ser\225 a nossa \250ltima ac\231\227o neste mundo. "
gameforge.main_quest_lv50._380_say = "Bom, no fim acabou por ser um pouco diferente do[ENTER]que esper\225vamos. \201 uma hist\243ria triste. Mas[ENTER]infelizmente n\227o se pode acreditar em quem est\225[ENTER]envolvido na Magia Negra. Eles deviam ter pensado[ENTER]nisso. \201 estranho que o autor deste texto tenha[ENTER]sequer conseguido obter informa\231\245es sobre estas[ENTER]magias proibidas. Quem sabe qual seria o[ENTER]objectivo de quem lhe deu essas informa\231\245es. No[ENTER]entanto, dev\237amos terminar este caminho, mesmo[ENTER]sendo perigoso. J\225 sabemos tanto que seria uma[ENTER]pena desistir agora. "
gameforge.main_quest_lv50._390_say = "J\225 estiveste no Vale Seungryong. N\227o me parece[ENTER]que encontraremos algo mais a\237. Hmm, onde ser\225[ENTER]que podemos procurar... J\225 sei! Os Memoriais t\234m[ENTER]tido um grande papel na nossa busca. E h\225[ENTER]Memoriais que ainda n\227o investig\225mos. Aqueles que[ENTER]se encontram noutros Reinos! \201 muito perigoso.[ENTER]Provavelmente ser\225s alvo de ataques constantes.[ENTER]Por isso prepara-te bem e vem ter comigo quando[ENTER]estiveres pronto. "
gameforge.main_quest_lv50._400_say = "Mas primeiro, vou dar-te a recompensa por teres[ENTER]encontrado a 11\170 P\225gina. "
gameforge.main_quest_lv50._40_targetVid = "Vai ter com o Uriel "
gameforge.main_quest_lv50._410_sayReward = "Recebeste 6.000.000 Pontos de Experi\234ncia.[ENTER]Recebeste 150.000 Yang.[ENTER]Recebeste uma Medalha do Drag\227o.[ENTER]Dica: Para a pr\243xima miss\227o precisas de estar[ENTER]pelo menos a n\237vel 55. "
gameforge.main_quest_lv50._50_sayTitle = "Encontraste a 9\170 P\225gina "
gameforge.main_quest_lv50._60_say = "Encontraste a 9\170 P\225gina na Caverna das Aranhas.[ENTER]Leva-a ao Uriel. "
gameforge.main_quest_lv50._70_say = "Encontraste mais alguma coisa sobre a magia[ENTER]negra? Wow, a 9\170 P\225gina do Di\225rio! Estou muito[ENTER]ansioso para saber se a magia funcionou ou n\227o.[ENTER]Vamos l\225 ver. Hmm, aqui diz... "
gameforge.main_quest_lv50._75_sayTitle = "9\170 P\225gina: "
gameforge.main_quest_lv50._80_sayReward = "O ataque de Lee Seop come\231ou. E ainda n\227o sabemos[ENTER]exactamente como usar a Magia Negra. Estou muito[ENTER]nervoso. Estamos na linha da frente, a tentar[ENTER]defender o nosso Reino, mas a nossa for\231a n\227o \233[ENTER]suficiente. O ex\233rcito inimigo \233 demasiado forte[ENTER]e se algo n\227o acontecer em breve, iremos perder o[ENTER]combate. Temos de nos retirar. Seria melhor[ENTER]encontrarmos um local irregular, onde eles n\227o[ENTER]possam usar os cavalos: a Terra do Gelo. Com um[ENTER]pouco de sorte talvez tenhamos tempo para[ENTER]continuar a investiga\231\227o. Oh, Deus nos ajude... "
gameforge.main_quest_lv50._90_say = "Hmm...O ataque come\231ou antes de eles terem tido[ENTER]tempo de investigar a Magia Negra[ENTER]apropriadamente. Eles barricaram-se na Terra do[ENTER]Gelo. Devem estar a referir-se \224 Montanha Sohan.[ENTER]Dev\237amos procurar mais pistas. Vai at\233 \224 Montanha[ENTER]Sohan e v\234 o que consegues descobrir. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Encontraste a 12\170 P\225gina na \193rea Joan. Leva-a ao[ENTER]Uriel na \193rea Yongan. "
gameforge.main_quest_lv55._10_sendLetter = "Procura o Memorial "
gameforge.main_quest_lv55._110_say = "Encontraste a 12\170 P\225gina na \193rea Yongan. Leva-a[ENTER]ao Uriel na \193rea Pyungmo. "
gameforge.main_quest_lv55._120_say = "Estou contente por te ver de novo. Lamento ter-te[ENTER]enviado a todos os cantos do mundo, mas pelo[ENTER]menos o nosso sucesso provou que est\225vamos[ENTER]certos, n\227o achas? Vamos ver o que diz. Espero[ENTER]que tenha valido a pena. "
gameforge.main_quest_lv55._130_sayTitle = "A 12\170 P\225gina: "
gameforge.main_quest_lv55._140_sayReward = "Encontramos os informadores e eles pagaram pela[ENTER]mentira com as suas vidas. Mas o mais importante[ENTER]\233 que ainda conseguimos extrair algumas[ENTER]informa\231\245es deles: N\227o precisamos da Caverna das[ENTER]Aranhas, mas sim do Templo da Escurid\227o. Este \233 o[ENTER]local onde os seguidores da cren\231a antiga[ENTER]praticam os seus rituais negros desde o in\237cio[ENTER]dos tempos. "
gameforge.main_quest_lv55._145_sayTitle = "Continua\231\227o da 12\170 P\225gina: "
gameforge.main_quest_lv55._150_sayReward = "Apenas temos mais uma forma de derrotar Lee Seop.[ENTER]Temos de nos dirigir para o Templo da Escurid\227o[ENTER]para podermos usar a Magia Negra. J\225 n\227o h\225[ENTER]muitos de n\243s, e a exaust\227o causada pelos \250ltimos[ENTER]meses j\225 pesa. Mas mesmo um punhado de homens[ENTER]cansados pode mudar o destino do mundo se tiverem[ENTER]informa\231\227o suficiente. N\227o podemos desviar-nos do[ENTER]nosso objectivo. Vamos l\225. "
gameforge.main_quest_lv55._160_say = "Ah, ent\227o eles encontraram o lugar certo. Afinal[ENTER]de contas eu tinha raz\227o! Realmente era o Templo[ENTER]Hwang. Provavelmente lembras-te desse lugar[ENTER]negro, repleto de m\225s energias. Desde que \233[ENTER]poss\237vel recordar, t\234m l\225 lugar rituais e[ENTER]cerim\243nias das quais os alde\245es se devem manter[ENTER]afastados. "
gameforge.main_quest_lv55._170_say = "Hoje em dia os monstros s\227o as \250nicas coisas[ENTER]vivas no Templo. H\225 muito tempo que j\225 n\227o[ENTER]existem l\225 humanos. \201 muito perigoso, mas tenho a[ENTER]certeza de que o conseguir\225s fazer. Atravessa o[ENTER]Vale Seungryong e procura a \250ltima P\225gina no[ENTER]Templo Hwang. A hist\243ria contada pelo Di\225rio[ENTER]termina nesse lugar. Preciso de saber como tudo[ENTER]acabou. Boa sorte! Oh, espera um segundo, aqui[ENTER]est\225 a tua recompensa pela 12\170 P\225gina. "
gameforge.main_quest_lv55._180_sayReward = "Recebeste 26.000 Pontos de Experi\234ncia.[ENTER]Recebeste 15.000 Yang.[ENTER]Recebeste um Nariz de Porco. "
gameforge.main_quest_lv55._190_sayReward = "Recebeste 162.500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "A \218ltima P\225gina "
gameforge.main_quest_lv55._20_say = "Como j\225 encontraste v\225rias P\225ginas do Di\225rio[ENTER]perto de memoriais, o Uriel acha que poder\225s[ENTER]encontrar mais informa\231\245es sobre a magia negra[ENTER]secreta perto dos memoriais inexplorados.[ENTER]Vai ao Reino de Chunjo e examina o memorial na[ENTER]\193rea Joan. "
gameforge.main_quest_lv55._210_sayTitle = "Mata Bogeymans no Templo "
gameforge.main_quest_lv55._220_say = "J\225 encontraste 12 das 13 P\225ginas do Di\225rio. Agora[ENTER]falta apenas mais um passo. O Uriel diz que a[ENTER]Magia Negra foi usada no Templo Hwang. Devias ir[ENTER]at\233 l\225 tentar obter mais informa\231\245es.[ENTER]Come\231a a tua busca matando Bogeymans no Templo. "
gameforge.main_quest_lv55._230_say = "Tenho de procurar mais fundo no Templo! "
gameforge.main_quest_lv55._240_sendLetter = "O Templo da Escurid\227o "
gameforge.main_quest_lv55._250_sayTitle = "A energia negra do Templo "
gameforge.main_quest_lv55._260_sayReward = "Depois de passares algum tempo no Templo, come\231as[ENTER]a desenvolver um sentimento em rela\231\227o a este[ENTER]lugar estranho e negro: sombras mexem-se em todos[ENTER]os cantos. Energia negra \233 emitida de cada falha[ENTER]e recanto como se fosse \243leo. \201 \243bvio que o[ENTER]pr\243prio Templo \233 a fonte da Energia. Foi aqui que[ENTER]tudo come\231ou... "
gameforge.main_quest_lv55._270_say = "Apercebes-te de que a energia que paira no ar se[ENTER]torna mais forte \224 medida que te aproximas do[ENTER]centro do Templo. Devias tentar encontrar o[ENTER]centro exacto. Deve ser a\237 que se situa a fonte[ENTER]de tamanha escurid\227o. "
gameforge.main_quest_lv55._280_npcChat = "O Memorial Gum "
gameforge.main_quest_lv55._290_say = "O Memorial Gum encontra-se no cora\231\227o do Templo.[ENTER]Aproximas-te lentamente e encontras a \250ltima[ENTER]P\225gina do Di\225rio. "
gameforge.main_quest_lv55._300_say = "Encontraste a ultima p\225gina do Di\225rio Secreto no[ENTER]Templo da Escurid\227o. Leva-a ao Uriel e conta-lhe[ENTER]sobre a tua descoberta. "
gameforge.main_quest_lv55._30_say = "Como j\225 encontraste v\225rias P\225ginas do Di\225rio[ENTER]perto de memoriais, o Uriel acha que poder\225s[ENTER]encontrar mais informa\231\245es sobre a magia negra[ENTER]secreta perto dos memoriais inexplorados.[ENTER]Vai ao Reino de Jinno e examina o memorial na[ENTER]\193rea Pyungmo. "
gameforge.main_quest_lv55._310_say = "Aqui est\225 a 13\170 e ultima P\225gina ! N\227o imaginas[ENTER]como estou agradecido por teres feito isto. V\234[ENTER]como as minhas m\227os tremem. Estou demasiado[ENTER]excitado at\233 para ler esta p\225gina. Phew...[ENTER]Ah, bem, vamos ver como acaba a hist\243ria. "
gameforge.main_quest_lv55._320_sayTitle = "A 13\170 P\225gina: "
gameforge.main_quest_lv55._330_sayReward = "Finalmente chegamos.[ENTER]Depois de tantos problemas, temos agora a[ENTER]seguinte miss\227o: Temos de organizar a cerim\243nia e[ENTER]conjurar a Magia Negra. Apenas espero que sejamos[ENTER]suficientemente fortes. Muitos de n\243s est\227o a[ENTER]vacilar devido \224 exaust\227o causada pela longa[ENTER]viagem e a constante fuga dos guerreiros de Lee[ENTER]Seop. Mas temos de tentar, ou o nosso Reino ir\225[ENTER]perecer. "
gameforge.main_quest_lv55._335_sayTitle = "Continua\231\227o da 13\170 P\225gina: "
gameforge.main_quest_lv55._340_sayReward = "Somos sete. Vestimos a nossa melhor roupa, mesmo[ENTER]que agora se pare\231am com trapos. Vamos juntar-nos[ENTER]num circulo e dar as m\227os para que as linhas do[ENTER]poder sejam seladas. Depois iremos come\231ar a[ENTER]cantar as palavras m\225gicas e esperar que a magia[ENTER]negra n\227o fa\231a mais sacrif\237cios... "
gameforge.main_quest_lv55._350_sayReward = "... Acabou...[ENTER]No princ\237pio tudo parecia muito promissor. A sala[ENTER]encheu-se de energia e m\250sica, mas subitamente[ENTER]senti-me muito estranho. Os meus seis camaradas[ENTER]ca\237ram de joelhos. O Templo come\231ou a tremer. Um[ENTER]trov\227o caiu entre n\243s e fomos atirados para tr\225s.[ENTER]E as linhas do poder foram quebradas...[ENTER]Agora tudo est\225 calmo. Os meus camaradas est\227o[ENTER]mortos no ch\227o. A Magia n\227o funcionou.[ENTER]Falh\225mos. "
gameforge.main_quest_lv55._360_say = "O qu\234? \201 s\243 isto?!?[ENTER]Isto \233 de doidos! Tanto trabalho para nada? Eu[ENTER]n\227o acredito nisto. N\243s viajamos, lutamos,[ENTER]traduzimos e pesquisamos durante horas. Tudo isto[ENTER]para nada! Estamos t\227o s\225bios como est\225vamos[ENTER]antes. De qualquer maneira, ser\225 melhor ficarmos[ENTER]longe dessa magia negra, que foi o que pensei[ENTER]logo desde o inicio. Mas saber \233 melhor do que[ENTER]acreditar, n\227o \233 verdade? "
gameforge.main_quest_lv55._370_say = "Primeiro vamos fazer uma pausa. Estou com uma dor[ENTER]de cabe\231a e tu deves estar bastante cansado.[ENTER]Preciso de pensar um pouco nisto. Assim que tiver[ENTER]ponderado nisto falaremos mais.[ENTER]Apesar de tudo, fizeste um servi\231o valioso. N\227o[ENTER]me esquecerei de o recompensar! "
gameforge.main_quest_lv55._380_sayReward = "Recebeste 7.000.000 Pontos de Experi\234ncia. "
gameforge.main_quest_lv55._390_sayReward = "Recebeste 175.000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Recebeste o Livro do L\237der. "
gameforge.main_quest_lv55._40_say = "Como j\225 encontraste v\225rias P\225ginas do Di\225rio[ENTER]perto de memoriais, o Uriel acha que poder\225s[ENTER]encontrar mais informa\231\245es sobre a magia negra[ENTER]secreta perto dos memoriais inexplorados.[ENTER]Vai ao Reino de Shinsoo e examina o memorial na[ENTER]\193rea Yongan. "
gameforge.main_quest_lv55._50_npcChat = "Aqui est\225! "
gameforge.main_quest_lv55._60_say = "Aqui est\225 o Memorial que o Uriel estava \224[ENTER]procura. Est\225 aqui tamb\233m uma P\225gina dobrada! \201[ENTER]melhor levar isto ao Uriel rapidamente. "
gameforge.main_quest_lv55._70_sendLetter = "Encontraste a 12\170 P\225gina "
gameforge.main_quest_lv55._80_targetVid = "Regressa ao Uriel "
gameforge.main_quest_lv55._90_say = "Encontraste a 12\170 P\225gina na \193rea Pyungmo. Leva-a[ENTER]ao Uriel na \193rea Joan. "
gameforge.main_quest_lv6 = {}
gameforge.main_quest_lv6._100_sayReward = "Vai ter com o Ferreiro. Ele precisa da tua ajuda. "
gameforge.main_quest_lv6._10_targetVid = "Vai ter com o Guarda da Cidade "
gameforge.main_quest_lv6._110_say = "Quem \233s tu e o que queres daqui? Estou muito[ENTER]ocupado por isso n\227o me interrompas.[ENTER]Oh, o Guarda da Cidade enviou-te? Pensava que[ENTER]nunca mais aparecia algu\233m. N\227o \233 muito dif\237cil e[ENTER]n\227o vai demorar muito tempo. \201 algo indicado para[ENTER]um jovem aventureiro como tu. "
gameforge.main_quest_lv6._120_say = "Era suposto ter recebido uma encomenda do Guarda[ENTER]do Armaz\233m - preciso muito de um Nariz de Porco.[ENTER]H\225 muito tempo que estou \224 espera. Podes[ENTER]ajudar-me e arranjar-me o Nariz de Porco? \201 muito[ENTER]importante. "
gameforge.main_quest_lv6._130_targetVid = "Pergunta ao Guarda do Armaz\233m "
gameforge.main_quest_lv6._140_sendLetter = "Vai ter com o Guarda do Armaz\233m "
gameforge.main_quest_lv6._150_sayReward = "O Ferreiro est\225 \224 espera de uma entrega urgente[ENTER]do Guarda do Armaz\233m. Vai at\233 ao Guarda do[ENTER]Armaz\233m e pede-lhe o Nariz de Porco para o[ENTER]Ferreiro. "
gameforge.main_quest_lv6._160_sayTitle = "Guarda do Armaz\233m "
gameforge.main_quest_lv6._170_say = "Bem-vindo. Sou o Guarda do Armaz\233m desta vila. Se[ENTER]estiveres na posse de demasiadas coisas, podes[ENTER]armazenar aqui algumas delas. "
gameforge.main_quest_lv6._180_say = "Queres... Ah, o Ferreiro enviou-te por causa do[ENTER]Nariz de Porco! "
gameforge.main_quest_lv6._190_say = "Parece que estou a ficar velho e a esquecer-me[ENTER]das coisas. No passado nada deste tipo[ENTER]aconteceria. Aqui tens o Nariz de Porco. Por[ENTER]favor leva-o imediatamente ao Ferreiro. Vejo-te[ENTER]mais tarde. "
gameforge.main_quest_lv6._200_sendLetter = "Regressa ao Ferreiro "
gameforge.main_quest_lv6._20_sayReward = "O Guarda da Cidade tem uma nova miss\227o para ti.[ENTER]Vai ter com ele e pergunta-lhe sobre o que \233. "
gameforge.main_quest_lv6._210_sayReward = "O Guarda do Armaz\233m esqueceu-se completamente da[ENTER]entrega. Ele deu-te o Nariz de Porco. Entrega-o[ENTER]rapidamente ao Ferreiro para que n\227o tenha de[ENTER]esperar mais tempo. "
gameforge.main_quest_lv6._220_say = "Voltaste mais depressa do que eu pensava! Devias[ENTER]continuar com esta rapidez, pode ser \250til no[ENTER]futuro. Agora ouve-me com aten\231\227o, eu tenho uma[ENTER]informa\231\227o muito importante para ti. "
gameforge.main_quest_lv6._230_say = "Sabes alguma coisa sobre melhoramentos? \201 claro[ENTER]que n\227o! Ainda \233s um jovem aventureiro! \201 assim:[ENTER]Se me deres uma pe\231a do teu equipamento posso[ENTER]tentar melhorar a sua qualidade em troca de algum[ENTER]Yang. "
gameforge.main_quest_lv6._240_say = "A arte do melhoramento pode acontecer de v\225rias[ENTER]formas diferentes - quanto mais elevado o n\237vel[ENTER]mais dif\237cil ser\225 o melhoramento. Para o[ENTER]melhoramento de itens +3 ou abaixo apenas[ENTER]precisas de Yang, enquanto que para outros n\237veis[ENTER]do item poder\225s precisar de itens adicionais.[ENTER]Como por exemplo o Nariz de Porco que me[ENTER]trouxeste. No entanto por vezes o item que[ENTER]pretendes melhorar \233 destru\237do, mesmo se for[ENTER]manuseado por um Ferreiro experiente como eu.[ENTER]Volta de novo quando tiveres tempo. Posso criar[ENTER]itens fant\225sticos! "
gameforge.main_quest_lv6._250_sayReward = "Recebeste %s Pontos de Experi\234ncia. "
gameforge.main_quest_lv6._260_sayReward = "Recebeste %s Yang. "
gameforge.main_quest_lv6._270_sayReward = "Recebeste P\234lo de Lobo+. "
gameforge.main_quest_lv6._30_say = "Hey, tu a\237! N\227o \233 altura de ficar por aqui sem[ENTER]fazer nada. Tens de treinar no duro! \201 a \250nica[ENTER]forma de aumentares as tuas hip\243teses de[ENTER]sobreviv\234ncia nestes tempos dif\237ceis! "
gameforge.main_quest_lv6._40_say = "Mas j\225 que est\225s aqui, eu tenho uma miss\227o para[ENTER]ti: o Ferreiro esteve aqui h\225 pouco tempo e disse[ENTER]algo sobre porcos e problemas de entregas. Talvez[ENTER]ele precise de ajuda. Vai ter com ele e diz-lhe[ENTER]que eu te enviei.[ENTER]Podes ir! "
gameforge.main_quest_lv6._50_sayReward = "Se completares a miss\227o do Ferreiro ser\225s[ENTER]recompensado. "
gameforge.main_quest_lv6._60_sayReward = "Pontos de Experi\234ncia: %s "
gameforge.main_quest_lv6._70_sayReward = "Yang: %d "
gameforge.main_quest_lv6._80_targetVid = "Encontra o Ferreiro "
gameforge.main_quest_lv6._90_sendLetter = "A miss\227o do Ferreiro "
gameforge.main_quest_lv60 = {}
gameforge.main_quest_lv60._100_say = "Montanha Sohan? Um vez encontrei uma velha l\225pide[ENTER]nesse local! "
gameforge.main_quest_lv60._10_sendLetter = "Uma nova pista "
gameforge.main_quest_lv60._110_say = "Por acaso n\227o te lembras de ver qualquer[ENTER]inscri\231\227o nela? Evidentemente que n\227o. Esta[ENTER]l\225pide poder\225 dar-nos informa\231\245es valiosas sobre[ENTER]a Na\231\227o das Trevas. Ser\225 que podes ir \224 Montanha[ENTER]Sohan e tirar uma c\243pia da inscri\231\227o para mim? "
gameforge.main_quest_lv60._120_say = "De acordo com as investiga\231\245es de Uriel, as 7[ENTER]Sacerdotisas do Drag\227o pertenciam \224 Na\231\227o das[ENTER]Trevas. Examina a velha l\225pide na Montanha Sohan.[ENTER]Sup\245e-se que era nesse local onde, h\225 muito[ENTER]tempo, se situava a capital da Na\231\227o das Trevas. "
gameforge.main_quest_lv60._130_say = "Por acaso n\227o te lembras de ver qualquer[ENTER]inscri\231\227o nela? Evidentemente que n\227o. Esta[ENTER]l\225pide poder\225 dar-nos informa\231\245es valiosas sobre[ENTER]a Na\231\227o das Trevas. Ser\225 que podes ir \224 Montanha[ENTER]Sohan e tirar uma c\243pia da inscri\231\227o para mim? "
gameforge.main_quest_lv60._140_sayReward = "Localizaste a velha l\225pide dos tempos da Na\231\227o[ENTER]das Trevas e fizeste uma c\243pia da inscri\231\227o.[ENTER]Leva-a ao Uriel. "
gameforge.main_quest_lv60._150_say = "De acordo com as investiga\231\245es de Uriel, as 7[ENTER]Sacerdotisas do Drag\227o pertenciam \224 Na\231\227o das[ENTER]Trevas. Examina a velha l\225pide na Montanha Sohan.[ENTER]Sup\245e-se que era nesse local onde, h\225 muito[ENTER]tempo, se situava a capital da Na\231\227o das Trevas. "
gameforge.main_quest_lv60._160_say = "Finalmente! Deixa-me analisar a inscri\231\227o...[ENTER]Diz o seguinte: a Na\231\227o das Trevas dedicou-se \224[ENTER]magia negra e serve Sung Mahi, Deus dos Dem\243nios. "
gameforge.main_quest_lv60._170_say = "Oh... Sung Mahi! Ser\225 que as 7 Sacerdotisas do[ENTER]Drag\227o tentaram invocar Sung Mahi usando o poder[ENTER]da feiti\231aria proibida? "
gameforge.main_quest_lv60._180_say = "Fizeste um bom trabalho. Pelo teu esfor\231o, \233[ENTER]justo que recebas uma recompensa. "
gameforge.main_quest_lv60._190_sayReward = "Recebeste %s Pontos de Experi\234ncia. "
gameforge.main_quest_lv60._200_sayReward = "Recebeste %s Yang. "
gameforge.main_quest_lv60._20_say = "O Uriel encontrou novas informa\231\245es relativas \224[ENTER]hist\243ria do velho di\225ro. Procura-o e descobre[ENTER]mais. "
gameforge.main_quest_lv60._210_sayReward = "Recebeste %d. "
gameforge.main_quest_lv60._220_sendLetter = "Na\231\227o das Trevas II "
gameforge.main_quest_lv60._230_say = "De acordo com o Uriel, a Floresta Fantasma[ENTER]outrora foi parte do reino da Na\231\227o das Trevas.[ENTER]Talvez l\225 possas encontrar mais pistas. Mas esta[ENTER]floresta est\225 repleta de perigos e as Pedras[ENTER]Metin provocaram um frenesim em todas as[ENTER]criaturas nesse local.[ENTER]Encontra a \193rvore do Mal para receberes novas[ENTER]pistas. Depois fala com o Uriel. "
gameforge.main_quest_lv60._240_say = "A Na\231\227o das Trevas est\225 rodeada por v\225rios[ENTER]segredos. Gra\231as a ti, j\225 conseguimos descortinar[ENTER]alguns, mas ainda nos faltam informa\231\245es vitais.[ENTER]Por favor parte em busca de um documento antigo.[ENTER]Ele dever\225 estar localizado na Floresta Fantasma,[ENTER]perto da Montanha Sohan. "
gameforge.main_quest_lv60._250_counter = "P\225ginas em falta: "
gameforge.main_quest_lv60._260_say = "A Na\231\227o das Trevas est\225 rodeada por v\225rios[ENTER]segredos. Gra\231as a ti, j\225 conseguimos descortinar[ENTER]alguns, mas ainda nos faltam informa\231\245es vitais.[ENTER]Por favor parte em busca de um documento antigo.[ENTER]Ele dever\225 estar localizado na Floresta Fantasma,[ENTER]perto da Montanha Sohan. "
gameforge.main_quest_lv60._270_sayReward = "Derrotaste a \193rvore do Mal e conseguiste o[ENTER]documento. Est\225 escrito num idioma estranho.[ENTER]Leva-o ao Uriel para o traduzir. "
gameforge.main_quest_lv60._280_say = "Finalmente! Encontraste o documento antigo.[ENTER]Espero que lance alguma luz sobre este assunto! "
gameforge.main_quest_lv60._290_say = "Mas o qu\234ee...? N\227o diz praticamente nada! O[ENTER]documento \233, na realidade, composto por 10[ENTER]p\225ginas. Por favor regressa \224 floresta e encontra[ENTER]as 9 p\225ginas em falta. "
gameforge.main_quest_lv60._300_say = "Ainda precisas de encontrar %d p\225gina(s). "
gameforge.main_quest_lv60._30_say = "Como est\225s? Lembras-te do di\225rio e da hist\243ria[ENTER]que ele contava? Aquela que acabava abruptamente[ENTER]na 13\170 p\225gina? "
gameforge.main_quest_lv60._310_say = "Portanto, vamos l\225 ver...[ENTER]Aparentemente a Na\231\227o das Trevas lan\231ou uma[ENTER]maldi\231\227o sobre a Grande Sacerdotisa do culto do[ENTER]Drag\227o e usou os poderes sagrados das sete[ENTER]mulheres para conseguir executar as artes antigas[ENTER]da magia negra. "
gameforge.main_quest_lv60._320_say = "Para invocar Sung Mahi, a magia negra tem de ser[ENTER]usada simultaneamente em sete locais diferentes.[ENTER]Mas Lee Seop e o seu ex\233rcito conseguiram parar o[ENTER]ritual e acabar com o plano da Na\231\227o das Trevas. "
gameforge.main_quest_lv60._330_say = "Esta Na\231\227o era, sem d\250vida, algo a temer. Eles[ENTER]eram capazes de controlar a consci\234ncia humana[ENTER]atrav\233s de magia negra! "
gameforge.main_quest_lv60._340_sendLetter = "A Pista "
gameforge.main_quest_lv60._350_say = "O Uriel descobriu pistas relacionadas com o[ENTER]Memorial Gum nos pergaminhos antigos. Vai ter com[ENTER]ele para descobrires mais. "
gameforge.main_quest_lv60._360_say = "Deixa-me resumir o que descobrimos at\233 agora:[ENTER]Outrora existiu um povo, auto-denominado Na\231\227o[ENTER]das Trevas, que servia o Deus Dem\243nio Sun Mahi.[ENTER]Para o invocarem, lan\231aram uma maldi\231\227o sobre as[ENTER]Sacerdotisas do Drag\227o e usaram os seus poderes[ENTER]sagrados para executarem as artes proibidas da[ENTER]magia negra. Mas o ritual precisava de ser[ENTER]executado em 7 localiza\231\245es em simult\226neo. "
gameforge.main_quest_lv60._370_say = "As Sacerdotisas do Drag\227o apenas executaram a[ENTER]magia negra na Torre, e n\227o nas 7 localiza\231\245es[ENTER]diferentes... Por isso \233 que a invoca\231\227o de Sung[ENTER]Mahi falhou! "
gameforge.main_quest_lv60._380_say = "A Na\231\227o das Trevas deve ter dado informa\231\227o[ENTER]errada \224s 7 Sacerdotisas do Drag\227o. "
gameforge.main_quest_lv60._390_say = "Talvez nem eles soubessem como o fazer... Pode[ENTER]ser apenas um acaso, mas os pergaminhos antigos[ENTER]mencionam esta Torre relacionada com o Memorial[ENTER]Gum. Parece que se referem \224 Torre Demon\237aca no[ENTER]Templo Hwang. "
gameforge.main_quest_lv60._400_say = "Finalmente descobrimos a pista decisiva sobre as[ENTER]7 Sacerdotisas do Drag\227o! Descansa um pouco e[ENTER]falaremos depois do que fazer a seguir. Tenho um[ENTER]pressentimento que ter\225s pela frente uma visita \224[ENTER]Torre Demon\237aca... "
gameforge.main_quest_lv60._40_say = "Sim, naturalmente. Sete pessoas fugiram de Lee[ENTER]Seop e da sua cavalaria para o Templo Hwang e, no[ENTER]seu desespero, usaram a magia negra proibida...[ENTER]no fim, apenas uma dessas pessoas sobreviveu. "
gameforge.main_quest_lv60._410_sayReward = "A pr\243xima parte desta aventura estar\225 dispon\237vel[ENTER]quando atingires o n\237vel 66. "
gameforge.main_quest_lv60._50_say = "Correcto. Fiz mais umas pesquisas e descobri que[ENTER]os sete membros desse culto sagrado eram as[ENTER]Sacerdotisas do Drag\227o. Em velhos pergaminhos[ENTER]elas est\227o associadas com um povo teocr\225tico[ENTER]apelidado de Na\231\227o das Trevas. Seriam estas[ENTER]Sacerdotisas parte desta misteriosa na\231\227o? Toma,[ENTER]l\234 este pergaminho atenta e cuidadosamente e[ENTER]volta a falar comigo quando acabares. "
gameforge.main_quest_lv60._60_sendLetter = "Na\231\227o das Trevas I "
gameforge.main_quest_lv60._70_say = "De acordo com as investiga\231\245es de Uriel, as 7[ENTER]Sacerdotisas do Drag\227o pertencem \224 Na\231\227o das[ENTER]Trevas. Examina a velha l\225pide na Montanha Sohan.[ENTER]Sup\245e-se que a capital da Na\231\227o das Trevas possa[ENTER]um dia ter sido localizada a\237. Antes de partires,[ENTER]fala com o Uriel de novo. "
gameforge.main_quest_lv60._80_say = "A feiti\231aria inacreditavelmente muito[ENTER]desenvolvida e o facto de que, de acordo com o[ENTER]di\225rio, eles tenham sido destru\237dos por Lee Seop[ENTER]apontam para a ideia de que as 7 Sacerdotisas do[ENTER]Drag\227o faziam parte da Na\231\227o das Trevas. "
gameforge.main_quest_lv60._90_say = "Nos velhos pergaminhos existe um mapa. Numa[ENTER]inspec\231\227o mais pr\243xima, podes determinar que a[ENTER]capital da Na\231\227o das Trevas deveria estar[ENTER]localizada na Montanha Sohan. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Inacredit\225vel! Compreendes o significado disto?[ENTER]Originalmente n\227o existiam dem\243nios ou esp\237ritos[ENTER]na Torre Demon\237aca. O que se passa na Torre[ENTER]actualmente \233 consequ\234ncia das ac\231\245es da[ENTER]Sacerdotisa do Drag\227o. Num \250ltimo acto de[ENTER]desespero, ela usou este maldito e negro ritual[ENTER]para tentar derrotar a cavalaria de Lee Seop,[ENTER]abrindo a porta para os dem\243nios entrarem neste[ENTER]mundo. No fim, acabou por pagar isto com a sua[ENTER]vida. "
gameforge.main_quest_lv66._10_sendLetter = "O Di\225rio "
gameforge.main_quest_lv66._110_say = "Foi esta porta que o Fantasma da Morte e os seus[ENTER]seguidores demon\237acos usaram para entrar no nosso[ENTER]mundo. No entanto, a grande miss\227o da Na\231\227o das[ENTER]Trevas e das Sacerdotisas do Drag\227o falhou: a[ENTER]invoca\231\227o de Sung Mahi n\227o foi bem-sucedida e Lee[ENTER]Seop, ao contr\225rio do que pretendiam, subiu ao[ENTER]poder e acabou por estabelecer um reino unido.[ENTER][ENTER]Gra\231as \224 tua ajuda, finalmente consegui resolver[ENTER]o maior mist\233rio da minha vida! "
gameforge.main_quest_lv66._120_say = "Como recompensa, gostaria de te presentear com um[ENTER]Pergaminho da B\234n\231\227o. Por favor aceita este meu[ENTER]presente, eu insisto! "
gameforge.main_quest_lv66._130_sendLetter = "Tens uma mensagem. "
gameforge.main_quest_lv66._140_say = "O Guarda da Cidade tem uma carta para ti. Vai[ENTER]l\234-la e descobre quem \233 o remetente secreto. "
gameforge.main_quest_lv66._150_say = "Tens andado desaparecido ultimamente, h\227? \201[ENTER]suposto entregar-te esta carta - n\227o sei quem a[ENTER]enviou, ele n\227o se apresentou. "
gameforge.main_quest_lv66._160_say = "O papel usado para a carta parece ser muito[ENTER]antigo. Numa caligrafia apressada, pode ler-se o[ENTER]seguinte:[ENTER]Tenho informa\231\245es importantes sobre as 7[ENTER]Sacerdotisas do Drag\227o e Sung Mahi. Aguardo-te[ENTER]atr\225s da Torre Demon\237aca no Templo Hwang. Estou[ENTER]na sombra da \225rvore. Despacha-te! Temos pouco[ENTER]tempo! "
gameforge.main_quest_lv66._170_sendLetter = "Carta An\243nima "
gameforge.main_quest_lv66._180 = "Vai at\233 ao Templo Hwang e encontra o misterioso[ENTER]remetente da carta nas traseiras da Torre[ENTER]Demon\237aca. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Bem-vindo! Permite-me que me apresente primeiro:[ENTER]o meu nome \233 Lee Chung. Foi muito corajoso da tua[ENTER]parte seguires as instru\231\245es de algu\233m que nem[ENTER]sequer conheces. N\227o me enganei ao escolher-te -[ENTER]e tu tamb\233m n\227o ir\225s lamentar a minha decis\227o![ENTER]Ouve o que tenho a dizer! "
gameforge.main_quest_lv66._20_say = "Uriel tem novidades sobre a \250ltima sobrevivente[ENTER]das Sacerdotisas do Drag\227o. O seu di\225rio deve[ENTER]encontrar-se na Torre Demon\237aca. Vai ter com o[ENTER]Uriel para descobrires mais. "
gameforge.main_quest_lv66._210_sendLetter = "Um novo Mal "
gameforge.main_quest_lv66._220_say = "Ouve o que Lee Chung tem para te dizer. "
gameforge.main_quest_lv66._230_say = "Existe uma raz\227o pela qual deves vir ao Templo[ENTER]Hwang: recentemente t\234m acontecido algumas coisas[ENTER]estranhas. E agora descobrimos uma entrada para[ENTER]uma caverna massiva nas traseiras da Torre[ENTER]Demon\237aca! "
gameforge.main_quest_lv66._240_say = "Uma caverna gigantesca? O que h\225 no seu interior? "
gameforge.main_quest_lv66._250_say = "Nesta caverna existe um novo e inimagin\225vel mal \224[ENTER]nossa espera. Os nossos batedores falam de uma[ENTER]macabra criatura que consegue at\233 fazer com que[ENTER]os dem\243nios se escondam nas sombras. O seu[ENTER]terr\237vel aparecimento e a sua insaci\225vel fome de[ENTER]vida fazem-nos crer que este \233 o lend\225rio Agwi -[ENTER]um dos 10 Grandes Dem\243nios do mundo demon\237aco. Se[ENTER]estivermos correctos, corremos todos grande[ENTER]perigo. "
gameforge.main_quest_lv66._260_say = "Mais aterrorizador que dem\243nios... esta criatura[ENTER]deve ser verdadeiramente poderosa e perversa. "
gameforge.main_quest_lv66._270_say = "Correcto. Eu e os meus homens j\225 tent\225mos, v\225rias[ENTER]vezes, explorar as Catacumbas do Dem\243nio. Mas[ENTER]todas as tentativas resultaram em falhan\231o e j\225[ENTER]sofremos enormes perdas. Por isso precisamos da[ENTER]ajuda de um proeminente guerreiro neste assunto -[ENTER]da\237 te termos convocado. Ir\225s ajudar-nos? "
gameforge.main_quest_lv66._280_say = "Sim, irei ajudar. "
gameforge.main_quest_lv66._290_say = "Oh, isso d\225-nos uma nova esperan\231a! Agora, como[ENTER]sei que est\225s do nosso lado, posso contar-te toda[ENTER]a verdade: Eu, Lee Chung, sou o comandante dos[ENTER]Guerreiros da Sombra. Somos uma unidade de elite[ENTER]secreta do ex\233rcito de Lee Seop. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, \233 bom ver que est\225s de novo saud\225vel e em[ENTER]seguran\231a. Est\225s preparado para uma nova[ENTER]aventura? Ainda nos faltam informa\231\245es[ENTER]importantes relativas \224 Na\231\227o das Trevas e \224s 7[ENTER]Sacerdotisas do Drag\227o. A \250ltima Sacerdotisa deve[ENTER]ter escondido o seu di\225rio na Torre Demon\237aca[ENTER]antes de tentar executar a magia negra. Vai at\233[ENTER]l\225 e traz-me o di\225rio. \201 poss\237vel que esteja na[ENTER]posse do Rei Dem\243nio. "
gameforge.main_quest_lv66._310_say = "Os Guerreiros da Sombra t\234m perseguido um \250nico[ENTER]objectivo desde a sua forma\231\227o - evitar a[ENTER]ressurrei\231\227o de Sung Mahi. Essa \233 a nossa miss\227o.[ENTER]Juntos vamos enviar estes Agwi de volta para o[ENTER]inferno de onde sa\237ram e descobrir como \233 que[ENTER]chegaram at\233 ao nosso mundo! "
gameforge.main_quest_lv66._320_sendLetter = "N\227o h\225 tempo "
gameforge.main_quest_lv66._330_say = "Lee Chung, comandante dos Guerreiros da Sombra,[ENTER]est\225 \224 tua procura. Parece ser muito urgente! "
gameforge.main_quest_lv66._340_say = "Tenho um pedido urgente. Est\225s a ver aquele[ENTER]soldado ferido? Ele \233 um dos meus batedores que[ENTER]foi enviado para explorar as Catacumbas do[ENTER]Dem\243nio sob minhas ordens. Enquanto o fazia, foi[ENTER]atacado por um Agwi e envenenado. O veneno est\225 a[ENTER]espalhar-se pelo seu corpo - ele j\225 n\227o tem muito[ENTER]tempo. "
gameforge.main_quest_lv66._350_say = "Ele precisa de um ant\237doto e precisa dele r\225pido![ENTER]Ser\225 que consegues arranjar algum? Poder\225s[ENTER]encontr\225-lo no Bosque Rubro perto das Dr\237ades[ENTER]Rubras.[ENTER]Ele \233 um dos meus melhores guerreiros - salva a[ENTER]sua vida e irei recompensar-te com %s. "
gameforge.main_quest_lv66._360_say = "Irei procurar o ant\237doto! "
gameforge.main_quest_lv66._370_say = "Obrigado! Ele ainda respira, mas est\225 a ficar[ENTER]cada vez mais fraco. N\227o temos tempo a perder! "
gameforge.main_quest_lv66._380_notice = "Tens mais %d minutos. "
gameforge.main_quest_lv66._390_sendLetter = "O Ant\237doto "
gameforge.main_quest_lv66._400_say = "Sabes, pelo que Lee Chung te contou, que o[ENTER]ant\237doto pode ser encontrado no Bosque Rubro.[ENTER]Captura %d Dr\237ades Rubras para o conseguires.[ENTER][ENTER]No Bosque Rubro existem perigos ainda maiores do[ENTER]que os que existem na Floresta Fantasma, por isso[ENTER]tem cuidado. "
gameforge.main_quest_lv66._40_say = "Derrotaste o Rei Dem\243nio e recebeste o di\225rio da[ENTER]Sacerdotisa do Drag\227o. Leva-o ao Uriel. Ele ir\225[ENTER]analis\225-lo. "
gameforge.main_quest_lv66._410_say = "O tempo terminou. O soldado est\225 a morrer.[ENTER]Leva-lhe o ant\237doto o mais r\225pido poss\237vel. "
gameforge.main_quest_lv66._420_say = "Tens mais %d minutos. "
gameforge.main_quest_lv66._430_say = "Finalmente encontraste o ant\237doto! R\225pido, leva-o[ENTER]a Lee Chung! "
gameforge.main_quest_lv66._440_say = "Aqui, r\225pido! Acho que chegaste no momento certo.[ENTER]Isto \233 um enorme peso que sai de cima do meu[ENTER]peito. Eu e os meus homens estamos extremamente[ENTER]gratos pelo que fizeste. "
gameforge.main_quest_lv66._450_say = "Gra\231as \224 tua ajuda, o meu soldado sobreviveu.[ENTER]Aqui tens a tua recompensa por teres conseguido[ENTER]salv\225-lo. "
gameforge.main_quest_lv66._460_say = "Levaste o teu tempo. Ele est\225 agarrado \224 vida com[ENTER]toda a sua for\231a. Mas felizmente chegaste a[ENTER]tempo. "
gameforge.main_quest_lv66._470_say = "Ele parece estar a voltar a si. Mas foi por pouco[ENTER]- ele quase morreu por teres demorado tanto a[ENTER]encontrar o ant\237doto. Desculpa, mas isto \233 tudo o[ENTER]que te posso dar como recompensa. "
gameforge.main_quest_lv66._480_sendLetter = "O Relat\243rio "
gameforge.main_quest_lv66._490_say = "O batedor recuperou a consci\234ncia. Presta aten\231\227o[ENTER]ao relato do que ele observou enquanto este nas[ENTER]Catacumbas do Dem\243nio. "
gameforge.main_quest_lv66._500_say = "Obrigado por me salvares. Vi coisas[ENTER]inacredit\225veis nas Catacumbas do Dem\243nio. Mas[ENTER]ent\227o fui descoberto, e... "
gameforge.main_quest_lv66._50_say = "Encontraste-o! O di\225rio da \250ltima Sacerdotisa do[ENTER]Drag\227o. As minha m\227os est\227o a tremer de[ENTER]antecipa\231\227o! Vou precisar de algum tempo para[ENTER]analisar o seu conte\250do. Aproveita este tempo[ENTER]para descansares. Irei chamar-te quando tiver[ENTER]mais para te contar. "
gameforge.main_quest_lv66._510_say = "O que viste? "
gameforge.main_quest_lv66._520_say = "Havia pessoas em mantos negros com um capuz a[ENTER]cobrir-lhes a cara. Peda\231os da sua conversa[ENTER]permitiram-me deduzir que eram Servos das Trevas.[ENTER]Mas n\227o \233 tudo: Um esp\237rito fantasmag\243rico, na[ENTER]forma de uma mulher, flutuava sobre as suas[ENTER]cabe\231as. Os Servos das Trevas chamavam-lhe[ENTER]Banshee. "
gameforge.main_quest_lv66._530_say = "Isso n\227o soa bem... O que ser\225 que os Servos das[ENTER]Trevas e esta Banshee est\227o a tramar? "
gameforge.main_quest_lv66._540_say = "A Banshee invocou os Agwi, criaturas demon\237acas[ENTER]vindas directamente dos confins do inferno,[ENTER]usando magia negra. Eles chamam Azrael ao Rei dos[ENTER]Agwi. "
gameforge.main_quest_lv66._550_say = "Tentei sair \224 pressa para informar Lee Chung[ENTER]desta descoberta. Mas tropecei e fui descoberto.[ENTER][ENTER]Ah! Acabei de me lembrar... O Comandante Lee[ENTER]Chung tem algo importante para te dizer. Se fosse[ENTER]a ti, ia agora ter com ele. "
gameforge.main_quest_lv66._560_sendLetter = "Amea\231a das Trevas "
gameforge.main_quest_lv66._570_say = "Vai ter com Lee Chung e fala com ele sobre a nova[ENTER]amea\231a que se esconde nas Catacumbas do Dem\243nio. "
gameforge.main_quest_lv66._580_say = "O que os meus batedores relataram \233 assustador,[ENTER]n\227o \233? Os Servos das Trevas, uma esp\233cie de[ENTER]culto, s\227o os respons\225veis pelo surgimento dos[ENTER]Agwi. Eles tamb\233m ergueram o esp\237rito da \250ltima[ENTER]Sacerdotisa do Drag\227o. Ela voltou a este mundo[ENTER]como Banshee, uma manifesta\231\227o do mal e, usando[ENTER]os seus poderes m\225gicos, poder\225 em breve invocar[ENTER]o Deus Dem\243nio Sung Mahi. "
gameforge.main_quest_lv66._590_say = "O qu\234?! Esta Banshee \233 o esp\237rito da \250ltima[ENTER]Sacerdotisa do Drag\227o?! "
gameforge.main_quest_lv66._600_say = "Sem d\250vida. Mesmo entre as irm\227s do culto do[ENTER]Drag\227o, apenas ela possu\237a o poder de invocar os[ENTER]quatro sagrados Sentinelas Celestiais e de[ENTER]executar a magia negra. Agora sabemos quem est\225[ENTER]por detr\225s desta nova amea\231a: estes Servos das[ENTER]Trevas, juntamente com a Banshee, est\227o a planear[ENTER]completar a miss\227o da Na\231\227o das Trevas e[ENTER]despertar Sung Mahi! "
gameforge.main_quest_lv66._60_sendLetter = "A Solu\231\227o do Puzzle "
gameforge.main_quest_lv66._610_say = "Temos muito para te agradecer: salvaste um dos[ENTER]meus homens de uma morte certa e, gra\231as a isso,[ENTER]fomos capazes de aprender mais sobre a s\250bita[ENTER]apari\231\227o dos Agwi e a amea\231a mais recente das[ENTER]Catacumbas do Dem\243nio. Tira algum tempo para[ENTER]descansares antes de come\231armos a pensar numa[ENTER]t\225ctica adequada. "
gameforge.main_quest_lv66._620_say = "A aventura continuar\225 quando tiveres atingido o[ENTER]n\237vel 72. "
gameforge.main_quest_lv66._70_say = "O Uriel est\225 \224 tua procura. Ele j\225 leu o di\225rio. "
gameforge.main_quest_lv66._80_say = "Ah, maravilhoso. Aqui est\225s tu.[ENTER]As cr\243nicas da \250ltima Sacerdotisa do Drag\227o s\227o[ENTER]verdadeiramente espantosas. Ouve bem: "
gameforge.main_quest_lv66._90_say = "O meu destino est\225 selado! Barriquei-me num andar[ENTER]superior desta torre e os homens de Lee Seop[ENTER]est\227o prestes a quebrar a porta da minha pris\227o[ENTER]final. N\227o h\225 escapat\243ria. Perdi.[ENTER][ENTER]N\227o! Isto n\227o pode acabar assim! Nem tudo pode[ENTER]estar decidido pelo destino. Preciso de executar[ENTER]a magia negra, esse antigo poder maligno, e, por[ENTER]mim mesma, invocar as for\231as das trevas. Ir\225[ENTER]certamente ser a minha morte. Mas os meus[ENTER]inimigos ir\227o ter o mesmo destino que eu, nem que[ENTER]seja a \250ltima coisa que eu fa\231a! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "O qu\234, ainda n\227o a entregaste? A Cana de Pesca \233[ENTER]para o Pescador no rio.[ENTER]Despacha-te, ele precisa dela urgentemente! "
gameforge.main_quest_lv7._10_targetVid = "Outro favor "
gameforge.main_quest_lv7._110_npcChat = "O Ferreiro enviou-te esta nova Cana! "
gameforge.main_quest_lv7._120_say = "Obrigado. Agora posso finalmente livrar-me da[ENTER]minha fiel, mas gasta, Cana de Pesca.[ENTER]Eu n\227o me sustento apenas da pesca, mas \233 uma das[ENTER]grandes alegrias na minha vida! Percebes alguma[ENTER]coisa de pesca? "
gameforge.main_quest_lv7._130_say = "Agora pega na Cana de Pesca e coloca um isco no[ENTER]anzol clicando em cima dele. Depois atira a[ENTER]linha, clicando na tua habilidade de Pesca.[ENTER]Quando achares que apanhaste um peixe usa a[ENTER]habilidade de novo. Se n\227o apanhaste, tenta de[ENTER]novo.[ENTER]Estas \225guas s\227o muito boas para a pesca gra\231as \224[ENTER]sua biodiversidade. O peixe \233 nutritivo e[ENTER]saud\225vel, e podes at\233 conseguir apanhar v\225rios[ENTER]tesouros valiosos. Devias experimentar. "
gameforge.main_quest_lv7._140_say = "Ah sim, aqui est\225 o pagamento pela Cana de Pesca.[ENTER]Por favor entrega-o ao Ferreiro quando[ENTER]regressares \224 vila. "
gameforge.main_quest_lv7._150_sayItem = "Recibo de entrega da cana de pesca "
gameforge.main_quest_lv7._160_sayReward = "Entregaste a Cana de Pesca ao Pescador. Regressa[ENTER]ao Ferreiro com o pagamento e ir\225s receber a tua[ENTER]recompensa. "
gameforge.main_quest_lv7._170_say = "Encontraste o Pescador?[ENTER]\211ptimo, poupaste-me algum tempo valioso ao[ENTER]fazeres esta entrega. Como recompensa irei dar-te[ENTER]algum Yang e 1.500 Pontos de Experi\234ncia. "
gameforge.main_quest_lv7._180_sendLetter = "Voucher "
gameforge.main_quest_lv7._190_sayReward = "Com este voucher, o Ferreiro ir\225 melhorar uma[ENTER]pe\231a do teu Equipamento gratuitamente. Arrasta o[ENTER]item que queres melhorar para cima do Ferreiro[ENTER]para abrires o menu de Melhoramento. "
gameforge.main_quest_lv7._200_sayItem = "Voucher para um melhoramento gr\225tis "
gameforge.main_quest_lv7._20_sayReward = "Por favor vai ter com o Ferreiro. Ele precisa de[ENTER]algu\233m para fazer uma entrega. "
gameforge.main_quest_lv7._210_sayTitle = "Dica: "
gameforge.main_quest_lv7._220_sayReward = "1) O Voucher n\227o aparecer\225 no Invent\225rio.[ENTER]2) Um refinamento bem-sucedido - tal como em[ENTER]qualquer outra altura - n\227o \233 100% garantido. "
gameforge.main_quest_lv7._230_sayTitle = "O Voucher j\225 foi usado. "
gameforge.main_quest_lv7._240_sayReward = "J\225 usaste o voucher para um refinamento gr\225tis.[ENTER]Apenas \233 v\225lido para um refinamento. "
gameforge.main_quest_lv7._30_say = "Ol\225 aventureiro! Poderias fazer-me outro favor?[ENTER]Normalmente n\227o pe\231o a outras pessoas para[ENTER]fazerem coisas por mim, mas pareces ser de[ENTER]confian\231a. Pensa nisto como uma honra! "
gameforge.main_quest_lv7._40_say = "Criei uma Cana de Pesca para o Pescador, mas[ENTER]infelizmente estou muito ocupado. N\227o tenho tempo[ENTER]para ir lev\225-la ao Pescador. Podes fazer isso por[ENTER]mim? "
gameforge.main_quest_lv7._50_sayItem = "Um cana de pesca muito flex\237vel "
gameforge.main_quest_lv7._60_say = "O Pescador dever\225 estar perto do rio. Se lhe[ENTER]entregares a Cana de Pesca irei melhorar uma pe\231a[ENTER]do teu equipamento gratuitamente. \201 um neg\243cio[ENTER]justo, n\227o achas? "
gameforge.main_quest_lv7._70_sendLetter = "Encontra o Pescador "
gameforge.main_quest_lv7._80_sayReward = "O Ferreiro fez uma cana de pesca para o Pescador.[ENTER]Encontra o Pescador junto ao rio e entrega-lhe a[ENTER]cana de pesca. "
gameforge.main_quest_lv7._90_npcChat = "Para quem \233 a Cana de Pesca? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "A L\225grima Celestial recebe o seu brilho perfeito[ENTER]do un\237ssono m\225gico entre a Resina da \193rvore[ENTER]Sagrada, a Ess\234ncia de Cristal Azul e o Quartzo[ENTER]Infernal.[ENTER]A Ess\234ncia de Cristal Azul tem de ser obtida do[ENTER]soberano da Terra do Gelo. "
gameforge.main_quest_lv72._10_sendLetter = "Tabuleta de Pedra Gasta "
gameforge.main_quest_lv72._110_say = "Tomaste nota desta surpreendente inscri\231\227o.[ENTER]Relata a Lee Chung aquilo que acabaste de ler. "
gameforge.main_quest_lv72._120_say = "Ah, regressaste a salvo! Se leio correctamente a[ENTER]tua cara, assumo que foste bem-sucedido? "
gameforge.main_quest_lv72._130_say = "Na verdade, sim! Gra\231as \224 inscri\231\227o presente na[ENTER]Tabuleta de Pedra Gasta, consegui descobrir que \233[ENTER]poss\237vel invocar os poderes sagrados usando uma[ENTER]pedra preciosa m\225gica, conhecida como L\225grima[ENTER]Celestial. "
gameforge.main_quest_lv72._140_say = "A L\225grima Celestial... ent\227o ela existe mesmo.[ENTER]Descobriste alguma pista sobre como a poderemos[ENTER]obter? "
gameforge.main_quest_lv72._150_say = "Para produzir uma L\225grima Celestial \233 preciso[ENTER]Resina da \193rvore Sagrada, Ess\234ncia de Cristal[ENTER]Azul e Quartzo Infernal. Diz-se que a Ess\234ncia de[ENTER]Cristal Azul tem de ser obtida do soberano da[ENTER]Terra do Gelo. "
gameforge.main_quest_lv72._160_say = "O soberano da Terra do Gelo? Hmm... Deve[ENTER]referir-se \224 Montanha Sohan.[ENTER]Irei mostrar as tuas notas aos magos dos[ENTER]Guerreiros da Sombra e irei analis\225-las com eles.[ENTER]Irei informar-te quando souber mais! "
gameforge.main_quest_lv72._170_say = "Toma isto como recompensa pelas tuas ac\231\245es. Irei[ENTER]continuar a contar com a tua ajuda! "
gameforge.main_quest_lv72._180_sendLetter = "Tesouro Gelado "
gameforge.main_quest_lv72._190_say = "O comandante Lee Chung informou-te que o primeiro[ENTER]elemento necess\225rio para a produ\231\227o da L\225grima[ENTER]Celestial, a Ess\234ncia de Cristal Azul, est\225[ENTER]relacionado com o lend\225rio tesouro do Nove Caudas[ENTER]na Montanha Sohan. Ele \233 protegido por Golems do[ENTER]Gelo, Yetis e Homens do Gelo. Ca\231a estes monstros[ENTER]para tentares obter a Ess\234ncia de Cristal Azul.[ENTER]Volta a falar com Lee Chung antes de te dirigires[ENTER]para o combate. "
gameforge.main_quest_lv72._200_say = "Os magos dos Guerreiros da Sombra descobriram que[ENTER]o terr\237vel Nove Caudas da Montanha Sohan guarda a[ENTER]Ess\234ncia de Cristal Azul como se da sua vida se[ENTER]tratasse. "
gameforge.main_quest_lv72._20_say = "Lee Chung, comandante dos Guerreiros da Sombra,[ENTER]gostaria de falar contigo. Eles descobriu como[ENTER]podes derrotar os Agwi nas Catacumbas do Dem\243nio. "
gameforge.main_quest_lv72._210_say = "O tesouro do Nove Caudas \233 guardado por Golems do[ENTER]Gelo, Yetis e Homens do Gelo.[ENTER][ENTER]S\227o necess\225rias 50 Ess\234ncias de Cristal Azul para[ENTER]produzir a L\225grima Celestial. "
gameforge.main_quest_lv72._220_say = "Acredita-se que o Quartzo Infernal esteja[ENTER]localizado no Templo Hwang ou na Terra do Fogo.[ENTER]Enviei batedores para descobrir mais. "
gameforge.main_quest_lv72._230 = "O comandante Lee Chung informou-te que o primeiro[ENTER]elemento necess\225rio para a produ\231\227o da L\225grima[ENTER]Celestial, a Ess\234ncia de Cristal Azul, est\225[ENTER]relacionado com o lend\225rio tesouro do Nove Caudas[ENTER]na Montanha Sohan. Ele \233 protegido por Golems do[ENTER]Gelo, Yetis e Homens do Gelo. Ca\231a estes monstros[ENTER]para tentares obter a Ess\234ncia de Cristal Azul. "
gameforge.main_quest_lv72._240_notice = "Procuras entre os corpos dos monstros derrotados[ENTER]e encontras uma pedra preciosa azul e reluzente.[ENTER]Tem de ser a Ess\234ncia de Cristal Azul. "
gameforge.main_quest_lv72._250_notice = "Tens de encontrar %d Ess\234ncia(s) de Cristal Azul. "
gameforge.main_quest_lv72._260_say = "Acho que j\225 recebeste conselhos suficientes por[ENTER]hoje. Volta de manh\227. "
gameforge.main_quest_lv72._270_say = "Estes cristais n\227o me servem de nada. V\234 por ti[ENTER]mesmo: est\227o rachados. Para os poder usar, n\227o[ENTER]podem ter qualquer falha! Continua \224 procura! "
gameforge.main_quest_lv72._280_say = "Estes s\227o de excelente qualidade! Continua assim![ENTER]S\243 preciso de mais %d. "
gameforge.main_quest_lv72._290_say = "Recolheste todas as Ess\234ncias de Cristal Azul que[ENTER]precis\225vamos. Sinto o poder do Nove Caudas no seu[ENTER]interior. Fant\225stico... Elas est\227o literalmente a[ENTER]vibrar com a energia. Muito bem! "
gameforge.main_quest_lv72._300_say = "A aventura continuar\225 quando atingires o n\237vel 78. "
gameforge.main_quest_lv72._30_say = "Ao contr\225rio dos dem\243nios a que estamos[ENTER]habituados, n\227o podes simplesmente matar um Agwi.[ENTER]N\243s, Guerreiros da Sombra, j\225 tent\225mos usar todos[ENTER]os m\233todos que conseguimos imaginar - tudo sem[ENTER]sucesso. "
gameforge.main_quest_lv72._40_say = "Mas agora descobri que as Sacerdotisas do Drag\227o[ENTER]possu\237am o poder de invocar esp\237ritos sagrados[ENTER]para banir os esp\237ritos demon\237acos. "
gameforge.main_quest_lv72._50_say = "No Bosque Rubro existia um dos templos sagrados[ENTER]das Sacerdotisas do Drag\227o. Vai at\233 ao Bosque e[ENTER]procura pelas ru\237nas e por quaisquer sinais do[ENTER]seu culto. Alguns batedores trouxeram relatos de[ENTER]uma tabuleta gasta, feita de pedra, que est\225[ENTER]coberta por matagal... Talvez possamos descobrir[ENTER]nela algo de \250til. "
gameforge.main_quest_lv72._60_sendLetter = "A Descoberta "
gameforge.main_quest_lv72._70_say = "Lee Chung contou-te que as Sacerdotisas do Drag\227o[ENTER]eram capazes de invocar poderes sagrados, uma[ENTER]antiga magia branca, capazes de banir esp\237ritos[ENTER]malignos. Procura a Tabuleta de Pedra Gasta de[ENTER]que Lee Chung falou no Bosque Rubro para[ENTER]descobrirem mais informa\231\245es. "
gameforge.main_quest_lv72._80_say = "Ao fim de uma longa busca, cruzas-te com uma[ENTER]tabuleta de pedra na vegeta\231\227o rasteira que[ENTER]parece estar ali perdida h\225 s\233culos. Tem de ser a[ENTER]velha tabuleta de que Lee Chung falava![ENTER]Minuciosamente, tentas decifrar a inscri\231\227o[ENTER]gasta. "
gameforge.main_quest_lv72._90_say = "A L\225grima Celestial \233 o segredo mais valioso das[ENTER]Sacerdotisas do Drag\227o. A arte da sua produ\231\227o[ENTER]foi mantida secreta durante gera\231\245es e, em casos[ENTER]extremos, defendida com sangue. Um Agwi e os seus[ENTER]dem\243nios n\227o se conseguem aproximar do portador[ENTER]desta pedra preciosa m\225gica. Se a L\225grima[ENTER]Celestial for previamente repleta com a for\231a dos[ENTER]poderes sagrados, os seus efeitos tornam-se[ENTER]esmagadores. Ela brilha tanto quanto a Estrela[ENTER]Polar no firmamento. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah, fant\225stico! Funcionou. Aqui tens o teu[ENTER]Quartzo Infernal. "
gameforge.main_quest_lv78._10_sendLetter = "Quartzo Infernal "
gameforge.main_quest_lv78._110_sendLetter = "Elemento Final "
gameforge.main_quest_lv78._120_say = "Lee Chung e o conselho de magos descobriram que[ENTER]podes obter o elemento final, a Resina da \193rvore[ENTER]Sagrada, das \193rvores do Mal Vermelhas. Ca\231a-as no[ENTER]Bosque Rubro e recolhe 100 por\231\245es de Resina.[ENTER]Fala com Lee Chung antes de partires. "
gameforge.main_quest_lv78._130_say = "Lee Chung e o conselho de magos descobriram que[ENTER]podes obter o elemento final, a Resina da \193rvore[ENTER]Sagrada, das \193rvores do Mal Vermelhas. Ca\231a-as no[ENTER]Bosque Rubro e recolhe 100 por\231\245es de Resina. "
gameforge.main_quest_lv78._140_say = "Este \233 o \250ltimo passo na produ\231\227o da L\225grima[ENTER]Celestial. Tem cuidado contigo, pois o Bosque[ENTER]Rubro est\225 apinhado de criaturas mort\237feras! "
gameforge.main_quest_lv78._150_say = "Ainda precisas de %d unidade(s) de Resina da[ENTER]\193rvore Sagrada. "
gameforge.main_quest_lv78._160_notice = "J\225 encontraste Resina da \193rvore Sagrada[ENTER]suficiente! Leva-a ao comandante Lee Chung. "
gameforge.main_quest_lv78._170_say = "Essa \233 a Resina da \193rvore Sagrada? Consigo sentir[ENTER]o seu enorme poder. Fant\225stico! Infelizmente tive[ENTER]de enviar todos os magos numa miss\227o. Eles ir\227o[ENTER]demorar a voltar. N\227o existe um alquimista na tua[ENTER]cidade-natal chamado Baek-Go? "
gameforge.main_quest_lv78._180_say = "Sim, por acaso existe. "
gameforge.main_quest_lv78._190_say = "Ah, soberbo! Pega nos 3 elementos e vai ter com[ENTER]Baek-Go. Ele ser\225 capaz de criar a L\225grima[ENTER]Celestial a partir deles. "
gameforge.main_quest_lv78._200_say = "Percorreste uma longa e exaustiva viagem. Por[ENTER]favor, aceita esta recompensa por todos os teus[ENTER]esfor\231os. "
gameforge.main_quest_lv78._20_say = "Lee Chung, comandante dos Guerreiros da Sombra,[ENTER]descobriu mais sobre o Quartzo Infernal. Para o[ENTER]produzires precisas de tr\234s subst\226ncias[ENTER]diferentes: Terra Vulc\226nica de Doyyumhwan, Jubas[ENTER]Flamejantes e Pedras Basilares. Ca\231a Chamas,[ENTER]Guerreiros Chama e Tigres de Fogo para obteres[ENTER]estas subst\226ncias e junta 20 de cada para formar[ENTER]um Quartzo Infernal.[ENTER]Fala com Lee Chung antes de partires para o[ENTER]combate. "
gameforge.main_quest_lv78._210_sendLetter = "L\225grima Celestial "
gameforge.main_quest_lv78._220_say = "Regressa \224 tua cidade-natal, encontra o Baek-Go[ENTER]e, em nome de Lee Chung, pede-lhe para criar uma[ENTER]L\225grima Celestial a partir dos 3 elementos. "
gameforge.main_quest_lv78._230_say = "Estiveste afastado daqui algum tempo. Estava a[ENTER]come\231ar a interrogar-me sobre o que te poderia[ENTER]ter acontecido. O que te traz at\233 mim? "
gameforge.main_quest_lv78._240_say = "Lee Chung pediu-me para vir ter contigo para um[ENTER]favor. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! O comandante dos Guerreiros da Som...[ENTER]Oh! Shhhhh! Sil\234ncio! Perante ti encontra-se um[ENTER]mago dos Guerreiros da Sombra. Mas essa[ENTER]informa\231\227o \233 altamente secreta. Ningu\233m na vila[ENTER]pode ter conhecimento disto.[ENTER]Que favor \233 que Lee Chung pretende que lhe fa\231a? "
gameforge.main_quest_lv78._260_say = "Ele pede que cries uma L\225grima Celestial a partir[ENTER]destes 3 elementos. "
gameforge.main_quest_lv78._270_say = "Uma L\225grima Celestial... Ele tem tantos magos ao[ENTER]seu dispor... Porque \233 que ele me deixa sempre as[ENTER]tarefas mais dif\237ceis?![ENTER]...[ENTER]OK. Vamos l\225 ent\227o... L\225grima Celestial.[ENTER]Maravilhoso! Irei envi\225-la directamente a Lee[ENTER]Chung atrav\233s de um mensageiro e ele ir\225 mandar[ENTER]chamar-te quando tudo estiver pronto. Podes[ENTER]dizer-me para que ir\225 servir? "
gameforge.main_quest_lv78._280_say = "N\227o posso revelar nada espec\237fico. Apenas isto:[ENTER]esta pedra invoca poderes sagrados para banir[ENTER]dem\243nios e outras criaturas malignas. "
gameforge.main_quest_lv78._290_say = "Muito interessante. Desejo-te o maior sucesso na[ENTER]tua miss\227o. Como recompensa pelas tuas ac\231\245es at\233[ENTER]agora, aqui tens 2 Cabe\231as Encolhidas. Agora que[ENTER]sei como o processo funciona, ficarei contente[ENTER]por poder ajudar-te caso precises de mais[ENTER]L\225grimas Celestiais no futuro.[ENTER]Oh... E podes enviar os meus cumprimentos a Lee[ENTER]Sung tamb\233m? "
gameforge.main_quest_lv78._300_say = "A aventura continuar\225 quando atingires o n\237vel 84. "
gameforge.main_quest_lv78._30_say = "Os nossos magos descobriram que o Quartzo[ENTER]Infernal necess\225rio para a produ\231\227o da L\225grima[ENTER]Celestial cont\233m no seu interior o poder do fogo.[ENTER]Este Quartzo deve tamb\233m ser a causa da for\231a[ENTER]inacredit\225vel das criaturas da Terra do Fogo. "
gameforge.main_quest_lv78._40_say = "O Quartzo Infernal pode ser criado com 3[ENTER]subst\226ncias: Terra Vulc\226nica, Juba Flamejante e[ENTER]Pedra Basilar. Podes encontr\225-las a todas na[ENTER]Terra do Fogo. "
gameforge.main_quest_lv78._50_say = "Conseguiste! Finalmente temos os %d peda\231os de[ENTER]Quartzo Infernal que precis\225vamos. A tua coragem[ENTER]e for\231a voltaram a exceder as minhas[ENTER]expectativas. "
gameforge.main_quest_lv78._60_say = "Falta uma subst\226ncia. Precisamos de Terra[ENTER]Vulc\226nica, Juba Flamejante e Pedra Basilar. "
gameforge.main_quest_lv78._70_say = "Desculpa, mas apenas posso produzir 7 peda\231os de[ENTER]Quartzo Infernal por dia. Este procedimento \233 um[ENTER]desafio \224s minhas habilidades m\225gicas. N\227o sou um[ENTER]mago! "
gameforge.main_quest_lv78._80_say = "Ora bem! Irei agora misturar as tr\234s subst\226ncias[ENTER]e tentar criar um Quartzo Infernal. "
gameforge.main_quest_lv78._90_say = "Argh! A magia falhou. Aparentemente sobrestimei[ENTER]as minhas capacidades m\225gicas. Da pr\243xima vez ir\225[ENTER]funcionar melhor, de certeza. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Agora que derrotaste o General Tartaros, foi[ENTER]aberta uma entrada para um andar das Catacumbas[ENTER]do Dem\243nio at\233 agora desconhecido. O Pr\237ncipe[ENTER]Charon deve encontrar-se l\225 em baixo![ENTER]Teleporta-te para o sexto andar e enfrenta o[ENTER]pr\237ncipe Agwi. Mas tem cuidado! Ele \233[ENTER]extremamente forte e astuto que nem um dem\243nio. "
gameforge.main_quest_lv84._10_sendLetter = "A Luta Come\231a "
gameforge.main_quest_lv84._110_say = "A forma como te moves pelas Catacumbas do Dem\243nio[ENTER]- livremente e sem medo - \233 imposs\237vel tu seres[ENTER]um mero mortal! O obelisco de basalto no quinto[ENTER]andar ir\225 servir de portal para um sexto andar[ENTER]escondido. "
gameforge.main_quest_lv84._120_say = "\201 de l\225 que o Pr\237ncipe Charon envia as suas[ENTER]ordens para o General-Agwi Tartaros.[ENTER]De que est\225s \224 espera? Derrota Charon e contraria[ENTER]os planos sinistros dos Servos das Trevas e da[ENTER]Banshee! "
gameforge.main_quest_lv84._130_sayReward = "Conseguiste! Charon, o Pr\237ncipe Agwi, foi[ENTER]aniquilado. "
gameforge.main_quest_lv84._140_say = "Exausto mas aliviado, limpas o suor da tua testa.[ENTER]Subitamente, um riso arrepiante ecoa pelas[ENTER]Catacumbas do Dem\243nio, t\227o penetrante que te gela[ENTER]a espinha:[ENTER]Ahahahaha! Demasiado tarde, humanos pat\233ticos! O[ENTER]nosso mestre Sung Mahi j\225 foi despertado e n\227o h\225[ENTER]nada que possam agora fazer para o travar! Ir\225[ENTER]chegar o dia em que Sung Mahi recuperar\225 todas as[ENTER]suas for\231as na ilha onde os drag\245es do mal[ENTER]dormem.[ENTER]O vosso mundo est\225 condenado! "
gameforge.main_quest_lv84._150_sendLetter = "Hist\243ria Inacabada "
gameforge.main_quest_lv84._160_say = "Vai ter com Lee Chung e relata-lhe a mensagem[ENTER]amea\231adora da Banshee. "
gameforge.main_quest_lv84._170_say = "Depois de relatares as tuas vit\243rias sobre[ENTER]Tartaros e Charon ao comandante, repetes a[ENTER]assustadora mensagem da Banshee. Ele come\231a a[ENTER]falar, com um ar s\233rio: "
gameforge.main_quest_lv84._180_say = "Assumi que assim que derrot\225ssemos o Pr\237ncipe[ENTER]Agwi ir\237amos impedir os planos dos Servos das[ENTER]Trevas e da Banshee. Como eu estava errado... "
gameforge.main_quest_lv84._190_say = "A Banshee deve ter conseguido completar a[ENTER]ressurrei\231\227o de Sung Mahi juntamente com Azrael,[ENTER]o Rei Agwi. Tremo s\243 de pensar nisso... "
gameforge.main_quest_lv84._200_say = "A ilha onde os drag\245es do mal dormem... Hmm, deve[ENTER]referir-se \224 Rocha do Drag\227o Negro. \201 uma ilha[ENTER]inexplorada, muito longe daqui.[ENTER]Mesmo que n\227o tenhamos conseguido o que[ENTER]quer\237amos, ainda te devemos uma grande quantidade[ENTER]de gratid\227o. Sem a tua ajuda, poder\237amos nunca[ENTER]ter descoberto a causa do mal que deambulava nas[ENTER]profundezas das Catacumbas do Dem\243nio. "
gameforge.main_quest_lv84._20_say = "Lee Chung recebeu a L\225grima Celestial e preparou[ENTER]tudo para a tua miss\227o nas Catacumbas do Dem\243nio.[ENTER]Vai ter com ele para descobrires mais. "
gameforge.main_quest_lv84._210_say = "Conseguiste grandes feitos. Feitos que ningu\233m[ENTER]al\233m de ti seria capaz de conseguir. Irei estar[ENTER]ao teu lado sempre que precisares, pelo resto da[ENTER]minha vida. Adeus! "
gameforge.main_quest_lv84._30_say = "Agora que estamos na posse da L\225grima Celestial,[ENTER]\233 apenas uma quest\227o de tempo at\233 derrotarmos os[ENTER]Servos das Trevas e banirmos os Agwi do nosso[ENTER]mundo! Mas o poder completo da L\225grima apenas[ENTER]ser\225 libertado se for usada numa localiza\231\227o[ENTER]espec\237fica das Catacumbas do Dem\243nio. "
gameforge.main_quest_lv84._40_say = "Temos conhecimento de 5 andares nas Catacumbas do[ENTER]Dem\243nio. No quinto e \250ltimo andar de que temos[ENTER]conhecimento, ir\225s cruzar-te com Tartaros, o[ENTER]terr\237vel General Agwi e terceiro na linha de[ENTER]comando atr\225s do Rei Azrael e Charon. Derrota-o[ENTER]com a ajuda da L\225grima Celestial! "
gameforge.main_quest_lv84._50_say = "Mas onde est\225 Charon? "
gameforge.main_quest_lv84._60_sendLetter = "General Tartaros "
gameforge.main_quest_lv84._70_say = "Usa a L\225grima Celestial apenas quando tiveres[ENTER]atingido o quinto andar das Catacumbas do[ENTER]Dem\243nio.[ENTER]A entrada para as Catacumbas do Dem\243nio pode ser[ENTER]encontrada nas traseiras da Torre Demon\237aca. "
gameforge.main_quest_lv84._80_say = "Os poderes sagrados come\231am a ter efeito atrav\233s[ENTER]da L\225grima Celestial. Sentes um poder tremendo a[ENTER]correr pelo teu corpo. O poder desta pedra[ENTER]preciosa \233 alucinante![ENTER][ENTER]Derrota o General Tartaros. "
gameforge.main_quest_lv84._90_sendLetter = "Pr\237ncipe Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Encontra o Guarda da Cidade "
gameforge.main_quest_lv9._20_sendLetter = "Fala com o Guarda da Cidade "
gameforge.main_quest_lv9._30_sayReward = "Deste os teus primeiros passos no caminho para[ENTER]seres um verdadeiro her\243i. Est\225 na hora de[ENTER]maiores responsabilidades. Vai ter com o Guarda[ENTER]da Cidade e recebe a tua \250ltima miss\227o de[ENTER]inicia\231\227o. "
gameforge.main_quest_lv9._40_say = "Est\225s pronto para enfrentar algumas tarefas mais[ENTER]dif\237ceis? Lembra-te que as miss\245es simples acabam[ENTER]assim que decidires come\231ar a combater pelo teu[ENTER]Reino. Ter\225s de ultrapassar muitos combates e[ENTER]bastante sofrimento. Por isso mant\233m a guarda.[ENTER]Aqui tens uma recompensa pelo teu esfor\231o. Espero[ENTER]que te seja \250til. "
gameforge.main_quest_lv9._50_say = "A partir de agora o Capit\227o ir\225 guiar-te. Ele ir\225[ENTER]orientar o teu progresso e dar-te miss\245es para te[ENTER]treinar. Pratica os teus combates e depois vai[ENTER]ter com ele. Boa sorte! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Rocha do Drag\227o Negro "
gameforge.main_quest_lv90._020_say = "A tua viagem foi longa e \225rdua. Mas agora[ENTER]finalmente chegaste ao teu destino: a Rocha do[ENTER]Drag\227o Negro.[ENTER]Procura o Almirante Angmur. Ir\225s encontr\225-lo no[ENTER]Cabo Fogo de Drag\227o. "
gameforge.main_quest_lv90._030_say = "Bem-vindo \224 Rocha do Drag\227o Negro, estranho![ENTER]Vieste ajudar-nos na luta contra Sung Mahi? "
gameforge.main_quest_lv90._040_say = "Sim, certamente. Lee Chung, Comandante dos[ENTER]Guerreiros da Sombra, enviou-me. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Ele \233 um antigo camarada meu. Ent\227o[ENTER]est\225s aqui a seu pedido... Muito bem, ent\227o sei[ENTER]que posso confiar em ti. "
gameforge.main_quest_lv90._060_say = "Obrigado. Qual \233 a situa\231\227o aqui? "
gameforge.main_quest_lv90._070_say = "Os dem\243nios governam grandes por\231\245es da ilha.[ENTER]Nada e ningu\233m est\225 a salvo. Eles at\233 se comem[ENTER]uns aos outros. A influ\234ncia negra de Sung Mahi[ENTER]fez com que enlouquecessem. "
gameforge.main_quest_lv90._080_say = "Preciso da tua ajuda. Podes explorar a ilha e[ENTER]trazer-me um relat\243rio actualizado da situa\231\227o? "
gameforge.main_quest_lv90._090_say = "Claro. "
gameforge.main_quest_lv90._1000_say = "Percebido. "
gameforge.main_quest_lv90._100_say = "Obrigado. Espera, vou mostrar-te o caminho. "
gameforge.main_quest_lv90._1010_say = "\201s muito diligente, mas isso n\227o \233 suficiente.[ENTER]Continua a recolher! "
gameforge.main_quest_lv90._1020_sayTitle = "Recolher Tijolos de Barro "
gameforge.main_quest_lv90._1030_say = "Vai combater as mant\237coras para recolheres[ENTER]Tijolos de Barro. "
gameforge.main_quest_lv90._1040_1_notice = "J\225 recolheste Tijolos de Barro suficientes. "
gameforge.main_quest_lv90._1040_2_notice = "Entrega-os ao Almirante Angmur. "
gameforge.main_quest_lv90._1050_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv90._1060_say = "Muito bem, gra\231as a ti temos materiais[ENTER]suficientes para fortalecer o baluarte defensivo.[ENTER]Assim que isso estiver terminado, irei mandar[ENTER]algu\233m chamar-te. "
gameforge.main_quest_lv90._1070_sendLetter = "Tarefa de Lee Chung "
gameforge.main_quest_lv90._1080_say = "Lee Chung tem uma tarefa para ti. "
gameforge.main_quest_lv90._1090_say = "Infelizmente algumas m\225s not\237cias fazem com que[ENTER]nos voltemos a encontrar: os Servos das Trevas[ENTER]est\227o mais pr\243ximos do seu objectivo. Em breve,[ENTER]Sung Mahi ir\225 tornar-se invenc\237vel.[ENTER]N\227o temos tempo a perder! Vai ter com o[ENTER]teleportador. A partir da\237, um navio ir\225 levar-te[ENTER]at\233 \224 Rocha do Drag\227o Negro. L\225, procura o[ENTER]Almirante Angmur. J\225 enviei uma carta a anunciar[ENTER]a tua chegada. "
gameforge.main_quest_lv90._1100_say = "Irei p\244r-me j\225 a caminho. "
gameforge.main_quest_lv90._110_sayReward = "Explora a Rocha do Drag\227o Negro. Dirige-te aqui[ENTER]primeiro: (%d, %d). "
