gameforge.main_quest_lv90._200_say = {}
gameforge.main_quest_lv90._210_sayReward = "O teu terceiro destino \233: %d, %d "
gameforge.main_quest_lv90._220_sayReward = "Exploraste todas as regi\245es.[ENTER]Regressa ao Almirante Angmur. "
gameforge.main_quest_lv90._230_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv90._240_say = "Depois de teres viajado por toda a ilha, o[ENTER]seguinte tornou-se claro para ti: os dem\243nios[ENTER]abundam por todo o lado. "
gameforge.main_quest_lv90._250_say = "Fizeste um bom trabalho. Toma isto como uma[ENTER]recompensa de agradecimento. "
gameforge.main_quest_lv90._260_sendLetter = "Carta de Lee Chung "
gameforge.main_quest_lv90._270_say = "Enquanto relatas a situa\231\227o actual da Rocha do[ENTER]Drag\227o Negro, a express\227o facial do Almirante[ENTER]Angmur torna-se mais pesada. "
gameforge.main_quest_lv90._280_say = "Gostava que me tivesses trazido melhores not\237cias. "
gameforge.main_quest_lv90._290_say = "Os dem\243nios na ilha est\227o a tornar-se cada vez[ENTER]mais fortes. Se n\227o conseguirmos travar Sung Mahi[ENTER]e os Servos das Trevas.... que o Deus Drag\227o[ENTER]tenha miseric\243rdia de n\243s. "
gameforge.main_quest_lv90._300_say = "Sim, admito que a situa\231\227o parece um pouco[ENTER]desoladora. "
gameforge.main_quest_lv90._310_say = "Bem podes dizer isso de novo...[ENTER]Lee Chung deve ter descoberto uma pista decisiva.[ENTER]Ele enviou-me uma carta com algumas informa\231\245es[ENTER]importantes. Mas a carta nunca chegou at\233 mim. A[ENTER]mensagem foi interceptada pelos Gnoll. "
gameforge.main_quest_lv90._320_say = "Precisamos de encontrar esta carta. Podes[ENTER]ajudar-nos? "
gameforge.main_quest_lv90._330_say = "Claro. J\225 estou a caminho. "
gameforge.main_quest_lv90._340_say = "Obrigado. Os Gnoll encontram-se perto daqui. "
gameforge.main_quest_lv90._350_sayTitle = "Encontra a Carta de Lee Chung. "
gameforge.main_quest_lv90._360_say = "Uma das seguintes criaturas est\225 na posse da[ENTER]Carta de Lee Chung: Guerreiro Gnoll, Arqueiro[ENTER]Gnoll, Defensor Gnoll, Mago Gnoll, General Gnoll,[ENTER]Lorde Gnoll ou Guarda Supremo Gnoll. "
gameforge.main_quest_lv90._370_say = "Se queremos travar Sung Mahi, precisamos desta[ENTER]carta![ENTER]O ladr\227o encontra-se entre as fileiras da tribo[ENTER]Gnoll. "
gameforge.main_quest_lv90._380_1_notice = "Encontraste a carta. "
gameforge.main_quest_lv90._380_2_notice = "Leva-a ao Almirante Angmur. "
gameforge.main_quest_lv90._390_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv90._400_say = "Est\225s de volta e na posse da carte! Boa, sabia[ENTER]que podia contar contigo. Vamos l\225 v\234-la. "
gameforge.main_quest_lv90._410_say = "Sauda\231\245es, Angmur![ENTER]Meu amigo, nos acampamentos abandonados de Sung[ENTER]Mahi encontr\225mos algo: os Servos das Trevas[ENTER]contactaram os seus aliados na ilha usando[ENTER]mensagens secretas. Uma dessas mensagens foi[ENTER]enviada \224 tribo dos Gnoll. Se a conseguires[ENTER]interceptar, estaremos um importante passo \224[ENTER]frente dos dem\243nios! Vou enviar %s como suporte e[ENTER]espero que a for\231a e a coragem estejam contigo[ENTER]nesta altura sombria.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "Os meus batedores ir\227o descobrir se os Gnoll j\225[ENTER]receberam a carta ou n\227o. Entretanto, aceita isto[ENTER]como agradecimento. "
gameforge.main_quest_lv90._430_sendLetter = "A Carta dos Gnoll I "
gameforge.main_quest_lv90._440_say = "O Almirante Angmur est\225 \224 tua procura. Descobre o[ENTER]que ele pretende. "
gameforge.main_quest_lv90._450_say = "O General Gnoll j\225 recebeu a carta enviada pelos[ENTER]Servos. Podes obt\234-la para n\243s? Mas tem cuidado:[ENTER]os Gnoll s\227o extremamente agressivos. Eles atacam[ENTER]primeiro e fazem perguntas depois. "
gameforge.main_quest_lv90._460_say = "J\225 estou a caminho. "
gameforge.main_quest_lv90._470_say = "Obrigado. Sabia que pod\237amos contar contigo. "
gameforge.main_quest_lv90._480_sayTitle = "Encontra a Carta dos Gnoll! "
gameforge.main_quest_lv90._490_say = "Encontra o General Gnoll. Ele tem a carta! "
gameforge.main_quest_lv90._500_say = "N\227o temos tempo a perder. Por favor despacha-te e[ENTER]traz-me a carta. "
gameforge.main_quest_lv90._510_1_notice = "Conseguiste obter a Carta dos Gnoll. "
gameforge.main_quest_lv90._510_2_notice = "Leva-a ao Almirante Angmur. "
gameforge.main_quest_lv90._520_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv90._530_say = "Tens a carta! Finalmente algumas boas not\237cias,[ENTER]hein?[ENTER]Hmm...[ENTER]N\227o consigo ler uma \250nica palavra. A carta parece[ENTER]estar encriptada. O nosso escol\225stico parece[ENTER]conhecer algumas coisas sobre criptologia. Irei[ENTER]ter com ele directamente. Assim que souber mais[ENTER]alguma coisa, entrarei em contacto contigo. "
gameforge.main_quest_lv90._540_say = {}
gameforge.main_quest_lv90._550_say = {}
gameforge.main_quest_lv90._560_sendLetter = "A Carta dos Gnoll II "
gameforge.main_quest_lv90._570_say = "O Almirante Angmur est\225 \224 tua procura. Parece ser[ENTER]importante. Descobre o que ele quer. "
gameforge.main_quest_lv90._580_say = "A carta encriptada consiste em duas p\225ginas. A[ENTER]mensagem apenas pode ser descodificada quando as[ENTER]duas folhas se encontrem uma sobre a outra. O[ENTER]Lorde Gnoll est\225 na posse da segunda folha.[ENTER]Podes ajudar-nos? "
gameforge.main_quest_lv90._590_say = "Claro. "
gameforge.main_quest_lv90._600_say = "Obrigado. A tua ajuda \233 preciosa! "
gameforge.main_quest_lv90._610_sayTitle = "A Carta dos Gnoll II "
gameforge.main_quest_lv90._620_say = "Encontra a segunda folha da Carta dos Gnoll![ENTER]Poder\225s obt\234-la do Lorde Gnoll. "
gameforge.main_quest_lv90._630_say = "O tempo est\225 a esgotar-se! Despacha-te e descobre[ENTER]a segunda folha da carta. "
