gameforge.main_quest_lv90._650_say = "Excelente, agora podemos descodificar a mensagem:[ENTER]Hmm, ela parece de falar sobre drag\245es que dormem[ENTER]no cora\231\227o do mundo. Ela descreve um m\233todo[ENTER]atrav\233s do qual os podes acordar e fazer[ENTER]enlouquecer.[ENTER]Oh n\227o! Isto n\227o soa nada bem... "
gameforge.main_quest_lv90._660_say = {}
gameforge.main_quest_lv90._670_say = "Parece que as Mant\237coras e o Gang dos Ladr\245es[ENTER]Rubros tamb\233m receberam cartas. Irei descobrir[ENTER]mais sobre estas novidades e depois chamo-te. "
gameforge.main_quest_lv90._680_say = "O Almirante Angmur tem uma nova tarefa para ti. "
gameforge.main_quest_lv90._690_sendLetter = "As Mant\237coras "
gameforge.main_quest_lv90._700_say = "O Almirante Angmur tem uma nova tarefa para ti. "
gameforge.main_quest_lv90._710_say = "Muito bem, aqui est\225s tu! A nossa informa\231\227o[ENTER]sobre as mant\237coras j\225 tem algum tempo.[ENTER]Precisamos de descobrir qu\227o fortes s\227o as suas[ENTER]fileiras neste momento. "
