gameforge.main_quest_lv90._800_say = "As for\231as das mant\237coras n\227o s\227o particularmente[ENTER]grandes. Tens a vantagem no jogo de n\250meros. Mas[ENTER]os seus guerreiros s\227o bem treinados e[ENTER]extremamente duros.[ENTER]Recomendaria que fortalecesses a muralha de[ENTER]defesa que rodeia o forte. Como se encontra[ENTER]actualmente, n\227o iria resistir a um assalto das[ENTER]mant\237coras. "
gameforge.main_quest_lv90._810_say = "Muito bem, essa \233 a informa\231\227o que precis\225vamos.[ENTER]Irei tomar em conta o teu conselho e fortalecer a[ENTER]muralha defensiva.[ENTER]Por favor aceita isto como recompensa. "
gameforge.main_quest_lv90._820_say = "Fala com o Almirante Angmur. "
