gameforge.main_quest_lv90._950_say = "OK. "
gameforge.main_quest_lv90._960_say = "Obrigado! Com a Areia Fina agora seremos capazes[ENTER]de fortalecer o baluarte.[ENTER]Os meus homens ir\227o deitar m\227os ao trabalho[ENTER]imediatamente.[ENTER]Irei mandar chamar-te assim que voltarmos a[ENTER]precisar da tua ajuda. "
