gameforge.main_quest_lv91._150_say = "Muito bem, isto n\227o facilita a nossa situa\231\227o...[ENTER]Os meus batedores ir\227o procurar a localiza\231\227o do[ENTER]Martyaxwar.[ENTER]Toma, entretanto aceita isto como recompensa.[ENTER]Irei informar-te assim que ouvir algo de volta. "
gameforge.main_quest_lv91._160_sendLetter = "O Esconderijo do Martyaxwar "
