gameforge.main_quest_lv91._180_say = "Aqui est\225s tu, finalmente! Agora sabemos a[ENTER]localiza\231\227o do Martyaxwar. Os meus batedores[ENTER]tamb\233m observaram que ele colocou a carta no seu[ENTER]Colar de Farpas, algo que ele nunca remove. "
