gameforge.main_quest_lv91._250_say = "Bom trabalho. N\227o foi um advers\225rio f\225cil. Apenas[ENTER]podemos esperar que a carta nos diga mais sobre[ENTER]os planos sinistros dos dem\243nios. "
gameforge.main_quest_lv91._260_say = "Raios, estava mesmo a ver - est\225 tamb\233m[ENTER]encriptada! Yon-I-Walker, o nosso escol\225stico,[ENTER]precisa de dar uma vista de olhos. Por favor vai[ENTER]ter com ele. "
