gameforge.main_quest_lv91._320_say = "Ainda n\227o consegui descodificar a carta. Mas[ENTER]parece ser o idioma da tribo de crust\225ceos que[ENTER]vivem na Ba\237a de Nephrite. "
gameforge.main_quest_lv91._330_say = "Para poder interpretar estes caracteres, irei[ENTER]precisar do Manuscrito Carapa\231a da tribo de[ENTER]crust\225ceos. Podes ir buscar 10 por mim? "
gameforge.main_quest_lv91._340_say = "Claro. "
gameforge.main_quest_lv91._350_sayTitle = "Manuscrito Carapa\231a "
gameforge.main_quest_lv91._360_say = "Vai para o combate contra a tribo de crust\225ceos e[ENTER]obt\233m 10 Manuscritos Carapa\231a. "
gameforge.main_quest_lv91._370_say = "Infelizmente o Manuscrito Carapa\231a foi danificado[ENTER]e n\227o o posso usar. Por favor traz-me outro. "
gameforge.main_quest_lv91._380_say = "Encontraste os Manuscritos Carapa\231a. Eles t\234m a[ENTER]forma de carapa\231as de tartarugas. "
gameforge.main_quest_lv91._390_say = "Perfeito! Agora posso descodificar a carta.[ENTER]Bom trabalho! Aceita isto como sinal da minha[ENTER]gratid\227o. "
gameforge.main_quest_lv91._400_say = "Traz-me mais %d unidade(s)! "
gameforge.main_quest_lv91._410_1_notice = "Encontraste um Manuscrito Carapa\231a. "
gameforge.main_quest_lv91._410_2_notice = "Entrega-o ao Yon-I-Walker. "
gameforge.main_quest_lv91._420_sendLetter = "Carta das Mant\237coras descodificada. "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker est\225 \224 tua procura. Vai ter com ele[ENTER]e descobre se ele j\225 conseguiu descodificar a[ENTER]carta. "
gameforge.main_quest_lv91._440_say = "*murm\250rios* ...ah! Aqui est\225s tu! Gra\231as \224 tua[ENTER]ajuda consegui descodificar uma grande parte da[ENTER]mensagem. Mas n\227o estou a fazer progressos[ENTER]relativamente \224 \250ltima parte.[ENTER]Lamento, mas preciso de pedir a tua ajuda[ENTER]novamente. Preciso de P\243 de Carapa\231a com alguma[ENTER]urg\234ncia. Poder\225s encontr\225-la no General Lagosta[ENTER]ou no Rei Caranguejo da tribo de crust\225ceos. "
gameforge.main_quest_lv91._450_say = "P\243 de Carapa\231a "
gameforge.main_quest_lv91._460_say = "Sim, apenas a tribo de crust\225ceos o possui. Mesmo[ENTER]uma pequena dose deste p\243 \233 letal! Tr\234s doses[ENTER]devem ser suficientes. Boa sorte. "
gameforge.main_quest_lv91._470_say = "Irei j\225 para l\225. "
gameforge.main_quest_lv91._480_sayTitle = "P\243 de Carapa\231a "
gameforge.main_quest_lv91._490_say = "Vai combater o General Lagosta e o Rei Caranguejo[ENTER]da tribo de crust\225ceos e obt\233m 3 doses de P\243 de[ENTER]Carapa\231a. "
gameforge.main_quest_lv91._500_say = "O P\243 de Carapa\231a \233 extremamente venenoso. Preciso[ENTER]de esperar um dia para que os seus efeitos[ENTER]diminuam.[ENTER]Volta amanh\227. Espero ser capaz de te dizer mais. "
gameforge.main_quest_lv91._510_say = "Tens o P\243 de Carapa\231a! "
gameforge.main_quest_lv91._520_say = "Bom trabalho. Agora posso finalmente descodificar[ENTER]a carta.[ENTER]Por favor aceita isto como recompensa. "
gameforge.main_quest_lv91._530_say = "Traz-me mais %d unidade(s)! "
gameforge.main_quest_lv91._540_say = "Este P\243 de Carapa\231a est\225 contaminado. Por favor[ENTER]traz-me uma nova dose. "
gameforge.main_quest_lv91._550_1_notice = "Encontraste uma dose de P\243 de Carapa\231a. "
gameforge.main_quest_lv91._550_2_notice = "Leva-a ao Yon-I-Walker. "
gameforge.main_quest_lv91._560_sendLetter = "Envenenado! "
gameforge.main_quest_lv91._570_say = "O Almirante Angmur precisa urgentemente de ti.[ENTER]Descobre o que ele quer. "
gameforge.main_quest_lv91._580_say = "Aqui est\225s tu! Louvado seja o Deus Drag\227o.[ENTER]Yon-I-Walker foi envenenado pelo P\243 de Carapa\231a. "
gameforge.main_quest_lv91._590_say = "Ele queria despachar-se e descuidou-se. O que[ENTER]piora toda esta situa\231\227o \233 o facto de n\227o termos[ENTER]armazenadas quaisquer ervas medicinais.[ENTER]Procura a Flor-Rocha - as suas ra\237zes poder\227o[ENTER]neutralizar o veneno. Marquei no teu mapa as[ENTER]localiza\231\245es onde a podes encontrar. "
gameforge.main_quest_lv91._600_say = "Claro. "
gameforge.main_quest_lv91._610_say = "Sabia que podia contar contigo. Por favor[ENTER]despacha-te, n\227o temos muito tempo! "
gameforge.main_quest_lv91._620_sayTitle = "Salva o Yon-I-Walker! "
gameforge.main_quest_lv91._630_say = "Encontra as Ra\237zes de Flor-Rocha para poderes[ENTER]curar o Yon-I-Walker, que foi envenenado. "
gameforge.main_quest_lv91._640_1_notice = "Leva a Raiz de Flor-Rocha ao Yon-I-Walker. "
gameforge.main_quest_lv91._650_say = "*tosse*[ENTER]*som dorido*[ENTER]Ah, \233s tu. N\227o estou muito bem. Encontraste as[ENTER]Ra\237zes de Flor-Rocha? "
gameforge.main_quest_lv91._660_say = "Sim, tenho-as aqui. "
gameforge.main_quest_lv91._670_say = "Ah, j\225 me sinto melhor. Parece que a minha hora[ENTER]ainda n\227o chegou.[ENTER]Agrade\231o-te. Aceita isto como recompensa. Agora[ENTER]posso completar o meu trabalho. O Almirante[ENTER]Angmur ir\225 informar-te assim que conseguir[ENTER]descodificar a carta. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker quer falar contigo. "
gameforge.main_quest_lv91._760_say = "(Em falta: %s %s, %s %s) "
gameforge.main_quest_lv91._770_say = {}
gameforge.main_quest_lv91._780_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 92. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "A Carta dos Ladr\245es Rubros "
gameforge.main_quest_lv92._020_say = "A \250ltima carta enviada pelos Servos das Trevas[ENTER]encontra-se na posse do Gang dos Ladr\245es Rubros.[ENTER]O Almirante Angmur tem mais informa\231\245es para ti. "
gameforge.main_quest_lv92._030_say = "Estamos cada vez mais perto de descortinar os[ENTER]planos dos Servos das Trevas. A \250ltima carta[ENTER]encontra-se actualmente na posse do Gang dos[ENTER]Ladr\245es Rubros. "
gameforge.main_quest_lv92._040_say = "O Gang dos Ladr\245es Rubros? "
gameforge.main_quest_lv92._050_say = "Existe um grupo de criminosos que foi banido para[ENTER]a Rocha do Drag\227o Negro. O que h\225 de estranho[ENTER]relativamente aos Ladr\245es Rubros \233 o facto de[ENTER]humanos se terem alinhado com dem\243nios. "
gameforge.main_quest_lv92._060_say = "Dem\243nios... Alinhados com humanos em vez de os[ENTER]comerem? Curioso... "
gameforge.main_quest_lv92._070_say = "Eles est\227o unidos por um objectivo em comum: ouro.O acampamento dos Ladr\245es Rubros n\227o fica longe[ENTER]daqui. Derrota o Ladr\227o Rubro Executor e o[ENTER]General Negro. Um deles est\225 na posse da carta. "
gameforge.main_quest_lv92._080_say = "No entanto eles foram avisados atempadamente[ENTER]sobre as nossas inten\231\245es e separaram a carta em[ENTER]quatro partes. Temos de encontr\225-las todas. "
gameforge.main_quest_lv92._090_say = "Entendido. "
gameforge.main_quest_lv92._100_say = "Obrigado! "
gameforge.main_quest_lv92._110_sayTitle = "A Carta dos Ladr\245es Rubros "
gameforge.main_quest_lv92._120_say = "Luta contra o Ladr\227o Rubro Executor e o General[ENTER]Negro. Encontra todos os quatro peda\231os da carta. "
gameforge.main_quest_lv92._130_say = "A carta ainda n\227o est\225 completa. Encontra todos[ENTER]os peda\231os. "
gameforge.main_quest_lv92._140_1_notice = "Encontraste todas as partes da Carta dos Ladr\245es[ENTER]Rubros. "
gameforge.main_quest_lv92._140_2_notice = "Mostra-a ao Almirante Angmur. "
gameforge.main_quest_lv92._150_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv92._160_say = "Bom trabalho. Aceita isto como sinal da minha[ENTER]gratid\227o. "
gameforge.main_quest_lv92._170_sendLetter = "A Carta dos Ladr\245es Rubros "
gameforge.main_quest_lv92._180_say = "O Almirante Angmur precisa da tua ajuda. "
gameforge.main_quest_lv92._190_say = "Ainda bem que aqui est\225s. Temos um problema. "
gameforge.main_quest_lv92._200_say = "O que se passa? "
gameforge.main_quest_lv92._210_say = "Na realidade, existe um quinto peda\231o da Carta[ENTER]dos Ladr\245es Rubros. Sem esse peda\231o, o resto da[ENTER]carta de nada nos vale. J\225 enviei o Bae-Yong, um[ENTER]dos meus homens mais corajosos, mas deve ter[ENTER]acontecido algo. Ele j\225 deveria ter regressado h\225[ENTER]muito tempo. Podes procur\225-lo? "
gameforge.main_quest_lv92._220_say = "Claro! Fazes ideia de onde ele possa estar agora? "
gameforge.main_quest_lv92._230_say = "Tenho uma ideia, sim. Da \250ltima vez que[ENTER]comunic\225mos, ele estava a pensar em ir at\233 \224 Ba\237a[ENTER]de Nephrite. Mas ningu\233m tem a certeza se ele[ENTER]ter\225 ou n\227o chegado l\225. "
gameforge.main_quest_lv92._240_say = "Vou p\244r-me j\225 a caminho! "
gameforge.main_quest_lv92._250_sayTitle = "O Soldado Desaparecido "
gameforge.main_quest_lv92._260_say = "Encontra o quinto peda\231o da carta. Para isso,[ENTER]procura pelo Bae-Yong na Ba\237a de Nephrite. "
gameforge.main_quest_lv92._270_say = "Ainda n\227o encontraste o Bae-Yong? Isto \233 uma[ENTER]quest\227o de vida ou morte! Por favor continua a[ENTER]procurar. "
gameforge.main_quest_lv92._280_say = "*tosse*[ENTER]Obrigado por me encontrares. Fui gravemente[ENTER]ferido em combate e acho que n\227o me sobra muito[ENTER]mais tempo...[ENTER]Toma, consegui obter isto de um Ladr\227o Rubro.[ENTER]Leva-o ao Almirante. Vai! Eu fico b...[ENTER](Ele morre nos teus bra\231os.) "
gameforge.main_quest_lv92._290_1_notice = "Antes de Bae-Yong morrer, ele deu-te o peda\231o da[ENTER]carta que faltava. "
gameforge.main_quest_lv92._290_2_notice = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv92._300_say = "Est\225s de volta! Encontraste o Bae-Yong? "
gameforge.main_quest_lv92._310_say = "Sim, mas... "
gameforge.main_quest_lv92._320_say = "Mas?[ENTER]Oh n\227o... Ele est\225 morto? "
gameforge.main_quest_lv92._330_say = "N\227o podia faz mais por ele. Os meus p\234sames. Ele[ENTER]era um homem corajoso \150 ele defendeu o \250ltimo[ENTER]peda\231o da carta com a sua vida. Aqui est\225. "
gameforge.main_quest_lv92._340_say = "A perda do Bae-Yong ir\225 afectar-nos imenso. Mas[ENTER]tenho imenso orgulho nele. Ele completou a sua[ENTER]miss\227o \150 temos agora todos os peda\231os da carta. "
gameforge.main_quest_lv92._350_say = "Agrade\231o-te por tudo. Toma, aceita isto como[ENTER]recompensa.[ENTER]Vou agora acender algum incenso no templo pelo[ENTER]Bae-Yong. Mandarei chamar-te mais tarde. "
gameforge.main_quest_lv92._360_say = "Vai ter com o Almirante Angmur. "
gameforge.main_quest_lv92._370_sendLetter = "Descodifica a Carta dos Ladr\245es Rubros "
gameforge.main_quest_lv92._380_say = "O Almirante Angmur tem informa\231\245es importantes[ENTER]sobre a Carta dos Ladr\245es Rubros. Ouve o que ele[ENTER]tem para te dizer. "
gameforge.main_quest_lv92._390_say = "Ah, aqui est\225s tu. Os Servos das Trevas est\227o a[ENTER]dar-me uma dor de cabe\231a. Esta carta tamb\233m se[ENTER]encontra encriptada. Por favor leva-a ao[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv92._400_say = "Entendido. "
gameforge.main_quest_lv92._410_say = "Leva a carta encriptada ao Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "Argh! Tens sempre de te esgueirar at\233 mim dessa[ENTER]forma?! O que posso fazer por ti? "
gameforge.main_quest_lv92._430_say = "Aqui est\225 a Carta dos Ladr\245es Rubros. Tal como as[ENTER]outras, esta est\225 encriptada. "
gameforge.main_quest_lv92._440_say = "Deixa-me dar uma vista de olhos. Hmm, isto[ENTER]parecem ser os caracteres dos Trit\245es. N\227o dever\225[ENTER]ser muito dif\237cil descodific\225-los. "
gameforge.main_quest_lv92._450_say = "Excelente. Durante quanto tempo precisas dela? "
gameforge.main_quest_lv92._460_say = "N\227o tenhas tanta pressa. A descodifica\231\227o n\227o \233[ENTER]particularmente complicada, mas sem mais recursos[ENTER]isto n\227o ir\225 funcionar. "
gameforge.main_quest_lv92._470_say = "Mas \233 claro que n\227o... Isso seria demasiado f\225cil. "
gameforge.main_quest_lv92._480_say = "Vejo que n\227o perdeste o teu sentido de humor,[ENTER]hehe.[ENTER]Para descodificar a carta preciso de Escamas de[ENTER]Oin. Dos membros da tribo dos Trit\245es, apenas o[ENTER]General Kappa e o pr\243prio Trit\227o podem usar estas[ENTER]raras escamas. Por favor obt\233m dez. "
gameforge.main_quest_lv92._490_say = "Vou j\225 p\244r-me a caminho. "
gameforge.main_quest_lv92._500_sayTitle = "Encontra Escamas de Oin! "
gameforge.main_quest_lv92._510_say = "Apenas o Trit\227o, Rei dos Trit\245es, e o General[ENTER]Kappa usam Escamas de Oin. "
gameforge.main_quest_lv92._520_say = "N\227o consigo descodificar a carta sem as escamas.[ENTER]Preciso delas urgentemente. "
gameforge.main_quest_lv92._530_1_notice = "Encontraste as Escamas de Oin trit\243nicas. "
gameforge.main_quest_lv92._530_2_notice = "Leva-as rapidamente ao Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Fizeste um \243ptimo trabalho. Assim que tiver[ENTER]descodificado a carta irei informar o Almirante[ENTER]Angmur. Devias descansar um pouco.[ENTER]Toma, aceita isto como sinal do meu apre\231o. "
gameforge.main_quest_lv92._550_say = "O Yon-I-Walker gostaria de falar contigo. "
gameforge.main_quest_lv92._560_sendLetter = "Planos Sinistros "
gameforge.main_quest_lv92._570_say = "A carta dos Servos das Trevas foi descodificado.[ENTER]O Almirante Angmur quer falar contigo sobre os[ENTER]seus planos sinistros. "
gameforge.main_quest_lv92._580_say = "Conseguimos descodificar completamente a mensagem[ENTER]secreta. Lembras-te da carta enviada aos Gnoll?[ENTER]Ela j\225 falava de drag\245es, adormecidos nas[ENTER]profundezas da ilha, assim como de um m\233todo de[ENTER]os acordar e enraivecer. Agora descobrimos a[ENTER]raz\227o pela qual os Servos das Trevas est\227o t\227o[ENTER]interessados nisto. "
gameforge.main_quest_lv92._590_say = "Se matares um drag\227o nesse momento, quando a sua[ENTER]mente se encontra num estado t\227o negro quanto as[ENTER]mand\237bulas do Inferno, ele ir\225 cuspir uma P\233rola[ENTER]da Noite. Com a ajuda desta p\233rola, os poderes[ENTER]incomensur\225veis de Sung Mahi poder\227o ser[ENTER]invocados para o nosso mundo. Esse \233 o seu plano[ENTER]sinistro! "
gameforge.main_quest_lv92._600_say = "Os nossos pr\243ximos passos precisam de ser bem[ENTER]ponderados. Assim que tiver novidades para ti,[ENTER]mandarei chamar-te. Obrigado por tudo. "
gameforge.main_quest_lv92._610_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 93. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Abastecimento de Poder I "
gameforge.main_quest_lv93._020_say = "O Almirante Angmur quer falar contigo. "
gameforge.main_quest_lv93._030_say = "Estamos no rasto dos Servos das Trevas. "
gameforge.main_quest_lv93._040_say = "Para os derrotar, precisamos de fortalecer os[ENTER]teus poderes. J\225 ouviste falar da Luz Interior? \201[ENTER]energia concentrada. Alguns seres ou plantas[ENTER]m\237ticos possuem-na. O Yon-I-Walker pode criar um[ENTER]t\243nico a partir dela. Vai ter com ele de seguida. "
gameforge.main_quest_lv93._050_say = "Percebido. "
gameforge.main_quest_lv93._060_say = "Ah, aqui est\225 a minha salva\231\227o![ENTER]A Luz Interior, ah sim... o meu t\243nico ir\225[ENTER]tornar-te um advers\225rio ao n\237vel dos Servos das[ENTER]Trevas. "
gameforge.main_quest_lv93._070_say = "Para isso, preciso da Luz Interior dos Ciclopes e[ENTER]dos Gigantes. Apenas os l\237deres das tribos de[ENTER]cada um destes grupos a possuem. Enfrenta[ENTER]primeiro os Ciclopes. "
gameforge.main_quest_lv93._080_say = "Percebido. "
gameforge.main_quest_lv93._090_sayTitle = "A Luz Interior I "
gameforge.main_quest_lv93._100_say = "Derrota o Polyphemos, Rei dos Ciclopes, e obt\233m a[ENTER]sua Luz Interior. "
gameforge.main_quest_lv93._110_say = "Est\225s de volta de m\227os a abanar? N\227o te irei[ENTER]conseguir ajudar assim. Traz-me a Luz Interior! "
gameforge.main_quest_lv93._120_1_notice = "Encontraste a Luz Interior. Leva-a ao[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Fala com o Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "Ent\227o isto \233 a Luz Interior... antes de poder[ENTER]trabalhar nela, precisa de ser limpa. Isso ir\225[ENTER]demorar algum tempo. Irei informar-te quando[ENTER]estiver pronta. "
gameforge.main_quest_lv93._150_sendLetter = "Abastecimento de Poder II "
gameforge.main_quest_lv93._160_say = "O Yon-I-Walker est\225 \224 tua procura. "
gameforge.main_quest_lv93._170_say = "A Luz Interior do Polyphemos j\225 est\225 limpa. De[ENTER]seguida precisaremos da que se encontra na posse[ENTER]dos gigantes.[ENTER]Tens de derrotar o Rei Wubba para a obteres. "
gameforge.main_quest_lv93._180_say = "Vou j\225 p\244r-me a caminho. "
gameforge.main_quest_lv93._190_sayTitle = "A Luz Interior II "
gameforge.main_quest_lv93._200_say = "Derrota o rei dos gigantes, o Rei Wubba, e obt\233m[ENTER]a sua Luz Interior. "
gameforge.main_quest_lv93._210_say = "Voltaste de m\227os a abanar? Ficaria surpreendido[ENTER]se n\227o estivesses \224 altura desta miss\227o. P\245e-te a[ENTER]caminho e tenta de novo! "
gameforge.main_quest_lv93._220_1_notice = "Tens a Luz Interior dos gigantes nas tuas m\227os. "
gameforge.main_quest_lv93._220_2_notice = "Leva-a ao Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Fala com o Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "A Luz Interior do Rei Wubba possui um enorme[ENTER]poder. Acredito que isto se deva ao seu tamanho.[ENTER]Preciso de a limpar. Isto vai demorar um pouco. "
gameforge.main_quest_lv93._250_sendLetter = "Abastecimento de Poder III "
gameforge.main_quest_lv93._260_say = "O Yon-I-Walker est\225 \224 tua procura. "
gameforge.main_quest_lv93._270_say = "Aqui est\225s tu, excelente. Preciso da tua ajuda.[ENTER]Para que os efeitos do meu t\243nico se desenvolvam[ENTER]completamente, preciso de mais um componente: a[ENTER]Ess\234ncia Milenar. "
gameforge.main_quest_lv93._280_say = "Ess\234ncia Milenar? Nunca ouvi falar disso. "
gameforge.main_quest_lv93._290_say = "\201 uma mistura muito eficiente feita de v\225rias[ENTER]ess\234ncias de ervas. Conheces o Oct\225vio? Ele vive[ENTER]no continente e \233 a \250nica pessoa capaz de[ENTER]produzir a Ess\234ncia Milenar. Vai ter com ele.[ENTER]Espero que ele nos ajude. Ele consegue ser um[ENTER]pouco teimoso... "
gameforge.main_quest_lv93._300_say = "Percebido. "
gameforge.main_quest_lv93._310_sayTitle = "Fala com o Oct\225vio! "
gameforge.main_quest_lv93._320_say = "Procura o Oct\225vio. Ele vive no continente e \233 o[ENTER]\250nico que pode criar a Ess\234ncia Milenar. "
gameforge.main_quest_lv93._330_say = "Ol\225! Em que te posso ajudar? Talvez uma[ENTER]Samgyetang? \201 uma especialidade da casa com... "
gameforge.main_quest_lv93._340_say = "Oct\225vio, n\227o estou aqui pela comida! Preciso de[ENTER]algo bastante diferente: a Ess\234ncia Milenar. "
gameforge.main_quest_lv93._350_say = "Woah, shhhhhh, n\227o t\227o alto! A Ess\234ncia[ENTER]Milenar... N\227o, isso n\227o \233 poss\237vel. Como tens[ENTER]conhecimento disso? Apenas um punhado de gente[ENTER]consegue suportar o poder que ela proporciona.[ENTER]N\227o quero correr esse risco. Agora vai, antes que[ENTER]mais algu\233m te ou\231a. "
gameforge.main_quest_lv93._360_say = "Oct\225vio, espera e ouve-me! Fui enviado pelo[ENTER]Yon-I-Walker da Rocha do Drag\227o Negro. Precisamos[ENTER]urgentemente desta Ess\234ncia. Sem ela n\227o temos[ENTER]qualquer hip\243tese contra os Servos das Trevas. E[ENTER]ent\227o, o mundo como o conhecemos estar\225[ENTER]condenado.[ENTER]Apenas tu podes produzir a Ess\234ncia. Por favor! "
gameforge.main_quest_lv93._370_say = "O Yon-I-Walker, dizes? Hmm, ele \233 um velho amigo[ENTER]meu. J\225 tivemos muitas conversas em volta de uma[ENTER]boa garrafa de vinho. Preciso de pensar neste[ENTER]assunto. Volta de manh\227 e irei dar-te uma[ENTER]resposta. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Ainda n\227o tomei uma decis\227o. Volta de novo mais[ENTER]tarde. "
gameforge.main_quest_lv93._400_npcChat = "A Ess\234ncia Milenar "
gameforge.main_quest_lv93._410_say = "O Oct\225vio quer falar contigo. "
gameforge.main_quest_lv93._420_say = "Portanto, estive a noite toda a pensar no teu[ENTER]pedido. Estou a correr um enorme risco, mas tenho[ENTER]a certeza que estou a fazer a coisa certa. Sim,[ENTER]irei ajudar-te. "
gameforge.main_quest_lv93._430_say = "Excelente! "
gameforge.main_quest_lv93._440_say = "No entanto, n\227o tenho nada armazenado neste[ENTER]momento. Podes obter alguns ingredientes para[ENTER]mim? Dessa forma poderei produzir a Ess\234ncia para[ENTER]ti. "
gameforge.main_quest_lv93._450_say = "\201 claro. De que precisas? "
gameforge.main_quest_lv93._460_say = "Faltam-me Ra\237zes de Gango, Cogumelos Tue e Rosas[ENTER]Alpinas Preciso de 200 unidades de cada[ENTER]ingrediente. "
gameforge.main_quest_lv93._470_say = "Irei j\225 lan\231ar-me a essa tarefa. Onde posso[ENTER]encontrar tudo isso? "
gameforge.main_quest_lv93._480_say = "Ir\225s encontrar estas plantas nas mais diversas[ENTER]localiza\231\245es do continente. Enquanto procuras,[ENTER]irei come\231ar os meus preparativos aqui. "
gameforge.main_quest_lv93._490_sayTitle = "A Receita Milenar "
gameforge.main_quest_lv93._500_say = "Procura Ra\237zes de Gango, Cogumelos Tue e Rosas[ENTER]Alpinas.[ENTER]Precisas de 200 unidades de cada. "
gameforge.main_quest_lv93._510 = "Ir\225s encontrar estas plantas nas mais diversas[ENTER]localiza\231\245es do continente. Enquanto procuras,[ENTER]irei come\231ar os meus preparativos aqui. "
gameforge.main_quest_lv93._520_say = "Ah, est\225s de volta, muito bem. E tens tudo[ENTER]contigo. Ent\227o vou j\225 deitar m\227os ao trabalho.[ENTER]N\227o devo ser interrompido durante este tempo.[ENTER]Volta amanh\227 por esta hora. Por essa altura a[ENTER]Ess\234ncia j\225 dever\225 estar pronta. "
gameforge.main_quest_lv93._530_say = "Entendido. At\233 amanh\227. "
gameforge.main_quest_lv93._540_say = "Percebo que precises da Ess\234ncia urgentemente,[ENTER]mas tens de ter paci\234ncia por um pouco mais de[ENTER]tempo. Volta mais tarde. "
gameforge.main_quest_lv93._550_say = "O Oct\225vio est\225 \224 tua procura. "
gameforge.main_quest_lv93._560_say = "Ah, chegaste no momento certo: a Ess\234ncia Milenar[ENTER]acabou de ficar pronta a ser usada! Agora podes[ENTER]lev\225-la ao Yon-I-Walker. "
gameforge.main_quest_lv93._570_say = "Obrigado! "
gameforge.main_quest_lv93._580_sendLetter = "Ess\234ncia Milenar "
gameforge.main_quest_lv93._590_say = "O Yon-I-Walker est\225 \224 tua procura. "
gameforge.main_quest_lv93._600_say = "Tens a Ess\234ncia Milenar! Agora tenho todos os[ENTER]ingredientes para o meu t\243nico. Irei mandar[ENTER]chamar-te assim que estiver pronto. "
gameforge.main_quest_lv93._610_say = "Entendido. "
gameforge.main_quest_lv93._620_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 94. "
