gameforge.main_quest_lv94._030_say = "Consegui. Fui capaz de combinar as ess\234ncias mais[ENTER]eficientes que conhecemos umas com as outras.[ENTER]Apresento-te: as P\233rolas Leviathan! "
gameforge.main_quest_lv94._040_say = "Obrigado! "
gameforge.main_quest_lv94._050_say = "Se levares estas c\225psulas, poder\225s n\227o sentir[ENTER]qualquer mudan\231a. Mas um olho bem treinado, como[ENTER]o meu ou o do Angmur, conseguir\225 not\225-lo.[ENTER]Angmur quer falar contigo. Vai ter com ele agora. "
gameforge.main_quest_lv94._060_sayTitle = "Fortalece-te! "
gameforge.main_quest_lv94._070_say = "Engole as P\233rolas Leviathan e procura o Almirante[ENTER]Angmur. "
gameforge.main_quest_lv94._080_sendLetter = "Chamamento das Montanhas do Trov\227o "
gameforge.main_quest_lv94._090_say = "O Almirante Angmur tem novidades para ti. "
gameforge.main_quest_lv94._1000_say = "Irei precisar de algum tempo para analisar as[ENTER]amostras. Volta amanh\227 que terei os resultados[ENTER]prontos, espero eu. "
gameforge.main_quest_lv94._100_say = "Ah, as P\233rolas Leviathan mostram o seu efeito:[ENTER]Consigo claramente ver uma aura de poder em teu[ENTER]redor.[ENTER]Os meus batedores t\234m uma ideia de onde o[ENTER]quartel-general dos Servos das Trevas se pode[ENTER]encontrar. O local est\225 fortemente protegido.[ENTER]Podes dar uma vista de olhos? "
gameforge.main_quest_lv94._1010_say = "Irei reportar as minhas descobertas ao Angmur.[ENTER]Ele ir\225 ent\227o entrar em contacto contigo. "
gameforge.main_quest_lv94._1020_say = "O Almirante Angmur tem informa\231\245es sobre o Ouro[ENTER]Negro. Vai ter com ele. "
gameforge.main_quest_lv94._1030_say = "Aye, aqui est\225s tu. A an\225lise ao Ouro Negro ainda[ENTER]n\227o est\225 completa. Espero em breve ter mais para[ENTER]te contar. Toma, aqui tens uma recompensa pelos[ENTER]teus esfor\231os. "
gameforge.main_quest_lv94._1040_say = "N\227o podemos perder mais tempo. R\225pido, traz-me[ENTER]amostras do Ouro Negro! "
gameforge.main_quest_lv94._1050_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 95. "
