gameforge.main_quest_lv94._260_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv94._270_say = "Ah, est\225s de volta! Muito bem, iremos avaliar as[ENTER]informa\231\245es que recolheste e delinear uma[ENTER]estrat\233gia. "
gameforge.main_quest_lv94._280_say = "Aqui est\225 a tua recompensa. "
gameforge.main_quest_lv94._290_sendLetter = "Enfraquece os Ladr\245es Rubros "
gameforge.main_quest_lv94._300_say = "O Almirante Angmur est\225 \224 tua procura. "
gameforge.main_quest_lv94._310_say = "Um ataque directo parece-me ser demasiado[ENTER]arriscado nesta altura. Antes de partirmos para o[ENTER]ataque, \233 melhor enfraquecermos o ex\233rcito do[ENTER]inimigo. "
gameforge.main_quest_lv94._320_say = "Os seguintes grupos vivem nas Montanhas do[ENTER]Trov\227o: os Gigantes, os Ciclopes e os Ladr\245es[ENTER]Rubros.[ENTER]Iremos atacar os Ladr\245es Rubros primeiro! "
gameforge.main_quest_lv94._330_say = "Que fraquezas t\234m os Ladr\245es Rubros? "
gameforge.main_quest_lv94._340_say = "O Chefe Rubro usa sempre uma capa especial, um[ENTER]s\237mbolo de for\231a e invencibilidade. Rouba-lhe[ENTER]essa capa - isso ir\225 destruir a motiva\231\227o do Gang[ENTER]dos Ladr\245es Rubros! "
gameforge.main_quest_lv94._350_say = "O Chefe Rubro? Isso n\227o ser\225 tarefa f\225cil... "
gameforge.main_quest_lv94._360_say = "Tens raz\227o. Mas se algu\233m o consegue enfrentar,[ENTER]esse algu\233m \233s tu. Boa sorte! "
gameforge.main_quest_lv94._370_sayTitle = "O Chefe Rubro "
gameforge.main_quest_lv94._380_say = "Derrota o Chefe Rubro e rouba-lhe a sua capa. "
gameforge.main_quest_lv94._390_say = "... falhaste? N\227o, n\227o acredito nisso. Volta a[ENTER]enfrentar o Chefe Rubro. Tenho a certeza que[ENTER]desta vez o ir\225s derrotar. "
gameforge.main_quest_lv94._400_1_notice = "Derrotaste o Chefe Rubro. "
gameforge.main_quest_lv94._400_2_notice = "Pega na sua capa e leva-a ao Almirante Angmur. "
gameforge.main_quest_lv94._410_say = "O Almirante Angmur est\225 \224 tua espera. "
gameforge.main_quest_lv94._420_say = "A capa! Sabia que o ias conseguir. Iremos[ENTER]pendur\225-la perto do seu acampamento para que eles[ENTER]a consigam ver - isso ir\225 desconcertar o Gang dos[ENTER]Ladr\245es Rubros. Os meus companheiros ir\227o tratar[ENTER]disso. Dessa forma poder\225s ter algum tempo para[ENTER]recuperar. "
gameforge.main_quest_lv94._430_sendLetter = "Enfraquece os Ciclopes "
gameforge.main_quest_lv94._440_say = "O Almirante Angmur gostaria de falar contigo. "
gameforge.main_quest_lv94._450_say = "O nosso plano est\225 a funcionar: quando os Ladr\245es[ENTER]Rubros viram a capa, houve um grande dist\250rbio.[ENTER]No fim, os dem\243nios e os humanos acabaram a lutar[ENTER]uns com os outros. Agora esse Gang encontra-se[ENTER]completamente desorganizado. De seguida, temos os[ENTER]Ciclopes. "
gameforge.main_quest_lv94._460_say = "Como vamos proceder? "
gameforge.main_quest_lv94._470_say = "Os Ciclopes veneram o seu l\237der. Se eliminarmos o[ENTER]esquadr\227o de lideran\231a, os Ciclopes ir\227o entrar[ENTER]em p\226nico e dispersar. Derrota o General Outis %d[ENTER]vezes, o Arges %d vezes e o Polyphemos %d vezes. "
gameforge.main_quest_lv94._480_say = "Ser\225 um prazer. "
gameforge.main_quest_lv94._490_say = "Tem cuidado. "
gameforge.main_quest_lv94._500_sayTitle = "Combate os Ciclopes! "
gameforge.main_quest_lv94._510_say = "Derrota o General Outis %d vezes, o Arges %d[ENTER]vezes e o Polyphemos %d vezes. "
gameforge.main_quest_lv94._520 = "Mal posso acreditar que est\225s a ter d\250vidas em[ENTER]rela\231\227o aos Ciclopes, de todas as criaturas! Vai![ENTER]Sei que o consegues fazer! "
gameforge.main_quest_lv94._530_1_notice = "Derrotaste os l\237deres dos Ciclopes. "
gameforge.main_quest_lv94._530_2_notice = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv94._540_say = "Vai ter com o Almirante Angmur. "
gameforge.main_quest_lv94._550_say = "As not\237cias dos teus feitos perseguem-te! Os[ENTER]Ciclopes est\227o em fuga.[ENTER]Tudo o que nos resta s\227o os Gigantes. Irei reunir[ENTER]informa\231\245es sobre as suas fraquezas e mandarei[ENTER]chamar-te. "
gameforge.main_quest_lv94._560_sendLetter = "Enfraquece os Gigantes "
gameforge.main_quest_lv94._570_say = "O Almirante Angmur mandou chamar-te. "
gameforge.main_quest_lv94._580_say = "Os meus batedores descobriram a fraqueza dos[ENTER]Gigantes. "
gameforge.main_quest_lv94._590_say = "Conta-me! "
gameforge.main_quest_lv94._600_say = "Os Gigantes encontram-se na posse de um Totem com[ENTER]grande valor espiritual. Se o roubarmos,[ENTER]poderemos quebrar a sua vontade. "
gameforge.main_quest_lv94._610_say = "Onde posso encontrar esse Totem? "
gameforge.main_quest_lv94._620_say = "O Totem tem a forma de um grande peda\231o de \226mbar.[ENTER]Para o proteger de ladr\245es, ele foi dividido em[ENTER]%d partes.[ENTER]O Rei Wubba e os seus Oficiais andam na posse[ENTER]dessas partes. "
gameforge.main_quest_lv94._630_say = "Entendido. "
gameforge.main_quest_lv94._640_sayTitle = "Totem dos Gigantes "
gameforge.main_quest_lv94._650_say = "Obt\233m todos os peda\231os do Totem. "
gameforge.main_quest_lv94._660_say = "Os Gigantes s\227o advers\225rios poderosos. Mas tu[ENTER]tens de os derrotar e trazer-me esse Totem! "
gameforge.main_quest_lv94._670_say_1_notice = "J\225 conseguiste todos os peda\231os do Totem. "
gameforge.main_quest_lv94._670_say_2_notice = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv94._680_say = "Aye, j\225 me estava a come\231ar a preocupar![ENTER]Conseguiste mesmo faz\234-lo. Agora estamos na posse[ENTER]do sagrado Totem dos Gigantes.[ENTER]A tua recompensa por isto ser\225 grande. "
gameforge.main_quest_lv94._690_sendLetter = "Para as Montanhas do Trov\227o "
gameforge.main_quest_lv94._700_say = "O Almirante Angmur est\225 \224 tua procura. "
gameforge.main_quest_lv94._710_say = "Os meus batedores t\234m observado os Ciclopes a[ENTER]recolher qualquer coisa nas Montanhas do Trov\227o e[ENTER]a lev\225-la para algum local. "
gameforge.main_quest_lv94._720_say = "Descobre o que os Ciclopes andam a planear. De[ENTER]certeza que n\227o \233 algo de bom... E tamb\233m duvido[ENTER]que eles v\227o desvendar o seu segredo t\227o[ENTER]facilmente. "
gameforge.main_quest_lv94._730_say = "Entendido. "
gameforge.main_quest_lv94._740_sayTitle = "O que est\227o os Ciclopes a planear? "
gameforge.main_quest_lv94._750_say = "Descobre o que \233 que os Ciclopes andam a recolher[ENTER]nas Montanhas do Trov\227o. "
gameforge.main_quest_lv94._760_say = "Descobre o que os Ciclopes andam a tramar. N\227o[ENTER]pode ser algo de bom... E tamb\233m duvido que eles[ENTER]revelem o seu segredo facilmente. "
gameforge.main_quest_lv94._770_1_notice = "Tens na tua m\227o uma pedra preta reluzente, assim[ENTER]como um Peda\231o de Papel. "
gameforge.main_quest_lv94._770_2_notice = "Mostra ao Almirante Angmur o que descobriste. "
gameforge.main_quest_lv94._780_say = "Vai ter com o Almirante Angmur. "
gameforge.main_quest_lv94._790_say = "Descobriste o que os Ciclopes est\227o a fazer nas[ENTER]Montanhas do Trov\227o? "
gameforge.main_quest_lv94._800_say = "Os Ciclopes n\227o queriam falar, mas no fim fui[ENTER]capaz de os convencer a dar-me isto: uma pedra[ENTER]negra e este peda\231o de papel. "
gameforge.main_quest_lv94._810_say = "Localiz\225mos os veios de Ouro Negro nas Montanhas[ENTER]do Trov\227o e estamos agora a miner\225-los como[ENTER]pediste. Para a entrega iremos encontrar-nos nas[ENTER]Montanhas do Trov\227o, como planeado. "
gameforge.main_quest_lv94._820_say = "Ouro Negro... Isso \233 um min\233rio que apenas existe[ENTER]nas Montanhas do Trov\227o. Porque \233 que os Servos[ENTER]das Trevas precisam dele? "
gameforge.main_quest_lv94._830_say = "Precisamos de descobrir o que eles est\227o a[ENTER]planear. "
gameforge.main_quest_lv94._840_say = "Aqui diz: "
gameforge.main_quest_lv94._850_sendLetter = "Ouro Negro "
gameforge.main_quest_lv94._860_say = "O Almirante Angmur gostaria de falar contigo[ENTER]sobre o Ouro Negro. "
gameforge.main_quest_lv94._870_say = "O Alquimista n\227o foi capaz de analisar o Ouro[ENTER]Negro. Era um peda\231o demasiado pequeno.[ENTER]Precisamos de descobrir as suas propriedades e a[ENTER]raz\227o pela qual os Servos das Trevas o querem![ENTER]Podes voltar \224s Montanhas do Trov\227o e obter mais[ENTER]amostras de Ouro Negro? "
gameforge.main_quest_lv94._880_say = "Vai ter primeiro com o Alquimista. Ele ir\225[ENTER]dizer-te o n\250mero de amostras que precisa. "
gameforge.main_quest_lv94._890_say = "Fala com o Alquimista. "
gameforge.main_quest_lv94._900_say = "Sauda\231\245es. O Almirante Angmur j\225 te informou[ENTER]sobre a tua tarefa? "
gameforge.main_quest_lv94._910_say = "Sim. De quantas amostras de Ouro Negro precisas? "
gameforge.main_quest_lv94._920_say = "Hmm, deixa-me pensar um segundo. Acho que %d[ENTER]amostras devem ser suficientes para uma an\225lise. "
gameforge.main_quest_lv94._930_say = "Entendido. "
gameforge.main_quest_lv94._940_sayTitle = "O Ouro das Montanhas do Trov\227o "
gameforge.main_quest_lv94._950_sayTitle = "Vai ter com o Alquimista. "
gameforge.main_quest_lv94._960_say = "Procura amostras de Ouro Negro nas Montanhas do[ENTER]Trov\227o. "
gameforge.main_quest_lv94._970_1_notice = "Descobriste um veio de Ouro Negro e conseguiste[ENTER]obter uma amostra do min\233rio. "
gameforge.main_quest_lv94._970_2_notice = "Leva-a ao Alquimista. "
gameforge.main_quest_lv94._980_say = "Ah, encontraste Ouro Negro. Mostra-me! Hmm, n\227o[ENTER]tem falhas e o peda\231o \233 de um tamanho[ENTER]suficiente... sim, posso usar isto para a minha[ENTER]an\225lise. Agora s\243 preciso de mais %d. "
gameforge.main_quest_lv94._990_say = "N\227o posso fazer nada com esta amostra. \201[ENTER]demasiado leve e pequena para uma an\225lise[ENTER]completa. Traz-me outra! "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "Febre de Ouro "
gameforge.main_quest_lv95._020_say = "O Almirante Angmur est\225 \224 tua procura. Ele tem[ENTER]novas informa\231\245es sobre o Ouro Negro. "
gameforge.main_quest_lv95._030_say = "O Ouro Negro extrai energia de criaturas nas suas[ENTER]redondezas e liberta-a para outro corpo. Os[ENTER]Servos das Trevas pretendem infundir Sung Mahi[ENTER]com poder roubado![ENTER]O Gigante Capit\227o Ganchos re\250ne enormes[ENTER]quantidades de Ouro Negro nas Montanhas do[ENTER]Trov\227o. Obt\233m-nas! "
