gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "No Anzol: Capit\227o Ganchos "
gameforge.main_quest_lv95._080_say = "Derrota o Capit\227o Ganchos dos Gigantes e obt\233m o[ENTER]Ouro Negro! "
gameforge.main_quest_lv95._090_say = "N\227o tens tempo a perder. Derrota o Capit\227o[ENTER]Ganchos e obt\233m o Ouro Negro! "
gameforge.main_quest_lv95._100_1_notice = "N\227o havia qualquer rasto do Ouro Negro. Em vez[ENTER]disso, o Capit\227o Ganchos transportava uma carta. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv95._120_say = "Aye, ent\227o conseguiste enfrentar o Capit\227o[ENTER]Ganchos. O que \233 isso? Uma carta? Mostra-me! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Raios. O Capit\227o Ganchos j\225 passou o Ouro Negro \224[ENTER]Banshee.[ENTER]A \250ltima frase \233 um quebra-cabe\231as: A maldi\231\227o da[ENTER]vida ser\225 invocada a partir do nevoeiro do tempo[ENTER]pelo ex\233rcito da escurid\227o. "
gameforge.main_quest_lv95._150_say = "Temos de travar esta entrega! Pensamos que o[ENTER]esconderijo da Banshee fica para oeste da Fal\233sia[ENTER]de Gautama - um local sem deus, constantemente[ENTER]rodeado de um denso nevoeiro. Os Ogres e os[ENTER]L\233mures deambulam por l\225. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "Assim que souber que rota ser\225 usada para levar o[ENTER]Ouro Negro \224 Banshee irei informar-te. "
gameforge.main_quest_lv95._180_sendLetter = "Intercepta a Entrega "
gameforge.main_quest_lv95._190_say = "Vai ter com o Almirante Angmur. Ele tem mais[ENTER]informa\231\245es sobre a entrega do Ouro Negro. "
gameforge.main_quest_lv95._200_say = "Os meus batedores descobriram que o Capit\227o[ENTER]Shruk, comandante dos Ogres, est\225 a transportar o[ENTER]Ouro Negro para a Fal\233sia de Gautama. Ele leva-o[ENTER]num saco atado ao seu cinto. Obt\233m-no! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Entendido. Vou j\225 partir em ca\231a. "
gameforge.main_quest_lv95._230_sayTitle = "Intercepta a entrega! "
gameforge.main_quest_lv95._240_say = "Procura o Capit\227o Shruk e consegue o saco que[ENTER]cont\233m o Ouro Negro antes que ele chegue \224[ENTER]Banshee. "
gameforge.main_quest_lv95._250_say = "O Capit\227o Shruk n\227o \233 tarefa simples. Mas tu[ENTER]consegues derrot\225-lo! Tenta de novo. "
gameforge.main_quest_lv95._260_1_notice = "Recebeste o saco. "
gameforge.main_quest_lv95._260_2_notice = "Regressa com ele ao Almirante Angmur. "
gameforge.main_quest_lv95._270_say = "Leva os teus esp\243lios ao Almirante Angmur. "
gameforge.main_quest_lv95._280_say = "O Ouro Negro est\225 neste saco? Mostra-me![ENTER]Hey?! S\243 est\225 aqui uma nota... "
gameforge.main_quest_lv95._290_say = "A entrega do Ouro Negro ir\225 ter lugar assim que[ENTER]tiver sido completamente processado. "
gameforge.main_quest_lv95._300_say = "Raios, o Ouro Negro ainda se encontra nas m\227os[ENTER]erradas. Pelo menos agora sabemos que ele tem de[ENTER]ser processado antes da Banshee o poder usar para[ENTER]o que pretende. "
gameforge.main_quest_lv95._310_say = "Ainda n\227o \233 demasiado tarde. Irei descobrir quem[ENTER]se encontra actualmente na posse do Ouro Negro e[ENTER]se o mesmo j\225 foi processado. Assim que descobrir[ENTER]algo, mandarei chamar-te. Toma isto como[ENTER]recompensa. At\233 breve! "
gameforge.main_quest_lv95._320_sendLetter = "Interrompe o Processamento "
gameforge.main_quest_lv95._330_say = "Vai ter com o Almirante Angmur. Ele tem novidades[ENTER]sobre o Ouro Negro. "
gameforge.main_quest_lv95._340_say = "Descobrimos que o Grande Ogre est\225 pessoalmente[ENTER]respons\225vel por supervisionar o processamento do[ENTER]Ouro Negro e depois lev\225-lo \224 Banshee. "
gameforge.main_quest_lv95._350_say = "Neste momento ele encontra-se na Fal\233sia de[ENTER]Gautama.[ENTER]Evita que o Ouro Negro chegue ao seu destino.[ENTER]R\225pido, antes que seja demasiado tarde! "
gameforge.main_quest_lv95._360_say = {}
gameforge.main_quest_lv95._370_sayTitle = "O Grande Ogre "
gameforge.main_quest_lv95._380_say = "Derrota o l\237der dos Ogres e evita que o Ouro[ENTER]Negro fique completo. "
gameforge.main_quest_lv95._390_say = "Cada minuto conta! P\225ra o Grande Ogre! "
gameforge.main_quest_lv95._400_notice = "Derrotaste o Grande Ogre. "
gameforge.main_quest_lv95._410_say = "N\227o nos podes travar! A Banshee j\225 recebeu o Ouro[ENTER]Negro. Chegaram demasiado tarde, idiotas! "
gameforge.main_quest_lv95._420_say = "O n\243 aperta-se. Regressa ao Almirante Angmur e[ENTER]d\225-lhe o teu relato. "
gameforge.main_quest_lv95._430_say = "Fala com o Almirante Angmur. "
gameforge.main_quest_lv95._440_say = "Isso foi r\225pido! Tens o Ouro Negro? "
gameforge.main_quest_lv95._450_say = "N\227o, cheguei demasiado tarde. A Banshee j\225 o tem. "
gameforge.main_quest_lv95._460_say = "Que o Deus Drag\227o tenha miseric\243rdia de n\243s. Mas[ENTER]n\227o vamos desistir t\227o facilmente! Irei enviar os[ENTER]meus batedores para descobrirem o paradeiro da[ENTER]Banshee.[ENTER]Assim que tiver conhecimento informar-te-ei. Tira[ENTER]algum tempo para relaxares e aceita isto como[ENTER]recompensa. "
gameforge.main_quest_lv95._470_sendLetter = "Maldi\231\227o da Vida "
gameforge.main_quest_lv95._480_say = "O Almirante Angmur tem novas informa\231\245es para ti.[ENTER]Vai ter com ele. "
gameforge.main_quest_lv95._490_say = "J\225 sabemos o que significam a maldi\231\227o da vida e[ENTER]ex\233rcito da escurid\227o. Outrora viveu um mago[ENTER]horr\237vel na Rocha do Drag\227o Negro. Ele sonhava[ENTER]com o dom\237nio completo sobre o continente e n\227o[ENTER]olhava literalmente a meios para o conseguir:[ENTER]atrav\233s de magia negra ele ergueu os mortos e[ENTER]enviou-os para o combate como um ex\233rcito seu. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Invocar os mortos \150 s\243 pensar nisso faz-me[ENTER]estremecer. Os Servos das Trevas est\227o a usar o[ENTER]Ouro Negro para criar um ex\233rcito de[ENTER]mortos-vivos. Temos de os travar! "
gameforge.main_quest_lv95._520_say = "Procura o Mago L\233mure nas velhas ru\237nas da[ENTER]Fal\233sia de Gautama. Ele sabe qualquer coisa sobre[ENTER]esta maldi\231\227o. Se lhe pedires com jeitinho tenho[ENTER]a certeza que te ir\225 dizer tudo o que precisas de[ENTER]saber. "
gameforge.main_quest_lv95._530_say = "Pedir com jeitinho... hum. Entendido. "
gameforge.main_quest_lv95._540_sayTitle = "Maldi\231\227o da Vida "
gameforge.main_quest_lv95._550_say = "Derrota o Mago L\233mure e obt\233m informa\231\245es sobre a[ENTER]Maldi\231\227o da Vida e a invoca\231\227o dos mortos. "
gameforge.main_quest_lv95._560_say = "N\227o temos tempo a perder. Derrota o Mago L\233mure e[ENTER]espreme-lhe as informa\231\245es sobre a Maldi\231\227o da[ENTER]Vida. "
gameforge.main_quest_lv95._570_1_notice = "Derrotaste o Mago L\233mure e encontraste uma[ENTER]tabuleta de pedra com uma inscri\231\227o. "
gameforge.main_quest_lv95._570_2_notice = "Mostra-a ao Almirante Angmur. "
gameforge.main_quest_lv95._580_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv95._590_say = "Aye, o Mago L\233mure estava na posse desta tabuleta[ENTER]de pedra? Deixa-me dar uma vista de olhos. "
gameforge.main_quest_lv95._600_sayReward = "S\227o necess\225rias tr\234s coisas para acordar os[ENTER]mortos:[ENTER]1. Um corpo humano[ENTER]2. ...[ENTER]A Tabuleta dos L\233mures est\225 partida aqui. Falta o[ENTER]resto da inscri\231\227o. "
gameforge.main_quest_lv95._610_say = "Lamento, mas tens de partir de novo. Precisamos[ENTER]do resto da inscri\231\227o. Devem existir mais duas[ENTER]partes da Tabuleta dos L\233mures. "
gameforge.main_quest_lv95._620_say = "Aqui tens a tua recompensa por tudo o que[ENTER]conseguiste fazer at\233 agora. Agora por favor[ENTER]parte \224 ca\231a do resto da Tabuleta dos L\233mures! "
gameforge.main_quest_lv95._630_sendLetter = "A Inscri\231\227o "
gameforge.main_quest_lv95._640_sayTitle = "Encontra a Tabuleta dos L\233mures! "
gameforge.main_quest_lv95._650_say = "Derrota o Mago L\233mure e encontra os peda\231os que[ENTER]faltam \224 tabuleta de pedra. "
gameforge.main_quest_lv95._660_say = "Por favor, precisamos de saber o que esta[ENTER]inscri\231\227o diz. N\227o desistas! "
gameforge.main_quest_lv95._670_say = "Leva as duas sec\231\245es da Tabuleta dos L\233mures em[ENTER]falta ao Almirante Angmur. "
gameforge.main_quest_lv95._680_say = "Aye, est\225s de volta! Vamos juntar os peda\231os da[ENTER]Tabuleta dos L\233mures e ler a inscri\231\227o. "
gameforge.main_quest_lv95._690_sayReward = "S\227o necess\225rias tr\234s coisas para acordar os[ENTER]mortos:[ENTER]1. Um corpo humano[ENTER]2. Ouro Negro[ENTER]3. Casca de \193rvore Dem\243nio[ENTER]Apenas um mago com habilidade fant\225stica \233 capaz[ENTER]de invocar a Maldi\231\227o da Vida e a manter. E[ENTER]quando morrer, todo o ex\233rcito de mortos-vivos[ENTER]cair\225 consigo. "
gameforge.main_quest_lv95._700_say = "Ent\227o \233 por isto que os nossos cemit\233rios foram[ENTER]profanados e os corpos roubados dos t\250mulos.[ENTER]Pretendem traz\234-los de volta \224 vida e envi\225-los[ENTER]contra n\243s num ex\233rcito de mortos-vivos. Que[ENTER]ideia horripilante! "
gameforge.main_quest_lv95._710_say = "Precisamos de travar este ultraje! "
gameforge.main_quest_lv95._720_say = "Aye, mas o tempo est\225 contra n\243s. Apenas a[ENTER]Banshee \233 capaz de invocar uma maldi\231\227o deste[ENTER]tamanho \150 mas n\227o fazemos ideia de onde ela se[ENTER]esconde. Irei enviar mais homens para encontrar a[ENTER]localiza\231\227o da grande sacerdotisa negra. Assim[ENTER]que souber algo aviso-te. "
gameforge.main_quest_lv95._730_say = {}
gameforge.main_quest_lv95._740_say = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 96. "
gameforge.main_quest_lv95._750_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv95._760_say = "(Em falta: %s %s, %s %s) "
gameforge.main_quest_lv95._770_sayReward = {}
gameforge.main_quest_lv96 = {}
gameforge.main_quest_lv96._010_sendLetter = "Evitar a Maldi\231\227o "
gameforge.main_quest_lv96._020_say = "O Almirante Angmur gostaria de falar contigo. "
gameforge.main_quest_lv96._030_say = "Ainda bem que aqui est\225s. Descobrimos uma forma[ENTER]de sabotar os planos dos Servos e da Banshee. "
gameforge.main_quest_lv96._040_say = {}
gameforge.main_quest_lv96._050_say = {}
gameforge.main_quest_lv96._060_say = "Para que as almas dos mortos possam abandonar os[ENTER]seus corpos \233 necess\225rio um medium. Este medium \233[ENTER]o Terreno Sagrado, que os Gigantes andam a[ENTER]armazenar em sacos.[ENTER]Se fores capaz de roubar 100 sacos, poderemos[ENTER]conseguir evitar a Maldi\231\227o da Vida. "
gameforge.main_quest_lv96._070_say = "Vou p\244r-me j\225 a caminho! "
gameforge.main_quest_lv96._080_sayTitle = "Terreno Sagrado "
gameforge.main_quest_lv96._090_say = "Derrota os Gigantes e rouba 100 sacos de Terreno[ENTER]Sagrado. "
gameforge.main_quest_lv96._100_say = "O tempo est\225 contra n\243s. R\225pido, despacha-te e[ENTER]rouba os sacos de Terreno Sagrado! "
gameforge.main_quest_lv96._110_1_notice = "Roubaste todos os sacos de Terreno Sagrado. "
gameforge.main_quest_lv96._110_2_notice = "Leva-as ao Almirante Angmur. "
gameforge.main_quest_lv96._120_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv96._130_say = "Sabia que pod\237amos contar contigo, como sempre![ENTER]Por favor aceita esta recompensa. "
gameforge.main_quest_lv96._140_sendLetter = "Evitar a Maldi\231\227o "
gameforge.main_quest_lv96._150_say = "O Almirante Angmur tem mais uma tarefa para ti. "
gameforge.main_quest_lv96._160_say = "Os Ogres tamb\233m guardam um medium para a[ENTER]invoca\231\227o dos mortos. Mas n\227o sabemos o que \233.[ENTER]Vai at\233 aos Ogres e traz de volta o que for que[ENTER]te pare\231a suspeito. "
gameforge.main_quest_lv96._170_say = {}
gameforge.main_quest_lv96._180_say = {}
gameforge.main_quest_lv96._190_say = "Entendido. "
gameforge.main_quest_lv96._200_sayTitle = "O Medium dos Ogres "
gameforge.main_quest_lv96._210_say = "Derrota os Ogres e descobre que forma toma o seu[ENTER]medium. "
gameforge.main_quest_lv96._220_say = "Sei que n\227o tens muitas pistas... Mas deve[ENTER]existir algo para encontrares! "
