gameforge.main_quest_lv96._250_say = "Muito bem! Irei pedir ao Yon-I-Walker para[ENTER]analisar estes itens. "
gameforge.main_quest_lv96._260_say = "Encontra o Yon-I-Walker e pede que ele te d\234 os[ENTER]resultados da sua an\225lise. "
gameforge.main_quest_lv96._270_say = "Ah aqui est\225s tu! J\225 consegui dar uma vista de[ENTER]olhos nos itens que encontraste nos Ogres. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "As moedas douradas no saco emanam um forte poder[ENTER]negro. Elas s\227o o medium. Por favor leva esta[ENTER]informa\231\227o ao Almirante Angmur. "
gameforge.main_quest_lv96._300_sendLetter = "Evitar a Maldi\231\227o "
gameforge.main_quest_lv96._310_say = "Vai ter com o Almirante Angmur. "
gameforge.main_quest_lv96._320_say = "Toma, leva a Faixa do Ca\231ador de Ouro. Usa-a para[ENTER]localizares os Sacos de Moedas dos Ogres. "
gameforge.main_quest_lv96._330_say = "Precisamos de 100 Moedas Douradas. Mas nem todas[ENTER]as moedas que vais encontrar podem ser usadas[ENTER]como medium. Tens muito trabalho pela frente. "
gameforge.main_quest_lv96._340_say = "Sem problema. "
gameforge.main_quest_lv96._350_sayTitle = "Ca\231a ao Ouro "
gameforge.main_quest_lv96._360_say = "Vai combater os Ogres e recolher Sacos de Moedas.[ENTER]Nem todas as moedas s\227o mediums \150 analisa-as com[ENTER]o o Yon-I-Walker. "
gameforge.main_quest_lv96._370_say = "Sim, consigo sentir aqui a magia negra. "
gameforge.main_quest_lv96._380_say = "Fant\225stico, agora temos todas as moedas que podem[ENTER]ser usadas como medium. Isto n\227o ir\225 deixar a[ENTER]Banshee muito alegre certamente![ENTER]Toma, aceita isto como recompensa. O Angmur ir\225[ENTER]dar-te a tua pr\243xima tarefa. "
gameforge.main_quest_lv96._390_say = "Ainda h\225 moedas douradas em falta. Recolhe mais[ENTER]%d. "
gameforge.main_quest_lv96._400_sendLetter = "Evitar a Maldi\231\227o "
gameforge.main_quest_lv96._410_say = "O Almirante Angmur est\225 \224 tua procura. "
gameforge.main_quest_lv96._420_say = "Precisamos de garantir que os Servos das Trevas[ENTER]n\227o s\227o capazes de obter a Casca de \193rvore[ENTER]Dem\243nio. "
gameforge.main_quest_lv96._430_say = "As \193rvores Dem\243nio s\227o uma das esp\233cies mais[ENTER]misteriosas do nosso mundo e n\227o servem qualquer[ENTER]pessoa, nem mesmo Sung Mahi.[ENTER]Existem tr\234s tipos delas na Fal\233sia de Gautama:[ENTER]Aku-Boku, Arboretum e Sic\243moro. Rouba-lhes a[ENTER]casca! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Entendido. "
gameforge.main_quest_lv96._460_sayTitle = "Podar as \193rvores Dem\243nio "
gameforge.main_quest_lv96._470_say = "Rouba a casca de uma Aku-Boku, uma Arboretum e[ENTER]uma Sic\243moro. "
gameforge.main_quest_lv96._480_counterName = "(Em falta: %s %s, %s %s) "
gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "O tempo urge. Torna as \193rvores Dem\243nio em em[ENTER]farpas e obt\233m a sua casca antes que os Servos o[ENTER]consigam! "
gameforge.main_quest_lv96._510_1_notice = "Derrotaste todas as \193rvores Dem\243nio, mas algu\233m[ENTER]chegou l\225 antes de ti: a casca j\225 tinha sido[ENTER]arrancada dos troncos. "
gameforge.main_quest_lv96._510_2_notice = "Levas estas not\237cias ao Almirante Angmur. "
gameforge.main_quest_lv96._520_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv96._530_say = "\201 bom ver que regressas inteiro! Tiveste sucesso?[ENTER]O qu\234?! A casca j\225 tinha sido arrancada \224s[ENTER]\193rvores Dem\243nio e havia sinais de um combate[ENTER]recente? Os Servos das Trevas devem ter chegado[ENTER]l\225 antes de n\243s. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Se eles t\234m a casca, ent\227o eles tamb\233m ir\227o[ENTER]encontrar uma forma de invocar a Maldi\231\227o da[ENTER]Vida.[ENTER]Parece ser inevit\225vel \150 vamos para a guerra. A[ENTER]Banshee n\227o se poder\225 esconder de n\243s por muito[ENTER]mais tempo. Os meus homens j\225 se encontram no seu[ENTER]rasto. Irei mandar-te chamar quando a tivermos[ENTER]encontrado. "
gameforge.main_quest_lv96._560_sayTitle = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 97. "
gameforge.main_quest_lv96._570_counterName = "(Em falta: %s %s, %s %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d unidades "
gameforge.main_quest_lv96._590_say = "Ent\227o as moedas douradas servem como um medium.[ENTER]Bem, irei aconselhar-me com o Yon-I-Walker sobre[ENTER]os nossos pr\243ximos passos. Entrarei em contacto[ENTER]contigo em breve. "
gameforge.main_quest_lv96._600_say = {}
