gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "Travar a Banshee "
gameforge.main_quest_lv97._020_say = "O esconderijo da Banshee foi descoberto! Vai ter[ENTER]com o Almirante Angmur para saberes mais. "
gameforge.main_quest_lv97._030_say = "Os meus homens descobriram finalmente a base da[ENTER]Banshee na Fal\233sia de Gautama. Ela encontra-se[ENTER]escondida no negrume das profundezas das[ENTER]florestas nessa zona e encontra-se a\237 a trabalhar[ENTER]na sua magia negra. Mais ainda, ela acordou um[ENTER]dos seus antigos Servos do Templo do Culto do[ENTER]Drag\227o. Em conjunto, ela pretende invocar a[ENTER]Maldi\231\227o da Vida. "
gameforge.main_quest_lv97._040_say = "Sem a sua ajuda, a Banshee n\227o ser\225 capaz de[ENTER]manter a Maldi\231\227o. Derrota a Serva do Templo,[ENTER]Mu-Shu, e acalma as almas dos nossos camaradas,[ENTER]antes que os seus corpos se ergam contra n\243s. "
gameforge.main_quest_lv97._050_say = "\201 praticamente imposs\237vel conseguirmos[ENTER]esgueirar-nos at\233 perto da Serva do Templo para a[ENTER]atacarmos. Aproveita o momento em que ela se[ENTER]encontra t\227o concentrada na sua magia negra que[ENTER]ela cai num estado de transe! "
gameforge.main_quest_lv97._060_say = "Entendido. "
gameforge.main_quest_lv97._070_say = "Tem cuidado! Quando era viva, ela era a[ENTER]guarda-costas principal da grande sacerdotisa e[ENTER]teve um excelente treino n\227o s\243 em magia, como[ENTER]tamb\233m no combate com espada. "
gameforge.main_quest_lv97._080_sayTitle = "A Serva do Templo "
gameforge.main_quest_lv97._090_say = "Derrota Mu-Shu, a Serva do Templo da Banshee, na[ENTER]Fal\233sia de Gautama. "
gameforge.main_quest_lv97._100_notice = "Com um golpe mortal desferido, a Serva do Templo[ENTER]fica por terra. "
gameforge.main_quest_lv97._110_say = "Seus tolos! Ca\237ram na armadilha que a Banshee[ENTER]criou para voc\234s. Enquanto perdiam o vosso tempo[ENTER]comigo, a minha Senhora e Yah-Ki, a verdadeira[ENTER]Serva do Templo, j\225 deram in\237cio \224 Maldi\231\227o. Rezo[ENTER]para que tenham sucesso! "
gameforge.main_quest_lv97._120_say = "Uma s\243sia desviou as tuas aten\231\245es! Depois de a[ENTER]revistares, encontras um colar semelhante \224quele[ENTER]do Martyaxwar. No compartimento interior[ENTER]encontra-se um documento. "
gameforge.main_quest_lv97._130_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv97._140_say = "Est\225s de volta! Derrotaste a Serva do Templo? "
gameforge.main_quest_lv97._150_say = "N\227o, fomos enganados por uma s\243sia. A verdadeira[ENTER]Serva do Templo conseguiu preparar a invoca\231\227o[ENTER]dos mortos em paz. Mas toma, encontrei este[ENTER]documento. "
gameforge.main_quest_lv97._160_say = "Maldi\231\227o! Como fomos capazes de cair no joguinho[ENTER]dela?! Por favor, mostra-me o documento. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hmm, encriptado. Mas talvez esta mensagem nos[ENTER]possa revelar onde \233 que a sua base realmente se[ENTER]encontra escondida. J\225 vi caracteres iguais a[ENTER]estes antes... Creio que Yak-Hwan, o Guarda do[ENTER]Pal\225cio, mostrou-me algo semelhante recentemente.[ENTER]Vai ter com ele. Ele devia dar uma vista de olhos. "
gameforge.main_quest_lv97._200_sendLetter = "Descodificar o documento "
gameforge.main_quest_lv97._210_say = "Vai ter com o Yak-Hwan e mostra-lhe o documento[ENTER]encriptado. "
gameforge.main_quest_lv97._220_say = "Sauda\231\245es! O meu nome \233 Yak-Hwan. \201 uma honra[ENTER]conhecer-te. Os teus feitos j\225 s\227o lend\225rios! Que[ENTER]posso fazer por ti?[ENTER]Ah, uma mensagem encriptada. Deixa-me ver. "
gameforge.main_quest_lv97._230_say = "Sim, devo ser capaz de conseguir descodificar[ENTER]estes caracteres sem problema. No entanto, para[ENTER]isso irei precisar de Terra F\243ssil. O alquimista[ENTER]\233 capaz de ter um bocado por l\225. Por favor vai[ENTER]ter com ele e pergunta-lhe. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Claro. "
gameforge.main_quest_lv97._270_sayTitle = "Terra F\243ssil "
gameforge.main_quest_lv97._280_say = "Vai ter com o alquimista e pergunta-lhe sobre a[ENTER]Terra F\243ssil. "
gameforge.main_quest_lv97._290_say = "N\227o te est\225s a esquecer de nada? Precisas de me[ENTER]trazer a Terra F\243ssil. "
gameforge.main_quest_lv97._300_notice = "O alquimista deu-te a Terra F\243ssil. Agora[ENTER]regressa ao Yak-Hwan. "
gameforge.main_quest_lv97._310_say = "Ah, a Terra F\243ssil. Muito bem, vou deitar m\227os ao[ENTER]trabalho. Irei reportar o que descobrir ao[ENTER]Almirante. "
gameforge.main_quest_lv97._320_sendLetter = "Pela porta das traseiras "
gameforge.main_quest_lv97._330_say = "O Almirante Angmur est\225 \224 tua procura. "
gameforge.main_quest_lv97._340_say = "J\225 sabemos onde reside a Serva do Templo Yah-Ki.[ENTER]Mas a base parece um forte \150 tropas patrulham-na[ENTER]o dia todo. Desta vez um ataque directo seria[ENTER]puro suic\237dio. "
gameforge.main_quest_lv97._350_say = "Por esta raz\227o queremos atacar numa emboscada.[ENTER]Os meus homens est\227o \224 procura do local[ENTER]apropriado. Distrai os guardas para nos dares[ENTER]mais tempo. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "O maior perigo prov\233m de uma tropa de guardas que[ENTER]se auto-intitulam Brigada da Morte Negra. Esta[ENTER]Brigada \233 composta por: Moghu, Carnifex e General[ENTER]Albus. O seu l\237der \233 o Skeletos.[ENTER]Elimina-os antes que eles descubram o meu[ENTER]ex\233rcito de batedores. "
gameforge.main_quest_lv97._380_say = "Entendido. "
gameforge.main_quest_lv97._390_sayTitle = "Brigada da Morte Negra "
gameforge.main_quest_lv97._400_say = "Elimina a Brigada da Morte Negra composta por[ENTER]Moghu, Carnifex, General Albus e Skeletos. "
gameforge.main_quest_lv97._410_say = "Derrota os membros da Brigada da Morte Negra[ENTER]antes que eles descubram o ex\233rcito de batedores. "
gameforge.main_quest_lv97._420_say = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv97._430_say = "O nosso plano est\225 pronto para entrar em ac\231\227o![ENTER]Enquanto distra\237as a Brigada da Morte Negra os[ENTER]meus homens encontraram uma boa posi\231\227o para uma[ENTER]emboscada.[ENTER]Assim que a nossa estrat\233gia de ataque estiver[ENTER]definida irei mandar chamar-te. "
gameforge.main_quest_lv97._440_sendLetter = "A Serva do Templo "
gameforge.main_quest_lv97._450_say = "O Almirante Angmur precisa da tua ajuda! "
gameforge.main_quest_lv97._460_say = "Ainda bem que aqui est\225s. Skeletos, o l\237der da[ENTER]Brigada da Morte Negra, sobreviveu e atacou os[ENTER]meus homens no preciso momento em que estavam a[ENTER]planear atacar a base. Ningu\233m foi capaz de[ENTER]passar por ele. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "J\225 o derrotaste uma vez, por favor ajuda os meus[ENTER]homens na Fal\233sia de Gautama! Enfrenta o[ENTER]Skeletos. Depois disso, ataca a base e mata a[ENTER]Serva do Templo, Yah-Ki. "
gameforge.main_quest_lv97._490_say = "Entendido. "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Derrota a Yah-Ki "
gameforge.main_quest_lv97._520_say = "Derrota a Serva do Templo, Yah-Ki, e evita que[ENTER]ela invoque o ex\233rcito dos mortos. "
gameforge.main_quest_lv97._530_say = "O dia decisivo chegou. Se cairmos, o mundo cair\225[ENTER]connosco. Mas se formos vitoriosos, os nossos[ENTER]feitos ser\227o cantados mesmo daqui a 100 anos.[ENTER]Trava os Servos das Trevas. Derrota a Serva do[ENTER]Templo, Yah-Ki! "
gameforge.main_quest_lv97._540_say = "O que est\225s aqui a fazer? A batalha ainda n\227o[ENTER]est\225 ganha! Derrota a Serva do Templo, Yah-Ki.[ENTER]Todas as nossas esperan\231as est\227o contigo. "
gameforge.main_quest_lv97._550_1_notice = "Deitaste o teu advers\225rio por terra e a vit\243ria \233[ENTER]tua! "
gameforge.main_quest_lv97._550_2_notice = "N\227o h\225 tempo para descansar \150 a Serva do Templo,[ENTER]Yah-Ki, espera-te. "
gameforge.main_quest_lv97._560_notice = "Venceste! Com um grito de gelar o sangue, a[ENTER]Yah-Ki cai por terra. "
gameforge.main_quest_lv97._570_say = "Aaargh! Isto n\227o \233 poss\237vel! Derrotada por um[ENTER]mortal... oh, Banshee, perdoai-me! Falhei. N\227o[ENTER]consegui completar a minha tare... "
gameforge.main_quest_lv97._580_say = "Revistas o seu corpo sem vida e encontras uma[ENTER]carta selada. Regressa com ela ao Almirante[ENTER]Angmur. "
gameforge.main_quest_lv97._590_say = "Aye, louvado seja o Deus Drag\227o! Est\225s de volta,[ENTER]e inteiro! Derrotaste a Serva do Templo? "
gameforge.main_quest_lv97._600_say = "Sim, enviei-a de volta para o Inferno de onde[ENTER]saiu. No momento da sua morte ela implorou[ENTER]desculpa \224 Banshee pelo seu fracasso. Ela tinha[ENTER]isto em sua posse. "
gameforge.main_quest_lv97._610_say = "Uma carta selada. Mostra-me! "
gameforge.main_quest_lv97._620_sayReward = "Minha Senhora, Eles engoliram o nosso isco e o[ENTER]nosso plano est\225 a funcionar. A invoca\231\227o do[ENTER]ex\233rcito dos mortos est\225 a decorrer e ningu\233m nos[ENTER]conseguir\225 parar agora. Assim que os corpos sem[ENTER]vida come\231arem a marchar, iremos atacar o Cabo[ENTER]Fogo de Drag\227o e enterrar a sua popula\231\227o sob os[ENTER]nossos p\233s. Iremos depois atravessar para o[ENTER]continente e vos encontraremos na Terra do Fogo.[ENTER]O mundo ir\225 arder sob os nossos passos![ENTER]Curvo-me profundamente perante a Senhora, A sua[ENTER]Serva eterna "
gameforge.main_quest_lv97._630_say = "Uma mensagem para a Banshee! Aye, a maldita bruxa[ENTER]espera agora em v\227o pelo seu ex\233rcito das trevas[ENTER]na Terra do Fogo.[ENTER]Agrade\231o-te. Sem a tua ajuda, o Cabo Fogo de[ENTER]Drag\227o e a sua popula\231\227o teria sido destru\237do[ENTER]pelo ex\233rcito de mortos. N\227o s\243 nos salvaste,[ENTER]como devolveste a paz \224s almas dos nossos[ENTER]antepassados.[ENTER]Presenteio-te com esta recompensa por tudo o que[ENTER]fizeste. "
gameforge.main_quest_lv97._640_sayTitle = "A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 98. "
gameforge.main_quest_lv97._650_say = "Precis\225mos de muito tempo para localizar a base.[ENTER]Por favor, n\227o podemos perder mais tempo! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan precisa de Terra F\243ssil? Felizmente[ENTER]ainda n\227o a usei toda. Toma, n\227o tens de qu\234.[ENTER]Leva-a at\233 ele e d\225-lhe os meus cumprimentos. "
gameforge.main_quest_lv97._670_counterName = "(Em falta: %s %s, %s %s) "
gameforge.main_quest_lv97._680_sayReward = {}
gameforge.main_quest_lv97._690_1_notice = "Eliminaste a Brigada da Morte Negra "
gameforge.main_quest_lv97._690_2_notice = "Regressa ao Almirante Angmur. "
gameforge.main_quest_lv97._700_sayTitle = "Derrota Skeletos, l\237der da Brigada da Morte Negra! "
gameforge.main_quest_lv97._710_say = "A Serva do Templo poder\225 ser derrotada de uma vez[ENTER]por todas quando tiveres derrotado o Skeletos. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Reconstru\231\227o do Forte "
gameforge.main_quest_lv98._020_say = "O Almirante Angmur est\225 \224 procura da tua ajuda.[ENTER]Vai ter com ele. "
gameforge.main_quest_lv98._030_say = "Obrigado por vires. O combate n\227o nos passou sem[ENTER]deixar o seu rasto. O forte tamb\233m foi atacado e[ENTER]a muralha protectora foi deitada abaixo em v\225rios[ENTER]locais. Esta paz n\227o ir\225 durar muito. Precisamos[ENTER]de usar esta calma em nosso proveito e[ENTER]reconstruir. "
gameforge.main_quest_lv98._040_say = "Para fortificar a muralha protectora precisamos[ENTER]da armadura da tribo de crust\225ceos. "
gameforge.main_quest_lv98._050_say = "Entendido. De quantas unidades desta armadura[ENTER]precisas? "
gameforge.main_quest_lv98._060_say = "100 dever\227o ser suficientes. Ainda podes atacar a[ENTER]tribo de crust\225ceos na Ba\237a de Nephrite. "
gameforge.main_quest_lv98._070_say = "Aye, isso n\227o \233 uma quantidade suficiente de[ENTER]Armadura Crust\225cea. Por favor obt\233m mais algumas[ENTER]unidades. "
gameforge.main_quest_lv98._080_1_notice = "J\225 recolheste todas as unidades de Armadura[ENTER]Crust\225cea que precisavas. "
gameforge.main_quest_lv98._080_2_notice = "Leva-as ao Almirante Angmur. "
gameforge.main_quest_lv98._090_say = "Aye, muito bem. A Armadura Crust\225cea ir\225[ENTER]ajudar-nos a refortificar a muralha protectora.[ENTER]Por favor aceita isto como recompensa. Irei[ENTER]perguntar aos meus engenheiros se necessitam de[ENTER]mais algum material para depois te dizer. "
gameforge.main_quest_lv98._130_sendLetter = "Reconstru\231\227o do Forte "
gameforge.main_quest_lv98._140_say = "O Almirante Angmur precisa de novo da tua ajuda.[ENTER]Vai ter com ele. "
gameforge.main_quest_lv98._150_say = "Para fortificarmos ainda mais a muralha[ENTER]precisamos de Lan\231as do Trit\227o. Como o nome[ENTER]sugere, ir\225s encontr\225-las entre os Trit\245es. Por[ENTER]favor traz-me 100. "
gameforge.main_quest_lv98._160_say = "Entendido. "
gameforge.main_quest_lv98._170_say = "Aqui est\225s tu! Aye, isso n\227o s\227o Lan\231as do Trit\227o[ENTER]suficientes. Por favor continua a recolh\234-las. "
gameforge.main_quest_lv98._180_1_notice = "Recolheste todas as Lan\231as do Trit\227o "
gameforge.main_quest_lv98._180_2_notice = "Leva-as ao Almirante Angmur. "
gameforge.main_quest_lv98._190_say = "Perfeito! Agora podemos construir uma[ENTER]fortifica\231\227o defensiva mais segura. Agrade\231o a[ENTER]tua ajuda. J\225 agora, o Yak-Hwan est\225 \224 tua[ENTER]procura. Descobre o que ele quer. "
gameforge.main_quest_lv98._200_sendLetter = "Emerg\234ncia "
gameforge.main_quest_lv98._210_say = "Vai ter com o Yak-Hwan. Ele tem uma tarefa[ENTER]importante para ti. "
gameforge.main_quest_lv98._220_say = "Ah, muito bem, aqui est\225s tu! Precisamos da tua[ENTER]assist\234ncia mais uma vez. "
gameforge.main_quest_lv98._230_say = {}
gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "Os tempos dif\237ceis da guerra n\227o passaram pelas[ENTER]pessoas que residem no forte sem deixarem rasto.[ENTER]Elas est\227o a sofrer \224 fome e a sua mis\233ria cresce[ENTER]a cada dia que passa. Se n\227o fizermos nada, isto[ENTER]n\227o acabar\225 bem para elas. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Gangs de ogres andam a emboscar e atacar os[ENTER]nossos transportes de mantimentos. Temos de[ENTER]travar esta pilhagem. O Capit\227o Shruk e os seus[ENTER]generais est\227o por detr\225s disto. Mata o capit\227o[ENTER]dos ogres e 50 Generais Ogg! "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "J\225 est\225s de volta? Ainda existem alguns ogres por[ENTER]a\237. Por favor d\225 cabo deles todos! "
gameforge.main_quest_lv98._310_1_notice = "Derrotaste todos os ogres. "
gameforge.main_quest_lv98._310_2_notice = "Agora regressa ao Yak-Hwan. "
gameforge.main_quest_lv98._320_say = "Finalmente os transportes de mantimentos est\227o a[ENTER]chegar ao forte e as nossas pessoas est\227o a[ENTER]receber comida e medicamentos! O estado de[ENTER]emerg\234ncia est\225 a terminar. \201s um verdadeiro[ENTER]her\243i. "
gameforge.main_quest_lv98._330_sendLetter = "Agradecimento "
gameforge.main_quest_lv98._340_say = "O Yak-Hwan quer falar contigo. "
gameforge.main_quest_lv98._350_say = "Gra\231as \224 tua ajuda, o perigo na Rocha do Drag\227o[ENTER]Negro foi banido por agora. Por essa raz\227o, as[ENTER]pessoas gostariam de te agradecer pessoalmente. "
gameforge.main_quest_lv98._360_say = "D\225 uma volta ao forte e fala com as pessoas. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "Obrigado. Irei visitar todos os residentes. "
gameforge.main_quest_lv98._390_say = "Nem todos os cidad\227os tiveram a oportunidade de[ENTER]te agradecer. Eles ficar\227o desapontados. Por[ENTER]favor certifica-te de que n\227o te esqueceste de[ENTER]ningu\233m. "
gameforge.main_quest_lv98._400_say = "Coragem e sabedoria est\227o no teu cora\231\227o em[ENTER]iguais quantidades. Os teus feitos ser\227o cantados[ENTER]daqui a gera\231\245es. Curvo-me perante ti. "
gameforge.main_quest_lv98._410_say = "Que estejas sempre bem armado contra todos os[ENTER]perigos! "
gameforge.main_quest_lv98._420_say = "Tens um lugar de honra nos nossos cora\231\245es para[ENTER]sempre. "
gameforge.main_quest_lv98._430_say = "Aqueles foram alguns tempos turbulentos, n\227o[ENTER]foram? Tenho a certeza que o pr\243prio Deus Drag\227o[ENTER]foi o respons\225vel por te mostrar o caminho para a[ENTER]nossa ilha. "
gameforge.main_quest_lv98._440_1_notice = "Falaste com todos os residentes. "
gameforge.main_quest_lv98._440_2_notice = "Agora regressa ao Yak-Hwan. "
gameforge.main_quest_lv98._450_say = "Isso significou muito para os residentes do forte.O Almirante gostaria de falar contigo mais uma[ENTER]vez. Vai ter com ele de seguida. "
gameforge.main_quest_lv98._460_say = {}
gameforge.main_quest_lv98._470_say = {}
gameforge.main_quest_lv98._480_sendLetter = "O Agradecimento do Almirante "
gameforge.main_quest_lv98._490_say = "O Almirante Angmur gostaria de mostrar a sua[ENTER]gratid\227o para contigo. Vai ter com ele. "
gameforge.main_quest_lv98._500_say = "Sem ti, os residentes deste forte teriam sido[ENTER]massacrados por dem\243nios. Pela tua ajuda no[ENTER]combate contra os Servos das Trevas, agrade\231o-te,[ENTER]em nome das minhas tropas e de toda a popula\231\227o.[ENTER]Na Rocha do Drag\227o Negro ir\225s sempre encontrar um[ENTER]local ao qual poder\225s chamar casa. "
gameforge.main_quest_lv98._510_say = {}
gameforge.main_quest_lv98._520_say = "Mas a Banshee e os Servos das Trevas n\227o ir\227o[ENTER]fazer qualquer tipo de pausa e ir\227o continuar[ENTER]indefinidamente a forjar os seus negros planos.[ENTER]A aventura continuar\225 assim que tiveres atingido[ENTER]o n\237vel 99. "
