gameforge.manwoo = {}
gameforge.manwoo._10_npcChat = "O viveiro de peixes "
gameforge.manwoo._20_sayTitle = "Pescador: "
gameforge.manwoo._30_say = "Gostava de aumentar o meu viveiro de peixes. Para[ENTER]isso preciso de Carpas ainda vivas. S\227o peixes[ENTER]bons para procriar e s\227o bastante populares ente[ENTER]os pescadores. No entanto s\227o dif\237ceis de[ENTER]apanhar. "
gameforge.manwoo._40_say = "Se me trouxeres uma Carpa irei oferecer-te uma[ENTER]recompensa. Tenho uma Caixa no meu s\243t\227o h\225 anos.[ENTER]J\225 nem me lembro do que est\225 no seu interior.[ENTER]Tanto pode ser algo sem valor como algo[ENTER]extremamente valioso. At\233 monstros podem estar no[ENTER]seu interior.[ENTER]Se quiseres a minha Caixa traz-me uma Carpa ainda[ENTER]viva. "
gameforge.manwoo._50_npcChat = "Trocar a Carpa pela Caixa "
gameforge.manwoo._60_say = "Trazes uma Carpa para o meu viveiro? Obrigado![ENTER]Aqui est\225 a caixa que te prometi. Boa sorte! "
gameforge.manwoo._70_sayReward = "Recebeste uma Caixa![ENTER]Clica com o bot\227o direito para a abrires. "
gameforge.map_warp = {}
gameforge.map_warp._100_say = "Despacha-te e diz-me para onde queres ser[ENTER]transportado. Estou cansado. "
gameforge.map_warp._10_npcChat = "Quero viajar. "
gameforge.map_warp._110_sayReward = "Isto custa %s Yang. "
gameforge.map_warp._11_array = "\193rea Jungrang "
gameforge.map_warp._120_sayReward = "Mas vou aumentar o pre\231o se continuares com isto! "
gameforge.map_warp._12_array = "\193rea Waryong "
gameforge.map_warp._130_say = "Como j\225 disse: Apenas posso transportar-te para[ENTER]este local quando tiveres atingido o n\237vel 60.[ENTER]Ainda queres ser transportado? Se n\227o, fecha a[ENTER]janela.[ENTER]E p\225ra de mudar de ideias. N\227o estou aqui para[ENTER]brincadeiras. "
gameforge.map_warp._13_array = "\193rea Imha "
gameforge.map_warp._140_sayReward = "A viagem ir\225 custar-te %d Yang. "
gameforge.map_warp._14_array = "Castelo Shinsoo "
gameforge.map_warp._150_say = "Podia transportar-te gratuitamente, mas tenho uma[ENTER]fam\237lia grande. Tenho de os sustentar, por isso[ENTER]preciso de ganhar dinheiro. "
gameforge.map_warp._15_array = "Castelo Chunjo "
gameforge.map_warp._160_sayReward = "Custa %s Yang. "
gameforge.map_warp._16_array = "Castelo Jinno "
gameforge.map_warp._170_say = "Vou transportar-te imediatamente. Vais para um[ENTER]lugar perigoso, por isso tem cuidado. Boa sorte! "
gameforge.map_warp._17_array = "\193rea Miryang "
gameforge.map_warp._180_select = "Yongan "
gameforge.map_warp._18_array = "\193rea Songpa "
gameforge.map_warp._190_select = "Grafschaft Yayang "
gameforge.map_warp._19_array = "\193rea Daeyami "
gameforge.map_warp._200_select = "Joan "
gameforge.map_warp._20_sayTitle = "Teleportador:  "
gameforge.map_warp._210_select = "\193rea Bokjung "
gameforge.map_warp._220_select = "Pyungmoo "
gameforge.map_warp._230_select = "\193rea Bakra "
gameforge.map_warp._240_say = "Como quiseres. Tem cuidado, aqui vamos! "
gameforge.map_warp._250_say = "Como quiseres... Vejo-te em breve! "
gameforge.map_warp._260_npcChat = "Rocha do Drag\227o Negro "
gameforge.map_warp._270_say = "Recentemente foi descoberta uma nova ilha[ENTER]misteriosa. Foi designada como Rocha do Drag\227o[ENTER]Negro. Todos os que queiram sobreviver a esse[ENTER]lugar t\234m de ter bastante experi\234ncia. Por essa[ENTER]raz\227o, apenas poderei transportar quem j\225 tenha[ENTER]atingido o n\237vel 90.[ENTER]Est\225s preparado para fazer esta viagem? "
gameforge.map_warp._280_say = "Apenas podes chegar \224 ilha de navio \150 e a viagem[ENTER]para l\225 \233 longa e \225rdua. Quanto mais alto for o[ENTER]teu n\237vel, mais exigente ser\225 o transporte. Por[ENTER]esta raz\227o tenho que te cobrar uma taxa mais[ENTER]alta. "
gameforge.map_warp._280_sayReward = "A viagem ir\225 custar-te %d Yang. "
gameforge.map_warp._30_say = "Este \233 um lugar fascinante. Mas alguma vez[ENTER]acontece algo fora do normal por aqui?[ENTER]Provavelmente n\227o. Noutras partes do Reino tudo \233[ENTER]diferente! Tenho a certeza que existe algum lugar[ENTER]interessante para onde te possa transportar. Como[ENTER]os poderes do mal est\227o de novo mais fortes, o[ENTER]espa\231o e o tempo est\227o num caos. Nem sempre[ENTER]poder\225s regressar.[ENTER]Queres ser transportado? "
gameforge.map_warp._40_say = "Hm... Com o teu n\237vel actual ainda \233s demasiado[ENTER]fraco para aguentar a viagem pelo espa\231o e tempo.[ENTER]Volta quando estiveres acima de n\237vel 10. "
gameforge.map_warp._50_say = "Para onde te queres teleportar? "
gameforge.map_warp._60_sayReward = "Isto custa %s Yang. "
gameforge.map_warp._70_say = "Estes s\227o os lugares para onde te posso[ENTER]teleportar assim que atinges o n\237vel 60. "
gameforge.map_warp._80_sayReward = "Mas ir\225 custar-te %s Yang. "
