gameforge.map_warp._97_select = "Usar o Amuleto Deus Drag\227o "
gameforge.marriage_manage = {}
gameforge.marriage_manage._1000_npcChat = "Lista de Casamentos "
gameforge.marriage_manage._100_sayItem = "Fato de Casamento "
gameforge.marriage_manage._1010_say = "De momento n\227o h\225 Casamentos a decorrer. "
gameforge.marriage_manage._1015_foreach = "%s & %s "
gameforge.marriage_manage._1020_say = "\201s um convidado neste Casamento! Diverte-te! "
gameforge.marriage_manage._1030_say = "A tinta ainda nem secou! D\234em mais um tempo. "
gameforge.marriage_manage._10_npcChat = "Quero casar-me "
gameforge.marriage_manage._110_sayReward = "Se te quiseres casar ter\225s de usar um Fato de[ENTER]Casamento. "
gameforge.marriage_manage._120_sayItem = "Vestido de Casamento "
gameforge.marriage_manage._130_sayReward = "Se te quiseres casar tens de usar um Vestido de[ENTER]Casamento. "
gameforge.marriage_manage._140_say = "O amor por si s\243 n\227o te pode ajudar a organizar[ENTER]um casamento, tamb\233m precisas de Yang.[ENTER]Infelizmente n\227o tens Yang suficiente neste[ENTER]momento. Quando tiveres poupado 1 milh\227o de Yang,[ENTER]poderei planear a tua cerim\243nia. "
gameforge.marriage_manage._150_sayReward = "Precisas de 1.000.000 Yang. "
gameforge.marriage_manage._160_say = "J\225 tens maturidade suficiente e pareces estar[ENTER]determinado. Com quem queres casar? "
gameforge.marriage_manage._170_sayReward = "Por favor introduz o nome da pessoa com quem[ENTER]queres casar. "
gameforge.marriage_manage._180_say = "Est\225s t\227o excitado que nem consegues escrever o[ENTER]nome? Tenta de novo. "
gameforge.marriage_manage._190_say = "Ent\227o n\227o sabes o nome da pessoa com quem queres[ENTER]casar? Tens a certeza de que te queres casar? "
gameforge.marriage_manage._200_sayReward = "%s n\227o est\225 online. "
gameforge.marriage_manage._20_say = "J\225 h\225 um Casamento a decorrer. Espera um pouco ou[ENTER]volta mais tarde! "
