gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah, \233s tu! J\225 n\227o nos vemos h\225 algum tempo.[ENTER]Mais um ano passou, ho ho ho![ENTER]Talvez te estejas a perguntar porque regressei \224[ENTER]vila. Permite-me que te explique... "
gameforge.new_christmas._030_say = "Vivemos tempos dif\237ceis. Hoje em dia poucas s\227o[ENTER]as pessoas que querem comprar livros ou outras[ENTER]coisas do g\233nero. Com o avan\231ar da minha idade,[ENTER]fica cada vez mais dif\237cil voar por a\237 num tren\243[ENTER]puxado por renas. Por essa raz\227o, este ano decidi[ENTER]celebrar o Natal aqui na vila. "
gameforge.new_christmas._040_say = "Se tiveres mais quest\245es n\227o hesites em[ENTER]perguntar-me. Feliz Natal! "
gameforge.new_christmas._050_npcChat = "Gostarias de um pouco de Vinho Quente? "
gameforge.new_christmas._060_say = "Ho ho o! Certamente sabes o que isso \233, correcto?[ENTER]N\227o existe bebida melhor para o Inverno! Misturas[ENTER]um bom vinho, uma pitada de canela e um pouco de[ENTER]cravo... mmmmm! "
gameforge.new_christmas._070_say = "Nestes dias t\227o frios, um gole de Vinho Quente[ENTER]ir\225 fazer-te maravilhas! Ir\225 dar-te for\231a e[ENTER]ajudar-te a moveres-te mais rapidamente.[ENTER]Gostarias de experimentar?[ENTER]Muito bem, um copo de Vinho Quente a sair! "
gameforge.new_christmas._080_say = "Pareces gostar do sabor do Vinho Quente ho ho![ENTER]Sentes o calor a espalhar-se dentro de ti? Oh, e[ENTER]o sabor... T\227o doce e frutado! Feliz Natal! "
gameforge.new_christmas._090_npcChat = "Mais Vinho Quente por favor! "
gameforge.new_christmas._100_say = "Espera um segundo! Esqueci-me de um pequeno[ENTER]pormenor! Apenas posso preparar-te Vinho Quente[ENTER]uma vez por dia, pois n\227o tenho ingredientes[ENTER]suficientes para mais. E dura apenas 20 horas.[ENTER]Numa garrafa existem 6 por\231\245es, e os efeitos de[ENTER]cada gole duram 30 minutos. Consome o Vinho de[ENTER]forma sensata! "
gameforge.new_christmas._110_say = "De nada! J\225 tiveste de esperar tempo suficiente.[ENTER]Esta maravilhosa bebida ir\225 dar-te asas, ho ho[ENTER]ho! Por isso espero que a aproveites. Feliz[ENTER]Natal! "
gameforge.new_christmas._120_say = "O qu\234, queres mais? Desculpa, mas acho que j\225[ENTER]bebeste o suficiente. Ainda n\227o passaram 24 horas[ENTER]desde que te servi uma ra\231\227o de Vinho Quente.[ENTER]Demasiada bebida n\227o te far\225 bem, sabes?![ENTER]Volta mais tarde. E at\233 l\225 diverte-te com as[ENTER]festividades! "
