gameforge.new_christmas_gift_box._020_say = "Desembrulha o pr\243ximo presente em %d min. "
gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Para que s\227o as Meias? "
gameforge.new_christmas_sock._020_say = "As Meias! Quase me esquecia delas![ENTER]Queria esconder os meus presentes nas Meias por[ENTER]cima da lareira. Mas v\225rias criaturas nada[ENTER]natal\237cias roubaram-mas todas! Por favor ajuda-me[ENTER]a recuper\225-las. "
gameforge.new_christmas_sock._030_say = "N\227o \233 f\225cil encontrar Meias. Ir\225s precisar da[ENTER]Cria de Rena para as farejar. "
gameforge.new_christmas_sock._040_say = "N\227o \233 fofinha?[ENTER]E tem um olfacto muito apurado. \201 uma[ENTER]especialista na busca por Meias![ENTER]Ela permanecer\225 contigo durante 2 horas e ir\225[ENTER]ajudar-te na busca. Depois disso, ficar\225 cansada[ENTER]e precisar\225 de descansar durante 24 horas antes[ENTER]de poder continuar.[ENTER]Se n\227o quiseres esperar tanto tempo, tenta[ENTER]espreitar o que est\225 por detr\225s da moeda[ENTER]girat\243ria. Ouvi dizer que por l\225 existe outra[ENTER]Cria de Rena \224 tua espera. Mas tamb\233m ficarei[ENTER]contente se me visitares de novo amanh\227! "
gameforge.new_christmas_sock._050_npcChat = "Trago-te Meias! "
gameforge.new_christmas_sock._060_say = "Traz-me pelo menos 5 Meias e receber\225s uma[ENTER]recompensa. Urrgh, o cheiro de meias bolorentas \233[ENTER]insuport\225vel! Volta quando tiveres recolhido[ENTER]Meias suficientes. Feliz Natal! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, j\225 recolheste Meias suficientes. Hmm,[ENTER]deixa-me ver.[ENTER]URRGH, este cheiro! Bem, s\227o definitivamente as[ENTER]Meias certas! Feliz Natal! "
gameforge.new_christmas_sock._080_npcChat = " - Cria de Rena "
gameforge.new_christmas_sock._090_say = "J\225 te dei um Selo da Cria de Rena hoje. O[ENTER]pequenote precisa de descansar um pouco. Amanh\227[ENTER]voltar\225 a estar em topo de forma. Se n\227o quiseres[ENTER]esperar tanto tempo, tenta espreitar o que est\225[ENTER]por detr\225s da moeda girat\243ria. Ouvi dizer que por[ENTER]l\225 existe outra Cria de Rena \224 tua espera. Mas[ENTER]tamb\233m ficarei contente se me visitares de novo[ENTER]amanh\227! "
gameforge.new_christmas_sock._100_say = "J\225 me trouxeste as tuas meias hoje. Lembra-te que[ENTER]apenas podes entregar-me algumas a cada 24 horas. "
