gameforge.new_quest_lv17._012_say_title = "Wonda-Rim: "
gameforge.new_quest_lv17._020_say_title = "O presente para Chaegirab "
gameforge.new_quest_lv17._021_say = "O meu tio Chaegirab dedicou a sua vida \224 ci\234ncia[ENTER]e investiu todo o seu Yang na sua pesquisa. Ele[ENTER]tem sido sempre bom para mim, pelo que gostaria[ENTER]de o surpreender com um presente. Podes ir ter[ENTER]com o Uriel e perguntar-lhe se faz alguma ideia[ENTER]do que eu poderia oferecer? Ele \233 o antigo mentor[ENTER]do meu tio, pelo que o conhece bastante bem. "
gameforge.new_quest_lv17._030_say = "Mas n\227o contes nada ao meu tio! "
gameforge.new_quest_lv17._031_say = "Poder\225s ajudar-me? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Fala com o Uriel "
gameforge.new_quest_lv17._040_target = "Uriel: "
gameforge.new_quest_lv17._041_say = "Fala com o Uriel sobre o seu antigo aluno[ENTER]Chaegirab. "
gameforge.new_quest_lv17._042_say = "O Uriel encontra-se em %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim quer oferecer um presente a Chaegirab... "
gameforge.new_quest_lv17._051_say = "Os prazeres da vida de um cientista v\234m da[ENTER]investiga\231\227o. \201 t\227o simples como isso. A melhor[ENTER]forma de agradar a Chaegirab \233 ajud\225-lo nas suas[ENTER]tarefas. O Lobo Mu-Rang \233 um visitante raro[ENTER]destas terras e, de igual forma, o seu p\234lo \233 um[ENTER]raro deleite para os bi\243logos. Cinco peda\231os[ENTER]devem ser suficientes. Podes dizer isso a[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._052_say = "Tenho a certeza que este P\234lo ir\225 impressionar o[ENTER]bi\243logo. "
gameforge.new_quest_lv17._060_select = "Sim, irei inform\225-lo. "
gameforge.new_quest_lv17._065_say_title = "Regressar a Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel lembrou-se de um \243ptimo presente para[ENTER]Chaegirab. Vai ter com Wonda-Rim e conta-lhe. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim encontra-se em %s. "
gameforge.new_quest_lv17._070_say = "A sugest\227o do Uriel parece-me bem. Como quero[ENTER]mesmo fazer disto uma surpresa para o meu Tio[ENTER]Chaegirab preciso de obter o P\234lo. Podes ir e[ENTER]matar 5 Mu-Rangs por mim? "
gameforge.new_quest_lv17._071_say = "\201 suposto matar Mu-Rangs para obter o seu P\234lo. "
gameforge.new_quest_lv17._072_say = "5 s\227o suficientes para um bom presente. "
gameforge.new_quest_lv17._073_say = "Vamos l\225! "
gameforge.new_quest_lv17._074_notice = "J\225 apanhaste algum P\234lo de boa qualidade. "
gameforge.new_quest_lv17._075_say = "Ca\231a Mu-Rang e obt\233m o seu P\234lo. "
gameforge.new_quest_lv17._076_say_reward = "J\225 conseguiste obter %s de 5 peda\231os de P\234lo. "
gameforge.new_quest_lv17._081_say_title = "P\234lo para Wonda-Rim "
gameforge.new_quest_lv17._082_say = "J\225 recolheste P\234los suficientes, agora leva-o ao[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "J\225 obtiveste %s peda\231os de P\234lo. "
gameforge.new_quest_lv17._110_say = "Este P\234lo \233 realmente muito bom, obrigado. Podes[ENTER]lev\225-lo ao meu tio? "
gameforge.new_quest_lv17._120_target = "Tio Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim pediu-te para levares o P\234lo de Mu-Rang[ENTER]a Chaegirab. "
gameforge.new_quest_lv17._122_say = "Chaegirab encontra-se em %s. "
gameforge.new_quest_lv17._130_say = "Aha. Ent\227o \233 isso que ele anda a tentar fazer. "
gameforge.new_quest_lv17._131_say = "De quem \233 este P\234lo? \201 de Wonda-Rim, mas mataste[ENTER]os lobos por ele?[ENTER]Estou envergonhado por ter um sobrinho que pede[ENTER]aos outros que fa\231am as coisas por ele. Por isso[ENTER]desculpa-me, mas n\227o posso aceitar isto, mesmo[ENTER]que te tenha consumido muito tempo e esfor\231o. "
gameforge.new_quest_lv17._132_say_reward = "Conta a Wonda-Rim que percebi tudo! Se ele quer[ENTER]oferecer-me algo, deve ir ele mesmo ca\231\225-lo. "
gameforge.new_quest_lv17._140_say = "Chaegirab n\227o aceitou o P\234lo e est\225 zangado com[ENTER]Wonda-Rim pela sua pregui\231a. Ele mandou-te[ENTER]regressar a Wonda-Rim. "
gameforge.new_quest_lv17._141_say = "O que disse o meu tio? Espero que ele tenha[ENTER]gostado do meu presente. "
gameforge.new_quest_lv17._142_1_select = "Sim, ele ficou muito entusiasmado. "
gameforge.new_quest_lv17._142_2_select = "N\227o, n\227o gostou nada. "
gameforge.new_quest_lv17._143_say = "\211ptimo! Adoro presentear os outros. E obviamente[ENTER]tenho para ti uma generosa recompensa. Toma isto! "
gameforge.new_quest_lv17._144_say_reward_a = "Recebeste 20.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang.[ENTER]Recebeste uma Pe\231a d'Ouro. "
gameforge.new_quest_lv17._144_say_reward_b = "Mentiste a Wonda-Rim e por isso perdeste Karma. "
gameforge.new_quest_lv17._145_say = "Ele n\227o aceitou o P\234lo? Hum... Talvez n\227o tenha[ENTER]sido grande ideia pedir-te para ca\231ares os lobos[ENTER]em vez de ser eu a faz\234-lo. Irei agir de forma[ENTER]diferente na pr\243xima vez. "
gameforge.new_quest_lv17._146_say_reward = "Mas n\227o quero que todo o teu trabalho duro tenha[ENTER]sido em v\227o: vai ter com Yang-Shin. Ele ir\225[ENTER]comprar-te o P\234lo por um bom pre\231o. "
gameforge.new_quest_lv17._147_say = "Que reviravolta surpreendente. Bom, pelo menos[ENTER]ainda tens o P\234lo. Vai ter com o ca\231ador[ENTER]Yang-Shin em Yayang e vende-lhe o P\234lo. "
gameforge.new_quest_lv17._148_say = "Que reviravolta surpreendente. Bom, pelo menos[ENTER]ainda tens o P\234lo. Vai ter com o ca\231ador[ENTER]Yang-Shin em Bokjung e vende-lhe o P\234lo. "
gameforge.new_quest_lv17._149_say = "Que reviravolta surpreendente. Bom, pelo menos[ENTER]ainda tens o P\234lo. Vai ter com o ca\231ador[ENTER]Yang-Shin em Bakra e vende-lhe o P\234lo. "
gameforge.new_quest_lv17._151_say = "P\234lo de Mu-Rang? Isso ser\225 muito \250til. Irei criar[ENTER]alguma roupa interior para mim com ele. Aqui tens[ENTER]algum Yang pelo teu esfor\231o. Oh, e encontrei este[ENTER]Livro ontem, talvez possas encontrar alguma[ENTER]utilidade para ele. "
gameforge.new_quest_lv17._152_say_reward = "Recebeste 40.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang.[ENTER]Recebeste um Livro de Habilidades. "
