gameforge.new_quest_lv22._010_target = "Guarda da Cidade: "
gameforge.new_quest_lv22._011_say = "O Guarda da Cidade tem uma miss\227o para ti. Vai[ENTER]ter com ele e descobre o que se passa. "
gameforge.new_quest_lv22._015_npcChat = "O irm\227o doente "
gameforge.new_quest_lv22._016_send_letter = "O guarda doente "
gameforge.new_quest_lv22._017_say_title = "Guarda da Cidade: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "Guarda da Torre "
gameforge.new_quest_lv22._021_say = "Estou preocupado com o meu irm\227o, o Guarda da[ENTER]Torre. Ele n\227o se tem andado a sentir muito bem e[ENTER]agora est\225 muito doente. Tem uma forte dor de[ENTER]cabe\231a e uma estranha erup\231\227o cut\226nea, mas n\227o[ENTER]pode simplesmente abandonar o seu posto. Podes[ENTER]arranjar algum Rem\233dio do Baek-Go para ele? "
gameforge.new_quest_lv22._022_say = "Eu pr\243prio iria l\225, mas a Torre Gumsan[ENTER]encontra-se no Templo Hwang, no centro do Vale[ENTER]Seungryong. E esse local est\225 repleto de[ENTER]criaturas perigosas... "
gameforge.new_quest_lv22._023_say = "Aqui est\225s tu de novo. Esqueceste-te dos[ENTER]sintomas? Devias estar com aten\231\227o quando est\227o a[ENTER]falar contigo. O meu irm\227o tem uma forte dor de[ENTER]cabe\231a e uma estranha erup\231\227o cut\226nea. Agora vai[ENTER]ter com o Baek-Go! "
gameforge.new_quest_lv22._024_select = "Ajudar o irm\227o "
gameforge.new_quest_lv22._025_say_title = "Rem\233dio do Baek-Go "
gameforge.new_quest_lv22._026_say = "Fala com Baek-Go sobre o Rem\233dio para o Guarda da[ENTER]Torre. "
gameforge.new_quest_lv22._027_say = "Baek-Go encontra-se em %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "Ent\227o precisas de um Rem\233dio? \201 perigoso utilizar[ENTER]medicamentos sem saber o que \233 preciso tratar![ENTER]Tens de me informar dos sintomas da doen\231a. "
gameforge.new_quest_lv22._032_1_select = "Dores de cabe\231a e erup\231\245es "
gameforge.new_quest_lv22._032_2_select = "Dores de garganta e c\227ibras "
gameforge.new_quest_lv22._032_3_select = "N\227o sei. "
gameforge.new_quest_lv22._035_say = "Parecem-me arranh\245es de dem\243nios. Isto ocorre[ENTER]frequentemente quando se est\225 pr\243ximo de[ENTER]demasiadas criaturas demon\237acas. Posso produzir[ENTER]algo que o ir\225 ajudar, mas ir\225s precisar de[ENTER]arranjar alguns dos ingredientes. "
gameforge.new_quest_lv22._040_say = "Preciso: "
gameforge.new_quest_lv22._041_say_reward = "Tens de ca\231ar: "
gameforge.new_quest_lv22._042_say = "Tamb\233m preciso de: "
gameforge.new_quest_lv22._043_say = "Nunca ouvi falar de tal doen\231a. Tens a certeza[ENTER]que esses s\227o os sintomas correctos? Se fosse a[ENTER]ti iria ter com o Guarda da Cidade para perguntar[ENTER]de novo. "
gameforge.new_quest_lv22._044_say = "N\227o posso fazer um diagn\243stico sem sintomas.[ENTER]Regressa e pergunta de novo quais s\227o. "
gameforge.new_quest_lv22._050_set_title = "Rem\233dio "
gameforge.new_quest_lv22._056_notice = "Bom, j\225 s\243 me faltam %s Ervas Medicinais. "
gameforge.new_quest_lv22._057_notice = "Devem ser todas as Ervas Medicinais de que[ENTER]preciso. Devo regressar rapidamente ao Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Muito bem, j\225 s\243 faltam %s f\237gados. "
gameforge.new_quest_lv22._060_notice = "Ah, F\237gado de Tigre. J\225 s\243 me faltam %s. "
gameforge.new_quest_lv22._061_notice = "Devem ser todos os F\237gados de Tigre de que[ENTER]preciso. Devo regressar rapidamente ao Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Infelizmente este F\237gado de Tigre n\227o me serve. "
gameforge.new_quest_lv22._063_say = "Precisas de mais %s Ervas Medicinais. "
gameforge.new_quest_lv22._064_say = "Precisas de mais %s F\237gados de Tigre. "
gameforge.new_quest_lv22._065_say = "J\225 tens todos os ingredientes para o Rem\233dio. Vai[ENTER]e d\225-os ao Baek-Go. "
gameforge.new_quest_lv22._066_say = "Obt\233m os ingredientes para o Rem\233dio de Baek-Go: "
gameforge.new_quest_lv22._070_say = "Obrigado, agora posso criar o Rem\233dio para os[ENTER]arranh\245es de dem\243nio. "
gameforge.new_quest_lv22._071_say = "Terminei! Aqui tens o teu Rem\233dio. Os[ENTER]ingredientes frescos significam que o Rem\233dio n\227o[ENTER]dura muito tempo - dever\225s entreg\225-lo ao teu[ENTER]paciente dentro dos pr\243ximos %s minutos. "
gameforge.new_quest_lv22._072_say = "Podes encontrar o Guarda da Torre no centro do[ENTER]Templo Hwang. Tem cuidado no teu caminho para l\225,[ENTER]o Vale Seungryong est\225 repleto de criaturas[ENTER]perigosas. "
gameforge.new_quest_lv22._073_say = "N\227o \233 suficiente. Perdeste os ingredientes[ENTER]enquanto vinhas para aqui? N\227o posso fazer nada[ENTER]enquanto n\227o tiver tudo o que te pedi. "
gameforge.new_quest_lv22._080_target = "Guarda da Torre "
gameforge.new_quest_lv22._082_set_clock = "Tempo restante "
gameforge.new_quest_lv22._083_say = "Bom, ainda tens tempo suficiente, mas tens de te[ENTER]despachar. Vai ter com o Guarda da Torre[ENTER]rapidamente, antes que o Rem\233dio perca o efeito. "
gameforge.new_quest_lv22._084_say = "Foste demasiado lento e o tempo terminou.[ENTER]De qualquer forma deves levar o Rem\233dio ao Guarda[ENTER]da Torre, pode ser que ainda funcione. "
gameforge.new_quest_lv22._085_say = "Obrigado por me trazeres o Rem\233dio. A comich\227o[ENTER]est\225 a matar-me. "
gameforge.new_quest_lv22._086_say = "Oh, isto sabe muito bem. At\233 j\225 sinto a comich\227o[ENTER]a melhorar. "
gameforge.new_quest_lv22._087_say = "Mereces uma excepcionalmente generosa recompensa[ENTER]por isto! "
gameforge.new_quest_lv22._088_say_reward = "Recebeste 50.000 Pontos de Experi\234ncia.[ENTER]Recebeste 12.000 Yang.[ENTER]Recebeste Sapatos Fita d'Ouro+4.[ENTER]Recebeste 5 Po\231\245es Roxas. "
gameforge.new_quest_lv22._089_say = "Oh, isto sabe muito mal. O efeito do Rem\233dio j\225[ENTER]passou do prazo - quanto tempo demoraste a chegar[ENTER]aqui? A minha l\237ngua parece fezes de macaco[ENTER]curadas. "
gameforge.new_quest_lv22._090_say = "Hum, espera um segundo... parece que estou a[ENTER]ficar melhor. Sim, est\225 a funcionar! Ok, parece[ENTER]que assim sendo n\227o irei ficar zangado. Ir\225s[ENTER]receber a tua recompensa. "
gameforge.new_quest_lv22._091_say = "Parece que perdeste o Rem\233dio. Por favor vai de[ENTER]novo ca\231ar e obter os ingredientes para o Baek-Go[ENTER]criar um novo Rem\233dio. Eu pr\243prio me irei tornar[ENTER]num dem\243nio se esta comich\227o continuar assim por[ENTER]muito mais tempo. "
gameforge.new_quest_lv22._095_say_reward = "Recebeste 50.000 Pontos de Experi\234ncia.[ENTER]Recebeste 8.000 Yang. "
gameforge.new_quest_lv22._098_say = "Perdeste o rem\233dio de novo? Nunca na minha vida[ENTER]vi algu\233m t\227o cabe\231a no ar! Bem, n\227o h\225 muito que[ENTER]possamos fazer acerca disto. "
gameforge.new_quest_lv22._100_say_reward = "Recebeste 25.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin: "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "O desertor "
gameforge.new_quest_lv26._021_say = "Yang-Shin est\225 a ter dificuldades em encontrar um[ENTER]bom local de ca\231a. Vai ter com ele e v\234 como o[ENTER]poder\225s ajudar. "
gameforge.new_quest_lv26._025_say = "Nada \233 como antes desde a queda das Pedras Metin.[ENTER]At\233 mesmo ca\231ar se tornou imposs\237vel em alguns[ENTER]locais devido ao facto de os animais selvagens se[ENTER]terem come\231ado a comportar como se tivessem[ENTER]raiva. O Nakajima vive por a\237 algures no exterior[ENTER]e tenho a certeza que ele saber\225 onde existe um[ENTER]bom local para ca\231ar. Podes ir ter com ele e[ENTER]perguntar-lhe? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "Ent\227o queres saber um bom local de ca\231a? N\227o[ENTER]tenhas tanta pressa, se \233 suposto eu ajudar-te[ENTER]ent\227o tamb\233m dever\225s fazer-me um favor. "
gameforge.new_quest_lv26._032_say = "Deves saber... Eu n\227o vivo aqui voluntariamente.[ENTER]Preciso de me esconder porque fugi das[ENTER]atrocidades do ex\233rcito. Apenas queria que a[ENTER]minha queria Ah-Yu soubesse que ainda estou vivo.[ENTER]Podes entregar-lhe esta mensagem?[ENTER]Mas lembra-te que \233 apenas para a Ah-Yu! Ela[ENTER]dever\225 dizer-te onde nos beij\225mos pela primeira[ENTER]vez - quero encontr\225-la nesse local, que tamb\233m \233[ENTER]um \243ptimo para a ca\231a. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Procura o Nakajima "
gameforge.new_quest_lv26._037_say = "O Nakajima deve conhecer alguns bons locais de[ENTER]ca\231a. Procura-o. "
gameforge.new_quest_lv26._038_say = "O Nakajima encontra-se em %s. "
gameforge.new_quest_lv26._040_say = "\201s o Nakajima? Yang-Shin enviou-me! Ele est\225 \224[ENTER]procura de um local para ca\231ar. Talvez tenhas[ENTER]alguma ideia de algum s\237tio onde ca\231ar n\227o seja[ENTER]perigoso? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima \233 um desertor e agora tem de se esconder[ENTER]do ex\233rcito. A sua mulher, Ah-Yu, pensa que ele[ENTER]morreu na guerra. Informa-a que Nakajima ainda[ENTER]est\225 vivo. "
gameforge.new_quest_lv26._052_say = "Ah-Yu encontra-se em %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... ele est\225 vivo? O meu querido marido[ENTER]est\225 vivo? N\227o tenho palavras para agradecer por[ENTER]me contares isto! O local de que ele falou era o[ENTER]Vale de Yonjang. Irei j\225 l\225 ter para me encontrar[ENTER]com ele. "
gameforge.new_quest_lv26._058_say = "Obrigado por tornares poss\237vel esta reuni\227o. Leva[ENTER]esta Rosa contigo, talvez a possas oferecer a[ENTER]algu\233m que amas? E agora desculpa-me... Mas tenho[ENTER]que me despachar! "
gameforge.new_quest_lv26._061_say = "O Vale de Yonjang - onde Nakajima e Ah-Yu se[ENTER]beijaram pela primeira vez - ainda \233 um bom local[ENTER]de ca\231a. "
gameforge.new_quest_lv26._062_say = "Yang-Shin ficar\225 satisfeito quando ouvir sobre[ENTER]isto. Dirige-te a %s e conta-lhe as novidades. "
gameforge.new_quest_lv26._063_say = "O Vale de Yonjang? Parece-me plaus\237vel uma vez[ENTER]que nunca ouvi falar de uma Pedra Metin que tenha[ENTER]contaminado essa zona. Provavelmente serei capaz[ENTER]de ca\231ar a\237! Aqui tens, mereces esta recompensa. "
gameforge.new_quest_lv26._064_sayReward = "Recebeste 35.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv26._065_sayReward = "Recebeste 17.500 Yang. "
