gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "Yu-Hwan, o m\250sico, precisa da tua ajuda. Vai ter[ENTER]com ele r\225pido e descobre o que se passa! "
gameforge.new_quest_lv28._015_npcChat = "Preocupa\231\245es de Ah-Yu "
gameforge.new_quest_lv28._016_say = "Ah-Yu parece ter algo que n\227o quer contar ao[ENTER]Yu-Hwan. Vai ter com ela e v\234 se ela quer[ENTER]desabafar contigo. "
gameforge.new_quest_lv28._017_say = "Ah-Yu encontra-se em %s. "
gameforge.new_quest_lv28._018_select = "Falarei com a Ah-Yu brevemente! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Conheces a Ah-Yu? Ela recolhe ervas para as[ENTER]minhas po\231\245es. Costumava andar de bom humor, mas[ENTER]ontem ela parecia-me muito afastada... Ela n\227o me[ENTER]quis contar o que se passava, mas ser\225 que \233 por[ENTER]trabalhar para mim?[ENTER]Por favor vai ter com ela e tenta descobrir como[ENTER]ela est\225. Talvez ela desabafe contigo. "
gameforge.new_quest_lv28._022_say = "\201 muito simp\225tico do Yu-Hwan preocupar-se comigo.[ENTER]Mas sim, h\225 algo que me anda a preocupar... N\227o[ENTER]queria falar sobre isto, mas est\225 a ser t\227o duro[ENTER]para mim! \201 sobre Yang-Shin, o ca\231ador. Ele tem[ENTER]andado a fazer chantagem comigo desde que[ENTER]descobriu que o meu marido, o Nakajima, \233 um[ENTER]desertor. O Yang-Shing est\225 a amea\231ar-me de[ENTER]informar algu\233m sobre a situa\231\227o dele! E ent\227o[ENTER]iriam encontr\225-lo e execut\225-lo... "
gameforge.new_quest_lv28._023_say = "Desta vez ele quer uma Pata de Urso em troca do[ENTER]seu sil\234ncio. Mas por agora n\227o posso ir ca\231ar.[ENTER]Podes ajudar-me a obter aquilo que o Yang-Shin[ENTER]pretende? "
gameforge.new_quest_lv28._024_set_title = "Ca\231ar Ursos "
gameforge.new_quest_lv28._025_notice = "Vamos \224 ca\231a! Matar o Bera \233 a melhor forma de[ENTER]obter Patas de Urso. "
gameforge.new_quest_lv28._026_notice = "Apanhei uma Pata de Urso! "
gameforge.new_quest_lv28._027_notice = "Deve ser tudo. Vamos ter com o Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Esta Pata de Urso n\227o me serve. "
gameforge.new_quest_lv28._029_say = "Precisas de mais %s Pata(s) de Urso. "
gameforge.new_quest_lv28._031_say_reward = "Tens de ca\231ar: "
gameforge.new_quest_lv28._032_say = "Ah-Yu perguntou-te se podes cumprir a tarefa que[ENTER]Yang-Shin lhe deu. "
gameforge.new_quest_lv28._032_say_reward = "Precisas de mais %s Pata(s) de Urso.[ENTER]Ca\231a o Bera para as obteres. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "Obtiveste a Pata de Urso que era pedida. Leva-a[ENTER]ao Yang-Shin para pagares a d\237vida de Ah-Yu. "
gameforge.new_quest_lv28._037_say = "O Yang-Shin encontra-se em %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "A Chantagem "
gameforge.new_quest_lv28._041_say_title = "Patas de Urso "
gameforge.new_quest_lv28._042_say = "Trouxeste-me algumas Patas de Urso? Por favor n\227o[ENTER]penses mal de mim! Estamos a viver tempos[ENTER]dif\237ceis e tenho de me safar como puder, ainda[ENTER]por cima agora que a ca\231a ficou mais dif\237cil e as[ENTER]Pedras Metin transformaram os animais numas[ENTER]criaturas assassinas. Viver da ca\231a nunca foi t\227o[ENTER]perigoso. "
gameforge.new_quest_lv28._043_say = "Por favor diz \224 Ah-Yu que ela n\227o tem nada com[ENTER]que se preocupar. Pode contar com isso. Pelo[ENTER]menos at\233 eu voltar a precisar de algo... Hehehe! "
gameforge.new_quest_lv28._044_say = "Pretendias enganar-me com isto? Eu queria Patas[ENTER]de Urso frescas! "
gameforge.new_quest_lv28._045_say_reward = "\201 muito simp\225tico da tua parte ajudares a Ah-Yu.[ENTER]Mas isso tamb\233m significa que tens de fazer o que[ENTER]eu disser.[ENTER]Agora vai-te embora e n\227o voltes at\233 teres duas[ENTER]Patas de Urso! "
gameforge.new_quest_lv28._046_say = "Passa \224 Ah-Yu a mensagem que Yang-Shin ir\225 parar[ENTER]de fazer chantagem com ela porque o ajudaste. "
gameforge.new_quest_lv28._051_say = "\201s a nossa salva\231\227o! Estou eternamente grata.[ENTER]Toma, leva todo o meu Yang. N\227o \233 muito, mas tu[ENTER]mereces. "
gameforge.new_quest_lv28._055_1_select = "Obrigado, ser\225 muito \250til! "
gameforge.new_quest_lv28._055_2_select = "N\227o, n\227o posso aceitar isto. "
gameforge.new_quest_lv28._056_say = "Isto \233 tudo o que tenho. Mas vale a pena se for[ENTER]para me livrar daquele b\225rbaro carrasco. "
gameforge.new_quest_lv28._057_say = "Oh, obrigado! O teu lugar ao lado do Deus Drag\227o[ENTER]est\225 garantido! "
gameforge.new_quest_lv28._058_say_reward = "Recebeste %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Recebeste %s Pontos de Experi\234ncia. "
gameforge.new_quest_lv28._070_say = "Preciso: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah: "
gameforge.new_quest_lv29._015_npcChat = "A Porcelana Partida "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "A minha amada Porcelana Celadon! Est\225 na minha[ENTER]fam\237lia h\225 tr\234s gera\231\245es e agora tr\234s dos meus[ENTER]preciosos vasos est\227o partidos. Vi aquele[ENTER]irrespons\225vel do Taurean a andar perto do armaz\233m[ENTER]mais cedo. Tenho a certeza que \233 o culpado! "
gameforge.new_quest_lv29._022_say = "N\227o seria a primeira tolice que ele fez na vida,[ENTER]mas isto \233 passar dos limites. Algu\233m lhe deveria[ENTER]ensinar uma li\231\227o! Tens tempo para o fazer? "
gameforge.new_quest_lv29._023_1_select = "Com prazer "
gameforge.new_quest_lv29._023_2_select = "N\227o \233 da minha conta "
gameforge.new_quest_lv29._024_say = "N\227o tenho tempo para educar crian\231as loucas. Tens[ENTER]de o apanhar tu mesmo. No entanto duvido que o[ENTER]consigas... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Tr\234s vasos feitos de Porcelana Celadon, heran\231as[ENTER]de fam\237lia do Yonah, est\227o quebrados. Ele acha[ENTER]que a culpa \233 do Taurean. Vai ter com o Taurean e[ENTER]averigua esta acusa\231\227o. "
gameforge.new_quest_lv29._032_say = "Taurean encontra-se em %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Porque est\225s a olhar assim para mim? N\227o fiz[ENTER]nada... "
gameforge.new_quest_lv29._035_say_reward = "O que fizeste aos vasos do Yonah? "
gameforge.new_quest_lv29._036_say_reward = "Vasos? Yonah? N\227o sei do que est\225s a falar! "
gameforge.new_quest_lv29._037_say_reward = "Ent\227o fazes o favor de me explicar de novo porque[ENTER]\233 que tr\234s dos vasos est\227o partidos? "
gameforge.new_quest_lv29._038_say_reward = "Juro que n\227o estive sequer perto de um vaso hoje[ENTER]e que nem vi o Yonah. Ali\225s, passei o dia todo[ENTER]com a Harang. Ela at\233 me trancou no celeiro[ENTER]durante algum tempo! Vai ter com ela e[ENTER]pergunta-lhe se n\227o acreditares em mim! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean garante que est\225 inocente. Ele esteve a[ENTER]brincar o dia todo com a Harang e n\227o podia ter[ENTER]partido os vasos. Vai ter com Harang para ver se[ENTER]o que ele diz \233 verdade. "
gameforge.new_quest_lv29._042_say_reward = "Harang, tens visto o Taurean? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean? Sim, estivemos todo o dia a brincar.[ENTER]Passa-se alguma coisa? "
gameforge.new_quest_lv29._045_say_reward = "Yonah disse que o Taurean partiu tr\234s dos seus[ENTER]vasos. "
gameforge.new_quest_lv29._046_say_reward = "O Yonah \233 mau. Ele afugenta-me a mim e ao Taurean[ENTER]assim que nos aproximamos dele. Est\225 sempre t\227o[ENTER]preocupado com as suas porcelanas. A \250nica pessoa[ENTER]que pode tocar nos seus preciosos vasos \233 o seu[ENTER]amigo, o Rapaz do Est\225bulo. Ter\225 sido ele a[ENTER]parti-los? "
gameforge.new_quest_lv29._047_say = "Harang encontra-se em %s. "
gameforge.new_quest_lv29._050_target = "Rapaz do Est\225bulo: "
gameforge.new_quest_lv29._051_say = "Harang confirmou a inoc\234ncia de Taurean. Mas eles[ENTER]tamb\233m podem estar a proteger-se mutuamente.[ENTER]Antes de fazeres qualquer julgamento dever\225s ir[ENTER]ter com o Rapaz do Est\225bulo, que \233 amigo do[ENTER]Yonah. "
gameforge.new_quest_lv29._052_say = "OH, o velho Yonah. Sempre t\227o preocupado com as[ENTER]suas porcelanas que at\233 culpa as crian\231as da[ENTER]Vila. Ele n\227o se apercebe que a culpa \233 das[ENTER]Pedras Metin - desde que come\231aram a envenenar o[ENTER]nosso Reino os recursos j\225 n\227o s\227o o que eram.[ENTER]At\233 a porcelana se come\231ou a deteriorar. Mas o[ENTER]Yonah simplesmente recusa-se a acreditar nisso... "
gameforge.new_quest_lv29._053_say = "Se recolheres algum Feno, ele poder\225 acomodar um[ENTER]pouco melhor a porcelana quando a coloca nas suas[ENTER]caixas. Tenho a certeza que ser\225 uma boa forma de[ENTER]o apaziguar. "
gameforge.new_quest_lv29._054_say = "O Rapaz do Est\225bulo est\225 em[ENTER]%s ou %s. "
gameforge.new_quest_lv29._061_say = "\201 \243bvio que Taurean n\227o tem culpa por os vasos do[ENTER]Yonah estarem partidos. \201 a maldita radia\231\227o das[ENTER]Pedras Metin que est\225 a tornar tudo mais fr\225gil.[ENTER]Recolhe Feno para o Yonah para que ele possa[ENTER]arrumar as suas porcelanas de forma mais segura![ENTER]Certamente alguns alde\245es poder\227o dar-te Feno. "
gameforge.new_quest_lv29._062_say = "Podes encontrar %s e %s em frente aos p\243rticos da[ENTER]Vila. Deves conseguir obter uma decente[ENTER]quantidade de Feno dos chap\233us da palha que eles[ENTER]usam. "
gameforge.new_quest_lv29._063_notice = "Irei conseguir uma boa mecha de Feno com isto. J\225[ENTER]s\243 me faltam %s. "
gameforge.new_quest_lv29._064_notice = "Este chap\233u n\227o \233 feito de Feno, mas sim de[ENTER]fibras de Coco. N\227o me serve para nada. "
gameforge.new_quest_lv29._065_1_say = "Vejo que tens uma grande quantidade de Feno[ENTER]contigo. Certamente o Yonah ir\225 ficar mais calmo[ENTER]se lhe deres algum. "
gameforge.new_quest_lv29._065_notice = "Este chap\233u n\227o \233 feito de Feno, mas sim de[ENTER]fibras de Coco. Al\233m disso est\225 muito[ENTER]danificado... "
gameforge.new_quest_lv29._066_say = "Tamb\233m podes ca\231ar os Infantaria Selvagem ou os[ENTER]Infantaria Selvagem Maus. Podes obter Feno dos[ENTER]seus chap\233us de palha. "
gameforge.new_quest_lv29._067_say_reward = "J\225 obtiveste %s de %s mechas de Feno. "
gameforge.new_quest_lv29._068_notice = "Obtiveste uma mecha de Feno. "
gameforge.new_quest_lv29._070_npcChat = "O Celeiro "
gameforge.new_quest_lv29._071_say_reward = "Taurean, antes tinhas dito que estiveste no[ENTER]Celeiro. Por acaso n\227o ficaste com algum Feno? "
gameforge.new_quest_lv29._072_say_reward = "Haha, vamos ver... Estava em todo o meu cabelo e[ENTER]nos meus sapatos. Consegues ver? Aqui est\225 mais[ENTER]um pouco, toma! "
gameforge.new_quest_lv29._073_notice = "N\227o \233 muito Feno, mas deve ser suficiente para[ENTER]uma pequena mecha. Agora j\225 s\243 me faltam %s. "
gameforge.new_quest_lv29._074_say_reward = "N\227o fui eu, juro! Harang n\227o te disse que[ENTER]estivemos a lutar no Celeiro? "
gameforge.new_quest_lv29._075_say_reward = "Estiveste no Celeiro mais cedo, n\227o estiveste?[ENTER]Por acaso n\227o ficaste com algum Feno de l\225? "
gameforge.new_quest_lv29._076_say_reward = "Ah, sabes sobre o Celerio? O qu\234? Ainda tenho[ENTER]Feno nas minhas roupas? Oh sim, toma algum! "
gameforge.new_quest_lv29._077_say_reward = "Posso ficar com ele? "
gameforge.new_quest_lv29._078_say_reward = "Suponho que sim... "
gameforge.new_quest_lv29._079_say_reward = "Agora n\227o tenho tempo. Preciso de acalmar o[ENTER]Taurean em rela\231\227o ao assunto dos vasos! "
gameforge.new_quest_lv29._080_npcChat = "Feno para o Yonah "
gameforge.new_quest_lv29._081_say_reward = "H\225 algum Feno perdido pelo Est\225bulo que eu possa[ENTER]levar ao Yonah? "
gameforge.new_quest_lv29._082_say_title = "Rapaz do Est\225bulo: "
gameforge.new_quest_lv29._083_say_reward = "N\227o temos muito Feno. Os animais selvagens e os[ENTER]bandidos no exterior da vila tem evitado que o[ENTER]apanhemos. "
gameforge.new_quest_lv29._084_say_reward = "Mas posso dar-te uma pequena quantidade! "
gameforge.new_quest_lv29._085_notice = "N\227o \233 muito, mas deve ser suficiente para uma[ENTER]mecha. Agora j\225 s\243 me faltam %s. "
gameforge.new_quest_lv29._086_say_reward = "Infelizmente n\227o posso fazer mais nada por ti. "
gameforge.new_quest_lv29._090_send_letter = "Feno Anti-Quebras "
gameforge.new_quest_lv29._091_say = "J\225 recolheste Feno suficiente para o Yonah.[ENTER]Dirige-te a %s para lho entregares. "
gameforge.new_quest_lv29._101_say_reward = "A culpa n\227o \233 do Taurean. A radia\231\227o das Pedras[ENTER]Metin fez com que a porcelana ficasse mais[ENTER]fr\225gil. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "O que dizes? Isso n\227o faz nenhum sentido! Aquele[ENTER]malandro mentiu-te! "
gameforge.new_quest_lv29._104_say_reward = "Taurean esteve todo o dia a brincar com a Harang[ENTER]no Celeiro. "
gameforge.new_quest_lv29._105_say_reward = "Fiquei de te enviar cumprimentos do teu amigo, o[ENTER]Rapaz do Est\225bulo, e tamb\233m trouxe algum Feno[ENTER]para ajudar a proteger os teus vasos. "
gameforge.new_quest_lv29._106_say_reward = "Admito, estou um pouco envergonhado com a minha[ENTER]reac\231\227o. Mas deves ter em conta que sou muito[ENTER]agarrado \224s minhas porcelanas, pois trazem-me[ENTER]boas mem\243rias da minha fam\237lia. Quando um vaso se[ENTER]parte para mim \233 mais do que um simples objecto[ENTER]perdido... "
gameforge.new_quest_lv29._107_say_reward = "Tenho de pedir desculpas a ti e ao Taurean. Aqui[ENTER]est\225 uma pequena recompensa pelos teus esfor\231os. "
gameforge.new_quest_lv29._108_notice = "Recebes um b\243nus de %s Pontos de Experi\234ncia. "
gameforge.new_quest_lv29._109_say_reward = "Fiquei de te enviar cumprimentos do teu amigo, o[ENTER]Rapaz do Est\225bulo, e tamb\233m trouxe algum Feno[ENTER]para ajudar a proteger os teus vasos. "
gameforge.new_quest_lv29._110_say_reward = "\201 muito simp\225tico da tua parte, mas podes[ENTER]arranjar-me mais %s mechas de Feno para que os[ENTER]meus vasos fiquem mesmo seguros? "
gameforge.new_quest_lv29._111_say_reward = "Creio que ir\225 ser dif\237cil arranjar mais Feno. Mas[ENTER]os meus vasos s\227o praticamente sagrados para mim.[ENTER]Ficaria incrivelmente grato se conseguisses[ENTER]arranjar-me mais algumas mechas, e iria dar-te[ENTER]algum Yang por isso. "
gameforge.new_quest_lv29._112_say_reward = "Aquela malandra da Harang est\225 feita com o[ENTER]Taurean, de certeza! "
gameforge.new_quest_lv29._113_say_reward = "Aparentemente ningu\233m acredita em mim quando digo[ENTER]que vi o rapaz a andar perto do armaz\233m mais[ENTER]cedo. "
gameforge.new_quest_lv29._114_say_reward = "Est\225 tudo bem. Aqui tens uma pequena compensa\231\227o[ENTER]pelos teus esfor\231os. "
gameforge.new_quest_lv29._115_say_reward = "Aqui tens %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "*Est\244mago a roncar* "
gameforge.new_quest_lv42._020_target = "Oct\225vio: "
gameforge.new_quest_lv42._021_say = "O meu est\244mago est\225 a roncar que nem um Javali.[ENTER]Talvez eu devesse ir visitar o Oct\225vio. Ele faz o[ENTER]melhor estufado de alimentos marinhos do Reino. "
gameforge.new_quest_lv42._022_say_title = "Oct\225vio: "
gameforge.new_quest_lv42._023_say = "Queres um estufado de alimentos marinhos? Aquele[ENTER]com todas as cabe\231as? Oh, desculpa, mas a minha[ENTER]cozinha n\227o v\234 nenhum peixe h\225 dias. Normalmente[ENTER]o Pescador traz-me alguns peixes de \225guas[ENTER]profundas para o meu estufado. "
gameforge.new_quest_lv42._024_say = "Bom, ele n\227o aparece por aqui h\225 dias. Talvez[ENTER]possas ir ter com ele e perguntar o que se passa? "
gameforge.new_quest_lv42._025_say = "Oct\225vio encontra-se em %s. "
gameforge.new_quest_lv42._026_select = "Vamos l\225 encontrar o pescador! "
gameforge.new_quest_lv42._030_target = "Pescador: "
gameforge.new_quest_lv42._031_say = "Acabaram-se os dias despreocupados no mar![ENTER]Existem Pescadores a desaparecer todos os dias, \233[ENTER]terr\237vel! Desde que as Pedras Metin come\231aram a[ENTER]cair no mar que as baleias, outrora pac\237ficas, se[ENTER]transformaram em criaturas marinhas brutais. A[ENTER]pesca tornou-se um neg\243cio perigoso. "
gameforge.new_quest_lv42._032_say = "As nossas lan\231as j\225 n\227o conseguem penetrar a pele[ENTER]das baleias. Agora \233 mais rija que a pele de um[ENTER]Ogre. "
gameforge.new_quest_lv42._033_say = "Talvez Yonah saiba o que fazer. Antigamente ele[ENTER]era um homem do mar e ca\231ou baleias durante anos. "
gameforge.new_quest_lv42._034_say_title = "Pescador: "
gameforge.new_quest_lv42._035_say = "O Oct\225vio est\225 \224 espera do peixe de \225guas[ENTER]profundas. Pergunta ao Pescador porque \233 que a[ENTER]entrega est\225 atrasada. "
gameforge.new_quest_lv42._036_say = "O Pescador encontra-se em %s. "
gameforge.new_quest_lv42._037_send_letter = "Monstros Marinhos Furiosos "
gameforge.new_quest_lv42._038_say = "O Pescador pediu-te para ires ter com o Yonah e[ENTER]pedires conselhos sobre como ca\231ar as malfadadas[ENTER]baleias. "
gameforge.new_quest_lv42._039_say = "Yonah encontra-se em %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "Ouvi falar no que aconteceu \224s baleias. Tem sido[ENTER]um mau neg\243cio para os Pescadores. Mesmo que eles[ENTER]se aventurem no mar as suas lan\231as s\227o demasiado[ENTER]fr\225geis para penetrar a pele das baleias. Quando[ENTER]eu trabalhava num baleeiro us\225vamos armas[ENTER]especiais para baleias com peles velhas e rijas.[ENTER]Eram capazes de penetrar qualquer coisa. "
gameforge.new_quest_lv42._042_say = "\201 preciso uma t\233cnica especial para endurecer[ENTER]lan\231as para ca\231a \224s baleias. A \250nica pessoa que[ENTER]consegue fazer este tipo de lan\231a \233 um Ferreiro. "
gameforge.new_quest_lv42._043_say_reward = "Dirige-te ao Ferreiro "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah recomenda a utiliza\231\227o de lan\231as muito[ENTER]robustas e afiadas para a ca\231a \224s baleias.[ENTER]Dirige-te ao Ferreiro e pergunta-lhe se ele pode[ENTER]criar algumas dessas lan\231as. "
gameforge.new_quest_lv42._050_target = "Ferreiro "
gameforge.new_quest_lv42._051_say = "Sim, j\225 ouvi falar dessas lan\231as e posso[ENTER]inclusive cri\225-las. No entanto, para que ganhem a[ENTER]durabilidade necess\225ria preciso de uma Pedra[ENTER]Diamante. "
gameforge.new_quest_lv42._052_say = "Preciso: "
gameforge.new_quest_lv42._053_say_reward = "Processo: "
gameforge.new_quest_lv42._054_say_title = "Ferreiro "
gameforge.new_quest_lv42._060_set_title = "Pedra Diamante "
gameforge.new_quest_lv42._061_notice = "Vamos ver. Preciso de uma Picareta para garimpar.[ENTER]Ser\225 que a minha se encontra algures ou terei de[ENTER]pedir uma nova ao Deokbae? "
gameforge.new_quest_lv42._062_say = "Precisas de mais %s Pedras Diamante. "
gameforge.new_quest_lv42._063_say = "Tens tudo o que precisas. Agora dirige-te ao[ENTER]Ferreiro rapidamente. "
gameforge.new_quest_lv42._064_say = "\211ptimo, agora tenho tudo o que preciso. Regressa[ENTER]amanh\227 \224 mesma hora para levantares as lan\231as.[ENTER]Este tipo de ferro tem de ser forjado com cuidado[ENTER]e precis\227o. "
gameforge.new_quest_lv42._065_say = "Podes obter Pedra Diamante ao garimpar um Veio de[ENTER]Diamante com uma Picareta. "
gameforge.new_quest_lv42._066_say = "O Ferreiro precisa de Pedra Diamante para criar[ENTER]lan\231as especiais para a ca\231a de baleias. Procura[ENTER]Veios de Diamante para que possas garimpar Pedra[ENTER]Diamante. Se n\227o tiveres uma Picareta para[ENTER]garimpar podes comprar uma no Deokbae. "
gameforge.new_quest_lv42._067_say = "O Ferreiro encontra-se em %s. "
gameforge.new_quest_lv42._068_say = "Precisamos de mais %s Pedras Diamante antes de[ENTER]podermos come\231armos a trabalhar nas lan\231as. "
gameforge.new_quest_lv42._070_set_title = "As lan\231as "
gameforge.new_quest_lv42._071_set_clock = "Tempo de Espera "
gameforge.new_quest_lv42._072_say = "O Ferreiro j\225 deve ter terminado. Agora vai ter[ENTER]com ele para levantares as lan\231as especiais para[ENTER]ca\231a \224 baleia. "
gameforge.new_quest_lv42._073_say = "As lan\231as ainda n\227o est\227o prontas. Precisas de[ENTER]ter um pouco de mais paci\234ncia. "
gameforge.new_quest_lv42._074_say = "Aqui tens as tuas lan\231as. Leva-as ao Pescador. "
gameforge.new_quest_lv42._075_say = "J\225 te pedi para esperares at\233 as lan\231as estarem[ENTER]prontas. Volta mais tarde. "
gameforge.new_quest_lv42._079_say = "Recebeste algumas Lan\231as para Ca\231ar Baleias do[ENTER]Ferreiro. Leva-as ao Pescador. "
gameforge.new_quest_lv42._080_say = "\211ptimo! Estas lan\231as s\227o realmente[ENTER]impressionantes! Agora podemos proteger-nos dos[ENTER]ataques das baleias. Por favor informa o Oct\225vio[ENTER]que dentro em breve ele voltar\225 a ter peixe[ENTER]fresco! "
gameforge.new_quest_lv42._081_say_reward = "Recebeste 500.000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Como recompensa especial recebeste 3x: "
gameforge.new_quest_lv42._083_say = "N\227o s\227o lan\231as suficientes para afugentar uma[ENTER]baleia. Quanto muito ir\237amos fazer-lhes c\243cegas. "
gameforge.new_quest_lv42._084_say_reward = "Por favor regressa ao Ferreiro e pede-lhe para[ENTER]criar mais umas lan\231as. "
gameforge.new_quest_lv42._090_say = "Agora os Pescadores est\227o bem equipados e podem[ENTER]voltar a ca\231ar no mar aberto. Vai ter com o[ENTER]Oct\225vio e assegura-lhe que ir\225 ter uma nova[ENTER]entrega brevemente. "
gameforge.new_quest_lv42._095_say = "O que est\225s a dizer? As baleias pac\237ficas[ENTER]tornaram-se monstros marinhos agressivos? Isso \233[ENTER]terr\237vel... Obrigado por ajudares os Pescadores.[ENTER]Grande parte do menu depende das suas entregas. "
gameforge.new_quest_lv42._096_say = "Oh, e sobre o roncar do teu est\244mago: \201 claro que[ENTER]te posso oferecer um estufado de alimentos[ENTER]marinhos, mas n\227o preferes algum Sushi? "
gameforge.new_quest_lv42._098_say_reward = "Recebeste 750.000 Pontos de Experi\234ncia.[ENTER]Recebeste 2 Peda\231os de Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Visitar Wonda-Rim "
gameforge.new_quest_lv43._006_send_letter = "O \211rf\227o "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "Nunca mais ouviste falar de Wonda-Rim. A sua[ENTER]rela\231\227o com o tio pode ter melhorado e podem j\225[ENTER]ter esquecido todo aquele epis\243dio do P\234lo de[ENTER]Mu-Rang. Porque n\227o lhe vais fazer uma visita? "
gameforge.new_quest_lv43._012_say = "Wonda-Rim encontra-se em %s. "
gameforge.new_quest_lv43._020_say = "\201 simp\225tico da tua parte vires visitar-me. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Fui criado pelo meu tio Chaegirab. Sempre tivemos[ENTER]uma boa rela\231\227o... mas sempre que lhe pergunto[ENTER]sobre os meus pais ele esquiva-se da pergunta.[ENTER]Eles est\227o mortos, mas ele n\227o me conta mais nada[ENTER]al\233m disso. "
gameforge.new_quest_lv43._023_say_reward = "Um dia quero casar-me e ter uma fam\237lia, por isso[ENTER]gostava de saber como cheguei at\233 onde estou[ENTER]hoje. Podias falar com o meu tio e perguntar-lhe[ENTER]sobre os meus pais? Mas por favor n\227o lhe digas[ENTER]que eu te enviei. "
gameforge.new_quest_lv43._024_select = "Vou falar com ele! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim n\227o \233 o sobrinho biol\243gico de[ENTER]Chaegirab, foi apenas criado por ele. Agora est\225[ENTER]na hora de saber quem eram os seus verdadeiros[ENTER]pais. Pergunta ao Chaegirab qual a verdadeira[ENTER]hist\243ria. "
gameforge.new_quest_lv43._026_say = "Chaegirab encontra-se em %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... N\227o, n\227o sou o seu tio biol\243gico.[ENTER]N\227o sei quem s\227o os seus pais. Escondi a verdade[ENTER]dele at\233 agora porque n\227o acho que ele estava[ENTER]preparado para a ouvir. Mas talvez finalmente[ENTER]tenha chegado a hora. "
gameforge.new_quest_lv43._033_say = "Encontrei-o com uma horda de Orcs Lutadores no[ENTER]Vale Seungryong. Se ainda existir uma forma de[ENTER]descobrir algo sobre os pais do Wonda-Rim ser\225s[ENTER]capaz de o descobrir dos Orcs. "
gameforge.new_quest_lv43._034_say = "Posso ser muito duro com ele, mas serei sempre o[ENTER]seu tio. Mesmo que ele continue a ser um[ENTER]malandro. "
gameforge.new_quest_lv43._035_say_reward = "Dirige-te ao Vale Seungryong e ca\231a Orcs[ENTER]Lutadores at\233 descobrires uma pista sobre os pais[ENTER]do Wonda-Rim. "
gameforge.new_quest_lv43._036_say = "Descobriste uma velha Carta num saco de um Orc[ENTER]Lutador. \201 quase imposs\237vel de decifrar, mas[ENTER]consegues discernir nela o nome Wonda-Rim. Esta \233[ENTER]a prova que procuravas, por isso leva-a ao[ENTER]Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "Vamos l\225! A melhor hip\243tese que tens de descobrir[ENTER]algo sobre os pais do Wonda-Rim \233 matando Orcs[ENTER]Lutadores. Eles podem estar na posse de uma prova[ENTER]qualquer! "
gameforge.new_quest_lv43._043_notice = "Pistas sobre o Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "J\225 te disse tudo o que sei. A \250nica pista que[ENTER]temos s\227o os Orcs Lutadores. Mas infelizmente n\227o[ENTER]\233 poss\237vel ter uma conversa decente com eles... "
gameforge.new_quest_lv43._049_say = "Uma Carta? Vamos ver... \201 realmente dif\237cil de[ENTER]ler... Fala sobre um raide. Aparentemente os Orcs[ENTER]pegaram fogo \224 quinta e tiveram de fugir pelas[ENTER]suas vidas. Deixaram o seu filho para tr\225s... E[ENTER]aqui est\225 um nome. "
gameforge.new_quest_lv43._050_say = "Obrigado por me trazeres isto. Finalmente sei o[ENTER]que aconteceu. "
gameforge.new_quest_lv43._051_say = "Devia falar com Chaegirab. Ele obviamente passou[ENTER]por alguns sarilhos para me salvar. Irei tentar[ENTER]ser um melhor sobrinho para ele. Vejo-te em[ENTER]breve, meu amigo! "
gameforge.new_quest_lv43._052_say_title = "Informa\231\227o: "
gameforge.new_quest_lv43._053_say_reward = "Recebeste 32.000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Recebeste 1.250.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv43._060_say = "Falaste com o meu tio Chaegirab? O qu\234? Tens um[ENTER]palpite? Que est\225s a dizer? Se n\227o tens nada para[ENTER]mostrar, tamb\233m n\227o devias andar por a\237 a dar[ENTER]palpites![ENTER][ENTER]Por favor vai ter com o meu tio e pergunta-lhe de[ENTER]novo. Afinal de contas, estou a pagar-te para[ENTER]isso. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Carta do Capit\227o "
gameforge.new_quest_lv52._020_say_title = "Compatriota Leal "
gameforge.new_quest_lv52._021_say_reward = "Gostaria que me fizesses um favor. N\227o tenho[ENTER]conseguido dormir e, apesar do rem\233dio do[ENTER]Baek-Go, continuo \224s voltas de noite.[ENTER]Podes ir ter com ele e pedir-lhe um rem\233dio mais[ENTER]forte? "
gameforge.new_quest_lv52._022_say = "Baek-Go encontra-se em %s. "
gameforge.new_quest_lv52._030_set_title = "Uma boa noite de sono "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "O Capit\227o est\225 a ter problemas em dormir. Vai ter[ENTER]com o Baek-Go e pede-lhe uns comprimidos para[ENTER]dormir mais fortes. "
gameforge.new_quest_lv52._041_say = "Rem\233dio para dormir para o Capit\227o? Lamento, mas[ENTER]n\227o tenho nada mais forte que te possa dar. No[ENTER]entanto o Yu-Hwan poder\225 criar algo \224 base de[ENTER]Ervas que \233 capaz de te dar o efeito pretendido. "
gameforge.new_quest_lv52._042_say = "Ah, recebeste a minha carta. N\227o sei que mais[ENTER]fazer. N\227o consigo ter uma boa noite de sono. Por[ENTER]favor ajuda-me pedindo conselhos ao Baek-Go. "
gameforge.new_quest_lv52._042_select = "Ent\227o \233 melhor ir ter com o Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go encontra-se em %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan encontra-se em %s. "
gameforge.new_quest_lv52._046_say = "Ent\227o vai ter com o Capit\227o e diz-lhe que n\227o o[ENTER]podes ajudar. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "Baek-Go n\227o tinha nenhum medicamento mais forte.[ENTER]No entanto Yu-Hwan poder\225 ser capaz de nos ajudar[ENTER]se tiver conhecimento de uma erva com o efeito[ENTER]pretendido. "
gameforge.new_quest_lv52._052_say = "Conhe\231o bem o Capit\227o. Como j\225 sabes tenho andado[ENTER]a cumprir miss\245es secretas para ele desde h\225[ENTER]algum tempo. Mas posso dizer-te que n\227o s\227o ervas[ENTER]que v\227o resolver os seus problemas. "
gameforge.new_quest_lv52._053_say = "H\225 outra raz\227o pela qual o Capit\227o n\227o consegue[ENTER]dormir. E acredita em mim, ele sabe exactamente[ENTER]qual \233 essa raz\227o. Mas \233 algo que tem de ser ele[ENTER]pr\243prio a resolver e que eu n\227o posso tratar por[ENTER]ele. Vai ter com ele e pergunta-lhe. "
gameforge.new_quest_lv52._054_say_title = "Capit\227o "
gameforge.new_quest_lv52._055_say_reward = "Ah, recebeste a minha carta. N\227o sei simplesmente[ENTER]o que fazer. Por favor pede alguns conselhos ao[ENTER]Baek-Go para que eu finalmente possa ter uma boa[ENTER]noite de sono. "
gameforge.new_quest_lv52._055_select = "Sim, senhor! "
gameforge.new_quest_lv52._056_say = "Obrigado! "
gameforge.new_quest_lv52._056_say_reward = "J\225 o fui ver e ele n\227o tem nenhum medicamento[ENTER]mais forte. Mas vou ter com o Yu-Hwan e[ENTER]perguntar-lhe se te pode ajudar. "
gameforge.new_quest_lv52._060_target = "Capit\227o "
gameforge.new_quest_lv52._061_say = "Yu-Hwan n\227o quer falar sobre os segredos de[ENTER]terceiros, por isso \233 prov\225vel que seja algo[ENTER]desagrad\225vel. Mas n\227o vale a pena, tens de falar[ENTER]com o Capit\227o sobre isto. Se n\227o soubermos qual a[ENTER]causa, n\227o poderemos resolver os seus problemas[ENTER]de sono. Por isso vai at\233 %s. "
gameforge.new_quest_lv52._062_say_reward = "N\227o h\225 nenhum rem\233dio mais forte dispon\237vel. Mas[ENTER]talvez eu possa ajudar se souber a causa das suas[ENTER]ins\243nias, Capit\227o. "
gameforge.new_quest_lv52._063_say_reward = "N\227o \233 algo que eu gostaria de contar a um jovem[ENTER]como tu. "
gameforge.new_quest_lv52._064_say_reward = "N\227o \233 algo que eu gostaria de contar a uma jovem[ENTER]como tu. "
gameforge.new_quest_lv52._065_say_reward = "Mas se eu n\227o tiver uma boa noite de sono[ENTER]brevemente irei acabar por dar em louco. Parece[ENTER]que tem de ser...[ENTER]Mas lembra-te, isto \233 apenas para os teus[ENTER]ouvidos: Sou atormentado por quatro fantasmas[ENTER]todas as noites. Mas o pior \233 que... Eu fui o[ENTER]respons\225vel pelas suas mortes. "
gameforge.new_quest_lv52._066_say_reward = "S\227o quatro soldados. Eles dizem que foram[ENTER]torturados e mortos pelos Conjuradores e[ENTER]Atormentadores Negros do Vale Seungryong. Fui eu[ENTER]que ordenei que eles se dirigissem a esse local -[ENTER]enviei-os para a morte! "
gameforge.new_quest_lv52._067_say_reward = "O que podemos fazer acerca destes tipos de[ENTER]fantasmas? "
gameforge.new_quest_lv52._068_say_reward = "Eles querem vingan\231a! O que devo fazer? Se eu[ENTER]sair daqui para retribuir a Vila ir\225 ficar sem[ENTER]L\237der e ser\225 conquistada. E se eu n\227o for irei[ENTER]dar em louco. "
gameforge.new_quest_lv52._069_say_reward = "Se eu n\227o fosse respons\225vel pela seguran\231a desta[ENTER]Vila iria imediatamente. Assim vejo apenas uma[ENTER]sa\237da: "
gameforge.new_quest_lv52._070_say_reward = "Algu\233m ter\225 de se vingar por mim! Mas como serei[ENTER]capaz de enviar mais homens para o Vale, se[ENTER]arrisco-me a estar a envi\225-los para a sua ru\237na?[ENTER]N\227o posso simplesmente fazer este pedido de \226nimo[ENTER]leve... "
gameforge.new_quest_lv52._071_say_reward = "Uma decis\227o dessas n\227o \233 f\225cil. "
gameforge.new_quest_lv52._080_1_select = "O bem da vila... "
gameforge.new_quest_lv52._080_2_select = "N\227o ser\225 f\225cil... "
gameforge.new_quest_lv52._080_3_select = "N\227o podes esperar que fa\231a algo assim! "
gameforge.new_quest_lv52._081_say_reward = "... vale mais do que a tua cobardia. Irei vingar[ENTER]os teus homens. E se eu n\227o voltar, virei[ENTER]visitar-te esta noite. "
gameforge.new_quest_lv52._082_say_reward = "... tratar destes Conjuradores e Atormentadores.[ENTER]Mas ir\225s dormir bem esta noite, prometo! "
gameforge.new_quest_lv52._083_say_reward = "Tens desejos de morrer? \201 demasiado perigoso[ENTER]enfrentar os Atormentadores e os Conjuradores.[ENTER]Tenta dizer isso aos fantasmas! "
gameforge.new_quest_lv52._084_say_reward = "Tens raz\227o. Mas mesmo assim estava \224 espera que[ENTER]te voluntariasses. Estarias a fazer um grande[ENTER]servi\231o a mim e a toda a vila. "
gameforge.new_quest_lv52._090_1_select = "Bem... "
gameforge.new_quest_lv52._090_2_select = "N\227o, n\227o vou conseguir faz\234-lo! "
gameforge.new_quest_lv52._091_say_reward = "...se eu sou a tua ultima esperan\231a, ent\227o eu vou[ENTER]eliminar esses conjuradores e atormentadores por[ENTER]ti! "
gameforge.new_quest_lv52._092_say_reward = "Se eu tentar isso, outro fantasma ir\225[ENTER]encontrar-te. "
gameforge.new_quest_lv52._093_say_reward = "OK. Bem deixa-me dar-te algum Yang pelos teus[ENTER]esfor\231os. "
gameforge.new_quest_lv52._093_say_reward_exp = "Recebeste 20.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv52._093_say_reward_gold = "Recebeste 25.000 Yang. "
gameforge.new_quest_lv52._100_notice = "A conversa terminou. "
gameforge.new_quest_lv52._110_say_reward = "Estava \224 espera que dissesses isso. Mas[ENTER]infelizmente n\227o sei quais foram os[ENTER]Atormentadores ou Conjuradores que os mataram.[ENTER]Mas acho que conseguirei sentir quando a alma de[ENTER]um dos fantasmas for libertada. "
gameforge.new_quest_lv52._111_say_reward = "Irei enviar-te uma carta. Os fantasmas[ENTER]contaram-me que a vingan\231a tem de ter lugar no[ENTER]Tri\226ngulo do Deus Drag\227o. No local existem tr\234s[ENTER]pilares que formam os v\233rtices do tri\226ngulo. "
gameforge.new_quest_lv52._120_set_title = "Vinga 4 dos soldados ca\237dos "
gameforge.new_quest_lv52._125_say_title = "Carta do Capit\227o "
gameforge.new_quest_lv52._130_say_reward = "Ainda h\225 3 soldados por vingar! "
gameforge.new_quest_lv52._131_say = "Parece que tiveste sucesso. Ouvi a voz de um dos[ENTER]soldados ca\237dos. Ele disse que me perdoa, agora[ENTER]que a sua morte foi vingada. E tudo isto gra\231as a[ENTER]ti! "
gameforge.new_quest_lv52._132_say = "Por favor vinga os outros soldados e mata[ENTER]Atormentadores Negros, Conjuradores Negros,[ENTER]Grandes Atormentadores e Grandes Conjuradores.[ENTER]Lembra-te que apenas poder\225s libertar as almas[ENTER]dos soldados ca\237dos no tri\226ngulo formado pelos[ENTER]tr\234s pilares do Deus Drag\227o. "
gameforge.new_quest_lv52._140_say_reward = "Ainda h\225 2 soldados por vingar! "
gameforge.new_quest_lv52._141_say = "Eliminaste outro dos assassinos dos meus[ENTER]soldados! \192 meia-luz consegui ver um dos soldados[ENTER]a levantar a m\227o numa contin\234ncia. "
gameforge.new_quest_lv52._150_say_reward = "Falta vingar um soldado! "
gameforge.new_quest_lv52._151_say = "\201s uma pessoa incr\237vel! O fantasma de um dos[ENTER]soldados ca\237dos veio ter comigo h\225 momentos e[ENTER]disse-me adeus. Provavelmente ser\225 dif\237cil[ENTER]encontrar o \250ltimo assassino. "
gameforge.new_quest_lv52._160_say = "Os fantasmas que andam a atormentar o Capit\227o[ENTER]pertencem aos jovens soldados que morreram no[ENTER]decorrer desta miss\227o. Eles foram mortos pelos[ENTER]Atormentadores Negros, Conjuradores Negros,[ENTER]Grandes Atormentadores e Grandes Conjuradores. "
gameforge.new_quest_lv52._161_say = "Para poderes vingar a morte dos soldados tens de[ENTER]ir at\233 ao Tri\226ngulo do Deus Drag\227o, formado pelos[ENTER]tr\234s pilares no centro do Vale Seungryong, e[ENTER]eliminar os Atormentadores e Conjuradores. "
gameforge.new_quest_lv52._162_say = "O Tri\226ngulo do Deus Drag\227o encontra-se no centro[ENTER]do Vale Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Primeiro soldado vingado "
gameforge.new_quest_lv52._171_send_letter = "Segundo soldado vingado "
gameforge.new_quest_lv52._172_send_letter = "Terceiro soldado vingado "
gameforge.new_quest_lv52._173_send_letter = "Todos os soldados vingados "
gameforge.new_quest_lv52._180_say_reward = "Vingaste todos os 4 soldados! "
gameforge.new_quest_lv52._181_say = "Encontraste o \250ltimo assassino! O \250ltimo dos[ENTER]quatro fantasmas dos soldados ca\237dos surgiu \224[ENTER]minha frente e pediu-me para agradecer a tua[ENTER]coragem. Ele tamb\233m deixou algo para ti: %s "
gameforge.new_quest_lv52._182_say = "Vem ter comigo para receberes a tua recompensa.[ENTER]Estarei \224 tua espera em %s. "
gameforge.new_quest_lv52._183_say_reward = "Fizeste um grande servi\231o a mim e \224 vila.[ENTER]Aqui tens a recompensa que o fantasma deixou para[ENTER]ti: %s "
gameforge.new_quest_lv52._184_say_reward = "E aqui tens algum Yang. Vou retirar-me e[ENTER]finalmente conseguir dormir descansado. "
gameforge.new_quest_lv52._185_say_reward = "Ficarei profundamente em d\237vida para contigo,[ENTER]jovem. "
gameforge.new_quest_lv52._186_say_reward = "Ficarei eternamente em d\237vida para contigo. "
gameforge.new_quest_lv52._190_say_title = "Informa\231\227o: "
gameforge.new_quest_lv52._191_say_reward = "Recebeste 3.300.000 Pontos de Experi\234ncia.[ENTER]Recebeste 270.000 Yang.[ENTER]Recebeste um Manual de Habilidades. "
gameforge.new_quest_lv52._85_say = "Ent\227o talvez mais tarde? Por favor vai ter com o[ENTER]Baek-Go quando mudares de ideias. "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Capit\227o "
gameforge.new_quest_lv54._020_say_title = "As novas provis\245es "
gameforge.new_quest_lv54._030_say = "Neste momento \233 dif\237cil manter as tropas[ENTER]motivadas, especialmente quando \233 t\227o dif\237cil[ENTER]obter provis\245es frescas. A Negociadora da Loja[ENTER]Geral, uma das nossas fornecedoras mais[ENTER]importantes, tem enviado apenas uma pequena[ENTER]quantidade das po\231\245es que precisamos. "
gameforge.new_quest_lv54._031_say_reward = "Por favor vai ter com a Negociadora da Loja Geral[ENTER]e descobre o que se passa. "
gameforge.new_quest_lv54._032_select = "Irei dar-te as po\231\245es! "
gameforge.new_quest_lv54._040_say_title = "Loja Geral: "
gameforge.new_quest_lv54._040_set_title = "Novas Provis\245es "
gameforge.new_quest_lv54._050_target = "Loja Geral: "
gameforge.new_quest_lv54._051_say = "Sim, ultimamente tem sido muito dif\237cil obter[ENTER]novas provis\245es. As rotas comerciais tornaram-se[ENTER]muito perigosas e os assassinos e animais[ENTER]selvagens est\227o sempre a surgir. Os Vendedores[ENTER]Ambulantes, a quem comprava os meus bens, n\227o t\234m[ENTER]qualquer hip\243tese contra os tigres. "
gameforge.new_quest_lv54._052_say = "Talvez o Capit\227o e os seus soldados possam ajudar.Por favor vai ter com ele e pergunta-lhe se pode[ENTER]enviar alguns soldados para proteger os[ENTER]mercadores. "
gameforge.new_quest_lv54._054_say = "Vai ter com a Negociadora da Loja Geral e[ENTER]descobre porque \233 que as novas provis\245es est\227o[ENTER]atrasadas. "
gameforge.new_quest_lv54._055_say = "A Negociadora da Loja Geral encontra-se em %s. "
gameforge.new_quest_lv54._056_say_title = "Capit\227o "
gameforge.new_quest_lv54._060_say = "Proteger as rotas comerciais? Sim... gostaria de[ENTER]fazer isso. Mas n\227o tenho soldados suficientes[ENTER]para proteger todos os Vendedores Ambulantes. "
gameforge.new_quest_lv54._061_say = "Al\233m disso, n\243s soldados n\227o devemos ca\231ar[ENTER]tigres. Apenas ca\231adores do cl\227 de ca\231adores[ENTER]est\227o autorizados a faz\234-lo. N\227o haveria paz na[ENTER]vila se viol\225ssemos essa regra. "
gameforge.new_quest_lv54._062_say_reward = "Portanto deverias falar com o Yang-Shin. Ele \233 um[ENTER]membro do cl\227 de ca\231adores. Talvez ele te possa[ENTER]ajudar a tratar do problema dos tigres. "
gameforge.new_quest_lv54._064_say = "Vai ter com o Capit\227o e tenta convenc\234-lo a[ENTER]proteger as rotas comerciais contra os tigres. "
gameforge.new_quest_lv54._065_say = "O Capit\227o encontra-se em %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Muitos dos ca\231adores estavam alistados como[ENTER]guerreiros e pereceram durante a guerra. Agora[ENTER]tornou-se praticamente imposs\237vel manter sob[ENTER]controlo a popula\231\227o de animais selvagens. Os[ENTER]felinos s\227o um problema especial, pois est\227o a[ENTER]expandir o seu territ\243rio, colocando em perigo os[ENTER]viajantes. "
gameforge.new_quest_lv54._072_say = "Se nos ajudares com isto, irei dar-te como[ENTER]recompensa este valioso Escudo Tigre Monge+3, que[ENTER]pertencia ao meu camarada Mi-Song. Para o obteres[ENTER]ter\225s de reduzir de forma significativa a[ENTER]popula\231\227o de tigres. "
gameforge.new_quest_lv54._073_say = "A ra\231a de Tigres Brancos Malditos, em particular,[ENTER]tem-se multiplicado de forma descontrolada. "
gameforge.new_quest_lv54._074_say = "Como prova, irei precisar de: "
gameforge.new_quest_lv54._075_say = "Tens de ca\231ar: "
gameforge.new_quest_lv54._076_say = "Procura o Yang-Shin e tenta convenc\234-lo a[ENTER]proteger as rotas comerciais contra os tigres. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "O Yang-Shin encontra-se em %s. "
gameforge.new_quest_lv54._080_set_title = "O P\234lo Brilhante de Tigre "
gameforge.new_quest_lv54._081_notice = "Um esp\233cime espl\234ndido. S\243 preciso de mais %s! "
gameforge.new_quest_lv54._082_notice = "Feito! \201 melhor ir r\225pido ter com o Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "Este P\234lo Brilhante de Tigre n\227o serve. "
gameforge.new_quest_lv54._084_say = "Precisas de mais %s unidade(s) de P\234lo Brilhante[ENTER]de Tigre. "
gameforge.new_quest_lv54._085_say = "Obt\233m P\234lo Brilhante de Tigre dos Tigres Brancos[ENTER]Malditos. "
gameforge.new_quest_lv54._090_npcChat = "Tenho o P\234lo Brilhante de Tigre. "
gameforge.new_quest_lv54._091_say = "Isso n\227o \233 nem perto da quantidade que eu[ENTER]preciso. Como posso deduzir que os caminhos j\225[ENTER]est\227o seguros de novo com base nestes P\234los? "
gameforge.new_quest_lv54._092_say = "Ahh finalmente! Estes P\234los ir\227o dar um bom[ENTER]neg\243cio... er! Ainda aqui est\225s? Gra\231as a ti as[ENTER]estradas est\227o finalmente seguras de novo! Tenho[ENTER]a certeza que o Capit\227o te ir\225 dar uma boa[ENTER]recompensa. "
gameforge.new_quest_lv54._093_say = "E agora vai-te embora. Preciso de limpar os P\234los. "
gameforge.new_quest_lv54._094_say = "Oh, o Capit\227o n\227o te quer dar uma recompensa?[ENTER]Bem, o problema n\227o \233 meu. E caso estejas aqui[ENTER]para reaver os P\234los: Esquece, n\227o os irei[ENTER]devolver! "
gameforge.new_quest_lv54._095_say_reward = "Mas prometi-te um escudo, portanto irei dar-te[ENTER]um. Esta coisa velha j\225 n\227o tem qualquer[ENTER]utilidade para mim. "
gameforge.new_quest_lv54._096_say = "Recompensa: "
gameforge.new_quest_lv54._097_say_reward = "Recebeste um Escudo Tigre Monge+3. "
gameforge.new_quest_lv54._098_say = "Queres enganar-me com apenas meia d\250zia de[ENTER]P\234los?! Assim as minhas d\237vidas... Quero dizer,[ENTER]assim as rotas comerciais nunca mais voltar\227o a[ENTER]ser seguras! "
gameforge.new_quest_lv54._099_say_reward = "Vai ca\231ar tigres at\233 teres recolhido %s P\234los[ENTER]Brilhantes de Tigre. "
gameforge.new_quest_lv54._100_say = "E \233 tudo. Agora \233 melhor voltar ao Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Recebeste 3.750.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv54._102_say_reward = "Recebeste 125.000 Yang. "
