gameforge.new_quest_lv7._010_target = "Oct\225vio: "
gameforge.new_quest_lv7._011_say_title = "Oct\225vio: "
gameforge.new_quest_lv7._012_say_title = "Idosa "
gameforge.new_quest_lv7._020_say_title = "O casamento da filha "
gameforge.new_quest_lv7._021_say = "Tens filhos? Ent\227o dever\225s compreender as minhas[ENTER]preocupa\231\245es... \233 sobre a minha filha! Ela[ENTER]encontrou um homem que lhe virou a cabe\231a do[ENTER]avesso. E agora ela fugiu para outro Reino com o[ENTER]seu amor. "
gameforge.new_quest_lv7._022_say = "Ele pertence ao Reino Chunjo. \201 claro que eu[ENTER]estou contra isso! Para mim uma senhora do Reino[ENTER]Shinsoo n\227o se pode casar com um sonhador[ENTER]espiritual de Chunjo. Depois de uma discuss\227o[ENTER]entre n\243s, ela fugiu com ele para o Reino Chunjo. "
gameforge.new_quest_lv7._023_say = "Ele pertence ao Reino Jinno. \201 claro que eu estou[ENTER]contra isso! Para mim uma senhora do Reino Chunjo[ENTER]n\227o se pode casar com um bruto de Jinno. Depois[ENTER]de uma discuss\227o entre n\243s, ela fugiu com ele[ENTER]para o Reino Jinno. "
gameforge.new_quest_lv7._024_say = "Ele pertence ao Reino Shinsoo. \201 claro que eu[ENTER]estou contra isso! Para mim uma senhora do Reino[ENTER]Jinno n\227o se pode casar com um armado em rico de[ENTER]Shinsoo. Depois de uma discuss\227o entre n\243s, ela[ENTER]fugiu com ele para o Reino Shinsoo. "
gameforge.new_quest_lv7._030_say = "Ouvi dizer que ela se quer casar l\225 com ele. "
gameforge.new_quest_lv7._031_say = "Agora a minha filha est\225 \224 espera de um sinal[ENTER]meu. O que devo fazer? Ela \233 a minha \250nica filha![ENTER]\201 claro que tenho de lhe dar a minha b\234n\231\227o.[ENTER]Por favor vai ter com a Idosa por mim e[ENTER]pergunta-lhe se pode ajudar com as prepara\231\245es. "
gameforge.new_quest_lv7._040_target = "Idosa "
gameforge.new_quest_lv7._041_say = "Encontra a Idosa e pergunta-lhe se pode ajudar a[ENTER]fazer os preparativos para o casamento. "
gameforge.new_quest_lv7._042_say = "A Idosa encontra-se em %s. "
gameforge.new_quest_lv7._051_say = "Um casamento, dizes? Bem, \233 um momento importante[ENTER]na vida de uma mulher. Tudo tem de dar certo,[ENTER]desde o vestido da noiva ao fato do noivo, al\233m[ENTER]dos An\233is de Casal, que a cerim\243nia transforma em[ENTER]Alian\231as. Quando o pai da noiva tiver dado o seu[ENTER]consentimento e o Yang necess\225rio tiver sido[ENTER]pago, a celebra\231\227o poder\225 ser preparada. "
gameforge.new_quest_lv7._052_say = "As flores s\227o particularmente importantes - n\227o[ENTER]pode existir casamento sem um ramo de flores que[ENTER]o noivo tenha oferecido \224 noiva. O ramo dever\225[ENTER]ser composto pelas seguintes flores: "
gameforge.new_quest_lv7._054_say = "Preciso: "
gameforge.new_quest_lv7._055_say = "Tens de ca\231ar: "
gameforge.new_quest_lv7._056_say = "Ainda preciso de: "
gameforge.new_quest_lv7._060_say = "Regressa quando tiveres todas as tr\234s flores.[ENTER]Irei verificar se est\227o suficientemente frescas e[ENTER]irei criar um bonito ramo. Ent\227o poder\225s lev\225-lo[ENTER]\224 minha irm\227. Ela ir\225 tratar da cerim\243nia. "
gameforge.new_quest_lv7._081_say = "Recolhe uma flor de cada tipo. Poder\225s obt\234-las[ENTER]matando Lobos Alfa Ferozes, Lobos Azuis Ferozes e[ENTER]Lobos Alfa Azuis Ferozes. "
gameforge.new_quest_lv7._082_say = "Esta flor seca n\227o \233 propriamente decorativa.[ENTER]Tanto trabalho e nada para mostrar! "
gameforge.new_quest_lv7._083_say = "Esta flor seca n\227o \233 propriamente decorativa.[ENTER]Tanto trabalho e nada para mostrar! "
gameforge.new_quest_lv7._084_say = "Esta flor seca n\227o \233 propriamente decorativa.[ENTER]Tanto trabalho e nada para mostrar! "
gameforge.new_quest_lv7._085_1_say_reward = "Falta-te %s Flor Vermelha. Podes obt\234-la matando[ENTER]Lobos Alfa Ferozes. "
gameforge.new_quest_lv7._085_2_say_reward = "Falta-te %s Flor Laranja. Podes obt\234-la matando[ENTER]Lobos Azul Ferozes. "
gameforge.new_quest_lv7._085_3_say_reward = "Falta-te %s Flor Amarela. Podes obt\234-la matando[ENTER]Lobos Alfa Azuis Ferozes. "
gameforge.new_quest_lv7._085_say_reward = "Ainda te falta %s Flor Vermelha. "
gameforge.new_quest_lv7._086_say_reward = "Ainda te falta %s Flor Laranja. "
gameforge.new_quest_lv7._087_say_reward = "Ainda te falta %s Flor Amarela. "
gameforge.new_quest_lv7._088_notice = "Esta flor \233 um esp\233cime espl\234ndido. Muito bem! "
gameforge.new_quest_lv7._089_notice = "Esta flor \233 um esp\233cime espl\234ndido. Muito bem! "
gameforge.new_quest_lv7._090_notice = "Esta flor \233 um esp\233cime espl\234ndido. Muito bem! "
gameforge.new_quest_lv7._091_say = "J\225 est\225! Estas flores dever\227o servir para criar[ENTER]um ramo maravilhoso! Agora regressa rapidamente \224[ENTER]Idosa antes que as flores comecem a murchar! "
gameforge.new_quest_lv7._092_say = "Recolhe flores para o ramo da noiva. "
gameforge.new_quest_lv7._110_say = "S\227o flores bonitas, mas n\227o s\227o suficientemente[ENTER]especiais para um casamento desta dimens\227o. "
gameforge.new_quest_lv7._111_say = "Podes obt\234-las matando Lobos Alfa Ferozes, Lobos[ENTER]Azuis Ferozes e Lobos Alfa Azuis Ferozes. "
gameforge.new_quest_lv7._112_say = "Estas flores dever\227o servir para compor um ramo[ENTER]maravilhoso. "
gameforge.new_quest_lv7._115_say = "Obrigado, parece \243ptimo! Aqui tens, leva este[ENTER]ramo de flores \224 minha irm\227. "
gameforge.new_quest_lv7._116_say_reward = "Podes encontr\225-la na \193rea Bokjung do Reino Chunjo. "
gameforge.new_quest_lv7._117_say_reward = "Podes encontr\225-la na \193rea Bakra do Reino Jinno. "
gameforge.new_quest_lv7._118_say_reward = "Podes encontr\225-la na \193rea Yayang do Reino Shinsoo. "
gameforge.new_quest_lv7._120_set_title = "A irm\227 "
gameforge.new_quest_lv7._125_notice = "Este \233 o Reino certo. Deverei conseguir encontrar[ENTER]a irm\227 da Idosa aqui. "
gameforge.new_quest_lv7._129_say = "Este \233 o Reino certo. Deverei encontrar o Oct\225vio[ENTER]aqui. "
gameforge.new_quest_lv7._130_say = "Este parece ser o Reino certo. Agora procura a[ENTER]irm\227 da Idosa. "
gameforge.new_quest_lv7._131_say = "N\227o parece ser o Reino certo. "
gameforge.new_quest_lv7._132_say_reward = "Tens de ir at\233 \224 \193rea Bokjung no Reino Chunjo. "
gameforge.new_quest_lv7._133_say_reward = "Tens de ir at\233 \224 \193rea Bakra no Reino Jinno. "
gameforge.new_quest_lv7._134_say_reward = "Tens de ir at\233 \224 \193rea Yayang no Reino Shinsoo. "
gameforge.new_quest_lv7._135_say = "Regressa ao Oct\225vio, que se encontra em Yongan no[ENTER]Reino Shinsoo. "
gameforge.new_quest_lv7._136_say = "Regressa ao Oct\225vio, que se encontra em Joan no[ENTER]Reino Chunjo. "
gameforge.new_quest_lv7._137_say = "Regressa ao Oct\225vio, que se encontra em Pyungmoo[ENTER]no Reino Jinno. "
gameforge.new_quest_lv7._140_say = "Aqui est\227o as flores para o casamento da filha do[ENTER]Oct\225vio. Dever\227o ser dadas \224 noiva com uma[ENTER]b\234n\231\227o. Ela saber\225 quem lhe ofereceu o ramo. "
gameforge.new_quest_lv7._141_say = "S\227o flores lindas! Ir\227o dar um ar ainda mais[ENTER]esbelto \224 noiva. Isto completa os preparativos.[ENTER]Por favor informa o Oct\225vio de que est\225 convidado[ENTER]para a cerim\243nia. Sei que ele vai ficar muito[ENTER]contente. "
gameforge.new_quest_lv7._142_say = "E agora vai ter com o Oct\225vio. De que est\225s \224[ENTER]espera? "
gameforge.new_quest_lv7._143_say = "Trouxeste as flores para o casamento da filha do[ENTER]Oct\225vio? \201s uma pessoa muito simp\225tica! Mas...[ENTER]onde est\227o? Perdeste-as no caminho para aqui? "
gameforge.new_quest_lv7._144_say_reward = "Regressa ao teu Reino e arranja novas flores para[ENTER]o casamento. "
gameforge.new_quest_lv7._145_say = "Vai ter com a irm\227 da Idosa antes que as flores[ENTER]sequem. "
gameforge.new_quest_lv7._150_say = "Porque cheiras a sopa de r\227-touro? Bem, n\227o[ENTER]interessa, desde que tenhas boas not\237cias. "
gameforge.new_quest_lv7._151_say = "N\227o consigo agradecer-te o suficiente. Estou t\227o[ENTER]contente por poder estar presente no casamento da[ENTER]minha filha! "
gameforge.new_quest_lv7._152_say = "Aqui tens a tua recompensa: "
gameforge.new_quest_lv7._153_say_reward = "Uma arma criada para ser empunhada por um mestre[ENTER]das artes marciais. Toma bem conta dela! "
gameforge.new_quest_lv7._154_say_reward = "Recebeste %s Pontos de Experi\234ncia. "
gameforge.new_quest_lv7._155_say_reward = "Recebeste %s Yang. "
gameforge.new_quest_lv7._160_say = "Obviamente est\225s a confundir-me com um familiar[ENTER]distante. N\227o tenho uma filha e n\227o tenho Yang[ENTER]suficiente para organizar um casamento. "
gameforge.new_quest_lv7._165_say = "Gostarias de experimentar uma colher da minha[ENTER]sopa de r\227-touro? Preparei-a de acordo com uma[ENTER]receita antiga da minha tia. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young: "
gameforge.new_quest_lv75._020_set_title = "Di\225rio de uma Lenda "
gameforge.new_quest_lv75._021_say = "Encontrei estes restos mortais de um guerreiro.[ENTER]N\227o sei se \233 o Sura que Heuk-Young procura, mas[ENTER]certamente ela ficar\225 interessada. "
gameforge.new_quest_lv75._022_say = "N\227o morreu apenas um Sura aqui. Vi os seus restos[ENTER]mortais. Pergunto-me se o guerreiro lend\225rio[ENTER]estar\225 entre eles... Deveria regressar e informar[ENTER]Heuk-Young disto. "
gameforge.new_quest_lv75._023_say = "Encontrei um peda\231o de papel velho congelado no[ENTER]Golem de Gelo Negro. Mal o consigo ler, mas[ENTER]poder\225 ser uma pista do interesse da Heuk-Young. "
gameforge.new_quest_lv75._024_say = "Encontrei algumas coisas que poder\227o interessar a[ENTER]Heuk-Young. Deveria ir visit\225-la e dar-lhe o[ENTER]peda\231o de papel. Tamb\233m a poderei informar acerca[ENTER]do corpo. "
gameforge.new_quest_lv75._025_say = "Heuk-Young pediu-me para prestar aten\231\227o a[ENTER]quaisquer pistas sobre o lend\225rio Sura.[ENTER]Infelizmente n\227o fa\231o a m\237nima ideia do que estou[ENTER]\224 procura... "
gameforge.new_quest_lv75._030_say = "Procura o lend\225rio lutador Akuma. Ele foi o Sura[ENTER]mais famoso de sempre - um guerreiro praticamente[ENTER]invenc\237vel. Os rumores dizem que ele at\233 chegou a[ENTER]desafiar o Imperador uma vez. Creio que foi aqui[ENTER]neste lugar que Akuma desapareceu h\225 centenas de[ENTER]anos. Por favor procura pistas que nos possam[ENTER]indicar onde ele se encontrava. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Examinar os guerreiros mortos "
gameforge.new_quest_lv75._060_say = "Parecem ser os restos mortais de um guerreiro. No[ENTER]entanto o bra\231o esquerdo n\227o parece humano...[ENTER]Deve ter sido um Sura. Tenho de informar[ENTER]Heuk-Young acerca disto. "
gameforge.new_quest_lv75._070_notice = "Uma p\225gina de um livro... congelada num Golem de[ENTER]Gelo Negro... "
gameforge.new_quest_lv75._090_say = "N\227o posso realmente dizer-te exactamente o que[ENTER]procuramos. Limita-te a procurar por a\237 e[ENTER]regressa quando tiveres encontrado alguma coisa. "
gameforge.new_quest_lv75._100_say = "O que tens a\237? Deixa-me ver! "
gameforge.new_quest_lv75._105_say = "Uma p\225gina... e que tipo de escrita \233 esta?[ENTER]Parece ser bastante antiga. Poder\225s ter[ENTER]encontrado algo muito importante. Aquilo que aqui[ENTER]est\225 escrito parece familiar. Parece que esta[ENTER]p\225gina j\225 fez parte de um livro. "
gameforge.new_quest_lv75._109_say = "Se consegu\237ssemos encontrar mais algumas p\225ginas[ENTER]tudo faria um pouco mais sentido. Procura mais[ENTER]pistas! "
gameforge.new_quest_lv75._110_say = "Aqui est\225s tu de novo. Encontraste alguma coisa?[ENTER]Conta-me! "
gameforge.new_quest_lv75._115_say = "Um Sura morto... Poder\225 ser ele ou poder\225 ser um[ENTER]dos seus seguidores. Precisamos de mais provas[ENTER]para termos a certeza. Procura pistas que possam[ENTER]revelar a identidade do corpo. J\243ias, talvez[ENTER]notas ou algo assim... "
gameforge.new_quest_lv75._120_say = "O Esqueleto de Sura e uma P\225gina de um livro?[ENTER]Deixa-me dar uma vista de olhos na p\225gina...[ENTER]Hum.. Poder\225s ter encontrado os restos mortais de[ENTER]Akuma. No entanto precisamos de mais provas. Por[ENTER]favor tenta encontrar mais p\225ginas. "
gameforge.new_quest_lv75._130_say = "J\225 encontrei algumas provas, mas n\227o tenho[ENTER]realmente a certeza se o lend\225rio Sura esteve ou[ENTER]n\227o aqui. Preciso de mais informa\231\245es. "
gameforge.new_quest_lv75._140_1_select = "Bom "
gameforge.new_quest_lv75._140_2_select = "Criatura de Gelo "
gameforge.new_quest_lv75._140_3_select = "\192 beira do desespero "
gameforge.new_quest_lv75._140_4_select = "Terror negro "
gameforge.new_quest_lv75._140_5_select = "A cara da morte "
gameforge.new_quest_lv75._140_6_select = "O destino do guerreiro "
gameforge.new_quest_lv75._140_7_select = "N\227o, n\227o tenho interesse. "
gameforge.new_quest_lv75._150_say = "Apenas posso decifrar algumas das frases. Elas[ENTER]contam sobre uma vida na corte e um amor[ENTER]excessivo pela aventura... "
gameforge.new_quest_lv75._160_1_say = "O texto na p\225gina amarelada est\225 esbatido e[ENTER]tremido, como se tivesse sido escrito por algu\233m[ENTER]muito velho ou sem for\231as: \"...Criaturas de Gelo.[ENTER]Mesmo as minhas habilidades de Sura n\227o me[ENTER]ajudaram a derrot\225-las todas. Algumas delas ainda[ENTER]vagueiam pela Gruta e tenho de ter especial[ENTER]prud\234ncia caso elas me encontrem. At\233 h\225 pouco[ENTER]tempo ofereciam-me protec\231\227o, mas agora...\" A[ENTER]partir daqui n\227o existe mais texto. "
gameforge.new_quest_lv75._160_2_say = "Esta p\225gina tamb\233m se encontra muito gasta. Pela[ENTER]data que se encontra no canto podes reconhecer[ENTER]que parece um di\225rio: \"N\227o \233 a primeira vez que[ENTER]desejo ter agido de forma diferente enquanto[ENTER]procurava a Gruta. Estava t\227o orgulhoso e[ENTER]contente comigo mesmo! Todas estas coisas[ENTER]conduziram-me certamente \224 morte...\" A pen\250ltima[ENTER]palavra est\225 fortemente sublinhada. "
gameforge.new_quest_lv75._160_3_say = "A p\225gina est\225 bastante danificada, peda\231os dela[ENTER]parecem ter sido arrancados. Apenas \233 poss\237vel[ENTER]decifrar partes da mensagem: \"... A corte do[ENTER]Imperador... onde os escol\225sticos me ensinaram[ENTER]tudo o que eu desesperadamente queria saber... \233[ENTER]f\225cil abrir o portal, mas... morte e terror no[ENTER]escuro...\" Um grande rasgo evita que possas ler o[ENTER]resto. "
gameforge.new_quest_lv75._160_4_say = "Ir\225s encontrar um esbo\231o nesta p\225gina: O retrato[ENTER]da cara de uma mulher.[ENTER]Sob ele est\227o escritas algumas palavras na[ENTER]caligrafia j\225 familiar. No entanto o texto parece[ENTER]estar mais tremido e agitado: \"A Morte tem as[ENTER]suas garras j\225 de fora - Descobri isto ontem.[ENTER]Olhei apenas de relance para a criatura antes de[ENTER]o medo se ter apoderado de mim e eu ter de[ENTER]recuar. Oh minha querida Sumni, se eu pudesse ter[ENTER]adivinhado o futuro! Se eu tivesse conhecimento[ENTER]pr\233vio deste horror indescrit\237vel nunca me teria[ENTER]aventurado at\233 aqui!\" "
gameforge.new_quest_lv75._160_5_say = "Durante a Dinastia Hee-se viveu um Sura lend\225rio,[ENTER]de seu nome Akuma. Ele era muito talentoso no[ENTER]combate, pelo que raramente encontrava[ENTER]advers\225rios contra quem ele pudesse testar a sua[ENTER]for\231a. Um dia ele encontrou algumas notas sobre[ENTER]um lugar misterioso, selado h\225 muito tempo atr\225s,[ENTER]e decidiu investir todo o seu tempo na busca[ENTER]desse lugar. Chegou a descobrir como encontrar e[ENTER]abrir os portais. Ele prometeu regressar \224 sua[ENTER]amada Sunmi assim que tivesse terminado as suas[ENTER]buscas... Mas ele nunca voltou... "
gameforge.new_quest_lv75._170_say = "A caligrafia parece-me muito arcaica... Tamb\233m se[ENTER]encontra muito tremida e desalinhada, como se j\225[ENTER]n\227o restassem muitas for\231as ao seu autor. "
gameforge.new_quest_lv75._171_say = "Isto n\227o faz sentido. Precisamos de mais p\225ginas. "
gameforge.new_quest_lv75._172_say = "Estou a come\231ar a perceber o que poder\225 ter[ENTER]acontecido aqui. Mas ainda existem muitas coisas[ENTER]das quais n\227o tenho a certeza. "
gameforge.new_quest_lv75._173_say = "Gostarias de saber os detalhes? "
gameforge.new_quest_lv75._174_say = "Outra p\225gina! Quem escreveu isto deveria estar[ENTER]completamente desesperado. Deverei resumir o que[ENTER]est\225 aqui? "
gameforge.new_quest_lv75._175_say = "Algumas das p\225ginas est\227o muito estragadas, pelo[ENTER]que apenas posso adivinhar o que dizem. no[ENTER]entanto estou a come\231ar a perceber o que se[ENTER]passou nesta Gruta h\225 muitos anos atr\225s. "
gameforge.new_quest_lv75._176_say = "J\225 n\227o falta muito. Queres saber o que eu[ENTER]descobri? "
gameforge.new_quest_lv75._177_say = "Parece que j\225 n\227o faltam muitas p\225ginas. "
gameforge.new_quest_lv75._178_say = "Queres saber o que j\225 descobri at\233 agora? "
gameforge.new_quest_lv75._180_notice = "Encontrei a \250ltima p\225gina nos Golems de Gelo[ENTER]Negros. "
gameforge.new_quest_lv75._185_send_letter = "Agora j\225 devemos estar na posse de todas as[ENTER]p\225ginas! "
gameforge.new_quest_lv75._190_notice = "Encontrei esta p\225gina nos Golems de Gelo Negros. "
gameforge.new_quest_lv75._195_send_letter = "Encontrei uma nova p\225gina! "
gameforge.new_quest_lv75._200_npcChat = "Procurar os guerreiros mortos "
gameforge.new_quest_lv75._210_say = "Existem 3 p\225ginas do fr\225gil livro perto dos[ENTER]esqueletos humanos. As pontas estragadas indicam[ENTER]que foram arrancadas de um livro. A caligrafia na[ENTER]p\225gina est\225 esbatida e \233 de dif\237cil leitura. "
gameforge.new_quest_lv75._220_say = "Acho que isto deve ser suficiente. Irei levar[ENTER]isto a Heuk-Young. "
gameforge.new_quest_lv75._230_say = "Pergunto-me que restos mortais ser\227o estes...[ENTER]Bom, de uma coisa tenho a certeza, n\227o possu\237a[ENTER]nada que ainda pudesse ser utilizado hoje em dia. "
gameforge.new_quest_lv75._240_send_letter = "Tenho as p\225ginas! "
gameforge.new_quest_lv75._250_say = "Deveria regressar a Heuk-Young. Talvez ela[ENTER]consiga encaixar as pe\231as deste puzzle. "
gameforge.new_quest_lv75._270_say = "Estou surpresa por teres descoberto tantas coisas[ENTER]na Gruta. As p\225ginas parecem ter feito parte de[ENTER]um livro. Aquilo que nelas est\225 escrito \233[ENTER]bastante interessante. Tudo faz sentido quando[ENTER]penso nas outras hist\243rias que j\225 ouvi... Se me[ENTER]deres as p\225ginas poderei compil\225-las num livro.[ENTER]Talvez venha a dar jeito quando te dirigires \224[ENTER]Gruta das Almas. Se n\227o te servir para nada tenho[ENTER]a certeza que ir\225s encontrar algu\233m que to ir\225[ENTER]comprar. "
gameforge.new_quest_lv75._280_say = "Juntei as p\225ginas num livro e adicionei algumas[ENTER]das minhas notas. Talvez te possam servir de[ENTER]algo. Posso contar-te o resto da hist\243ria se[ENTER]desejares. "
gameforge.new_quest_lv75._290_1_select = "Sim, conta-me mais! "
gameforge.new_quest_lv75._290_2_select = "N\227o, n\227o tenho interesse nisso! "
gameforge.new_quest_lv75._310_say = "O que queres de mim? N\227o v\234s que estou a ler? "
gameforge.new_quest_lv75._320_say = "Sr. Soon: "
gameforge.new_quest_lv75._330_say = "Tens a\237 um livro muito interessante. De onde vem[ENTER]ele? Posso dar uma vista de olhos? "
gameforge.new_quest_lv75._340_say = "Estas s\227o as notas sobre a Gruta das Almas certo?[ENTER]A caligrafia \233 estranha e a escrita \233 bastante[ENTER]antiquada... Deve ter sido dif\237cil obter um livro[ENTER]como este. \201 claro que eu gostaria de p\244r as[ENTER]minhas m\227os nele. N\227o est\225s interessado em[ENTER]vend\234-lo? "
gameforge.new_quest_lv75._350_1_select = "Sim "
gameforge.new_quest_lv75._350_2_select = "N\227o "
gameforge.new_quest_lv75._360_say = "Quanto Yang queres pelo livro? "
gameforge.new_quest_lv75._370_say = "Haha... Tens muita piada. Obviamente n\227o \233 f\225cil[ENTER]negociar contigo. Ok, este \233 o neg\243cio: 500.000[ENTER]Yang pelo Di\225rio Lend\225rio. \201 pegar ou largar! "
gameforge.new_quest_lv75._380_1_select = "Fico com os 500.000 Yang. "
gameforge.new_quest_lv75._380_2_select = "Vamos esquecer isto ent\227o. "
gameforge.new_quest_lv75._390_say = "Ok, ent\227o esquece. "
gameforge.new_quest_lv75._400_say = "N\227o, desculpa, isso \233 demasiado caro para mim. "
gameforge.new_quest_lv75._410_say = "Vamos l\225 fazer outra oferta... Estou disposto a[ENTER]dar-te %s Yang pelo Di\225rio Lend\225rio. "
gameforge.new_quest_lv75._420_say = "Concordas com isto? "
gameforge.new_quest_lv75._425_say = "Esta \233 a minha \250ltima oferta! "
gameforge.new_quest_lv75._430_1_select = "Fico com os %s Yang. "
gameforge.new_quest_lv75._430_2_select = "Ent\227o parece-me que n\227o teremos neg\243cio. "
gameforge.new_quest_lv75._440_say = "O que quiseres... "
gameforge.new_quest_lv75._450_say = "N\227o \233 propriamente barato, mas eu quero ser[ENTER]generoso. "
gameforge.new_quest_lv75._460_say = "Existe um limite na minha generosidade. Irei[ENTER]dar-te 500.000 Yang pelo Di\225rio Lend\225rio. "
gameforge.new_quest_lv75._470_say = "\201 pegar ou largar! "
gameforge.new_quest_lv75._480_say = "Ok, ent\227o esquece. "
gameforge.new_quest_lv75._490_say = "Que pena. Ah bom, pode ser que mudes de ideias[ENTER]mais tarde. "
gameforge.new_quest_lv80 = {}
gameforge.new_quest_lv80._010_target = "Sr. Soon: "
gameforge.new_quest_lv80._020_set_title = "A M\225scara de Madeira Negra "
gameforge.new_quest_lv80._030_say = "Ah, mesmo a tempo! Ouvi dizer que recentemente[ENTER]estiveste na Gruta das Almas. "
gameforge.new_quest_lv80._040_say = "Esta \233 a primeira vez que vejo algu\233m que[ENTER]regressou desse lugar. Tenho de admitir, estou[ENTER]muito curioso... "
gameforge.new_quest_lv80._050_1_say = "Tenho uma miss\227o para ti, mas \233 bastante[ENTER]perigosa. No entanto acho que um homem como tu[ENTER]dever\225 ser capaz de a levar a cabo. "
gameforge.new_quest_lv80._050_2_say = "Tenho uma miss\227o para ti, mas \233 bastante[ENTER]perigosa. No entanto acho que uma mulher como tu[ENTER]dever\225 ser capaz de a levar a cabo. "
gameforge.new_quest_lv80._060_say = "Toma esta M\225scara de Madeira e dirige-te \224 \225rea[ENTER]de Doyyumhwan. A\237 procura os Fantasmas de Chamas.[ENTER]J\225 os dever\225s conhecer - s\227o criaturas esf\233ricas[ENTER]que est\227o completamente cobertas de chamas. "
gameforge.new_quest_lv80._070_say = "Se matares um deles a M\225scara de Madeira ir\225[ENTER]reagir e ir\225 converter-se em cinzas. N\227o[ENTER]desanimes se n\227o funcionar das primeiras vezes. "
gameforge.new_quest_lv80._080_say = "Depois traz-me as cinzas. "
gameforge.new_quest_lv80._090_say = "J\225 que te diriges para zonas perigosas tamb\233m me[ENTER]poderias trazer %s Pe\231as de Gelo. Preciso[ENTER]desesperadamente delas. "
gameforge.new_quest_lv80._100_say = "Os Yetis t\234m frequentemente Pe\231as de Gelo com[ENTER]eles. Por isso de que est\225s \224 espera? "
gameforge.new_quest_lv80._110_say_title = "Fogo e Gelo "
gameforge.new_quest_lv80._120_say = "O Sr. Soon deu-me a tarefa de... "
gameforge.new_quest_lv80._130_say = "J\225 encontrei as Pe\231as de Gelo. "
gameforge.new_quest_lv80._140_say = "Ainda preciso: "
gameforge.new_quest_lv80._150_say_reward = "Aparentemente posso encontr\225-las ca\231ando Yetis! "
gameforge.new_quest_lv80._160_say = "A M\225scara de Madeira Negra j\225 se converteu em[ENTER]Cinzas Enfeiti\231adas. "
gameforge.new_quest_lv80._170_say = "Preciso: "
gameforge.new_quest_lv80._180_say_reward = "Preciso de ter "
gameforge.new_quest_lv80._190_say_reward = "comigo. De acordo com o Sr. Soon a m\225scara ir\225[ENTER]converter-se em Cinzas Enfeiti\231adas quando eu[ENTER]combater com os Fantasmas de Chamas. "
gameforge.new_quest_lv80._200_say = "Agora s\243 preciso das Cinzas Enfeiti\231adas e das[ENTER]Pe\231as de Gelo. \211ptimo, espera s\243 um segundo... "
gameforge.new_quest_lv80._210_say = "Funcionou! O que os textos antigos dizem \233 mesmo[ENTER]verdade! "
gameforge.new_quest_lv80._220_say = "Produzi o Gelo Negro com os itens que me[ENTER]trouxeste. "
gameforge.new_quest_lv80._230_say = "No entanto tenho outra miss\227o para ti, que est\225[ENTER]relacionada com a primeira. Se tamb\233m completares[ENTER]esta irei dar-te todas as minhas poupan\231as! "
gameforge.new_quest_lv80._240_say = "Leva o Gelo Negro \224 Gruta das almas e sacrifica-o[ENTER]no Santu\225rio Negro. "
gameforge.new_quest_lv80._250_say = "Ainda falta(m) %s Pe\231a(s) de Gelo. "
gameforge.new_quest_lv80._260_notice = "Algo n\227o est\225 certo. "
gameforge.new_quest_lv80._270_say = "\211ptimo - Vejo que tens as Pe\231as de Gelo. Agora s\243[ENTER]me faltam as Cinzas Enfeiti\231adas. "
gameforge.new_quest_lv80._280_say = "De que est\225s \224 espera...? "
gameforge.new_quest_lv80._290_say = "Hum... Estas parecem ser Cinzas normais, n\227o as[ENTER]Enfeiti\231adas. "
gameforge.new_quest_lv80._300_target = "Santu\225rio Negro "
gameforge.new_quest_lv80._310_set_title = "O Santu\225rio Negro "
gameforge.new_quest_lv80._320_say = "\201 suposto eu levar o Gelo Negro \224 Gruta das almas[ENTER]e sacrific\225-lo no Santu\225rio Negro. N\227o ser\225 f\225cil[ENTER]encontrar o Santu\225rio! "
gameforge.new_quest_lv80._330_npcChat = "Sacrificar o Gelo Negro! "
gameforge.new_quest_lv80._340_say = "\192 medida que te aproximas do altar, as trevas[ENTER]parecem rodear-te. No escuro, vozes incorp\243reas[ENTER]sussurram sobre a sua ang\250stia eterna. Este \233[ENTER]realmente um local profano. Queres mesmo[ENTER]sacrificar o Gelo Negro? "
gameforge.new_quest_lv80._350_1_select = "Sim! O que pode acontecer de pior? "
gameforge.new_quest_lv80._350_2_select = "N\227o, isto ainda pode acabar mal! "
gameforge.new_quest_lv80._360_say = "Ainda n\227o tenho a certeza de que fiz a coisa[ENTER]certa - sacrificar algo na Gruta... Tenho a[ENTER]certeza que o Deus Drag\227o n\227o o aprova. Quem me[ENTER]dera poder desfazer o que fiz. "
gameforge.new_quest_lv80._370_say = "N\227o estou a gostar disto. Sacrificar algo na[ENTER]Gruta provavelmente n\227o teria a aprova\231\227o do Deus[ENTER]Drag\227o. N\227o o irei fazer. "
gameforge.new_quest_lv80._380_say = "\201 o Santu\225rio errado! "
gameforge.new_quest_lv80._390_send_letter = "Regressa ao Soon "
gameforge.new_quest_lv80._400_set_title = "Monstros estranhos "
gameforge.new_quest_lv80._410_say = "Deveria regressar ao Sr. Soon para receber a[ENTER]minha recompensa. "
gameforge.new_quest_lv80._420_say = "Ouvi dizer que foram avistados uns monstros[ENTER]estranhos em algumas partes do Reino. "
gameforge.new_quest_lv80._430_say = "Espero que n\227o esteja relacionado com o facto de[ENTER]ter sacrificado o Gelo Negro na Gruta das Almas. "
gameforge.new_quest_lv80._440_say = "Muito bem! Aqui est\225 a tua recompensa. "
gameforge.new_quest_lv80._450_npcChat = "Viste os monstros? "
gameforge.new_quest_lv80._460_say = "%s?! Meu Deus... N\227o fa\231o a m\237nima ideia de como[ENTER]uma coisa destas pode ter acontecido... Vou j\225[ENTER]investigar isto no meu livro. "
gameforge.new_quest_lv80._470_say = "N\227o fui capaz de sacrificar o Gelo Negro...[ENTER]pareceu-me t\227o errado! Irei regressar ao Soon e[ENTER]dizer-lhe que n\227o irei completar esta miss\227o. "
gameforge.new_quest_lv80._475_npcChat = "O Gelo Negro "
gameforge.new_quest_lv80._476_say = "Vejo que j\225 n\227o tens o Gelo Negro contigo.[ENTER]Sacrificaste-o mesmo? Conta-me o que se passou! "
gameforge.new_quest_lv80._477_say = "Desculpa-me, mas isto \233 um mal entendido - ainda[ENTER]tenho o Gelo Negro. Vou busc\225-lo e voltar mais[ENTER]tarde... "
gameforge.new_quest_lv80._480_say = "Ah, aqui est\225s tu! Porque ainda tens o Gelo Negro[ENTER]contigo? "
gameforge.new_quest_lv80._490_say = "N\227o fui capaz de fazer o que me pediste. Seria[ENTER]contra a vontade do Deus Drag\227o. N\227o irei[ENTER]sacrificar o Gelo! "
gameforge.new_quest_lv80._495_say = "Bah, que in\250til! Nem consegue completar uma[ENTER]tarefa t\227o simples. Parece que tenho de encontrar[ENTER]algu\233m que n\227o seja t\227o picuinhas.[ENTER]D\225-me o Gelo Negro! Vamos l\225, d\225-mo! "
gameforge.new_quest_lv80._500_say = "Deverei mesmo entregar o Gelo Negro ao Soon? "
gameforge.new_quest_lv80._510_1_select = "Sim, quero livrar-me dele! "
gameforge.new_quest_lv80._510_2_select = "N\227o, ele poder\225 causar sarilhos! "
gameforge.new_quest_lv80._520_say = "Aqui tens, fica com o Gelo Negro e deixa-me em[ENTER]paz! "
gameforge.new_quest_lv80._530_say = "Est\225s \224 espera que eu te agrade\231a? Sai da minha[ENTER]vista! "
gameforge.new_quest_lv80._535_sayReward = "Recebeste 70.000.000 Pontos de Experi\234ncia. "
gameforge.new_quest_lv80._540_say = "N\227o irei regressar com o Gelo Negro. Vou atir\225-lo[ENTER]ao mar - a\237 n\227o ir\225 fazer mal a ningu\233m! "
gameforge.new_quest_lv80._550_say = "N\227o te atreverias! D\225-me o Gelo ou irei[ENTER]amaldi\231oar-te a ti e \224 tua fam\237lia! "
gameforge.new_quest_lv80._560_say = "Faz o que quiseres - n\227o te deixarei impedir-me. "
gameforge.new_quest_lv80._570_target_pos = "Litoral Sul "
gameforge.new_quest_lv80._580_target_pos = "Litoral Ocidental "
gameforge.new_quest_lv80._590_target_pos = "Litoral Oriental "
gameforge.new_quest_lv80._599_set_title = "No fim de um caminho errado "
gameforge.new_quest_lv80._600_say = "Deveria dirigir-me a Yongan e atirar o Gelo Negro[ENTER]ao mar. "
gameforge.new_quest_lv80._610_say = "Deveria dirigir-me a Joan e atirar o Gelo Negro[ENTER]ao mar. "
gameforge.new_quest_lv80._620_say = "Deveria dirigir-me a Pyungmoo e atirar o Gelo[ENTER]Negro ao mar. "
gameforge.new_quest_lv80._630_say_reward = "Assim que te preparas para atirar o Gelo Negro ao[ENTER]mar ele derrete. L\237quido negro escorre pelos teus[ENTER]dedos at\233 ao ch\227o e evapora-se antes de sequer[ENTER]lhe conseguires tocar. "
gameforge.new_quest_lv80._640_say = "Subitamente surgem \224 tua frente os seguintes[ENTER]objectos: "
gameforge.new_quest_lv80._650_say = "\192 medida que apanhas os itens, sentes satisfa\231\227o[ENTER]por teres tomado a decis\227o correcta. E agora tens[ENTER]nas tuas m\227os a gratid\227o do Deus Drag\227o. "
gameforge.new_quest_lv80._660_say = "Oh n\227o, esqueci-me de trazer comigo o Gelo Negro![ENTER]Parece-me que a \250nica coisa a fazer \233 obt\234-lo e[ENTER]vir aqui de novo. "
gameforge.new_quest_lv80._670_sayReward = "Tamb\233m recebeste 120.000.000 Pontos de[ENTER]Experi\234ncia. "
gameforge.new_quest_premium_lv4 = {}
gameforge.new_quest_premium_lv4._100_npcChat = "Abrir Loja "
gameforge.new_quest_premium_lv4._100_say_reward = "Tens de ca\231ar: "
gameforge.new_quest_premium_lv4._10_targetVid = "Loja Geral: "
gameforge.new_quest_premium_lv4._110_say = "Procura o Vendedor de Armas e pergunta-lhe porque[ENTER]ele j\225 n\227o canta sob a janela da Negociadora da[ENTER]Loja Geral. "
gameforge.new_quest_premium_lv4._120_qSetTitle = "Recolhe Lil\225s "
gameforge.new_quest_premium_lv4._130_notice = "Obtiveste uma bonita flor de Lil\225s! "
gameforge.new_quest_premium_lv4._140_notice = "Terminado! Agora vamos apressar-nos a regressar[ENTER]ao Vendedor de Armas. "
gameforge.new_quest_premium_lv4._150_notice = "Infelizmente esta flor de Lil\225s est\225 seca. "
gameforge.new_quest_premium_lv4._160_say = "Precisas do seguinte n\250mero de flores de Lil\225s: %s  "
gameforge.new_quest_premium_lv4._170_say = "N\227o \233 suficiente. Este Lil\225s apenas chega para[ENTER]algumas gotas! "
gameforge.new_quest_premium_lv4._180_say = "Ah... Lil\225s! Agora s\243 preciso de um pouco da[ENTER]estranha Ess\234ncia de Alm\237scar. Apenas a poder\225s[ENTER]obter numa Loja especial. Uma Moeda rotativa ir\225[ENTER]indicar-te o caminho. Ir\225s precisar de alguns[ENTER]Escudos do Drag\227o, mas tenho a certeza que j\225[ENTER]tens alguns acumulados e guardados, n\227o \233?[ENTER]Ficaria eternamente agradecido! Depois poder\225s[ENTER]levantar a tua compra no Guarda do Armaz\233m. Ent\227o[ENTER]finalmente poderei ter todos os ingredientes. "
gameforge.new_quest_premium_lv4._190_say = "Por favor apressa-te e traz-me a Ess\234ncia de[ENTER]Alm\237scar. Ir\225s ser recompensado se o fizeres. "
gameforge.new_quest_premium_lv4._200_say_reward = "Continua com as tuas ca\231adas at\233 que me tenhas[ENTER]trazido %s flores de Lil\225s! "
gameforge.new_quest_premium_lv4._20_sayTitle = "Meu querido "
gameforge.new_quest_premium_lv4._210_say = "Mata Lobos Azuis para as obteres. "
gameforge.new_quest_premium_lv4._220_say = "\201 tudo. Agora regressa ao Vendedor de Armas. "
gameforge.new_quest_premium_lv4._230_qSetTitle = "A Ess\234ncia de Alm\237scar "
gameforge.new_quest_premium_lv4._240_say = "Muito obrigado. Agora finalmente poderei produzir[ENTER]uma nova fragr\226ncia. "
gameforge.new_quest_premium_lv4._250_say = "Podes dizer \224 minha amada que irei cantar de novo[ENTER]sob a sua janela esta noite. Ela ficar\225[ENTER]satisfeita. "
gameforge.new_quest_premium_lv4._260_say = "Mereces uma recompensa: "
gameforge.new_quest_premium_lv4._270_say_reward = "Yang: %d "
gameforge.new_quest_premium_lv4._280_say = "Sem a Ess\234ncia de Alm\237scar n\227o posso produzir a[ENTER]minha fragr\226ncia. Por favor deixa-te guiar pela[ENTER]Moeda rotativa e arranja-me outro exemplar. "
gameforge.new_quest_premium_lv4._290_say_reward = "Regressa com %s x Ess\234ncia de Alm\237scar. "
gameforge.new_quest_premium_lv4._300_say = "Preciso de levar alguma Ess\234ncia de Alm\237scar ao[ENTER]Vendedor de Armas. \201 suposto que eu me deixe[ENTER]guiar pela Moeda rotativa, encomende uma estranha[ENTER]Ess\234ncia e a levante no Guarda do Armaz\233m. "
gameforge.new_quest_premium_lv4._30_say = "Tenho saudades do meu amado, o Vendedor de Armas.[ENTER]Durante semanas ele cantou sob a minha janela[ENTER]todas as noites mas j\225 h\225 uns dias que n\227o ou\231o[ENTER]nada dele. Talvez ele tenha medo do meu pai.[ENTER]Podes tentar descobrir o que se passa com ele? "
gameforge.new_quest_premium_lv4._310_say_title = "O Vendedor de Armas "
gameforge.new_quest_premium_lv4._320_say = "Oh, obrigado. Dizes que ele simplesmente se[ENTER]atrasou com algo? Que al\237vio. Irei esperar por[ENTER]ele esta noite. "
gameforge.new_quest_premium_lv4._330_say_reward = "Pelo teu esfor\231o recebes: %s Pontos de[ENTER]Experi\234ncia. "
gameforge.new_quest_premium_lv4._340_say = "Regressa rapidamente \224 negociadora da Loja Geral. "
gameforge.new_quest_premium_lv4._350_npcChat = "Lil\225s "
gameforge.new_quest_premium_lv4._35_qSetTitle = "Fala com o Vendedor de Armas "
gameforge.new_quest_premium_lv4._360_npcChat = "A Ess\234ncia de Alm\237scar "
gameforge.new_quest_premium_lv4._40_qSetTitle = "Uma nova fragr\226ncia "
gameforge.new_quest_premium_lv4._45_qSetTitle = "Ca\231a Lobos Azuis "
gameforge.new_quest_premium_lv4._50_targetVid = "Vendedor de Armas: "
gameforge.new_quest_premium_lv4._55_qSetTitle = "Regressa ao Vendedor de Armas "
gameforge.new_quest_premium_lv4._60_sayTitle = "O malandro "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Entrega a Ess\234ncia de Alm\237scar ao Vendedor de[ENTER]Armas "
gameforge.new_quest_premium_lv4._70_say = "\201 verdade, nunca mais cantei sob a sua janela[ENTER]porque... oh, bom, sinto-me t\227o envergonhado por[ENTER]falar nisto! O meu odor corporal est\225 a tornar-se[ENTER]um pouco repulsivo. Lavo-me a toda a hora, mas o[ENTER]odor simplesmente n\227o desaparece. \201 por isso que[ENTER]quero produzir uma fragr\226ncia que entorpe\231a os[ENTER]sentidos da negociadora da Loja Geral, a minha[ENTER]amada, com o seu fascinante e m\225gico cheiro. Para[ENTER]ela a apar\234ncia exterior \233 muito importante. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "Dirige-te \224 negociadora da Loja Geral "
gameforge.new_quest_premium_lv4._80_say = "Preciso mesmo de produzir uma nova fragr\226ncia. \201[ENTER]a \250nica forma que tenho de me livrar do meu[ENTER]desagrad\225vel odor corporal. "
gameforge.new_quest_premium_lv4._90_say = "Para isso tenho de juntar v\225rios ingredientes.[ENTER]Estes precisam de ser juntos primeiro: "
gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Servidor de Testes "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Sou um homem muito velho, mas ainda estou em boa[ENTER]forma e saud\225vel porque tenho um segredo.[ENTER]Descobri que uma po\231\227o feita de Sumo de Raiz de[ENTER]Gango e Cogumelo Tue pode prolongar a tua vida.[ENTER]Se quiseres experimentar a po\231\227o, leva os[ENTER]ingredientes ao Yu-Hwan. Ele poder\225 criar a po\231\227o[ENTER]por ti. "
gameforge.npc_talk._10_say = "Est\225 quieto e mant\233m a disciplina! Porta-te bem e[ENTER]n\227o causes sarilhos. Tens de respeitar os teus[ENTER]camaradas. Compreendido? "
gameforge.npc_talk._110_npcChat = "Pareces bastante forte... "
gameforge.npc_talk._120_say = "Durante muitos anos, o segredo da for\231a foi[ENTER]passado entre a minha fam\237lia. O meu pai[ENTER]contou-me que se adicionares uma Flor de Sino a[ENTER]uma po\231\227o da maneira correcta, a po\231\227o ir\225 dar-te[ENTER]for\231a extra durante um curto per\237odo de tempo.[ENTER]Pelo que sei, o Baek-Go consegue criar esta[ENTER]po\231\227o. S\243 precisas de lhe levar Flores de Sino. "
gameforge.npc_talk._130_npcChat = "Oliveirinha da serra... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan: "
gameforge.npc_talk._150_say = "...o vento leva a flor... Tamb\233m gostas de[ENTER]m\250sica? Quando estou aqui sozinho canto v\225rios[ENTER]tipos de m\250sicas, tudo para me esquecer da[ENTER]guerra. Mas sem um Reino a proteger-me n\227o seria[ENTER]capaz de continuar a fazer o que fa\231o. "
gameforge.npc_talk._160_npcChat = "Porque l\234s tanto? "
gameforge.npc_talk._170_sayTitle = "Sr. Soon: "
gameforge.npc_talk._180_say = "Oh, aventureiro! O mundo est\225 repleto de[ENTER]problemas. Apenas consegues sobreviver se tiveres[ENTER]um certo n\237vel de sabedoria. Por isso honra os[ENTER]teus livros. Em maus momentos - e hoje em dia os[ENTER]momentos s\227o sempre maus - eles ir\227o ajudar-te.[ENTER]Acredita em mim! "
gameforge.npc_talk._190_npcChat = "Tens filhos? "
gameforge.npc_talk._200_say = "Na verdade eu n\227o queria filhos, mas...[ENTER]Bom, eu continuo a recolher Flores de Kaki porque[ENTER]se as preparares correctamente conseguir\225s[ENTER]fortalecer a tua energia m\225gica. Foi Baek-Go que[ENTER]o descobriu. Ele precisa de apenas uma Flor para[ENTER]criar 100 po\231\245es. No entanto a Flor de Kaki tem[ENTER]tamb\233m efeitos secund\225rios. Se uma mulher usar um[ENTER]colar feito dessas flores ela ir\225 ter um filho.[ENTER]Entre n\243s dois, acho que a minha mulher tirou[ENTER]proveito disto... "
gameforge.npc_talk._20_npcChat = "Humm, cheira bem aqui... "
gameforge.npc_talk._210_npcChat = "Que se passa com o teu p\233? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Estou a ficar melhor. Enquanto andava por a\237 no[ENTER]outro dia, tropecei numa Raiz de Gango e torci o[ENTER]tornozelo. Felizmente conhe\231o o doutor Baek-Go,[ENTER]pelo que ele me tratou e me deu alguns conselhos:[ENTER]Para curar pequenas feridas \233 poss\237vel criar uma[ENTER]po\231\227o a partir destas mesmas Ra\237zes de Gango. Por[ENTER]isso tornei as malditas ra\237zes que me fizeram[ENTER]isto num ch\225, curando o mal que elas me[ENTER]causaram... "
gameforge.npc_talk._240_npcChat = "Quem \233s tu? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Sou Wonda-Rim, o sobrinho de Chaegirab. O meu tio[ENTER]\233 famoso! Conhece-lo? Ele faz diversas[ENTER]experi\234ncias com po\231\245es e ervas. Enquanto o fazia[ENTER]ele descobriu que podes obter muita protec\231\227o[ENTER]contra magias se misturares 100 unidades de \193gua[ENTER]Bo com uma Amora. Tanto quanto sei, Hu-Ahn-So \233[ENTER]capaz de produzir esta po\231\227o se lhe levares os[ENTER]ingredientes. "
gameforge.npc_talk._270_npcChat = "Porque tens tantas cicatrizes? "
gameforge.npc_talk._280_sayTitle = "Traidor Balso: "
gameforge.npc_talk._290_say = "N\227o sou um bom guerreiro, por isso muitas vezes[ENTER]fico ferido na guerra. A certa altura perguntei[ENTER]ao Yu-Hwan se ele n\227o poderia criar-me uma po\231\227o[ENTER]para proteger o meu corpo dos ferimentos. Ele[ENTER]criou algo a partir de Sumo de Flor de Sino e de[ENTER]Lil\225s, mas infelizmente a protec\231\227o n\227o foi[ENTER]suficiente. Ou talvez tenha sido apenas a minha[ENTER]pr\243pria incompet\234ncia. Mas tenho a certeza que a[ENTER]po\231\227o ir\225 ajudar-te. "
gameforge.npc_talk._300_npcChat = "Porque \233 que tanta gente te chama traidor? "
gameforge.npc_talk._30_sayTitle = "Oct\225vio: "
gameforge.npc_talk._310_say = "Fugi da guerra e juntei-me ao Cl\227 Vento Nego. Os[ENTER]meus camaradas nunca me perdoaram por isso.[ENTER]Depois descobri que os guerreiros do Cl\227 Vento[ENTER]Negro matam pessoas inocentes, pelo que abandonei[ENTER]imediatamente o Cl\227. Foi horr\237vel! "
gameforge.npc_talk._320_say = "Tens pessoas inocentes a pesarem-te na[ENTER]consci\234ncia? Ent\227o mereces mesmo o teu nome.[ENTER]Impediste-as de viverem uma boa vida. "
gameforge.npc_talk._330_say = "Vivemos num mundo sem justi\231a. Mas decidi que[ENTER]nunca mais farei nada de errado! N\227o quero que[ENTER]andem por a\237 a chamar-me traidor.[ENTER][ENTER]Tens algum Yang para mim? "
gameforge.npc_talk._340_npcChat = "Chamam-te o S\225bio? "
gameforge.npc_talk._350_sayTitle = "Uriel: "
gameforge.npc_talk._360_say = "H\225 tanto para aprender neste vasto mundo. A[ENTER]ignor\226ncia e o poder militar n\227o combinam bem.[ENTER]N\227o queres viver como estes ignorantes soldados[ENTER]certo? Conhecimento \233 poder! "
gameforge.npc_talk._370_npcChat = "Contaram-me que praticas medicina... "
gameforge.npc_talk._380_say = "Fa\231o o que posso. Mas todos os dias existem cada[ENTER]vez mais baixas neste perigoso mundo. N\227o temos[ENTER]m\227os nem medicamentos suficientes. S\227o tempos[ENTER]dif\237ceis! Talvez me possas dar uma m\227ozinha mais[ENTER]tarde? "
gameforge.npc_talk._390_npcChat = "Como est\225 a correr o neg\243cio da ca\231a? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin: "
gameforge.npc_talk._40_say = "Bem-vindo! O nosso restaurante tradicional \233 t\227o[ENTER]bem-sucedido que poder\237amos abrir restaurantes[ENTER]por todo o mundo. Se quiseres algo delicioso para[ENTER]comer, passa por aqui e experimenta a nossa[ENTER]comida. "
gameforge.npc_talk._410_say = "Hum... Desde que as Pedras Metin come\231aram a cair[ENTER]os animais enlouqueceram. Hoje em dia j\225 arriscas[ENTER]a vida ao simplesmente pores um p\233 na rua para[ENTER]ca\231ares umas galinhas. S\227o tempos dif\237ceis para[ENTER]os ca\231adores. Felizmente sou um dos melhores! "
gameforge.npc_talk._420_npcChat = "De onde vem a tua grande pontaria? "
gameforge.npc_talk._430_say = "Sou um mestre do arco porque tenho uma receita[ENTER]secreta, he he! Quando juntas Sumo de Flor de[ENTER]P\234ssego e Lil\225s obt\233ns uma po\231\227o que aumenta a[ENTER]tua pontaria.[ENTER]Leva os ingredientes a Yu-Hwan. Tenho a certeza[ENTER]que ele poder\225 criar esta po\231\227o para ti. "
gameforge.npc_talk._440_npcChat = "Que bonito ramo de flores... "
gameforge.npc_talk._450_say = "Era costume eu apanhar Flores de P\234ssego com o[ENTER]meu irm\227o. Mas hoje tenho de o fazer sozinha. N\227o[ENTER]s\227o muito bonitas, mas t\234m um efeito especial. Se[ENTER]levares uma Flor de P\234ssego a o Baek-Go ele ir\225[ENTER]criar-te uma po\231\227o que te far\225 sentir mais leve! "
gameforge.npc_talk._460_npcChat = "Onde est\225 o teu irm\227o? "
gameforge.npc_talk._470_say = "Recentemente o meu irm\227o tem viajado muito.[ENTER]Ultimamente mal o vejo e preocupo-me muito com[ENTER]ele. "
gameforge.npc_talk._480_npcChat = "Vendes bolos de arroz? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang: "
gameforge.npc_talk._500_say = "Devido \224 guerra \233 dif\237cil vender Bolos de Arroz.[ENTER]Perdi muitos clientes gra\231as aos bandidos. N\227o[ENTER]sei mais o que hei de fazer para me sustentar. "
gameforge.npc_talk._50_say = "Embora seja um grande restaurante, a mob\237lia \233[ENTER]surpreendentemente simples. "
gameforge.npc_talk._510_npcChat = "Quem costuma comprar-te bens? "
gameforge.npc_talk._520_say = "Vendo a maior parte dos meus bolos a viajantes.[ENTER]Um dia, um misterioso cavaleiro vestido de negro[ENTER]veio ver-me. Como pagamento ele deu-me uma[ENTER]receita com a qual podes produzir \193gua Zin. \201 uma[ENTER]po\231\227o que aumenta o teu poder de ataque. Vendi a[ENTER]receita ao Hu-Ahn-So. Se lhe levares \193gua Sim e[ENTER]uma Rosa Alpina ele poder\225 produzir \193gua Zin para[ENTER]ti. "
gameforge.npc_talk._530_npcChat = "Porque est\225s t\227o triste? "
gameforge.npc_talk._540_say = "Oh, quem poderia imaginar que os nossos doces[ENTER]sonhos seriam desfeitos de forma t\227o cruel...? O[ENTER]meu pobre marido que faleceu em combate! ...Por[ENTER]favor vinga a sua morte! "
gameforge.npc_talk._550_npcChat = "J\225 faleceram tantos na guerra... "
gameforge.npc_talk._560_say = "Estamos a perder cada vez mais homens na guerra,[ENTER]por isso as mulheres desta vila uniram-se e[ENTER]pediram ao Hu-Ahn-So para criar uma melhor po\231\227o[ENTER]de cura. Ap\243s uma longa pesquisa ele produziu uma[ENTER]po\231\227o que aumenta a Defesa, reduzindo o n\250mero de[ENTER]po\231\245es de cura necess\225rias. Vai v\234-lo. Tenho a[ENTER]certeza que ele consegue produzir-te a po\231\227o a[ENTER]que ele chama \193gua Sambo. Precisas apenas de lhe[ENTER]levar \193gua Dok e uma Rosa Alpina. "
gameforge.npc_talk._570_npcChat = "Oh, que crian\231a fofa... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Ele est\225 a gritar de novo... N\227o sei o que ele[ENTER]quer... Ser\227o doces? Oh n\227o! "
gameforge.npc_talk._600_npcChat = "Como est\227o voc\234s duas? "
gameforge.npc_talk._60_npcChat = "Conta-me algo sobre a Olaria. "
gameforge.npc_talk._610_say = "O meu filho! Agora que o meu marido morreu na[ENTER]guerra tenho de cuidar de mim mesma. Estou a[ENTER]tentar sustentar-me a mim e ao meu filho. E[ENTER]gra\231as \224 \193gua Bo encontrei uma forma de ganhar a[ENTER]vida. Apenas tenho de levar 100 Sumos de Flor de[ENTER]Kaki e 1 Cogumelo Tue ao Yu-Hwan. Ele cria a \193gua[ENTER]Bo a partir destes ingredientes, e a \193gua[ENTER]vende-se muito bem. Afinal de contas, tenho de[ENTER]fazer algo para ganhar dinheiro... "
gameforge.npc_talk._620_npcChat = "Como est\225 o teu marido? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "O meu suposto marido est\225 casado com os seus[ENTER]livros. Ele j\225 mal olha para mim. E n\227o sou uma[ENTER]mulher feia. "
gameforge.npc_talk._650_npcChat = "Como vai o neg\243cio? "
gameforge.npc_talk._660_say = "Desde que a guerra come\231ou o neg\243cio tem sido[ENTER]mau. A Uni\227o dos Mercadores outrora foi poderosa,[ENTER]mas esses dias chegaram ao fim. N\227o podemos[ENTER]continuar a ignorar os animais selvagens, as[ENTER]membros do cl\227 Jura de Cristal e os membros do[ENTER]cl\227 Vento Negro. "
gameforge.npc_talk._670_npcChat = "Porque est\225s de t\227o mau humor? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "A Harang \233 uma rapariga m\225! Detesto-a! Sou fraco[ENTER]e ela passa a vida a chatear-me! "
gameforge.npc_talk._700_say = "\201s um homem cheio de m\250sculos. N\227o te esque\231as de[ENTER]os treinar! "
gameforge.npc_talk._70_sayTitle = "Yonah: "
gameforge.npc_talk._710_npcChat = "O que est\225s a fazer? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Estou \224 espera do Taurean. Muitas vezes brincamos[ENTER]e combatemos juntos. Que cobarde! Se ele n\227o[ENTER]quiser vir aqui voluntariamente irei fazer-lhe a[ENTER]vida negra! "
gameforge.npc_talk._740_npcChat = "Taurean tem medo de ti. "
gameforge.npc_talk._750_say = "Na realidade o Taurean \233 mais forte que eu. Por[ENTER]isso \233 que magiquei uma forma de eu conseguir[ENTER]vencer. Um Ninja disse-me que podes misturar \193gua[ENTER]Young com uma Amora e criar uma po\231\227o que te[ENTER]deixa desferir golpes mais r\225pidos. Quando a[ENTER]tiver serei finalmente capaz de vencer o Taurean![ENTER]Se tamb\233m te quiseres tornar num lutador \225gil[ENTER]apenas tens de levar os ingredientes ao[ENTER]Hu-Ahn-So. Tenho a certeza que ele te poder\225[ENTER]criar esta po\231\227o. "
gameforge.npc_talk._760_npcChat = "Novo conhecimento... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Meu amigo, o mundo est\225 repleto de quest\245es que[ENTER]ficam por responder. E eu procuro as respostas e[ENTER]procuro o conhecimento. J\225 ouviste falar de armas[ENTER]\233picas e Pedras Esp\237ritas? "
gameforge.npc_talk._790_npcChat = "O que est\225s a fazer? "
gameforge.npc_talk._800_say = "Provavelmente j\225 sabes que eu investigo coisas[ENTER]ainda desconhecidas. De momento estou a[ENTER]investigar um m\233todo de melhorar ainda mais as[ENTER]armas e o poder das Pedras Esp\237ritas. "
gameforge.npc_talk._80_say = "Gosto de ser oleiro. \201 muito satisfat\243rio moldar[ENTER]o barro com as minhas pr\243prias m\227os e ver como[ENTER]algo \233 criado... Normalmente apenas crio coisas[ENTER]simples. No oriente, nas fronteiras do[ENTER]continente, os m\233todos de produ\231\227o s\227o muito mais[ENTER]desenvolvidos. Uma vez vi por l\225 alguns oleiros a[ENTER]trabalhar e fiquei inspirado. Por vezes, quando[ENTER]tenho tempo, tamb\233m fa\231o algumas experi\234ncias.[ENTER]Mas ainda n\227o descobri qual o truque que eles[ENTER]usam. "
gameforge.npc_talk._810_npcChat = "A investiga\231\227o das armas... "
gameforge.npc_talk._820_say = "Interessante n\227o \233? Queres saber mais sobre o[ENTER]assunto? Ent\227o traz-me a correspondente arma de[ENTER]n\237vel 65 +9. Preciso tamb\233m de um Manual de[ENTER]Duelos e dois Pergaminhos da B\234n\231\227o. Irei tentar[ENTER]fazer uma arma \233pica com eles. "
gameforge.npc_talk._830_say = "No entanto n\227o prometo que ir\225 funcionar. "
gameforge.npc_talk._840_npcChat = "As Pedras Esp\237ritas... "
gameforge.npc_talk._850_say = "As Pedras Esp\237ritas s\227o bastante utilizadas, mas[ENTER]apesar deste seu grande uso muitas das pessoas[ENTER]n\227o sabem qual \233 o seu verdadeiro poder. Mas a[ENTER]minha investiga\231\227o ajudou-me a descobrir[ENTER]bastantes coisas acerca delas. Se me trouxeres[ENTER]uma Pedra Esp\237rita poderei melhor\225-la para ti. "
gameforge.npc_talk._90_npcChat = "\201s muito jovem para alguem da tua idade... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Medalha do Her\243i "
gameforge.olympic_badge._020_say = "Ajuda-me! "
gameforge.olympic_badge._030_say = "Malditos ladr\245es...[ENTER]Assaltaram a minha casa a noite passada![ENTER]Roubaram a minha Medalha do Her\243i. Um dos meus[ENTER]antepassados foi condecorado com essa medalha[ENTER]depois de ter corrido 42.195 km do campo de[ENTER]batalha at\233 ao seu imperador para o informar da[ENTER]vit\243ria na batalha.[ENTER]E agora desapareceu! "
gameforge.olympic_badge._040_say = "Que chatice... ela tem um valor sentimental para[ENTER]mim e para a minha fam\237lia. O que irei fazer[ENTER]agora? "
gameforge.olympic_badge._050_say = "Poder\225s ajudar-me? "
gameforge.olympic_badge._060_npcChat = "Medalha do Her\243i "
gameforge.olympic_badge._070_say = "Finalmente voltaste! Encontraste a Medalha do[ENTER]Her\243i? "
gameforge.olympic_badge._080_say = "Mas porqu\234? Que interesse t\234m os ladr\245es na minha[ENTER]medalha? N\227o tem qualquer valor para estranhos![ENTER]Podes ajudar-me a encontr\225-la? "
gameforge.olympic_badge._090_npcChat = "Encontra a Medalha do Her\243i! "
gameforge.olympic_badge._100_say = "Regressaste de m\227os vazias? Oh n\227o, estou uma[ENTER]pilha de nervos. Se n\227o me consegues ajudar, quem[ENTER]conseguir\225? Por favor, continua a procurar! "
gameforge.olympic_badge._110_say = "Encontraste a minha medalha![ENTER]Mas espera... isto \233 apenas um peda\231o. Que[ENTER]desgra\231a! Eles partiram-na em 5 peda\231os! Por[ENTER]favor traz-me todos os fragmentos! Ent\227o poderei[ENTER]tentar reconstruir a Medalha. "
gameforge.olympic_badge._120_say = "Aqueles criminosos miser\225veis partiram a minha[ENTER]rel\237quia de fam\237lia! Obrigado por encontrares[ENTER]todos os peda\231os. Agora poderei junt\225-los. "
gameforge.olympic_badge._130_say = "Muito obrigado! Devolveste a honra \224 minha[ENTER]fam\237lia. \201 claro que todo este teu esfor\231o n\227o[ENTER]ser\225 em v\227o. Aqui tens a tua recompensa! "
gameforge.olympic_badge._140_say = "Queres mesmo desistir desta miss\227o? Se escolheres[ENTER]'sim' n\227o poder\225s voltar a aceit\225-la mais tarde. "
gameforge.olympic_badge._150_say = "Entendo que n\227o tenhas tempo para isto por agora.[ENTER]Volta quando te der mais jeito. Mas n\227o me fa\231as[ENTER]esperar demasiado tempo! "
gameforge.olympic_badge._160_say = "Infelizmente chegaste demasiado tarde e j\225 n\227o me[ENTER]podes ajudar. Desejo-te o melhor para o futuro! "
gameforge.olympic_badge._170_say = "Ca\231a o monstros que me roubaram. Mas tem cuidado,[ENTER]eles s\227o muito fortes - pelo menos n\237vel 30. Se[ENTER]me devolveres a Medalha do Her\243i, irei dar-te uma[ENTER]generosa recompensa! "
gameforge.olympic_badge._180_say = "Encontra a Medalha do Her\243i e leva-a ao Yu-Hwan. "
gameforge.olympic_badge._190_say = "O Yu-Hwan precisa da tua ajuda. Vai ter com ele![ENTER]Poder\225s encontr\225-lo na segunda vila. "
