gameforge.pony_buy._290_say = "J\225 terminei a Miniatura do Cavalo. Agora podes[ENTER]montar um Cavalo Iniciante e andar mais depressa.[ENTER]A Miniatura do Cavalo custa 100.000 Yang.[ENTER]Queres compr\225-la? "
gameforge.pony_buy._300_select = "N\227o comprar "
