gameforge.skill_reset2._10_npcChat = "Reinicializar habilidades "
gameforge.skill_reset2._110_say = "Como queiras. Se mudares de ideias vem ter comigo[ENTER]novamente. "
gameforge.skill_reset2._120_say = "N\227o tens Yang suficiente. Lamento, mas n\227o te[ENTER]posso ajudar. Afinal de contas tamb\233m preciso de[ENTER]me sustentar. "
gameforge.skill_reset2._130_say = "Este Item d\225-te a possibilidade de esqueceres o[ENTER]teu Treino anterior e iniciares um novo. No[ENTER]entanto ter\225s de estar pelo menos a n\237vel 31 para[ENTER]o usares. Depois disso, ser\225s livre de reescrever[ENTER]o teu destino.[ENTER]Queres deitar por terra as Habilidades que te[ENTER]trouxeram at\233 aqui? "
gameforge.skill_reset2._135_say = "N\227o seguiste nenhum treino e n\227o tens Pontos de[ENTER]Habilidade para reiniciar! "
gameforge.skill_reset2._140_say = "Este item apenas pode ser utilizado a partir de[ENTER]n\237vel 31. "
gameforge.skill_reset2._20_say = "Ainda n\227o come\231aste qualquer treino! Se ainda n\227o[ENTER]gastaste nenhuns Pontos de Habilidade, tamb\233m n\227o[ENTER]os podes reiniciar. Volta quando tiveres feito[ENTER]algum erro no teu treino. Nessa altura poderei[ENTER]ajudar-te. "
gameforge.skill_reset2._30_say = "Receio n\227o te poder ajudar, jovem. J\225 atingiste o[ENTER]n\237vel %s, e infelizmente apenas podes mudar o teu[ENTER]treino at\233 ao n\237vel 30. "
gameforge.skill_reset2._40_say = "N\227o seguiste nenhum treino e n\227o tens Pontos de[ENTER]Habilidade para reiniciar! "
gameforge.skill_reset2._50_say = "Oh, o que se passa? Vejo uma grande tristeza nos[ENTER]teus olhos... Espera, eu posso ajudar-te. Consigo[ENTER]fazer com que as pessoas se esque\231am das suas[ENTER]habilidades e possam aprender outras novas. O que[ENTER]achas? Apenas te ir\225 custar %s Yang. "
gameforge.skill_reset2._60_select = "N\227o reiniciar "
gameforge.skill_reset2._70_say = "Vejam s\243 essa cara triste! N\227o te sentes bem? Se[ENTER]n\227o estiveres feliz com o teu treino eu posso[ENTER]ajudar-te a esquecer tudo num instante. "
gameforge.skill_reset2._80_say = "Isto significa que todos os teus Pontos de[ENTER]Habilidade ser\227o reiniciados para que os possas[ENTER]redistribuir. Infelizmente n\227o te poderei[ENTER]devolver os pontos que ganhaste atrav\233s da[ENTER]leitura de Livros.[ENTER]Queres prosseguir? Queres esquecer tudo e come\231ar[ENTER]do zero? Se sim, irei precisar que me d\234s %s[ENTER]Yang. "
