gameforge.spider_dungeon_3floor_boss = {}
gameforge.spider_dungeon_3floor_boss._100_say = "Queres dizer-me que n\227o te sentes suficientemente[ENTER]confiante para explorares a Caverna das Aranhas?[ENTER]\201s um guerreiro experiente com habilidades[ENTER]t\233cnicas sofisticadas - alguns daqueles seres[ENTER]rastejantes n\227o devem ser problema para ti. Mas[ENTER]sabes que precisas de uma Passagem para entrares[ENTER]na Caverna, certo? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Acesso ao Ninho de Procria\231\227o "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Novo Perigo "
gameforge.spider_dungeon_3floor_boss._120_say = "Criaste uma c\243pia exacta da inscri\231\227o. Leva-a ao[ENTER]Capit\227o. "
gameforge.spider_dungeon_3floor_boss._130_say = "\211ptimo, conseguiste! Mostra-ma ent\227o...[ENTER]Hmm... N\227o conhe\231o estes s\237mbolos, n\227o consigo[ENTER]entender uma \250nica palavra. \201 melhor pedires[ENTER]ajuda ao Uriel. "
gameforge.spider_dungeon_3floor_boss._140_say = "Vai ter com o Uriel e mostra-lhe a inscri\231\227o. Ele[ENTER]certamente conseguir\225 traduzi-la. "
gameforge.spider_dungeon_3floor_boss._150_say = "O Capit\227o pede para eu traduzir esta misteriosa[ENTER]inscri\231\227o? Naturalmente. Gosto de um bom desafio.[ENTER]Passa-ma c\225.[ENTER]Isto \233... Bem, isto \233 terr\237vel! Um momento, vou[ENTER]escrever a tradu\231\227o neste papel.[ENTER]Leva-o ao Capit\227o o mais r\225pido poss\237vel e volta[ENTER]aqui. Se aquilo que aqui est\225 escrito for[ENTER]verdade, estamos todos em grande perigo! Vai,[ENTER]vai! "
gameforge.spider_dungeon_3floor_boss._160_say = "Ainda n\227o foste ter com o Capit\227o?! Por favor![ENTER]Tens de te despachar. N\227o temos tempo a perder.[ENTER]Ele precisa de ler esta carta! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Entrega a carta de Uriel "
gameforge.spider_dungeon_3floor_boss._180_say = "Aquele velho tolo... Ser\225 muito pedir um[ENTER]obrigado?! Muito bem. Ele disse que a informa\231\227o[ENTER]\233 extremamente importante, por isso \233 melhor ir[ENTER]entreg\225-la ao Capit\227o rapidamente. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "A Carta de Uriel "
gameforge.spider_dungeon_3floor_boss._200_say = "Oh n\227o! Se o que aqui est\225 escrito for verdade,[ENTER]ent\227o um perigoso dem\243nio aracn\237deo criou as suas[ENTER]teias no 3\186 andar da Caverna das Aranhas - a[ENTER]Aranha Baronesa. A inscri\231\227o diz que precisas de[ENTER]uma chave especial para poderes aceder a esta[ENTER]caverna secreta. Vai ter com o Uriel e[ENTER]pergunta-lhe o que sabe desta chave. Depois[ENTER]arranja um grupo e assaltem em conjunto este[ENTER]esconderijo da Aranha Baronesa! Toma, tenho mais[ENTER]uma Passagem para ti. "
gameforge.spider_dungeon_3floor_boss._20_say = "Este port\227o apenas pode ser aberto com a Chave do[ENTER]Aracn\237deo. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "A Chave do Aracn\237deo "
gameforge.spider_dungeon_3floor_boss._220_say = "Devia ir ter com o Uriel assim que puder. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, est\225s de volta. Assumo que o Capit\227o te p\244s[ENTER]ao corrente da ordem para destruir a Aranha[ENTER]Baronesa? No entanto a entrada para o Ninho de[ENTER]Procria\231\227o da Baronesa est\225 selada e apenas pode[ENTER]ser aberta com a Chave do Aracn\237deo. A produ\231\227o[ENTER]desta chave \233 muito laboriosa. Mas se me[ENTER]trouxeres um Saco Venenoso de Aranha, Ovos de[ENTER]Aranha, Teia de Aranha, Olhos de Aranha, Pernas[ENTER]de Aranha e, ainda, um Veneno da Rainha Aranha,[ENTER]poderei criar uma para ti. "
gameforge.spider_dungeon_3floor_boss._240_say = "Queres que te crie uma Chave do Aracn\237deo? Para o[ENTER]poder fazer, preciso de um Saco Venenoso de[ENTER]Aranha, Ovos de Aranha, Teia de Aranha, Olhos de[ENTER]Aranha, Pernas de Aranha e, ainda, um Veneno da[ENTER]Rainha Aranha. J\225 encontraste todos estes itens? "
gameforge.spider_dungeon_3floor_boss._250_say = "Fant\225stico! Tens tudo aquilo que preciso para[ENTER]produzir uma Chave do Aracn\237deo. Por favor espera[ENTER]um momento. N\227o devo demorar muito... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ha, terminei! Aqui tens a tua Chave do Aracn\237deo.[ENTER]Ela ir\225 dar-te acesso ao esconderijo da Aranha[ENTER]Baronesa.[ENTER]Desejo muito sucesso a ti e aos teus camaradas na[ENTER]luta contra este monstro de pernas compridas! Mas[ENTER]tens de te despachar - a chave \233 muito inst\225vel.[ENTER]Ao fim de 24 horas ir\225 desintegrar-se de novo nos[ENTER]seus componentes. "
gameforge.spider_dungeon_3floor_boss._270_say = "Oh, oh... Lamento dizer, mas ningu\233m nasce um[ENTER]perito. Tens de compreender que a cria\231\227o desta[ENTER]chave \233 extremamente complexa. Mesmo o mais[ENTER]pequeno erro poder\225 levar a uma tentativa falhada[ENTER]de a criar.[ENTER]Infelizmente, durante o processo de cria\231\227o,[ENTER]perdi todos os componentes que me deste. Da[ENTER]pr\243xima vez irei certamente conseguir cri\225-la! "
gameforge.spider_dungeon_3floor_boss._280_say = "Falta-te algo... Ainda n\227o te posso criar uma[ENTER]Chave do Aracn\237deo. Aqui tens uma lista de tudo o[ENTER]que precisamos: Saco Venenoso de Aranha, Ovos de[ENTER]Aranha, Teia de Aranha, Olhos de Aranha, Pernas[ENTER]de Aranha e, ainda, um Veneno da Rainha Aranha. "
gameforge.spider_dungeon_3floor_boss._300_say = "O l\237der do teu grupo entrou na Caverna. Queres[ENTER]segui-lo? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "Reiniciar miss\227o CA3 "
gameforge.spider_dungeon_3floor_boss._310_say = "Demoraste muito tempo. A chave j\225 se desintegrou.[ENTER]Precisas de produzir uma nova para conseguires[ENTER]acesso a este local. "
gameforge.spider_dungeon_3floor_boss._320_say = "J\225 existe um grupo no Ninho de Procria\231\227o da[ENTER]Baronesa a lan\231ar um ataque \224 Aranha Baronesa. "
gameforge.spider_dungeon_3floor_boss._330_say = "Apenas poder\225s entrar quando o grupo anterior[ENTER]tiver terminado a sua miss\227o. Por favor volta[ENTER]dentro de %s minutos. "
gameforge.spider_dungeon_3floor_boss._340_say = "Tempo de espera at\233 que o port\227o para o Ninho de[ENTER]Procria\231\227o da Baronesa seja reaberto: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s minutos "
gameforge.spider_dungeon_3floor_boss._360_say = "O guerreiro que entrou na Caverna antes de ti[ENTER]apenas se pode mover depois de passarem 10[ENTER]segundos. Por favor aguarda um momento. "
gameforge.spider_dungeon_3floor_boss._370_say = "Gostarias de iniciar uma conquista? Tens 20[ENTER]minutos para a completar. Antes do tempo[ENTER]terminar, ningu\233m poder\225 abandonar o Ninho de[ENTER]Procria\231\227o da Baronesa.[ENTER]Uma nova tentativa de conquista poder\225 ter lugar[ENTER]depois de passada 1 hora. "
gameforge.spider_dungeon_3floor_boss._380_say = "Precisas da Chave do Aracn\237deo para abrires a[ENTER]entrada. "
gameforge.spider_dungeon_3floor_boss._390_say = "Apenas o l\237der do grupo pode usar a Chave do[ENTER]Aracn\237deo. "
gameforge.spider_dungeon_3floor_boss._400_say = "A Aranha Baronesa foi derrotada! Dentro de 3[ENTER]minutos todos os guerreiros ser\227o transportados[ENTER]para fora da Caverna. "
gameforge.spider_dungeon_3floor_boss._40_say = "Antes da produ\231\227o da Chave "
gameforge.spider_dungeon_3floor_boss._410_say = "N\227o funcionou. Tenta de novo! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Aten\231\227o: a Aranha Baronesa est\225 a enfurecer-se![ENTER]Os seus ataques ser\227o mais fortes, mas tamb\233m[ENTER]baixou as suas defesas. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Caverna das Aranhas 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, ainda bem que aqui est\225s. Tenho informa\231\245es[ENTER]importantes para ti: uma patrulha de batedores[ENTER]descobriu um terceiro andar na Caverna das[ENTER]Aranhas. Suspeitamos que l\225 existam algumas[ENTER]aranhas extremamente monstruosas e trai\231oeiras.[ENTER]Al\233m disso, os meus homens encontraram uma velha[ENTER]l\225pide com uma inscri\231\227o, mas n\227o conseguiram[ENTER]fazer uma c\243pia do que estava escrito.[ENTER]Vai \224 procura desta l\225pide e traz-me uma c\243pia[ENTER]desta inscri\231\227o. Toma esta Passagem, que te dar\225[ENTER]acesso sem problemas \224 Caverna das Aranhas. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "A Inscri\231\227o "
gameforge.spider_dungeon_3floor_boss._80_say = "No 3\186 andar da Caverna das Aranhas ir\225s encontrar[ENTER]uma velha l\225pide com uma inscri\231\227o gravada. Faz[ENTER]uma c\243pia desta inscri\231\227o e entrega-a ao Capit\227o. "
gameforge.spider_dungeon_3floor_boss._90_say = "Perfeito, encontraste a velha l\225pide e fizeste[ENTER]uma c\243pia da inscri\231\227o nela gravada! Regressa ao[ENTER]Capit\227o e mostra-lhe a inscri\231\227o. "
gameforge.subquest_01 = {}
gameforge.subquest_01._100_sayTitle = "Loja Geral: "
gameforge.subquest_01._10_targetVid = "Obter Garrafa Vazia "
gameforge.subquest_01._110_say = "Muito bem. Podes obter Garrafas Vazias do Yonah,[ENTER]o Oleiro.[ENTER]Muito obrigado. "
gameforge.subquest_01._120_targetVid = "Encontra Yonah, o Oleiro "
gameforge.subquest_01._130_sayReward = "A Negociadora da Loja Geral precisa de uma[ENTER]Garrafa Vazia do Yonah para a sua Po\231\227o Vermelha. "
gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "Oh meu Deus! Raios! N\227o consigo parar de tossir![ENTER]Como \233 suposto conseguir trabalhar assim?[ENTER]A dona da Loja Geral enviou-te? Tenho algumas[ENTER]Garrafas Vazias, mas n\227o te posso dar de nenhuma[ENTER]de gra\231a. "
gameforge.subquest_01._160_say = "Eu sou asm\225tico. Disseram-me que as Sementes de[ENTER]P\234ssego s\227o um bom rem\233dio para o asma. Se me[ENTER]arranjares uma Semente de P\234ssego eu irei dar-te[ENTER]uma Garrafa Vazia. Poder\225s apanh\225-las nos Javalis[ENTER]Selvagens no exterior da vila. Assim que os[ENTER]agricultores plantam as Sementes de P\234ssego, os[ENTER]Javalis Selvagens escavam e comem-nas. "
gameforge.subquest_01._170_sendLetter = "Apanha a Semente de P\234ssego "
gameforge.subquest_01._180_sayReward = "A Negociadora da Loja Geral precisa de uma[ENTER]Garrafa Vazia do Yonah para a sua Po\231\227o Vermelha.[ENTER]O Yonah, que tem asma, ir\225 dar-te uma Garrafa[ENTER]Vazia se lhe levares algumas Sementes de P\234ssego.[ENTER]Podes obt\234-las dos Javalis Selvagens. "
gameforge.subquest_01._190_npcChat = "Para obter Sementes de P\234ssego... "
gameforge.subquest_01._200_say = "Podes obter as Sementes de P\234ssego dos Javalis[ENTER]Selvagens nas redondezas da vila. Assim que os[ENTER]agricultores semeiam as Sementes de P\234ssego, os[ENTER]Javalis Selvagens escavam-nas e comem-nas.[ENTER]Cough, cough.[ENTER]Obrigado desde j\225. "
gameforge.subquest_01._20_npcChat = "Obter Garrafa Vazia "
gameforge.subquest_01._210_sendLetter = "Regressa a Yonah "
gameforge.subquest_01._220_sayTitle = "Regressa ao Yonah. "
gameforge.subquest_01._230_sayReward = "Encontraste uma Semente de P\234ssego. Entrega-a ao[ENTER]Yonah. "
gameforge.subquest_01._240_say = "Oh! Apanhaste-a! "
gameforge.subquest_01._250_say = "Obrigado. Agora posso acalmar o meu asma e voltar[ENTER]ao trabalho. "
gameforge.subquest_01._260_say = "Aqui tens uma Garrafa Vazia. Leva-a \224 Negociadora[ENTER]da Loja Geral. "
gameforge.subquest_01._270_sendLetter = "Entrega a Garrafa Vazia "
gameforge.subquest_01._280_sayReward = "A Negociadora da Loja Geral precisa de uma[ENTER]Garrafa Vazia do Yonah. Leva-a at\233 ela. "
gameforge.subquest_01._290_sayTitle = "Loja Geral: "
gameforge.subquest_01._300_say = "Obrigado. Espero que n\227o te tenha dado muito[ENTER]trabalho. Toma isto pelo teu esfor\231o. Obrigado,[ENTER]mais uma vez! "
gameforge.subquest_01._30_say = "Desculpa, se n\227o estiveres ocupado podes fazer-me[ENTER]um favor? Preciso de uma Garrafa Vazia para a[ENTER]minha po\231\227o vermelha. "
gameforge.subquest_01._310_sayReward = "Recebeste 1.500 Pontos de Experi\234ncia.[ENTER]Recebeste 1.000 Yang. "
gameforge.subquest_01._320_say = "Ainda n\227o tens uma Garrafa Vazia? "
gameforge.subquest_01._330_say = "Queres ca\231ar Javalis Selvagens de novo para[ENTER]conseguir outra Garrafa Vazia ou queres desistir[ENTER]da Miss\227o? "
gameforge.subquest_01._340_select = "Sim, vou ca\231ar os Javalis. "
gameforge.subquest_01._350_select = "N\227o, quero desistir. "
gameforge.subquest_01._360_say = "Queres mesmo desistir? "
gameforge.subquest_01._370_say = "Obrigado por me ajudares. "
gameforge.subquest_01._380_say = "\201 demasiado dif\237cil para mim. Desculpa. "
gameforge.subquest_01._40_say = "Estou ocupada com a minha loja e n\227o posso ir[ENTER]busc\225-la eu mesma. Se me arranjares a Garrafa[ENTER]Vazia irei recompensar-te. "
gameforge.subquest_01._50_select = "Aceitar "
gameforge.subquest_01._60_select = "Recusar "
gameforge.subquest_01._70_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_01._80_say = "Obrigado por me ajudares. Regressa quando tiveres[ENTER]tempo. "
gameforge.subquest_01._90_say = "Tem um bom dia. E volta brevemente. "
