gameforge.subquest_02._100_sayTitle = "Vendedor de Armaduras: "
gameforge.subquest_02._10_targetVid = "O Jantar "
gameforge.subquest_02._110_say = "Toda esta conversa sobre comida est\225 a deixar-me[ENTER]com fome. Apetece-me mesmo um Guisado de Veado,[ENTER]Urso, Couve e Dois Ovos. "
gameforge.subquest_02._120_say = "O meu pai disse-te o que ele gostaria de comer? "
gameforge.subquest_02._121_select = "Guisado de porco, urso, couve e um ovo. "
gameforge.subquest_02._122_select = "Guisado de veado, urso, couve e um ovo. "
gameforge.subquest_02._123_select = "Guisado de veado, urso, couve e dois ovos. "
gameforge.subquest_02._124_select = "Esqueci-me do que era... "
gameforge.subquest_02._130_say = "Obrigado por conseguires a informa\231\227o t\227o[ENTER]rapidamente. Aqui est\225 a tua recompensa. "
gameforge.subquest_02._140_sayReward = "Recebeste 1.000 Pontos de Experi\234ncia.[ENTER]Recebeste 1.500 Yang. "
gameforge.subquest_02._150_say = "Negociadora da Loja Geral:[ENTER]N\227o estou surpreendida, ele tem sempre pedidos[ENTER]t\227o estranhos. Podes perguntar-lhe de novo, por[ENTER]favor? "
gameforge.subquest_02._160_say = "Negociadora da Loja Geral:[ENTER]Ele disse isso? Tens a certeza? Isso n\227o parece[ENTER]nada do meu pai... Podes perguntar-lhe de novo,[ENTER]por favor? Acho que ele n\227o deve querer esse[ENTER]prato. "
gameforge.subquest_02._20_say = "Sabes que o Vendedor de Armaduras \233 o meu pai,[ENTER]certo? Quero preparar o jantar para ele, mas n\227o[ENTER]sei o que lhe apetece comer. Podes perguntar-lhe[ENTER]o que ele pretende para o jantar?[ENTER]Irei recompensar-te pelo teu trabalho. "
gameforge.subquest_02._30_sayReward = "A Negociadora da Loja Geral gostaria de saber[ENTER]aquilo que o seu pai, o Vendedor de Armaduras,[ENTER]gostaria de comer ao jantar. "
gameforge.subquest_02._40_sayReward = "Dirige-te ao Vendedor de Armaduras e pergunta-lhe. "
gameforge.subquest_02._50_say = "Bem-vindo![ENTER]Eu produzo armaduras que te podem proteger de[ENTER]ataques de punhais e espadas. "
gameforge.subquest_02._60_say = "Oh, a minha filha enviou-te? Ela quer saber o que[ENTER]precisa de cozinhar hoje? Deixa-me pensar.[ENTER]Mmmhhh, gostaria de comer um Guisado de Veado,[ENTER]Urso, Couve e Dois Ovos. \201 mesmo isso que me[ENTER]apetece! "
gameforge.subquest_02._70_targetVid = "O Jantar "
gameforge.subquest_02._80_sayReward = "A Negociadora da Loja Geral gostaria de saber[ENTER]aquilo que o seu pai, o Vendedor de Armaduras,[ENTER]gostaria de comer ao jantar. "
gameforge.subquest_02._90_sayReward = "Regressa a ela e diz-lhe o que descobriste. "
