gameforge.subquest_03._100_sayTitle = "Regressa ao Baek-Go. "
gameforge.subquest_03._10_targetVid = "Ingrediente para o Rem\233dio "
gameforge.subquest_03._110_sayReward = "Encontraste o F\237gado de Lobo. Leva-o ao Baek-Go. "
gameforge.subquest_03._120_say = "Obrigado! Devemos-te uma! "
gameforge.subquest_03._130_say = "Os pacientes ir\227o elogiar-te. "
gameforge.subquest_03._140_say = "Toma isto como recompensa. De certeza que ir\225s[ENTER]precisar disso um dia. "
gameforge.subquest_03._150_sayReward = "Recebeste 3.000 Pontos de Experi\234ncia.[ENTER]Recebeste 5.000 Yang.[ENTER]Recebeste um P\234lo de Lobo. "
gameforge.subquest_03._20_say = "Podes ajudar-me? Desde que as Pedras Metin[ENTER]come\231aram a cair do c\233u uma doen\231a misteriosa[ENTER]come\231ou a espalhar-se. Muitos m\233dicos trabalham[ENTER]num rem\233dio dif\237cil, mas falta um ingrediente. No[ENTER]exterior da vila existem muitos animais selvagens[ENTER]e, por isso, n\227o podemos andar livremente por l\225. "
gameforge.subquest_03._30_say = "Podes arranjar-me o ingrediente para o rem\233dio?[ENTER]Pe\231o-te isto porque \233s um aventureiro.[ENTER]Preciso de um F\237gado de Lobo de um Lobo Azul. "
gameforge.subquest_03._40_say = "Por favor traz-me um F\237gado de Lobo de um Lobo[ENTER]Azul. Informa-me assim que o tiveres. "
gameforge.subquest_03._50_sayReward = "Desde que as Pedras Metin come\231aram a cair do c\233u[ENTER]uma doen\231a misteriosa come\231ou a espalhar-se. O[ENTER]Baek-Go precisa de um F\237gado de Lobo de um Lobo[ENTER]Azul para produzir um rem\233dio. Recolhe um F\237gado[ENTER]de Lobo para ele. "
gameforge.subquest_03._60_npcChat = "Como apanho o F\237gado de Lobo? "
gameforge.subquest_03._70_say = "Existe apenas uma forma de obteres F\237gado de[ENTER]Lobo: Tens de ca\231ar Lobos Azuis. "
gameforge.subquest_03._80_say = "Tenho pena dos Lobos, mas precisamos dos F\237gados[ENTER]para o Rem\233dio. Obrigado desde j\225. "
gameforge.subquest_03._90_sendLetter = "Regressa a Baek-Go "
