gameforge.subquest_04._100_say = "Tens um longo caminho pela frente. Toma conta de[ENTER]ti! E n\227o te esque\231as: Tens de utilizar o portal[ENTER]no ponto azul. "
gameforge.subquest_04._10_targetVid = "Como est\225 o Deokbae? "
gameforge.subquest_04._110_sayReward = "Vai e entrega a carta do Ferreiro a Deokbae, o[ENTER]Lenhador. Poder\225s encontr\225-lo na segunda Vila, \224[ENTER]qual poder\225s aceder apenas atrav\233s do portal. "
gameforge.subquest_04._120_sendLetter = "Uma carta do Ferreiro. "
gameforge.subquest_04._130_targetVid = "Encontra o Deokbae. "
gameforge.subquest_04._140_npcChat = "Uma carta do Ferreiro. "
gameforge.subquest_04._150_sayTitle = "Deokbae: "
gameforge.subquest_04._160_say = "Bem-vindo. Aqui tenho alguns bons machados.[ENTER]Queres comprar um? N\227o precisas de um machado?[ENTER]Ent\227o porque est\225s aqui?[ENTER]Ah, uma carta do Ferreiro. Obrigado. Sou um[ENTER]Lenhador, mas tamb\233m vendo Picaretas e outras[ENTER]ferramentas. Por vezes encomendo-lhe coisas. Foi[ENTER]assim que nos torn\225mos bons amigos. "
gameforge.subquest_04._170_say = "Devia ir mesmo tomar uma bebida ao Bar do[ENTER]Seo-Pyung. Obrigado por me trazeres a carta.[ENTER]Envia os meus cumprimentos ao Ferreiro. "
gameforge.subquest_04._180_say = "Uma carta do Ferreiro? Bolas, j\225 l\225 vai algum[ENTER]tempo... Onde est\225 ela? N\227o a perdeste no caminho[ENTER]pois n\227o? "
gameforge.subquest_04._190_select = "Aqui est\225 "
gameforge.subquest_04._200_select = "Oh! N\227o a tenho. "
gameforge.subquest_04._20_say = "Ol\225, aventureiro! Gostaria de te pedir um favor.[ENTER]Conheces um tipo chamado Deokbae? \201 um lenhador e[ENTER]um bom amigo meu. Por vezes \233 um pouco[ENTER]aborrecido, mas ele \233 um dos \250ltimos lenhadores[ENTER]que ainda trabalha arduamente. "
gameforge.subquest_04._210_say = "Desistir da Miss\227o? "
gameforge.subquest_04._220_say = "Que simp\225tico. Volta brevemente. "
gameforge.subquest_04._230_say = "Perdeste-a? Desaparece da minha vista! "
gameforge.subquest_04._240_say = "Regressa ao Ferreiro para a arranjares. E desta[ENTER]vez n\227o a percas! "
gameforge.subquest_04._250_sayReward = "Regressa ao Ferreiro para receberes a tua[ENTER]recompensa. "
gameforge.subquest_04._260_targetVid = "Regressa ao Ferreiro "
gameforge.subquest_04._270_npcChat = "Entreguei a Carta. "
gameforge.subquest_04._280_say = "Ent\227o, como est\225 o Deokbae? Hehe! Sempre o mesmo.[ENTER]Obrigado. Aqui est\225 a tua recompensa. N\227o \233 muito[ENTER]mas de certeza que precisar\225s disso um dia. Mais[ENTER]uma vez, obrigado. "
gameforge.subquest_04._290_sayReward = "Recebeste 4.000 Pontos de Experi\234ncia.[ENTER]Recebeste 3.000 Yang. "
gameforge.subquest_04._30_say = "N\227o o vejo h\225 algum tempo e escrevi-lhe uma carta[ENTER]a perguntar como est\225. Gostaria que lhe[ENTER]entregasses a carta por mim. Hoje em dia existem[ENTER]por a\237 muitos perigos.[ENTER]Tem cuidado. E n\227o amachuques a carta! "
gameforge.subquest_04._40_say = "Oh, n\227o sabes como chegar \224 pr\243xima Vila? Clica[ENTER]no M para veres o mapa. Um ponto azul estar\225[ENTER]representado nele. Esse ponto indica a[ENTER]localiza\231\227o do portal para a \225rea adjacente. A[ENTER]segunda Vila encontra-se nessa \225rea. "
gameforge.subquest_04._50_select = "Irei faz\234-lo. "
gameforge.subquest_04._60_select = "N\227o, obrigado. "
gameforge.subquest_04._70_say = "Queres desistir desta miss\227o? "
gameforge.subquest_04._80_say = "Volta brevemente. "
gameforge.subquest_04._90_say = "Bom, \233 uma pena. "
