gameforge.subquest_05._300_say = "Tens a certeza que esta \233 a ordem correcta? "
gameforge.subquest_05._30_sayTitle = "Sr. Soon: "
gameforge.subquest_05._310_select = "Sim, tenho. "
gameforge.subquest_05._320_select = "N\227o, nem por isso. "
gameforge.subquest_05._330_say = "\201 bom ouvir isso. Volta sempre. "
gameforge.subquest_05._340_say = "Era demasiado bom... Sai daqui... "
gameforge.subquest_05._350_say = "\211ptimo! Isto \233 \243ptimo! Muito obrigado! "
gameforge.subquest_05._40_say = "Aha... Hum... N\227o, isto...[ENTER]Yikes, de onde apareceste? Como te atreves a[ENTER]perturbar-me enquanto leio?! Oh meu Deus,[ENTER]desculpa, n\227o queria gritar contigo. Por vezes[ENTER]enquanto leio encontro algo que simplesmente n\227o[ENTER]entendo e isso \233 muito frustrante.[ENTER]Podes ajudar-me com algo? "
gameforge.subquest_05._50_say = "Estou a examinar os Leques usados pelos Xam\227s.[ENTER]Tenho tido problemas a descobrir quais s\227o os[ENTER]melhores. \201 imposs\237vel eu test\225-los a todos.[ENTER]Uriel, o s\225bio, certamente saber\225 tudo sobre os[ENTER]Leques. Podes perguntar-lhe por mim? Estou[ENTER]interessado nos seguintes Leques: Aqu\225tico, Ave[ENTER]do Para\237so, Triplo e Asa de Grou. "
gameforge.subquest_05._60_say = "Preciso que ele ordene os leques de acordo com o[ENTER]seu Valor de Ataque. "
gameforge.subquest_05._70_select = "Aceitar "
gameforge.subquest_05._80_select = "Recusar "
gameforge.subquest_05._90_say = "Queres desistir desta miss\227o? "
gameforge.subquest_06 = {}
gameforge.subquest_06._100_say = "Vai-te embora, j\225! Gatuno in\250til... "
gameforge.subquest_06._10_targetVid = "Encomenda de Armadura "
gameforge.subquest_06._110_say = "Obrigado! Dirige-te ao Ferreiro e pergunta-lhe[ENTER]como vai a armadura. "
gameforge.subquest_06._120_sayReward = "Dirige-te ao Ferreiro e pergunta-lhe como vai a[ENTER]encomenda de Armadura que o Vendedor de Armaduras[ENTER]fez. "
gameforge.subquest_06._130_npcChat = "Armadura para o Vendedor de Armaduras "
gameforge.subquest_06._140_say = "O que \233 agora? Porque me est\225s a incomodar? Oh, o[ENTER]Vendedor de Armaduras enviou-te? Esse velho \233[ENTER]muito impaciente. N\227o \233 que n\227o o queira fazer...[ENTER]Simplesmente n\227o tenho os materiais necess\225rios.[ENTER]Podes arranj\225-los para mim?[ENTER]Para produzir a Armadura preciso de Ferro, Couro[ENTER]e Carv\227o. Podes obter o Ferro do Uriel, o Couro[ENTER]do Octavio e o Carv\227o do Yonah. "
gameforge.subquest_06._150_select = "Vou arranjar-te os materiais "
gameforge.subquest_06._160_select = "N\227o, para j\225 n\227o. "
gameforge.subquest_06._170_say = "Queres mesmo desistir desta miss\227o? "
gameforge.subquest_06._180_say = "Tamb\233m o podes fazer mais tarde. Mas n\227o demores[ENTER]muito, esta miss\227o \233 urgente! "
gameforge.subquest_06._190_say = "Bom, suponho que tenho eu mesmo de arranjar essas[ENTER]coisas. Toma conta de ti. "
gameforge.subquest_06._200_say = "Ent\227o vai l\225 para que eu possa regressar ao meu[ENTER]trabalho em paz... "
gameforge.subquest_06._20_npcChat = "Encomenda de Armadura "
gameforge.subquest_06._210_sendLetter = "Obter materiais "
gameforge.subquest_06._220_sayReward = "Arranja os materiais para o Ferreiro. "
gameforge.subquest_06._221_say = "Ferro - Podes obt\234-lo do Uriel. "
gameforge.subquest_06._222_say = "Couro - Podes obt\234-lo do Oct\225vio. "
gameforge.subquest_06._223_say = "Carv\227o - Podes obt\234-lo do Yonah. "
gameforge.subquest_06._224_sayReward = "O Uriel deu-te o Ferro. "
gameforge.subquest_06._225_sayReward = "O Oct\225vio deu-te o Couro. "
gameforge.subquest_06._226_sayReward = "O Yonah deu-te o Carv\227o. "
gameforge.subquest_06._230_targetVid = "Dirige-te ao Oct\225vio "
gameforge.subquest_06._240_targetVid = "Dirige-te ao Uriel. "
gameforge.subquest_06._250_targetVid = "Dirige-te ao Yonah. "
gameforge.subquest_06._260_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._270_say = "Muito obrigado por me trazeres de volta o meu[ENTER]Livro. Agora poderei continuar a minha[ENTER]investiga\231\227o.[ENTER]Toma, aqui tens algum Ferro. Usa-o bem. "
gameforge.subquest_06._280_say = "Precisas de Ferro? Posso dar-te algum. Mas[ENTER]primeiro tenho de te pedir um favor: recentemente[ENTER]perdi um livro enquanto era perseguido por uma[ENTER]matilha de C\227es Selvagens. Traz-me esse livro de[ENTER]volta e irei dar-te algum Ferro. "
gameforge.subquest_06._285_say = "O Uriel ir\225 dar-te Ferro se lhe devolveres o[ENTER]livro que est\225 na posse dos C\227es Selvagens. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._300_say = "Mais Ferro? J\225 te dei algum. Agora n\227o tenho mais. "
gameforge.subquest_06._30_say = "Podes ajudar-me? Obrigado pelo favor que fizeste[ENTER]antes \224 minha filha. No entanto agora \233 a minha[ENTER]vez de te pedir um favor. Pedi ao Ferreiro da[ENTER]vila para produzir algumas armaduras, mas ainda[ENTER]n\227o recebi not\237cias dele. Podes descobrir qual o[ENTER]estado da encomenda? "
gameforge.subquest_06._310_npcChat = "Preciso de Couro. "
gameforge.subquest_06._320_sayTitle = "Oct\225vio: "
gameforge.subquest_06._330_say = "Obrigado pelo Fel! Agora finalmente posso voltar[ENTER]a cozinhar as minhas deliciosas refei\231\245es. Mmm...[ENTER]Toma este Couro como recompensa. "
gameforge.subquest_06._340_say = "Posso dar-te algum Couro.[ENTER]No entanto, nada da vida \233 gratuito.[ENTER]E que tal uma troca? Irei dar-te o Couro se me[ENTER]conseguires arranjar um Fel.[ENTER]Uso Fel nas minhas receitas com frequ\234ncia.[ENTER]N\227o me importo se n\227o tiveres interesse. "
gameforge.subquest_06._345_say = "O Oct\225vio ir\225 dar-te Couro se lhe trouxeres um[ENTER]Fel. "
gameforge.subquest_06._350_npcChat = "Preciso de Couro. "
gameforge.subquest_06._360_say = "J\225 te dei algum Couro. Perdeste-o? N\227o tenho mais. "
gameforge.subquest_06._370_npcChat = "Preciso de Carv\227o "
gameforge.subquest_06._380_say = "Obrigado pelo Barro. Tu co\231as as minhas costas e[ENTER]eu co\231o as tuas: Aqui tens o teu Carv\227o. Espero[ENTER]ver-te em breve! "
gameforge.subquest_06._390_say = "Que se passa? Est\225s aqui para obteres Carv\227o?[ENTER]Tenho montes de Carv\227o, mas n\227o to posso dar sem[ENTER]nada em troca. Ter\225s de fazer algo por mim[ENTER]primeiro. "
gameforge.subquest_06._395_say = "Yonah ir\225 dar-te Carv\227o se lhe deres Barro. Podes[ENTER]obt\234-lo ca\231ando Javalis Selvagens Rubros. "
gameforge.subquest_06._400_say = "Estou sem Barro para fazer lou\231as. Se me[ENTER]trouxeres um pouco de Barro irei dar-te algum[ENTER]Carv\227o. Seria bom que matasses alguns Javalis[ENTER]Selvagens Rubros, pois caso acredites ou n\227o eles[ENTER]comem Barro. Obrigado desde j\225! "
gameforge.subquest_06._40_select = "Sim, vou faz\234-lo. "
gameforge.subquest_06._410_npcChat = "Preciso de Carv\227o "
gameforge.subquest_06._420_say = "O qu\234? J\225 te dei o Carv\227o! Est\225s a tentar[ENTER]enganar-me? "
gameforge.subquest_06._430_npcChat = "Tenho todos os materiais. "
gameforge.subquest_06._440_say = "Parece que n\227o tens Ferro. Dirige-te ao Uriel... "
gameforge.subquest_06._450_say = "Parece que n\227o tens Couro. Vai ter com o Oct\225vio. "
gameforge.subquest_06._460_say = "N\227o tens Carv\227o. Hmm, falta Carv\227o? Obt\233m algum[ENTER]do Yonah. "
gameforge.subquest_06._470_makequestbutton = "Tenho todos os materiais! "
gameforge.subquest_06._480_qSetTitle = "Materiais para o Ferreiro "
gameforge.subquest_06._490_targetVid = "Dirige-te ao Ferreiro "
gameforge.subquest_06._500_sayTitle = "A Armadura Encomendada "
gameforge.subquest_06._50_select = "N\227o tenho tempo para isto. "
gameforge.subquest_06._510_sayReward = "Tenho todos os materiais necess\225rios. Vamos[ENTER]regressar ao Ferreiro. "
gameforge.subquest_06._520_npcChat = "Tenho os materiais que me pediste. "
gameforge.subquest_06._530_say = "J\225 tens todos os materiais? Estou impressionado![ENTER]Obrigado. Agora posso entregar a encomenda ao[ENTER]Vendedor de Armaduras.[ENTER]Vai contar-lhe a boa not\237cia! "
gameforge.subquest_06._540_sayReward = "Informa o Vendedor de Armaduras que o seu pedido[ENTER]estar\225 terminado brevemente. "
gameforge.subquest_06._550_targetVid = "Regressa ao Vendedor de Armaduras "
gameforge.subquest_06._560_npcChat = "O Ferriero ir\225 entregar-ta brevemente! "
gameforge.subquest_06._570_say = "Oh, ent\227o ele ir\225 termin\225-la em breve? Obrigado[ENTER]por tratares deste assunto.[ENTER]Toma isto como recompensa. "
gameforge.subquest_06._580_sayReward = "Recebeste 26.000 Pontos de Experi\234ncia.[ENTER]Recebeste 15.000 Yang.[ENTER]Recebeste um Nariz de Porco. "
gameforge.subquest_06._590_sayReward = "Recebeste uma Armadura Tigre+3. "
gameforge.subquest_06._600_sayReward = "Recebeste um Quimono Carmim+3. "
gameforge.subquest_06._60_say = "Queres desistir de vez desta miss\227o? "
gameforge.subquest_06._610_sayReward = "Recebeste uma Armadura da Desgra\231a+3. "
gameforge.subquest_06._620_sayReward = "Recebeste um Robe Cor-de-Rosa+3. "
gameforge.subquest_06._70_select = "Aceitar "
gameforge.subquest_06._80_select = "Recusar "
gameforge.subquest_06._90_say = "Ir\225s faz\234-lo mais tarde? Ent\227o regressa[ENTER]brevemente, esta miss\227o \233 urgente! "
gameforge.subquest_07 = {}
gameforge.subquest_07._100_say = "Espera um segundo. Quero certificar-me que este \233[ENTER]o Livro certo... Hum, sim, \233 realmente[ENTER]fant\225stico. Irei definitivamente cozinhar estes[ENTER]pratos! Obrigado! "
gameforge.subquest_07._10_targetVid = "O melhor Livro de Culin\225ria "
gameforge.subquest_07._110_say = "Hum... Mas eu preciso... Espera, amigo! Posso[ENTER]pedir-te outro favor? Tenho quase todos os[ENTER]ingredientes para este fant\225stico prato, mas[ENTER]falta-me Intestino de Lobo. N\227o \233 f\225cil obter um[ENTER]e \233 melhor quando comido fresco. Por favor[ENTER]arranja-me um! "
gameforge.subquest_07._120_sayReward = "Arranja um Intestino de Lobo para o Oct\225vio.[ENTER]Podes obt\234-lo nos Lobos Cinza. "
gameforge.subquest_07._130_npcChat = "Tenho um Intestino de Lobo. "
gameforge.subquest_07._140_say = "Gra\231as a ti finalmente poderei cozinhar esta rara[ENTER]refei\231\227o. Isto ser\225 um festim. Estou realmente[ENTER]grato pela tua ajuda.[ENTER]Por favor aceita esta modesta recompensa. "
gameforge.subquest_07._150_sayReward = "Recebeste 12.000 Pontos de Experi\234ncia.[ENTER]Recebeste 5.000 Yang.[ENTER]Recebeste uma Garra de Lobo. "
gameforge.subquest_07._160_say = "Preciso de um Intestino de Lobo. Por favor[ENTER]arranja-mo. "
gameforge.subquest_07._20_npcChat = "O melhor Livro de Culin\225ria "
gameforge.subquest_07._30_say = "Hum... Por acaso n\227o conheces o Sr. Soon? Ele \233 o[ENTER]rato de biblioteca que passa a vida inteira a[ENTER]ler.[ENTER]Ouvi dizer que o Sr. Soon tem um excelente Livro[ENTER]de Culin\225ria. Por favor descobre-me se \233 verdade.[ENTER]Disseram-me que esse Livro est\225 repleto de raras[ENTER]e ex\243ticas receitas que eu gostaria de aprender. "
gameforge.subquest_07._40_targetVid = "Pergunta ao Sr. Soon "
gameforge.subquest_07._50_sayReward = "Pergunta ao Sr. Soon se ele n\227o t\234m o Livro de[ENTER]Culin\225ria. "
gameforge.subquest_07._60_npcChat = "Tens algum Livro de Culin\225ria especial? "
gameforge.subquest_07._70_say = "Bla, bla... Oh! Tu de novo! O que queres?[ENTER]Sim, tenho um Livro de Culin\225ria de receitas[ENTER]ex\243ticas. Leva-o contigo se quiseres, n\227o preciso[ENTER]dele. Mas por favor n\227o me interrompas enquanto[ENTER]leio! "
gameforge.subquest_07._80_targetVid = "O Sr. Soon deu-te o Livro de Culin\225ria especial.[ENTER]Entrega-o ao Octavio. "
gameforge.subquest_07._90_npcChat = "Aqui est\225 o Livro de Culin\225ria! "
gameforge.subquest_08 = {}
gameforge.subquest_08._100_sayReward = "Dirige-te ao Vendedor de Armas e pergunta-lhe[ENTER]onde podes comprar Bolos de Arroz. "
gameforge.subquest_08._10_targetVid = "Bolo de Arroz "
gameforge.subquest_08._110_npcChat = "O que sabes sobre bolos de arroz? "
gameforge.subquest_08._120_sayTitle = "Vendedor de Armas: "
gameforge.subquest_08._130_say = "O qu\234? Bolo de Arroz? Isso \233 uma nova arma?! Sim,[ENTER]bom ent\227o...[ENTER]Oh, est\225s a falar de Bolos de Arroz comest\237veis.[ENTER]Porque n\227o disseste isso logo? \201 melhor ires ter[ENTER]com o Oct\225vio. Ele sabe tudo o que h\225 a saber[ENTER]sobre comida. "
gameforge.subquest_08._140_makequestbutton = "Bolo de Arroz "
gameforge.subquest_08._150_sayReward = "Dirige-te ao Octavio e pergunta-lhe o que sabe[ENTER]sobre Bolos de Arroz. "
gameforge.subquest_08._160_say = "Hmm, Bolos de Arroz? Aqueles com cerejas e a\231\250car[ENTER]por cima? Sim, j\225 comi alguns. Podes obt\234-los da[ENTER]vendedora de Bolos de Arroz que est\225 na vila[ENTER]vizinha. Penso que ela se chama Yu-Rang. "
gameforge.subquest_08._170_select = "N\227o tenho tempo para isto. "
gameforge.subquest_08._180_say = "Tens um longo caminho pela frente. Adeus. "
gameforge.subquest_08._190_say = "Bom, tu \233 que ficas a perder. Adeus! "
gameforge.subquest_08._200_say = "Vais ver que vai valer a pena. Tem uma boa viagem! "
gameforge.subquest_08._20_say = "Desculpa, podes ajudar-me por favor? O meu beb\233[ENTER]chora sem parar e j\225 n\227o sei o que fazer para o[ENTER]acalmar. O meu beb\233 adora bolos de arroz e acho[ENTER]que isso poderia ajudar. Penso que o Vendedor de[ENTER]Armas saiba onde se podem arranjar. Podes[ENTER]perguntar-lhe por mim? "
gameforge.subquest_08._210_makequestbutton = "Encontra a Yu-Rang "
gameforge.subquest_08._220_targetVid = "Bolo de Arroz "
gameforge.subquest_08._230_sayReward = "Dirige-te \224 vendedora de Bolos de Arroz, Yu-Rang.[ENTER]Poder\225s encontr\225-la na segunda Vila. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Posso ajudar-te? Oh, Bolos de Arroz! \201 claro que[ENTER]te posso arranjar alguns! Mas... Podes fazer-me[ENTER]um favor primeiro? Um rapaz chamado Taurean vem[ENTER]aqui muitas vezes para me chatear, apesar de eu[ENTER]nunca lhe ter feito nada. Se castigares o Taurean[ENTER]por mim, irei dar-te alguns Bolos de Arroz, ok? "
gameforge.subquest_08._260_makequestbutton = "Encontra o Taurean "
gameforge.subquest_08._270_sayReward = "A Yu-Rang est\225 sempre a ser chateada pelo[ENTER]Taurean. Castiga-o e ela ir\225 dar-te um Bolo de[ENTER]Arroz. "
gameforge.subquest_08._280_npcChat = "Porque chateias a Yu-Rang? "
gameforge.subquest_08._290_say = "O qu\234, quem \233 que ando a chatear? Oh, est\225s a[ENTER]referir-te \224 rapariga que vende Bolos de Arroz?[ENTER]N\227o, eu n\227o queria chate\225-la! Eu apenas estava[ENTER]aborrecido e ela pareceu-me simp\225tica e n\227o ter[ENTER]muito para fazer. Por isso fui ter com ela[ENTER]algumas vezes para brincar, mas ela ficou[ENTER]zangada... As raparigas s\227o estranhas. Suponho[ENTER]que n\227o a irei visitar mais vez nenhuma, ent\227o! "
gameforge.subquest_08._300_makequestbutton = "Regressa \224 Yu-Rang "
gameforge.subquest_08._30_select = "Aceitar "
gameforge.subquest_08._310_targetVid = "Bolo de Arroz "
gameforge.subquest_08._320_sayReward = "O Taurean n\227o ir\225 chatear mais a Yu-Rang. Vai ter[ENTER]com ela e recebe o teu Bolo de Arroz. "
gameforge.subquest_08._330_say = "Ha, ha! Castigaste o Taurean! Obrigado. Agora ele[ENTER]ir\225 pensar duas vezes antes de voltar a[ENTER]chatear-me. Aqui tens o teu Bolo de Arroz. Bom[ENTER]proveito! "
gameforge.subquest_08._340_makequestbutton = "Regressa \224 Ah-Yu "
gameforge.subquest_08._350_targetVid = "Bolo de Arroz para a Ah-Yu "
gameforge.subquest_08._360_sayReward = "Recebeste o Bolo de Arroz da Yu-Rang. Leva-o \224[ENTER]Ah-Yu. Poder\225s encontr\225-la a ela e \224 sua crian\231a[ENTER]na primeira Vila. "
gameforge.subquest_08._370_npcChat = "Aqui est\225 o Bolo de Arroz para o teu filho "
gameforge.subquest_08._380_say = "Trouxeste-me o Bolo de Arroz! Muito obrigado.[ENTER]Oh! Olha, o meu beb\233 parou de chorar e est\225 agora[ENTER]a comer o bolo alegremente. Conseguiste. Obrigado[ENTER]pela ajuda! "
gameforge.subquest_08._390_sayReward = "Recebeste 26.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang. "
gameforge.subquest_08._40_say = "Mas... N\227o posso deixar este lugar e o beb\233 est\225[ENTER]a atormentar os vizinhos todos... N\227o dever\225[ENTER]demorar muito! Tens a certeza que n\227o tens tempo[ENTER]suficiente? "
gameforge.subquest_08._50_say = "Parece que est\225s ocupado? Por favor volta mais[ENTER]tarde.[ENTER]N\227o chores, meu querido. "
gameforge.subquest_08._60_say = "Parece que vou ter de o pedir a outra pessoa.[ENTER]Boa sorte na tua jornada! "
gameforge.subquest_08._70_say = "Muito obrigado! \201 um al\237vio para mim. "
gameforge.subquest_08._80_makequestbutton = "Bolo de Arroz "
gameforge.subquest_08._90_targetVid = "Bolo de Arroz "
gameforge.subquest_09 = {}
gameforge.subquest_09._100_sayReward = "Encontra a Soldado Jura de Cristal que roubou o[ENTER]Machado Dourado ao Ferreiro e devolve-o. "
gameforge.subquest_09._10_targetVid = "Encontra o Machado Dourado "
gameforge.subquest_09._110_sendLetter = "Encontrei o Machado Dourado "
gameforge.subquest_09._120_npcChat = "Aqui est\225 o Machado Dourado. "
gameforge.subquest_09._130_say = "Obrigado! Estou em d\237vida para contigo. Agora n\227o[ENTER]tenho de me preocupar com o que hei de dizer ao[ENTER]Deokbae quando o vir. "
gameforge.subquest_09._140_sayReward = "Recebeste 36.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang.[ENTER]Recebeste um Ornamento. "
gameforge.subquest_09._20_npcChat = "O Machado Dourado "
gameforge.subquest_09._30_say = "Lembras-te do meu amigo Deokbae? Prometi[ENTER]criar-lhe um Machado. Mas infelizmente desviei a[ENTER]minha aten\231\227o durante uns segundos e uma Soldado[ENTER]Jura de Cristal roubou-mo. Podes recuperar o[ENTER]Machado por mim? Ainda deve estar na posse de uma[ENTER]Soldado Jura de Cristal. Dever\225s conseguir[ENTER]reconhec\234-lo. N\227o h\225 muitos machados desse tipo.[ENTER]Irei dar-te uma recompensa fant\225stica se o[ENTER]conseguires recuperar! "
gameforge.subquest_09._40_say = "Queres desistir desta miss\227o? "
gameforge.subquest_09._50_sayTitle = "Ferreiro "
gameforge.subquest_09._60_say = "Quero mesmo este Machado! Voltaremos a ver-nos?[ENTER]Adeus. "
gameforge.subquest_09._70_say = "Obrigado pela tua ajuda. Tem cuidado! O cl\227 Jura[ENTER]de Cristal \233 muito perigoso. "
gameforge.subquest_09._80_say = "Obrigado pela tua ajuda. Tem cuidado! O cl\227 Jura[ENTER]de Cristal tem causado muitos problemas[ENTER]ultimamente. "
gameforge.subquest_09._90_makequestbutton = "Encontra o Machado Dourado "
gameforge.subquest_10 = {}
gameforge.subquest_10._100_sayReward = "Pergunta ao Ferreiro pelo Gancho de Cabelo. "
gameforge.subquest_10._10_targetVid = "Encontra o Gancho de Cabelo "
gameforge.subquest_10._110_npcChat = "O Gancho de Cabelo roubado "
gameforge.subquest_10._120_say = "O qu\234? Ela acha que eu lhe roubei o seu Gancho de[ENTER]Cabelo? Isso \233 inacredit\225vel! Quem \233 que ela[ENTER]pensa que eu sou? Eu estava a trabalhar na minha[ENTER]loja! Ah, provavelmente n\227o te deveria contar[ENTER]isto, mas o Vendedor de Armaduras esteve na Loja[ENTER]Geral recentemente. "
gameforge.subquest_10._130_makequestbutton = "O Gancho de Cabelo roubado "
gameforge.subquest_10._140_sayReward = "Pergunta ao Vendedor de Armas pelo Gancho de[ENTER]Cabelo. "
gameforge.subquest_10._150_say = "O qu\234? Achas que eu roubei o Gancho de Cabelo da[ENTER]Negociadora da Loja Geral? N\227o, nunca, n\227o o fiz![ENTER]Estou a ser sincero! Estive l\225 para visitar a[ENTER]Negociadora! Mas ela n\227o estava l\225. Em vez disso[ENTER]encontrei uma Arqueira Jura de Cristal. Quando[ENTER]ela me viu, fugiu. Talvez ela tenha roubado o[ENTER]Gancho de Cabelo. "
gameforge.subquest_10._160_sayReward = "Recupera o Gancho de Cabelo da Arqueira Jura de[ENTER]Cristal! "
gameforge.subquest_10._170_sendLetter = "Encontraste o Gancho de Cabelo "
gameforge.subquest_10._180_targetVid = "Dirige-te \224 Loja Geral. "
gameforge.subquest_10._190_npcChat = "Tenho aqui o teu Gancho de Cabelo. "
gameforge.subquest_10._200_say = "Oh! Muito obrigado. Estou t\227o feliz. Finalmente[ENTER]recuperei o meu Gancho de Cabelo![ENTER]Tens sido uma grande ajuda ultimamente. Como[ENTER]posso mostrar o meu apre\231o? Tenho um Bilhete de[ENTER]Equita\231\227o. N\227o \233 nada de especial, mas n\227o[ENTER]preciso mais dele uma vez que n\227o posso abandonar[ENTER]a Loja. Leva-o como prova da minha gratid\227o.[ENTER]Mais uma vez, obrigado. "
gameforge.subquest_10._20_say = "Por favor ouve-me! Tenho um grande problema. Sa\237[ENTER]da Loja por um momento para tratar de uns[ENTER]assuntos importantes. Enquanto estava longe[ENTER]algu\233m me roubou o meu Gancho de Cabelo favorito. "
gameforge.subquest_10._210_sayReward = "Recebeste 60.000 Pontos de Experi\234ncia.[ENTER]Recebeste 10.000 Yang.[ENTER]Recebeste um Bilhete de Equita\231\227o. "
gameforge.subquest_10._220_say = "Ainda n\227o encontraste o meu Gancho de Cabelo?[ENTER]Espero que o encontres. "
gameforge.subquest_10._230_select = "Desistir "
gameforge.subquest_10._240_say = "Queres mesmo desistir da Miss\227o? "
gameforge.subquest_10._250_say = "Sim, elas n\227o s\227o canja... Talvez devesses[ENTER]descansar um pouco e tentar de novo mais tarde? "
gameforge.subquest_10._260_say = "Onde estar\225 o meu Gancho de Cabelo favorito?[ENTER]Parece que n\227o o encontrarei...[ENTER]Adeus. "
gameforge.subquest_10._270_say = "Muito obrigado. Significa muito para mim. "
gameforge.subquest_10._30_say = "O meu pai deu-me este maravilhoso Gancho de[ENTER]Cabelo pelo meu anivers\225rio e eu adoro-o. Mas \233[ENTER]claro que n\227o posso abandonar a minha loja de[ENTER]novo, caso contr\225rio ainda me roubam outra coisa[ENTER]importante. Podes procurar o Gancho de Cabelo por[ENTER]mim? Suspeito do Ferreiro. Ele uma vez disse que[ENTER]andava \224 procura de algo assim. "
gameforge.subquest_10._40_select = "Vou procur\225-lo. "
gameforge.subquest_10._50_say = "Queres mesmo desistir da Miss\227o? "
gameforge.subquest_10._60_say = "Vejo-te mais tarde. Diverte-te! "
gameforge.subquest_10._70_say = "Onde estar\225 o meu Gancho de Cabelo? Adeus... "
gameforge.subquest_10._80_say = "Vais procur\225-lo por mim? Oh, obrigado! "
gameforge.subquest_10._90_targetVid = "Dirige-te ao Ferreiro "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Pergunta ao Yu-Hwan sobre o irm\227o da Mirine. "
gameforge.subquest_11._10_targetVid = " Encontra o meu irm\227o "
gameforge.subquest_11._110_npcChat = "Viste o irm\227o da Mirine? "
gameforge.subquest_11._120_say = "Apaixonei-me sem compreender o amor... Lalalaa...[ENTER]De quem est\225s \224 procura? O irm\227o da Mirine?[ENTER]Tivemos uma conversa r\225pida antes de ele ter ido[ENTER]para as montanhas \224 procura de algumas ervas[ENTER]raras. N\227o sei onde ele est\225 agora. O ca\231ador da[ENTER]vila por vezes vai \224s montanhas. Porque n\227o lhe[ENTER]perguntas?[ENTER]La, la, la, o amor \233 triste, mas t\227o bonito... "
gameforge.subquest_11._130_targetVid = "Pergunta ao Yang-Shin pelo irm\227o da Mirine. "
gameforge.subquest_11._140_say = "O irm\227o da Mirine? Sim, ele andava \224 procura de[ENTER]ervas nas montanhas. Ele ficou t\227o contente[ENTER]quando encontrou algumas ervas raras. Ele queria[ENTER]comprar alguns vestidos para a sua irm\227 com o[ENTER]lucro que fizesse com a sua venda. \201 uma pessoa[ENTER]muito simp\225tica. Tenho a certeza que ele estar\225[ENTER]de volta dentro de alguns dias. N\227o achas? "
gameforge.subquest_11._150_targetVid = "Conta as novidades \224 Mirine "
gameforge.subquest_11._160_npcChat = "As novidades sobre o irm\227o da Mirine. "
gameforge.subquest_11._170_say = "Olha, recentemente recebi uma carta do meu irm\227o![ENTER]Ele escreveu a contar-me que encontrou um local[ENTER]repleto de Ervas e que ir\225 demorar um pouco at\233[ENTER]ele voltar.[ENTER]Desculpa, n\227o deveria ter-te incomodado com isto.[ENTER]Toma, n\227o \233 muito mas espero que aceites e me[ENTER]desculpes.[ENTER]Obrigado por teres tomado algum tempo para[ENTER]fazeres esta longa viagem. "
gameforge.subquest_11._180_sayReward = "Recebeste 122.000 Pontos de Experi\234ncia.[ENTER]Recebeste 5.000 Yang. "
gameforge.subquest_11._20_npcChat = " Encontra o meu irm\227o "
gameforge.subquest_11._30_say = "Posso pedir-te um favor? O meu irm\227o est\225 fora j\225[ENTER]h\225 algum tempo. N\227o ou\231o sobre ele h\225 muito.[ENTER]Estou a ficar um pouco preocupada. Podes[ENTER]procur\225-lo? "
gameforge.subquest_11._40_say = "O meu irm\227o queria visitar o Yu-Hwan, que se[ENTER]encontra na vila vizinha. Se fores ter com o[ENTER]Yu-Hwan pode ser que ele te d\234 not\237cias do meu[ENTER]irm\227o. Obrigado desde j\225. "
gameforge.subquest_11._50_select = "Sim, vou faz\234-lo. "
gameforge.subquest_11._60_say = "Tu vais desistir desta miss\227o para sempre? "
gameforge.subquest_11._70_say = "Obrigado. Por favor procura por ele. Estou mesmo[ENTER]preocupada. Vejo-te mais tarde. "
gameforge.subquest_11._80_say = "Que pena que n\227o me queiras ajudar.[ENTER]Adeus. "
gameforge.subquest_11._90_say = "Vais procur\225-lo? Muito obrigado! Estou mesmo[ENTER]preocupada. Boa sorte! "
