gameforge.subquest_12._100_qSetTitle = "Mi-Jung do Cl\227 Jura de Cristal "
gameforge.subquest_12._10_targetVid = "Mata a Mi-Jung do Cl\227 Jura de Cristal "
gameforge.subquest_12._110_sayReward = "Regressa ao Guarda da Cidade. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung do Cl\227 Jura de Cristal "
gameforge.subquest_12._130_sayReward = "Vai matar a Mi-Jung do Cl\227 Jura de Cristal. Assim[ENTER]que o tiveres feito regressa ao Guarda da Cidade. "
gameforge.subquest_12._140_targetVid = "Dirige-te ao Guarda da Cidade "
gameforge.subquest_12._150_sayTitle = "Mataste a Mi-Jung do Cl\227 Jura de Cristal "
gameforge.subquest_12._160_sayReward = "Regressa ao Guarda da Vila para receberes a tua[ENTER]recompensa. "
gameforge.subquest_12._170_npcChat = "Matei a Mi-Jung "
gameforge.subquest_12._180_say = "Oh! \201s mesmo t\227o bom quanto ouvi. \201s incr\237vel.[ENTER]Obrigado. Tratar do problema que \233 o cl\227 Jura de[ENTER]Cristal tornou-se mais f\225cil gra\231as a ti. Muito[ENTER]bem! "
gameforge.subquest_12._190_sayReward = "Recebeste 122.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang.[ENTER]Recebeste uma Pulseira de Prata. "
gameforge.subquest_12._20_say = "chega aqui um segundo. \201s um bom lutador. J\225 ouvi[ENTER]falar muito de ti pelo Capit\227o. "
gameforge.subquest_12._30_say = "Podes ir atr\225s da Mi-Jung do cl\227 Jura de Cristal?[ENTER]\201 dif\237cil proteger a vila e os seus habitantes[ENTER]dos ataques do cl\227 Jura de Cristal. Se matarmos a[ENTER]Mi-Jung, uma dos seus l\237deres, a situa\231\227o ir\225[ENTER]mudar. A seguran\231a da nossa vila est\225 nas tuas[ENTER]m\227os. Acredito que n\227o ir\225s falhar! "
gameforge.subquest_12._40_select = "Sim, irei faz\234-lo. "
gameforge.subquest_12._50_select = "Agora n\227o. "
gameforge.subquest_12._60_say = "N\227o queres mesmo ajudar-nos? "
gameforge.subquest_12._70_say = "Acho que n\227o \233 a altura certa ent\227o... Volta mais[ENTER]tarde. "
gameforge.subquest_12._80_say = "Se n\227o quiseres ajudar n\227o h\225 nada que eu possa[ENTER]fazer acerca disso. Adeus... "
gameforge.subquest_12._90_say = "N\227o nos queres ajudar? "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "Vai ter com a Ariyoung "
gameforge.subquest_13._10_targetVid = "Materiais para fazer armas "
gameforge.subquest_13._110_targetVid = "Dirige-te \224 Ah-Yu. "
gameforge.subquest_13._120_sayReward = "O Vendedor de Armas precisa da tua ajuda. Obt\233m o[ENTER]Ferro do Uriel e o Linho da Ariyoung. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "Precisas de Ferro? Posso dar-te algum, mas apenas[ENTER]se me fizeres um favor. "
gameforge.subquest_13._150_say = "Deixei cair algo quando tive de correr pela minha[ENTER]vida a fugir dos tigres: \201 um pacote que cont\233m[ENTER]livros importantes, feito de pano. Se eu n\227o os[ENTER]reaver n\227o poderei continuar as minhas[ENTER]investiga\231\245es sobre as Pedras Metin.[ENTER]Traz-me o Pacote e irei dar-te algum Ferro. "
gameforge.subquest_13._160_npcChat = "Tenho o teu Pacote. "
gameforge.subquest_13._170_say = "Obrigado! Realmente pe\231o-te favores demasiado[ENTER]frequentemente. Toma algum Ferro. Espero que[ENTER]cumpra o seu prop\243sito. "
gameforge.subquest_13._180_say = "O qu\234? Precisas de mais Ferro? Ele n\227o cresce nas[ENTER]\225rvores, sabes?! Irei dar-te mais algum Ferro,[ENTER]mas apenas se me fizeres um favor primeiro.[ENTER]Alguns tigres roubaram o meu Pacote. Tive de[ENTER]fugir para me salvar e havia alguns documentos[ENTER]muito importantes dentro dele. Se n\227o os reaver[ENTER]n\227o conseguirei continuar a minha investiga\231\227o[ENTER]das Pedras Metin. Por favor encontra o Pacote que[ENTER]os tigres me roubaram. "
gameforge.subquest_13._190_say = "J\225 to dei. Esqueceste-te disso? "
gameforge.subquest_13._200_sayTitle = "Pacote encontrado "
gameforge.subquest_13._20_npcChat = "Material para armas "
gameforge.subquest_13._210_say = "Encontraste o Pacote de Uriel. Regressa at\233 ele. "
gameforge.subquest_13._220_npcChat = "Preciso de Linho "
gameforge.subquest_13._230_say = "Precisas de Linho? Dei-o \224 Ah-Yu.[ENTER]Espera! J\225 que vais ter com ela poderias levar[ENTER]esta carta. Somos boas amigas, mas por causa da[ENTER]filha dela n\227o temos tido muito tempo para nos[ENTER]ver.[ENTER]Tamb\233m lhe escrevo a dizer para te dar algum do[ENTER]seu Linho... Assim todos t\234m a ganhar![ENTER]E d\225-lhe os meus cumprimentos. "
gameforge.subquest_13._240_say = "Ariyuong:[ENTER]Certamente recebeste o Linho da Ah-Yu certo? "
gameforge.subquest_13._250_npcChat = "Carta da Ariyoung "
gameforge.subquest_13._260_say = "Uma carta da Ariyoung? \201 bom ter not\237cias dela[ENTER]depois de tanto tempo. Antigamente juntavamo-nos[ENTER]muitas vezes para falar. Mas ultimamente tem sido[ENTER]dif\237cil conseguir faz\234-lo. Por favor espera um[ENTER]momento.[ENTER]Diz aqui que precisas de algum Linho? Ariyoung[ENTER]deu-me algum. Posso oferecer-te um pouco.[ENTER]Obrigado por me trazeres a carta. Irei[ENTER]responder-lhe o mais r\225pido poss\237vel... "
gameforge.subquest_13._270_qSetTitle = "Est\225 na hora de ir ter com o Vendedor de Armas. "
gameforge.subquest_13._280_targetVid = "Dirige-te ao Vendedor de Armas. "
gameforge.subquest_13._290_sayTitle = "Dar materiais "
gameforge.subquest_13._300_sayReward = "Tenho todos os materiais. Vamos ter com o[ENTER]Vendedor de Armas. "
gameforge.subquest_13._30_say = "Hey, podes fazer-me um favor?[ENTER]Estou a tentar criar alguns tipos de armas novos.[ENTER]N\227o \233 f\225cil encontrar os materiais necess\225rios.[ENTER]Tenho muito trabalho para fazer e n\227o posso[ENTER]procurar os materiais eu mesmo. Podes arranj\225-los[ENTER]por mim? "
gameforge.subquest_13._310_say = "Muito bem. \201s realmente r\225pido e eficaz. Agora[ENTER]deixa-me trabalhar nestas armas![ENTER]*clank, clank*[ENTER]Aqui est\227o. Estes s\227o os novos tipos de armas.[ENTER]Fiz o meu melhor. Espero que gostes da tua nova[ENTER]arma. Diverte-te com ela! "
gameforge.subquest_13._320_sayTitle = "Recompensa: "
gameforge.subquest_13._330_sayReward = "Recebeste 122.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Recebeste uma Espada Larga+3. "
gameforge.subquest_13._350_sayReward = "Recebeste uma Adaga de Tesoura+3. "
gameforge.subquest_13._360_sayReward = "Recebeste um Leque de Pav\227o+3. "
gameforge.subquest_13._40_say = "\201 claro que te irei recompensar. Assim que as[ENTER]armas estiverem terminadas, irei dar-te uma[ENTER]delas. Preciso dos seguintes materiais: Ferro e[ENTER]Linho. Podes obter ferro do Uriel e Linho da[ENTER]Ariyoung. Avisa-me quando tiveres tudo. "
gameforge.subquest_13._50_say = "Queres mesmo desistir da Miss\227o? "
gameforge.subquest_13._60_say = "Parece que era demasiado para ti.[ENTER]Regressa quando tiveres mais tempo! "
gameforge.subquest_13._70_say = "Se n\227o quiseres faz\234-lo n\227o te poderei for\231ar.[ENTER]Adeus. "
gameforge.subquest_13._80_say = "Muito bem![ENTER]Assim que as armas estiverem terminadas irei[ENTER]oferecer-te uma. Boa sorte. "
gameforge.subquest_13._90_sendLetter = "Procurar os materiais "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "Regressa ao Guarda da Cidade "
gameforge.subquest_15._10_targetVid = "Eun-Jung do Cl\227 Jura de Cristal. "
gameforge.subquest_15._110_sayReward = "Mataste a Eun-Jung do Cl\227 Jura de Cristal. Vai[ENTER]ter com o Guarda da Cidade e informa-o. "
gameforge.subquest_15._120_say = "Fant\225stico! Portaste-te ainda melhor do que eu[ENTER]esperava. N\243s n\227o conseguimos fazer nada frente[ENTER]\224s l\237deres do Cl\227 Jura de Cristal, mas tu[ENTER]derrotaste ambas com facilidade. "
gameforge.subquest_15._130_say = "Isto \233 incr\237vel. Ir\225s receber uma recompensa[ENTER]adequada. Por favor aceita isto e continua a[ENTER]trabalhar pela paz da nossa vila! "
gameforge.subquest_15._140_sayReward = "Recebeste 150.000 Pontos de Experi\234ncia.[ENTER]Recebeste 25.000 Yang.[ENTER]Recebeste um Colar d'Ouro +4. "
gameforge.subquest_15._20_say = "Chega aqui um momento.[ENTER]Ouvi falar muito de ti pelo Capit\227o. Pareces ser[ENTER]uma pessoa destemida. \201 por isso que preciso de[ENTER]novo da tua ajuda: O Cl\227 Jura de Cristal tem[ENTER]andado a portar-se pior que nunca. "
gameforge.subquest_15._30_say = "Derrotaste Mi-Jung, a l\237der do Cl\227 Jura de[ENTER]Cristal. Mas ainda estamos em perigo! O perigo[ENTER]causado pelo Cl\227 Jura de Cristal n\227o diminuiu,[ENTER]pelo contr\225rio, apenas piorou! "
gameforge.subquest_15._40_say = "Para acabar com isto temos de matar a Capit\227o[ENTER]Eun-Jung. O resto n\227o dever\225 ser problema.[ENTER]Vai e mata Eun-Jung! O nosso destino est\225 nas[ENTER]tuas m\227os. "
gameforge.subquest_15._50_sayTitle = "Guarda da Cidade: "
gameforge.subquest_15._60_say = "Vais regressar mais tarde? \201s a pessoa certa para[ENTER]isto. "
gameforge.subquest_15._70_say = "N\227o o consegues fazer? Bom. Vejo-te em breve. "
gameforge.subquest_15._80_say = "Eu sabia que nos quererias ajudar! Mata a[ENTER]Eun-Jung que n\243s trataremos do resto. Boa sorte! "
gameforge.subquest_15._90_sayReward = "Mata Eun-Jung, a l\237der do Cl\227 Jura de Cristal.[ENTER]Esperemos que o Cl\227 Jura de Cristal pare depois[ENTER]disso. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Pergunta ao Yu-Hwan "
gameforge.subquest_16._10_targetVid = "\192 procura da Cavalaria Antiga "
gameforge.subquest_16._110_targetVid = "Vai ter com o Yu-Hwan "
gameforge.subquest_16._120_say = "A vida \233 maravilhosa - o amor \233 maravilhoso...[ENTER]Oh, tu de novo! O que queres desta vez?[ENTER]Informa\231\227o sobre a Cavalaria Antiga? Porque me[ENTER]est\225s a perguntar sobre isso? O Capit\227o tem[ENTER]grandes planos?! "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Poucos textos originais dessa altura[ENTER]sobreviveram, mas conhe\231o algumas can\231\245es sobre a[ENTER]Cavalaria Antiga. Espera um minuto, deixa-me[ENTER]apenas afinar o meu instrumento...[ENTER]Oh, est\225s com pressa? Hoje em dia ningu\233m tem[ENTER]paci\234ncia para ouvir as minhas m\250sicas...[ENTER]Bom. Resumindo, a Cavalaria de Isup era quase[ENTER]invenc\237vel. Eram soldados extremamente bem[ENTER]treinados e protegidos por pesadas armaduras, mas[ENTER]ao mesmo tempo r\225pidos. "
gameforge.subquest_16._150_say = "Era o melhor ex\233rcito que este continente alguma[ENTER]vez viu. Muitos reinos sucumbiram porque nada[ENTER]conseguia travar a Cavalaria. Seria similar nos[ENTER]dias de hoje. Mas s\227o necess\225rios m\233todos de[ENTER]treino extremamente rigorosos e uma grande[ENTER]quantidade de ferro de alta qualidade para[ENTER]equipar um ex\233rcito desse tipo. Deverias[ENTER]perguntar ao Vendedor Ambulante e ao Uriel. Eles[ENTER]poder\227o ter mais detalhes sobre este assunto. "
gameforge.subquest_16._160_makequestbutton = "Dirige-te ao Vendedor Ambulante "
gameforge.subquest_16._170_qSetTitle = "A Cavalaria Antiga "
gameforge.subquest_16._180_targetVid = "Vendedor Ambulante: "
gameforge.subquest_16._190_sayReward = "Yu-Hwan, o m\250sico, diz que o Vendedor Ambulante e[ENTER]o Uriel poder\227o ter mais informa\231\245es sobre a[ENTER]Cavalaria Antiga. Vai ter com o Vendedor[ENTER]Ambulante primeiro. "
gameforge.subquest_16._200_sayTitle = "Vendedor Ambulante: "
gameforge.subquest_16._20_npcChat = "A Cavalaria Antiga "
gameforge.subquest_16._210_say = "O que queres de um simples Vendedor Ambulante[ENTER]como eu?[ENTER]As armaduras de ferro da Cavalaria Antiga? Essas[ENTER]s\227o hist\243rias antigas. Quem est\225 interessado[ENTER]nisso? Tenho que ganhar dinheiro para comer e n\227o[ENTER]posso ficar aqui o dia todo \224 conversa! "
gameforge.subquest_16._220_say = "Est\225 a ser cada vez mais dif\237cil ter o suficiente[ENTER]para sobreviver. Desde que estas pedras come\231aram[ENTER]a cair do c\233u que eu...[ENTER]O que est\225s a dizer? Oh sim, a Cavalaria. Tanto[ENTER]quanto sei, eles usavam armaduras especiais e[ENTER]para as produzirem necessitavam de conhecimentos[ENTER]especiais. Eram as melhores armaduras alguma vez[ENTER]feitas! Punhais normais e at\233 mesmo flechas eram[ENTER]incapazes de perfurar estas protec\231\245es perfeitas! "
gameforge.subquest_16._230_say = "Podes imaginar qu\227o importantes eram estas[ENTER]armaduras ao veres quanto dinheiro era necess\225rio[ENTER]para criar e manter este ex\233rcito. Diz-se que[ENTER]usaram os tesouros inteiros de v\225rios reinos! Se[ENTER]eu pudesse vender algumas armaduras dessas n\227o[ENTER]precisaria de trabalhar para o resto da vida! "
gameforge.subquest_16._240_say = "Hoje em dia, as armaduras podem at\233 ser feitas de[ENTER]Pedras Metin. Com este novo tipo de armaduras j\225[ENTER]n\227o \233 um sonho criar um ex\233rcito como o de outros[ENTER]tempos.[ENTER]Mas j\225 estou a falar demasiado. Tenho de voltar \224[ENTER]minha vida. Adeus! "
gameforge.subquest_16._250_sayTitle = "A Cavalaria Antiga "
gameforge.subquest_16._260_say = "O Vendedor Ambulante sabia algumas coisas sobre[ENTER]as armaduras de ferro da Cavalaria Antiga. Agora[ENTER]vai \224 1\170 vila e pergunta a Uriel, o s\225bio, sobre[ENTER]os m\233todos de treino. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "O que te traz aqui?[ENTER]A Cavalaria Antiga? \201 claro que sei algumas[ENTER]coisas sobre eles. Toda a gente sabe. Esse[ENTER]ex\233rcito ficar\225 para a hist\243ria como um dos[ENTER]melhores de sempre! Muito do que se diz por a\237 \233[ENTER]exagerado, mas os soldados eram muito temidos. E[ENTER]com raz\227o. "
gameforge.subquest_16._290_say = "A Cavalaria Antiga era superior a tudo o resto,[ENTER]principalmente gra\231as aos seus treinos[ENTER]intensivos. Apenas os melhores conseguiam passar[ENTER]os treinos, muitos morriam. Penso que se hoje em[ENTER]dia existisse esse tipo de treinos, nem um \250nico[ENTER]soldado estaria vivo ao fim do dia. "
gameforge.subquest_16._300_say = "Vou dar-te algumas informa\231\245es detalhadas sobre o[ENTER]treino, para que tenhas alguma ideia sobre o[ENTER]assunto. Sei que neste momento est\227o a decorrer[ENTER]algumas guerras terr\237veis, mas n\227o tenho a[ENTER]certeza se ser\225 sensato voltar a criar um[ENTER]ex\233rcito t\227o temido como a Cavalaria Antiga. "
gameforge.subquest_16._30_say = "Tenho uma nova tarefa para ti. Recebeste a ordem[ENTER]de encontrar informa\231\245es sobre a Cavalaria[ENTER]Antiga. Era a parte mais importante do ex\233rcito[ENTER]de Isup, o Imperador que unificou o continente. A[ENTER]Cavalaria Antiga era temida por todos os outros[ENTER]Reinos devido ao seu fant\225stico poder de ataque e[ENTER]velocidade. "
gameforge.subquest_16._310_say = "Vai ter com o Capit\227o e conta-lhe tudo o que[ENTER]descobriste sobre a Cavalaria Antiga. "
gameforge.subquest_16._320_makequestbutton = "Dirige-te ao Capit\227o "
gameforge.subquest_16._330_npcChat = "Relat\243rio sobre a Cavalaria Antiga "
gameforge.subquest_16._340_sayTitle = "Capit\227o "
gameforge.subquest_16._350_say = "Conseguiste descobrir alguma coisa? Conta! ...[ENTER]Hmm, isso \233 muito interessante. Portanto[ENTER]basicamente tudo se resume a armaduras[ENTER]resistentes e treino intensivo? Ent\227o dever\225 ser[ENTER]poss\237vel fazer algo assim! Um ex\233rcito como esse[ENTER]poderia reunir os tr\234s reinos! "
gameforge.subquest_16._360_say = "Mas iria precisar de muito dinheiro. E de muitos[ENTER]ferreiros excelentes. E de recrutas que[ENTER]decidissem voluntariar-se a passar por um[ENTER]verdadeiro inferno para se tornarem os melhores[ENTER]dos melhores![ENTER]N\227o, n\227o! N\227o olhes para mim dessa forma. N\227o te[ENTER]preocupes, j\225 fizeste o suficiente por agora. "
gameforge.subquest_16._370_say = "Toma a tua recompensa e vai descansar.[ENTER]Vejo-te mais tarde! "
gameforge.subquest_16._380_sayReward = "Recebeste 150.000 Pontos de Experi\234ncia.[ENTER]Recebeste 30.000 Yang.[ENTER]Recebeste Brincos d'Ouro. "
gameforge.subquest_16._40_say = "Com as informa\231\245es que reuniste poderemos[ENTER]refor\231ar o nosso poder militar. Primeiro deves[ENTER]visitar o m\250sico, Yu-Hwan. Tenho a certeza que[ENTER]ele sabe algumas coisas sobre a Cavalaria de[ENTER]Isup. "
gameforge.subquest_16._50_say = "Hm, como quiseres. At\233 depois, ent\227o. "
gameforge.subquest_16._60_say = "Alguma vez irei comandar uma Cavalaria assim? Tem[ENTER]cuidado. "
gameforge.subquest_16._70_say = "Obrigado. Tem cuidado. "
gameforge.subquest_16._80_sayTitle = "A Cavalaria Antiga "
gameforge.subquest_16._90_sayReward = "O Capit\227o anda \224 procura de informa\231\245es sobre a[ENTER]Cavalaria lend\225ria do Rei Isup. Yu-Hwan, o[ENTER]m\250sico, dever\225 ter algumas informa\231\245es. Vai ter[ENTER]com ele e pergunta-lhe. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Fala com a Negociadora da Loja Geral. "
gameforge.subquest_17._10_targetVid = "A Hist\243ria do Marido da Ariyoung "
gameforge.subquest_17._110_say = "Vai ter com a Negociadora da Loja Geral e[ENTER]pergunta-lhe sobre o marido da Ariyoung. "
gameforge.subquest_17._120_npcChat = "O marido da Ariyoung "
gameforge.subquest_17._130_say = "\201 uma hist\243ria triste. Ela n\227o sabe o que[ENTER]aconteceu ao marido? Ele est\225 num lugar do qual[ENTER]nunca ningu\233m regressa...[ENTER]Um dia, quando vinha a caminho da vila, ele foi[ENTER]raptado e morto pelo cl\227 Vento Negro. "
gameforge.subquest_17._140_say = "Ela ir\225 ficar devastada quando lhe contares. Eles[ENTER]amavam-se tanto. Mas ela tem de descobrir. De[ENTER]outra maneira a incerteza ir\225 mata-la. "
gameforge.subquest_17._150_targetVid = "Not\237cias Tristes "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "A negociadora da loja geral tem m\225s noticias.[ENTER]Regressa \224 Ariyoung e conta-lhe sobre a morte do[ENTER]seu marido. "
gameforge.subquest_17._180_npcChat = "O teu marido morreu... "
gameforge.subquest_17._190_say = "O qu\234... o que est\225s a dizer?! Ele... ele foi[ENTER]morto pelo Cl\227 Vento Negro? Oh... n\227o... ele est\225[ENTER]morto... N\227o sei o que fazer sem ele! "
gameforge.subquest_17._200_say = "Podes trazer-me o corpo do meu marido? Talvez[ENTER]ent\227o eu lhe possa pelo menos dizer adeus. Ou se[ENTER]n\227o conseguires trazer-me o seu corpo, pelo menos[ENTER]traz-me uma lembran\231a. Tenho a certeza que o[ENTER]Goo-Pae do Cl\227 Vento Negro ter\225 algo na sua[ENTER]posse. Por favor traz-me o que conseguires, desde[ENTER]que tenha pertencido ao meu marido! "
gameforge.subquest_17._20_say = "J\225 passou muito tempo desde que ouvi algo do meu[ENTER]marido. Estou t\227o preocupada. Espero que nada lhe[ENTER]tenha acontecido. Eu sei: N\227o vale a pena[ENTER]preocupar-me quando n\227o h\225 nada que eu possa[ENTER]fazer em rela\231\227o a isso. Mas o meu cora\231\227o est\225 a[ENTER]bater t\227o r\225pido que n\227o me consigo acalmar. "
gameforge.subquest_17._210_select = "Sim, irei ajudar-te. "
gameforge.subquest_17._220_say = "Por favor... Volta se mudares de ideias... "
gameforge.subquest_17._230_say = "N\227o encontraste nada?[ENTER]Obrigado de qualquer forma... Oh, coitada de mim! "
gameforge.subquest_17._240_say = "N\227o tenho forma de demonstrar como estou[ENTER]agradecida. Rezo pelo tua seguran\231a. "
gameforge.subquest_17._250_sendLetter = "Mata Goo-Paes "
gameforge.subquest_17._260_say = "O Cl\227 Vento Negro assaltou e matou o marido da[ENTER]Ariyoung. Mata Goo-Paes at\233 encontrares uma[ENTER]lembran\231a que tenha pertencido ao marido da[ENTER]Ariyoung. "
gameforge.subquest_17._270_npcChat = "Sobre o teu marido... "
gameforge.subquest_17._280_say = "Como correu? Descobriste a lembran\231a do meu[ENTER]marido? Ele era o meu mundo. N\227o encontraste nada[ENTER]mesmo? "
gameforge.subquest_17._290_select = "Ainda n\227o. Eu vou continuar a procurar! "
gameforge.subquest_17._300_say = "O Goo-Pae do cl\227 Vento Negro n\227o \233 um inimigo[ENTER]f\225cil. Descansa antes de o procurares. Obrigado[ENTER]pela tua ajuda. "
gameforge.subquest_17._30_say = "A Negociadora da Loja Geral pode ter ouvido algo[ENTER]sobre o meu marido. Ela tem muitos clientes;[ENTER]talvez ela tenha ouvido algo de algum deles. "
gameforge.subquest_17._310_say = "Ent\227o terei de esperar que outro her\243i me possa[ENTER]ajudar.[ENTER]Adeus. "
gameforge.subquest_17._320_say = "Oh, \233s uma pessoa muito simp\225tica! Por favor[ENTER]traz-me uma lembran\231a do meu marido. "
gameforge.subquest_17._330_sendLetter = "Anel de casamento da Ariyoung "
gameforge.subquest_17._340_targetVid = "Regressa \224 Ariyoung "
gameforge.subquest_17._350_sayTitle = "Regressa \224 Ariyoung "
gameforge.subquest_17._360_say = "Encontraste o Anel de Ariyoung num dos Goo-Paes[ENTER]mortos. N\227o consegues imaginar uma lembran\231a[ENTER]melhor.[ENTER]Leva o Anel \224 Ariyoung. "
gameforge.subquest_17._370_npcChat = "Encontrei este Anel. "
gameforge.subquest_17._380_say = "Esse Anel.. \233... meu! Muito obrigado! Agora o meu[ENTER]marido pode descansar em paz. Irei enterrar este[ENTER]Anel juntamente com uma carta que escrevi! A[ENTER]partir de agora irei viver sozinha. Mas pelo[ENTER]menos voltei a ver este Anel! \201 um sentimento[ENTER]maravilhoso.[ENTER]Obrigado, muito obrigado. "
gameforge.subquest_17._390_sendLetter = "Miss\227o completada! "
gameforge.subquest_17._400_say = "As not\237cias da ajuda que deste \224 Ariyoung est\227o a[ENTER]espalhar-se. Muitas pessoas apreciam a tua ajuda. "
gameforge.subquest_17._40_select = "Vou ter com a Negociadora da Loja Geral. "
gameforge.subquest_17._410_sayReward = "Recebeste 300.000 Pontos de Experi\234ncia. "
gameforge.subquest_17._420_sayReward = "Recebeste 10.000 Yang. "
gameforge.subquest_17._50_select = "N\227o tenho tempo para isto. "
gameforge.subquest_17._60_say = "Tu vais desistir desta miss\227o para sempre? "
gameforge.subquest_17._70_say = "Por favor... Volta se mudares de ideias... "
gameforge.subquest_17._80_say = "Tu n\227o tens tempo? Sem tempo para uma miss\227o t\227o[ENTER]f\225cil?[ENTER]Est\225 bem, ent\227o... "
gameforge.subquest_17._90_say = "Obrigado pela tua gentileza. Aiiii! Onde estar\225 o[ENTER]meu marido...? "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "Procura um homem que esteja a ler poemas e[ENTER]vestido com farrapos e fala com ele. "
gameforge.subquest_18._10_targetVid = "Onde Se Esconde Ele? "
gameforge.subquest_18._110_npcChat = "Onde est\225 o teu marido? "
gameforge.subquest_18._120_say = "N\227o sei onde \233 que ele poder\225 estar a[ENTER]esconder-se. Ele tornou-se t\227o bom nisso que \233[ENTER]realmente dif\237cil encontr\225-lo. Ser\225 que preciso[ENTER]de lhe atar um sino ao pesco\231o, como o Guarda do[ENTER]Armaz\233m recomendou? "
gameforge.subquest_18._130_npcChat = "Encontra o Sr. Soon! "
gameforge.subquest_18._140_say = "Ouves um bonito poema. Encantado pelas palavras,[ENTER]segue o som da voz at\233 encontrares um homem[ENTER]vestido com farrapos.[ENTER][ENTER]Este deve ser o marido da Aranyo![ENTER][ENTER]Est\225s prestes a virar-te para regressar \224 Aranyo[ENTER]quando ele te agarra o ombro. "
gameforge.subquest_18._150_say = "Tu n\227o \233s daqui. Foi a minha mulher que te enviou?Oh n\227o! Tu sabes quem sou! Ser\225 que te devia[ENTER]contar a verdade? "
gameforge.subquest_18._153_select = "Estava apenas de passagem. "
gameforge.subquest_18._157_select = "Bom... "
gameforge.subquest_18._160_say = "Aha. Que prazer conhecer-te. O tempo est\225[ENTER]maravilhoso hoje. Leste algum bom livro[ENTER]ultimamente? Neste momento ando a ler um livro do[ENTER]Oja. Recomendo-o vivamente. "
gameforge.subquest_18._170_say = "Tenho raz\227o, n\227o tenho? As piadas da minha mulher[ENTER]est\227o a ficar cada vez piores, tanto que j\225 n\227o[ENTER]consigo estar em casa a ler em paz. Ela[ENTER]simplesmente n\227o me entende e continua a mandar[ENTER]pessoas \224 minha procura... Encontraste-me aqui,[ENTER]mas a qualquer momento posso mudar-me para outro[ENTER]local. E que tal se n\227o dissesses uma palavra[ENTER]sobre me teres visto aqui? Irei dar-te alguns[ENTER]bons conselhos de ca\231a se o fizeres. "
gameforge.subquest_18._180_sendLetter = "Regressa \224 Aranyo "
gameforge.subquest_18._190_say = "Regressa \224 Aranyo e conta-lhe que n\227o conseguiste[ENTER]encontrar o Sr. Soon. "
gameforge.subquest_18._200_npcChat = "O segredo do Sr. Soon "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "N\227o o conseguiste encontrar? Eu at\233 lhe preparei[ENTER]umas armadilhas... Onde raios se esconde ele?[ENTER]Estou t\227o ocupada. Que destino o meu... "
gameforge.subquest_18._220_sendLetter = "Regressa ao Soon "
gameforge.subquest_18._230_say = "Regressa ao Sr. Soon e conta-lhe que foste bem[ENTER]sucedido. "
gameforge.subquest_18._240_npcChat = "Aqui estou. "
gameforge.subquest_18._250_say = "Correu tudo bem? Salvaste-me a vida! Toma isto,[ENTER]aventureiro. Aqui tens a tua recompensa como[ENTER]prometido. "
gameforge.subquest_18._260_sayReward = "Recebeste 7.000 Pontos de Experi\234ncia. "
gameforge.subquest_18._270_sayReward = "Recebeste 10.000 Yang. "
gameforge.subquest_18._280_say = "Regressa \224 Aranyo e conta-lhe que encontraste o[ENTER]Sr. Soon. "
gameforge.subquest_18._290_npcChat = "Esconder-se \233 dif\237cil "
gameforge.subquest_18._300_say = "Obrigado por n\227o revelares o meu esconderijo. N\227o[ENTER]\233 f\225cil esconder-me da minha mulher. Apenas quero[ENTER]ficar aqui a ler em paz. "
gameforge.subquest_18._30_say = "O meu marido \233 um pesadelo. E considera-se ele um[ENTER]acad\233mico! E enquanto estamos com problemas em[ENTER]sustentar-nos, tudo o que ele faz \233 ler livros.[ENTER]Viste-o por a\237? Porque raio decidi casar com um[ENTER]rato de biblioteca? "
gameforge.subquest_18._310_npcChat = "Paradeiro do Sr. Soon "
gameforge.subquest_18._320_say = "Encontraste-o?[ENTER]Muito obrigado! Se ele descobrir que o[ENTER]encontraste poder\225 fugir de novo. Vou para l\225[ENTER]imediatamente. Desta vez vou apanh\225-lo![ENTER]E toma isto como s\237mbolo da minha gratid\227o.[ENTER]Mal posso esperar por te apanhar, malandro...! "
gameforge.subquest_18._33_select = "Irei ajudar-te. "
gameforge.subquest_18._37_select = "N\227o tenho tempo para isto. "
gameforge.subquest_18._40_say = "Queres mesmo desistir da Miss\227o? "
gameforge.subquest_18._50_say = "Bom... Talvez tenhas tempo para o procurar noutro[ENTER]dia... "
gameforge.subquest_18._60_say = "Talvez tu o consigas encontrar... "
gameforge.subquest_18._70_say = "Ficaria muito grata. Se encontrares um mau[ENTER]escritor, avisa-me. Ele deve ser o \250nico em toda[ENTER]a vila. Ele pode estar a escrever um poema neste[ENTER]momento e pode querer estar sozinho. Quando[ENTER]descobrir que ando \224 procura dele talvez tente[ENTER]fugir. Por isso tem cuidado. "
gameforge.subquest_18._80_sendLetter = "Encontra o Sr. Soon "
gameforge.subquest_18._90_sayTitle = "Encontra o Sr. Soon "
gameforge.subquest_19 = {}
gameforge.subquest_19._100_sendLetter = "Arranja P\234lo de Lobo "
gameforge.subquest_19._10_npcChat = "Encontra um espanador "
gameforge.subquest_19._110_sayTitle = "Arranja P\234lo de Lobo "
gameforge.subquest_19._120_sayReward = "Arranja P\234lo de Lobo para que a Idosa possa[ENTER]limpar a sua casa e n\227o tenha de tossir mais.[ENTER]Poder\225s arranjar P\234lo de Lobo nos Lobos Cinza. "
gameforge.subquest_19._130_targetVid = "Regressa \224 Idosa "
gameforge.subquest_19._140_npcChat = "Entrega o P\234lo de Lobo "
gameforge.subquest_19._150_say = "P\234lo de Lobo, \243ptimo...[ENTER]Oh, n\227o. Este n\227o serve. Volta aos Lobos Cinza.[ENTER]Deves ser capaz de encontrar um melhor. "
gameforge.subquest_19._160_say = "Preciso de um espanador a s\233rio. Desculpa mas n\227o[ENTER]consigo fazer nada com isto. "
gameforge.subquest_19._170_select = "Vou tentar de novo. "
gameforge.subquest_19._180_select = "N\227o quero fazer isso. "
gameforge.subquest_19._190_say = "Queres mesmo desistir desta Miss\227o? "
gameforge.subquest_19._200_say = "Ent\227o volta mais tarde. "
gameforge.subquest_19._20_say = "Cough! Cough! Oh deus, esta tosse vai ser a minha[ENTER]morte. N\227o tenho nada com que limpar a casa, pelo[ENTER]que tudo est\225 cheio de p\243. Oh, mas porque raio[ENTER]n\227o tenho um espanador? O meu filho levou-o para[ENTER]trabalhar numa arma qualquer. O pr\243prio sangue do[ENTER]meu sangue est\225 a matar-me! "
gameforge.subquest_19._210_say = "Sei que \233 dif\237cil, mas por favor tenta de novo. "
gameforge.subquest_19._220_say = "Obrigado por tratares do assunto. "
gameforge.subquest_19._230_say = "\201s o aventureiro que esteve por aqui recentemente!Como \233 que a minha tosse est\225? Cough, cough! Como[ENTER]podes ver, n\227o melhorou muito. A casa ainda est\225[ENTER]cheia de p\243.[ENTER][ENTER]Oh? Trouxeste-me P\234lo de Lobo? Magn\237fico! \201s uma[ENTER]pessoa nobre.[ENTER]Espera um momento, volto dentro de uns segundos. "
gameforge.subquest_19._240_say = "Um, dois, um, dois. Um p\233 \224 frente do outro...[ENTER]Certo, aqui estou eu de novo.[ENTER]Muito obrigado! Finalmente poderei limpar a minha[ENTER]casa como deve ser. Tamb\233m encontrei algo que[ENTER]gostaria de te oferecer. N\227o sei se vale alguma[ENTER]coisa, mas talvez te seja \250til.[ENTER]Obrigado mais uma vez. Adeus! "
gameforge.subquest_19._250_sendLetter = "Algo poeirento "
gameforge.subquest_19._260_say = "A tua recompensa consiste num item grande e[ENTER]pesado que est\225 coberto de p\243 e \233 dif\237cil de[ENTER]identificar. Com curiosidade limpas o p\243 do item. "
gameforge.subquest_19._270_say = "\201 uma velha armadura de muito alta qualidade, o[ENTER]trabalho de um ferreiro muito talentoso. Que[ENTER]sorte! "
gameforge.subquest_19._280_say = "\201 uma armadura. Est\225 velha, mas ainda pode ser[ENTER]usada. Bom, pelo menos n\227o se perde tudo! "
gameforge.subquest_19._290_say = "\201 uma armadura, mas apesar de toda a tua[ENTER]esperan\231a parece ser completamente in\250til. "
gameforge.subquest_19._300_sayReward = "Recebeste 15.000 Pontos de Experi\234ncia. "
gameforge.subquest_19._30_select = "Irei arranjar-te um. "
gameforge.subquest_19._40_say = "Tudo est\225 cheio de p\243! Preciso de um espanador.[ENTER]Podes ajudar-me? "
gameforge.subquest_19._50_say = "J\225 passou algum tempo, mas penso que o meu[ENTER]marido, que descanse em paz, criou um a partir de[ENTER]P\234lo de Lobo.[ENTER]Cough! Cough![ENTER][ENTER]Talvez sejas capaz de arranjar algum P\234lo de Lobo[ENTER]para uma pobre idosa? Podes obt\234-lo dos Lobos[ENTER]Cinza. Estarias a ajudar-me imenso. "
gameforge.subquest_19._60_say = "Queres mesmo desistir da Miss\227o? "
gameforge.subquest_19._70_say = "Que pena. Pensei mesmo que me ias ajudar.[ENTER]Volta se mudares de ideias. "
gameforge.subquest_19._80_say = "Que tipo de recompensa poderia algu\233m esperar de[ENTER]uma pobre Idosa? "
gameforge.subquest_19._90_say = "N\227o \233 f\225cil conseguir algum P\234lo de Lobo, mas[ENTER]irei tentar. Afinal de contas um dia quero ser um[ENTER]grande her\243i! "
gameforge.subquest_20 = {}
gameforge.subquest_20._100_say = "Queres parar de procurar? "
gameforge.subquest_20._10_targetVid = "Ajuda a Ah-Yu! "
gameforge.subquest_20._110_say = "Ok, podes ir... Mas vem ter comigo quando tiveres[ENTER]um tempinho. "
gameforge.subquest_20._120_say = "\201s um cobarde. De qualquer forma, tenho a certeza[ENTER]que ias fugir assim que encontrasses os[ENTER]Selvagens! Agora vai-te embora! "
gameforge.subquest_20._130_say = "Obrigado por me ajudares. S\227o tr\234s Dardos. "
