gameforge.subquest_20._150_targetVid = "Ah-Yu: "
gameforge.subquest_20._160_sayTitle = "Os tr\234s Dardos "
gameforge.subquest_20._170_say = "Encontraste todos os tr\234s Dardos pertencentes ao[ENTER]marido da Ah-Yu. Agora regressa \224 Ah-Yu. "
gameforge.subquest_20._180_sayTitle = "Procura os Dardos! "
gameforge.subquest_20._190_say = "Infantaria Selvagem, Sarrafeiro Selvagem,[ENTER]Arqueiro Selvagem e General Selvagem: Todos estes[ENTER]monstros est\227o na posse de Dardos. Procura os[ENTER]Dardos do meu marido no meio dos deles. "
gameforge.subquest_20._200_sayReward = "Precisas de encontrar os tr\234s Dardos e[ENTER]entreg\225-los \224 Ah-Yu.[ENTER](N\250mero de Dardos: %s) "
gameforge.subquest_20._20_npcChat = "Recorda\231\245es de um marido "
gameforge.subquest_20._210_npcChat = "Onde posso encontrar os Dardos? "
gameforge.subquest_20._220_say = "\201 prov\225vel que os Selvagens estejam na posse dos[ENTER]Dardos do meu marido. Quem sabe, pode ser que n\227o[ENTER]os tenham vendido. S\227o Dardos muito bons.[ENTER][ENTER]Ir\225s continuar a procur\225-los? "
gameforge.subquest_20._230_select = "Sim, vou continuar a procurar "
gameforge.subquest_20._240_say = "\201s um cobarde! Suponho que n\227o possa fazer nada[ENTER]quanto a isto. Irei dar uma vista de olhos eu[ENTER]mesma.[ENTER][ENTER]Queres mesmo desistir da busca? "
gameforge.subquest_20._250_select = "Sim, desisto. "
gameforge.subquest_20._260_say = "Eu poderia faz\234-lo sozinha, mas o meu beb\233[ENTER]precisa de mim. Regressa quando tiveres[ENTER]encontrado todos os Dardos! "
gameforge.subquest_20._270_say = "Desististe de procurar os Dardos do Marido de[ENTER]Ah-Yu. "
gameforge.subquest_20._280_say = "Obrigado. Tenho a certeza que os ir\225s encontrar[ENTER]em breve! "
gameforge.subquest_20._290_npcChat = "Devolver os Dardos do Marido "
gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "Oh, por favor n\227o chores mais meu querido. A mam\227[ENTER]j\225 tem as suas preocupa\231\245es. Se continuares a[ENTER]chorar assim n\227o nos conseguiremos acalmar. Por[ENTER]favor p\225ra de chorar. "
gameforge.subquest_20._310_say = "Encontraste um, \243ptimo! Mas podes procurar tamb\233m[ENTER]os outros dois? Eles pertencem a um conjunto.[ENTER]Al\233m disso ficam melhor quando est\227o os tr\234s[ENTER]juntos pendurados na parede... Obrigado. "
gameforge.subquest_20._320_select = "Vou tentar de novo. "
gameforge.subquest_20._330_select = "Desisto. "
gameforge.subquest_20._340_say = "Desististe de procurar os Dardos do Marido de[ENTER]Ah-Yu. "
gameforge.subquest_20._350_say = "Obrigado por n\227o desistires! "
gameforge.subquest_20._360_say = "Oh, aqui est\227o eles! Estou muito contente,[ENTER]obrigado.[ENTER]N\227o \233 muito Yang, mas por favor aceita. "
gameforge.subquest_20._370_sayReward = "Recebeste 300.000 Pontos de Experi\234ncia.[ENTER]Recebeste 20.000 Yang. "
gameforge.subquest_20._40_say = "Oh, pareces um pouco em baixo. Normalmente est\225s[ENTER]t\227o alegre! Aconteceu alguma coisa? "
gameforge.subquest_20._50_say = "O meu marido cuidava de mim e certificava-se que[ENTER]nada de mau me acontecia. Mas ele morreu na[ENTER]guerra. As \250nicas coisas que me restam dele s\227o o[ENTER]nosso filho e os seus Dardos. "
gameforge.subquest_20._60_say = "Enquanto trabalhava algu\233m roubou os Dardos. Os[ENTER]vizinhos disseram-me que foram os Selvagens. N\227o[ENTER]posso procur\225-los eu mesma por causa do beb\233. "
gameforge.subquest_20._70_say = "Poderias trazer-me os Dardos? De certeza que os[ENTER]encontrar\225s na posse dos Selvagens. "
gameforge.subquest_20._80_select = "Vou procur\225-los. "
gameforge.subquest_20._90_select = "N\227o tenho tempo. "
