gameforge.subquest_21._130_sayReward = "Encontraste o Rem\233dio para o Traidor Balso, que[ENTER]contraiu uma doen\231a misteriosa a partir de um[ENTER]Homem Infestado. Entrega-lhe o Rem\233dio. "
gameforge.subquest_21._140_sayTitle = "Obt\233m o Rem\233dio "
gameforge.subquest_21._150_say = "Durante a sua longa fuga, o Traidor Balso[ENTER]contraiu uma doen\231a desconhecida. Obt\233m o rem\233dio[ENTER]nos Homens Infestados na Montanha Sohan. "
gameforge.subquest_21._160_npcChat = "Tenho o teu Rem\233dio! "
gameforge.subquest_21._170_say = "Oh, obrigado! Viver a vida de um fugitivo \233[ENTER]terr\237vel. Especialmente quando tamb\233m se fica[ENTER]doente. Felizmente agora posso recuperar. Muito[ENTER]obrigado. "
gameforge.subquest_21._180_sayTitle = "Recompensa: "
gameforge.subquest_21._190_sayReward = "Recebeste 1.900.000 Pontos de Experi\234ncia.[ENTER]Recebeste 30.000 Yang. "
gameforge.subquest_21._20_npcChat = "Tenho tanta comich\227o... "
gameforge.subquest_21._30_sayTitle = "Traidor Balso: "
gameforge.subquest_21._40_say = "Posso pedir-te um favor? Como j\225 deves saber, por[ENTER]aqui sou conhecido como um traidor. A minha vida[ENTER]\233 muito dif\237cil. J\225 passei tempos em que a minha[ENTER]vida era muito boa. Mas agora passa-se o oposto.[ENTER]Agora ando sempre em fuga. E isso significa que[ENTER]estou sempre sujeito a contrair doen\231as. "
gameforge.subquest_21._50_say = "H\225 alguns dias estive na Montanha Sohan e de[ENTER]alguma forma vi-me rodeado de alguns Homens[ENTER]Infestados. Felizmente consegui fugir, mas[ENTER]apanhei um tipo de doen\231a qualquer por ter tocado[ENTER]na sua pele.[ENTER]Podes ajudar-me a obter o Rem\233dio que preciso?[ENTER]Assumo que eles tenham algum com eles. N\227o gosto[ENTER]de fazer isto, mas podes ajudar-me, por favor? "
gameforge.subquest_21._60_select = "Sim, irei ajudar-te. "
gameforge.subquest_21._70_say = "Queres mesmo desistir de procurar? "
gameforge.subquest_21._80_say = "Bom, isto est\225 sempre a acontecer-me. Para onde[ENTER]quer que eu olhe, h\225 sempre pessoas que n\227o[ENTER]gostam de mim. Se mudares de ideias vem ter[ENTER]comigo. "
gameforge.subquest_21._90_say = "Vai-te! E nunca mais voltes aqui! \201 sempre a[ENTER]mesma coisa... "
gameforge.subquest_22 = {}
gameforge.subquest_22._100_say = "Obrigado. Confio em ti! Traz-me o Machado o mais[ENTER]r\225pido poss\237vel. "
gameforge.subquest_22._10_targetVid = "O Machado Dourado do Deokbae "
gameforge.subquest_22._110_targetVid = "Visita o Deokbae "
gameforge.subquest_22._120_sayTitle = "Encontrei o Machado Dourado "
gameforge.subquest_22._130_say = "Obtiveste o Machado Dourado do General Selvagem.[ENTER]Entrega-o ao Deokbae. "
gameforge.subquest_22._140_sayTitle = "\192 procura do Machado Dourado "
gameforge.subquest_22._150_say = "Recupera o Machado Dourado do Deokbae que est\225 na[ENTER]posse dos Generais Selvagens. "
gameforge.subquest_22._160_npcChat = "Encontrei o teu Machado Dourado! "
gameforge.subquest_22._170_sayTitle = "Deokbae: "
gameforge.subquest_22._180_say = "Sem a tua ajuda nunca mais iria recuperar o[ENTER]Machado. Muito obrigado. Vou ter mais cuidado no[ENTER]futuro e irei t\234-lo sempre comigo. "
gameforge.subquest_22._190_sayReward = "Recebeste 400.000 Pontos de Experi\234ncia. "
gameforge.subquest_22._200_sayReward = "Recebeste 30.000 Yang. "
gameforge.subquest_22._20_npcChat = "Sobre o teu Machado Dourado... "
gameforge.subquest_22._30_sayTitle = "Deokbae: "
gameforge.subquest_22._40_say = "Oh n\227o, oh n\227o! Perdi o Machado. Talvez saibas a[ENTER]que Machado me refiro? \201 o Machado Dourado que[ENTER]recebi do Ferreiro. Um Selvagem roubou-mo. "
gameforge.subquest_22._50_say = "Se o Ferreiro ouvir falar disto ir\225 ficar furioso[ENTER]e nunca mais ir\225 reparar os meus machados. Al\233m[ENTER]disso era um machado bastante bom. Talvez o[ENTER]possas recuperar? "
gameforge.subquest_22._60_select = "Recusar "
gameforge.subquest_22._70_say = "Queres mesmo desistir de procurar? "
gameforge.subquest_22._80_say = "Oh, volta quando tiveres tempo. "
gameforge.subquest_22._90_say = "\201 demasiado dif\237cil para ti? Bom, suponho que n\227o[ENTER]h\225 nada que eu possa fazer. Mas tem cuidado, os[ENTER]Selvagens andam por todo o lado. "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Procura o Yu-Hwan "
gameforge.subquest_23._10_targetVid = "Por favor procura pelo meu irm\227o mais velho! "
gameforge.subquest_23._110_targetVid = "Dirige-te ao Yu-Hwan "
gameforge.subquest_23._120_say = "O irm\227o mais velho da Mirine desapareceu de novo.[ENTER]Ele escreveu-lhe uma carta h\225 algum tempo, mas[ENTER]desde ent\227o nunca mais teve not\237cias dele.[ENTER]Vai ter com o Yu-Hwan e pergunta-lhe se ele sabe[ENTER]algo sobre o irm\227o mais velho da Mirine. "
gameforge.subquest_23._130_npcChat = "Viste o irm\227o da Mirine? "
gameforge.subquest_23._140_say = "O irm\227o da Mirine? Receio que n\227o te possa ajudar[ENTER]em rela\231\227o a isso. Tamb\233m n\227o tenho tido not\237cias[ENTER]recentes acerca dele. Mal me lembro da \250ltima vez[ENTER]que o vi. Tamb\233m estou preocupado. Talvez algo[ENTER]lhe tenha acontecido?[ENTER]Vai perguntar ao ca\231ador Yang-Shin. Ele passa os[ENTER]dias de um lado para o outro e pode t\234-lo visto. "
gameforge.subquest_23._150_sendLetter = "Procura o Yang-Shin "
gameforge.subquest_23._160_targetVid = "Dirige-te ao Yang-Shin "
gameforge.subquest_23._170_say = "O Ca\231ador Yang-Shin passa a vida de um lado para[ENTER]o outro. Talvez ele tenha visto o irm\227o mais[ENTER]velho da Mirine. "
gameforge.subquest_23._180_npcChat = "Viste o irm\227o da Mirine? "
gameforge.subquest_23._190_say = "Queres dizer o irm\227o mais velho de Mirine? A[ENTER]\250ltima vez que o vi ele estava a caminho do Vale[ENTER]Seungryong para recolher ervas. Fiquei um pouco[ENTER]surpreendido, pois \233 um local muito perigoso, mas[ENTER]n\227o pensei muito no assunto. "
gameforge.subquest_23._200_say = "Devia t\234-lo impedido. Se ele ainda n\227o contactou[ENTER]ningu\233m algo lhe deve ter acontecido. Deverias ir[ENTER]ao Vale Seungryong procurar por ele. "
gameforge.subquest_23._20_npcChat = "Porque choras? "
gameforge.subquest_23._210_select = "Come\231ar busca "
gameforge.subquest_23._220_say = "Queres mesmo desistir de procurar? "
gameforge.subquest_23._230_say = "A Mirine estava mesmo muito triste. Irei voltar[ENTER]mais tarde. "
gameforge.subquest_23._240_say = "Se um irm\227o mais velho n\227o entra em contacto h\225[ENTER]algum tempo n\227o quer necessariamente dizer que[ENTER]algo lhe tenha acontecido. N\227o precisas de te[ENTER]arriscar nesse perigoso Vale s\243 porque uma[ENTER]pequena rapariga te pediu. "
gameforge.subquest_23._250_say = "A miss\227o n\227o \233 t\227o insignificante como parece. O[ENTER]Vale Seungryong \233 um local muito perigoso, mas[ENTER]fiz uma promessa e irei cumpri-la. "
gameforge.subquest_23._260_sendLetter = "O Irm\227o Desaparecido "
gameforge.subquest_23._270_targetVid = "Procura o irm\227o mais velho de Mirine no Vale[ENTER]Seungryong! "
gameforge.subquest_23._280_sayTitle = "Procura o irm\227o da Mirine "
gameforge.subquest_23._290_say = "O irm\227o da Mirine est\225 \224 procura de ervas no Vale[ENTER]Seungryong. Vai at\233 l\225 e v\234 se ele est\225 bem.[ENTER]O Teleportador ir\225 ajudar-te caso precises de um[ENTER]atalho. "
gameforge.subquest_23._300_npcChat = "O corpo! "
gameforge.subquest_23._30_say = "Uma vez trouxeste-me uma carta do meu irm\227o, n\227o[ENTER]foi? Fiquei muito grata por isso. Infelizmente[ENTER]nunca mais tive not\237cias dele desde ent\227o. O meu[ENTER]irm\227o ainda n\227o voltou. Ainda est\225 \224 procura de[ENTER]ervas. "
gameforge.subquest_23._310_say = "Est\225 aqui um homem morto. \201 jovem e magro e[ENTER]parece ter andado a recolher Ginseng. Penso que[ENTER]possa ser o irm\227o mais velho de Mirine, que eu[ENTER]procurava. O cad\225ver tem um Colar com um[ENTER]Pendente. Vou lev\225-los comigo e mostr\225-los \224[ENTER]Mirine. "
gameforge.subquest_23._320_sendLetter = "Dirige-te \224 Mirine. "
gameforge.subquest_23._330_sayTitle = "Not\237cias Tristes "
gameforge.subquest_23._340_say = "Encontraste um Pendente num cad\225ver no Vale[ENTER]Seungryong, no qual est\225 gravado o nome de[ENTER]Mirine.[ENTER]Dirige-te a Mirine e d\225-lhe o Colar e o Pendente. "
gameforge.subquest_23._350_npcChat = "Conheces este colar? "
gameforge.subquest_23._360_say = "Oh, este colar... O meu irm\227o costumava us\225-lo[ENTER]constantemente. Tenho um parecido. Sempre os[ENTER]us\225mos como forma de nos lembrarmos um do outro e[ENTER]encontrarmos o caminho de um para o outro. Mas...[ENTER]O meu irm\227o j\225 n\227o est\225 aqui... E apenas o colar[ENTER]encontrou o caminho de volta para mim. "
gameforge.subquest_23._370_say = "Meu pobre irm\227o...[ENTER]E tudo por causa desta guerra. O meu irm\227o vendia[ENTER]ervas porque era a \250nica coisa que nos dava[ENTER]dinheiro para nos sustentarmos. Dava para[ENTER]comprarmos comida. Ele trabalhava arduamente para[ENTER]que eu tivesse o suficiente para comer. E agora[ENTER]ele est\225 morto. Por causa de mim... "
gameforge.subquest_23._380_say = "Obrigado por me trazeres isto. Agora pelo menos[ENTER]sei o que aconteceu. Se n\227o me tivesses ajudado[ENTER]nunca o teria descoberto. "
gameforge.subquest_23._390_say = "Irei tratar muito bem do pendente do meu irm\227o e[ENTER]irei dar-te o Colar como sinal da minha gratid\227o.[ENTER]Tenho a certeza que ter\225 alguma utilidade.[ENTER]Obrigado pela tua ajuda. De certeza que ele agora[ENTER]est\225 no C\233u, n\227o achas? "
gameforge.subquest_23._400_sayReward = "Recebeste 600.000 Pontos de Experi\234ncia.[ENTER]Recebeste 35.000 Yang. "
gameforge.subquest_23._40_say = "Estou preocupada com ele porque nunca mais recebi[ENTER]not\237cias. Desculpa, mas podes procurar o meu[ENTER]irm\227o de novo? O Yu-Hwan pode saber alguma coisa[ENTER]dele. "
gameforge.subquest_23._50_select = "Recusar "
gameforge.subquest_23._60_say = "Queres parar de procurar? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Ficarei aqui \224 espera. Talvez mais tarde? Por[ENTER]favor? "
gameforge.subquest_23._80_say = "N\227o tenho tempo![ENTER]Boa sorte para o teu irm\227o. "
gameforge.subquest_23._90_say = "N\227o seria bom abandonar uma rapariga triste. E a[ENTER]miss\227o n\227o dever\225 demorar muito. Vamos l\225! "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Queres desistir desta miss\227o? "
gameforge.subquest_24._10_targetVid = "Bolos de Arroz da Yu-Rang "
gameforge.subquest_24._110_say = "Se tiveres tempo mais tarde, por favor vem ter[ENTER]comigo. N\227o sei como iremos sobreviver sem vender[ENTER]Bolos de Arroz. "
gameforge.subquest_24._120_say = "Tudo gira \224 volta dos ricos que atiram Yang das[ENTER]janelas como se n\227o houvesse amanh\227. Mesmo quando[ENTER]n\227o sabemos se amanh\227 teremos comida na mesa![ENTER]Vai-te embora! "
gameforge.subquest_24._130_say = "Obrigado. \201 muito simp\225tico da tua parte. Irei[ENTER]esperar at\233 voltares. "
gameforge.subquest_24._140_sendLetter = "O Bolo de Arroz Roubado "
gameforge.subquest_24._150_say = "Recupera o Bolo de Arroz das Aranhas Beb\233 no[ENTER]Deserto. Se demorares demasiado tempo, as aranhas[ENTER]ir\227o comer o Bolo de Arroz, ou ele ir\225 ficar[ENTER]demasiado seco pela exposi\231\227o ao sol.[ENTER]Despacha-te! "
gameforge.subquest_24._160_sayReward = "Mata as Beb\233s Aranha no Deserto Yongbi. "
gameforge.subquest_24._170_npcChat = "Sobre o teu Bolo de Arroz roubado... "
gameforge.subquest_24._180_say = "O qu\234, as Aranhas comeram o Bolo de Arroz? Oh[ENTER]n\227o! Ou secou?! Por favor n\227o me digas que tudo[ENTER]est\225 perdido! "
gameforge.subquest_24._190_select = "N\227o, est\225 tudo bem. "
gameforge.subquest_24._200_select = "Desisto. "
gameforge.subquest_24._20_npcChat = "O teu Bolo de Arroz roubado... "
gameforge.subquest_24._210_say = "Talvez afinal n\227o o consigas fazer? O Bolo de[ENTER]Arroz \233 muito importante para mim. Imploro-te.[ENTER][ENTER]Queres desistir da miss\227o de encontrar o Bolo de[ENTER]Arroz da Yu-Rang no deserto? "
gameforge.subquest_24._220_select = "Vou tentar de novo. "
gameforge.subquest_24._230_select = "Desculpa, \233 demasiado dif\237cil. "
gameforge.subquest_24._240_say = "N\227o posso acreditar. Quem nos ir\225 ajudar agora? "
gameforge.subquest_24._250_say = "V\225 l\225! Ajuda-me! "
gameforge.subquest_24._260_say = "Ent\227o vais continuar \224 procura? Obrigado! Por[ENTER]favor tenta encontrar o Bolo de Arroz o mais[ENTER]r\225pido poss\237vel. "
gameforge.subquest_24._270_say = "N\227o, \233 demasiado tarde. Mesmo que o recuperes, j\225[ENTER]dever\225 estar completamente seco. N\227o o poderei[ENTER]vender. "
gameforge.subquest_24._280_say = "Olhas para o ch\227o e v\234s o Bolo de Arroz deixado[ENTER]pelas Aranhas. \201 demasiado tarde. Est\225 seco. "
gameforge.subquest_24._290_sayReward = "Demoraste demasiado tempo \224 procura do Bolo de[ENTER]Arroz. O Bolo ficou completamente seco.[ENTER]Falhaste a miss\227o. "
gameforge.subquest_24._300_sendLetter = "Regressa \224 Yu-Rang "
gameforge.subquest_24._30_say = "Hey! Como est\225 a tua m\227e? "
gameforge.subquest_24._310_targetVid = "Regressa \224 Yu-Rang "
gameforge.subquest_24._320_say = "Resgataste o Bolo de Arroz da Yu-Rang das patas[ENTER]das Aranhas mesmo a tempo. Leva-o at\233 ela. "
gameforge.subquest_24._330_npcChat = "Est\225s com sorte. Aqui tens o Bolo de Arroz "
gameforge.subquest_24._340_say = "\201s excelente! Nem sei o que dizer... Agora posso[ENTER]vend\234-lo amanh\227 na minha loja! Muito obrigado! "
gameforge.subquest_24._350_sayReward = "Recebeste 900.000 Pontos de Experi\234ncia. "
gameforge.subquest_24._360_sayReward = "Recebeste 25.000 Yang. "
gameforge.subquest_24._40_say = "Oh! Ela est\225 melhor, obrigado por perguntares. "
gameforge.subquest_24._50_say = "Pareces estar com problemas. Que se passa? "
gameforge.subquest_24._60_say = "Vendo Bolos de Arroz aqui todos os dias, mas hoje[ENTER]algo terr\237vel aconteceu. Aranhas gigantescas[ENTER]apareceram e assaltaram-me. Agora n\227o tenho[ENTER]nenhum Bolo de Arroz para vender. Como vou[ENTER]sobreviver? A minha fam\237lia n\227o tem outra forma[ENTER]de sustento... "
gameforge.subquest_24._70_select = "Vou encontr\225-lo por ti. "
gameforge.subquest_24._80_select = "Desculpa, n\227o tenho tempo. "
gameforge.subquest_24._90_sayTitle = "Pergunta: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "O que \233 que tu gostas? "
gameforge.subquest_25._10_targetVid = "Hu-Ahn-So "
gameforge.subquest_25._110_say = "Bom, desde que perdi o meu marido na guerra me[ENTER]tenho sentido um pouco sozinha. Hum... O que me[ENTER]poderia fazer sentir melhor? Bem... O meu marido[ENTER]passava a vida a trazer-me flores. "
gameforge.subquest_25._120_say = "Eram Flores que crescem muito longe da nossa[ENTER]vila. Apesar de ser perigoso, ele arranjava-me[ENTER]sempre algumas. Mas desde que o meu marido morreu[ENTER]nunca mais vi essas flores. E \233 em dias como este[ENTER]que sinto mais falta dele. Oh, o que acabei de[ENTER]dizer? Isto foi inapropriado. Por favor esquece o[ENTER]que acabei de dizer. "
gameforge.subquest_25._130_qSetTitle = "Regressa a Hu-Ahn-So "
gameforge.subquest_25._140_makequestbutton = "Regressa a Hu-Ahn-So "
gameforge.subquest_25._150_targetVid = "Hu-Ahn-So "
gameforge.subquest_25._160_say = "A Ariyoung tem saudades das Flores que o marido[ENTER]lhe trazia. Vai ter com o Hu-Ahn-So e conta-lhe[ENTER]sobre isso. "
gameforge.subquest_25._170_npcChat = "A prenda para a Ariyoung... "
gameforge.subquest_25._180_say = "Ent\227o, de que \233 que a Ariyoung gosta? N\227o lhe[ENTER]contaste nada sobre mim, pois n\227o? Hmm, ela gosta[ENTER]de um tipo de Flores que o seu marido costumava[ENTER]trazer? Isso fica muito longe da vila. Ser\225[ENTER]dif\237cil para mim ir at\233 l\225. E podem existir[ENTER]monstros no caminho, tigres por exemplo. "
gameforge.subquest_25._190_say = "Exactamente! Porque n\227o me d\225s uma ajuda? Porque[ENTER]n\227o vais colher as Flores por mim? Seria \243ptimo[ENTER]para ambos.[ENTER]O qu\234? Isto n\227o era parte do neg\243cio? V\225 l\225, n\227o[ENTER]v\234s quanto me estou a esfor\231ar para conseguir o[ENTER]seu amor? Anda l\225, ajuda-me! Irei recompensar-te[ENTER]com bastante Yang! "
gameforge.subquest_25._200_select = "Recusar "
gameforge.subquest_25._20_npcChat = "Oh, minha querida Ariyoung "
gameforge.subquest_25._210_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_25._220_say = "Raios! Como \233 que eu vou conseguir essas Flores[ENTER]agora?[ENTER]Por favor, volta se mudares de ideias. "
gameforge.subquest_25._230_say = "Nunca amaste algu\233m? Tens ideia do que sinto pela[ENTER]Ariyoung? Oh, Ariyoung... "
gameforge.subquest_25._240_say = "Muito obrigado! Por favor traz-me essas Flores. "
gameforge.subquest_25._250_qSetTitle = "Vai buscar as Flores "
gameforge.subquest_25._260_targetVid = "Flores "
gameforge.subquest_25._270_sayTitle = "Flores para a Ariyoung "
gameforge.subquest_25._280_say = "Para ajudares o Hu-Ahn-So a contar \224 Ariyoung[ENTER]aquilo que ele sente, tens de colher algumas[ENTER]flores especiais. As flores podem ser encontradas[ENTER]no canto do mapa da vila vizinha. "
gameforge.subquest_25._290_npcChat = "N\227o encontrei as Flores. "
gameforge.subquest_25._300_say = "Hm, raios...[ENTER]Queria contar-lhe o que sinto. \201 t\227o dif\237cil[ENTER]conseguir o seu amor. Minha querida Ariyoung... "
gameforge.subquest_25._30_say = "Conheces a Ariyoung? Bom, ela \233... n\227o, ela era[ENTER]casada. O seu marido morreu h\225 alguns anos, e[ENTER]desde ent\227o ela tem vivido sozinha. Ela tem uma[ENTER]personalidade impressionante e ainda \233 uma mulher[ENTER]muito bonita. Ela casou-se muito cedo e eu[ENTER]cheguei tarde de mais...  "
gameforge.subquest_25._310_select = "Vou tentar de novo. "
gameforge.subquest_25._320_select = "Desisto "
gameforge.subquest_25._330_say = "Queres desistir desta miss\227o? "
gameforge.subquest_25._340_say = "Oh...[ENTER]Se mudares de ideias...[ENTER]Estarei por aqui...[ENTER]Por favor ajuda-me... "
gameforge.subquest_25._350_say = "Ir\225 o meu amor acabar assim? Ariyoung... "
gameforge.subquest_25._360_say = "Muito obrigado. Tamb\233m deves ser uma pessoa[ENTER]apaixonada, para compreenderes o que sinto pela[ENTER]Ariyoung. "
gameforge.subquest_25._370_npcChat = "As Flores favoritas da Ariyoung "
gameforge.subquest_25._380_say = "Estas Flores parecem exactamente aquelas que a[ENTER]Ariyoung descreveu. Vou levar algumas. "
gameforge.subquest_25._390_qSetTitle = "Regressa a Hu-Ahn-So "
gameforge.subquest_25._400_say = "Encontrei as flores favoritas das Ariyoung e[ENTER]colhi algumas. Devia lev\225-las ao Hu-Ahn-So para[ENTER]que ele possa declarar o seu amor \224 Ariyoung. "
gameforge.subquest_25._40_say = "Mas o seu marido morreu na guerra. \201 por isso que[ENTER]ela \233 uma vi\250va t\227o jovem. Quero que ela saiba o[ENTER]que eu sinto! Sei que \233 um pedido ego\237sta, mas[ENTER]podes ajudar-me? "
gameforge.subquest_25._410_npcChat = "Aqui est\227o as flores favoritas da Ariyoung "
gameforge.subquest_25._420_say = "Oh, s\227o estas as Flores? Agora posso contar \224[ENTER]Ariyoung o que sinto! Achas que \233 demasiado cedo[ENTER]para isso? Oh bom, n\227o interessa se \233 demasiado[ENTER]cedo. Tenho de contar-lhe, caso contr\225rio irei[ENTER]rebentar. Aqui tens a tua recompensa, e muito[ENTER]obrigado! "
gameforge.subquest_25._430_sayReward = "Recebeste 400.000 Pontos de Experi\234ncia. "
gameforge.subquest_25._440_sayReward = "Recebeste 12.000 Yang. "
gameforge.subquest_25._50_say = "Achas que ela gosta de homens esbeltos? Ou de[ENTER]roupas com estilo?[ENTER]Primeiro preciso de descobrir os gostos dela,[ENTER]apenas ent\227o serei capaz de falar com ela. Podes[ENTER]descobrir isso por mim, por favor? Mas n\227o lhe[ENTER]contes nada sobre mim! Imploro-te![ENTER]Irei dar-te uma recompensa se o fizeres. "
gameforge.subquest_25._60_qSetTitle = "Vai ter com a Ariyoung "
gameforge.subquest_25._70_makequestbutton = "Vai ter com a Ariyoung "
gameforge.subquest_25._80_targetVid = "Dirige-te \224 Ariyoung "
gameforge.subquest_25._90_say = "O Hu-Ahn-So est\225 apaixonado pela Ariyoung. Para o[ENTER]ajudares a contar \224 Ariyoung aquilo que sente,[ENTER]tens de descobrir aquilo de que ela gosta.[ENTER]Pergunta \224 Ariyoung do que \233 que ela gosta, mas[ENTER]tem cuidado para n\227o revelares demasiado! "
gameforge.subquest_26 = {}
gameforge.subquest_26._100_say = "Tu \233 que perdes. Ir\225s perder uma oportunidade[ENTER]\250nica na vida! "
gameforge.subquest_26._10_targetVid = "Dirige-te ao Guarda do Armaz\233m "
gameforge.subquest_26._110_say = "Muito bem! Sabia que irias mostrar interesse. Se[ENTER]conseguires algumas volta aqui e partilha-as[ENTER]comigo! "
gameforge.subquest_26._120_sendLetter = "Dirige-te ao Oct\225vio "
gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "Dirige-te ao Oct\225vio "
gameforge.subquest_26._150_say = "O Guarda do Armaz\233m deu-te um bom conselho: a[ENTER]Sopa de Pernas de R\227 \233 um rem\233dio excelente para[ENTER]a fraqueza e ossos cansados. Pergunta ao Oct\225vio[ENTER]se ele pode fazer esta sopa. "
gameforge.subquest_26._160_npcChat = "Sopa de Pernas de R\227? "
gameforge.subquest_26._170_say = "Sopa de Pernas de R\227... Sim, eu antes fazia[ENTER]disso. Mas j\225 n\227o o fa\231o. Antes eu n\227o tinha medo[ENTER]dos monstros, por isso conseguia arranjar Pernas[ENTER]Traseiras de R\227 com facilidade. "
gameforge.subquest_26._180_say = "Mas agora... Estou demasiado velho e cansado. Com[ENTER]essa sopa eu poderia recuperar alguma energia,[ENTER]mas as R\227s n\227o s\227o f\225ceis de matar. Se me[ENTER]trouxeres as Pernas Traseiras de R\227 para a sopa,[ENTER]irei fazer a melhor Sopa de Pernas de R\227 que o[ENTER]mundo j\225 provou! "
gameforge.subquest_26._190_select = "Claro, irei faz\234-lo. "
gameforge.subquest_26._200_select = "N\227o o consigo fazer. "
gameforge.subquest_26._20_npcChat = "Como est\225s? "
gameforge.subquest_26._210_say = "Queres desistir desta miss\227o? "
gameforge.subquest_26._220_say = "Est\225s ocupado? Volta se mudares de ideias. "
gameforge.subquest_26._230_say = "A minha Sopa n\227o \233 muito conhecida. Se a[ENTER]conhecesses irias aceitar a Miss\227o...[ENTER]Ah, bom... Adeus. "
gameforge.subquest_26._240_say = "Ent\227o despacha-te! Irei preparar tudo para a Sopa[ENTER]de Pernas de R\227. "
gameforge.subquest_26._250_sendLetter = "Recebeste Pernas Traseiras de R\227 "
gameforge.subquest_26._260_targetVid = "Oct\225vio: "
gameforge.subquest_26._270_sendLetter = "Obt\233m as Pernas Traseiras de R\227 "
gameforge.subquest_26._280_say = "J\225 conseguiste apanhar as Pernas Traseiras de R\227.[ENTER]Regressa ao Oct\225vio. "
gameforge.subquest_26._290_sayTitle = "Mata L\237deres R\227 de \193rvore "
gameforge.subquest_26._300_say = "O Oct\225vio precisa de Pernas Traseiras de R\227 para[ENTER]fazer a sua Sopa de Pernas de R\227. Podes obt\234-las[ENTER]ca\231ando os L\237deres R\227 de \193rvore no Templo Hwang. "
gameforge.subquest_26._30_sayTitle = "Guarda do Armaz\233m "
gameforge.subquest_26._310_npcChat = "N\227o posso fazer isto agora. "
gameforge.subquest_26._320_say = "O que se passa? Quando eu era da tua idade[ENTER]conseguia arranjar cerca de 10 Pernas Traseiras[ENTER]de R\227 por dia! "
gameforge.subquest_26._330_select = "Tenta de novo "
gameforge.subquest_26._340_say = "Est\225s cansado? Porque n\227o descansas um pouco e[ENTER]tentas mais tarde? "
gameforge.subquest_26._350_say = "Poderia fazer bom uso dessa Sopa de Pernas de R\227.[ENTER]Mas parece que isso n\227o vai acontecer. \201 pena.[ENTER]Adeus! "
gameforge.subquest_26._360_say = "Ent\227o n\227o fiques por aqui e vai! A \225gua j\225 est\225 a[ENTER]ferver e tudo est\225 a postos! "
gameforge.subquest_26._370_targetVid = "Dirige-te ao Oct\225vio "
gameforge.subquest_26._380_say = "Agora, a isso \233 que eu chamo umas Pernas[ENTER]Traseiras de R\227. Costumavam ser mais pequenas,[ENTER]mas tenho a certeza que estas tamb\233m ir\227o saber[ENTER]bem. Espera um momento...[ENTER]J\225 cheira muito bem. Mais uma pitada de sal...[ENTER]Certo! Aqui tens a tua por\231\227o. Hahaha, agora[ENTER]tenho energia para uma semana inteira de[ENTER]trabalho. "
gameforge.subquest_26._390_say = "E n\227o contes nada a ningu\233m. Muito menos ao[ENTER]Guarda do Armaz\233m. Ele gosta de falar, e se as[ENTER]propriedades desta sopa se tornarem conhecidas[ENTER]n\227o descansarei um minuto porque todos ir\227o[ENTER]querer prov\225-la. "
gameforge.subquest_26._400_sayReward = "Recebeste 5.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_26._40_say = "Ultimamente n\227o me tenho sentido muito bem. O meu[ENTER]corpo j\225 n\227o \233 o que era. Quando era jovem podia[ENTER]trabalhar at\233 de madrugada, todos os dias da[ENTER]semana, enquanto consumia \225lcool. Agora j\225 \233 um[ENTER]cabo dos trabalhos para me levantar de manh\227.[ENTER]Preciso de um caldeir\227o inteiro de Sopa de Pernas[ENTER]de R\227 para recuperar a minha energia. "
gameforge.subquest_26._410_sayReward = "Recebeste 50.000 Yang. "
gameforge.subquest_26._50_say = "N\227o sabes o que \233 uma Sopa de Pernas de R\227?[ENTER]Quando algu\233m come uma ta\231a cheia fica logo[ENTER]acordado e cheio de energia. At\233 \233 capaz de[ENTER]trabalhar uma semana inteira de seguida sem se[ENTER]cansar![ENTER]O Oct\225vio costumava fazer esta sopa, mas por[ENTER]alguma raz\227o deixou de a fazer h\225 algum tempo. "
gameforge.subquest_26._60_select = "Vou falar com o Oct\225vio. "
gameforge.subquest_26._70_select = "Estou ocupado. "
gameforge.subquest_26._80_say = "Queres desistir desta miss\227o? "
gameforge.subquest_26._90_say = "Ok, se est\225s ocupado volta quando tiveres tempo. "
gameforge.subquest_27 = {}
gameforge.subquest_27._100_say = "Ele devia ter vergonha de se intitular pai! Se eu[ENTER]o encontrar que Deus tenha miseric\243rdia da sua[ENTER]alma! Acredita, n\227o estou a exagerar. Pergunta[ENTER]aos ouros alde\245es, eles concordam comigo. "
gameforge.subquest_27._10_targetVid = "Sr. Soon: "
gameforge.subquest_27._110_targetVid = "Loja Geral: "
gameforge.subquest_27._120_makequestbutton = "Dirige-te \224 Negociadora da Loja Geral. "
gameforge.subquest_27._130_say = "Talvez a Negociadora da Loja Geral saiba aquilo[ENTER]que o Sr. Soon anda a tramar. Vai ter com ela e[ENTER]pergunta-lhe se ouviu algo do Sr. Soon. "
gameforge.subquest_27._140_npcChat = "O que se passa com o Sr. Soon? "
gameforge.subquest_27._150_say = "Ontem ele veio aqui e perguntou sobre o Livro do[ENTER]Templo Secreto. Ele n\227o tinha Yang, por isso[ENTER]apenas deu uma vista de olhos. Deve ser muito[ENTER]importante para ele, para estar a ignorar a sua[ENTER]fam\237lia desta forma. Porque ser\225 que ele est\225 t\227o[ENTER]interessado? "
gameforge.subquest_27._160_sayTitle = "Loja Geral: "
gameforge.subquest_27._170_say = "Tenho pena da Aranyo. Ela n\227o se casou com o Sr.[ENTER]Soon para ter de trabalhar dia e noite. Tenho a[ENTER]certeza de que ela n\227o estava \224 espera de ter de[ENTER]sustentar a fam\237lia sozinha.[ENTER]Devias falar com ele. Quem sabe, talvez ele[ENTER]finalmente compreenda o que est\225 a fazer de[ENTER]errado. "
gameforge.subquest_27._180_makequestbutton = "Vai ter com o Sr. Soon "
gameforge.subquest_27._190_qSetTitle = "Vai ter com o Sr. Soon "
gameforge.subquest_27._200_targetVid = "O Sr. Soon de novo "
gameforge.subquest_27._20_npcChat = "A alegria da leitura "
gameforge.subquest_27._210_say = "Dirige-te ao Sr. Soon[ENTER]Dirige-te ao Sr. Soon e pergunta-lhe sobre o[ENTER]Livro do Templo Secreto. "
gameforge.subquest_27._220_npcChat = "O que \233 o Livro do Templo Secreto? "
gameforge.subquest_27._230_say = "Tu sabes que j\225 li todos os livros existentes \224[ENTER]face da terra. Recentemente ouvi falar de um[ENTER]Livro do Templo Secreto. Rumores dizem que esse[ENTER]Livro cont\233m todos os segredos do Templo da[ENTER]Escurid\227o. Tamb\233m dever\225 explicar como \233 poss\237vel[ENTER]algu\233m tornar-se um santo. "
gameforge.subquest_27._240_say = "Quero mesmo ler esse livro. Podes arranj\225-lo por[ENTER]mim? Se o fizeres irei dar-te algo em troca, nem[ENTER]que tenha de vender a minha casa. "
gameforge.subquest_27._250_select = "Irei faz\234-lo! "
gameforge.subquest_27._260_select = "N\227o posso, desculpa. "
gameforge.subquest_27._270_say = "Queres desistir desta miss\227o? "
gameforge.subquest_27._280_say = "Anda l\225, n\227o queres ajudar-me? Se n\227o o fizeres[ENTER]agora, pelo menos volta mais tarde. Ficarei aqui[ENTER]\224 tua espera. "
gameforge.subquest_27._290_say = "N\227o queres mesmo ajudar-me? Precisas de f\233rias[ENTER]hein... este livro \233 muito importante para mim...[ENTER]O que fa\231o agora? Raios! "
gameforge.subquest_27._300_say = "Obrigado, ficarei \224 espera. "
gameforge.subquest_27._30_say = "Gostas de ler tanto quanto eu? Palavras que se[ENTER]juntam para formar frases que por sua vez se[ENTER]combinam formando livros. Que maravilhoso! E a[ENTER]pura alegria de algu\233m que escreve um livro para[ENTER]que outras pessoas o leiam! N\227o h\225 nada melhor[ENTER]que isso! "
gameforge.subquest_27._310_makequestbutton = "Encontraste o Livro do Templo Secreto "
gameforge.subquest_27._320_qSetTitle = "Encontraste o Livro do Templo Secreto. Regressa[ENTER]ao Sr. Soon. "
gameforge.subquest_27._330_targetVid = "Regressa ao Sr. Soon "
gameforge.subquest_27._340_makequestbutton = "Derrota os Fan\225ticos Negros "
gameforge.subquest_27._350_sayTitle = "Mataste os Fan\225ticos Negros. "
gameforge.subquest_27._360_say = "Entrega o Livro do Templo Secreto ao Sr. Soon. "
gameforge.subquest_27._370_say = "O Sr. Soon tem um grande interesse no Livro do[ENTER]Templo Secreto. Se matares Fan\225ticos Negros[ENTER]poder\225s conseguir encontrar o Livro. "
gameforge.subquest_27._380_npcChat = "O Livro do Templo Secreto "
gameforge.subquest_27._390_say = "Oh, \233 isso! Muito obrigado![ENTER]Aqui tens a tua recompensa.[ENTER]Agora deixa-me, que tenho de ler! "
gameforge.subquest_27._400_sayReward = "Recebeste 850.000 Pontos de Experi\234ncia. "
gameforge.subquest_27._40_say = "A vida pulsa por entre as p\225ginas deste livro![ENTER]Conhecimentos recentes e sabedorias antigas vivem[ENTER]aqui! Imagina qu\227o cinzenta a minha vida seria[ENTER]sem livros...[ENTER]Mas infelizmente... A minha mulher n\227o compreende[ENTER]isto. Podes tentar convenc\234-la de que isto \233 algo[ENTER]bom? "
gameforge.subquest_27._410_sayReward = "Recebeste 20.000 Yang. "
gameforge.subquest_27._420_say = "Hey... Ainda n\227o o conseguiste? Se come\231as uma[ENTER]miss\227o devias tentar termin\225-la.[ENTER]Agora acaba a miss\227o! "
gameforge.subquest_27._430_say = "Os Fan\225ticos Negros n\227o devem ser subestimados.[ENTER]Tenta de novo mais tarde. "
gameforge.subquest_27._440_say = "Bem, ent\227o terei de pedir ajuda a outra pessoa.[ENTER]Adeus. "
gameforge.subquest_27._450_say = "Obrigado, ficarei \224 espera. Mal posso esperar[ENTER]para o ter nas minhas m\227os e o ler. "
gameforge.subquest_27._50_makequestbutton = "Dirige-te \224 Aranyo  "
gameforge.subquest_27._60_sayTitle = "Dirige-te \224 Aranyo  "
gameforge.subquest_27._70_say = "Dirige-te \224 Aranyo e pergunta-lhe sobre o seu[ENTER]marido. "
gameforge.subquest_27._80_npcChat = "Porque est\225s t\227o zangada? "
gameforge.subquest_27._90_say = "Zangada? Estou quase a explodir de f\250ria! O meu[ENTER]marido vai trabalhar? N\227o. Ele traz Yang para[ENTER]casa? N\227o. Em vez disso ele esconde-se algures[ENTER]por a\237 com o nariz metido nas p\225ginas de um[ENTER]livro! Alguma vez ouviste falar de algo assim? Um[ENTER]livro pode comprar-nos roupas? Pode arranjar-nos[ENTER]comida? "
