gameforge.subquest_30._140_sayTitle = "Arranjar Min\233rios para novas armas "
gameforge.subquest_30._150_say = "O Ferreiro precisa de Min\233rios para produzir um[ENTER]novo tipo de armas. Ele precisa de 100 unidades[ENTER]de Min\233rio d'Ouro, 100 unidades de Min\233rio de[ENTER]Prata e 100 unidades de Min\233rio de \201bano.[ENTER]Dep\243sitos de Min\233rio podem ser encontrados[ENTER]espalhados pelo mapa. Mas tamb\233m podes negociar,[ENTER]trocando ou comprando, com outros jogadores. "
gameforge.subquest_30._160_npcChat = "Recolhi os Min\233rios para ti. "
gameforge.subquest_30._170_say = "Isso n\227o chega. Preciso de 100 unidades de[ENTER]Min\233rio d'Ouro, 100 unidades de Min\233rio de Prata[ENTER]e 100 unidades de Min\233rio de \201bano. "
gameforge.subquest_30._180_select = "Tentar de novo "
gameforge.subquest_30._190_select = "Desistir "
gameforge.subquest_30._200_say = "Queres mesmo desistir para sempre? "
gameforge.subquest_30._20_say = "Hey, tu! Sim, estou a falar contigo! J\225 n\227o \233s um[ENTER]principiante. E porqu\234? Porque te dei tarefas[ENTER]complicadas! Foi apenas para teu bem, hehehe. Mas[ENTER]agora tenho um verdadeiro favor para te pedir. "
gameforge.subquest_30._210_say = "\201 dif\237cil obter min\233rios, n\227o \233? A sorte apenas[ENTER]sorri \224queles que trabalham arduamente. E que tal[ENTER]fazeres uma pausa e tentares de novo mais tarde? "
gameforge.subquest_30._220_say = "Que pena. Era uma ideia brilhante.[ENTER]Oh bom, que raio. Adeus! "
gameforge.subquest_30._230_say = "Se te esfor\231ares, brevemente ter\225s conseguido[ENTER]reunir tudo. Boa sorte! "
gameforge.subquest_30._240_say = "Oh, j\225 reuniste tudo! Hahaha! J\225 estou a ver que[ENTER]tudo ir\225 correr bem.[ENTER]Espera um minuto, n\227o demorarei muito.[ENTER]E c\225 vamos! "
gameforge.subquest_30._250_say = "Hmm, est\225 terminada. Por vezes at\233 me surpreendo[ENTER]com o meu pr\243prio talento. Aqui tens a tua arma.[ENTER]\201 nova, por isso toma bem conta dela! "
gameforge.subquest_30._260_sayReward = "Recebeste 200.000 Pontos de Experi\234ncia. "
gameforge.subquest_30._270_sayReward = "Recebeste 20.000 Yang. "
gameforge.subquest_30._280_sayReward = "Recebeste uma Espada de Prata+3 "
gameforge.subquest_30._290_sayReward = "Recebeste um Leque Aqu\225tico+3 "
gameforge.subquest_30._30_say = "Quero tentar forjar uma nova arma, mas \233-me muito[ENTER]dif\237cil obter os materiais necess\225rios. Podes[ENTER]faz\234-lo por mim? Irei recompensar-te com a[ENTER]primeira arma que forjar. "
gameforge.subquest_30._40_say = "Preciso de 100 unidades de Min\233rio d'Ouro, 100[ENTER]unidades de Min\233rio de Prata, 100 unidades de[ENTER]Min\233rio de \201bano. Parece mais do que na realidade[ENTER]\233. Podes obter bastantes minerais de uma s\243 vez[ENTER]nos Veios. Se ainda assim for demasiado dif\237cil[ENTER]para ti, podes sempre negociar com algu\233m. Faz[ENTER]como entenderes. Desejo-te sucesso! "
gameforge.subquest_30._50_select = "Recusar "
gameforge.subquest_30._60_say = "Queres desistir desta miss\227o? "
gameforge.subquest_30._70_say = "N\227o precisas de ter pressa. Vem ter comigo se[ENTER]mudares de ideias. "
gameforge.subquest_30._80_say = "Que pena. Era uma ideia brilhante.[ENTER]Oh bom, que raio. Adeus! "
gameforge.subquest_30._90_say = "Oh! Vais faz\234-lo?[ENTER]\201s um bom amigo! "
