gameforge.subquest_31._170_select = "Tentar de novo "
gameforge.subquest_31._180_select = "Desistir "
gameforge.subquest_31._190_say = "Queres desistir desta miss\227o? "
gameforge.subquest_31._200_say = "\201 demasiado dif\237cil? \201 claro que a sorte n\227o \233[ENTER]tudo, tamb\233m \233 preciso trabalho \225rduo. Porque n\227o[ENTER]tentas de novo mais tarde? "
gameforge.subquest_31._20_npcChat = "Ainda precisas de mais Min\233rios? "
gameforge.subquest_31._210_say = "Bom, l\225 se v\227o os meus planos para uma nova[ENTER]armadura. Era uma ideia que poderia mudar o[ENTER]mundo! Que pena... "
gameforge.subquest_31._220_say = "S\234 forte! Sei que o conseguir\225s fazer! "
gameforge.subquest_31._230_say = "Fant\225stico. \201s realmente bom a obter materiais.[ENTER]Agora presta aten\231\227o. Aqui... E aqui... E agora[ENTER]vou deixar arrefecer um pouco...[ENTER]Toma, isto \233 para ti, uma recompensa pelo teu[ENTER]esfor\231o. At\233 breve! "
gameforge.subquest_31._240_sayReward = "Recebeste 200.000 Pontos de Experi\234ncia. "
gameforge.subquest_31._250_sayReward = "Recebeste 20.000 Yang. "
gameforge.subquest_31._260_sayReward = "Recebeste uma Armadura Le\227o+3. "
gameforge.subquest_31._270_sayReward = "Recebeste um Quimono Formiga Rubi+3. "
gameforge.subquest_31._280_sayReward = "Recebeste uma Armadura Fantasma+3. "
gameforge.subquest_31._290_sayReward = "Recebeste um Robe Amoroso+3. "
gameforge.subquest_31._30_say = "Ol\225, tens um minuto para mim?[ENTER]Estou muito agradecido por me teres ajudado a[ENTER]forjar uma nova arma. Mas agora preciso de te[ENTER]pedir um favor mais uma vez. Desta vez quero[ENTER]fazer novas armaduras. Depois de ter forjado uma[ENTER]nova arma \233 \243bvio que tamb\233m preciso de fazer uma[ENTER]nova armadura. "
gameforge.subquest_31._40_say = "\201 claro que irei precisar de materiais para fazer[ENTER]a nova armadura. Podes recolh\234-los por mim?[ENTER]Como recompensa irei dar-te a primeira armadura[ENTER]que completar.[ENTER]Desta vez preciso de 100 unidades de Min\233rio de[ENTER]Cobre, 100 unidades de Min\233rio de \201bano e 100[ENTER]unidades de Pe\231a de P\233rola. J\225 deverias sab\234-lo.[ENTER]Desejo-te sucesso! "
gameforge.subquest_31._50_select = "Aceitar "
gameforge.subquest_31._60_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_31._70_say = "Porque est\225s a hesitar? Regressa quando estiveres[ENTER]pronto para recolher os Min\233rios. "
gameforge.subquest_31._80_say = "T\227o pouca quantidade de Min\233rio n\227o \233 um pedido[ENTER]muito grande.[ENTER]Bom, faz como entenderes. Vai-te embora! "
gameforge.subquest_31._90_say = "Vais ajudar-me de novo? \201s uma boa pessoa.[ENTER]E n\227o te preocupes: a primeira armadura \233 tua! "
