gameforge.subquest_32._120_targetVid = "Dirige-te \224 Negociadora da Loja Geral. "
gameforge.subquest_32._130_sayReward = "Materiais para o Vendedor "
gameforge.subquest_32._140_sayReward = "O Vendedor Ambulante precisa de alguns materiais[ENTER]para um colar.[ENTER]Arranja-lhe 100 Dentes Molares dos Orcs Mago[ENTER]Elite, um Acess\243rio da Negociadora da Loja Geral[ENTER]e um Fio de Tecelagem da Ariyoung. "
gameforge.subquest_32._150_npcChat = "Preciso do Fio de Tecelagem. "
gameforge.subquest_32._160_say = "Produzir Fios de Tecelagem n\227o \233 complicado. Mas[ENTER]enquanto o fa\231o n\227o posso continuar o meu outro[ENTER]trabalho. Hoje remendei as roupas rotas da Ah-Yu[ENTER]e queria devolv\234-las. "
gameforge.subquest_32._170_say = "O que achas: Devolves as roupas \224 Ah-Yu por mim[ENTER]enquanto te arranjo um Fio de Tecelagem. De[ENTER]acordo? "
gameforge.subquest_32._180_say = "Queres desistir da Miss\227o para sempre? "
gameforge.subquest_32._190_say = "N\227o fica muito longe. Porque ainda est\225s[ENTER]hesitante? Volta quando te tiveres decidido. "
gameforge.subquest_32._200_say = "Oh, estava a contar com que tivesses algum tempo.[ENTER]Parece que terei de o fazer eu mesma. Adeus! "
gameforge.subquest_32._20_npcChat = "Sobre o colar... "
gameforge.subquest_32._210_say = "Maravilhoso, muito obrigado! D\225 os meus[ENTER]cumprimentos \224 Ah-Yu e certifica-te que n\227o[ENTER]amarrotas as roupas no caminho! Irei ficar aqui \224[ENTER]tua espera. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Quando tiveres regressado da pr\243xima vila eu j\225[ENTER]terei terminado o teu Fio de Tecelagem. N\227o te[ENTER]esqueceste das roupas da Ah-Yu, pois n\227o? Ela[ENTER]iria ficar chateada comigo por isso. "
gameforge.subquest_32._240_say = "A Ah-Yu ficou contente com as Roupas? Nesse caso[ENTER]foi um prazer fazer todo aquele trabalho \225rduo[ENTER]para ela. Aqui tens o teu Fio de Tecelagem. \201[ENTER]bastante forte e pode ser usado num diverso[ENTER]n\250mero de coisas. "
gameforge.subquest_32._250_say = "J\225 te dei um Fio de Tecelagem. Perdeste-o? "
gameforge.subquest_32._260_npcChat = "A Ariyoung envia-te estas roupas. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, que simp\225tica. Foi muito r\225pida. Temos de[ENTER]cultivar novas amizades, n\227o \233? Muitas vezes[ENTER]ajudamo-nos uma \224 outra...[ENTER]Obrigado por me teres trazido as roupas. D\225 os[ENTER]meus cumprimentos \224 Ariyoung. "
gameforge.subquest_32._290_npcChat = "Preciso de um Acess\243rio. "
gameforge.subquest_32._300_say = "Est\225s \224 procura de um Acess\243rio? Posso dar-te um[ENTER]se me ajudares.[ENTER]De momento estou a trabalhar num novo medicamento[ENTER]analg\233sico, mas preciso de um ingrediente:[ENTER]F\237gados de Tigres. S\227o muito dif\237ceis de[ENTER]arranjar.[ENTER]Preciso de 100 F\237gados de Tigres. "
gameforge.subquest_32._30_say = "N\243s, os Vendedores Ambulantes, n\227o temos uma vida[ENTER]f\225cil durante tempos de guerra. Existe mercadoria[ENTER]necess\225ria em todo o lado, mas os pedidos mudam[ENTER]t\227o rapidamente que nunca sei se tenho as coisas[ENTER]certas para vender ou n\227o. J\225 para n\227o falar dos[ENTER]longos e perigosos caminhos que tenho de[ENTER]percorrer, nos quais todos os monstros aguardam a[ENTER]passagem de viajantes descuidados. Queres ganhar[ENTER]algum Yang? Ficaria agradecido por alguma ajuda. "
gameforge.subquest_32._310_say = "Tamb\233m preciso de certas Ervas Medicinais, mas[ENTER]tamb\233m conseguir\225s obt\234-las dos Tigres. Eles[ENTER]gostam de rebolar nelas porque gostam do seu[ENTER]odor. Irei dar-te um Acess\243rio em troca das Ervas[ENTER]Medicinais e dos F\237gados de Tigres. "
gameforge.subquest_32._320_say = "Ca\231a Tigres ou Tigres Brancos "
gameforge.subquest_32._330_say = "O que dizes? Podemos fazer um acordo? "
gameforge.subquest_32._340_say = "A minha tarefa \233 muito dif\237cil para ti? N\227o[ENTER]consigo imaginar tal coisa! Vem ter comigo de[ENTER]novo quando mudares de ideias. "
gameforge.subquest_32._350_say = "Vieste de t\227o longe e agora vais desistir? Como[ENTER]quiseres...[ENTER]Tem um bom dia. "
gameforge.subquest_32._360_say = "Muito bem. Isto vai ajudar ambos, n\227o \233? Obrigado[ENTER]e boa sorte! "
gameforge.subquest_32._370_npcChat = "Posso receber o Acess\243rio agora? "
gameforge.subquest_32._380_say = "Deixa-me ver... 100 F\237gados de Tigre e Ervas[ENTER]Medicinais, est\225 aqui tudo. Obrigado![ENTER]Aqui tens, realmente mereces este Acess\243rio.[ENTER]Adeus! "
gameforge.subquest_32._390_qSetTitle = "Regressa ao Vendedor Ambulante "
gameforge.subquest_32._400_targetVid = "Regressa ao Vendedor Ambulante "
gameforge.subquest_32._40_say = "De momento os colares feitos de Dentes Molares[ENTER]dos Orcs s\227o muito requisitados. Os Dentes[ENTER]Molares s\227o grandes e duros e s\227o ideais para a[ENTER]cria\231\227o de certas j\243ias. Al\233m disso, os soldados[ENTER]acham que os Dentes Molares dos Orcs Mago Elite[ENTER]s\227o amuletos da sorte.[ENTER]Podes arranjar-me alguns desses Dentes Molares?[ENTER]100 dever\227o chegar para come\231ar. "
gameforge.subquest_32._410_sayReward = "Regressa ao Vendedor Ambulante "
gameforge.subquest_32._420_sayReward = "Finalmente conseguiste recolher todos os[ENTER]materiais para o colar. Leva-os ao Vendedor[ENTER]Ambulante. "
gameforge.subquest_32._430_npcChat = "Tenho todos os materiais! "
gameforge.subquest_32._440_sayTitle = "Vendedor Ambulante: "
gameforge.subquest_32._450_say = "Tens todos os materiais? Deixa c\225 ver...[ENTER]Sim, est\225 tudo aqui. Gra\231as \224 tua ajuda poderei[ENTER]aumentar a minha oferta de bens. Aqui tens a tua[ENTER]parte. Diverte-te.[ENTER]Venham todos! Aqui existe um pouco de tudo para[ENTER]todos! "
gameforge.subquest_32._460_sayReward = "Recebeste 1.100.000 Pontos de Experi\234ncia. "
gameforge.subquest_32._470_sayReward = "Recebeste uma Pulseira d'Ouro, um Colar d'Ouro e[ENTER]Brincos d'Ouro. "
gameforge.subquest_32._480_say = "Hmmm, desculpa mas falta algo. Entregas[ENTER]incompletas n\227o me servem de nada. Vais continuar[ENTER]a tentar? "
gameforge.subquest_32._490_say = "Queres desistir desta miss\227o? "
gameforge.subquest_32._500_say = "Obrigado por n\227o desistires t\227o facilmente.[ENTER]A sorte sorri \224queles que tentam! Ficarei aqui \224[ENTER]tua espera. "
gameforge.subquest_32._50_say = "Tamb\233m preciso de um Acess\243rio e de um Fio de[ENTER]Tecelagem. Um poder\225s obter da Negociadora da[ENTER]Loja Geral, o outro poder\225s obter da Ariyoung.[ENTER]N\227o \233 f\225cil conseguir tudo o que preciso, mas[ENTER]vender colares \233 um bom neg\243cio e ter\225s uma boa[ENTER]recompensa por me trazeres os materiais.[ENTER]O que achas? Parece-te interessante? "
gameforge.subquest_32._510_say = "A tarefa \233 demasiado dif\237cil? Bom, pelo menos[ENTER]tentaste. Caso um dia tenha uma tarefa mais[ENTER]simples irei informar-te. Adeus! "
gameforge.subquest_32._520_say = "Vais tentar novamente? Obrigado! Vou ficar \224 tua[ENTER]espera. "
gameforge.subquest_32._60_say = "Queres desistir desta miss\227o? "
gameforge.subquest_32._70_say = "Est\225s ocupado? Compreendo. Mas por favor volta[ENTER]quando tiveres tempo. "
gameforge.subquest_32._80_say = "Oh meu Deus, como irei conseguir completar todas[ENTER]as minhas tarefas?[ENTER]Adeus! "
gameforge.subquest_32._90_say = "Fant\225stico. Ficarei aqui \224 tua espera. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Encontraste um Mapa do Tesouro "
gameforge.subquest_33._10_targetVid = "Dirige-te ao Sr. Soon "
gameforge.subquest_33._110_say = "Tu ca\231aste os Deuses animais que andam nas[ENTER]redondezas da vila e encontraste as 4 partes do[ENTER]Mapa do Tesouro. Leva-as ao Soon. "
gameforge.subquest_33._120_sayTitle = "\192 ca\231a dos Deuses-Animal "
gameforge.subquest_33._130_say = "Obt\233m as 4 partes do Mapa do Tesouro ca\231ando os[ENTER]Deuses animais Lykos, Scrofa, Bera e Tigris. "
gameforge.subquest_33._140_sayReward = "(Partes do Mapa encontradas: %s ) "
gameforge.subquest_33._150_sendLetter = "O Mapa do Tesouro "
gameforge.subquest_33._160_sayTitle = "Encontraste todas as partes! "
gameforge.subquest_33._170_say = "Regressa ao Sr. Soon e diz-lhe que encontraste[ENTER]todas as partes do Mapa do Tesouro. "
gameforge.subquest_33._175_npcChat = "Tenho todas as partes do Mapa. "
gameforge.subquest_33._180_say = "Oh! Fant\225stico! Todos os quatro peda\231os juntos...[ENTER]Nunca esperei ver isto! Agora eu posso juntar os[ENTER]peda\231os para ter o mapa completo... Espera um[ENTER]momento... "
gameforge.subquest_33._190_say = "Hum... Estranho. O mapa refere que o tesouro est\225[ENTER]escondido sob a rocha perto do Idoso. N\227o consigo[ENTER]acreditar que isso esteja certo. Se assim fosse[ENTER]j\225 teria sido encontrado. Que brincadeira[ENTER]infantil esta![ENTER]De qualquer forma, queres procurar na mesma ou[ENTER]posso simplesmente queimar o mapa? "
gameforge.subquest_33._200_select = "Irei procurar "
gameforge.subquest_33._20_npcChat = "Sobre o Mapa do Tesouro... "
gameforge.subquest_33._210_select = "Queima-o "
gameforge.subquest_33._220_say = "Tens a certeza que n\227o precisas mais do mapa? "
gameforge.subquest_33._230_say = "Que hist\243ria pat\233tica![ENTER]Pe\231o desculpa por te ter enviado \224 procura dos[ENTER]peda\231os do mapa. Irei agora queim\225-los para que[ENTER]mais ningu\233m seja enganado.[ENTER]Mesmo assim, muito obrigado. Adeus. "
gameforge.subquest_33._240_say = "Porque est\225s a hesitar agora? J\225 recolheste todos[ENTER]os peda\231os do Mapa... Podias ir l\225 e dar uma[ENTER]vista de olhos. Toma, aqui tens o mapa! "
gameforge.subquest_33._250_say = "Como queiras. Eu ficaria muito surpreendido se tu[ENTER]realmente encontrasses algo mas mesmo assim[ENTER]desejo-te boa sorte! Leva o mapa! "
gameforge.subquest_33._260_say = "O Mapa foi dividido em quatro partes. Precisamos[ENTER]de todas para o completar! "
gameforge.subquest_33._270_select = "Tentar de novo "
gameforge.subquest_33._280_say = "Desistes? Bem, como queiras. Adeus. "
gameforge.subquest_33._290_say = "Eu sabia que o irias fazer. Tenho f\233 em ti! "
gameforge.subquest_33._300_targetVid = "Pedra perto do Idoso "
gameforge.subquest_33._30_say = "Hey, encontrei algumas informa\231\245es estranhas em[ENTER]alguns textos antigos. Os textos falam de um Mapa[ENTER]do Tesouro que existe na vila. Conheces os Deuses[ENTER]Guardi\245es Animais? O Lykos, o Bera, o Tigris e o[ENTER]Scrofa? "
gameforge.subquest_33._310_sayTitle = "\192 procura do tesouro "
gameforge.subquest_33._320_say = "Hum sob a Pedra do Idoso... N\227o fa\231o a m\237nima[ENTER]ideia...[ENTER]Talvez devesse perguntar ao Idoso. Porque \233 que[ENTER]ele tem de estar t\227o longe? Raios. "
gameforge.subquest_33._330_sayTitle = "Idoso: "
gameforge.subquest_33._340_say = "De que \233 que est\225s \224 procura? Um tesouro? Haha,[ENTER]irias ficar \224 procura dele durante muito tempo![ENTER]Mostra-me o Mapa...[ENTER]Hmmm. Eu acho que est\225 por aqui perto. Boa sorte,[ENTER]hihi... "
gameforge.subquest_33._350_say = "Este deve ser o local. Vamos escavar![ENTER]Raios, o ch\227o parece ser bastante duro. Hum...[ENTER][ENTER]Hey, consigo ver uma caixa! "
gameforge.subquest_33._360_sendLetter = "O tesouro existe! "
gameforge.subquest_33._370_sayTitle = "Regressa ao Soon "
gameforge.subquest_33._380_say = "Estavas a escapar no local que o Mapa do Tesouro[ENTER]indicava e encontraste mesmo uma Caixa do[ENTER]tesouro! Vai ter com o Sr. Soon e conta-lhe sobre[ENTER]esta reviravolta surpreendente. "
gameforge.subquest_33._390_npcChat = "Encontrei o tesouro! "
gameforge.subquest_33._400_say = "Oh! Isto \233 surpreendente! Deixa ver...[ENTER]Fant\225stico. Isto \233 corresponde exactamente \224[ENTER]descri\231\227o da Caixa do Tesouro presente nos textos[ENTER]antigos. Agora apenas tenho de descobrir como a[ENTER]abrir. Mas isso n\227o \233 um problema teu.[ENTER]Obrigado! Toma isto como prova da minha gratid\227o! "
gameforge.subquest_33._40_say = "Uma hist\243ria antiga fala destes quatro monstros,[ENTER]equivalentes a Deuses, que dividiram o Mapa em[ENTER]quatro partes e protegem os territ\243rios. N\227o[ENTER]tenho a certeza se ser\225 verdade. Podes verificar[ENTER]isso por mim? Oh por favor, esta incerteza est\225 a[ENTER]matar-me... Imploro-te, por favor ajuda-me! "
gameforge.subquest_33._410_sayReward = "Recebeste 1.400.000 Pontos de Experi\234ncia. "
gameforge.subquest_33._420_sayReward = "Recebeste 25.000 Yang. "
gameforge.subquest_33._430_sayReward = "Recebeste um Elmo M\225scara Fantasma+1. "
gameforge.subquest_33._440_sayReward = "Recebeste um Capacete Castelo+1. "
gameforge.subquest_33._450_sayReward = "Recebeste um Capuz de A\231o+1. "
gameforge.subquest_33._460_sayReward = "Recebeste um Chap\233u da Luz do Sol+1. "
gameforge.subquest_33._470_say = "Bem, onde \233 que ele est\225? Tu est\225s a gozar[ENTER]comigo?! Ainda n\227o o encontraste, pois n\227o? "
gameforge.subquest_33._50_say = "N\227o est\225s interessado em Mapas do Tesouro? \201s uma[ENTER]pessoa estranha... Vou continuar a procurar[ENTER]pistas nestes textos. Vem ter comigo se mudares[ENTER]de ideias. "
gameforge.subquest_33._60_say = "N\227o gostas deste tipo de aventuras pois n\227o? E[ENTER]agora... Como conseguirei arranjar as partes do[ENTER]Mapa?[ENTER]Oh, bom... Adeus... "
gameforge.subquest_33._70_say = "\201s um verdadeiro amigo. Eu acredito que o vais[ENTER]encontrar. "
gameforge.subquest_33._80_sendLetter = "O Mapa do Tesouro do Sr. Soon "
gameforge.subquest_33._90_targetVid = "Dirige-te ao Sr. Soon "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "O Capit\227o ainda est\225 com problemas em controlar o[ENTER]Cl\227 Vento Negro. Mata os Generais do Cl\227 Vento[ENTER]Negro, Jak-To, To-Su e Gu-Ryung. Talvez ent\227o[ENTER]eles acalmem. "
gameforge.subquest_34._10_npcChat = "O que est\225 o cl\227 Vento Negro a fazer? "
gameforge.subquest_34._110_say = "Os chefes est\227o mortos! "
gameforge.subquest_34._120_select = "Tentar de novo "
gameforge.subquest_34._130_say = "Queres desistir desta miss\227o? "
gameforge.subquest_34._140_say = "Combater n\227o \233 f\225cil, e vencer mais dif\237cil \233.[ENTER]Principalmente se est\225s a combater contra os[ENTER]generais.[ENTER]Tenta de novo! "
gameforge.subquest_34._150_say = "Tal como eu disse, o cl\227 Vento Negro \233 muito[ENTER]forte. Adeus. "
gameforge.subquest_34._160_say = "\201s muito corajoso! Penso que ser\225s capaz de[ENTER]derrotar o Cl\227 Vento Negro. "
gameforge.subquest_34._170_targetVid = "Reporta ao Capit\227o "
gameforge.subquest_34._180_say = "Regressa ao Capit\227o e diz-lhe que mataste os[ENTER]chefes do cl\227 Vento Negro. "
gameforge.subquest_34._185_npcChat = "Eu matei os Generais! "
gameforge.subquest_34._190_say = "Hmm... Derrotaste os generais. \211ptimo. O Cl\227[ENTER]Vento Negro tem andado a dar-nos dores de cabe\231a,[ENTER]mas gra\231as \224 tua ajuda agora seremos capazes de[ENTER]os derrotar. Sem os generais para os comandar,[ENTER]ser\225 fac\237limo. Aqui tens uma recompensa. Espero[ENTER]ver-te em breve! "
gameforge.subquest_34._200_sayReward = "Recebeste 1.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_34._20_sayTitle = "Capit\227o "
gameforge.subquest_34._210_sayReward = "Recebeste um Anel de Idiomas. "
gameforge.subquest_34._30_say = "Apesar de teres derrotado o cl\227 Vento Negro eles[ENTER]n\227o desistem. Em vez de se manterem escondidos[ENTER]eles portam-se como uma matilha selvagem. Se os[ENTER]quisermos derrotar a s\233rio temos de matar os seus[ENTER]chefes. "
gameforge.subquest_34._40_say = "Assim que os generais tiverem sido derrotados, os[ENTER]outros membros ser\227o f\225ceis. Ser\225 um trabalho[ENTER]dif\237cil, mas temos de derrotar os generais do Cl\227[ENTER]Vento Negro, Jak-To, To-Su e Gu-Ryung. Se os[ENTER]derrotares n\227o teremos de nos preocupar mais com[ENTER]o Cl\227 Vento Negro. Ok, ent\227o boa sorte. Irei[ENTER]rezar pela tua vit\243ria. "
gameforge.subquest_34._50_say = "Queres desistir desta miss\227o? "
gameforge.subquest_34._60_say = "Bom... Volta quando te sentires preparado... N\227o[ENTER]h\225 tantas pessoas competentes como tu. "
gameforge.subquest_34._70_say = "N\227o o consegues fazer...?[ENTER]Como vamos derrotar o cl\227 Vento Negro agora...? "
gameforge.subquest_34._80_say = "Eu sabia que podia contar contigo! Assim que os[ENTER]generais forem mortos, os outros membros do cl\227[ENTER]Vento Negro n\227o ser\227o mais um problema. Boa[ENTER]sorte! "
gameforge.subquest_34._90_sendLetter = "Mata os chefes do cl\227 Vento Negro "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "Vamos ter com o Rapaz do Est\225bulo "
gameforge.subquest_36._10_targetVid = "Yonah: "
gameforge.subquest_36._110_say = "Recolheste 10 fardos de Feno. Leva-os ao Rapaz do[ENTER]Est\225bulo para que ele possa alimentar os cavalos. "
gameforge.subquest_36._120_sayTitle = "Feno para os Est\225bulos "
gameforge.subquest_36._130_say = "H\225 falta de comida nos Est\225bulos. Arranja 10[ENTER]fardos de Feno e leva-os ao Rapaz do Est\225bulo[ENTER]antes que os cavalos morram de fome! Podes obter[ENTER]Feno ca\231ando monstros. "
gameforge.subquest_36._140_npcChat = "Precisas de Feno? "
gameforge.subquest_36._150_say = "Vieste aqui porque o Yonah te enviou? Tenho[ENTER]ouvido falar muito de ti. Oh, todos os nossos[ENTER]cavalos v\227o morrer \224 fome. Temos de os salvar.[ENTER]Ajuda-me e arranja Feno para os cavalos! "
gameforge.subquest_36._160_say = "Uma promessa \233 uma promessa. Al\233m disso posso vir[ENTER]a querer montar um cavalo mais tarde. Tenho mesmo[ENTER]de encontrar algum Feno! "
gameforge.subquest_36._170_say = "Desculpa. Ando \224 procura, mas \233 simplesmente[ENTER]imposs\237vel encontrar algum Feno. "
gameforge.subquest_36._180_say = "Sei que n\227o \233 muito bom pedir-te para fazeres o[ENTER]trabalho que me compete, mas pensava que serias[ENTER]capaz de o fazer. Podes tentar de novo? Conhe\231o[ENTER]uma pessoa importante noutro Reino. Se me[ENTER]ajudares irei perguntar-lhe se pode fazer algo[ENTER]por ti. "
gameforge.subquest_36._190_select = "Tentar de novo "
gameforge.subquest_36._200_say = "\201 claro que te irei ajudar. Deixa ver o que posso[ENTER]fazer. "
gameforge.subquest_36._20_npcChat = "Os Est\225bulos Est\227o em Sarilhos "
gameforge.subquest_36._210_say = "N\227o tenho for\231a suficiente. Gostaria de ajudar,[ENTER]mas n\227o posso. N\227o sou suficientemente forte. "
gameforge.subquest_36._220_npcChat = "Tenho Feno para os cavalos. "
gameforge.subquest_36._230_say = "Tens o Feno? Oh, obrigado. N\227o t\237nhamos comida[ENTER]suficiente para os cavalos, por isso falei com o[ENTER]Yonah. Ele \233 um bom amigo meu. Eu tinha a certeza[ENTER]que ele ia tentar perguntar por a\237 para ver se[ENTER]algu\233m poderia dar uma ajuda. Mas n\227o sabia que[ENTER]ele iria conseguir algu\233m t\227o r\225pido. V\234 s\243 o[ENTER]entusiasmo com que os cavalos est\227o a comer! "
gameforge.subquest_36._240_sayReward = "Recebeste 1.800.000 Pontos de Experi\234ncia. "
gameforge.subquest_36._250_sendLetter = "Regressa ao Yonah "
gameforge.subquest_36._260_sayTitle = "Regressa ao Yonah "
gameforge.subquest_36._270_say = "Levaste 10 fardos de Feno ao Rapaz do Est\225bulo[ENTER]para alimentar os cavalos esfomeados. Regressa ao[ENTER]Yonah e conta-lhe o teu sucesso. "
gameforge.subquest_36._280_npcChat = "O assunto dos cavalos est\225 tratado! "
gameforge.subquest_36._290_say = "Ol\225, est\225s de volta![ENTER]Provavelmente foi um trabalho \225rduo recolher[ENTER]tantos fardos de Feno. Obrigado por n\227o[ENTER]desistires! Aqui tens um pequeno presente. "
gameforge.subquest_36._300_sayReward = "Recebeste um Livro de Miss\227o. "
gameforge.subquest_36._30_say = "Hey, tenho uma pergunta para ti![ENTER]Conhe\231o algu\233m que \233 respons\225vel pelos Est\225bulos,[ENTER]mas ultimamente temos tido v\225rios problemas e a[ENTER]tua ajuda dava-nos jeito. Durante a guerra os[ENTER]cavalos t\234m tido muito para fazer, e mesmo um[ENTER]forte e resistente cavalo adulto tem os seus[ENTER]limites. "
gameforge.subquest_36._40_say = "Existem muitos cavalos, mas n\227o existe comida[ENTER]suficiente. V\225rios est\227o a morrer. Podes arranjar[ENTER]comida para os cavalos poderem recuperar a sua[ENTER]energia, por favor? N\227o sei a quem mais posso[ENTER]pedir ajuda.[ENTER]Recolhe 10 fardos de Feno e leva-os ao Rapaz do[ENTER]Est\225bulo. Ele j\225 sabe do problema. Diz-lhe apenas[ENTER]que te enviei. "
gameforge.subquest_36._50_select = "Vou-me embora imediatamente! "
gameforge.subquest_36._60_select = "N\227o, isso \233 trabalho de escravo. "
gameforge.subquest_36._70_say = "Hoje em dia cada vez mais pessoas querem um[ENTER]cavalo. Mas ningu\233m quer saber se estamos a ficar[ENTER]sem comida para os cavalos. E agora eles est\227o a[ENTER]morrer \224 fome nos Est\225bulos. Volta se mudares de[ENTER]ideias. "
gameforge.subquest_36._80_say = "Oh, pobres cavalos! Eles est\227o esfomeados e n\227o[ENTER]posso fazer nada quanto a isso. O que posso[ENTER]fazer... "
gameforge.subquest_36._90_say = "Sei que tens muito trabalho e estou muito grato[ENTER]pela tua ajuda. Hoje em dia os cavalos s\227o muito[ENTER]importantes. E precisamos realmente do Feno. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "O Yonah est\225 a dar o seu melhor para produzir[ENTER]porcelana nova, mas n\227o est\225 a fazer progressos[ENTER]nenhuns com as suas experi\234ncias. Vai ter com o[ENTER]Uriel e pergunta-lhe se ele sabe algo sobre a[ENTER]Porcelana Celadon. "
gameforge.subquest_37._10_targetVid = "O Segredo da Porcelana Celadon "
gameforge.subquest_37._110_npcChat = "Conheces a Porcelana Celadon? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Porcelana Celadon? Bom, eu sei muito sobre[ENTER]hist\243ria e ci\234ncia, mas tenho muito interesse em[ENTER]arte. \201 por isso que lamento informar-te que n\227o[ENTER]te posso dizer nada sobre a Porcelana Celadon.[ENTER]Talvez o Sr. Soon saiba algo? Ele n\227o \233 muito[ENTER]popular, mas l\234 v\225rios livros. Talvez ele saiba[ENTER]algo sobre isso. "
gameforge.subquest_37._140_makequestbutton = "Dirige-te ao Sr. Soon "
gameforge.subquest_37._150_targetVid = "Vai ao Soon "
gameforge.subquest_37._160_say = "Infelizmente o Uriel n\227o sabe nada sobre a[ENTER]Porcelana Celadon. Mas o Sr. Soon l\234 muitos[ENTER]livros. Vai ter com ele e pergunta-lhe se sabe[ENTER]como se faz. "
gameforge.subquest_37._170_sayTitle = "Sr. Soon: "
gameforge.subquest_37._180_say = "O que queres? N\227o me interrompas enquanto leio![ENTER]Huh? Porcelana Celadon? Claro que sei sobre isso.[ENTER]Eu devo ter lido no m\237nimo uma d\250zia de livros[ENTER]sobre esse tema particular.[ENTER]Porqu\234? Bem, n\227o \233 \224 toa que me chamam \"rato de[ENTER]biblioteca\", sabias? Eu compreendo tudo o que[ENTER]alguma vez foi escrito nestes livros! "
gameforge.subquest_37._190_say = "Eu podia escrever exactamente como criar[ENTER]Porcelana Celadon sem sequer parar para pensar,[ENTER]mas por que havia de o fazer? Hmm.[ENTER]Bom, espera, tenho uma ideia: Pedi um livro que[ENTER]me falta ao Vendedor Ambulante da vila vizinha,[ENTER]mas n\227o tenho tempo para ir l\225 busc\225-lo. Vai[ENTER]busc\225-lo por mim e ent\227o irei ajudar-te com a[ENTER]Porcelana.[ENTER]P\245e-te a caminho! "
gameforge.subquest_37._200_makequestbutton = "Vamos ter com o Vendedor Ambulante "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Dirige-te ao Vendedor Ambulante "
gameforge.subquest_37._220_say = "O Sr. Soon sabe tudo sobre a Porcelana Celadon.[ENTER]Ele n\227o quer partilhar o seu conhecimento sem[ENTER]receber algo em troca.[ENTER]Vai ter com o Vendedor Ambulante e traz o Livro[ENTER]que o Soon lhe tinha pedido. "
gameforge.subquest_37._230_npcChat = "O Soon enviou-me... "
gameforge.subquest_37._240_say = "Hey! Vieste ajudar-me de novo?[ENTER]Ahh. Queres o livro que o Sr. Soon me encomendou.[ENTER]Eu iria acabar por passar pela vila dele, mas ele[ENTER]\233 demasiado impaciente e at\233 envia outros para ir[ENTER]buscar o que encomendou.[ENTER]Hmm. Aqui o tens. Eu n\227o entendo o que o Soon[ENTER]gosta nesses montes de papeis. \201 mais importante[ENTER]ganhar Yang rapidamente! "
gameforge.subquest_37._250_qSetTitle = "Regressa ao Sr. Soon "
gameforge.subquest_37._260_targetVid = "Regressa ao Sr. Soon "
gameforge.subquest_37._270_say = "Recebeste o livro do Sr. Soon do Vendedor[ENTER]Ambulante. Regressa ao Sr. Soon para lhe[ENTER]entregares o livro e ele te dizer como produzir[ENTER]Porcelana Celadon. "
gameforge.subquest_37._280_npcChat = "Tenho o livro "
gameforge.subquest_37._290_say = "Yay! Finalmente j\225 tenho o livro novo! Muito[ENTER]obrigado. N\227o existem muitos livros que eu ainda[ENTER]n\227o tenha lido...[ENTER]Eu escrevi tudo o que era mais importante para[ENTER]fazer a Porcelana Celadon. Segue as minhas[ENTER]instru\231\245es e vais produzir uma fant\225stica[ENTER]porcelana.[ENTER]E agora \233 tempo de eu ler o novo livro. At\233 \224[ENTER]pr\243xima. "
gameforge.subquest_37._300_makequestbutton = "Regressa ao Yonah "
gameforge.subquest_37._30_say = "Hmm... Isto n\227o serve. E isto tamb\233m n\227o... Oh,[ENTER]ol\225! V\234 isto: Estou a produzir porcelana sem[ENTER]parar, mas quase todas as pe\231as se partem[ENTER]imediatamente. Talvez precise de um novo tipo de[ENTER]porcelana... "
gameforge.subquest_37._310_targetVid = "Leva as notas ao Yonah "
gameforge.subquest_37._320_say = "O Soon manteve a promessa e escreveu como[ENTER]produzir a Porcelana Celadon. Leva-a ao Yonah. "
gameforge.subquest_37._330_say = "Ooh!!![ENTER]Aqui est\225 escrito tudo sobre a produ\231\227o da[ENTER]Porcelana Celadon. Com a ajuda destas notas[ENTER]finalmente conseguirei ficar para a hist\243ria como[ENTER]um mestre do artesanato.[ENTER]Obrigado pela tua ajuda. Poderei mostrar-te os[ENTER]meus melhores trabalhos de olaria muito em breve![ENTER]Podes contar com isso! Irei produzir Porcelana[ENTER]Celadon t\227o boa que ir\225 durar s\233culos. "
gameforge.subquest_37._340_sayReward = "Recebeste 2.500.000 Pontos de Experi\234ncia. "
gameforge.subquest_37._350_sayReward = "Recebeste 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Recebeste Sapatos em Jade+3. "
gameforge.subquest_37._40_say = "Quero tentar um m\233todo novo. N\227o \233 simples[ENTER]produzir Porcelana Celadon, raz\227o pela qual[ENTER]apenas um punhado de pessoas no mundo inteiro[ENTER]sabe como o fazer. Mas preciso de descobrir como[ENTER]se produz, pelo bem da minha arte! Bom... Hmm, o[ENTER]Uriel talvez saiba algo sobre este assunto! Por[ENTER]favor vai ter com o Uriel e descobre como[ENTER]produzir a Porcelana Celadon! "
gameforge.subquest_37._50_say = "Queres desistir desta miss\227o? "
gameforge.subquest_37._60_say = "Hm, est\225s muito ocupado? Lembra-te de voltares se[ENTER]por acaso tiveres algum tempo dispon\237vel. "
gameforge.subquest_37._70_say = "Compreendo. Adeus... "
gameforge.subquest_37._80_say = "Obrigado. O Uriel saber\225 o que fazer. At\233 \224[ENTER]pr\243xima! "
gameforge.subquest_37._90_targetVid = "Vai ter com o Uriel "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "O Arco Ornamentado do ca\231ador, que \233 uma heran\231a[ENTER]de fam\237lia, foi roubado. Vai \224 Caverna dos[ENTER]Macacos Dif\237cil e recupera o Arco das patas[ENTER]daqueles macacos ladr\245es. "
gameforge.subquest_38._10_targetVid = "O Tesouro do Ca\231ador "
gameforge.subquest_38._110_sendLetter = "Encontrei o Arco Ornamentado "
gameforge.subquest_38._120_targetVid = "Vai ter com o ca\231ador Yang-Shin "
gameforge.subquest_38._125_say = "Encontraste o Arco Ornamentado do ca\231ador. Leva-o[ENTER]ao Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Aqui est\225 o Arco "
gameforge.subquest_38._140_say = "Wow, \233 isso mesmo! O meu Arco, yay! A minha honra[ENTER]foi restitu\237da. Tenho sofrido tanto desde que o[ENTER]perdi... Estou mesmo muito grato pela tua ajuda.[ENTER]\201 uma honra para mim dar-te isto. Pode n\227o[ENTER]parecer muito, mas \233 dado do meu cora\231\227o. Gra\231as[ENTER]a ti posso continuar a minha vida em paz! "
gameforge.subquest_38._150_sayReward = "Recebeste 1.500.000 Pontos de Experi\234ncia. "
gameforge.subquest_38._160_sayReward = "Recebeste 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Recebeste Capas de Bravura. "
gameforge.subquest_38._180_say = "Encontraste o meu Arco? Mas onde \233 que ele est\225?[ENTER]Perdeste-o de novo? "
gameforge.subquest_38._190_select = "Vou continuar \224 procura. "
gameforge.subquest_38._200_say = "Assim seja.[ENTER]Toma conta de ti. "
gameforge.subquest_38._20_say = "Hey, podes ouvir-me por uns segundos? Como v\234s[ENTER]sou um ca\231ador; a minha fam\237lia pratica ca\231a h\225[ENTER]v\225rias gera\231\245es. Somos todos ca\231adores, uma[ENTER]fam\237lia com muita honra. Mas eu cometi um erro[ENTER]grave que ir\225 desonrar-me perante toda a minha[ENTER]fam\237lia... "
gameforge.subquest_38._210_say = "Podes tentar de novo?[ENTER]Obrigado. Com as tuas habilidades certamente[ENTER]conseguir\225s faz\234-lo. "
gameforge.subquest_38._30_say = "Estou a referir-me a um Arco Ornamentado que me[ENTER]foi roubado h\225 algum tempo por macacos. Eu estava[ENTER]a ca\231ar na Caverna dos Macacos Dif\237ceis e desviei[ENTER]a aten\231\227o por apenas um segundo... Eles[ENTER]aproveitaram-se da situa\231\227o e roubaram-no. "
gameforge.subquest_38._40_say = "Nunca estive nas profundezas da Caverna dos[ENTER]Macacos Dif\237ceis, pelo que n\227o conhe\231o os[ENTER]caminhos e por isso preciso da tua ajuda. Alguns[ENTER]locais disseram-me que tens muito talento. Por[ENTER]isso estou a pedir-te este favor. N\227o posso[ENTER]encarar os meus antepassados sem o meu Arco[ENTER]Ornamentado. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh! Preciso de o recuperar o mais depressa[ENTER]poss\237vel...[ENTER]Por favor volta quando tiveres tempo. Adeus. "
gameforge.subquest_38._70_say = "Muito bem...[ENTER]Tem cuidado nas tuas aventuras. "
gameforge.subquest_38._80_say = "Vais encontr\225-lo facilmente porque \233 um Arco[ENTER]bastante Ornamentado. Irei dar-te uma boa[ENTER]recompensa por ele! "
gameforge.subquest_38._90_sayTitle = "Procura o Arco Ornamentado "
gameforge.subquest_39 = {}
gameforge.subquest_39._100_sayTitle = "O estado do Traidor Balso "
gameforge.subquest_39._10_targetVid = "Entrega para o Traidor Balso "
gameforge.subquest_39._110_say = "A sa\250de do Traidor Balso piorou. Vai ter com o[ENTER]Baek-Go e pergunta-lhe como \233 poss\237vel ajudar o[ENTER]Balso. "
gameforge.subquest_39._120_makequestbutton = "Vai ter com o Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Vai ter com o Baek-Go "
gameforge.subquest_39._140_targetVid = "Vamos ter com o Baek-Go "
gameforge.subquest_39._150_npcChat = "Tenho um paciente... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Oh, \233s tu, como est\225s? Est\225s a tratar de um[ENTER]paciente doente? Conta-me o que se passa com[ENTER]ele...[ENTER]Hmm... E que Rem\233dio \233 que ele tem estado a tomar?O qu\234?! N\227o admira que ele tenha piorado! Esse[ENTER]Rem\233dio n\227o serve para nada! "
gameforge.subquest_39._180_say = "Ele tem sorte por ainda estar vivo! \201 muito[ENTER]perigoso administrar o rem\233dio incorrecto a uma[ENTER]pessoa doente! Mas eu sei o que o poder\225 ajudar.[ENTER]Existe um certo tipo de Erva que livra o corpo do[ENTER]veneno e restitui a sa\250de. No entanto \233 muito[ENTER]perigoso tentar obt\234-la. "
gameforge.subquest_39._190_say = "Tanto quanto sei, essa Erva apenas cresce na[ENTER]Caverna dos Macacos Dif\237ceis. Mas \233 sempre[ENTER]colhida para o Lord Macaco, que gosta de a comer.[ENTER]Vais ter de o matar se a quiseres obter.[ENTER]Posso criar o Rem\233dio correcto se me trouxeres a[ENTER]Erva. "
gameforge.subquest_39._200_select = "Okay, irei busc\225-la. "
gameforge.subquest_39._20_npcChat = "Sobre o teu Rem\233dio... "
gameforge.subquest_39._210_select = "N\227o consigo fazer isso. "
gameforge.subquest_39._220_say = "Queres desistir desta miss\227o? "
gameforge.subquest_39._230_select = "Sim "
gameforge.subquest_39._240_say = "Bom, talvez mais tarde, quando tiveres algum[ENTER]tempo livre.[ENTER]Existem muitas pessoas doentes, mas poucas andam[ENTER]\224 procura de uma cura. "
gameforge.subquest_39._250_say = "Hmm, parece que ter\225 de ser assim. \201 uma pena que[ENTER]ningu\233m tenha coragem suficiente. Como \233 que isto[ENTER]vai acabar... "
gameforge.subquest_39._260_say = "Oh, obrigado. Vai ser uma tarefa dif\237cil. Mas[ENTER]ir\225s estar a ajudar muitas pessoas! "
gameforge.subquest_39._270_makequestbutton = "Erva do Lorde Macaco "
gameforge.subquest_39._280_targetVid = "Regressa ao Baek-Go "
gameforge.subquest_39._290_sayTitle = "Encontraste a Erva Azul "
gameforge.subquest_39._300_say = "Conseguiste obter a Erva Azul do Lorde Macaco.[ENTER]Leva-a ao Baek-Go, para que ele possa criar o[ENTER]Rem\233dio para o Balso. "
gameforge.subquest_39._30_say = "Obrigado por me trazeres aquele Rem\233dio da \250ltima[ENTER]vez. Mas estou com um problema... O efeito do[ENTER]Rem\233dio j\225 passou. E acho que estou pior.[ENTER]*cough* Preciso de um tratamento rapidamente. "
gameforge.subquest_39._310_sayTitle = "Obt\233m a Erva da Caverna dos Macacos Dif\237ceis "
gameforge.subquest_39._320_say = "O Baek-Go pode criar um Rem\233dio para a doen\231a do[ENTER]Traidor Balso. Para isso ele precisa da Erva[ENTER]Azul. Poder\225s obt\234-la do Lorde Macaco que se[ENTER]encontra na Caverna dos Macacos Dif\237ceis. "
gameforge.subquest_39._330_npcChat = "A Erva Azul... "
gameforge.subquest_39._340_say = "Parece que a doen\231a se est\225 a espalhar como uma[ENTER]epidemia, mas ainda n\227o conhecemos a sua causa.[ENTER]No entanto a organiza\231\227o acad\233mica informou-nos[ENTER]que \233 poss\237vel criar uma cura com a Erva Azul.[ENTER]O que se passa? J\225 encontraste a Erva? "
gameforge.subquest_39._350_select = "Ainda n\227o. Mas em breve! "
gameforge.subquest_39._360_select = "N\227o consigo arranjar a Erva "
gameforge.subquest_39._370_say = "Queres mesmo desistir?[ENTER]Hmm, suponho que n\227o consigas mesmo fazer mais[ENTER]nada. O que irei fazer? A Erva seria uma[ENTER]verdadeira b\234n\231\227o... "
gameforge.subquest_39._380_select = "N\227o o consigo fazer. "
gameforge.subquest_39._390_select = "Quero ajudar! "
gameforge.subquest_39._400_say = "Os macacos s\227o demasiado fortes para mim. N\227o[ENTER]consigo arranjar a Erva. Lamento. "
gameforge.subquest_39._40_say = "Sei que existe um m\233dico que vive na vila[ENTER]vizinha. Podes ir ter com ele e explicar a minha[ENTER]situa\231\227o para que ele te possa dizer o que pode[ENTER]ser feito? Como v\234s, n\227o posso sair da vila neste[ENTER]estado. Estou muito grato pela tua ajuda da[ENTER]\250ltima vez, e fica descansado porque tamb\233m te[ENTER]irei recompensar desta vez. "
gameforge.subquest_39._410_say = "Recusas-te a ajudar pessoas que est\227o a sofrer de[ENTER]uma doen\231a terr\237vel e misteriosa. Sai da minha[ENTER]frente! "
gameforge.subquest_39._420_say = "Tens raz\227o. Algu\233m tem de conseguir obter esta[ENTER]Erva, caso contr\225rio todas aquelas pessoas[ENTER]doentes ir\227o sofrer. Irei tratar disto. "
gameforge.subquest_39._430_say = "Ent\227o despacha-te! "
gameforge.subquest_39._440_say = "Conseguiste obter a Erva Azul! Espero que ela[ENTER]possa mesmo curar esta doen\231a misteriosa. Espera[ENTER]um segundo, irei criar o Rem\233dio num instante... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Aqui tens o Rem\233dio. Despacha-te a ir ter com o[ENTER]teu paciente e d\225-lho. Ele dever\225 ficar bom em[ENTER]breve.[ENTER]Al\233m disso, por favor diz-lhe que \233 sempre melhor[ENTER]consultar um m\233dico antes de tomar algum rem\233dio. "
gameforge.subquest_39._470_makequestbutton = "Leva o Rem\233dio ao Balso "
gameforge.subquest_39._480_targetVid = "Entregas o Rem\233dio ao Traidor Balso. "
gameforge.subquest_39._490_sayTitle = "O Rem\233dio do Traidor Balso "
gameforge.subquest_39._500_say = "O Baek-Go fez um Rem\233dio que pode criar diversas[ENTER]doen\231as raras a partir da Erva Azul. Leva-o ao[ENTER]Traidor Balso que se encontra na pr\243xima vila. "
gameforge.subquest_39._50_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_39._510_npcChat = "Aqui tens o Rem\233dio "
gameforge.subquest_39._520_say = "Est\225s a trazer-me o novo Rem\233dio? Houve[ENTER]progressos nas investiga\231\245es m\233dicas? Desculpa[ENTER]por te dar tanto trabalho. Devia ter pedido[ENTER]conselhos a um m\233dico logo quando adoeci. No[ENTER]entanto tenho de aceitar que agora preciso de[ENTER]tomar este Rem\233dio. "
gameforge.subquest_39._530_say = "Obrigado por ajudares a curar a minha miser\225vel[ENTER]doen\231a. N\227o tenho muitos amigos.[ENTER]Toma, n\227o \233 muito, mas \233 oferecido do meu[ENTER]cora\231\227o. Por favor aceita. Se conseguir[ENTER]sobreviver nunca te irei esquecer. "
gameforge.subquest_39._540_sayReward = "Recebeste 4.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_39._550_sayReward = "Recebeste 65.000 Yang. "
gameforge.subquest_39._60_say = "Se descobrires como me ajudar poder\225s[ENTER]encontrar-me aqui. "
gameforge.subquest_39._70_sayTitle = "Traidor Balso: "
gameforge.subquest_39._80_say = "Vou ter que continuar a viver assim?[ENTER]At\233 \224 pr\243xima. "
gameforge.subquest_39._90_say = "Obrigado... Tem cuidado! "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "Sabia que podia contar contigo! \201 um trabalho[ENTER]dif\237cil, mas tenho a certeza que o conseguir\225s[ENTER]fazer. Boa sorte! "
gameforge.subquest_40._10_targetVid = "Instrumentos de Apoio \224 Guerra "
gameforge.subquest_40._110_targetVid = "Regressa ao Capit\227o "
gameforge.subquest_40._120_say = "Recolheste as 5.000 Pontas de Flecha. Leva-as ao[ENTER]Capit\227o. "
gameforge.subquest_40._130_say = "O ex\233rcito tem tido problemas em arranjar mais[ENTER]flechas.[ENTER]Mata Arqueiros Infestados na Montanha Sohan e[ENTER]arranja Pontas de Flecha para o Capit\227o. 5.000[ENTER]dever\227o chegar. "
gameforge.subquest_40._140_npcChat = "Sobre as Pontas de Flecha... "
gameforge.subquest_40._150_say = "Estes Arqueiros Infestados t\234m uma certa doen\231a[ENTER]que se espalhou pelo continente. Nem os nossos[ENTER]m\233dicos a conseguem explicar. As Pontas de Flecha[ENTER]ainda s\227o normais, mas est\227o a tornar-se cada vez[ENTER]mais t\243xicas. "
gameforge.subquest_40._160_select = "Vou continuar. "
gameforge.subquest_40._170_say = "Queres desistir desta miss\227o? "
gameforge.subquest_40._180_say = "Est\225s com medo da doen\231a? Acalma-te e volta mais[ENTER]tarde. "
gameforge.subquest_40._190_say = "Tens a certeza que queres desistir? Hmm, talvez[ENTER]esta tarefa seja realmente demasiado dif\237cil para[ENTER]ti. Vou pedir a outra pessoa. Adeus! "
gameforge.subquest_40._200_say = "Percebo...[ENTER]Nunca desistes pois n\227o?[ENTER]Vamos l\225! "
gameforge.subquest_40._20_say = "Aten\231\227o guerreiros! Como podem ver, o n\250mero de[ENTER]ataques infligidos pelos nossos inimigos tem[ENTER]aumentado a cada dia. Tamb\233m recebemos[ENTER]informa\231\245es alarmantes do Yu-Hwan. Resumindo: N\227o[ENTER]temos flechas suficientes! "
gameforge.subquest_40._210_npcChat = "Aqui est\227o 5.000 Pontas de Flecha! "
gameforge.subquest_40._220_say = "Que trabalho fant\225stico! Agora podemos[ENTER]preparar-nos para o ataque. Vou ordenar[ENTER]imediatamente que se comecem a produzir mais[ENTER]flechas.[ENTER]Foi um verdadeiro trabalho de equipa. Espero que[ENTER]possamos contar contigo mais tarde. "
gameforge.subquest_40._230_say = "Aqui tens a tua recompensa. Da pr\243xima vez que[ENTER]tiver um trabalho importante, tu ser\225s a primeira[ENTER]pessoa que irei chamar.[ENTER]Tudo de bom e vemo-nos em breve! "
gameforge.subquest_40._240_sayReward = "Recebeste 4.500.000 Pontos de Experi\234ncia. "
gameforge.subquest_40._250_sayReward = "Recebeste 50.000 Yang. "
gameforge.subquest_40._260_sayReward = "Recebeste 3 Golpes Cr\237ticos.[ENTER]Recebeste 3 Golpes Perfuradores. "
gameforge.subquest_40._30_say = "Os arqueiros s\227o um factor estrat\233gico importante[ENTER]na guerra. Assim que os nossos inimigos estejam[ENTER]ao seu alcance, os nossos arqueiros devem[ENTER]disparar sobre eles. Dessa forma podemos[ENTER]afugent\225-los imediatamente ou pelo menos reduzir[ENTER]o seu n\250mero. Mas se existirem demasiados ataques[ENTER]num curto espa\231o de tempo iremos ficar sem[ENTER]flechas. "
gameforge.subquest_40._40_say = "\201 por isso que precisamos de ti! Vai \224 Montanha[ENTER]Sohan e mata Arqueiros Infestados para obter as[ENTER]suas Pontas de Flecha. Essas Pontas de Flecha s\227o[ENTER]venenosas, mas o seu efeito ir\225 ajudar-nos a[ENTER]derrotar os nossos inimigos.[ENTER]Precisamos de 5.000 Pontas de Flecha. O que dizes? "
gameforge.subquest_40._50_select = "Aceito. "
gameforge.subquest_40._60_select = "\201 demasiado dif\237cil para mim. "
gameforge.subquest_40._70_say = "Queres desistir desta miss\227o? "
gameforge.subquest_40._80_say = "A Montanha Sohan fica demasiado longe para ti?[ENTER]Por favor pensa melhor. Esta miss\227o \233 da maior[ENTER]import\226ncia. "
gameforge.subquest_40._90_say = "Hum... Tens medo dos Arqueiros Infestados?[ENTER]Parece que esperava demasiado de ti... Agora j\225[ENTER]n\227o h\225 esperan\231a... "
