gameforge.subquest_41._100_say = "Recolheste os 100 Olhos de Aranha para a nova[ENTER]receita do Oct\225vio. Devias ir entreg\225-los[ENTER]rapidamente. "
gameforge.subquest_41._10_targetVid = "Especial de Olhos de Aranha "
gameforge.subquest_41._110_sayTitle = "Recolhe Olhos de Aranha "
gameforge.subquest_41._120_say = "O Oct\225vio quer experimentar a sua nova receita[ENTER]chamada \"Especial de Olhos de Aranha\". Para a[ENTER]fazer, ele precisa de 100 Olhos de Aranha das[ENTER]aranhas do Deserto Yongbi. "
gameforge.subquest_41._130_targetVid = "Regressa ao Oct\225vio "
gameforge.subquest_41._140_npcChat = "Eu tenho os Olhos de Aranha "
gameforge.subquest_41._150_sayTitle = "Oct\225vio: "
gameforge.subquest_41._160_say = "Mostra-me. Exactamente 100 olhos, muito bem. Bem,[ENTER]vamos ver ent\227o...[ENTER]Mmhhh, feito! Tamb\233m queres experimentar? N\227o[ENTER]fiques t\227o chocado. Isto n\227o vai matar-te. "
gameforge.subquest_41._170_say = "Hmm,hmm... Que maravilha! Muito nutritivo, n\227o[ENTER]muito doce.... que sabor incr\237vel! Eu sabia que[ENTER]ia valer o esfor\231o.[ENTER]Nunca teria conseguido fazer isto sem ti. Muito[ENTER]obrigado pela tua ajuda! "
gameforge.subquest_41._180_sayReward = "Recebeste 2.100.000 Pontos de Experi\234ncia. "
gameforge.subquest_41._190_say = "O que \233 que est\225s a dizer? Isso n\227o s\227o 100[ENTER]olhos, eu posso dizer sem os contar![ENTER]Vai recolher mais por favor. "
gameforge.subquest_41._200_say = "Queria mesmo cozinhar isto.[ENTER]Esquece, obrigado. Tem cuidado contigo. "
gameforge.subquest_41._20_say = "Hey, como est\225s? Estou a ler um livro de[ENTER]culin\225ria que o Sr. Soon me deu. Nele descobri[ENTER]uma receita muito interessante chamada \"Especial[ENTER]de Olhos de Aranha\". Nunca vi nada como esta[ENTER]receita! E tu? Parece ser um prato especial de[ENTER]outro Reino. "
gameforge.subquest_41._210_say = "Obrigado por n\227o me deixares em apuros.[ENTER]\201s muito simp\225tico. "
gameforge.subquest_41._30_say = "Eu realmente gostaria de experimentar este prato[ENTER]mas como vou encontrar todos os Olhos de Aranha?[ENTER]Eu preciso mesmo da tua ajuda novamente.[ENTER]Por favor recolhe os Olhos de Aranha das Aranhas[ENTER]do Deserto de Yongbi. "
gameforge.subquest_41._40_say = "Podes fazer isso por mim? Eu ficaria realmente[ENTER]muito grato.[ENTER]Para fazer esta receita s\227o necess\225rios 100 olhos[ENTER]para uma por\231\227o de tamanho razo\225vel. Estou[ENTER]realmente excitado... "
gameforge.subquest_41._50_say = "Queres desistir desta miss\227o? "
gameforge.subquest_41._60_say = "Quero mesmo fazer isto... Quando me quiseres[ENTER]fazer este favor por favor vem ter comigo. "
gameforge.subquest_41._70_say = "Hum... Onde irei ent\227o arranjar os Olhos de[ENTER]Aranha?[ENTER]Ok... Adeus... "
gameforge.subquest_41._80_say = "Obrigado. Sabia que me farias este favor. Ir\225s,[ENTER]claro, ser recompensado por isto. "
gameforge.subquest_41._90_sayTitle = "Regressa ao Oct\225vio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Lamento ouvir isso. Ou\231o tantas vozes de pessoas[ENTER]mortas, que apenas n\227o podem descansar em paz.[ENTER]N\243s temos realmente que ajuda-los.[ENTER]Eu vou perguntar a outro. At\233 a pr\243xima. "
gameforge.subquest_42._10_targetVid = "Deixa os Mortos Descansar "
gameforge.subquest_42._110_say = "Como \233s corajoso. Tenho a certeza que os[ENTER]guerreiros jovens corajosos em breve v\227o chegar[ENTER]ao Nirvana com a tua ajuda. "
gameforge.subquest_42._120_say = "Estas guerras terr\237veis continuam a matar cada[ENTER]vez mais jovens. S\227o soldados que lutam pelas[ENTER]suas fam\237lias e pelo seu Reino nas linhas da[ENTER]frente. Mas depois de morrer alguns n\227o conseguem[ENTER]atingir o Nirvana. E por isso ficam a vaguear por[ENTER]este mundo. "
gameforge.subquest_42._130_say = "Ouvi dizer que os Coron\233is Negros Elite do Templo[ENTER]Hwang est\227o na posse de uma Estola do Templo e de[ENTER]uma Doutrina do Templo. Por favor ajuda-me a mim[ENTER]e aos meus camaradas a acalmar as almas daqueles[ENTER]que morreram em nome do seu Reino. "
gameforge.subquest_42._140_sayTitle = "Regressa ao Professor For\231a Drag\227o "
gameforge.subquest_42._150_say = "Encontraste a Estola do Templo e a Doutrina do[ENTER]Templo. Leva-os ao Professor For\231a Drag\227o, para[ENTER]que os Xam\227s possam come\231ar o ritual para acalmar[ENTER]os mortos. "
gameforge.subquest_42._160_sayTitle = "Obt\233m a Doutrina e a Estola do Templo "
gameforge.subquest_42._170_say = "As Xam\227s precisam da Estola do Templo e da[ENTER]Doutrina do Templo para uma cerim\243nia para[ENTER]acalmar os esp\237ritos dos guerreiros mortos[ENTER]durante a guerra.[ENTER]Mata Coron\233is Negros Elite no Templo Hwang para[ENTER]obteres os objectos do ritual. "
gameforge.subquest_42._180_npcChat = "Eu tenho a Estola e a Doutrina. "
gameforge.subquest_42._190_say = "Foste maravilhoso. Agora podemos acalmar os[ENTER]guerreiros mortos. Eles fizeram o seu melhor.[ENTER]Agora, eles podem descansar em paz.[ENTER]Deixa-me dar-te a recompensa por esta nobre ac\231\227o. "
gameforge.subquest_42._200_sayReward = "Recebeste 1.700.000 Pontos de Experi\234ncia. "
gameforge.subquest_42._20_sayTitle = "Professor - For\231a Drag\227o: "
gameforge.subquest_42._210_sayReward = "Recebeste 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Recebeste 3 Diamantes. "
gameforge.subquest_42._230_say = "Foste maravilhoso. Agora podemos acalmar os[ENTER]guerreiros mortos. Eles fizeram o seu melhor.[ENTER]Agora, eles podem descansar em paz.[ENTER]Deixa-me dar-te a recompensa por esta nobre ac\231\227o. "
gameforge.subquest_42._30_say = "Estas guerras terr\237veis continuam a matar cada[ENTER]vez mais jovens. S\227o soldados que lutam pelas[ENTER]suas fam\237lias e pelo seu Reino nas linhas da[ENTER]frente. Mas depois de morrer alguns n\227o conseguem[ENTER]atingir o Nirvana. E por isso ficam a vaguear por[ENTER]este mundo. "
gameforge.subquest_42._40_say = "Diz-se que durante a guerra eles ficaram[ENTER]resistentes \224 morte. Eles pensam que ainda t\234m de[ENTER]defender o seu Reino.[ENTER]Os nossos Xam\227s querem fazer uma cerim\243nia para[ENTER]acalmar os esp\237ritos. Para poderem fazer isso[ENTER]precisam de uma Estola do Templo e de uma[ENTER]Doutrina do Templo que, hoje em dia, s\227o dif\237ceis[ENTER]de obter. Podes arranjar-nos esses dois itens? "
gameforge.subquest_42._50_say = "Ouvi dizer que os Coron\233is Negros Elite do Templo[ENTER]Hwang est\227o na posse de uma Estola do Templo e de[ENTER]uma Doutrina do Templo. Por favor ajuda-me a mim[ENTER]e aos meus camaradas a acalmar as almas daqueles[ENTER]que morreram em nome do seu Reino. "
gameforge.subquest_42._60_select = "Irei ajudar-te. "
gameforge.subquest_42._70_select = "Desculpa, tenho medo. "
gameforge.subquest_42._80_say = "Queres desistir desta miss\227o? "
gameforge.subquest_42._90_say = "Ajuda-nos a acalmar as almas dos mortos para que[ENTER]eles possam descansar em paz. Esperarei aqui por[ENTER]ti. "
gameforge.subquest_44 = {}
gameforge.subquest_44._100_sendLetter = "A Aranha com o Sino "
gameforge.subquest_44._10_targetVid = "A aranha "
gameforge.subquest_44._110_say = "O Taurean disse que pendurou um sino numa aranha.[ENTER]Agora a Yu-Rang quer saber se o seu amigo \233[ENTER]realmente t\227o corajoso como ele diz.[ENTER]Procura a aranha no deserto. "
gameforge.subquest_44._120_say = "J\225 encontraste a aranha com o sino?[ENTER]N\227o? Provavelmente nunca a vais encontrar.[ENTER]Taurean \233 um cobarde e apenas se quer mostrar! "
gameforge.subquest_44._130_sendLetter = "N\227o encontro o sino. "
gameforge.subquest_44._140_sayTitle = "Muitas aranhas, nenhum sino "
gameforge.subquest_44._150_say = "Mataste algumas aranhas mas n\227o encontraste o[ENTER]sino. N\227o podes procurar para sempre. O melhor a[ENTER]fazer ser\225 ires ao Taurean e perguntar-lhe a[ENTER]verdade. "
gameforge.subquest_44._160_sendLetter = "Vai ter com o Taurean "
gameforge.subquest_44._170_targetVid = "Pergunta ao Taurean pelo sino "
gameforge.subquest_44._180_say = "\201 pouco prov\225vel que o Taurean tivesse coragem[ENTER]suficiente para pendurar o sino numa aranha. \201[ENTER]melhor perguntar-lhe a verdade directamente. "
gameforge.subquest_44._190_npcChat = "Fala-me da tua aposta com a Yu-Rang... "
gameforge.subquest_44._200_say = "Sabes da aposta com a Yu-Rang? Ela n\227o acredita[ENTER]em mim e acha que eu n\227o fui capaz de o fazer.[ENTER]Ela pensa que eu desmaio assim que vejo uma[ENTER]aranha gigante. "
gameforge.subquest_44._20_npcChat = "Uma aranha com um sino...? "
gameforge.subquest_44._210_say = "Para ser honesto... Ela tem raz\227o. N\227o fui[ENTER]corajoso o suficiente para lhe dizer porque sou[ENTER]demasiado orgulhoso. "
gameforge.subquest_44._220_say = "Mas tu pareces-me muito forte! N\227o podes p\244r o[ENTER]sino numa Aranha Beb\233 por mim e dizer que fui eu?[ENTER]Por favor, v\225 l\225. De outro modo eles v\227o gozar[ENTER]comigo para o resto vida. "
gameforge.subquest_44._230_say = "Queres desistir desta miss\227o? "
gameforge.subquest_44._240_say = "N\227o o queres fazer? Mas tu n\227o vais contar a[ENTER]Yu-Rang a verdade?[ENTER]Por favor, ajuda-me. Regressa quando tiveres um[ENTER]tempo para mim! "
gameforge.subquest_44._250_say = "Agora a Yu-Rang nunca mais vai voltar a falar[ENTER]comigo![ENTER]Ou ent\227o vai rir-se de mim... "
gameforge.subquest_44._260_say = "Ah, eu estava certo. Eu sabia que eras t\227o[ENTER]simp\225tico como parecias.[ENTER]Obrigado pela tua ajuda. Boa sorte! "
gameforge.subquest_44._270_sendLetter = "Regressa \224 Yu-Rang "
gameforge.subquest_44._280_say = "Regressa \224 Yu-Rang e conta-lhe sobre a mentira do[ENTER]Taurean. "
gameforge.subquest_44._290_npcChat = "A Yu-Rang est\225 muito decepcionada contigo. "
gameforge.subquest_44._300_say = "Contaste-lhe?![ENTER]Aceito que ela n\227o queira continuar a ser minha[ENTER]amiga. Mas fico muito triste. Espero um dia[ENTER]conseguir mudar a sua opini\227o sobre mim. Talvez[ENTER]eu consiga pensar em algo simp\225tico para lhe[ENTER]oferecer... "
gameforge.subquest_44._30_say = "Hey, podes fazer-me um favor? O meu amigo Taurean[ENTER]est\225 muito zangado porque o chamei de cobarde.[ENTER]Ele diz que na realidade \233 muito corajoso, e fez[ENTER]uma aposta comigo em como conseguia pendurar um[ENTER]sino numa Beb\233 Aranha. Ele tamb\233m me disse que j\225[ENTER]o fez, mas n\227o consigo simplesmente acreditar[ENTER]nele. "
gameforge.subquest_44._310_npcChat = "Taurean mentiu. "
gameforge.subquest_44._320_say = "A sua hist\243ria n\227o \233 verdadeira?[ENTER]Hmm, n\227o estou muito zangada pelo facto de ele[ENTER]ter mentido. Ningu\233m gosta de enfrentar uma[ENTER]vergonha. Mas ele devia pelo menos ter tentado[ENTER]fazer com que fosse verdade! N\227o quero continuar[ENTER]a ser amiga de tamanho cobarde. "
gameforge.subquest_44._330_sayReward = "A Yu-Rang vai dar-te uma recompensa pela tua[ENTER]honestidade. "
gameforge.subquest_44._340_sayReward = "Recebeste 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Recebeste 350.000 Pontos de Experi\234ncia. "
gameforge.subquest_44._360_sendLetter = "Sino para a aranha "
gameforge.subquest_44._370_say = "Encontra as Aranhas Beb\233s no deserto e tenta[ENTER]pendurar o sino do Taurean numa delas. "
gameforge.subquest_44._380_npcChat = "Sobre o sino... "
gameforge.subquest_44._390_say = "Ainda n\227o penduraste o sino numa aranha? Ent\227o[ENTER]faz isso rapidamente. E tem cuidado para que a[ENTER]Yu-Rang n\227o te apanhe. "
gameforge.subquest_44._400_sendLetter = "Feito! "
gameforge.subquest_44._40_say = "Sei que devia confiar num amigo meu, mas quero[ENTER]confirmar se ele o fez mesmo. O Deserto \233[ENTER]demasiado perigoso para eu l\225 ir. Mas tu[ENTER]conseguir\225s faz\234-lo facilmente. Podes ir l\225 dar[ENTER]uma vista de olhos por mim? "
gameforge.subquest_44._410_say = "Foi muito dif\237cil, mas finalmente conseguiste[ENTER]pendurar o sino na Aranha Beb\233. Agora regressa a[ENTER]Yu-Rang e diz-lhe que foi o Taurean a fazer. "
gameforge.subquest_44._420_npcChat = "O sino foi pendurado na aranha. "
gameforge.subquest_44._430_say = "Conseguiste? Isso \233 fant\225stico! Ent\227o diz \224[ENTER]Yu-Rang r\225pido para que finalmente ela acredite[ENTER]em mim! "
gameforge.subquest_44._440_npcChat = "O Taurean estava a dizer a verdade. "
gameforge.subquest_44._450_say = "Repete l\225?[ENTER]Encontraste uma aranha com um sino? Ent\227o o[ENTER]Taurean fez mesmo aquilo que disse. Pensava que[ENTER]ele n\227o seria capaz. Afinal talvez um dia ele[ENTER]venha a ser um homem a s\233rio.[ENTER]Obrigado por dares uma vista de olhos por mim.[ENTER]Aqui tens uma recompensa pela tua ajuda. "
gameforge.subquest_44._460_sendLetter = "Regressa ao Taurean "
gameforge.subquest_44._470_targetVid = "Regressa ao Taurean "
gameforge.subquest_44._480_say = "Contaste \224 Yu-Rang que o seu amigo pendurou mesmo[ENTER]um sino uma Beb\233 Aranha.[ENTER]Regressa ao Taurean e informa-o de que ela[ENTER]acreditou na mentira. "
gameforge.subquest_44._490_npcChat = "A Yu-Rang acredita em ti. "
gameforge.subquest_44._500_say = "Muito obrigado. Agora a Yu-Rang n\227o me vai[ENTER]menosprezar. Temos de manter isto em segredo para[ENTER]sempre. Prometes?[ENTER]At\233 breve! "
gameforge.subquest_44._50_select = "Aceitar "
gameforge.subquest_44._510_sayReward = "Taurean deu-te uma recompensa por teres ajudado[ENTER]na mentira: Recebeste 30.000 Yang. "
gameforge.subquest_44._520_sayReward = "Recebeste 700.000 Pontos de Experi\234ncia. "
gameforge.subquest_44._60_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_44._70_say = "Porque n\227o? Tens medo?[ENTER]Vem ter comigo quando mudares de ideias. "
gameforge.subquest_44._80_say = "Aaah, est\225s com medo?[ENTER]Mas tu \233s muito maior e mais forte que eu![ENTER]Haha, \233s um cobarde! Ent\227o vou ter de pedir a[ENTER]outro. "
gameforge.subquest_44._90_say = "As aranhas vivem no deserto. Tu \233s forte. Eu sei[ENTER]que vais conseguir. Boa sorte! "
gameforge.subquest_45 = {}
gameforge.subquest_45._100_sayTitle = "Encontra a informa\231\227o secreta "
gameforge.subquest_45._10_npcChat = "Aquilo sobre o Templo da Escurid\227o "
gameforge.subquest_45._110_say = "Tens a Doutrina do Templo, a Estola do Templo e a[ENTER]Tradu\231\227o das Maldi\231\245es. Leva tudo ao Sr. Soon. "
gameforge.subquest_45._120_say = "Se ajudares o Sr. Soon, o rato de biblioteca, ele[ENTER]poder\225 continuar a sua investiga\231\227o sobre o[ENTER]Templo da Escurid\227o. No entanto, ele apenas o[ENTER]conseguir\225 fazer se estiver na posse dos[ENTER]seguintes itens: a Doutrina do Templo, a Estola[ENTER]do Templo e a Tradu\231\227o das Maldi\231\245es.[ENTER]Obt\233m estes itens e leva-os ao Sr. Soon. Poder\225s[ENTER]encontr\225-los no Templo Hwang, no Vale Seungryong. "
gameforge.subquest_45._130_npcChat = "As coisas do Templo da Escurid\227o "
gameforge.subquest_45._140_say = "Ah, j\225 os conseguiste! Muito obrigado.[ENTER]Sobre o culto secreto no templo, bem, \233 muito[ENTER]simples: s\227o pessoas perigosas. Mas aprendeste[ENTER]isso da maneira dif\237cil. Parece que eles tamb\233m[ENTER]servem deuses das trevas. N\227o tenho mais[ENTER]detalhes, mas assumo que estejam a planear algo[ENTER]muito mau. "
gameforge.subquest_45._150_say = "Agora que tenho alguns dos seus itens sagrados,[ENTER]talvez consiga descobrir mais informa\231\245es. \201[ENTER]melhor come\231ar com a Doutrina do Templo.[ENTER]Vamos l\225 ver... Hmm... Aha...[ENTER]Porque \233 que ainda est\225s aqui? N\227o tens nada para[ENTER]fazer? "
gameforge.subquest_45._160_sayReward = "Recebeste 7.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_45._170_sayReward = "Recebeste 70.000 Yang. "
gameforge.subquest_45._180_sayReward = "Recebeste o Livro do L\237der. "
gameforge.subquest_45._190_say = "O qu\234? Ainda n\227o os tens? N\227o andes a mandriar[ENTER]quando aceitas uma miss\227o! Despacha-te! "
gameforge.subquest_45._200_select = "Tentar novamente "
gameforge.subquest_45._20_say = "H\225 algo a passar-se no interior do Templo da[ENTER]Escurid\227o. Penso que existam por l\225 criaturas[ENTER]perigosas a estudar magia antiga.[ENTER]Os segredos do Templo da Escurid\227o s\227o dif\237ceis[ENTER]de compreender, at\233 para mim. Mas estou certo de[ENTER]que os planos dessas criaturas s\227o muito[ENTER]duvidosos. Tenho de descobrir mais sobre isso! "
gameforge.subquest_45._210_say = "Ent\227o vou ter de perguntar a um her\243i mais forte.[ENTER]At\233 \224 pr\243xima. "
gameforge.subquest_45._220_say = "Obrigado.[ENTER]Eu espero que sejas mais bem sucedido desta vez! "
gameforge.subquest_45._30_say = "Preciso de mais informa\231\245es para os meus estudos.[ENTER]Penso que a Doutrina do Templo, a Estola do[ENTER]Templo e a Tradu\231\227o das Maldi\231\245es possam vir a[ENTER]ser \250teis. Podes trazer-me estas coisas? Ficaria[ENTER]muito agradecido![ENTER]E n\227o te demores muito, preciso disso o mais[ENTER]r\225pido poss\237vel! "
gameforge.subquest_45._40_select = "Vou j\225 faz\234-lo. "
gameforge.subquest_45._50_say = "Queres aceitar a miss\227o? "
gameforge.subquest_45._60_say = "Eu estou a pedir a tua ajuda! Se est\225s demasiado[ENTER]ocupado agora, volta mais tarde. Talvez tenhas[ENTER]mais tempo. Vou ficar \224 tua espera. "
gameforge.subquest_45._70_say = "Eu pedi-te ajuda e tu viras-me as costas?[ENTER]Oh, est\225 bem, tamb\233m n\227o precisamos de ti...[ENTER]Agora desaparece! "
gameforge.subquest_45._80_say = "Obrigado! "
gameforge.subquest_45._90_makequestbutton = "Templo da Escurid\227o "
gameforge.subquest_46 = {}
gameforge.subquest_46._100_say = "Boa sorte na tua busca! Apenas poderei criar a[ENTER]Porcelana correcta se tiver os materiais certos.[ENTER]Os meus clientes est\227o muito impacientes! "
gameforge.subquest_46._10_targetVid = "O Segredo da Porcelana Celadon "
gameforge.subquest_46._110_makequestbutton = "Porcelana Celadon "
gameforge.subquest_46._120_qSetTitle = "Porcelana Celadon "
gameforge.subquest_46._130_say = "Tens todos os materiais que o Yonah precisa para[ENTER]criar a Porcelana Celadon. Leva-os ao Yonah! "
gameforge.subquest_46._140_say = "Para que o Yonah possa criar a Porcelana Celadon,[ENTER]ele precisa dos seguintes materiais:[ENTER]Areia do Deserto dos Bandidos do Deserto, Min\233rio[ENTER]de Cristal dos Veios de Cristal e Sangue de[ENTER]Macaco dos Macacos Pedra Fortes ou Macacos[ENTER]Dourados Fortes na Caverna dos Macacos Dif\237ceis.[ENTER]Encontra os tr\234s materiais e leva-os ao Yonah! "
gameforge.subquest_46._150_targetVid = "O Segredo da Porcelana Celadon "
gameforge.subquest_46._160_npcChat = "Consegui todos os materiais "
gameforge.subquest_46._170_say = "Conseguiste! Obrigado! Com a t\233cnica correcta e[ENTER]os materiais certos poderei produzir a magn\237fica[ENTER]Porcelana Celadon. Os lucros que terei com a sua[ENTER]venda ser\227o uma b\234n\231\227o para a minha carteira.[ENTER]Toma esta recompensa. Mereceste-a. Irei come\231ar a[ENTER]produzir a Porcelana imediatamente! "
gameforge.subquest_46._180_sayReward = "Recebeste 3.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_46._190_sayReward = "Recebeste 30.000 Yang. "
gameforge.subquest_46._20_say = "Ol\225 aventureiro! N\227o foste tu quem h\225 uns tempos[ENTER]me trouxe as notas do Sr. Soon sobre como[ENTER]produzir Porcelana Celadon? Tenho um problema...[ENTER]Embora agora conhe\231a a t\233cnica, ainda n\227o estou a[ENTER]conseguir produzir Porcelana Celadon genu\237na.[ENTER]Provavelmente deve-se ao facto de eu utilizar os[ENTER]meus ingredientes normais, em vez dos materiais[ENTER]indicados nas notas, que s\227o dif\237ceis de obter. "
gameforge.subquest_46._30_say = "Preciso da fina Areia do Deserto, de uma unidade[ENTER]de Min\233rio de Cristal e de Sangue de Macaco. Se[ENTER]os misturar e adicion\225-los ao Barro, este ficar\225[ENTER]bastante duro quando exposto ao fogo. Al\233m disso[ENTER]a sua cor passar\225 a um verde p\225lido, parecida com[ENTER]jade. Esta cor \233 muito popular entre os meus[ENTER]clientes e por isso preciso de vender mais! "
gameforge.subquest_46._40_say = "Podes obter a Areia do Deserto dos Bandidos do[ENTER]Deserto, o Min\233rio de Cristal dos Veios de[ENTER]Cristal e para o Sangue de Macaco ter\225s de matar[ENTER]macacos na Caverna dos Macacos Dif\237ceis.[ENTER]Podes arranjar-me estes materiais? Sei que n\227o[ENTER]ser\225 f\225cil, mas irei dar-te uma recompensa[ENTER]generosa. "
gameforge.subquest_46._50_select = "Aceitar "
gameforge.subquest_46._60_select = "Recusar "
gameforge.subquest_46._70_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_46._80_say = "Se est\225s demasiado ocupado de momento, volta mais[ENTER]tarde. "
gameforge.subquest_46._90_say = "Est\225s a desistir? A s\233rio? Parece que tenho de[ENTER]procurar os materiais por mim mesmo. Preciso[ENTER]mesmo desta Porcelana. Adeus e boa sorte. "
gameforge.subquest_47 = {}
gameforge.subquest_47._100_select = "Ah! \201 isso. "
gameforge.subquest_47._10_answer = "Inimigos no horizonte "
gameforge.subquest_47._10_targetVid = "Capit\227o "
gameforge.subquest_47._110_select = "N\227o sei. "
gameforge.subquest_47._115_select = "Mostra-me de novo. "
gameforge.subquest_47._120_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_47._130_say = "Pensa de novo e volta mais tarde. Mas n\227o contes[ENTER]isto a outros! "
gameforge.subquest_47._140_say = "Oh meu Deus! \201 assim t\227o dif\237cil? Eras a minha[ENTER]\250ltima esperan\231a... E agora quem o ir\225 decifrar? "
gameforge.subquest_47._150_say = "Ok, mas despacha-te. Caso contr\225rio algu\233m vai[ENTER]come\231ar a suspeitar de algo:[ENTER][ENTER]Imoginis[ENTER]on[ENTER]enothizor "
gameforge.subquest_47._160_say = "E ent\227o? O que \233 que este c\243digo significa? "
gameforge.subquest_47._170_say = "Sim, est\225 certo! Agora tamb\233m j\225 compreendo.[ENTER]Tenho orgulho em ti. \201s um dos nossos melhores[ENTER]soldados![ENTER]Esta frase \233 uma palavra-passe combinada.[ENTER]Significa que o Yu-Hwan encontrou espi\245es[ENTER]inimigos e que precisamos de tomar ac\231\245es contra[ENTER]eles. Irei dar as ordens imediatamente. "
gameforge.subquest_47._180_sayReward = "Recebeste 1.300.000 Pontos de Experi\234ncia. "
gameforge.subquest_47._190_say = "Porque est\225s t\227o calado? N\227o consegues decifrar a[ENTER]mensagem? "
gameforge.subquest_47._200_select = "Tenho de pensar novamente. "
gameforge.subquest_47._20_answer = "Inimigos no horizonte "
gameforge.subquest_47._20_npcChat = "Sobre o c\243digo secreto... "
gameforge.subquest_47._210_select = "Desisto. "
gameforge.subquest_47._220_say = "Oh meu Deus! \201 assim t\227o dif\237cil? Eras a minha[ENTER]\250ltima esperan\231a... E agora quem o ir\225 decifrar? "
gameforge.subquest_47._230_say = "Ent\227o, o que significa? "
gameforge.subquest_47._240_say = "Sim, est\225 certo! Agora tamb\233m j\225 compreendo.[ENTER]Tenho orgulho em ti. \201s um dos nossos melhores[ENTER]soldados![ENTER]Esta frase \233 uma palavra-passe combinada.[ENTER]Significa que o Yu-Hwan encontrou espi\245es[ENTER]inimigos e que precisamos de tomar ac\231\245es contra[ENTER]eles. Irei dar as ordens imediatamente. "
gameforge.subquest_47._250_sayReward = "Recebeste 2.300.000 Pontos de Experi\234ncia. "
gameforge.subquest_47._260_say = "Tu ir\225s descobrir. Volta quando estiveres pronto! "
gameforge.subquest_47._270_say = "Hmm, isso n\227o me diz nada. O que ser\225 que ele[ENTER]quis dizer com isso?[ENTER]N\227o me parece que esteja correcto. Pensa de novo. "
gameforge.subquest_47._280_select = "Vou tentar de novo. "
gameforge.subquest_47._290_select = "Desisto. "
gameforge.subquest_47._300_say = "Ent\227o? O que \233 que significa? "
gameforge.subquest_47._301_answer_correct = "Inimigos no horizonte "
gameforge.subquest_47._302_answer_wrong = "Amigos no horizonte "
gameforge.subquest_47._303_answer_wrong = "Inimigo no horizonte "
gameforge.subquest_47._304_answer_wrong = "A verdade faz inimigos "
gameforge.subquest_47._305_answer_dontknow = "N\227o tenho ideia "
gameforge.subquest_47._30_say = "ATEN\199\195O![ENTER]Ah, \233s tu. Ainda bem que aqui est\225s! Recebi[ENTER]algumas informa\231\245es do Yu-Hwan. Ele escreveu a[ENTER]mensagem numa escrita secreta, como de costume.[ENTER]Demoro s\233culos para a decifrar. E tenho de lidar[ENTER]com este assunto rapidamente.[ENTER]Da \250ltima vez conseguiste faz\234-lo facilmente.[ENTER]Podes ajudar-me de novo, por favor? "
gameforge.subquest_47._310_say = "Sim, est\225 certo! Agora tamb\233m j\225 compreendo.[ENTER]Tenho orgulho em ti. \201s um dos nossos melhores[ENTER]soldados![ENTER]Esta frase \233 uma palavra-passe combinada.[ENTER]Significa que o Yu-Hwan encontrou espi\245es[ENTER]inimigos e que precisamos de tomar ac\231\245es contra[ENTER]eles. Irei dar as ordens imediatamente. "
gameforge.subquest_47._320_sayReward = "Recebeste 20.000 Yang. "
gameforge.subquest_47._330_say = "Tu ir\225s descobrir. Volta quando estiveres pronto! "
gameforge.subquest_47._40_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_47._50_say = "Mas tu conseguiste faz\234-lo da \250ltima vez. Porque[ENTER]est\225s a hesitar agora? Pensa melhor. "
gameforge.subquest_47._60_say = "Percebo o que queres dizer.[ENTER]N\227o queres trabalhar mais connosco, n\227o \233?[ENTER]\201 uma pena. N\227o h\225 muitos guerreiros corajosos. "
gameforge.subquest_47._70_say = "Oh! \201s a minha salva\231\227o! V\234, este \233 o c\243digo. D\225[ENTER]uma boa vista de olhos! "
gameforge.subquest_47._80_say = "Imoginis[ENTER]on[ENTER]enothizor[ENTER][ENTER]Consegues decifrar isto? "
gameforge.subquest_47._90_say = "Ent\227o como vai isso? Alguma pista? "
gameforge.subquest_48 = {}
gameforge.subquest_48._100_sayTitle = "Encontrar o espi\227o "
gameforge.subquest_48._10_npcChat = "Encontra o Espi\227o "
gameforge.subquest_48._110_say = "Um dos espi\245es vive como um pescador na vila de[ENTER]Pyungmo no reino de Jinno. Tenta entrar em[ENTER]contacto com ele discretamente e volta ao Capit\227o[ENTER]com o seu relat\243rio. "
gameforge.subquest_48._120_say = "Um dos espi\245es vive como um pescador na vila de[ENTER]Yongan no reino de Shinsoo. Tenta entrar em[ENTER]contacto com ele discretamente e volta ao Capit\227o[ENTER]com o seu relat\243rio. "
gameforge.subquest_48._130_say = "Um dos espi\245es vive como um pescador na vila de[ENTER]Joan no reino de Chunjo. Tenta entrar em contacto[ENTER]com ele discretamente e volta ao Capit\227o com o[ENTER]seu relat\243rio. "
gameforge.subquest_48._140_npcChat = "O que est\225s a fazer? "
gameforge.subquest_48._150_say = "Pshh, est\225 quieto! Est\225s a afugentar os peixes[ENTER]todos. E porque est\225s aqui j\225 agora? Fazes tanto[ENTER]barulho e \233s t\227o trapalh\227o; n\227o est\225s aqui para[ENTER]pescar certamente. "
gameforge.subquest_48._160_say = "Ah, compreendo. H\225 algum tempo que te espero;[ENTER]est\225s atrasado. N\227o foi f\225cil obter esta[ENTER]informa\231\227o sem ser capturado. Tens de compreender[ENTER]que os inimigos est\227o por toda a parte e que[ENTER]apenas est\227o \224 espera que descures o teu[ENTER]disfarce. "
gameforge.subquest_48._170_say = "Agora n\227o devemos ficar por aqui juntos mais[ENTER]tempo! Afinal de contas, n\227o queremos que algu\233m[ENTER]nos descubra.[ENTER]Aqui tens os documentos. Agora p\245e-te j\225 a[ENTER]caminho e vai entregar os documentos directamente[ENTER]ao Capit\227o. "
gameforge.subquest_48._180_say = "Um momento, por favor![ENTER]Tenho algo para ti. Um pequeno presente. Agora[ENTER]p\245e-te a caminho. "
gameforge.subquest_48._190_sayReward = "Est\225s curioso e abres o pacote para veres o que o[ENTER]espi\227o te ofereceu. "
gameforge.subquest_48._200_say = "\211ptimo! Escard\237nios Grelhados! \201 \243bvio que o[ENTER]espi\227o realmente percebe algo de pesca. "
gameforge.subquest_48._20_say = "Calma, soldado![ENTER]Uma vez que todos os Reinos mais pr\243ximos s\227o[ENTER]nossos inimigos, \233 importante que tenhamos amigos[ENTER]que possam esconder-se e recolher informa\231\227o para[ENTER]que possamos estar preparados para qualquer[ENTER]ataque. \201 extremamente importante que o seu[ENTER]disfarce nunca seja descoberto. "
gameforge.subquest_48._210_sayReward = "Recebeste 3 Escard\237nios Grelhados. "
gameforge.subquest_48._220_sendLetter = "Regressa ao Capit\227o "
gameforge.subquest_48._230_targetVid = "O Capit\227o "
gameforge.subquest_48._240_say = "A perigosa viagem a Pyungmoo no reino de Jinno[ENTER]foi um sucesso: recebeste informa\231\245es importantes[ENTER]do espi\227o que est\225 disfar\231ado de pescador.[ENTER]Agora regressa ao teu reino e leva essa[ENTER]informa\231\227o rapidamente ao Capit\227o. "
gameforge.subquest_48._250_say = "A perigosa viagem a Yongan no reino de Shinsoo[ENTER]foi um sucesso: recebeste informa\231\245es importantes[ENTER]do espi\227o que est\225 disfar\231ado de pescador.[ENTER]Agora regressa ao teu reino e leva essa[ENTER]informa\231\227o rapidamente ao Capit\227o. "
gameforge.subquest_48._260_say = "A perigosa viagem a Joan no reino de Chunjo foi[ENTER]um sucesso: recebeste informa\231\245es importantes do[ENTER]espi\227o que est\225 disfar\231ado de pescador.[ENTER]Agora regressa ao teu reino e leva essa[ENTER]informa\231\227o rapidamente ao Capit\227o. "
gameforge.subquest_48._270_npcChat = "A miss\227o foi um sucesso! "
gameforge.subquest_48._280_say = "S\227o estes os documentos? \211ptimo! Obrigado.[ENTER]Agora que sabemos sobre os planos dos nossos[ENTER]inimigos, podemos preparar-nos correctamente para[ENTER]nos protegermos. Fizeste um \243ptimo servi\231o para o[ENTER]teu reino! "
gameforge.subquest_48._290_sayReward = "Recebeste 5.500.000 Pontos de Experi\234ncia. "
gameforge.subquest_48._300_sayReward = "Recebeste 50.000 Yang. "
gameforge.subquest_48._30_say = "De certo que conheces o musico Yu-Hwan, correcto?[ENTER]Ele tamb\233m \233 um espi\227o e trabalha para n\243s. Um s\243[ENTER]espi\227o n\227o ajuda em nada, por isso temos v\225rios[ENTER]espalhados por todo o mundo. Um deles est\225 na[ENTER]primeira vila disfar\231ado de pescador. "
gameforge.subquest_48._40_say = "Uma vez que n\227o posso contactar directamente com[ENTER]ele sem estragar o seu disfarce, preciso da ajuda[ENTER]de alguns soldados destemidos.[ENTER]Sim, refiro-me a ti! Por favor, vai ter com este[ENTER]Pescador e recolhe o seu relat\243rio mais recente.[ENTER]\201 da maior import\226ncia para a seguran\231a do nosso[ENTER]Reino! "
gameforge.subquest_48._50_say = "Queres desistir desta miss\227o? "
gameforge.subquest_48._60_say = "Queres preparar-te primeiro? Ok, mas volta[ENTER]r\225pido. Ficarei \224 tua espera. Mas por favor[ENTER]despacha-te...Preciso desse relat\243rio! "
gameforge.subquest_48._70_say = "O que se passa contigo? Da \250ltima vez fizeste um[ENTER]trabalho fant\225stico para n\243s! E agora s\243 queres[ENTER]abandonar o teu reino? Mas n\227o h\225 nada que eu[ENTER]possa fazer sobre isso. At\233 \224 pr\243xima. "
gameforge.subquest_48._80_say = "Eu sabia que podia contar contigo. Boa sorte e[ENTER]tem cuidado! "
gameforge.subquest_48._90_makequestbutton = "Encontra-te com o espi\227o "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "O que \233 o Bingsu? "
gameforge.subquest_49._10_targetVid = "Bingsu? "
gameforge.subquest_49._110_say = "O Taurean tem andado em discuss\245es com a Harang[ENTER]porque ele n\227o acredita nela quando ela diz que \233[ENTER]poss\237vel fazer gelados no Ver\227o. Vai ter com a[ENTER]Harang e pergunta-lhe o que sabe sobre o Bingsu. "
gameforge.subquest_49._120_qSetTitle = "Perguntar \224 Harang "
gameforge.subquest_49._130_targetVid = "Perguntar \224 Harang "
gameforge.subquest_49._140_npcChat = "O que \233 o Bingsu? "
gameforge.subquest_49._150_say = "Aquele Taurean gosta de fingir que percebe de[ENTER]tudo. Ele nem sabe o que \233 o Bingsu! Como \233[ENTER]poss\237vel algu\233m n\227o conhecer uma coisa t\227o[ENTER]deliciosa?[ENTER]Tu tamb\233m n\227o sabes o que \233 o Bingsu?? Bom, \233[ENTER]melhor ires ao Oct\225vio na pr\243xima vila. Ele \233 um[ENTER]chef famoso e conhece muitas receitas deliciosas.[ENTER]Ele uma vez fez Bingsu para mim... mmmmh. Ele vai[ENTER]provar-te que tenho raz\227o! "
gameforge.subquest_49._160_makequestbutton = "Vamos ter com o Oct\225vio "
gameforge.subquest_49._170_say = "O Taurean quer mesmo saber o que \233 o Bingsu.[ENTER]Vai ter com o Oct\225vio, o dono do restaurante. Ele[ENTER]certamente poder\225 ajudar-te. "
gameforge.subquest_49._180_npcChat = "Sabes o que \233 o Bingsu? "
gameforge.subquest_49._190_say = "Bingsu? \201 claro que sei o que \233. Qualquer[ENTER]cozinheiro que se preze sabe fazer Bingsu![ENTER]Primeiro \233 preciso gelo picado bastante fino.[ENTER]Depois espalha-se a\231\250car por cima, adiciona-se[ENTER]fatias finas de Bolo de Arroz e, finalmente,[ENTER]frutas frescas para decora\231\227o. "
gameforge.subquest_49._200_say = "Porque perguntas? O Taurean e a Harang andam a[ENTER]discutir? Isso n\227o \233 novidade. Mas a Harang tem[ENTER]raz\227o. O Bingsu \233 algo extremamente popular em[ENTER]Ver\245es quentes. O Taurean \233 um bom rapaz, mesmo[ENTER]que por vezes seja um pouco picuinhas. Se me[ENTER]arranjares os ingredientes poderei fazer Bingsu[ENTER]para ele. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Gostaria de dar um presente ao Taurean e dar-lhe[ENTER]Bingsu. O que achas? Podes arranjar-me Pe\231as de[ENTER]Gelo da Montanha Sohan? "
gameforge.subquest_49._220_say = "Queres desistir desta Miss\227o? "
gameforge.subquest_49._230_say = "N\227o gostas de gelado? Ou j\225 comeste demasiado? \201[ENTER]para o Taurean, por isso por favor pensa melhor[ENTER]nisso. "
gameforge.subquest_49._240_say = "Que pena. O Taurean vai ficar muito desapontado.[ENTER]Adeus. "
gameforge.subquest_49._250_say = "Muito bem. Preciso de Pe\231as de Gelo que podes[ENTER]obter dos Gelos Encantados na Montanha Sohan.[ENTER]Traz-me 50 Pe\231as de Gelo. Depois poderei fazer o[ENTER]delicioso Bingsu. "
gameforge.subquest_49._260_targetVid = "Dirige-te ao Oct\225vio "
gameforge.subquest_49._270_say = "%s[ENTER]Conseguiste as Pe\231as de Gelo para o Bingsu do[ENTER]Taurean. Leva-as ao Oct\225vio. "
gameforge.subquest_49._275_say = "Tenho as Pe\231as de Gelo "
gameforge.subquest_49._280_say = "O Oct\225vio concordou fazer Bingsu para o Taurean,[ENTER]mas para isso precisa de gelo. Mata Gelos[ENTER]Encantados na Montanha Sohan e obt\233m 50 Pe\231as de[ENTER]Gelo. Depois leva-as ao Oct\225vio. "
gameforge.subquest_49._285_say = "\192 procura das Pe\231as de Gelo "
gameforge.subquest_49._290_npcChat = "Toma, trouxe-te as Pe\231as de Gelo. "
gameforge.subquest_49._300_say = "Ah, muito bem! A parte mais dif\237cil de fazer[ENTER]Bingsu j\225 est\225 terminada. Agora apenas preciso de[ENTER]espalhar um pouco de a\231\250car... e algumas[ENTER]frutas...[ENTER]Aqui tens! Um gelado para o Taurean. Leva-o at\233[ENTER]ele, que ele ir\225 esquecer a sua raiva[ENTER]rapidamente. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Desculpa, mas isso n\227o chega. Tens de arranjar[ENTER]mais, caso contr\225rio ser\225 uma por\231\227o muito[ENTER]pequena. "
gameforge.subquest_49._320_select = "Tentar de novo "
gameforge.subquest_49._330_say = "Sei que \233 muito longe e os monstros s\227o fortes.[ENTER]Se \233 demasiado dif\237cil para ti, ent\227o n\227o h\225 nada[ENTER]que possamos fazer.[ENTER]Adeus. "
gameforge.subquest_49._340_say = "Tenta de novo. Com a tua coragem e resist\234ncia[ENTER]ir\225s conseguir! "
gameforge.subquest_49._350_targetVid = "Bingsu? "
gameforge.subquest_49._360_say = "Est\225 pronto: O Oct\225vio fez o Bingsu a partir do[ENTER]gelo da Montanha Sohan. Vai ter com o Taurean[ENTER]rapidamente antes que derreta. "
gameforge.subquest_49._370_npcChat = "Aqui tens o Bingsu! "
gameforge.subquest_49._380_say = "Isto \233 o Bingsu? Sabe muito bem. Saboroso e[ENTER]refrescante. Nunca tinha provado nada como isto[ENTER]antes, obrigado! Ent\227o a Harang tem raz\227o. Terei[ENTER]que lhe pedir desculpas... "
gameforge.subquest_49._390_sayReward = "Recebeste 6.000.000 Pontos de Experi\234ncia. "
gameforge.subquest_49._400_sayReward = "Recebeste 70.000 Yang. "
gameforge.subquest_49._40_say = "Hoje tive uma discuss\227o com a Harang. Eu podia...[ENTER]Ela diz que h\225 algo muito delicioso feito de gelo[ENTER]picado. Chama-se Bingsu. "
gameforge.subquest_49._410_sayReward = "Recebeste um Pergaminho da Guerra. "
gameforge.subquest_49._420_say = "Lembraste-te de me trazer algum Bingsu? "
gameforge.subquest_49._430_say = "Oh meus Deus, esqueci-me completamente disso![ENTER]Hmm, ser\225 que devo continuar a tentar? Ou \233[ENTER]melhor desistir? "
gameforge.subquest_49._440_select = "Sim, vou continuar. "
gameforge.subquest_49._450_select = "Desisto. "
gameforge.subquest_49._460_say = "N\227o o consigo fazer, desculpa. "
gameforge.subquest_49._50_say = "Algo desse tipo apenas \233 poss\237vel durante o frio[ENTER]do Inverno. Mas ela continua a afirmar que \233[ENTER]poss\237vel. Podes descobrir se tamb\233m \233 poss\237vel[ENTER]fazer esse tal Bingsu no Ver\227o? Se \233 que tal[ENTER]coisa existe... "
gameforge.subquest_49._60_say = "Estou certo que este Bingsu \233 delicioso! Tens a[ENTER]certeza que nunca me vais querer ajudar a[ENTER]faz\234-lo? "
gameforge.subquest_49._70_say = "Se quiseres tentar de novo mais tarde avisa-me. "
gameforge.subquest_49._80_say = "Gostaria mesmo de experimentar o Bingsu... Mas[ENTER]tens raz\227o. A Harang provavelmente apenas se est\225[ENTER]a armar em sabichona e esse Bingsu nem existe![ENTER]Adeus. "
gameforge.subquest_49._90_say = "Obrigado pela tua ajuda. Avisa-me quando[ENTER]descobrires algo. Ent\227o poderei dizer das boas \224[ENTER]Harang! "
