gameforge.training_mount = {}
gameforge.training_mount._01_say = "Desculpa, mas n\227o tens a experi\234ncia de equita\231\227o[ENTER]necess\225ria para poderes melhorar a tua montada.[ENTER]Precisas de ter pelo menos um Cavalo Armado. "
gameforge.training_mount._02_say = "Desculpa, mas sem os documentos correctos n\227o h\225[ENTER]nada que possa fazer. N\227o me tentes enganar de[ENTER]novo, ou irei fazer-te pagar por isso. "
gameforge.training_mount._03_say = "Onde est\225 o teu Selo de Montada? N\227o posso[ENTER]melhorar montadas sem esse Selo.[ENTER]Espreita a moeda girat\243ria no canto inferior[ENTER]esquerdo. L\225 poder\225s encontrar Certificados que[ENTER]podem ser trocados por Selos de Montadas. "
gameforge.training_mount._04_say = "Quero usar uma nova montada! "
gameforge.training_mount._05_say = "Hey! Ainda montas um cavalo?! A s\233rio? Sabes que[ENTER]hoje em dia j\225 conseguimos domar animais[ENTER]selvagens, certo? "
gameforge.training_mount._06_say = "Para domares animais selvagens e os poderes[ENTER]treinar para o combate precisas de experi\234ncia em[ENTER]equita\231\227o. Al\233m disso ir\225s precisar de um dos[ENTER]seguintes itens: o Pergaminho da Evolu\231\227o, para[ENTER]evolu\237res a tua montada jovem para uma montada[ENTER]selvagem ou o Pergaminho da Muta\231\227o, para a[ENTER]evolu\237res uma montada selvagem para uma montada[ENTER]corajosa. "
gameforge.training_mount._07_say = "Se tiveres d\250vidas podes sempre vir falar comigo[ENTER]de novo. Tentarei ajudar-te no que for poss\237vel. "
gameforge.training_mount._08_say = "Quero melhorar a minha montada! "
gameforge.training_mount._09_say = "Ent\227o queres melhorar a tua montada? Sabes como[ENTER]funciona? Ok, vou explicar-te. "
gameforge.training_mount._10_say = "Para melhorares a tua montada jovem para uma[ENTER]montada selvagem, precisas de obter o Pergaminho[ENTER]da Evolu\231\227o. Encontra um Pergaminho da Muta\231\227o se[ENTER]o que pretendes \233 melhorar a tua montada selvagem[ENTER]para uma montada corajosa. Diz-se que estes[ENTER]pergaminhos podem ser encontrados numa terra[ENTER]long\237nqua habitada por perigosos gigantes! "
gameforge.training_mount._11_say = "Traz-me estes pergaminhos e irei melhorar a tua[ENTER]montada. Por acaso j\225 n\227o os ter\225s contigo? "
gameforge.training_mount._12_say = "Sim, quero melhorar a minha montada! "
gameforge.training_mount._13_say = "N\227o, para j\225 n\227o. "
gameforge.training_mount._14_say = "Ah, ent\227o tens contigo os pergaminhos. Qual deles[ENTER]tens? O Pergaminho da Evolu\231\227o permite-te treinar[ENTER]uma montada inexperiente para poder ser usada em[ENTER]combate. O Pergaminho da Muta\231\227o permite-te[ENTER]melhor\225-la para uma montada corajosa. "
gameforge.training_mount._15_2_say = "Tenho o Pergaminho da Muta\231\227o. "
gameforge.training_mount._15_say = "Tenho o Pergaminho da Evolu\231\227o. "
gameforge.training_mount._16_say = "N\227o tenho pergaminhos comigo. "
gameforge.training_mount._17_say = "Ah, vejam - o Pergaminho da Evolu\231\227o! Ok,[ENTER]deixa-me dar uma olhada no teu Selo de Montada.[ENTER]Algumas pessoas t\234m tentado trazer-me Selos[ENTER]falsos. Primeiro tenho de verificar a sua[ENTER]autenticidade. Passa-o para c\225.[ENTER](Arrasta o Selo para o Rapaz do Est\225bulo) "
gameforge.training_mount._18_say = "O Pergaminho da Muta\231\227o! At\233 agora ainda s\243 tinha[ENTER]ouvido falar dele em hist\243rias. Nunca tive um nas[ENTER]m\227os. Mostra-me o teu Selo de Montada ent\227o. Irei[ENTER]troc\225-lo por um mais poderoso assim que tiver[ENTER]verificado a sua autenticidade.[ENTER](Arrasta o Selo para o Rapaz do Est\225bulo) "
gameforge.training_mount._19_say = "Assim que tiveres encontrado um dos pergaminhos[ENTER]vem ter comigo. Irei trocar o teu Selo de montada[ENTER]antigo por um mais poderoso. "
gameforge.training_mount._20_say = "O teu Selo de montada j\225 viu melhores dias[ENTER]realmente. Espera um pouco, vou troc\225-lo por um[ENTER]novo.[ENTER]Aqui tens. Agora poder\225s invocar a tua montada[ENTER]selvagem.[ENTER]Vem ter comigo quando tiveres encontrado o[ENTER]Pergaminho da Muta\231\227o. Posso us\225-lo para dar-te[ENTER]um Selo de montada ainda mais poderoso. "
gameforge.training_mount._21_say = "Esse \233 o Selo de montada que recebeste de mim h\225[ENTER]algum tempo. Est\225 bastante gasto. D\225-mo e irei[ENTER]criar um Selo de montada para ti ainda mais[ENTER]poderoso! "
gameforge.training_mount._22_say = "Este Selo permite-te invocar a tua montada[ENTER]transformada. \201 inestim\225vel, por isso guarda-a[ENTER]com cuidado! "
gameforge.training_mount._23_say = "Posso usar habilidades de cavalo? "
gameforge.training_mount._24_say = "Queres usar habilidades de cavalo? \201s uma pessoa[ENTER]muito exigente! Embora eu tamb\233m sonhe com[ENTER]elas... Muito bem. Para as aprenderes primeiro[ENTER]tens de seguir algumas regras. "
gameforge.training_mount._25_say = "Para come\231ar, precisas de ser um mestre na[ENTER]equita\231\227o, caso contr\225rio estar\225s a colocar-te em[ENTER]perigo. Al\233m disso, a tua montada precisa de[ENTER]estar preparada para o combate, pois s\243 ent\227o[ENTER]poder\225 fazer uso das habilidades de cavalo. "
gameforge.training_mount._26_say = "A tua montada est\225 pronta para aprender[ENTER]habilidades de cavalo? N\227o poderei permitir que o[ENTER]treino continue caso n\227o esteja. O que queres[ENTER]fazer? "
gameforge.training_mount._27_say = "Compreendo. Irei agora avaliar a tua for\231a e[ENTER]mestria na equita\231\227o. Por favor espera um[ENTER]momento. "
gameforge.training_mount._28_say = "Hmm... Coluna forte, profici\234ncia na equita\231\227o e[ENTER]a tua montada parece estar pronta para o combate.[ENTER]Podes usar habilidades de cavalo. "
gameforge.training_mount._29_say = "Agora a tua montada pode usar habilidades de[ENTER]cavalo. No entanto, se arranjares outra montada,[ENTER]ela ter\225 de ser treinada e tamb\233m aprender as[ENTER]habilidades. Nesse caso, vem ter comigo[ENTER]novamente. "
gameforge.training_mount._30_say = "Vamos l\225 ver... J\225 te disse que \233 perigoso se n\227o[ENTER]tiveres experi\234ncia em equita\231\227o. Vem ter comigo[ENTER]quando fores mais experiente. "
gameforge.training_mount._31_say = "Lamento, mas parece que a tua montada ainda n\227o[ENTER]est\225 pronta.[ENTER]Vem ter comigo quando ela estiver mais desejosa[ENTER]de combate. "
gameforge.training_mount._32_say = "Talvez possas desmontar-te enquanto falamos?[ENTER]Tenho uma dor no pesco\231o e custa-me ter de olhar[ENTER]para cima para falar contigo. "
gameforge.training_mount._33_say = "N\227o tens a experi\234ncia de equita\231\227o necess\225ria[ENTER]para melhorares a tua montada. Precisas de ter[ENTER]pelo menos um Cavalo Armado para poderes treinar[ENTER]uma montada selvagem. Para poderes ter uma[ENTER]montada corajosa precisas de um Cavalo Militar. "
gameforge.training_mount._34_say = "Vejo que tens um Snack do Poder. Esta valiosa[ENTER]erva medicinal proporciona energia pura \224 tua[ENTER]Montada Melhor\225vel - ir\225 aumentar a sua dura\231\227o[ENTER]um certo n\250mero de dias. O que devo fazer?[ENTER]Queres que eu aumente a dura\231\227o da tua Montada ou[ENTER]pretendes que eu a melhore? "
gameforge.training_mount._35_select_1 = "Aumentar dura\231\227o "
gameforge.training_mount._35_select_2 = "Melhorar "
gameforge.training_mount._36_select_1 = "7 Dias "
gameforge.training_mount._36_select_2 = "15 Dias "
gameforge.training_mount._36_select_3 = "30 Dias "
gameforge.training_mount._36_select_4 = "Pergaminho da Muta\231\227o + 200k Yang "
gameforge.training_mount._37_say = "Infelizmente n\227o possuis o Snack do Poder[ENTER]apropriado para o aumento de dura\231\227o que[ENTER]escolheste. Mas tenho a certeza que o ir\225s[ENTER]encontrar atrav\233s da moeda rotativa! "
gameforge.training_mount._38_say = "O Pergaminho da Muta\231\227o possui um enorme poder![ENTER]Ele poder\225 aumentar a dura\231\227o da tua Montada[ENTER]Corajosa em at\233 4 dias. Uma tentativa ir\225[ENTER]custar-te 200.000 Yang. Mas a tua montada tem de[ENTER]se encontrar exausta e com menos de 1 dia de[ENTER]dura\231\227o restante para poderes usar essa[ENTER]tentativa. E \233 claro, um pouco de sorte tamb\233m[ENTER]faz parte deste processo! Se a tentativa falhar,[ENTER]recomendo a utiliza\231\227o de um Snack do Poder.[ENTER]Estes Snacks podem ser encontrados atrav\233s da[ENTER]moeda rotativa. "
gameforge.training_mount._39_say = "A tua Montada Melhor\225vel ainda tem demasiado[ENTER]poder. O Pergaminho da Muta\231\227o n\227o ter\225 qualquer[ENTER]efeito. Volta quando a tua Montada tiver menos de[ENTER]1 dia de dura\231\227o restante. "
gameforge.training_mount._40_say = "Infelizmente n\227o te posso ajudar. N\227o possuis um[ENTER]Pergaminho da Muta\231\227o ou tens menos de 200.000[ENTER]Yang. "
