gameforge.upgrade_refine_scroll._170_say = "Produzi um Pergaminho do Drag\227o! Realmente \233[ENTER]muito f\225cil produzir um Pergaminho do Drag\227o[ENTER]quando uso Metal M\225gico. Gosto disso! "
