gameforge.upgrade_refine_scroll._250_say = "Produzi um Manual do Ferreiro para ti! Agora tens[ENTER]o conhecimento antigo de uma dinastia completa de[ENTER]Ferreiros. Usa-o de forma s\225bia! Ha, ha, ha! "
gameforge.upgrade_refine_scroll._260_sayItem = "Manual do Ferreiro "
