gameforge.warehouse._100_say = "Bem-vindo! Sabes para que servem as Barras[ENTER]d'Ouro? Andares por a\237 com Yang \233 o mesmo que[ENTER]dizeres: Por favor, matem-me j\225! \201 por isso que[ENTER]eu troco o Yang das pessoas por Barras d'Ouro e[ENTER]as armazeno. "
gameforge.warehouse._10_npcChat = "Quero usar o Armaz\233m. "
gameforge.warehouse._110_say = "Ok, eu pe\231o-te mais do que normalmente pagarias[ENTER]por uma Barra de Ouro. Mas ainda \233 um pre\231o[ENTER]justo, n\227o achas? N\227o h\225 qualquer raz\227o para te[ENTER]sentires enganado. Como deves saber, existem[ENTER]muitos perigos por a\237... "
gameforge.warehouse._120_npcChat = "Abrir Armaz\233m de Artigos "
gameforge.warehouse._130_say = "As minas est\227o esgotadas. \201 dif\237cil encontrar[ENTER]Ouro ou Prata. Enquanto n\227o forem encontrados[ENTER]novos veios de min\233rio, n\227o haver\225 mais Ouro ou[ENTER]Prata. "
gameforge.warehouse._140_say = "Bem vindo![ENTER]Queres ver o teu Armaz\233m de Artigos? Ent\227o porque[ENTER]vieste ter comigo? Olha para o teu invent\225rio, l\225[ENTER]existe uma liga\231\227o directa para o Armaz\233m de[ENTER]Artigos. "
gameforge.warehouse._150_say = "Entra no Armaz\233m de Artigos quando quiseres[ENTER]clicando neste s\237mbolo. Caso n\227o a tenhas[ENTER]alterado, a palavra-passe \233 000000. "
gameforge.warehouse._20_sayTitle = "Guarda do Armaz\233m "
gameforge.warehouse._30_say = "Queres usar o Armaz\233m?[ENTER]Ir\225s ter de pagar algum Yang para o poderes[ENTER]utilizar. Como hoje estou de bom humor, poder\225s[ENTER]us\225-lo por apenas 500 Yang. Anda l\225, \233 barato,[ENTER]n\227o achas? "
gameforge.warehouse._40_say = "O qu\234? N\227o tens Yang suficiente?[ENTER]Volta quando tiveres! "
gameforge.warehouse._50_say = "O teu Armaz\233m est\225 aberto.[ENTER]Se o quiseres usar s\243 tens de falar comigo.[ENTER]A palavra-passe do teu Armaz\233m \233: "
gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "Devias alter\225-la por raz\245es de seguran\231a.[ENTER][ENTER]Podes pensar que 45 espa\231os n\227o s\227o suficientes,[ENTER]mas quem sabe, talvez te d\234 mais algum espa\231o se[ENTER]nos dermos bem. "
gameforge.warehouse._80_say = "Bem, eu n\227o for\231o ningu\233m. Se n\227o o queres fazer,[ENTER]poder\225s sempre voltar mais tarde. "
gameforge.warehouse._90_npcChat = "Abrir Armaz\233m "
